insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2024-03-12','Ana: Correo de consolación, TS - SSASB, al ctutelar, través del correo de contacto de Salud-Extremadura (Datos de contacto: cpedroso@sierradegata.es / 927 441 032) "Buenos días. A efectos de poder actualizar la aportación económica que corresponde abonar a D. José Lara Serrano por la plaza residencial pública que ocupa en nuestro centro, les solicitamos nos remitan a la mayor brevedad posible un certificado de la cuantía de su pensión. Muchas gracias. Consolación Pedroso Álvarez Trabajadora Social SSASB 037" ······································································································································ Mi respuesta: "En respuesta a tu consulta, decirte que estamos ahora cumplimentando las Declaraciones Anuales de PNC, entre todas ellas debe estar la de José Lara Serrano. No obstante en las mismas, como sabes, en los últimos años no aparece la cuantía que percibe, que este año asciende a 517,90 € x 14. Cuando tengamos firmada la declaración anual si quieres te la envío. Pero si necesitas imperiosamente un Certificado dímelo y lo solicito, pues no lo tenemos." ·················· Respuesta de Consolación, TS: "será suficiente con la declaración"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2024-03-12','Ana: Correo del ESM-CC (equiposaludmental.caceres@salud-juntaex.es): "Adjunto remito informe de CARLOS GONZÁLEZ LEO, con relación a la última consulta de Psquiatría con la dra. Donoso. Un saludo" ······················ Guardo en el expdte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2024-03-12','Ana: Correo-respuesta de Alberto, jefe S. Ecca. a mi correo-solicitud de enero: "OK A 400 € AYUDA HIJA. ESTRELLA: ABONAMOS LOS 400 € ...CONCEPTO "APORTACIÓN FRANCISCO HIJA"-------a la cuenta con número ES80 2100 2196 6502 0046 9639 y cuyo titular es D. Ana M Garrido Chamorro( 06.982.806Y)" ······· Ana Mª Garrido es la Prima de Fco. Tiene a la hija en ACOGIMIENTO. ········································································································································ En cuanto a mi correo del pasado viernes día 8, tras hablar con Francisco (nuevo número: 643 79 34 75) y reunirme con Alberto, envío correo a Toni y Nieves - Futuex (delegadapoyo.caceres2@futuex.es): "he llamado a Francisco y después de hablar con él al Hostal Neptuno y me dicen que no se puede abonar mediante transferencia, que podrían hacer excepción pero que hasta que a ellos no se le reflejara el ingreso en cuenta Francisco no podría alojarse allí. Lo he vuelto a hablar con Alberto y procuraremos que mañana a primera hora mis compañeras de la sección económica puedan enviar al banco una autorización de retirada de efectivo de 90€ para abonar por adelantado las 3 noches de hostal. *Pongo en copia a Lourdes, compañeras de la sección económica, para que se encargue, según me indica Alberto. Nieves, si pudieras acompañar a Francisco a ambas cosas sería perfecto. El chico que me ha atendido del hostal se acuerda de ti y de tu nombre." ························ Respuesta de Nieves: "Recibido, ya he llamado al hostal y también a Cacho y he quedado con ambos para mañana gestionarlo todo." ···························································· Hoy Francisco según me dijo intentará pasar la noche de nuevo en el CES (Centro de Emergencia Social de Cáritas. El cuál según refiere está muy solicitado y tiene que hacer cola desde muy temprano para tener opción a pasar la noche. Lleva quedándose allí desde que le dieron el alta en la UHB. ···················· *En conversación con Francisco, también refiere que estuvo en Madrid dos semanas, donde le robaron y lo pasó mal. ······ Denota cierta alteración y dice literalmente: "Yo cumplo órdenes", "Trabajo para el SES, el SEPAD y para Cáritas". También expresa que no quiere gastar mucho en el hostal porque todo el dinero que hay en su cuenta es para pagar la Universidad a su hija.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2024-03-12','miguel, emails de ssb de malpartida de cáceres para una herencia Lo siento no tengo más datos el teléfono es 927240577. Extensión 2017, Jordi Acosta. Te mando el teléfono de la hermana de Mari Carmen, Belen Solano 664725794, no puedo ayudarte de otra manera.Jordi de Acosta Redondo *********************************************** Hablo con Belén, la hna, y me confirma que está en la notaria de Virgen de Guadalupe 18, Cáceres, siendo el fallecido el tio Benito Solana Rollizo, del que heredan cada una 4000€+1/2 cuartón','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2024-03-12','Ana: Correo de Cristina, Ed. Asoc. Vera (educadorasocial@asociacionvera.com): "María Antonia Bravo Patillas va a participar en el curso "Ponte al día con tu teléfono móvil", para ello necesitamos la autorización firmada. Se adjunta a continuación" ················· Subo la autorización a la firma digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESSICA ESPERANZA'and edp.apellido1='LEON'and apellido2='ENCINAS'),'2024-03-12','TERESA ENVIO POR REGISOTRO OPCION DE PNC','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2024-03-12','Ana: Correo de Alberto, Jefe S. Ecca: "SALDO HOY: 2.261,98 € *CON SU PNC Y EL PRECIO CENTRO + DECESO + LOS 200 € QUE AUTORIZAMOS CUANDO NO ABONABA CENTRO.....Y SIN EXTRAS: APENAS AHORRA 200 €/AÑO SI ESTABLECEMOS EL LÍMITE EN 150 €/MES, SE AHORRARÍA AL AÑO 800 €/APROX....Y DEBERÍAMOS DE LIMITAR AL MÁXIMO LOS EXTRAS (QUE SE DETRAERÍAN DE ESOS 800 €) TEN EN CUENTA QUE TIENEN AUTORIZACIÓN GENERAL...DÉJALES CLARO EL LÍMITE Y LUEGO ME LO CONFIRMAS A MI. *DEBEMOS AJUSTARNOS MUCHO PARA INTENTAR ACUMULAR UN IMPORTE QUE PERMITA AFRONTAR SITUACIONES ALGO MÁS COMPLEJAS (COMO ACOMPAÑAMIENTOS)." ································· *A parte de las eventualidades que puedan surgir, Guadalupe necesita tratamiento bucodental o al menos dentadura, que a día de hoy no se puede permitir. Por lo que sería conveniente ahorrarle algo más al año. ································· Envío correo con consulta-propuesta a Cristina Hdez, TS CSS (cristina.hernandezca@salud-juntaex.es).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2024-03-12','Ana: Envío correo al ESM (equiposaludmental.caceres@salud-juntaex.es) con copia a la Dra. Cristina Donoso, Psiquiatra (cristina.donoso@salud-juntaex.es): "En relación a JESÚS MANUEL RAMOS BARGÓN, nos preguntan desde el Juzgado por el seguimiento del tratamiento y administración del inyectable. Tengo el informe de diciembre de 2023 que nos remitieron en el que indicaba que debía ponerse el inyectable en 28 días. ¿Podrían, por favor, enviarnos informe o nota de seguimiento donde corroboren que ha acudido en las fechas indicadas para la administración del mismo?. Por otra parte, como saben, el paciente es difícil de abordar así como de hacer el seguimiento y apoyo, no obstante, la educadora actual del Programa conveniado entre la Junta de Extremadura y Futuex a tal fin, está haciendo lo posible para conseguir una mínima adherencia al programa y que acepte su intervención y acompañamientos a las citas programadas." ·············· Les envío nuevo correo: "Disculpad, el informe que tengo es el del 13 de octubre de 2023, no de diciembre. Si hay informe de consulta posterior, ruego nos lo hagan llegar también." ······························································································································································································· Envío correo a Toni-Futuex, y a Nieves, Ed.Futuex (delegadapoyo.caceres2@futuex.es): "He mirado en el Aplicativo vuestro en el “perfil” de JESÚS MANUEL RAMOS BARGÓN, he descargado la nota de seguimiento de 13 de diciembre. Pero no hay nada más, no sé si Nieves ha podido volver a visitarle y/o acompañarle a las citas médicas/administración del inyectable. La pongo en copia y a Maite también. La cuestión es que nos piden desde el Juzgado Información acerca de la administración del inyectable y el apoyo/seguimiento que se le hace por parte de la CTAEx. Ya he solicitado al ESM que nos remitan informe médico de la última cita programada así como nota de asistencia a la administración del inyectable. No obstante, remitidnos por favor, a la mayor brevedad, INFORME FIRMADO de apoyos y seguimiento que se le presta desde el Programa conveniado para remitirlo también al Juzgado. Por otra parte, como sabéis, y así queda reflejado también en la nota de seguimiento, Jesús Manuel sigue demandando el cambio de domicilio. También sabéis que dadas sus circunstancias, sus ingresos y el precio del alquiler en Cáceres, es una cuestión más que complicada, por mucho que su madre diga que está dispuesta a aportar una parte, es difícil encontrar otra vivienda en que acepten a Jesús Manual como inquilino (recordad también los múltiples incidentes con la comunidad de vecinos actual). Él dice que ha enviado a la CTAEx números presupuestos de piso de alquiler para cambiarse, pero la realidad, al menos desde que yo estoy trabajando aquí y se zonificaron las zonas, aquí no ha llegado presupuesto de piso alguno por su parte ni por sus familiares. Está en su derecho de querer un cambio, por lo que no hay inconveniente en que le preste ese apoyo desde el Programa, pero en principio él tiene suficiente autonomía para este tipo de búsqueda. Su sentencia, en tanto no se resuelva la revisión de las medidas, indica: “incapacidad que se extiende únicamente al aspecto personal de control de su medicación y para administrar sus bienes"" ···································································································································································································· En cuanto al pensión de manutención de sus hijos, Alberto, Jefe S.Ecca. confirma: "SE SIGUE ABONANDO REGULARMENTE." ······················· Queda pendiente la consulta de los A. Jurídicos al respecto. No sabemos hasta cuando la tiene que seguir pasando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MORA'and apellido2='GARCIA MORA'),'2024-03-12','TERESA José Luis está citado para el día 21 de marzo, una vez valorado para la tramitación del PIA contactará la compañera contigo. Saludos.- Pilar','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2024-03-12','TERESA ME CONFIRMA AITOR QUE HA RECIBIDO LA TARJETA DE TRANSPORTE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2024-03-11','Ana: correo de Estrella, TS CSS-Plas (estrella.duranc@salud-juntaex.es): "Te escribo para informarte que se va de pase a domicilio Enrique, desde mañana hasta el martes que viene. Ha realizado planificación de dinero y menús con la Terapeuta Ocupacional. A ver si puede ir Clara algún día de la semana a supervisar, que nos llame para coordinarse con nosotras que iremos probablemente, otro día, así tiene doble supervisión" ······························ Comunicaré y solicitaré seguimiento a Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2024-03-12','Ana: envío correo a Toni - Futuex y Clara, Ed.-Futuex (delegadapoyo.plasencia@futuex.es) con copia a Maite, Jefa Secc. y a Puerto, TS SSASB-Valdeobispo (ssb5@mancomunidadvalledelalagon.es): "Te reenvío correo de Estrella, TS del C. Sociosanitario de Plasencia. Como veis Enrique se va de pase una semana a su domicilio. Piden que Clara haga seguimiento en el mismo y coordine la visita con ellas para no coincidir. Desde la sección social entendemos que es necearía esta visita, pero creemos conveniente que Clara acuda acompañada o bien de la Terapeuta Ocupacional o bien de la Trabajadora Social del programa, dados los antecedentes de Enrique. Agradeceríamos también que nos enviaseis informe de seguimiento firmado, lo más detallado posible, en cuanto a conductas, habilidades y capacidades de Enrique para vivir solo de nuevo. Más aún sin los apoyos que tenía antes del Servicio de Comedor de la Residencia del que era usuario y que ya no existe y del Servicio de Ayuda a Domicilio Municipal, que excepcionalmente se le prestaba con dos Auxiliares dadas las incidencias acaecidas también con ellas y el cuál no sabemos si sería posible que le volvieran a conceder por la dificultad que supone en esas condiciones, en el caso de que decidieran en el C. Sociosanitario darle el alta definitiva. Supuestamente hay pendiente, desde hace meses, una Subcomisión Sociosanitaria que no se ha llegado a convocar y que al parecer, no todo el equipo está de acuerdo en hacerlo. Pongo en copia a Puerto, TS de los Servicios Sociales de Atención Social Básica de su localidad para que esté al corriente de todo y a Maite, Jefa de Sección." ································································································································································································· Correo-respuesta de Estrella Durán en relación a la consulta al Catering que iba a realizar la TO del CSS: "Efectivamente, se me ha olvidado decirte, no hacen servicio a los pueblos, comentan que con el tiempo los harán, pero ahora mismo no, acaban de inaugurar la empresa..... Se ha llevado dinero y un menú de comidas, a ver qué tal....."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL MAR'and edp.apellido1='CAMPOS'and apellido2='ENCINAS'),'2024-03-12','Ana: A petición de Miguel, Asesor Jurídico, reitero, esta vez mediante correo electrónico solicitud de Informe Médico al Centro de Salud Aldea Moret (aldeamoret.admon@salud-juntaex.es // 927 23 50 12): "A fecha de 27 de febrero, se remitió por registro electrónico – SIR, el siguiente oficio solicitud que adjunto, relativo a Dª María del Mar Campos Encina, cuyo cargo ostenta la CTAEx. Su Médica de Atención Primaria es la Dra. María Plaza Terán. Adjunto así mismo el justificante de dicho registro. Rogamos, por favor, nos den respuesta a la mayor brevedad, pues ante la falta de respuesta, desde el Juzgado nos lo vuelven a requerir." ··························································································································································································································································· Envío correo al Ayto. de Cáceres (informacion@ayto-caceres.es): "El pasado 29 de febrero, se remitió por REISTRO ELECTRÓNICO oficio solicitud al IMAS, solicitando INFORME SOCIAL a requerimiento previo del Juzgado para revisión de medidas de apoyo. Dado que no hemos obtenido aún respuesta, no sabemos si han llegado bien el documento. Y puesto que no consigo contactar con el número del IMAS (927 21 23 35) ni con el específico de Servicios Sociales de Aldea Moret (927 030 109), agradeceríamos reenvíen este correo al INSTITUTO MUNICIPAL DE ASUNTOS SOCIALES, bien a la Coordinación del mismo, bien la las Trabajadoras Sociales de Aldea Moret, para que puedan dar respuesta a la mayor brevedad a nuestro oficio, ya que el Juzgado lo vuelve a requerir."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='VAZQUEZ'and apellido2='MUÑOZ'),'2024-03-12','Amalia : hablo con Maite del caso , lo hablará con Soraya para ver si se pide la plaza RAL y CO . En la Luz creo que no tendría opcioens.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2024-03-12','-Amalia : comunicacion de variaciones a PNC, se adjunta el nuevo DNI como Cristina.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO DAVID'and edp.apellido1='REBANALES'and apellido2='NIETO'),'2024-03-12','-Amalia : Veo con Estrella su situación eco. Percibe 517€ de PNC . No tiene limite de reintegros ,pero en el último mes ha sacado 270 . No los supera mensualmente. Pero paga con algún tipo de tarjeta bancaria en el SPAR , Carrefour , ... son compras de muy poca cuantía . No tiene saldo en cuenta . El seguro decesos no se le ha podido cargar, vamos a esperar y con la paguilla de marzo abonarlo. Si lo devuelve como hizo el año pasado no se le va a cargar de nuevo .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA DE LOS REMEDIOS'and edp.apellido1='PALOMO'and apellido2='GONZALEZ'),'2024-03-12','se le hará una transferencia puntual de 200€ correspondientes a los meses de febrero y marzo a la cuenta de la madre ( ver en el wasap del móvil ) y una transferencia permanente a partir del 1 de abril de 100€ al mes','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='MIRANDA'and apellido2='HERNANDEZ'),'2024-03-12','Ana: Envío correo a Ángel y Miguel, A. Jurídicos: "En relación a MARTÍN MIRANDA HERNÁNDEZ, residente en el CRR de Cáceres, he recibido llamada esta mañana de Ana, Directora de la Residencia de Mayores Cervantes (927 00 55 71 / 31076 // 22233), donde residía la difunta madre de Martín, también a cargo de la CTAEx: VICTORIANA HERNÁNDEZ GARCÍA. Ésta, fallecida a fecha de 8/12/2023, tenía unas joyas que Martín no deja de reclamar a la Residencia, dónde desconocen tanto el valor de las mismas y así cómo el modo de proceder. No saben si pueden dárselas a él. En principio no hay más herederos, pero tampoco saben la procedencia exacta de las mismas, pues estuvo casada en segundas nupcias con otro señor también fallecido. Nadie más le ha reclamado nada. Pide por favor, que os pongáis en contacto con ella y le indiquéis cómo debe proceder ante esta situación." ······························································································································································································ Respuesta de Ángel, A. Jurídico: "La herencia correspondiente de Victoriana está pendiente de formalizarse, hasta entonces, no pueden entregarle nada. He llamado a Ana, Directora de la Residencia, pero estaba reunida, he quedado con ella mañana para hablar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2024-03-12','Ana: Correo de Cristina, TS CSS-Plas: "en relación a la cuestión que me planteas en el correo sobre "la posibilidad de venta de uno de sus inmuebles y de si a día de hoy él estaría en disposición de opinar/expresar su voluntad sobre ello". Te comento que Martín se encuentra en disposición de opinar y/o expresar su voluntad, sigue con su decesión de no querer vender su inmueble." ················· Lo reenvío a Ángel, A. Jurídico y a Alberto y Estrella, S. Ecca. ······································· Respuesta de Ángel, A. Jurídico: "Pues en ese caso, veo complicado que podamos vender."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2024-03-13','miguel, emails de la hermana Belen Solana chanclon >solanachanclonbelen@gmail.com> referentes a la herencia: Este es lo de la casa que ha heredado Maricarmen solana conmigo y los 4000heuros me lan dado donde he ido------------------------------------------------- Por gas lo único te voy a mandar lo del notario para que te pongas en contacto con él él también tiene todos los papeles de la información de la herencia que lo aporte un cordial saludo el teléfono es número 927240577se llama Jordi de Acosta redondo notario de virjen de Guadalupe número 18 ------------------------------------------------------- mi respuesta: Hola Belén, cuando envíes documentos porfavor envialos en un único pdf. En cuanto al dinero abona la parte que corresponde a tu hermana Mª Carmen en su cuenta ES12 2103 7114 0000 3009 4618. Hablaré con la notaria esta mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL MAR'and edp.apellido1='CAMPOS'and apellido2='ENCINAS'),'2024-03-13','Ana: correo-respuesta de Consuelo, Ayto. Cáceres (chete.muriel@ayto-caceres.es): "El teléfono del IMAS de Aldea Moret es el 927231295. Reenvío este correo a la trabajadora social correspondiente Carolina Barras. Un saludo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2024-03-13','Ana: Javier Rodríguez, TS CSS-Plas (javier.rdguezper@salud-juntaex.es) al ctutelar@ y a mí: "Adjunto factura pendiente de pago. La ropa ya ha sido retirada de la tienda y está pendiente de pago. Entiendo tenéis el número de cuenta de anteriores ocasiones de la misma tienda."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-03-13','Ana: A petición de la Sección Económica, envío correo a Josér Luis, hermano de José Manuel (joseluisromeromediavilla@gmail.com): "En relación al Seguro de Hogar que se pretende formalizar para la vivienda familiar en que reside tu hermano, me comunican desde la Sección Económica que no han podido formalizarlo aún porque en todas las compañías en que han consultado le piden la siguiente información de la que nosotros no disponemos: “valor de contenido, valor de continente, fecha de edificación del piso, distribución del piso, etc.” Alberto, Jefe de la Sección Económica me pregunta si tú, que tendrás toda la información, podrías acudir a una compañía de seguros para formalizar uno a nombre de tu hermano y nos hagas llegar tú (o desde la compañía directamente) por correo electrónico la póliza para la firma por la Representante Legal y la domiciliación bancaria del pago del mismo en la cuenta de tu hermano. Ya me dice dices cuando puedas. Gracias de antemano, como siempre, por la colaboración."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2024-03-13','Ana: Tras llamada de Francisco (643 79 34 75), envío correo a Alberto, Jefe S. Ecca.: "En relación a Francisco Cacho Garrido, acabo de hablar con él. Solicita ampliar su estancia en el hostal hasta la noche del próximo martes día 19 incluida (para salir el miércoles por la mañana). Dice que no quiere ir más a los Albergues de Cáritas porque se mueve mucha droga fuera, mientras hacen cola y no quiere consumir más. También dice que ayer acudió a la cita con la Psiquiatra. Le voy a pedir el informe médico de seguimiento a ella. Pues según refiere, le han hablado de que posiblemente pueda ingresar en un centro de Villanueva de la Serena a mediados de la semana que viene. Voy a tratar de averiguar la veracidad de todo esto, pero sí es así me parece una oportunidad muy buena para él. *Puesto que tiene dinero, por mi parte ok a que amplíe la estancia en el hotal tal y como pide. Habría que volver a hacer una nueva autorización de retirada de efectivo y comunicar a Futuex para que le acompañen al banco y abonar la estancia por adelantado, igual que ayer. Pongo en copia a Maite, para que esté al corriente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2024-03-13','miguel, trras recibir la llamada de la educadora social de Nace (creo que la mujer de Chema Tovar) 620-190869, me pregunta inquisitiva en qué estado está el trámites de herencia del hno fallecido Tomás, le explico que sólo dejó una cuenta bancaria y al no tener testamento hay que hacerle la declaración de la herencia. Me dice que van a pasar 6 meses y van a multar por no haber liquidado el impuesto (no es cierto porque falleció el 24-10-23). Quedo en que agilizaremos el trámite de declaración de herederos que urge. Llamo a la notaria de virgen de guadalupe de Cáceres 927-240577, ext 2013 (José Luis Gilarte), le envío la documentación, jlgilarte@despacho.notariado.org: Buenos días José Luis, soy Miguel de la Comisión Tutelar de Adultos de la Junta de Extremadura (compañero de Angel Marin). Me indican en la notaria que te incorporas el viernes. Necesito que tramites con urgencia (en pocos días) una declaración de herederos de un antiguo tutelado de la Junta, Tomás Esteban Iglesias. Ha dejado herederos a 3 hermanos (Máxima, José Manuel y Esteban), los dos últimos tutelados por la Comisión Tutelar de Adultos. Te adjunto la herencia firmada en su día de la abuela de ellos de donde puedes extraer los datos de Máxima, que está incapacitada y cuyo cargo de tutor realizan en Córdoba. En cuanto a la representación de la Comisión Tutelar de José Manuel y Soledad te adjunto sentencias de incapacitación, nombramiento, aceptación de cargo. También te adjunto rendición final de cuentas de Tomás que contiene que el único bien que dejó fue una cuenta bancaria, junto los certificados de defunción, y últimas voluntades. Adjunto los dni, certificado de nacimiento de los tutelados, certificados de discapacidad por la Comisión Tutelar de Adultos. Para que te indiquen los dos testigos y conciertes cita para se acerquen a firmar (corre prisa por que cumple la fecha del pago del impuesto de sucesiones pronto), te adjunto los teléfonos de Chema Tovar 669-439020 y la educadora social del centro 620-190869 donde reside Soledad, en NACE (Cáceres). Mientras que José Manuel reside en Inclusive Aprosuba 9 de Villanueva de la Serena (Badajoz) Mira lo antes posible la documentación porque urge se tramite todo. Las dudas con la hermana que está en Córdoba Máxima tendríamos que preguntarlas tal vez a Chema Tovar 669-439020 y la educadora social 620-190869 -------------------------------------------------------- Envío a Alberto email para me remita con rápidez el certificado de saldo a fecha de fallecimiento para tramitar la liquidación del impuesto de sucesiones cuando llegue el momento y el desbloqueo y reparto del dinero. Hola Alberto, hay que tramitar rápidamente la herencia de Tomás que sólo dejó una cuenta bancaria. En el expte hay movimientos de cuenta pero necesitamos certificado de saldo bancario a fecha del fallecimiento de Tomás. Me urge que esté en pocos días. No lo dejes que tengo a la mujer de Chema Tovar insistiendo que cumple el plazo de presentación del impuesto en un mes. Confírmame si es o no necesario nuestra asistencia a la firma de dicha Declaración de Herederos. Normalmente no es necesaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2024-03-13','miguel, trras recibir la llamada de la educadora social de Nace (creo que la mujer de Chema Tovar) 620-190869, me pregunta inquisitiva en qué estado está el trámites de herencia del hno fallecido Tomás, le explico que sólo dejó una cuenta bancaria y al no tener testamento hay que hacerle la declaración de la herencia. Me dice que van a pasar 6 meses y van a multar por no haber liquidado el impuesto (no es cierto porque falleció el 24-10-23). Quedo en que agilizaremos el trámite de declaración de herederos que urge. Llamo a la notaria de virgen de guadalupe de Cáceres 927-240577, ext 2013 (José Luis Gilarte), le envío la documentación, jlgilarte@despacho.notariado.org: Buenos días José Luis, soy Miguel de la Comisión Tutelar de Adultos de la Junta de Extremadura (compañero de Angel Marin). Me indican en la notaria que te incorporas el viernes. Necesito que tramites con urgencia (en pocos días) una declaración de herederos de un antiguo tutelado de la Junta, Tomás Esteban Iglesias. Ha dejado herederos a 3 hermanos (Máxima, José Manuel y Esteban), los dos últimos tutelados por la Comisión Tutelar de Adultos. Te adjunto la herencia firmada en su día de la abuela de ellos de donde puedes extraer los datos de Máxima, que está incapacitada y cuyo cargo de tutor realizan en Córdoba. En cuanto a la representación de la Comisión Tutelar de José Manuel y Soledad te adjunto sentencias de incapacitación, nombramiento, aceptación de cargo. También te adjunto rendición final de cuentas de Tomás que contiene que el único bien que dejó fue una cuenta bancaria, junto los certificados de defunción, y últimas voluntades. Adjunto los dni, certificado de nacimiento de los tutelados, certificados de discapacidad por la Comisión Tutelar de Adultos. Para que te indiquen los dos testigos y conciertes cita para se acerquen a firmar (corre prisa por que cumple la fecha del pago del impuesto de sucesiones pronto), te adjunto los teléfonos de Chema Tovar 669-439020 y la educadora social del centro 620-190869 donde reside Soledad, en NACE (Cáceres). Mientras que José Manuel reside en Inclusive Aprosuba 9 de Villanueva de la Serena (Badajoz) Mira lo antes posible la documentación porque urge se tramite todo. Las dudas con la hermana que está en Córdoba Máxima tendríamos que preguntarlas tal vez a Chema Tovar 669-439020 y la educadora social 620-190869 -------------------------------------------------------- Envío a Alberto email para me remita con rápidez el certificado de saldo a fecha de fallecimiento para tramitar la liquidación del impuesto de sucesiones cuando llegue el momento y el desbloqueo y reparto del dinero. Hola Alberto, hay que tramitar rápidamente la herencia de Tomás que sólo dejó una cuenta bancaria. En el expte hay movimientos de cuenta pero necesitamos certificado de saldo bancario a fecha del fallecimiento de Tomás. Me urge que esté en pocos días. No lo dejes que tengo a la mujer de Chema Tovar insistiendo que cumple el plazo de presentación del impuesto en un mes. Confírmame si es o no necesario nuestra asistencia a la firma de dicha Declaración de Herederos. Normalmente no es necesaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2024-03-13','TERESA ENVIO POR REGISTRO SOLICITUD DE INGRESO EN RESIDENCIA YA QUE EN AL RESIDENCIA QUE ESTAS ACTUALMENTE NO PUEDE CONTINUAR POR PROBLEMAS CON UN USUARIO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO'and edp.apellido1='PAJARES'and apellido2='TALAVERA'),'2024-03-13','Ana: Llamada de Mª José, madre de Santiago. Reitera la solicitud de transferir la mitad del dinero que hay en la cuenta a la de su otro hijo, Alexander y de que se abonen la cuota de la Asociacion ASPAINCA a la que asiste para actividades de ocio y que ella ahora mismo no le puede costear. ·············· *Pide también que los A. Jurídicos se pongan en contacto con ella, pues aún no lo han hecho. ·············· Me informa además que Santiago ha comenzado a asistir a clases por las tardes para sacarse las COMPETENCIAS CLAVES en la Escuela de Adultos de Arroyo de la Luz. ····························································································································································································· Reenvío correo del 6 de febrero a Alberto, Jefe Secc. Ecca. y los A. Jurídicos, explicando: "En relación a SANTIGAGO PAJARES TALAVERA, me ha llamado de nuevo Mª José, su madre (927 271 419 /671 605 814). Ángel y Miguel: Quiere hablar con vosotros en relación a la reclamación de la pensión de alimentos y alguna cosa más, reenvío el correo de febrero. Subrayo en amarillo en el hilo. Se queja de que hace más de un mes que solicitó que la llamáseis. Alberto: Retomamos la cuestión económica. Puesto que su otro hijo, Alexander Pajares Talavera, es el otro titular de la cuenta que tenemos de Santiago, y la mitad de dinero le corresponde, pide que transfiramos la mitad de ese dinero a la otra cuenta de su otro hijo: Nª de cuenta de: ES15 0049 0217 7321 1007 0719 – Entidad: Santander. *Si no se hiciera habría que tener bien claros los motivos para justificar al Juzgado llegado el momento. *Además solicita que se abone la cuota de socio de la asociación ASPAINCA, a la que asiste regularmente Santiago para hacer actividades de ocio. Habría que valorar si es viable y en tal caso, para cuanto tiempo le daría. Si se dijera que no habría que aclarar bien los motivos para argumentar a su madre. Recordemos que Santiago no tiene ingresos ni derecho a prestaciones a día de hoy y es la propia madre quien lo mantiene y ha cubierto hasta ahora todas sus necesidades." ······································· Envío correo a Toni Nieves, Ed. Futuex (delegadapoyo.caceres2@futuex.es): "En relación a SANTIAGO PAJARES TALAVERA, acabo de hablar con su madre. Como sabéis, Santiago no tiene ningún tipo de ingresos ni reúne requisitos para la percepción de ninguna prestación a día de hoy. De la cuenta en que tanto él como su hermano son titulares, hay un dinero (no mucho) que según refiere, ha ido ahorrándoles ella. Pide que desde esa cuenta se abone la cuota de socio de la Asociación ASPAINCA, a la que acude para realizar actividades de ocio Santiago. La verdad es que no le daría para mucho tiempo, pues en teoría sólo le corresponde la mitad de lo que hay en la cuenta, con lo que después la CTAEx no contaría con nada para hacer frente a ningún tipo de imprevisto que pudiera surgir. No obstante, ¿Nieves, podrías acudir a ASPAINCA a preguntar por las actividades que realiza, la relevancia que tienen para Santiago y la cuota que abona? Si te lo pueden poner en documento escrito dirigido a la CTAEx, mejor. La madre dice que no sabe exactamente cuánto es, lo cual me extraña un poco. Ya me vais informando cuando podáis para que se pueda valorar la solicitud."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='MIRANDA'and apellido2='HERNANDEZ'),'2024-03-13','Ana: Correo de Ángel, A. Jurídico: "Esta mañana hablé con la Directora y le he dicho que hasta que no formalicemos la herencia de Victoriana, no le entregue nada a Martín."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='CARVAJAL'and apellido2='CORNEJO'),'2024-03-13','miguel, email de Tere me reenvia email de 25-9-23 "Tomas lleva toda la mañana llamándome en su línea… que le volvamos a poner como estaba, que no está tonto, que el cararmiñana (ts de del sassb de Zafra) es un mentiroso…, que vamos a conseguir que se muera LA ultima llamada ha sido para decirme que va a pasar la itv del coche y necesita el dinero para pagar la tasa Tenemos algo al respecto al tema de conducir de este hombre? Podemos autorizar el pago de la tasa? No se si hemos pedido ingreso involuntario o comunicado algo al juzgado ya que es imposible la intervención con él, el mismo manifiesta que no quiere ayuda de nadie, no deja entrar a nadie en el domicilio y desde futuex ya se han negado porque pone en peligro la integridad de la compañera, lo único que estamos interviniendo a nivel eco". Hola No tengo respuesta de este correo y este hombre sigue por ahí conduciendo Creo que el juzgado debería ser conocedor de que conduce con el carne caducado, además se pidió ingreso involuntario, como va este asunto? Le hemos arreglado en varias ocasiones averías del coche…. Me da miedo que este hombre lie alguna gorda con el coche…. ------------------------------------------------------------- mi contestación: Hola Tere, se envió al juzgado en noviembre del año pasado este oficio, q está subido a la intranet. Desde entonces creo no hemos recibido respuesta del juzgado. Acabo de hablar con el juzgado y me comentan que no se ha hecho nada desde entonces porque la compañera que llevaba el procedimiento se ha ido del puesto hace poco. Le he comentado la urgencia de la situación, está descompensado, no va a asistir vountariamente al forense, anda por ahí con un carnet cadudacado conduciendo. Se ha apuntado mi teléfono y va a decírselo a la compañera. Me llamará también acerca de una mujer que ingería unas pilas y dijimos q la íbamos a internar no sé si en la provincia de Cáceres, para que le informara por ella, pero ninguno de los dos sabíamos el nombre así que mañana me llamará para preguntar por qué pasó con aquella mujer.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2024-03-14','Ana: Correo de Ana Benavente, TS ESM-CC () al ctutelar@ con convocatoria de SUBCOMISIÓN DE GESTIÓN DE CASOS, día 20/03 a las 13 h. ·········· Respondo planteando si se puede adelantar la hora. Sino tendremos que asistir telemáticamente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2024-03-14','Ana: envío correo a Cristina, Ed. Asoc. Vera: "Adjunto la autorización firmada digitalmente para la participación de María Antonia Bravo Patillas en el curso "Ponte al día con tu teléfono móvil".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2024-03-14','Ana: Llamo al C. Salud Puerta de Argel de CC (927 24 23 25), me dicen que su MAP, el Dr. Ángel Alias (angel.alias@salud-juntaex.es) no está estos días. ······ Me pasan con la Enfermera, Isabel de Vera (53004). Me confirma que Jesús Manuel acude regularmente a ponerse el inyectable. ··· Me enviarán el registro de asistencia de los últimos años. ····························································································································································································· Envío a los Jurídicos: Adjunto: - El último Informe de Consulta de Psiquiatría de octubre de 2023. Aye habé con la Dra. Cristina Donoso, Psiquiatra, la cuál me informa que no ha vuelto a acudir pero porque está pendiente de la siguiente cita, que aún no se la han dado. - Informe de Seguimiento del Programa de Apoyo Comunitario conveniado entre la Junta y Futuex - Registro de Asistencia y ADMINISTRACIÓN DEL INYECTABLE en el Centro de Salud durante los últimos años. Está asistiendo regularmente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2024-03-14','Ana: Respuesta de Ángel, A. Jurídico, en relación a la Manutención que pasa a sus hijos: "Pues en este caso se desestimó la demanda que llegamos a presentar, por la falta de capacidad procesal y para ser parte, al estar incapacitado. Os explico. Solicitamos asistencia jurídica gratuita, se la concedieron, el Letrado designado presentó la demanda correspondiente, pero la desestimaron, porque el Juzgado entendió que el curatelado, debió estar representado por su representante legal, que somos nosotros y que lo estábamos, en la representación procesal del letrado y procurador designado, pero el Juzgado entendió que no era suficiente. Total, que todo quedó como estaba, sin modificarse las medidas de José Manuel. Vamos a volver a retomar el procedimiento, solicitando, de nuevo, asistencia jurídica gratuita. Asi que por favor: Alberto: envíame certificado de saldo en cuenta y de titularidad, así como de los gastos que tenga, de centro, de casa, etc. Ana: envíame pensiones que cobra, donde vive (en base de datos pone en domicilio), etc. En el caso de los hijos, información de donde trabajan y lo que cobran." ·································································································································· Respondo: "Adjunto la REVALORIZACIÓN DE LA PENSIÓN DE INCAPACIDAD PERMANENTE ABSOLUTA de JESÚS MANUEL RAMOS BARGÓN. El resto de datos exactos (nombre de los hijos, trabajos y salario) intentaremos averiguarlo, pues lo que sé es lo que os puse en el correo, que es lo que me transmitía la madre de Jesús Manuel sin mucha precisión. En cuanto averigüe os digo." ································································································ Envío correo a Toni-Futuex: "','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO'and edp.apellido1='PAJARES'and apellido2='TALAVERA'),'2024-03-14','miguel, tras hablar con Mª José, la madre del curatelado, envío email a la parte económica y la social: Buenos días, he hablado con Mª José la madre (927 271 419 /671 605 814) y le he explicado todo. Hay varias cuestiones: 1.-Pensión de alimentos: me comenta que tuvo muchos abogados de oficio y nunca ha logrado cobrar porque el padre cambiaba de domicilio, de trabajo, etc, en definitiva que no han logrado embargarle cuentas y cobrar, desde hace 18 años que se fue. 2.-Vivienda en que reside con Santiago (su hno Alexander está en el mismo centro que habían admitido a Santiago, y que ella no quiere que estén juntos por que se llevan fatal). Dicha vivienda está embargada por la Diputación de Sevilla, desconociendo el importe de dicho embargo. Y aunque está divorciada y la liquidación de la sociedad de gananciales vía judicial es de 2013 le siguen llegando las notificaciones por lo que no se descarta que la puedan subastar y perder la casa en algún momento, pese a que sólo le quedan 2 años de terminar de pagar la hipoteca. Lo tiene en manos de abogado de oficio y la he asesorado de que actualice dicha sentencia (pues tienen vigencia de 5 años) y cuando la tenga la inscriba en registro de la propiedad, civil y catastro para que no puedan embargarla y quitársela. 3.-Remoción: le he indicado que debe pedirla. Le he dicho que no tiene pensiones, que la administración por la Comisión es gratuita, pero que al no tener capacidad económica no podemos ejercer cargo alguno. Por eso le he indicado que pida otro abogado de oficio y pida la remoción. Una vez la tenga pueda tramitar con la trabajadora social de su domicilio la solicitud de un centro adecuado. Dice preguntará a Ana si es posible el acceso a piso tutelado. Ya le he comentado que aunque esté curatelado asistencialmente por la Comisión, no tiene prioridad sobre otras personas no representadas por la Comisión. 4.-Dinero de la cuenta del Santander: ya me ha explicado que el dinero es suyo, y le he dicho que son decisiones de la parte económica. Por lo que comenta, la han estado asesorando mal desde hace años, pues en planificación le venían a decir que la Junta le soluciona todo…En definitiva que el dinero si no tiene lo pone la Junta. Creo que la larga conversación le ha dejado clara la situación y si tiene dudas llamará a Ana o a mi.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MORENO'and apellido2='FOLLARAT'),'2024-03-14','miguel, modifico y remitimos al juzgado vía lexnet solicitud de nuevo Auto cambiando el anterior de autorización de venta. Se lo comento a Coro 618817695, y se lo envío por email a Maria Cadenas en contestación a su email de ayer: "Buenos días Miguel, En los próximos días iré al Juzgado de Villafranca. ¿se resolvió el auto que estaba pendiente de Mª ISABEL MORENO FOLLARAT?. Si no es así, me puedes enviar los datos del expediente para preguntar allí personalmente" ************************************************** mi contestación: Buenos días, hablé con el juzgado y hay que solicitar de nuevo la modificación del Auto porque estaba mal hecha por el despacho de José Santiago. Hablé con él y no se enteraba bien, así que he rehecho yo el escrito y lo hemos enviamos hoy por Lexnet la juzgado. Te adjunto el escrito para que la semana que viene te acerques a preguntar si quieres. A ver si pueden agilizarlo. Se lo comenté todo a Coro el otro día… Cualquier duda dimelo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2024-03-14','miguel, la hermana Maxima Esteban Iglesias nif 28958530N,tutelada por la Fundación Promi de Villanueva de Córdoba tlfno 957-123526, email pedroches@promi.es incapacitada 4-11-94, reside en Residencia de Adultos Miguel Vacas Gutierrez en c/ Pedroche nº16 envio email(Villanueva de Córdoba), llamo y hablo con la directora Mª José y le explico vamos a tramitar la herencia de Tomás. Me pide se lo envíe y explique por email: A/A Maria José Diaz Vallejo: Conforme conversación telefónica. Adjunto los datos del hermano fallecido de vuestra tutelada Maxima Esteban Iglesias. La Comisión Tutelar de Adultos de la Junta de Extremadura, ejerce el cargo de curador representativo (tutor) de los hermanos Soledad y José Manuel Esteban Iglesias. Y en su día dicha Comisión ejercía el cargo de tutor del hermano fallecido Tomás. Ha dejado sólo una cuenta bancaria cuyos movimientos de cuenta aparecen en el adjunto rendición final, certificado de defunción y últimas voluntades. Hemos dejado en la notaria de Cáceres de c/ virgen de Guadalupe, contacto Jose Luis Gilarte email jlgilarte@despacho.notariado.org; 927-240577(extensión 2013), para prepare rápidamente la Declaración de Herederos. Poneros en contacto con la notaria para facilitarles todo lo que necesiten para la firma de dicha Declaración de Herederos. Una vez se firme tendríais que liquidar el impuesto de sucesiones acogiéndose al beneficio de minusvalía que pueda corresponderle para que le salga Exenta. Recordad que Tomás falleció el 24-10-23 por lo que debemos agilizar los trámites. Quedo a vuestra disposición para aclarar cualquier duda. A/A Maria José Diaz Vallejo: Conforme conversación telefónica. Adjunto los datos del hermano fallecido de vuestra tutelada Maxima Esteban Iglesias. La Comisión Tutelar de Adultos de la Junta de Extremadura, ejerce el cargo de curador representativo (tutor) de los hermanos Soledad y José Manuel Esteban Iglesias. Y en su día dicha Comisión ejercía el cargo de tutor del hermano fallecido Tomás. Ha dejado sólo una cuenta bancaria cuyos movimientos de cuenta aparecen en el adjunto rendición final, certificado de defunción y últimas voluntades. Hemos dejado en la notaria de Cáceres de c/ virgen de Guadalupe, contacto Jose Luis Gilarte email jlgilarte@despacho.notariado.org; 927-240577(extensión 2013), para prepare rápidamente la Declaración de Herederos. Poneros en contacto con la notaria para facilitarles todo lo que necesiten para la firma de dicha Declaración de Herederos. Una vez se firme tendríais que liquidar el impuesto de sucesiones acogiéndose al beneficio de minusvalía que pueda corresponderle para que le salga Exenta. Recordad que Tomás falleció el 24-10-23 por lo que debemos agilizar los trámites. Quedo a vuestra disposición para aclarar cualquier duda. ************************************************ Maria José, en su día se firmó esta escritura de herencia de la abuela que adjunto, por si quieren verla en tus servicios jurídicos. Aunque no tiene que ver con la herencia a realizar ahora de su hermano Tomás.','2');
