insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2024-03-15','miguel, me llama Loli de la notaria y tras explicarle toda la documentación que la remiti, me pide le envíe nombramiento, incapacitación, los datos y nombramientos de la Gerente, etc: Buenas tardes Loli, tal como hemos hablado queda pendiente que Estefanía hable contigo y te aclare cuenta bancaria, gastos e ingresos con facturas a incorporar a la adjudicación de herencia. Coméntale a Estefanía quién será el mandatario verbal de Montserrat (la exmujer de Juan Felipe, hijo de la tutelada Alfonsa Montalban) Por mi parte te vuelvo a enviar testimonio de incapacitación, nombramiento a la Comisión. Prepararé y te enviaré la Autorización que me tiene que hacer la actual representante de la Comisión Tutelar de Adultos, Doña Estrella Martinez Lavado (te adjunto su nombramiento como representante de la Comisión, delegación de competencias de la Consejera de Salud y Servicios Sociales, Doña Sara García Espada. Cualquier duda me vas diciendo --------------------------------------------------------- Escribo a la abogada Estefania@beramendiygonzalez.com: Buenas tardes Estefanía, Loli de la notaria de Herrera del Duque te va a llamar para que le aclares y envíes todo lo que tengas relacionado con cuenta bancaria, ingresos, gastos, y dile quién puede firmar como mandatario verbal. No sé si es incompatible por conflicto de intereses que lo haga yo. En principio yo asistiré presencialmente. Te llamará el lunes, tenlo todo preparado','2');
