insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MURILLO'and apellido2='ROMANO'),'2024-03-15','miguel, llega email de Sandra Sánchez >ssanchez@inteligencialimite.org> Buenas tardes. Adjunto el fallo de la sentencia de Juan José Murillo Romano. -------------------------------------------------- mi contestación, Desde el Centro donde sigue el tratamiento tienen que comunicar al juzgado trimestralmente el cumplimiento del mismo. Queda en suspenso para que en 2 años no vuelva a ser condenado, caso contrario se levantaría la suspensión y respondería por ambas condenas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2024-03-15','TERESA Buenos días, Soy Esther, trabajadora social de los SSASB de Zalamea de la Serena. En esta localidad está tutelado por dicha comisión Pablo Galán Gilgado y me gustaría ponerme en contacto con vosotros para informaros de los recursos de los que dispone este Servicio y en el que Pablo pueda reunir los requisitos para poder ser beneficiario. Dejo el número de teléfono del ayuntamiento: 924 78 00 32. Mi número de telfno del despacho es 664 49 36 08. HABLO CON ELLA Y ACORDAMOS QUE LE GESTIONE SAD Y MINIMOS VITALES Y BONO SOCIAL LE INFORME QUE ESTA EN LISTA DE ESPERA PARA RESIDENCIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2024-03-15','Ana: Llamo al INSS de Cáceres. Me remitirán la REVALORIZACIÓN DE LA PENSIÓN EN FAVOR DE FAMILIARES CON % DE VIUDEDAD. ········ Hay que comunicar variación de domicilio, aún consta la del CRR de Mérida. ································································································································································································· Correo de Eusebia Pérez, Control de Pensiones INSS-CC (eusebia.perez@seg-social.es): "Adjunto certificado de Revalorización 2024 correspondiente a la pensionista María Joaquina Mayoral Pizarro"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='GIRALDO'and apellido2='BECERRA'),'2024-03-15','miguel, llega ejecutoria condenatoria 123-2023 de jzdos de Mérida, llamo a los Servicios Comunes que me informan y envío email a la parte social Tere y Maite, parte económica Alberto, y a Angel: Buenas tardes, acabo de hablar con los servicios comunes del juzgado de Mérida que llevan la ejectutoria 123-2023 por el que el curatelado representativo ha abonado hasta la fecha de esta sentencia condenatoria 800€ en concepto de responsabilidad civil, quedandole pendiente de abonar 3.790,23€ Por otro lado le queda por abonar en concepto de Costas procesales 3.362,48€ En principio el juzgado (el secretario) no nos está pidiendo el abono puesto que lo está abonando el Fco Javier Giraldo Becerra, no obstante Tere debes hablar con él y decirle lo que le queda por pagar y ver cómo lo va a abonar porque si no tendrás que coordinarte con Alberto y proceder al abono de las cantidades que os he indicado, y en cuyas transferencias debería figurar en concepto: EJ 123-2023; 0392/0000/78/0123/23, y en el caso de las COSTAS, en concepto: EJ 123-2023; costas; 0392/0000/78/0123/23 Cuenta para hacer el ingreso SANTANDER ES 55-0049.3569.92.0005001274. Por tanto habla Tere con él y a ver cómo y cuándo va a abonar todo esto y si no lo va a hacer él tendrás que coordinarlo con Alberto. Cualquier duda me decis.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-03-15','Ana: Correo de Lourdes, TS SAD - IMAS (lourdes.perez@ayto-caceres.es): "José Manuel ha discutido con la auxiliar y le ha dicho que no vuelva a su casa . Intentaremos prestar con otras auxiliares q tengan horas libres, hasta que podamos hacer efectivo el cambio ya que ahora no hay posibilidad de cambiar. Un saludo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2024-03-11','Ana: Correo de Guadalupe Cortés, TS SAD IMAS-CC (guadalupe.cortes@ayto-caceres.es): "Me llega incidencia de UNIGES sobre el seguimiento de SAD que se presta a Ventura Gómez García. Ya habíamos hablado de ello por teléfono, pero te remito la incidencia escrita por si aporta nueva información. Nos comenta la auxiliar que Ventura sigue teniendo mucha comida del catering privado en la nevera. Cuando la auxiliar llega al domicilio de Ventura, y ve tanta comida, intenta congelar varios tapers, pero a los dos días vuelve a sacarlos del congelador. Que la fruta la esconde en el lavavajillas para que la auxiliar no la vea porque ésta le insiste mucho que no debe coger tanta comida del catering si tiene suficiente, ya que como sale de viaje, de vez en cuando, no le haría falta el menú de todas las semanas. La auxiliar cree que sigue comprando el pan y el fiambre y es lo que come. Nos comenta también que ha coincidido con la Educadora de la Comisión tutelar en el domicilio y que ha visto todo lo que nos ha contado a nosotros. Con el tema de las compañías telefónicas, ha vuelto a cambiar y tiene algún problema con la anterior compañía, pero que también ésto lo sabe la Educadora de la Comisión tutelar. Por todo lo demás, la casa la mantiene en orden la auxiliar."','2');
