insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='MONTAÑO'and apellido2='MONTAÑO'),'2024-03-18','la PFHC con el Nº cuenta nuevo se tramitó desde CSS de Mérida como guardadores de hecho , estuve supervisando todo el proceso y está correcto .No podíamos pedirlo nosotros pq no somos curadores. Estamos en coordinación con el INSS por este caso . El problema es que seguimos como Defensa Judicial , no somos curadores aún. Se lo comento a los compañeros porque parece ya mucho tiempo . Como D. Judicial el juzgado nos instaba a tomar medidas para impedir que su hermano Damián, anterior tutor y titular de la prestación se quedase con ese dinero . Los cambios en la PFHC son trimestrales , en abril debería estar hecho el cambio al nuevo Nº cuenta','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2024-03-18','Ana: Envío correo a Miguel, A Jurídico: "Me acaba de llamar Mª José, del Piso de NACE (620 190 869), me dice que habló ya contigo la semana pasada, pero que ha acudido a la NOTARÍA, y le han dicho que hay que hacer UN APLAZAMIENTO YA, HOY O MAÑANA, porque se acaba el plazo. Ponte en contacto con ella, por favor..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2024-03-18','Ana: Envío correo a Alberto: "Te reenvío presupuesto de CONSULTAS EN NEUROLOGÍA que nos facilitan desde el centro (Autismo Sur) relativo a COSTI ALEXANDRU RIZEA. Dinos si es viable, están a la espera de respuesta. No sabemos cuántas citas necesitaría." ························· Las consultas serían online, el Neurólogo es de Barcelona. (Coste: 165€/1ª visita // 110€/visitas de seguimiento) ·································································································································································································· Respuesta de Alberto: "CONCLUSIÓN: PUEDE AFRONTAR ESTE GASTO. DEBEMOS OBTENER UNA ESTIMACIÓN DEL Nº DE SESIONES QUE PODRÍAN NECESITARSE Y DE LA PERIODICIDAD DE LAS MISMAS....IMPORTANTE: ESTOS CÁLCULOS SE REALIZAN TENIENDO EN CUENTA QUE NO VA A HABER GASTOS DE DESPLAZAMIENTO Y ALOJAMIENTO (QUE SERÍAN ENORMES PARA ESTE TUTELADO (BARCELONA)"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2024-03-18','miguel, me llama Mª José de Nace: Me comenta que ha ido a la notaria y si bien José Luis Gilarte está recien incorporado, ha abierto mi email del miercoles pasado delante de ella Le dice que los testigos no pueden ser ellos sino la Ctaex y que entre hoy y mañana tenemos que presentar la prorroga del impuesto de sucesiones. ------------------------------------------------------ Llamo reiteradamente sin éxito a la notaria de Virgen de Guadalupe, Cáceres (José Luis Gilarte)para me explique porqué no pueden ser otros testigos y porqué no puede agilizar la firma de la escritura de Declaración de Herederos. -------------------------------------------------------- email de Ana: Buenas Miguel, Me acaba de llamar Mª José, del Piso de NACE (620 190 869), me dice que habló ya contigo la semana pasada, pero que ha acudido a la NOTARÍA, y le han dicho que hay que hacer UN APLAZAMIENTO YA, HOY O MAÑANA, porque se acaba el plazo. Ponte en contacto con ella, por favor, para que te termine de aplicar. ------------------------------------------------------- mi contestación a Ana y Angel: Buenos días, yo también he hablado con ella. La notaria no me coge el teléfono ni viernes ni hoy. Angel algún modelo que tengamos para pedir el aplazamiento del impuesto? Dice Maria José que le ha dicho José Luis que pidamos primero la liquidación y cuando tengamos todo se autoliquide. En cuanto a la declaración de herederos dice que José Luis dice que los testigos no pueden ser ellos sino nosotros la Comisión Tutelar de Adultos…No lo entiendo puesto que nosotros no conocíamos al fallecido. En fin, acláramelo Angel, seguiré intentando hablar con la notaria. A ver si mañana puedo pedir el aplazamiento en Mérida… -------------------------------------------------------- Llega email de Chema Tovar a ctutelar asociacionace@hotmail.com Buenos días Miguel, puesto en contacto con la notaría, informarte de que hay que hacer urgentemente un aplazamiento, entre hoy día 18 y mañana 19 de marzo, para liquidar la herencia de Tomás Esteban. A continuación hacer la declaración de heredero en la que los dos testigos tienen que ser representantes legales de Tomás. ----------------------------------------------------------- Hablo con la oficina liquidadora de Mérida y me dicen que antes del cumplimiento del 5ª mes tenemos que presentar la solicitud de prórroga, modelo 750 dirigido a la oficina liquidadora de cáceres -------------------------------------------------------------- envío email a promi de villanueva de Córdoba, pedroches@promi.es Buenos días Maria José, aunque no he logrado hablar con la notaria, la misma le ha dicho a la educadora social donde reside, Nace, en Cáceres, que debemos pedir la prórroga en la presentación del impuesto de sucesiones porque no da tiempo a que esté en plazo. Tras llamar a la oficina liquidadora de Mérida, me dicen que hay que dirigir este modelo 750 de solicitud de prórroga antes del cumplimiento del 5 mes de fallecimiento, esto es, antes del 24-3-2024. Os adjunto el modelo para que lo presentéis en nombre de Máxima. Os recuerdo que el único bien a incorporar en la herencia es la cuenta bancaria, de la que hemos solicitado nos envíe el banco el certificado de saldo. Te adjunto de nuevo los movimientos bancarios para que de ahí saquéis la información para rellenar el modelo y lo enviéis a la oficina liquidadora de Cáceres, en nombre de Maxima. Nosotros haremos el mismo trámite para los otros dos hermanos, Soledad y José Manuel. -------------------------------------------------------- pongo email a la notaria jlgilarte@despacho.notariado.org; a Chema Tovar asociacionace@hotmail.com; y a la Trabajadora Social Ana Matamoros: Buenos días José Luis, me ha llamado esta mañana la educadora social de Nace, Mª José, y me comenta que tenemos que solicitar el aplazamiento urgente (hoy, mañana) del impuesto de sucesiones de Tomás. Llevo desde el viernes intentando contactar contigo. Por favor a ver si me puedes aclarar porqué no da tiempo a firmar la declaración de herederos antes del 24-4-24 (ya que Tomás falleció el 24-10-23). Por otra parte nunca se exige que los testigos sean de la Comisión Tutelar, ya que Tomás residía en un centro de Cáceres y los trabajadores de la Comisión no conocemos a los más de 800 personas que representa la Comisión, motivo por el cual entendemos que deben de ser testigos las personas que lo conocían o trabajadores en el centro donde residían. Aclárame esto cuando puedas. En cuanto a la prórroga, he puesto un mensaje a la Fundación de Córdoba que representa a una de las herederas (hna de Tomás) Máxima para que soliciten su prórroga. Nosotros solicitaremos la prórroga del impuesto de sucesiones esta semana, pues ha de hacerse antes de transcurrir los 5 meses desde el fallecimiento. Cuando puedas dinos cuanto antes, cuándo se puede firmar dicha Declaración de Herederos. Pongo en copia a Nace (D. José Maria Tovar) y a la trabajadora social de la Comisión Tutelar de Adultos.','2');
