insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2024-03-18','Amalia : escribo a Lourdes : me indica Jonathan y su hermano que no le ha llegado los 50€. Os paso el Nº cuenta del hermano , la cuenta está a nombre de Antonio y Beatriz , es de la Caixa ES8321002024230100563162 Quedarlo registrado para futuras peticiones , pero no reenviés estos 50€ , el hermano no quiere que lo moleste con estas gestiones. Los 50€ puede que se hayan enviado a la cuenta anterior que teníamos y que al parecer ha cerrado . Entiendo que el dinero no se habrá cargado TF DE ANTONIO HERMANO 627969982','2');
