insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2024-03-19','Ana: En relación al correo de Toni-Futuex, de ayer, "Desde el equipo de apoyo social comunitario, sobre el caso de Juan Chamorro Holguín, destacamos su solicitud de adquirir un nuevo teléfono móvil.Para evaluar su viabilidad, nos dirigimos a Jeyma para obtener información sobre el presupuesto. (Se trata de una tienda en Quintana de la Serena, donde hace pocas semanas se ha adquirido un terminal tambien básico, para otro tutelado Rafael Casares y se ha podido pagar por transferencia) El IBAN: ES14 2085 4572 7803 3042 9611 IBERCAJA El presupuesto es el siguiente: 30€ (teléfono móvil + tarjeta sim) El desglose sería el siguiente: - Teléfono Nokia 105= 25 euros. - Tarjeta SIM de prepago (4G 6+ llamadas ilimitadas)= 5 euros." contesto a ella y a la secc. económica: "Por mi parte OK A ESTE PRESUPUESTO, no creo que se pueda encontrar otro más económico, jeje. Compañeras de la sección económica, dado el precio no creo que haya problema, así que abonad en cuanto os sea posible y confirmadle a Toni dicho abono para que puedan pasar a recogerlo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2024-03-18','Ana: Llamada de Felisi, como siempre con mucha necesidad de hablar y desahogarse. Cada día está más desesperada con la situación de su hijo y la convivencia cada vez más complicada. Manifiesta que Aitor ha dejado de tomar todas las pastillas, está fumando muchos porros y le dice cosas como "estás muy vieja" o "estás muy gorda". No le trata bien y tampoco colabora en casa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MORENO'and apellido2='FOLLARAT'),'2024-03-19','miguel, me envia José Santiago comunicación del juzgado indicando que dan traslado al ministerio fiscal de las alegaciones hechas en diciembre. Pongo email a José Santiago y Maria Cadenas: Buenos días José, no entiendo que den traslado ahora al ministerio fiscal, cuando en reiteradas conversaciones con el juzgado de Villafranca (Alba creo se llama la funcionaria) insistieron que el expediente había quedado finalizado por que no se podía subsanar, motivo por el cual el mismo día que os han comunicado a vosotros el traslado al ministerio fiscal de vuestras alegaciones de subsanación para que continuaran la subsanación del Auto de Venta, nosotros hemos enviado nueva solicitud para que dicten nuevo Auto subsanando el dictado en 2021. En fin, que les va a llegar por dos vías la solicitud de modificación del Auto del 2021, la vuestra y la nuestra. A ver si con eso es suficiente y dictan un Auto estimando las modificaciones indicadas en su día por el notario de los Santos de Maimona, Don Carlos Fernández Duro. Adjunto el Lexnet que enviamos el día 14-3-2024 desde la Comisión Tutelar de Adultos. Pongo en copia a Maria que de vez en cuando pregunta por que la informen de en qué estado de tramitación se encuentra el expediente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2024-03-15','Ana. Correo de Toni-Futuex: "pues si se ha podido retirar el dinero, efectivamente a primera hora... La actualización más alla de este asunto, es que Francisco Cacho, está ingresado en el hospital- en UHB del San Pedro. Al parecer ha acudido para ajuste de medicación durante la noche.. luego se ha ido a las 8 porque habían quedado para el banco, se ha acordado dejar dinero en un bar para que le suministraba bocadillos, y ha regresado al hospital. Estaba muy preocupado porque sus pertenencias, mochila con el DNI están en consigna en la estación de autobuses, este a llamado a la compañera para informarle y pedirle si se la podría llevar, se ha hecho un gran esfuerzo, (en mitad de otra gestión) y se ha intentado por todos los medios, incluso presentando la autorización del banco donde aparece el num de DNI y que es un documento oficial, que se la dieran, pero el personal de la estación no ha transigido. Por lo tanto se avisará en hospital, que le comuniquen a el (ya que ya no tiene el teléfono disponible) que sus pertenencias continúan en la consigna de la estación y al salir deberá pagarlo (es un euro al dia o algo así). Según el dijo, estará ingresado unos pocos dias.. dos o tres. No sabemos si conoce este dato con precisión porque le ayudan explicado los psiquiatras, o es más bien una sensación suya. Seria genial que desde allí se considerara que pudiera ir a otro recurso, debido a la frecuencia de los ingresos, pero bueno, ya sabemos lo complicado que es esto aveces."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FERMIN'and edp.apellido1='GARCIA'and apellido2='PABLOS'),'2024-03-19','Ana: Reenvío a Teresa Nogueira, TS Novaforma, el correo que Estrella, S. Ecca. ha remitido a la oficina bancaria: "se adjunta autorización de reintegro mensual de José Fermín , la primera retirada del nuevo importe será el próximo día 1 de abril."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2024-03-13','Ana: Correo de Toni-Futuex: "Se va a realizar un seguimiento en domicilio, a ESGP mañana, dia 14 de Marzo, se han tenido que modificar algunas citas concertadas, pero es el único dia disponible, en que puedan acudir dos profesionales del proyecto, la educadora de referencia de su zona y la terapeuta. Una vez se haga el seguimiento, elaboramos informe.. a ver que tal mañana, se ha avisado a una farmacia donde acude de la hora del seguimiento, porque al parecer no tiene teléfono."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2024-03-19','Ana: Solicito a Toni Futuex, Informe de la visita de seguimiento en domicilio del jueves pasado, día 14.','2');
