insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='BERMEJO'and apellido2='TELLO'),'2024-03-22','-Amalia , esta semana he llamado a su hermana varias veces sin poder contactar con ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2024-02-21','Maite:Hemos firmado la baja de la plaza de RAL en Cabeza del Buey. Tras reunión con la UDHAC afirmaron que Andrés no podrá volver a centro de discapacidad. Se plantea su continuidad en el sociosanitario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RICARDO'and edp.apellido1='ROCHA'and apellido2='BARCO'),'2024-03-19','Escribo a rafa@camps : consultado el caso con nuestra asesoría jurídica , y dado que en la vivienda de nuestro curatelado no hay ningún desperfecto , no podemos enviar ningún reparador a dicho domicilio . En todo caso , tendría que llamar usted al perito del seguro de ese trastero.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEMESIA'and edp.apellido1='GARCIA'and apellido2='PANIAGUA'),'2024-03-19','Ana: Envío correo a Piedad, TS de SSASB - Mancomunidad de Trasirra (670 29 30 45 // ssbp@trasierratierrasdegranadilla.es): "En relación a NEMESIA GARCÍA PANIAGUA, residente en los PISOS TUTELADOS de GUIJO DE GRANADILLA, y cuyo cargo de curatela, como sabes, ejerce la CTAEx, me pongo en contacto contigo para solicitar, tal y como nos insta el Juzgado, INFORME SOCIAL en los términos que a continuación se exponen, para remitir al Juzgado para el procedimiento de REVISIÓN DE LAS MEDIDAS JUDICIALES DE APOYO: “Informe sobre la situación actual de Dña. Nemesia: - Discapacidad que presenta - Ámbitos y extensión que resulten afectados por su discapacidad y necesidad de apoyo - Cualquier consideración que estimen conveniente sobre él en razón al procedimiento judicial de revisión de medidas de apoyo”"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2024-03-19','Ana: Tras hablar con Puerto, TS SSASB Valdeobispo (722 23 05 66), envío correo a Estrella Durán, TS UME CSS-Plas: "Ya me han dicho que en el Sociosanitario que tanto tú como María, Psiquiatra, estáis reunidas. He recibido llamada de Puerto, Trabajadora Social de Valdeobispo. Ha puesto el manos libre, pues estaba en su despacho Enrique. Éste dice que ayer no le quedaba ya dinero. Había pedido dinero a alguien para poder regresar hoy al centro, pero no se lo quisieron dar. A puerto también le ha pedido dinero esta misma mañana. Ha pedido también a la farmacéutica que le lleve en coche, pero le han dicho que no puede ser. Exige que le solucionemos la forma de regresar. Hoy la oficina bancaria de su pueblo está cerrada. Habíamos pensado pediros que se quedara en su casa un día más para que mañana pudiera retirar dinero con una autorización extraordinaria que se hiciera desde la sección económica, pero el bus sale a las 9:00 y la sucursal no abre hasta las 10:00 h, con lo cuál esta opción tampoco es viable. También he hablado con el Alcalde y la Secretaria del Ayuntamiento. Enrique lleva allí toda la mañana demandando atención y que le lleven al sociosanitario con el vehículo del Ayto. Me dicen, con mucha razón, que ni pueden llevarlo, pues el vehículo no está para ese fin, y que tampoco pueden dejar de hace todas las gestiones y su trabajo para atenderle a él. El Alcalde me pregunta qué opciones hay para este chico pues nunca ha vivido solo y desde el Ayuntamiento no se le pueden prestar los apoyos que necesita. Me informan también que Enrique se ha ido sin teléfono esta semana. Yo no sabía que ya no tiene. Ahora entiendo que la educadora de Futuex no pudiera localizarlo el otro día. Vamos a intentar localizar un taxi que pueda ir a recogerlo, cuestión que no nos parece la más adecuada, pues entendemos que así reforzamos su conducta, pero no encontramos otra alternativa. ¿Podríais, por favor, indicarnos el contacto de alguno de confianza con el que soláis trabajar desde el socio con el que pudiésemos contar? También he preguntado a Toni, Coordinadora del Programa Conveniado con Futuex, van a consultar, pero aún no tenemos nada. Pongo en copia a Toni, Puerto, Maite y Ana Benavente." ································································································································································································· Envío nuevo correo a todas: "Tan sólo confirmar que desde FUTUEX finalmente han podido gestionar un taxi para hoy mismo, para que le recoja en plaza del pueblo a las 14:30 h y le lleve de regreso al Centro Sociosanitario. Ya he hablado con el Ayuntamiento y se lo van a comunicar, pues sigue por allí." ······················································ Correo de Toni-Futuex: "Taxis felix montes 629523623 Lo recoge a las 14.30h como hemos hablado, el telefono que tiene operativo supuestamente Enrique +34 634 41 71 55, por si tuvierais que contactar"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2024-03-19','Ana: Llamo a Mª Carmen, TS de la UHB - HSPA (56283): No obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANDRA'and edp.apellido1='GONZALEZ'and apellido2='ESCASO'),'2024-03-19','Está todo correcto , venía percibiendo nomina y PNC en cuantía reducida. Ha dejado de trabajar y ahora percibe una prestación por desempleo. PNC tiene su pensión suspendida hasta que se le envíe documentación sobre las nominas ( solicitadas y enviadas por Plena Inclusión Montijo ) y Declaración de la Renta de 2022( Estrella lo solicitó a una gestoría y está pendiente ).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2024-03-20','Ana: Escribo a Ana Castillo Foronda TS - FUNDACIÓN AUTISMO SUR (teayudamos@autismosur.es): "En relación al presupuesto del Neurólogo, el Jefe de la Sección Económica me indica que, gracias a lo que se le ha ido ahorrando, ahora Alex puede afrontar este gasto, al menos por un tiempo, pero indica, y copio literalmente, lo siguiente: “DEBEMOS OBTENER UNA ESTIMACIÓN DEL Nº DE SESIONES QUE PODRÍAN NECESITARSE Y DE LA PERIODICIDAD DE LAS MISMAS....IMPORTANTE: ESTOS CÁLCULOS SE REALIZAN TENIENDO EN CUENTA QUE NO VA A HABER GASTOS DE DESPLAZAMIENTO Y ALOJAMIENTO (QUE SERÍAN ENORMES PARA ESTE TUTELADO (BARCELONA)" ¿Cuándo le valore por primera vez el especialista, ¿podríais por favor hacerle esta consulta y que nos diga aproximadamente el número de sesiones y la periodicidad de las mismas? En cuanto a lo de los viajes a Barcelona, ya dijisteis que no es necesario, no obstante quiere que se le corrobore, pues para ese gasto sí que no le llegaría el dinero. Por otra parte, te adjunto la Revalorización Anual de PNC que ya hemos recibido."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2024-03-20','Buenos días, En relación al Auto de revisión de medidas de Rosa Serrano García, el Juzgado indica que: “Rosa está en tratamiento psicofarmacológico por TRASTORNO DE ACUMULACIÓN, COMPRAS COMPULSIVAS y DISTIMIA, entre otras, NO LE IMPIDE CONDUCIRSE DE FORMA AUTÓNOMA EN LAS ACTIVIDADES BÁSICAS DE LA VIDA DIARIA Y EN LAS INSTRUMENTALES. Quedó patente su CAPACIDAD para expresar su VOLUNTAD, DESEOS Y PREFERENCIAS. Establece una CURATELA ASISTENCIAL, respecto a los siguientes ámbitos: SALUD, para la asistencia en la prestación del consentimiento de tratamientos médicos y operaciones quirúrgicas COMPLEJOS. ECONÓMICO-JURÍDICOS-ADMINISTRATIVOS-CONTRACTUALES, asistencia para la realización de los actos MÁS COMPLEJOS del 287 del código civil (internamientos, ventas de propiedades, herencias, gastos extras, contratos, donaciones, renunciar a derechos, interponer demanda, préstamos, etc). Es decir, que para los actos que no son complejos, Rosa no precisa de nuestra asistencia. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PRUDENCIO'and edp.apellido1='RODERO'and apellido2='COMERON'),'2024-03-14','Ana: Correo de Ángel, A. Jurídico CTAEx, a Aseguradora AXA (autocorporaldefensa@axa.es): "En relación al expediente nº 9702857310 y en representación de D. Prudencio Rodero Comeron, curatelado por la Comisión tutelar de Adultos de Extremadura, enviamos Anexo I (propuesta de indemnización por lesiones temporales y por secuelas, por importe de 48.640,60 euros) y Anexo II (aceptación de la indemnización, incluyendo datos bancarios)."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MORENO'and apellido2='FOLLARAT'),'2024-03-20','miguel, me llama Maria Cadenas 824903608 para informarse de lo que ha pasado. Va a decirle a un secretario de Badajoz que hable con el de Villafranca y le explique que hay que modificar el Auto en los términos indicados por el notario. Me llama Coro 618817695, me va a enviar una factura de 2023 de cuando vendieron la primera tierra que su hna pagó la factura total y ha de abonarse 177€ por la tutelada, me enviará por email la factura explicandolo todo para que se lo envíe a la parte económica. Me llama José Santiago 661423311 para indicarme que ya está el expte en manos del fiscal y que pronto se resolverá la solicitud de modificación del Auto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANDRA'and edp.apellido1='SANDIN'and apellido2='HERNANDEZ'),'2024-03-20','Ana: Toni-Futuex, nos remite factura de la compra del PORTATIL MAC, adquirido en la tienda APP INFORMÁTICA MORALEJA SL, cuyo presupuesto se aprobó previamente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA VALLE'and edp.apellido1='PATARRO'and apellido2='CARMELO'),'2024-02-28','-Amalia : Valle tiene 60 años , es viuda sin hijos ni familiares . Ha estado 2.5 años ingresada en el Hospital San Juan de Dios de Almendralejo. Tiene 75% G.D. por diferentes patologías físicas , ictus , cáncer , cirrosis hepática ... Sin consumo de alcohol desde hace años pero con patologías derivadas del consumo. En la residencia está muy adapatada y también en el pueblo donde ha hecho amistades . Tiene una casa en Valencia del Ventoso , que al parecer ha dejado " cedida " para cuando fallezca a una amiga . Su estado de salud ha mejorado y a ella le gustaría volver a su domicilio . Pero en la propia sentencia la forense indica que sus ideas no están adaptadas a la realidad y que incluso antes de estar ingresada su estado era de situación de riesgo y exclusion . Su estado de salud no lo hace viable , he hablado con la Dtra. de la Residencia ( Paqui tf 924700808) y me dice que acude todos los meses al hospital por su tratamiento del cáncer . En Valencia del Ventoso , no se podría supervisar ni gestionar estos traslados al hospital , ni se garantiza la alimentación... La Ts de Fregenal indica que podría volver al domicilio activando SAD , Dependencia ... pero aún con todos estos servicios no se podría dar cobertura a su situación sanitaria y tendría que estar sola durante todo el día .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEREA'and edp.apellido1='DA COSTA'and apellido2='LORENZO'),'2024-03-20','Ana: correo de Mª Paz Casado, Psicóloga Clínica UHDAC (mariapaz.casado@salud-juntaex.es) a Soraya Masa. Me pone en copia: "Nerea D.C.L., con buena evolución y adaptación al funcionamiento de la Unidad, planteando actualmente pase terapéutico a su Centro de procedencia, te pido confirmación de la factibilidad para proceder, ya que la hermana de la paciente refiere que la información recibida del propio Centro es de no capacidad para su atención."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='FIGUEROA'and apellido2='RASTROLLO'),'2024-03-20','Ana: correo de Mª Paz Casado, Psicóloga Clínica UHDAC (mariapaz.casado@salud-juntaex.es) a Soraya Masa. Me pone en copia: "Comentar en relación a la situación de dos pacientes de la Unidad. Uno de ellos ya hemos hablado en anteriores ocasiones Cristofer F.R., en espera de que se le asigne plaza residencial para dar alta hospitalaria, con expresión de disconformidad creciente ante la prolongación de su ingreso y solicitando nuevo contacto (videollamada) con vosotros."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-03-20','ana: Correo de Estrella, S. Ecca: "te informo que se ha aceptado el presupuesto de Santa Lucía, en relación al seguro del hogar de José Manuel. Pagará 143,22 € al año, en un único pago"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='PEREZ'),'2024-03-20','-Amalia , registro petición para realizar un cambio en la petición de Centros de Discapacidad presentada ; eliminando de los centros solicitados el de LA PROVIDENCIA de Ribera del Fresno.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2024-03-21','Ana: Envío mail a Estrella, TS CSS, solicitando INFORMES MÉDICOS, para solicitud de valoración del Grado de Discapacidad y Revisión del Grado de Dependencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2024-03-20','Ana: Llamo a Mª Carmen, TS de la UHB - HSPA (56283) en relación al nuevo ingreso de Francisco. ······· Hablará con el Psiquiatra sobre la situación así como de las posibilidades de derivarle a UME. Y si considera conveniente hablar conmigo para que me llame o me diga cuando puedo llamarlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='RODRIGUEZ'and apellido2='ROBLES'),'2024-03-21','-Amalia : con respecto a si tenemos que darle un dinero para sacarse el carnet de conducir . Se solicitó al juzgado que se le retirara y no lo aceptaron. Vuelve a pedir el dinero para eso , Miguel informa : A mi entender…conforme la nueva ley 8/21 cumplimos su voluntad y deseos, porque no hay un impedimento judicial que establezca lo contrario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2024-03-21','Ana: Correo a Toni y Nieves, Ed. Futuex (delegadapoyo.caceres2@futuex.es): "...comunicaron que se aprueba el PRESUPUESTO DEL CÁTERIN “Qué bueno comidas” - Servicio mensual a domicilio para una persona 6,50€/día cubriendo TODOS los días de la semana (de lunes a domingo), con cenas: 315€/mes (aprox.) Por favor, ¿podríais encargaros de dar de baja el cáterin actual y contratar el que indicamos?. Comunicad, por favor, a la sección económica cuando sea efectivo el cambio, para poder abonar lo que se adeude en el actual y comenzar a abonar por transferencia el nuevo." ··································································································································· Respuesta de Toni: "Con catering el sol, intentamos dar de baja, a través de la compañera ya en otra ocasión y no nos fue posible, nos dijeron que alguien de la comisión tutelar debia ponerse en contacto directamente con ellos, la verdad que no le vemos el sentido pero asi, fue por lo tanto enviamos el numero de telelefono y el email del que se dispone, por se puediera desde el area eco, informar de la baja del servicio. Los datos son: amadora@solcatering.es y telefono ‎+34 927 27 82 36 Y se adjunta numero de cuenta de Que bueno comidas." ··············· Paso correo con información a la secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2024-03-21','miguel, Juan Carlos envía por tramita la solicitud de prorroga del Impuesto de Sucesiones (modelo 750) y lo guardamos en la carpeta herencia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2024-03-21','miguel, Juan Carlos envía por tramita la solicitud de prorroga del Impuesto de Sucesiones (modelo 750) y lo guardamos en la carpeta herencia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2024-03-21','Ana: Correo del Dr. Jesús Derecho Montes, Psiquiatra UHB (jesus.derecho@salud-juntaex.es): "Soy Jesús Derecho Montes, psiquiatra encargado del paciente Francisco Cacho Garrido, ingresado actualmente en la UHB de Psiquiatría del HSPA de Cáceres. He intentado contactar con vd. telefónicamente. Examinado hoy el paciente Francisco Cacho Garrido constato una mejoría clínica significativa, no presentando síntomas nucleares de su patología de base ni otros factores que contraindiquen un alta médica que, por otra parte, el paciente desea. Rechaza en estos momentos la opción de UME, refiriendo que buscará un recurso más duradero con la prestación que recibe, utilizando mientras tanto los disponibles que ya conoce y de hecho usa. La actitud del paciente es colaboradora y el discurso coherente. Por mi parte, si no experimenta cambios significativos, mañana le daré el alta médica." ········································································ Llamo al Dr. Dcho., se había planteado la derivación a UME, pero tiene serias dudas de que se lo rechazaran por falta de criterios de ingreso. Puesto que además Francisco está clínicamente estable y presenta "uso más que suficiente de sus facultades", posiblemente le darán el alta mañana. Tiene programada también para mañana una nueva analítica y realizará una reevaluación. ···· El propio Francisco conoce perfectamente los RR existentes y le gustaría, con el apoyo de la Educadora encontrar algo más estable. ········ Le expongo las dificultades que presentaba la semana pasada, de forma previa al ingreso tras el anterior alta. ··· Hablará con él al respecto e indagará. ······ Informo a Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2024-03-21','Ana: Envío correo a Toni, Futuex, con copia a Clara, Ed. y Ana Benavente, TS ESM: "En relación a MARÍA ANTONIA BERNARDO PIRIS, al parecer no deja de llamar a Miguel, Asesor Jurídico, diciendo que ha recuperado su capacidad y que liberemos sus cuentas. Por fin hemos recibido el auto de la revisión de las medidas de apoyo, os lo adjunto, para que además de poder leerlo, podáis llevarle una copia a ella y explicarle en qué consisten las nuevas medidas que otorgan a la CTAEX. *El testimonio de la FIRMEZA aún no lo hemos recibido (lo han reclamado ya), cuando llegue se podrá aceptar el nuevo cargo. Como podéis leer nombra a la CTAEx CURADORA con funciones REPRESENTATIVAS. Y Miguel, Asesor Jurídico, nos hace esta aclaración: “El Auto indica : En el fundamento tercero: Controla su economía, administrando diligentemente la cantidad de 400€ de la que le hace entrega la COMISIÓN TUTELAR. Realiza la compra de comida y abona el alquiler de la habitación en la que reside. Si bien es independiente en cuestiones básicas en el piso en que reside, es nula su conciencia de enfermedad, tomando los medicamentos que ella considera oportuno, tal como indica el fundamento cuarto. Y en el fundamento seis.- Por ello, la media de apoyo que se establece para la misma es la curatela con funciones representativas, alcanzando la misma únicamente los siguientes ámbitos: - a la toma de decisiones afectantes a su salud, y en particular, a su salud mental, debiendo cuidar EL CURADOR de que Dª. MARÍA ANTONIA acuda a las consultas y revisiones que el psiquiatra le tenga concertadas, y se adopten todas las cautelas precisas que garanticen que tome los medicamentos pautados por los médicos que le estén tratando en cada momento de su diagnóstico de salud mental, y - a los actos de especial trascendencia jurídica y económica a los que se refiere el art. 287 del CC, Y en el fallo se reitera, dentro de la curatela representativa, hace más incapié en el ámbito de la salud que en el patrimonial: 3.- Dª. MARÍA ANTONIA precisará la asistencia de dicho curador para: o la toma de decisiones afectantes a su salud, y en particular, a su salud mental, debiendo cuidar la COMISIÓN TUTELAR de que Dª. MARÍA ANTONIA acuda a las consultas y revisiones que el psiquiatra le tenga concertadas, y se adopten todas las cautelas precisas que garanticen que tome los medicamentos pautados por los médicos que le estén tratando en cada momento de su diagnóstico de salud mental, y o los actos de especial trascendencia jurídica y económica a los que se refiere el art. 287 del CC, en que LA COMISIÓN TUTELAR necesitará recabar autorización judicial Por tanto, no sé cómo se venía trabajando con ella, pero la resolución es clara cuando dice que ella actúa adecuadamente con los 400€ que le da la Ctaex.” *Por tanto, desde la CTAEx se va a seguir actuando como hasta ahora, teniendo en cuenta, como siempre se ha hecho, sus deseos y preferencias. Y con los apoyos necesarios y la supervisión en cuanto a su asistencia a citas programadas y demás cuestiones relacionadas. Pongo en copia a Ana Benavente, Trabajadora Social del Equipo de Salud Mental, para que por favor, nos mantenga informadas de TODAS las próximas citas programadas en el ESM y podáis, Toni, por favor, organizar la agenda para que Clara pueda acompañarle a las mismas. En el seguimiento que le hagáis, haced lo posible por “comprobar” si está tomando la medicación pautada. Si sospechaseis en algún momento, que no es así, por favor, comunicarlo tanto al ESM como a nosotros, para valorar qué y cómo podríamos hacer. También pongo en copia a Clara directamente, para que esté informada de la situación. Ya hablas tú con ella y organizas como consideres." ·································································································································································································· Respuesta de Toni: "Por ahora las tentativas de poder verla han sido infructuosas, se está en contacto con el Luis de Toro y se está intentando cuando acude alli, pero por el momento sin exito. Tiene cita el próximo 11 de abril y nos coordinaremos con la ts para intentar un primer contacto junto con el psiquiatra. Presenta resitencias pero no dejaremos de intentarlo y en el caso que rechace el apoyo informamos debidamente por si debe comunicarse al juzgado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2024-03-22','TERESA Supongo que estareis al tanto, pero Aitor no esta acudiendo a los controles de ECA y pasado mañana tenia cita y que pasa de ir tambien. Asique la via de CT , atraves de ECA sin acudir a controles, pues la tiene cerrada totalmente. Fue la primera semana pero ni siquiera orinó. Asique este muchacho sigue en una situación complicadilla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='DIAZ'and apellido2='ROMERO'),'2024-03-22','-ENVIADA A INMA Y EVA , SOLICITUD HF .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='VALERO'and apellido2='AGUEDO'),'2024-03-22','-Amalia : envío solicitud autorizacion general de salidas al director.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUSTAVO ALFREDO'and edp.apellido1='CASTAÑO'and apellido2='SOTO'),'2024-03-22','-Amalia : Escribo a Toni FUTUEX sobre las aclaraciones que me pide de el subsidio de excarcelación del SEPE. "Es compatible con su P. Orfandad si no supera el IPREM anual . También tienen en cuenta algunos datos económicos de la Declaración de Hacienda. Creo que tiene opciones de que se la den , si hago el cálculo sólo con la cuantía de la pensión. Que presente la solicitud y se la valorarán . Cómo va este chico en el domicilio ? En este caso es primordial seguimiento con el ESM , que acuda a citas y tenga adherencia a tratamiento . Insisto en que tengáis cuidado con estas visitas . Si está todo normalizado paso el caso para seguimiento a Ana .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='BERMEJO'and apellido2='TELLO'),'2024-03-22','Amalia : solicito al centro I.Social y Cdo. ingreso , pasarselo luego a Angel para solicitar el traslado a Avila.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2024-03-22','miguel, tras peticición de Escalona de informe social para el procedimiento de revisión de medidas de apoyo en el jzdo de Sevilla 6, envío email a la parte social y Angel e Inés: Buenos días, el juzgado de Sevilla nº6 ha iniciado el procedimiento de revisión de medidas del tutelado por requerimiento del juzgado nº5 de Cáceres. El día 4/4/24 será la vista. Desde la Comisión hemos enviado a abogacía y al juzgado el informe social que enviaron a Amalia desde el Centro Penitenciario de Sevilla que como veis viene sin rellenar Ayer me llamó Escalona para que le mande documentación y un informe social de la Comisión Tutelar de Adultos (dice que el económico no le interesa). En él habría que hablar de las medidas de apoyo que proponemos desde la Comisión. No sé si al final el hermano va a pedir o no la remoción del cargo. Que yo sepa a fecha de hoy no lo ha hecho. En el informe debéis indicar un poco los antecedentes y medidas de apoyo a adoptar. Hay que enviárselo la semana que viene que yo no estaré. Por lo que debéis dárselo a Angel e Inés. Yo voy a ir adelantándole la sentencia de incapacitación que es lo que básicamente me ha pedido, pues dice que no tiene nada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA REMEDIOS'and edp.apellido1='LOZANO'and apellido2='MUÑOZ'),'2024-03-22','Ana: Tras consultarlo con Amalia, que conoce y lleva el expediente, cumplimento la Declaración Anual de PNC, manteniendo el mismo domicilio y las cuantías de ingreso, aunque actualmente no está trabajando. Indica que lo deje así porque se prevé que vuelva a trabajar igual que en años anteriores. *Indico este hecho en al declaración. ······················ Actualizo cuantía en base de datos: 494,88 €','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2024-03-22','Ana: cumplimento y pongo para firma la Declaración Anual de PNC. ······················ Actualizo cuantía en base de datos: 776,85 €.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='MORALES'and apellido2='BOTELLO'),'2024-03-22','Ana: Cumplimento y pongo para la firma la DECLARACIÓN ANUAL DE PNC. ····················· Actualizo cuantía en base de datos: 517,90 €. ························ Modifico domicilio: CSS - Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MURILLO'and apellido2='ROMANO'),'2024-03-22','Ana: cumplimento y pongo para la firma la DECLARACIÓN ANUAL DE PNC. ·················· Incluyo ingresos en base de datos: 517,90 € (no constaba nada)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PILAR'and edp.apellido1='JIMENEZ'and apellido2='AGUILAR'),'2024-03-22','Ana: Llamada de Jesús, pareja de Pilar (72 145 510). Ha recibido un mensaje cambiando la cita con la Psiquiatra para el día 9 mayo. Aunque dice que le va a atender el mismo día que vaya él, ahora tiene la misma Psiquiatra, Rosa Galindo. Acudirán el 25 de abril a las 9:45 h. ······································· Ahora quieren volver a cambiar de casa. Pili no está a gusto porque dice que no tiene donde tender la ropa, que el único sitio que hay para tender lo ve la gente y no le gusta. ······························ Preguntan también por el seguro de decesos. Haré la consulta a la secc. ecca., pues en el expediente no hay nada al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='NUÑEZ'and apellido2='NAJARRO'),'2024-03-22','Ana: cumplimento y pongo para firma la Declaración Anual de PNC. ······················ Actualizo cuantía en base de datos: 517,90 €. ······························ Modifico domicilio: Residencia de INCLUSIVES Villanueva de la Serena.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2024-03-22','Ana: Llamada de Isabel de Cáceres, madre de Alfonso (680 784 490): "No estoy dispuesta a que vuelva a mi casa". ······· Dice que acaba de hablar con él y le ha dicho que a su casa no puede volver. ·· Éste le ha dicho que le libere la cuenta que se va para Madrid. ·· **No es consciente de su situación, del cargo de la CTAEx ni de su enfermedad. ························································································································································································································································· Respondo al correo de Estrella Durán, TS ESM (estrella.duranc@salud-juntaex.es) del día 20: "Tenía este correo pendiente. Precisamente acabo de hablar con Isabel. Dice que ha hablado con su hijo Alfonso y que ya le ha dicho claro que a casa no puede regresar. En semana santa tampoco. *Yo ya le dije en su día también a ella que debía decírselo. Isabel está realmente mal, se ha desahogado conmigo largo y tendido. Ya le he recomendado, aunque no me competa, que igual debe acudir a su médica para ajusto de medicación y/o derivación a apoyo Psicológico, cuanto menos. En cuanto la idea de irse a Madrid, él le manifiesta a Isabel que quiere que se liberen sus cuentas e irse a vivir solo. ¿A vosotras os dice que aceptaría centro allí? La madre me ha contado también que cuando vivían en Madrid, Leganés, le concedieron Centro de Día, pero él tampoco lo aceptó y fue imposible que asistiera. Por otra parte, Centro Privado con sus ingresos no se puede permitir. Y al estar empadronado, residiendo en Extremadura y en la red de salud mental de aquí, sinceramente no sé qué opciones hay para solicitar centro público de la Comunidad de Madrid. No sé si desde aquí me podéis orientar o si hay alguna fórmula para que desde vuestro propio centro se pida traslado a otra comunidad, no sé si se os ha dado alguna vez el caso, a mí no. Por otra parte, no está valorado por Dependencia, cuestión que podría ser necesaria para acceso a recursos tanto aquí como en Madrid. ¿Podrías por favor, solicitar a su médico somático (no sé quién es) el Anexo correspondiente – Informe de Salud, para solicitar valoración?" ································································································································································································ Correo-respuesta de Estrella Duran: "Isabel no ha hablado con su hijo de su negativa a que vuelva a domicilio. Hemos quedado con ella que el lunes día 1 que estará su otro hijo en el pueblo, vienen a Plasencia a decírselo, ya que le hemos insistido en que debe ser ella la que se lo comunique, no nosotras. Y sí, Isabel está muy mal, conmigo también se desahoga, intento liberarla de la culpa que siente... Lo de la idea de irse a Madrid, a lo mejor a la vuelta de Semana Santa, podíais hacerle una visita y tratar este tema con él. Desconozco cómo es el tema de que pueda ir a centro de Madrid, pensábamos que de CTA de Extremadura directamente con la de Madrid fuera fácil, pero lo desconocemos... El informe de salud, se lo pido a Rosa su Psiquiatra y a su Médico Somático y te lo envío después de semana santa." ··············· Nuevo correo de Estrella: "en la solicitud de dependencia de Alfonso, debéis hacer constar que va por la Instrucción 47 (yo lo pongo arriba del todo a boli) para que lo valoren las Terapeutas del centro, en vez de las de dependencia, por lo que poner en notificaciones a efectos de domiciliación, la dirección de este centro: Centro Socio-Sanitario de Plasencia Ctra de Cáceres s/nº 10600 Plasencia"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MOYA'),'2024-03-22','-Amalia : se deben 40€ de reintegro para pagar al cerrajero . Le doy contacto de empresa de limpieza a la Dtra. buscará presupuestos para limpieza integral de la casa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GREGORIO'and edp.apellido1='LOPEZ'and apellido2='CABRERA'),'2024-03-22','Miguel : Inés, una vez sea firme la sentencia pide el testimonio y en cuanto llegue envíaselo a la parte económica para que quiten al representante de la Comisión de las cuentas de Gregorio, que deja de tener medidas de apoyo y habremos de darle de baja en la Comisión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2024-03-21','Maite: ha llamado la madre de Julia. Está ingresada en la UCI en el hospital San Pedro de Alcántara. Está grave. La madre no sabe explicarme qué ha pasado. He llamado a Maricarmen, travajadora social de la UHB ( es el contacto que teniamos) . Se va a pasar por UCI para darnos información. Julia madre, me ha pedido dinero de la cuenta de Julia para cubrir los gastos de comida los días que esté ingresada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUSTAVO ALFREDO'and edp.apellido1='CASTAÑO'and apellido2='SOTO'),'2024-03-22','-Amalia : solicito a Toni ( FUTUEX ) información sobre el seguimiento de Gustavo y cómo va funcionando en el domicilio tras su excarcelación. Lo adjunto : " En principio la interacción con el, se esta desarrollando sin complicaciones, está tranquilo y parece tener adherencia al tratamiento, está tambien permitiendo que se le apoye en aspectos como la organización para hacer la compra. Según el comenta, le iban a ver antes de semana santa, pero no tenemos conocimiento exacto de la proxima cita de salud mental, intentaremos averiguarlo. Y desde el programa no se hacen seguimientos, de la compañera en la casa, si no que se le ve siempre fuera, para extremar un poco las condiciones de seguridad, pero por el momento está tranquilo y no presenta problemas conductuales. El otro dia pasamos una nota economica, que a el , le apremia. Lo pasé a Ana, pensando que ya estaba en su zona. Solicita un extra para ropa, que si no pueden ser 200 decia que se le concediera algo menos, pero insistia mucho en eso. Si se pudiera valorar, porque la hermana viene en semana santa y es cuando pensaban ir a comprar, seria perfecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2024-03-22','Maite:he hbalado con la trabajdora social del hospiatl. Me ha dicho que Julia está muy grave. Todavía es pronto para dar un pronóstico. Su madre se la encontró inconsciente y llamó al 112. Ha sido por una ingesta de pastillas pero no sabe cuales ni cuantas. Está entubada pq tiene problemas respiratorios. Hemos auorizado 120 € a la madre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUSTAVO ALFREDO'and edp.apellido1='CASTAÑO'and apellido2='SOTO'),'2024-03-22','-Amalia : Se finaliza con la petición del subsideo en el SEPE a esperas de que resuelvan. Se solicita un extra de 200€ para ropa a la S.eco. El caso pasará ya a seguimiento a la zona de Cáceres .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2024-03-22','Ana: Envío correo a Amadora, Catering Sol (amadora@solcatering.es) con copia a Toni-Futuex: "Tal y como acabo de hablar con Belén (927 27 82 36) mediante conversación telefónica, en relación a JUAN JOSÉ GONZÁLEX CARRERO, solicitamos la baja de servicio de cáterin a partir de primeros de abril. Es decir, la semana que viene será la última que utilice vuestro servicio. Sabemos que el próximo reparto incluye hasta el día 2 de abril, martes, esa sería la fecha a partir de la cual se daría de baja. Comunicaros, así mismo, que el motivo es estrictamente económico, pues su situación no le permite permitirse este gasto si quiere/necesita cubrir otros, pues él hasta el momento se ha mostrado contento tanto con la comida como con el servicio en sí. Ante cualquier cuestión, no dude en contactar. Pongo en copia a la coordinadora de su educadora de referencia para que estén al corriente." Comunico todo a la sección económica. ··········································· Correo-respuesta de Amadora - Caterin: "Tomaos nota y damos de baja el servicio con la fecha indicada. Seguimos estando aquí para cualquier necesidad."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2024-03-22','miguel, tras recibir nuevo email de la compradora instandonos al levantamiento registral de la hipoteca de la calle hinojo. Hablo con Jacinto de la notaria quién se ofrece para que en la notaria se firme la escritura de cancelación y me da los datos de una asesoría PROYEC.CONSULTORES TLF. 924.45.41.27. Previo pido autorización a Alberto para poder tramitar dicha cancelación. Llamo a la asesoría y me dan un email Veronica González Rodríguez >administracion@proyecconsultores.com> para enviar la documentación y me contesten a principios de abril: Buenas tardes, conforme hemos hablado por teléfono adjunto la escritura de compra en su día por el curatelado por la Comisión Tutelar de Adultos de la Junta de Extremadura, D. Juan Carlos Rubio Galán, así como la de venta, junto con nota simple, certificado de la deuda pendiente con Caja Badajoz cuando se firmó, y los testimonios firmes judiciales de incapacidad, nombramiento a la Comisión Tutelar de Adultos de la Junta de Extremadura y la aceptación del cargo de curador por la Comisión Tutelar de Adultos. Necesitamos estudiéis el trámite a realizar y os indiquéis vuestros honorarios para este trámite. En su día la venta la tramitó Jacinto de la notaria de Montijo, quién me ha comentado que ellos pueden tramitar la firma de la cancelación de la hipoteca también, por si queréis hablar con él. Los datos de contacto de la compradora por si los necesitáis son: Ana María Muñoz Toro >anamariamt99@gmail.com> Llevamos 3 años intentando que la oficina de Caja Badajoz nos facilitase los datos de su asesoría para que lo hubiesen tramitado pero de los pocos emails a que han contestado se entiende que han ido cambiando de directores y personal y ninguno nos ha hecho caso. Quedo a la espera de vuestra respuesta','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2024-03-22','Ana: Correo de Sonia, TS Asindi: "te escribo para decirte que estaba previsto que los hermanos Hernández Castaño se fueran a casa, pero he hablado con su madre y me dice que está cuidando de su nuera y no puede trasladarse ni a Villar del Rey ni a Cáceres para poder estar con sus hijos. He informado a Justo y a Roberto y están contentos porque van a ser tíos nuevamente y por ese motivo su madre está con su cuñada y con su hermano. En estos días te mando los calendarios de Abril, Mayo y Junio con los viajes previstos en esas fechas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2024-03-22','Ana: Correo de Sonia, TS Asindi: "te escribo para decirte que estaba previsto que los hermanos Hernández Castaño se fueran a casa, pero he hablado con su madre y me dice que está cuidando de su nuera y no puede trasladarse ni a Villar del Rey ni a Cáceres para poder estar con sus hijos. He informado a Justo y a Roberto y están contentos porque van a ser tíos nuevamente y por ese motivo su madre está con su cuñada y con su hermano. En estos días te mando los calendarios de Abril, Mayo y Junio con los viajes previstos en esas fechas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2024-03-22','Ana: Correo-respuesta de Ana Castillo Foronda TS - FUNDACIÓN AUTISMO SUR (teayudamos@autismosur.es): "Con respecto al correo de las citas con Neurología, en la primera sesión preguntaremos cuantas serían necesarias, estimamos que no serían muchas, pero aún así le preguntaremos al especialista para que nos confirme y nosotros comunicároslo." ································································································································································································· Respondo: "Perfecto, gracias. En cuanto al abono del tratamiento, entiendo que podrá realizarse mediante transferencia bancaria. Para lo que necesitaríamos que las facturas, a nombre de Alex y con número de cuenta de abono, se fueran enviando a la atención de la sección económica, a la dirección: ctutelar@salud-juntaex.es tras cada sesión para que puedan encargarse del pago."','2');
