insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2024-03-25','Ana: Pongo para la firma la DECLARACIÓN ANUAL DE PNC. ·············· Actualizo la cuantía en la base de datos: 517,90 €. ······································· Actualizo domicilio. Avda. Virgen de Guadalupe, 89. Casa nº 4- Helechosa de los Montes (Badajoz). ··············· Así mismo, indico en la Declaración que ha salido de C. Penitenciario el día 22/03/24 y los ingresos que percibía en ésta ya no los va a percibir.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2024-03-25','Amalia : he hablado con él por tf , ha estado en el médico y ya lo han derivado también a las consultas del ESM como le indiqué . La semana que viene irá la Delegada tutelar a visitarlo y canalizará lo que pueda ir necesitando. El tema económico , me dice que tiene 2 cuentas en Ibercaja , y una está en descubierto . La quiere cancelar , pregunto a S. eco si se puede hacer . Les indico : En el pueblo sólo hay una entidad bancaria , no sabe exactamente cuál es . Se va a informar y nos dará esos datos . Tendríamos varias opciones , cambiar la pensión a esa entidad bancaria y cerrar la de Ibercaja . O una tarjeta bancaria de recarga, porque en el pueblo sí hay cajero para sacar . O una transferencia a la cuenta del padre, para que saque el dinero en el pueblo. Ibercaja le cae lejos y tiene que pagar un taxi que le cobra 50€, con una pensión mínima es inviable. Quedamos pte. de la respuesta sobre la entidad que hay en el pueblo para poder decidir la mejor opción.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2024-03-22','Ana: Nos remiten desde el ESM (equiposaludmental.caceres@salud-juntaex.es) Informe de la última consulta en Psiquiatría, 14_03_24 y Reprogramación de la próxima cita: 4/4/24 a las 13 h.·························· Comunico a Toni y Nieves, Ed. Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUSTAVO ALFREDO'and edp.apellido1='CASTAÑO'and apellido2='SOTO'),'2024-03-25','Ana: Correo de Amalia, TS CTAEx del viernes 22: "estoy haciendo gestiones con este chico, percibe P. Orfandad de Clases Pasivas por importe de 819€ al mes. Es compatible con el subsidio de excarcelación del SEPE, lo va a solicitar. Ya le he pasado a la delegada tutelar la documentación necesaria , ya se ha aportado la solicitud y a esperar que el SEPE resuelva. Aunque es compatible hay un límite económico que no se puede superar y él va a estar en el límite. Me dice Toni de FUTUEX que te ha pasado una solicitud de 200€ para ropa, creía que el expediente lo llevabas tú. Me encargo de esa solicitud y ya lo paso a tu zona para seguimiento. Está funcionando muy bien en domicilio y está tranquilo. He pedido a la D. Tutelar que sobre todo supervise citas con ESM y tratamiento. En la intranet puedes leer el último informe de seguimiento desde Futuex y el Plan de Intervención que se definió para él , con los reintegros mensuales"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIO'and edp.apellido1='GUISADO'and apellido2='GUISADO'),'2024-03-25','TERESA Buenos días: La oncologa estaba pendiente de la decisión del Sepad ,si la decisión es Badajoz y se le busca plaza allí, no hay problema. 70 puntos ...pues no lo sé si será para T2 ,eso lo valora el Sepad así que vosotros tendréis más facilidad que yo lo podéis preguntar, yo se lo he pasado a Lola nuestra Trabajadora Social para que lo gestione con Vosotros . Me acaban de Llamar de Hospital Don Benito para ponerle el acceso Venoso Central ,( Porta k) en el hospital Santa Justa de Villanueva el Viernes 5 de Abril a las 15:00 h ..... Te mandaré consentimientos en cuanto me lo digan . Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL MAR'and edp.apellido1='CAMPOS'and apellido2='ENCINAS'),'2024-03-25','Ana: Envío a A. Jurídicos CTAEx: "Os reenvío el Informe que nos remite la Dra. María Plaza Terán, Médica de Atención Primaria de MARÍA DEL MAR CAMPOS ENCINAS, solicitado para la revisión. Como podéis leer, dice que no la conoce y que en el último año no ha sido valorada en el centro y no constan en el Jara problemas de salud crónicos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2024-03-25','TERESA He hablado con el ECA de Cáceres. La derivación de Aitor a comunidad terapeútica todavía no se ha hecho; su médico se ha jubilado y tienen que asignarle otro, además no ha acudido a la cita con la psicológa. Este caso está muy muy complicado.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL MAR'and edp.apellido1='CAMPOS'and apellido2='ENCINAS'),'2024-03-25','Ana: Envío a A. Jurídicos INFORME SOCIAL para la REVISIÓN DE LAS MEDIDAS junto con el resto de documentos aportados (Informe Vida Laboral, Cdo. Catastro, Cdo. Convivencia, Cdo. Empadronamiento, Cdo. negativo prestaciones SEPE, Cdo. Imputaciones IRPF, Cdo. Titularidad Bines Ayto.)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='VAZQUEZ'and apellido2='MUÑOZ'),'2024-03-25','-Amalia : Jonathan efectivamente tenía la P. Entorno cuando vivía en su casa y tenía G. III ; antes de pasar a ser curatelado. Actualmente tiene G.I., está en La Luz a la espera de plaza ( pte. respuesta de Soraya ) y esa P. Entorno está dada de baja .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUSTAVO ALFREDO'and edp.apellido1='CASTAÑO'and apellido2='SOTO'),'2024-03-25','-Amalia : Paso citación judicial para medidas de apoyo (el día 4 de abril a las 11.25h en los juzgados de Cáceres) a FUTUEX para que lo acompañen. A partir de abril el caso pasa ya a la zona de Ana para seguimiento , ya se lo he comunicado. Queda solicitado los 200€ extra para ropa a S. eco. Las citas con el ESM están ya supervisadas con la Delegada Tutelar. Ha solicitado subsideo de excarcelación del SEPE ,pendiente de resolución, va a quedar al límite , puede tardar la resolución.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2024-03-25','Maite: he hablado con el ECA de Cáceres ( Pilar trabajadora social 54621). No ha hecho la derivación de Aitor a comunidad terapéutica pq todavía no lo ha visto el médico( el suyo se ha jubilado y le tienen que asignar otro)y tampoco la psicóloga ya que no se presentó a la cita que tenía con ella el pasado 22 de marzo. Me dicen que tenemos que pedir cita de nuevo. He enviado un correo a Soraya para informala sobre la situación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSEFA'and edp.apellido1='MOYA'and apellido2='GARCIA'),'2024-03-25','TERESA RECIBO EMAIL DE TONI SABIDO voy a pedir la resolución T3 para Mª Josefa Moya Gonzalez en Sierra Pinar Zafra','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDREA'and edp.apellido1='GUERRERO'and apellido2='ZAMBRANO'),'2024-03-25','-Amalia : pregunto a Angel por la venta de la casa , no tengo información actualizada y le paso datos de la vecina interesada en comprar la otra vivienda , una pequeña que es practicamente un solar para que proceda igual . Angel , de esta señora el juzgado autorizó a la venta de una vivienda ( la que quería comprar el dueño de la tienda que hay en la planta baja ) . Una duda , este señor ya ha abonado todo el dinero y ha formalizado la compra ? Te paso datos de otra vivienda , es prácticamente un solar que también interesaría vender . Se podría arreglar algo con el dinero de la venta anterior , pero no tiene sentido echar allí nada de dinero . Con esa misma autorización se podría vender ésta otra ? Ya nos dices.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='CASTAÑO'and apellido2='TORNAVACA'),'2024-03-25','-Amalia : le pregunto a los juridicos sobre la deuda del procurador que envia la hija para que la abonemos. Me indica Angel que no tiene que abonarla Agustín si no su hija . Se lo paso a la residencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2024-03-25','-Amalia , escribo a Marga del Ctro. Pentin. de Estremera: la declaración anual de PNC se hace desde aquí , vamos a comunicar el cambio de dirección actual a la Comunidad de Madrid que no se había comunicado, puesto que parece que va a pasar allí bastante tiempo . Me ha dicho Jonathan que hace 2 semanas tuvo un juicio por videoconferencia y que próximamente bajará a Badajoz por otro juicio . Cuando tengáis información sobre los mismos nos contáis por favor.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIO'and edp.apellido1='GUISADO'and apellido2='GUISADO'),'2024-03-25','TERESA REGISTRO SOLCITIUD DE T3 PARA EUGENIO GUISADO, HAY UNA VACANTE EN BADAJOZ SEGUN ME INFOMRA TONI SABIDO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='SAYAGO'and apellido2='HERNANDEZ'),'2024-03-18','-Amalia : reenvío Diligencia donde se señala para comparecencia el 12/03/2024 a las 9:30 a Josefa Sayago Hernández, referente a la Revisión de Medidas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2024-03-25','-Amalia: Nos informan desde CRR del deseo de las hnas. de vender el piso familiar . Esta es la respuesta de Miguel que paso a Melania : "hay suficiente dinero para afrontar una venta, si es el deseo de las hermanas y de Manuel. Que se pongan en contacto conmigo las hermanas o la notaria donde se quiera firmar todo para hacer constar la tutela de Manuel Contador Mateos." firma miguel 2024 De: ALBERTO MARTIN ROSETE >alberto.martinr@salud-juntaex.es> Enviado el: jueves, 29 de febrero de 2024 9:52 Para: MIGUEL FERNANDEZ DE LLERA >miguel.fernandezd@salud-juntaex.es> Asunto: RE: SITUACIÓN MANUEL CONTADOR MATEOS MIGUEL: LA SITUACIÓN ECO DEL TUTELADO ES BUENA. SALDO 29/02/2024: 44.599,71 € EVOLUCIÓN ANUAL DEL SALDO: MUY POSITIVA. DE TODAS FORMAS, ENTENDEMOS QUE ESTA VENTA VA A SUPONER PARA EL UN INGRESO Y DEJAR DE ABONAR GASTOS, NO? EL ESTÁ ABONANDO CONSUMOS DE VIVIENDA EN AVD ANTONIO MASA CAMPOS 1 6 3 A - BADAJOZ. EL ESTÁ ABONANDO SEGURO DE HOGAR . ESTO ES INFORMACIÓN SIN MUCHO DETALLE QUE TE DOY.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='VALERO'and apellido2='AGUEDO'),'2024-01-22','Amalia : Natalia está en un centro de menores , hablé con el director y no hay copago en estas plazas . Además intentarán cubrir desde el centro todos los gastos que sean posible , incluido los reintegros . Sólo van a solicitar algún gasto extra como este de dentista que ellos no pueden cubrir . Iciar confirmó que le han ingresado la retroactividad de la prestación que le tramité . " Le he comprobado la cuenta y el 11 de diciembre le han entrado 906,60 € de la TGSS" Cuenta con esos ahorros y los ingresos mensuales de la prestación. Se autoriza el tto. dental .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2024-03-04','Amalia : se envia solicitud SAD para Carmen Leal . Faltaría que lo firme ella y si podéis lo remitís a SSASB .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='SAYAGO'and apellido2='HERNANDEZ'),'2024-03-11','-Amalia : comparecencia el 12/03/2024 a las 9:30 referente a la Revisión de Medidas, se hizo desde el CSS por videoconferencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2024-03-25','-Amalia : escribo a Gisela del CRR a su consulta : "el tema de la vivienda de Mari Loli es recurrente en ella. Siempre quiere arreglar o mejorar cosas del domicilio ,pero quien vive allí es su hermano y no ella . Estamos pendientes que la llamen para pasar a R. Mayores y allí hay copago , creo que lo más prudente es que ahorre para posibles gastos que pueda tener . De todas formas , nos puedes remitir los presupuestos que haya pedido sobre aquello que quiera reformar . Yo se lo pasará a la Sección económica para su valoración. Cómo se encuentra ? Hable con ella la semana pasada , ya está dandoles vueltas a la cabeza , porque quiere una u otra residencia. Ya le he explicado que no elegimos , ni ella ni la Comisión . La llamarán para cubrir la plaza que quede libre en cualquier parte de Extremadura , que es lo que ella ha querido al ampliar las plazas . Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2024-03-25','-Amalia : escribo a Miguel para el procedimiento de revisión de medidas : "ya indiqué en ese informe que os he enviado , que iba dirigido para el centro penitenciario de Sevilla los datos que yo conozco. El Informe tendrá que solicitarlo el juzgado al Centro penitenciario de Sevilla . Saturnino ha pasado allí derivado desde el CSS de Plasencia y ha estado en seguimiento por Ana . Desconozco qué medidas de apoyo pudiera necesitar . No sabéis si el juzgado ha llamado al hermano que quiere ser tutor ? Facilité todos los datos del hermano , se supone que tendría que citarlo el juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2024-03-11','-Amalia ; escribo a Miguel : adjunto el formulario que solicita el Jdo. de Sevilla nº 6 para la Revisión de medidas . Su hno. Francisco está interesado en ejercer el cargo de curador, facilito sus datos en el documento . Se pide también junto al formulario la partida literal de nacimiento ,en el expediente no la tenemos. Con respecto a informes médicos y medidas de apoyo a plantear, el juzgado tendrá que pedir esos informes al Centro penitenciario psiquiátrico de Sevilla donde se encuentra ingresado procedente del CSS Plasencia. Sobre la cuestión de plantear traslado del expediente a Andalucía , en mi opinión , no lo van a estimar , dado que su ingreso terminaría según sentencia en diciembre de este año ( según lo anotado en la intranet por Ana ) .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2024-03-25','-Amalia : escribo a Manuela , TS del Ctro. Penti, Sevilla , le envio citación revision medidas de apoyo para el 4 de abril y le paso el informe que envié la jgdo. de Sevilla con los datos del hermano que quiere ser tutor.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSEFA'and edp.apellido1='MOYA'and apellido2='GARCIA'),'2024-03-26','TERESA ARCHIVO RESOLUCION PLAZA T3 EN SIERRA PINAR IMPORTE DE LA PLAZA 1.168,56 €/MES REVISIO ECO PARA DAR DE BAJA A SUMINISTROS SI SE ADAPTA AL CENTRO EN TRES MESES','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIO'and edp.apellido1='GUISADO'and apellido2='GUISADO'),'2024-03-26','TERESA SE LE ADJUIDCA PLAZA T3 EN BADAJOZ','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-03-26','Ana: Llamada de José Manuel. En relación al SAD, dice que discutió con al Aux. que iba habitualmente porque no quería tenderle la ropa, vaciar los ceniceros, etc. La echó de su casa y habló con la coordinadora del servicio. Le recuerdo que no tienen por qué vaciarle los ceniceros, que eso lo puede hacer él y la ropa también puede tenderla y que además debe tratar a las Aux. con educación y con respeto. ···· Empezó a ir otra Auxiliar y ahora dice que no quiere que vaya más esa y quiere que vuelva la anterior. Ha hablado con Ana, la coordinadora de nuevo. ····················· En cuanto al CÁTERIN, verbaliza que ya no lo quiere, que lo que quiere es que le demos un dinero a su hermano para que éste le haga la compra y le lleve comidas caseras. *Le indico que en tal caso, su hermano nos envíe un correo comunicando que él está dispuesto a asumir ese compromiso. ······················· Por último, comunica que ha recogido una notificación del Jdo. sobre la multa que tiene que abonar. Le dirá a su hermano que la envíe por correo a los A. Jurídicos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PALOMA'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENEZ'),'2024-03-26','TERESA Te enviamos esto, porque ya está Paloma, haciendo de las suyas, y comenta que hablado contigo y le has dicho que se iba a pagar, pero te aviso para que no PAGUEIS AL TAXISTA, te explicamos por que: Por un lado, Paloma tenía una deuda con el taxista que la lleva en Jerez a todos sitios, si va al médico, a comprar, etc. llama al taxi, nunca va andando, como sabe. Él confiaba en que le pagara a fin de mes, cuando cobrara su padre, así lo venían haciendo desde hace tiempo. Este mes decía que ya tiene mucho que pagar cuando cobre su padre (como facturas que le debe a la casera) y no puede hacer frente a la deuda del taxi. SE ha hablado con Julio esta mañana, el taxista, y decía que le daba pena pero ya no puede más, le ha dado comida en muchas ocasiones incluso, pero considera que se está riendo de él y si no le pagaba, la denunciaría por impago. A media mañana comenta que le ha pagado Paloma, ya los 197€ que le debía, pero que ella le ha dicho que no nos diga nada y que cuando se lo ingresen a él, que él se lo de a ella. >>>>>ha pedido que informe lo que sea necesario, porque debe saberse lo que hace, pero que no le digamos nada a ella, que lo mete en un lío rápidamente, que ella es así... Paloma ha llamado diciendo que no le había pagado (siendo mentira) y que ha hablado contigo y ha autorizado que se haga la gestión, que van a pagarlo, por lo que se informa de la situación. Por otro lado, en una de las visitas rutinarias a Paloma se ha aprovechado que le tocaba retirada para acompañarla. Mientras íban al banco nos ha parado una señora que estaba abriendo su tienda y un poco enfadada y molesta nos ha pedido que pasemos. Comenta que Paloma debe en ese establecimiento 79,15€ desde el 10 de septiembre de 2022. Con toda la confianza le dieron los artículos y le dieron la facilidad de pagarlo poco a poco, afirmaba que lo haría, no fue con ninguna educadora ni pidió presupuesto. Se lo han recordado varias veces por las buenas, le han dicho que fuese dando un poco al mes para ir bajando el importe y poco a poco pagarlo, pero nada, pasado tanto tiempo sigue sin pagarlo. Se le ha explicado a la señora que no le den nada, sin previamente pago o presupuesto para su autorización. Se pidió la factura y el número de cuenta por si se decide pagar por ese medio, aunque ya se le ha explicado que nadie le autorizó en su momento hacer esa compra y, por tanto, puede que no se pague y tenga que hacerlo ella misma. Se adjunta el ticket y se resume aquí: TIENDA ROJO5 Fecha de la compra 10/09/2022 Importe 79,15€ Número de cuenta ES67 2080 3571 6130 4000 7428 Esto es todo, un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2024-03-26','Ana: Respuesta a los últimos correos del Estrella, TS CSS: "...Vamos por partes: - La madre me dijo que había hablado con él por teléfono y se lo había dicho justo antes de hablar conmigo, si no me dijo la verdad, ya lo desconozco. - Lo de que acuda con su otro hijo en persona, me para parece perfecto. De eso no me habló y tampoco me dijo nada de que su otro hijo fuera a visitarla. - Lo de las remociones de cargo no funciona así. Ya nos gustaría en muchos casos. Primero tendría que irse a vivir a Madrid y empadronarse allí para poder solicitar al Juzgado de allí, desde Abogacía General de la Junta, qué sea la institución tutelar de Madrid, en este caso, la que asuma el cargo. Para irse a vivir allí primero necesitaríamos un recurso residencial y entiendo que para el acceso a los mismos, será un proceso y requisitos similares a los de nuestra Comunidad Autónoma. - Otra cuestión sería que fuera a centro privado de forma voluntaria y una vez allí solicite plaza pública. Pero como sabes él no puede costearse plaza privada. - Por otra parte, no creo que reúna requisitos (desconozco protocolo y criterios) para hacer una canalización externa a otra Comunidad. - En cuanto a los informes, perfecto, gracias. *Tal y como indicas en tu otro correo: especificaré “que va por la Instrucción 47”."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PRUDENCIO'and edp.apellido1='RODERO'and apellido2='COMERON'),'2024-03-26','Ana: Correo de Lourdes, Secc. Ecca.: "Hoy 25 de marzo, han cargado en la cuenta de Prudencio la indemnización por el accidente, 48.640,60€, junto con la pensión. Su saldo actual es de 49.497,23€" ·············· Pido que desde la secc. ecca. se pongan en contacto con el centro para saldar la deuda con el mismo. ··· Y con el resto de deudas que disponga Alberto, Jefe Secc., el orden de abono.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PILAR'and edp.apellido1='JIMENEZ'and apellido2='AGUILAR'),'2024-03-25','Ana: Correo de Esterella, S. Ecca., aún no ha podido formalizarle el Seguro de Decesos a Pilar. En cuanto lo haga me lo comunicará.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANICA'and edp.apellido1='MEMET'and apellido2=''),'2024-03-26','TERESA He ido hoy a la consulta del cirujano con Amica Memec. En un principio me ha dicho el cirujano que le harían una mastectomía, que no le pondría ningún tratamiento de quimioterapia ni de radioterapia, solo con la intervención sería suficiente. Justo cuando he vuelto del hospital, me ha llamado por teléfono para decirme que ha hablado con los oncólogos y no han considerado la opción de la intervención, que han pensado en darle un tratamiento hormonal para bajar la inflamación y después consideran la intervención.De momento estamos a la espera de recibir la cita para oncología. Te vamos informando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2024-03-26','TF JOSE VICENTE : 613816265','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='AVILA'and apellido2='FEMIA'),'2024-03-26','Ana: Envío correo a Maite y Alberto, con copia Ángel - CTAEx: "En relación al Informe y documentos que nos remite la TS de Aliseda, nº de Colegiada 10-522 (no se identifica), pongo en copia a Alberto, porque esto le vendrá mejor a él que a nosotras. Excepto el DNI y la Tarjeta Sanitaria, todo lo demás es de tipo económico. El informe, en mi opinión, no se debería llamar Informe Social, pues no detalla nada de la situación de la persona, ni de las relaciones familiares, ni de la vivienda, ni de su salud, ni discapacidad, ni en concepto de qué tiene aprobada una Prestación Vinculada de Dependencia, ni el grado reconocido de ésta… Todo lo que detalla tiene relación con los bancos y similar. Con respecto a necesidad de ingreso involuntario que dice Ángel (le pongo también en copia), tampoco viene nada. Ahora leeré la sentencia, pues a este respecto, este informe y nada es lo mismo… También dice que aporta Certificado de Empadronamiento y no es así, se le habrá olvidado, porque no viene." ·································································································································································································· Según PARTE DISPOSITIVA del TESTIMONIO DE AUTO: "Para el ejercicio de las medidas de apoyo, se constituye la CURATELA de D. JOSE LUIS AVILA FEMIA, que será ejercida por la COMISION TUTELAR DE ADULTOS DE LA JUNTA DE EXTREMADURA La curatela será ASISTENCIAL en los siguientes aspectos: Asistencia en las citas médicas a las que tenga que acudir el discapaz, tratamiento médico, toma de medicación y demás cuestiones relativas a la salud física y psíquica, autocuidado, alimentación, viajes, compras, vida doméstica, necesidad de internamiento en su caso, y en general, ayuda y supervisión en las actividades básicas de la vida diaria. La curatela será REPRESENTATIVA en los siguientes aspectos: Administración de los bienes y disposición de los mismos, manejo de dinero, solicitud de créditos, transacciones" + "Se acuerda el INTERNAMIENTO NO VOLUNTARIO POR RAZONES PSIQUICAS DE D. JOSE LUIS AVILA FEMIA EN UN CENTRO RESIDENCIAL ADECUADO A LAS NECESIDADES DEL DISCAPAZ, ATENDIENDO A LA SITUACION PSIQUICA Y/O PATOLOGIAS QUE PRESENTA. Ofíciese al SEPAD a fin de que indiquen un Centro adecuado para tal fin." ··································································································································································································· Envío correo a Maite, Jefa Secc. CTAEx y a Soraya Masa, Jefa U.PP.AA., con copia a Ángel, A. Jurídico: "Os envío Testimonio de Auto de Medidas de Nombramiento relativo a D. JOSÉ LUIS ÁVILA FEMIA, persona cuyo cargo de CURATELA CON FUNCIONES REPRESENTATIVAS se ha aceptado recientemente por la CTAEx. A lo largo del documento podéis leer la situación en que se encuentra dicha persona, sobre todo en lo relativo al examen practicado por el Médico Forense. Así mismo, os copia uno de los últimos párrafos de la parte dispositiva: ... Adjunto también: - Informe Forense - Informe Social, emitido a fecha de 8/11/22 y remitido al Juzgado para el procedimiento de provisión de medidas de apoyo. El remitido para el inventario sólo refleja cuestione económicas. Soraya, por favor, dinos si quieres hablar primero tú con quien corresponda o si activamos directamente internamiento involuntario para INGRESO primero en UHB, para valoración, diagnóstico y posterior derivación a UME, o cómo debemos proceder."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2024-03-26','Ana: Correo de Toni-Futuex: Tanto al ctutelar@ como a mi correo: "María Luisa Montaña Aliseda llevo algún tiempo solicitando un móvil más moderno que el que tiene porque es muy antiguo y no funciona bien. Se adjunta un presupuesto de un terminal que es de los más económicos y básicos para lo que lo quiere ella, que es poder hacer videollamada con su hija y con su hermana que viven en Don Benito." ···························· Indico a la secc. ecca. que por mi parte ok al presupuesto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2024-03-26','Ana: Correo de Toni-Futuex, tanto al ctutelar@ como a mi correo: "La cuñada de Juanjo Maseda del Sol indica que a este se le ha estropeado el móvil, concretamente la pantalla y que han ido a preguntar si lo cubre la garantía y le han dicho que no. Ahora mismo Juanjo está sin poder utilizar el teléfono, que es primordial para él y que su familia pueda contactar con él, ya que hace mucha vida fuera de casa. Solicitan que se pueda comprar otro teléfono, y se adjunta también un presupuesto de un móvil para él (más o menos con las características que el suyo anterior)." ······································· Indico a la S. Ecca. que si es viable, ok al presupuesto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='AVILA'and apellido2='FEMIA'),'2024-03-27','Ana: Correo de Ángel, A. Jurídico a Soraya, Maite y a mí: "En relación con este internamiento, Abogacía nos ha trasladado Diligencia de Ordenación en la que el Juzgado nos solicita alegaciones, con motivo del escrito que ha presentado la madre, Dª. Felisa Femia Hernández, instando impulso procesal para que se agilice el internamiento involuntario, porque tanto ella, como el padre, D. Juan Ávila Vinagre, ya no residen en el domicilio familiar, al trasladarse a una residencia de mayores y José Luis se ha quedado solo en la vivienda, sin nadie que le asista y le cuide a diario, siendo sus hermanos quienes, residiendo en Madrid, se desplazan a Aliseda cuando pueden a fin de atenderle." ······························································································································································································ Según Cdo. del CADEX, se le reconoció el grado de discapacidad en 1996. ··· Según DICTAMEN TÉCNICO presenta DISCAPACIDAD INTELECTUAL LEVE y ALTERACIÓN DE LA CONDUCTA por TRASTORNO DE PERSONALIDAD. ··················································· Según SIDEX: Grado I - Dependencia. Tiene reconocida una Prestación Económica Vinculada al SAD, con reconocimiento de de 20 h. de atención (10 para atención personal + 10 h para necesidades domésticas). Cuantía de la prestación vinculada: 300 €. ··· Participación en el coste del servicio: 0,00 €.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2024-03-27','Ana: Al igual que ayer, llamo a Ramón, hijo de Julián Ramón (647 694 013), pues había llamado a otra compañera preguntando por mí, pero "El teléfono móvil no se encuentra disponible"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2024-03-27','Ana: Respondo a uno de los 3 correos que ha enviado Azucena, cuñada: "El presupuesto lo recibimos ayer y aún no ha podido ser valorado por el Jefe del Área económica, el cuál no trabaja hoy. En cuanto esté confirmado si se autoriza la compra, lo comunicaremos a la Educadora y a ti. Dile que debe tener un poco de paciencia." ··········· Reenvío a Nieves, Ed. Futuex para su conocimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2024-03-27','Ana: Envío correo a Jorge Morán Pila, Jefe UD. PRESTACIONES ECONÓMICAS - DEPENDENCIA: "Esta carta nos la remitieron el mes pasado desde la Residencia en la que reside actualmente reside Dº. JULIAN RAMÓN CIVANTOS FERNÁNDEZ, cuyo cargo ostenta la CTAEx. No sé por qué no se nos remitió directamente a nosotros. Como puedes ver, es de meses antes de habérnosla enviado. De hecho, por lo que veo, se remitió a otra residencia en la que estuvo haces años, no la actual, que es la Residencia de Mayores de Cedillo. Mis compañeras de la sección económica no han podido tramitar la Declaración de la Renta pendiente hasta hace unos días. La cuestión es que estamos fuera de plazo, pero igualmente vamos a registrar hoy el documento y no sé si dadas las circunstancias se puede hacer una excepción para que no decaiga el derecho al trámite y se dé por NO APROBADO el PIA. *Quizá ya sea tarde igualmente." ······························································································································································································ Envío a Juan Carlos, Aux. Adtvo. (juancarlos.cano@salud-juntaex.es) para REGISTRO: "adjunto: - Oficio - Justificante DECLARACIÓN RENTA 2022 Para remitir, a ser posible hoy mismo, por favor, a la UNIDAD DE PRESTACIONES ECONÓMICAS DEL SEPAD, espero que tengas tú el nº de buzón, pue éste yo no lo tengo. Sino seguro que te lo puede facilitar Martina u otra compañera del otro ala." ····························································································································· envío a Jorge Morán, por mail, los documentos remitidos por registro y el Justificante-Sir ·································································· Al mismo tiempo recibo correo de Jorge Morán: "Hola Ana, pásame la renta por aquí y le tramitamos el expediente, no le hemos hecho la No Aprobación Pia. No hace falta que la registres, de hecho más rápido si me lo mandas por email " ······················· Nuevo correo de Jorge: "si, con la renta le tramitamos el pago de la prestación, no te preocupes"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA VALLE'and edp.apellido1='PATARRO'and apellido2='CARMELO'),'2024-03-27','-Amalia : queda pte. llamar a Natalia , TS de Fregenal que lleva este caso , tf 924700000 para cuadrar : -el reintegro mensual para gastos de bolsillo, que va a estar entre 100-150€ Percibe P. viudedad por 770€ , abona de copago de la plaza en los Pisos tutelados de Fregenal 617 y le quedaría poquísimo . De esos unos 130 son recibos domiciliados ( suministros de agua , luz , OAR , tf , decesos ) . Hay que poner un límite porque hubo un mes que sacó de más y tiene una deuda fraccionada con el Ayto. Natalia , la TS, va a ver el presupuesto de nuevo para cuadrar bien todos los datos. -Tiene que enviarme solicitud e informes de salud para tramitar dependencia, lleva tiempo allí pero no se lo ha pedido . -No comparto su idea de que Valle pueda regresar al domicilio , coincido con la forense . Esta Sñra. ya venía de una situación de soledad y exclusion en su pueblo y tiene ideas que no están ajustadas a su realidad . Tiene que acudir mensualmente al médico por su tratamiento de cáncer que no podemos garantizar en el pueblo . Allí estaría sóla , no tiene familiares y la amiga (a la que al parecer tiene cedida su casa para cuando fallezca le ha sacado de la cuenta 8000€ ) y ya no quiere contacto con ella . Comento con los jurídicos este tema de la casa ,ella quiere quitar esa cesión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GREGORIA'and edp.apellido1='MORENO'and apellido2='BERMUDEZ'),'2024-03-20','Ana: Toni-Futuex, nos remite factura de fecha de 15 de febrero del TV cuyo presupuesto se aprobó previamente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIANA'and edp.apellido1='SANCHEZ'and apellido2='BERMEJO'),'2024-03-20','Ana: Toni-Futuex, nos remite factura el TRATAMIENTO BUCODENTAL realizado y abonado, en la clínica "Dental Médica Cauria".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GONZALEZ'and apellido2='GONZALEZ'),'2024-03-27','Ana: Toni-Futuex, nos remite factura de fecha de 16 de febrero de la LAVADORA comprada en ELECTROCASH cuyo presupuesto se aprobó previamente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GREGORIA'and edp.apellido1='MORENO'and apellido2='BERMUDEZ'),'2023-06-15','Ana: Información en correo de Toni-Futuex: "Gregoria se encuentra más o menos estable, con sus cabreos y exigencias dependiendo del momento… Mantiene sus discusiones con la otra tutelada y tiene bastante obsesión si se le atiende a una sí y a otra no, pero no es conveniente visitarlas el mismo día por este motivo o intentar que no se enteren de las visitas de una y otra. En la última visita, a principios de abril, su petición, además de la subida de asignación que ya se le ha explicado que no se puede, es tener una tele en la habitación, la administrativo se lo negó, pero se le dijo que se estima conveniente que, cada cierto tiempo, se le conceda algo de lo que pide y así se relaje y pueda sentir que lleva algo de las riendas de su vida. El mayor problema de ella es que no entiende su situación actual, el motivo por el que se le tuteló, le quitaron la vivienda y mucho menos llega a comprender que después de haber habido un juicio, lo haya ganado, no pueda recuperar su casa, a diario pasa por ella… Es una parte de su vida que no consigue superar porque no lo entiende, lógicamente, por la injusticia que vivió, se suele tranquilizar cuando se le dice que todo lo que tiene ahora de la tutela y demás es para protegerla, pero no siempre llega a ello y es necesario dejar que suelte todo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIANA'and edp.apellido1='SANCHEZ'and apellido2='BERMEJO'),'2023-06-15','Ana: Información en correo de Toni-Futuex: "Últimamente se encuentra algo más alterada, el 22 de marzo de 2023 se acudió a la cita con su psiquiatra de SM y le mantuvo la medicación porque estaba más o menos estable, pero desde mediados de abril se empezó desestabilizando. Todo le viene por el tema económico y suele coincidir cuando Sandra, la antigua auxiliar de los PPTT, la visita y le hace compra, siempre se queda sin dinero. La última visita fue el día 3 de mayo del presente año, en Coria, se retira la asignación y se le acompaña a la óptica para nueva graduación y se solicita presupuesto para cambio de gafas, nos dan presupuesto (que enviare ahora para valoración) y a la espera de aprobación para comunicar a la óptica y que se pongan a ello. Estas gestiones relajaron a la tutelada, se habla con ella y se trabaja la relación con los usuarios de la residencia, especialmente con otra tutelada con quien no se pueden casi ni ver, para intentar que se mantenga el menos contacto posible y aprenda a respetar las decisiones y las acciones de los demás, aunque se duda que lo lleve a cabo durante mucho tiempo. Emiliana antiene mucho contacto con sus primas, a quien llama hermanas y con el párroco de Hinojal, para ella son la familia que tiene y le hace muy feliz que la llamen."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIANA'and edp.apellido1='SANCHEZ'and apellido2='BERMEJO'),'2024-03-27','Ana: Llamo a Loli, Res. Santa Catalina de Calzadilla (927 146 458), en relación a la forma de retirar dinero de Emiliana y Gregoria (tienen que desplazarse a otra localidad para retirar el efectivo con el trastorno y gasto que conlleva) para valorar otras alternativas, pero hoy no se encuentra. Le dejarán nota para que me llame la semana que viene.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GREGORIA'and edp.apellido1='MORENO'and apellido2='BERMUDEZ'),'2024-03-27','Ana: Llamo a Loli, Res. Santa Catalina de Calzadilla (927 146 458), en relación a la forma de retirar dinero de Emiliana y Gregoria (tienen que desplazarse a otra localidad para retirar el efectivo con el trastorno y gasto que conlleva) para valorar otras alternativas, pero hoy no se encuentra. Le dejarán nota para que me llame la semana que viene.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PRUDENCIO'and edp.apellido1='RODERO'and apellido2='COMERON'),'2024-03-27','Ana: Correo de Ángel, A. Jurídico a mí y a Alberto, Jefe S. Ecca.: "Las cantidades reclamadas obedecen a los gastos extraordinarios que en su día se fijaron en la sentencia de divorcio. La retención de los 200 euros mensuales la ha ordenado el Juzgado. Lleva pagados, de los 4.731,03 euros que se fijaron de principal, a fecha de 21/3/24, 2.800 euros. Restan por pagar de principal, 1.931,03 euros. Una vez termine de pagar el principal, restarán por pagar los intereses, que se recalcularán en ese momento, porque los inicialmente fijados, 1.200 euros, son una estimación."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2024-03-27','-Amalia : Ayer estuvo ingresado en el H.DB-VVa , tenía un cortauñas en el estomago .Hoy le daban alta y volvia con su padre a Helechosa . El lunes iba a ir a sacar el reintegro a Castilblanco. Lo llamo hoy y me dice que ha ingresado en el centro : Reeducacion de emociones LUis Rojo , C/ Las Arenas , Finca Los Chopos , Don Benito . Pregunto a Julian el Dtor por el centro y el perfil que atienden , EMG , Mujeres V.Gº , adicciones... La plaza residencial es de 400€ al mes . No quiere que se le haga transferencia , quiere el dinero en mano . No me genera confianza. Para mayo , le llamaré , si continúa allí haremos el cambio de transferencia a Don Benito.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='RODRIGUEZ'and apellido2='ROBLES'),'2024-03-27','-Amalia : me comenta Estrella que la ha llamado para saber la respuesta del pago del curso para obtener el carnet de conducir. Lo han pillado con el coche y le han puesto varias multas que le irán llegando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2024-03-27','TERESA ENVIO POR REGISTRO SOLCICITUD DE INGRESO EN RESIDDENCIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARCELO'and edp.apellido1='MANZANO'and apellido2='PEREZ'),'2024-03-27','Ana: En relación al correo de ayer de Inés, Secc. Jurídica: "Hola compis, os traslado solicitud de abogacía de Defensa Judicial para la revisión de medidas de Marcelo Manzano Pérez. La celebración de la comparecencia es el próximo martes día 02/04/2024 y la de la vista el 24/04/2024. Anoto ambas en la hoja excell para conocimiento de ello, aunque ya sabemos que asiste abogacía. Está todo subido al expediente. Ana te he puesto en copia, por si hay que gestionar acompañamiento." ······································· Llamo a la Res. Real de Navalmoral (927 53 33 22 / 927 53 71 52): no está ni la directora ni el TS. Me facilitan dirección de correo: direccion@residenciareal.com Envío el siguiente correo: "A instancias de la Sección Jurídica del Gabinete Técnico de la CTAEx, me pongo en contacto por este medio que me facilitan en la residencia, para comunicar que el próximo día 02/04/2024 a las 10:00 horas se cita en el JUZGADO DE PRIMERA INSTANCIA E INTRUCCIÓN Nº1 DE NAVALMORAL DE LA MATA a D. Marcelo Manzano Pérez. No sé si habréis recibido en la residencia dicha citación. Solicitamos por favor, que desde vuestro recurso se gestione, si es posible, su acompañamiento al Juzgado. En caso de no ser viable por personal del centro, por favor, que acuda algún profesional de confianza que suela realizar acompañamientos y se le podría abonar mediante transferencia bancaria una vez nos remitáis Declaración Jurada de dicho servicio realizado. Como podéis leer en el Decreto adjunto, se nombra a la COMISIÓN TUTELAR DE ADULTOS como Defensora Judicial en el procedimiento de revisión de medidas de apoyo, no obstante, en estos procedimientos asisten desde Abogacía General de la Junta de Extremadura, no desde el Gabinete Técnico de la CTAEx. Así mismo, adjunto también oficio de citación para el RECONOCIMIENTO MÉDICO FORENSE para el próximo 24/04/2024, para lo que solicitamos acompañamiento en los mismos términos que para la vista de la semana que viene. También tendrá que asistir al JDO.1A.INST.E INSTRUCCION N.1 de NAVALMORAL DE LA MATA El día 24/04/2024 a las 12:45 horas para la celebración de la vista. Se adjuntan todos los documentos pertinentes."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-03-27','Ana: Envío correo a Toni-Futuex: "En relación a JOSÉ MANUEL ROMERO MEDIAVILLA, ayer me dijo que se le ha estropeado la máquina de afeitar. Por favor, si es posible, que la educadora corrobore que esto es así las emana que viene y, en tal caso, le acompañe a pedir presupuestos (más de uno). Ayer le indiqué justo eso, pero ayer mismo por la tarde fue a Electrocash y nos han remitido uno nada económico. Me ha llamado hoy con sus urgencias habituales, pero le he dicho que para empezar no está Alberto para autorizarlo y que además le indiqué ayer que se esperase a la semana que viene para ir con la educadora."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN PABLO'and edp.apellido1='ESTEBAN'and apellido2='CORRAL'),'2024-04-01','TERESA REGISTRO SOLICITUD DE ORFANDAD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='HERRERO'and apellido2='GARCIA'),'2024-04-01','Ana: Envío a los A. Jurídicos - CTAEx: "Me enviaron hace unas semanas desde la Asociación Vera, el AUTO de REVISIÓN de las MEDIDAS DE APOYO relativa a JOAQUÍN HERRERO GARCÍA, no sé si la hemos recibido (no la veo en su expediente) así que os la mando, por si tenéis que poneros en contacto con el Juzgado o algo." ························ Respuesta de Ángel, A. Jurídico: "Si, tenemos el Auto. Pedimos Firmeza."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANASTASIO'and edp.apellido1='VAQUERIZO'and apellido2='PIZARRO'),'2024-04-01','TERESA Nuevamente me pongo en contacto con ustedes, por nuestra vivienda que es colindante a la de Anastasio, calle Francisco Rubio 18 de Barcarrota, vuelve a tener filtraciones, rogaria tomaran medidas al respecto y enviaran al técnico correspondiente para su revisión, debido al estado de la vivienda de Anastasio, esta afectando a nuestra vivienda, un saludo DERIVO A FUTUEX PARA QUE CONTACTE CON EL ALBAÑIL QUE HIZO LA OBRA Y VALORE LOS DAÑOS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='CARVAJAL'and apellido2='CORNEJO'),'2024-04-01','TERESA Te comento sobre Tomas Carvajal, más de lo mismo, cartas y llamadas aqui casi diarias. Cuando Patricia trata de ponerse en contacto con el, coge el telefono pero no dice nada. Si consideramos relevante algo que ha pasado hoy, y es que ha recibido una carta en su domicilio personal, Jose Condiño Sopa (que es Secretario de Futuex) pero nada tiene que ver juridicamente con Tomás.. no sabemos si habra buscado su nombre en internet, porque las cartas que envia aqui si que vienen a su nombre, pero claro ya lo enviaras a su domicilio, y en el tono amenazante habitual, pues ya escama un poquito más, porque da entender aspectos personales.. como el nombre de una hermana de él (que no tiene ninguna vinculación con Zafra, ni con este hombre y que no sabemos como ha podido averiguar) pero claro es un tema un poco distinto, si empieza de esta forma, como localizar las direcciones personales y etc. Mi compañero júridico de Futuex, Tomás, iba a hablar con Miguel o Angel, un poco para saber que se puede hacer en este caso. O si hay que ponerlo en conocimiento de la guardia civil de zafra o cualquier cosa, para que almenos hablen con el, de que debe dejar de amenazar y acosar a la gente asi. No se si, en que punto esta lo del ingreso involuntario, pero es cierto, que ya varios meses en los que se constata que está aparentemente desestabilizado. Y que no permite intervención técnica alguna. Patricia, la compañera de la zona, (de la que por cierto tambien habla en las cartas, como del Carramiñana, y de su primo Manolo, que todos "estan tontos" y cosas peores) pero de hecho a la educadora, no la ha llegado ni a conocer..., hace alguas semanas, acordamos hablar con salud mental, llevando algunas de las cartas, pero no obtuvimos respuesta. Se nos ha ocurrido igual, que hace el, mandarle alguna carta, pero tampoco sabemos si esto surtira efecto.. y desde luego sabemos que rechazara el seguimiento. Sigue sacando el dinero en dos veces no? el se quejaba mucho de eso, no se si .. tampoco sabemos si esto ha sido el desencadenante, y si volviera hacerlo como antes, seria factible?? Que piensas de todo esto? que se puede hacer? es una situación complicada, y no sabemos si puede llegar a ser peligrosa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='CARVAJAL'and apellido2='CORNEJO'),'2024-04-01','miguel, contestación a Tere y Maite: Buenos días, tal como podéis ver en la intranet, la persona que lo llevaba no está y lo tienen parado en el juzgado. Ya les comenté la urgencia del caso. Volveré a insistirles y le enviaré el email de futuex. ------------------------------------------------------ envío nuevo email a la parte social: Hola de nuevo, he hablado con el abogado de Futuex. Parece ser que Tomás ha averiguado la dirección del secretario general de Futuex y está enviando cartas amenazantes. Le he pedido que me envíen un escrito o email explicando lo sucedido para unirlo al email de Toni y le he dicho que interpongan la correspondiente denuncia…A ver si con esto logramos que el juzgado dicte las medidas necesarias para obligarle a ir al forense y continuar el procedimiento de Internamiento Involuntario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-04-01','Ana: Envío a Alberto, Jefe S. Ecca. y A. Jurídicos: "Os reenvío corro de Futuex con EJECUTORIA DEL JUZGADO de 1ª Instancia e Instrucción Nº 6. Multa de 90 € e Indemnización de 300 € por el delito leve de lesiones (Sentencia 24/01/24). La recogió él en el Juzgado la semana pasada (lo digo por el plazo)" ································································ Correo de Lourdes, S. Ecca: "envío justificante de pago de multa e indemnización" ····················································································································································································································································· Envío correo a Toni y Nieves, Ed. Futuex: "En relación a José Manuel Romero Mediavilla, me ha llamado, y entre otras cosas, dice que la semana pasada llamó por decisión propia, y sin consultar a nadie, al Cáterin y dio de baja el servicio. Y claro, que ha llamado hoy le han dicho, lógicamente, que esta semana no le van a llevar comida. Dice que de momento tiene en el frigorífico comida. De todas formas dice que este cáterin, Mesa y Mantel, no le gusta ya no lo quiere. ¿Podríais por favor, solicitar presupuesto del Cáterin “Comidas Pajuelo” y remitírnoslo?" ······································································ Llamada de Pilar Martín, ante la negativa de acceso a CRR, quieren plantear reunión o subcomisión. Considera que tiene que ingresar en algún recurso residencial. ··· Quedamos a la espera de convocatoria por parte del ESM.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2024-04-01','miguel, me llama Doroteo Diaz Cerro 609928621, que me llamó hace días también para decirme que tiene que hacer la herencia de su tío y que no tiene forma de localizar a sus primos y tampoco tiene documentación de la herencia (algún papel, pero no sabe ni qué). Le envié que fuera a una asesoría a pedir presupuesto, llevase lo que pueda y allí le han dicho que no pueden dar un presupuesto hasta que le lleve toda la documentación y como no tiene forma de localizar esa documentación ni a sus primos, pues no va a poder hacerse...Así se lo he dicho. No obstante va a volver a la asesoría con lo que tiene por si puede hacerse algo. Dice que no quiere renunciar a la herencia porque su tío ha dejado bastantes cosas (no me dice cuáles) y que el motivo de querer hacerla es que hay que desbrozar un terreno, con casa que puede ser riesgo de incencio. Le he dicho que previo presupuesto que nos envíe a la Ctaex,a Ana, se tendrá que desbrozar en el el futuro','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE DOLORES'and edp.apellido1='VARGAS'and apellido2='CHAVERO'),'2024-04-01','miguel, pongo email a Angel y Amalia: sabes algo de este expediente? Esta mañana me ha llamado la trabajadora social Ana del SSB de Monesterio 685399978 y me pregunta si sabemos algo de la venta del inmueble del que nos hicieron propuesta de compra (un solar creo). He visto un escrito del 2022 dirigido al Ayto de Monesterio pidiendo documentación de un expte abierto por el ayto. Por otro lado dice que el vecino tiene humedades, no sé si algo más…le he pedido que el vecino nos envíe informe pericial y presupuesto de arreglo. Pongo en copia a Amalia para su conocimiento. He quedado en llamarla con lo que averigue.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN RAMON'and edp.apellido1='CIVANTOS'and apellido2='FERNANDEZ'),'2024-04-01','Ana: Envío a Juan Carlos, Aux. Adtvo. (juancarlos.cano@salud-juntaex.es): "Adjunto, para remitir a la Dirección Provincial del INSS de Cáceres, la siguiente documentación relativa a D. Julián Ramón Civantos Fernández, cuyo cargo ostenta la CTAEx: - Oficio-solicitud de certificado actualizado de Pensión de Jubilación - Testimonio de Auto de Nombramiento - Testimonio de Aceptación del Cargo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-04-01','miguel, contesto a Alberto (pregunta si ha de abonar ya la condena del procedimiento Ejecutoria 5/24 Y a Ana, preguntando por tramites con el perito, arreglo de filtraciones de agua de la vivienda: Hola, parte económica, he intendo hablar con el juzgado pero no para de comunicar en toda la mañana. Debéis abonar los 300€, en el documento indica cómo hacerlo…a esa cuenta y en concepto lo que ahí dice. Ana: he intentado hablar varias veces ya con el supuesto perito de la compañía Zurich 615936664, y aunque hoy me ha cogido el tfno, lo he notado huidizo y me ha dicho no me podía atender y que le llamara más tarde y ya o me cuelga o no lo coge. Como ya dije en email de hace días, y tenéis en la intranet, nosotros debemos proceder siempre igual, el interesado es el afectado (vecino) por tanto, no tenemos que hablar con nadie, porque sólo han amenazado con que van a cobrar alquileres perdidos, supuestos daños con los que José Maria (hermano de Romero Mediavilla) no está de acuerdo… Por tanto, vamos a esperar nos comuniquen por escrito, o lo reclamen judicialmente, pero ya digo, no me huele bien, no se identifica el perito y sólo tenemos un número de móvil de él, y me da que quieren aprovecharse de ellos, pues no está ni siquiera demostrado que la filtración del agua proceda de la vivienda de Romero Mediavilla (dicho por su hno José Luis). El vecino Javier Rebollo 633-446263 extorsiona, figuradamente, a nuestro tutelado (a su hermano José Luis), el cual tampoco lo veo muy espabilado… Nosotros no tenemos que hablar con ellos…si quieren algo que empiecen por enviarnos un informe oficial de perito y un presupuesto de arreglos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='BERMEJO'and apellido2='TELLO'),'2024-04-01','-Amalia : envio autorizacion gnral de salidas .Tarjeta de Muface , Centros concertados de Muface de Salud mental en Madrid .Sentencia . Toda la documentación está enviada .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2024-04-01','Ana: Llamada de Jairo, quiere apuntarse a clases de PADEL y a NATACIÓN. ······· Acordamos que enviarán la información y los precios de las actividades. ···························· Por otra parte quiere sacarse el PERMISO DE CONDUCIR. Le digo que necesitamos un Informe Médico en que se indique que la medicación que toma por sus patologías no afectan en la conducción.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='GOMEZ'and apellido2='CHAVEZ'),'2024-04-01','miguel, Angel ratificó la declaración de herencia, pero parece ser que queda por ratificar una escritura. Por lo que Pablo Garrote (abogado) queda conmigo en insistir a la notaria manden a la notaria de Don Gonzalo Fdez telemáticamente la escritura para que podamos ratificarla.Me mandará la autorización judicial de herencia (que dice ya tiene) y me indicará por email el protocolo de la escritura de la declaración de herederos a ratificar. Posteriormente la notaria de monesterio tendrá que preparar la herencia, ratificarla nosotros y solicitar aprobación judicial de herencia y autorización de venta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2024-04-01','miguel, tras nuevo intento sin éxito de hablar por tlfno con Jordi de la notaria de Virgen de Guadalupe (Cáceres), le envío email (que me indican en la notaria)Buenos días, he intentado reiteradas veces contactar con usted vía telefónica sin éxito. Le escrito de la Comisión Tutelar de Adultos (Junta de Extremadura) debido a que se ha puesto en contacto con nosotros Belén Solana Chanclon, indicándonos que usted está preparando una escritura, pero no me ha sabido indicar si es de adjudicación de herencia. Necesito que para se tramite la parte de la hermana, Mª Carmen, tutelada por la Comisión Tutelar de Adultos, se ponga en contacto conmigo y me indique qué se va a firmar, así como me facilite el borrador de la escritura que se esté preparando. -------------------------------------------------- Se lo reenvío a modo de contestación de la hna, Belén: Buenos días, tras intentar de nuevo hablar telefónicamente con Jordi, le he remitido email, que puede leer debajo, por si habla con él, para decirle que se ponga en contacto conmigo, porque le he llamado muchas veces y no me lo coge.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2024-03-22','miguel, recibo emaiil de la hna Belen, Belen Solana chanclon >solanachanclonbelen@gmail.com> Miguel no vamos a firmar nada y mi notario tiene la sentencia de la incautación de mi hermana de los juzgados poreso mi insistencia con usted y vosotros tenéis que firmar creo o venir para que usted sepa lo que hay y todo lo de Hacienda y cuando saquemos el dinero y meterlo Enel banco venga usted y lo haga un saludo yo ya se lo comunique porque era mi hobligacion si usted no puede alguien de la tutela un cordial saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='VAZQUEZ'and apellido2='MUÑOZ'),'2024-04-01','-Amalia : Esther , TO OLivenza , me va a enviar el PIA para la plaza .El estudio eco lo ha hecho ya J.Carlos. Se lo remito registrado .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE BLAS'and edp.apellido1='CAÑAS'and apellido2='LOZANO'),'2024-04-01','Ana: Envío correo a Toni y Nieves, Ed. Futuex: "... *Se autorizan 120€ para la compra de ropa, esperemos que los precios no hayan variado demasiado y le llegue para cosas que necesita. Mis compañeras de la secc. económica, remitirán al banco una autorización para retirar el extra abierto del 1 – 15 de abril, para que cuando os cuadre en agenda, le acompañéis a retirarlo y a comprar la ropa dentro de este plazo. Comunicárselo previamente, por favor, para que también sepan que está autorizado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSARIO'and edp.apellido1='MORENO'and apellido2='HERMOSA'),'2024-04-01','Ana: Entrego a Alberto, Jefe S. Ecca. carta de pago de dependencia solicitando ingreso de abonos indebidos: 101,91€. Por los días que mediaron desde que ingresó en Residencia (plaza pública) y se hizo efectiva la baja en la anterior prestación ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LEON'and edp.apellido1='LEAL'and apellido2='PEREZ OLAGUE'),'2024-04-01','Ana: Envío correo a Estrella, S. Ecca: "Cuando puedas mira si es viable este presupuesto relativo a LEON LEAL PEREZ OLAGUE de TRATAMIENTO BUCODENTAL, espero que no haya variado mucho, pues como puedes ver es de febrero… se quedó para atrás. Porfa, cuando veas si es viable, que será que sí, confírmale directamente a Toni de Futuex: areasocial3@futuex.es"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-04-02','Ana: Correo ayer-noche de Jessica Rey, Cáterin "A mesa y mantel" (ccamesaymantel@gmail.com // 661 68 59 65): "nos ponemos en contacto con ustedes para hacerles llegar la decisión de no seguir atendiendo el servicio de comidas a José Manuel Romero Mediavilla, este señor es INTRATABLE, y después de varias faltas de respeto y de no valorar nuestro trabajo preferimos dedicar nuestro tiempo y esfuerzo en alguien que realmente si lo merezca, disculpen las molestias que les pueda acarrear nuestra decisión, sin más quedamos a su disposición para otros posibles clientes, un saludo." ··············· Reenvío correo a Maite, Jefa Secc. y a Futuex (Toni y Nieves) para su conocimiento. ············· Envío correo de disculpas al catering, desde ctutelar@.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2024-04-02','miguel, email de Alberto: HERENCIA: RETOMAR...O NO...TEMA HERENCIA DE ESTE TUTELADO...YA SE PLANTEÓ EN 27/04/2021 X IBI C/CARRERA, 13: A NOMBRE DE FRANCISCO MURILLO TAPIA...NO SE SI SE HIZO ALGO. ****************************************************** mi contestación: Buenos días, adjunto email de debajo. Estábamos pendientes de saber con quién hablar para que nos remita la documentación solicitada por la notaria para hacer la declaración de herederos. No tenemos información ni documentación de esta herencia… Esta tutela la lleva ahora Tere, y la llevaba antes Amalia. Por favor, indicadme teléfono y persona de contacto para preparar la herencia.','2');
