insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='BLANCO'and apellido2='GUISADO'),'2024-03-20','Ana: Correo de Ángel, A. Jurídico a Alberto; Jefe S. Ecca., y a mí: "Os envío presupuesto recibido del Ayuntamiento de la Haba, para tapiar la puerta trasera de la vivienda de Felipe Blanco Guisado. Decidme si se acepta o no. Del sobrino y sobrina hemos vuelto a saber algo? Hacen uso de la casa? Recordad que tienen el 16,66% de propiedad, y el resto, 83,33% es de Felipe." ·················································································································································· Respuesta de Alberto: "ÁNGEL: A NIVEL ECO PUEDE AFRONTAR ESTE PRESUPUESTO SIN NINGÚN PROBLEMA. LOURDES: ABONAMOS, SI PROCEDE, COMO NOS VAYA INDICANDO ÁNGEL...EL PRESUPUESTO MÁXIMO ES DE 266,20 €."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='GARCIA'and apellido2='RAMIREZ'),'2024-04-02','miguel, recibo email de Marisol Marisol Garcia Ramirez >marisolgarram@gmail.com> Buenos días, Miguel Agradeceríamos nos informaras en qué situación se encuentra la solicitud presentada sobre la compra-hipoteca del piso de Jose Antonio García Ramirez. ¿Hay juzgado asignado? ¿cómo podemos avanzar? Salvo error, no hemos recibido respuesta del correo anterior. Quedamos a la espera de tus noticias, Un saludo Marisol García Teléfono:618 75 61 39 ************************************************************ mi contestación: Buenos días Marisol, ya tenemos número de procedimiento X15 nº127/24 del juzgado de 1º instancia e instrucción nº4 de Badajoz. Los teléfonos son 924-284254, 924-284255 por si queréis preguntar dudas. Hay que esperar a la resolución del procedimiento para que nos digan si autorizan o no la operación. He llamado al juzgado pero no me lo cogen.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GONZALEZ'and apellido2='GONZALEZ'),'2024-04-02','Ana: Llamo a Cristina, TS de la Ud. Alcoholismo del CSS - Plas: a Mª Carmen le dieron el alta antes de la semana santa. ····· Dice que una educadora fue a recogerla, pero no sabe si es de Futuex. ·················· Solicitará el Informe de Alta al médico y me lo remitirá.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PRUDENCIO'and edp.apellido1='RODERO'and apellido2='COMERON'),'2024-04-02','Ana: correo de Lourdes, S. Ecca. a Felisa Custodio, TS CAMF- Alcuéscar (trabajadora_social_alcuescar@imserso.es): "Buenas tardes, en referencia a Prudencio Rodero Comerón, ya dispone de saldo para poder afrontar las cuotas pendientes y poder preparar las cuotas actuales. • Para el tema de la deuda pendiente, necesitamos un certificado por el importe pendiente. • Para el tema de la cuota, si quieren hacemos transferencia al centro o bien realizan la domiciliación. Espero sus indicaciones. Si necesitan aclaración, pueden llamar por teléfono." ································································································································································································· Envío al CAMF (camf.alcuescar@imserso.es / trabajadora_social_alcuescar@imserso.es), DECLARACIÓN JURADA DE INGRESOS 2024, debidamente firmada y sellada por la Presidenta de la CTAEx.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GREGORIA'and edp.apellido1='MORENO'and apellido2='BERMUDEZ'),'2024-04-02','Ana: Hablo con Loli, Res. Calzadilla (927 14 64 58): Gregoria sí que tiene cuenta en Caja de Almendralejo y acude a retirar el efectivo en la oficina de la localidad. ··· Puesto que tiene una curatela (antigua incapacidad parcial), en su día pudo abrir una cuenta en dicha entidad bancaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIANA'and edp.apellido1='SANCHEZ'and apellido2='BERMEJO'),'2024-04-02','Ana: Hablo con Loli, Res. Calzadilla (927 14 64 58): en la localidad hay una oficina de Caja Almendralejo. En su día habló con una de las compañeras de las S. Ecca. (cree que era Icíar) e intentaron que se le abriera cuenta Gregoria en dicha entidad. Pero ésta ponía muchas dificultades para la gestión y finalmente no se pudo hacer. ················ Volveré a plantearlo a Alberto, Jefe S. Ecca. ························ Nadia, Ed. de Futuex, le ha dicho que pronto se dará de baja por Maternidad.','2');
