insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2024-04-02','Ana: Estrella me envía CI para TURBINOPLASTIA mediante RADIOFRECUENCIA y SOLICITUD DE INCLUSIÓN EN LISTA DE ESPERA. ········· *Le intervienen esta misma tarde. ······················· Una vez recabada la firma los remito a Admisión, tal y como acuerdo mediante conversación telefónica (admision.cssplasencia@salud-juntaex.es)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='GOMEZ'and apellido2='CHAVEZ'),'2024-04-02','miguel, tras comprobar en el expte que no tenemos el certificado de nacimiento original, pido a José de SSB SSB Monesterio >ssbase.monesterio@salud-juntaex.es> pida otro y a Pablo Garrote pablogarrotedelgado@icaba.com me indique la escritura de declaración de herederos pendiente de ratificar','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2024-04-03','Ana: Envío correo a Ana Castillo Foronda TS - FUNDACIÓN AUTISMO SUR (teayudamos@autismosur.es): "Mis compañeras ayer tuvieron problemas con la transferencia, intentaron con las claves online y hablando directamente con el banco, donde le dijeron que ellos se encargaban. Pero te reenvío el correo que envió ayer a última hora el chico del banco a mi compañera Lourdes… No contábamos con algo así, así que si podéis, por favor, abonarlo vosotros y cuanto se solucione este problema os lo reintegramos mediante transferencia desde la cuenta de Alex. Espero que no tarde mucho en solucionarse…. Y espero que finalmente o dejen empezar con las sesión mañana o que os den otra cita. Siento este contratiempo. Ya me dices cuando puedas." ········································· Finalmente se solucionó el problema con el banco y Lourdes, Secc. Ecca.. envió el JUSTIFICANTE DE TRANSFERNCIA a Autismo Sur. ······· He hablado con Ana Castillo, TS y ellos no habían llegado a hacerla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GONZALEZ'and apellido2='GONZALEZ'),'2024-04-03','Ana: En relación al requerimiento del Jdo, escribo a Inés, Secc. Jurídica: "Ayer por fin pude hablar con la TS de referencia del CSS. Había cogido días. Te adjunto el informe de alta de la Unidad de Desintoxicación Hospitalaria de Alcoholismo del C. Sociosanitario de Plasencia. Le dieron el alta el día 18, pero aquí no nos lo comunicaron." ························································································································································································································································· Según el informe de alta, paciente muy conocida en los distintos recursos y dispositivos de la Red de Salud Mental así como en los de atención y tratamiento de Adicciones: UHB Virgen del Puerto de Plasencia, UME Y URH del CSS y ESM, donde ha tenido un seguimiento discontinuo en Psiquiatría. Mejor aceptación de Tto. Psicológico. ···· Desde 2010 ha sido derivada en numerosas ocasiones a los recursos residenciales de la Red de Salud mental, siendo aceptado su ingreso en todas ellas, pero RECHAZADO por su parte, por lo que no llegó a ingresar ninguna vez. ················ También ha sido atendida por el Punto de Atención de Violencia de Género de Coria y en el C. de Rehabilitación Psicosocial de Plas. ·········· Requirió ingreso en UCI por Intento Autolítico Grave en octubre de 2020. ····· Según manifiesta Carmen, en la actualidad tiene una pareja que le ayuda en la tareas del hogar y en el aseo. Sólo sale de casa una vez al mes para acudir al banco. ·· Habla ocasionalmente por teléfono con su hermano mayor, con el pequeño no. "S siente dolida con ellos por el reparto que hicieron de la herencia de sus padres." "No amistades" ··· Su pareja es quién le lleva el alcohol a casa. *"Rechaza acudir a COMUNIDAD TERAPÉUTICA". Se planea como objetivo, además del cese del consumo, la activación conductual y la recuperación de su autonomía" ···················· "Al alta muestra motivación parcial para el mantenimiento de la abstinencia habiendo aumentado la conciencia de problema, planteando planes coherentes de futuro, pero escasos, precisando mayor amplitud de actividades sociales y alternativas al consumo" "Se le insiste en abandono de hábito tabáquico" ············································································································································································································································· Educadora de referencia de FUTUEX: Nadia. ····································· *Según sentencia: CURATELA "para la administración de su patrimonio, dejando conservada su capacidad respecto del manejo diario del dinero de bolsillo, siendo aconsejable ayuda y supervisión también en esta esfera" ································································································································································································································································ Envío correo a Toni y Nadia, Futuex: "...Además de los acompañamientos a seguimiento tanto al ECA como al ESM, sería bueno que abordaseis la posibilidad de participar en actividades que puedan ser de su interés y se desarrollen en su localidad, de modo que pueda crear un mínimo de red relacional y de apoyo, mejore su autoestima y habilidades y consiga mantener la abstinencia en cuanto al alcohol se refiere. En cuanto al tabaco, aunque lo veo complicado, al menos se podría comenzar intentar concienciarlas de que por salud debe, al menos, disminuir el consumo. A ver si con las citas en el ECA ayuda también a este objetivo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-04-03','Ana: correo de ayer de Toni-Futuex: "está José Manuel Romero Mediavilla, ahora en el juzgado para declarar sobre un asunto de agresión, como acusado, y del juzgado comentan si va a declarar con la comisión o le ponen un abogado de oficio. Como no hemos conseguido contactar, se va a indicar que le faciliten un abogado de oficio, para la declaración. Adjunto foto del atestado que es lo único que tenemos. José Manuel se ha enterado por el hermano,. ya que han intentado contactarle en Plasencia que seria la ultima información que tenia. Supuestamente ahora le tomaran declaración. Informaremos con las novedades." ··············································· Respondo a Toni con copia a Nieves, Ed. Futuex, Miguel, Ángel y Maite, CTAEx: "Pongo en copia a Miguel, Ángel y Maite. De todas formas, en mi opinión, está bien que se le ponga abogado de oficio, pues mis compañeros Asesores Jurídicos pueden asistir en calidad de representantes de la CTAEx, pero no de abogados, pues no actúan como tal. Compañeros, corregidme si no es así. No obstante, si no os importa, cuando se trate de temas de Juzgado y haya que tomar decisiones al respecto, como ya hiciste con Miguel, llamad mejor a los Asesores Jurídicos directamente: ..." ······································································· Nuevo correo de Toni-Futuex: "Finalmente se negó a declarar, ya que el mantiene no haber realizado está agresión. Estuvo aconsejando por su hermano, y se acogio a este derecho. Ya que al parecer la otra persona es una persona poco confiable. Suponemos le volveran a citar." Lo reenvío a Ángel y Miguel, A. Jurídicos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORCILLO'and apellido2='HERRERO'),'2024-04-03','Ana: Envío a Sandra, TS de la Res. Mayores de Coria (alexandra.alfonso@coria.org): "Buenos días, os informo del fallecimiento de vuestro tutelado JOSE MORCILLO HERRERO con DNI: 75990833-Y. Ante la ausencia de familiares, el Centro ha decidido que el sepelio se celebre en esta localidad, ya que el fallecido residía en Coria desde hace más de 30años. En cuanto tenga el Certificado de Defunción os lo envío a este correo electrónico." ····································· Tenía Seguro de Decesos. ·············· Contesto a Sandra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANASTASIO'and edp.apellido1='VAQUERIZO'and apellido2='PIZARRO'),'2024-04-03','TERESA Nos hemos puesto con esto, pero se complica un poco el tema. Hemos contactado con los albañiles que realizaron tanto la obra del tejado-pared como la obra de la fachada y se disculpan pero no quieren volver a realizar la obra. Nos indica que el tejado es viejo, es una casa sin mantenimiento, está en malas condiciones y para dar solución al mismo sería tirarlo y realizarlo de nuevo. Además menciona haber tenido problemas con la vecina, pues les exigía realizar trabajos que no se habían presupuestado referente a su vivienda (no a la de Anastasio) e incluso les amenazaba indicando que iban a dar quejas a la Junta de su trabajo. En mas de alguna ocasión la vecina los llamó para dar quejas a las cuales dieron solución pero tuvieron que decirle que ellos no estaban contratados como personal de mantenimiento de la vivienda. Mencionan que el tejado de la vivienda de la vecina también es viejo, quien indica que no pueda generar alguna que otra gotera o que se pueda filtrar agua por ahí. Nos aconsejan como solución rápida poner unas chapas que eviten que se filtre el agua por el tejado de Anastasio pero eso tiene que ser a través de un herrero. Hablamos también con la trabajadora social de la localidad la cual nos indica que nos podría facilitar el teléfono de dos empresas para que un aparejador valore, nos de solución y presupuesto de la situación. Por último, desconocemos dónde están las llaves de la vivienda de Anastasio. En la residencia nos indican que allí no están y el albañil nos indica que le iba a preguntar a su compañero por si se les hubiese pasado llevarlas a la residencia. Asique se podria en todo caso, pedir presupuesto de la empresa para que un aparejador valore de donde vienen y a quien corresponde el arreglo, o bien pedir de un tejado de chapa al herrero, como solucion . Tambien posiblemente si las llaves no aparecen, habra que pedir precio para hacer unas nuevas. Esta semana se pretendia ir, para allá, a ver si obtenemos infomracion de primera mano.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2024-04-03','Ana: Correo de Rosa Marina Fdez. Barrera, Psiquiatra - FEA (rosamarina.fernandez@salud-juntaex.es): "Adjunto enviamos Acta de la Subcomisión de Gestión de Casos del paciente ESGP celebrada el pasado 20 de Marzo en la sala de Juntas del Centro Sociosanitario de Plasencia. Para duda/aclaración pueden dirigirse a cualquiera de los miembros permanentes de esta Subcomisión." ································································································································································································ Correo de Estrella Durán, TS CSS-Plas (estrella.duranc@salud-juntaex.es): "Os comunico que Enrique Santos se irá de pase a domicilio del 5 al 8 de abril" ···················· Mi respuesta: "Ok, gracias por informar. Pongo en copia a Clara, Educadora del Programa que gestiona Futuex, y a Toni, su coordinadora, para que puedan organizar visita de seguimiento. Lo malo que al coincidir en fin de semana, en caso de que les cuadre en agenda, sólo podrán visitarle viernes y/o lunes."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2024-04-03','-Amalia : nuevo traslado en un mes para Alicante. Vuelta a cambiar las cuentas peculio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MINERVA'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2024-04-03','DIRECCIÓN DE RESIDENCIA HABTTUAL (DOtítClLtO DE LA PROGENTTORA) C/ PLASENC]A, 26, PORTAL 6, BAJO, B. IVÉRIDA. BADAJOZ. TELÉFONO CONTACTO: 669196556 (Diego, tío paterno). 665643499 (Laly, tía paterna','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA REMEDIOS'and edp.apellido1='LOZANO'and apellido2='MUÑOZ'),'2024-04-03','miguel, hablo con jzdo de 1º instancia nº4 de Badajoz y me comentan que devolvieron el escrito de solicitud de transmisión de vehículos a la oficina de reparto civil (antiguo juzgado decano)porque entienden que deberíamos haber hecho demanda de nuevo procedimiento. Me confirma que no es necesario solicitarlo de nuevo, sino que vale con esperar a que asignen procedimiento y juzgado. Intento hablar con la oficina de reparto civil por varios teléfonos sin éxito, para preguntar si ya hay asignado un nº de procedimiento y juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='GARCIA'and apellido2='RAMIREZ'),'2024-04-03','Buenos días Marisol, ya tenemos número de procedimiento X15 nº127/24 del juzgado de 1º instancia e instrucción nº4 de Badajoz. Los teléfonos son 924-284254, 924-284255 por si queréis preguntar dudas. Hay que esperar a la resolución del procedimiento para que nos digan si autorizan o no la operación. He llamado al juzgado pero no me lo cogen.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2024-04-03','Ana: correo de Estrella Durán, TS CSS-Plas (estrella.duranc@salud-juntaex.es), a mí y al ctutelar@: "Como se acordó con Soraya Masa, Andrés Silva Bonifacio pasará administrativamente a ectópico por lo que debe abonar la cuota pertinente, por lo que se pondrá en contacto con vosotros Monserrat Martín López de Gestión Económica, de este centro socio-sanitario, con objeto de que le facilitéis el número de cuenta etc."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2024-04-03','Ana: Correo de Yessica de Arriba, TS del Comedor Social y otros programas de Caritas - Plasencia (ydearriba@caritasplasencia.org): "Me pongo en contacto contigo en esta ocasión, para informarte que ayer entró ángel Félix en el Centro de Acogida de Cáritas en Plasencia. Me traslada ángel Félix que os comunique lo siguiente: Ha tenido desde hace varios días algunos inconvenientes con el compañero y dueño de la casa en la que vivía, y por ello, junto con la colaboración de Clara ( su tutora) y después de intentar convencerle entre las dos, hemos conseguido que dejase esa vivienda que no le venía bien, y pudiese entrar en el CAT. Me traslada también que os agradezca la aparición de Clara en su día a día, que han congeniado muy bien y con ella se siente cómodo y receptivo para trabajar. También os quiere agradecer el trabajo que hacéis tanto con él como con el resto de personas con las que trabajáis." ······················ Respondo y pongo en copia a Clara, Ed. y Toni, Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE BLAS'and edp.apellido1='CAÑAS'and apellido2='LOZANO'),'2024-04-03','Ana: Reenvío correo a Toni y Nieves, Ed. Futuex, con la Autorización Bancaria para la retirada del extra para ropa, por si hubiera algún problema cuando acudan al banco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PILAR'and edp.apellido1='JIMENEZ'and apellido2='AGUILAR'),'2024-04-03','Ana: Conversación con Pedro Martín Paniagua, propietario de la casa de Ahigal en la que viven de alquiler (646 227 862 // ryoga.hibiki.330@gmail.com): Pilar y Jesús quieren cambiar de vivienda. Le han dicho que le han robado a él del tendedero un chándal y alguna prenda más. ········· A él le ha quedado libre otra casa un poco más grande y con terraza donde podrán tender la ropa que a ellos les ha gustado más. ············ Lo tienen ya apalabrado. ················ La diferencia de precios son 40€ más al mes. Ellos están de acuerdo. ·········· A Pilar le supondría 20 € más al mes que tendrá que autorizar Alberto. ····················· Nos enviará el nuevo contrato para que sustituya al anterior. ·············································· Envío correo-e a Alberto y Ángel, CTAEx.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2024-04-03','miguel, llega email de jose luis gilarte (notaria de Cáceres): Buenos días. Perdona pero tarde en incorporarme al despacho. He intentado hablar contigo pero no ha sido posible. Esta misma mañana he revisado la documentación que me enviaste en su día y he hablado también con María José Mendoza (Cabra – Cordoba) que es de la Fundación en la que está interna la heredera MAXIMA ESTEBAN IGLESIAS. Te paso a detallar lo que he hablado con ella. - En primer lugar he quedado que ella me mandará la documentación de Máxima (C. nacimiento y datos personales). - También le he comentado de la necesidad de aportar el certificado de defunción de los padres de Tomás (Margarita y Tomas) y ella va a indagar por si entre la documentación que le aportaron cuando ingreso estuvieran esos documentos o si los tenéis vosotros que me los aportéis. En cuanto a los testigos, efectivamente deben ser dos personas que les conozcan a ellos y no de la Comisión Tutelar, simplemente que les conozcan y puedan manifestarlo en el Acta que se formalice. Para la firma del Acta, con que sea el representante de uno de los herederos es suficiente y con la presente del representante y la aportación de los originales de los documentos incorporados al acta es suficiente. De todas formas iré llamando para que hablemos personalmente del trámite. ********************************************************* mi contestación: Buenos días, disculpa porque estamos hasta arriba de trabajo. Comentarte que no tenemos nada de los padres, pero en NACE (Cáceres), Chema Tovar o Mª José 620190869 puede que te puedan ayudar a localizar esos certificados de defunción. Te adjunto la escritura de herencia que se firmó en Coria de la Abuela por si a través de esa notaria pudiésemos localizar dichos certificados. En cuanto a los testigos entiendo que puedes preguntar a Mª José de Nace 620190869. Si fuera necesario que asistiésemos personalmente dímelo e iría personalmente (salvo que pueda ratificar en Mérida), ya me dices. La Comisión Tutelar no conoce directamente a los curatelados (asistenciales/representativos), ya que estamos en Mérida y estas personas están por toda Extremadura, en domicilios familiares, propios o en centros. Cualquier duda vamos hablando','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2024-04-04','Ana: Hablo con Mª Carmen, TS HSPA: Julia sigue en la UCI, evoluciona muy despacio, a nivel respiratorio sigue grave. El problema añadido será que cuanto más tiempo esté en la UCI más secuelas tendrá y más complicadas será la recuperación después.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2024-04-04','Ana: Correo de Sheila, Directora CRR-CC: "En referencia a la persona usuaria tutelada Antonia Canelada del Rio, solicita poder disponer de 200€ extra como ayuda económica a su hermano Daniel, planteamos como opción a valorar la posibilidad de realización de transferencia a la cuenta de su hermano como una forma de poder justificar dicho gasto. ¿Qué os parece? Por otro lado informaros de que vamos a proceder a solicitar un certificado de empadronamiento y una partida de nacimiento para hacerle entrega a María de Cáritas la documentación que nos ha solicitado para la gestión, junto con el hermano de Antonia, de la herencia de la hermana fallecida años atrás." ······························································································································································································ Mi respuesta: "Por mi parte, si es viable, no hay problema en que ayude a su hermano económicamente y que se haga mediante transferencia. La sección económica tendrá que valorarlo igualmente. En cuanto al empadronamiento, podéis enviarnos el modelo para ser firmado por la Representante Legal. Y en relación a los trámites de la herencia, imagino que no habrá problemas, pero pongo en copia a mis compañeros Asesores Jurídicos, que son quienes llevan estas cuestiones."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2024-04-04','miguel, recibo email de Jordi de Acosta jaredondo2@despacho.notariado.org Buenos días Miguel, La escritura que se va a firmar por parte de las hermanas Solana Chanclón es una escritura de Toma de Legado, ya que en el testamento se les faculta para disponer del legado por sí solas. Todavía no le puedo enviar borrador, espero tenerlo en próximas fechas. JORDI DE ACOSTA REDONDO NOTARIA DE DON JOSE CARLOS LOZANO GALAN & DON IGNACIO FERRER CAZORLA & DON CARLOS DEL SOLAR BARROSO Avenida Virgen de Guadalupe, 18, 1º 10001 - Cáceres TELEFONO.- 927 240 577 / 78 FAX.- 927 260 389','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2024-04-04','Ana: Envío a Juan Carlos, Aux. Adtvo. (juancarlos.cano@salud-juntaex.es): "Adjunto, para remitir por REGISTRO, a la UNIDAD DE ACCESO Y VALORACIÓN DE DEPENDENCIA (Buzones Registro: Revisión de GRADO: A11032816), la siguiente documentación relativa a D. ALFONSO MARÍN DE CÁCERES: - Solicitud de revisión de grado de dependencia y recurso residencial - Informe de Salud + Índice de Barthel + Informe de Psiquiatría - DNI del Solicitante - DNI de la Representante Legal (Presidenta por Delegación de la Comisión Tutelar de Adultos de Extremadura) - Decreto de Nombramiento como Directora Gerente del SEPAD) - Resolución de Delegación de funciones" ······································································ Envío correo-e a Estrella Durán, TS UME-CSS Plas: "Te envío toda la documentación registrada a día de hoy para la revisión de grado de dependencia de ALFONSO MARÍN DE CÁCERES, incluido el justificante de registro."','2');
