insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PILAR'and edp.apellido1='JIMENEZ'and apellido2='AGUILAR'),'2024-04-04','Ana: correo-respuesta de Alberto: "ANA: PUEDE ASUMIR ESA SUBIDA DE APORTACIÓN ALQUILER DE 20 €/MES. LOURDES: UNA VEZ QUE ÁNGEL DE OK A NUEVO CONTRATO, MODIFICAMOS LA TRANSFERENCIA PERMANENTE Y LA SUBIMOS A 170 €/MES (ANTERIOR 150 €/MES). ESTRELLA: NO TENGO CONTROLADO EL DECESO EN H.CALCULO...XFA, ÉCHALE UN VISTAZO"','2');
