insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='GARCIA'and apellido2='MORENO'),'2024-04-04','Ana: Llamada de Abraham, hijo de Pilar (927 772 155): quiere que hable con Carmen, TS del Vivienda, pues dice que el alquiler que abonan es muy caro (340 €/mes) y necesitan irse a una vivienda social.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2024-04-03','Teléfono Manuel Contador: 722 86 00 06 Amalia: hablo con él para preguntar si está de acuerdo en la venta del piso familiar , me indica que sí , quiere venderlo y comprarse una casita en Olivenza.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='CARVAJAL'and apellido2='CORNEJO'),'2024-04-04','miguel, tras recibir el 27-3-24 email de incidencias de Tomás Carvajal y tras conversación el 2-4-2024 con el abogado de futuex, Tomás Salas,Tomás Salas >t.salas.abogado@gmail.com> nueva incidencia porque envía cartas al secretario de Futuex. Hoy me llega de Tomás Salas informe de incidencia Envíamos por lexnet ambas incidencias con oficio al jzdo nº2 de Zafra con el siguiente contenido: En el contenido del oficio pon “ en relación a la curatela asistencial de Don Tomás Carvajal Cornejo, se está tramitando el procedimiento ITR INTERNAMIENTO 0000500 /2023, en este juzgado de 1º instancia e instrucción nº2 de Zafra. Dicho procedimiento se encuentra paralizado por este juzgado hace más de 6 meses, por lo que se ruega lo agilicen ya que esta persona se encuentra descompensada, no asiste a médicos, no quiere acudir a la cita que tuvo en noviembre con el forense, por lo cual se les pidió que dictaran las medidas de apoyo de oficio, entre otras la intervención de los cuerpos de seguridad del estado para obligarle a que acuda a la cita con el fiscal. Se adjuntan dos nuevos informes de incidencia de Futuex, a los efectos oportunos. En ambos escritos se puede comprobar que está descompensado y puede suponer un peligro para sí mismo y para terceros. Uno de ellos donde se recoge que envía cartas al domicilio personal al secretario de Futuex. Se ruega a este juzgado retomen este procedimiento de internamiento involuntario mencionado y procedan a obligar a Don Tomás a acudir al Forense lo antes posible”.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2024-04-05','miguel, tras hablar ayer con Promi(llevan la tutela de la hna Máxima en Córdoba) comprobamos que no han abonado ni a ella ni a nosotros el dinero de la herencia de la abuela. Envío email a Rafael, rsantosrex@pajueloabogados.com, 924-242814, el abogado de la tía Buenos días, a fecha de hoy, y tras más de un año de la firma, siguen si estar desembolsadas las cantidades de la herencia que se firmó en Coria. Al tener ustedes los originales deben presentarlas al banco para que proceda al reparto. Adjunto la escritura y las cuentas de los tutelados por la Junta de Extremadura para que procedan a su abono ES04 2103 7130 7100 3001 2010 ------ SOLEDAD ESTEBAN IGLESIAS (28959754V) ES52 2103 7111 7100 3000 2202 ------ JOSÉ MANUEL ESTEBAN IGLESIAS (28955869L) La liquidación del impuesto de sucesiones liquidado se la remitiré en cuanto me lo remita la asesoría. ---------------------------------------------------- Llamo y contrato para liquidar el impuesto al contacto que me da Promi (MªJosé), Jesús Sánchez 606268320, jesussanchez@jssconsultores.com Buenos días, conforme hemos hablado por teléfono, necesitamos encargarte la tramitación y gestión del impuesto de sucesiones de la adjudicación de herencia firmada en Coria de la abuela de 4 hermanos, los Esteban Iglesias (cuya tramitación del Imp de Sucesiones de la otra hna Máxima, ya estáis tramitando con Mª José de Promi de Córdoba). Tres de ellos están tutelados por la Junta de Extremadura-Comisión Tutelar de Adultos, y uno de ellos fallecido después de la adjudicación de herencia de Coria objeto de este impuesto de sucesiones. Se trata de Tomás Esteban Iglesias, del que adjunto cert defunción, últimas voluntades, certificado de discapacidad, dni y testimonio de nombramiento del cargo de tutor que ostentaba hasta su fallecimiento esta Comisión Tutelar de Adultos. Los otros dos hermanos son Soledad Esteban Iglesias, que reside en Nace (Cáceres) y José Manuel Esteban Iglesias, que reside en Villanueva de la Serena (Badajoz), en Inclusive (Aprosuba 9) Adjunto de cada uno dni, certificado de discapacidad, nombramiento de cargo de tutor de la junta y aceptación del cargo. Cuando puedas indícame vuestros honorarios. Cualquier duda la hablamos el lunes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2024-04-05','miguel, tras hablar ayer con Promi(llevan la tutela de la hna Máxima en Córdoba) comprobamos que no han abonado ni a ella ni a nosotros el dinero de la herencia de la abuela. Envío email a Rafael, rsantosrex@pajueloabogados.com, el abogado de la tía Buenos días, a fecha de hoy, y tras más de un año de la firma, siguen si estar desembolsadas las cantidades de la herencia que se firmó en Coria. Al tener ustedes los originales deben presentarlas al banco para que proceda al reparto. Adjunto la escritura y las cuentas de los tutelados por la Junta de Extremadura para que procedan a su abono ES04 2103 7130 7100 3001 2010 ------ SOLEDAD ESTEBAN IGLESIAS (28959754V) ES52 2103 7111 7100 3000 2202 ------ JOSÉ MANUEL ESTEBAN IGLESIAS (28955869L) La liquidación del impuesto de sucesiones liquidado se la remitiré en cuanto me lo remita la asesoría. ---------------------------------------------------- Llamo y contrato para liquidar el impuesto al contacto que me da Promi (MªJosé), Jesús Sánchez 606268320, jesussanchez@jssconsultores.com Buenos días, conforme hemos hablado por teléfono, necesitamos encargarte la tramitación y gestión del impuesto de sucesiones de la adjudicación de herencia firmada en Coria de la abuela de 4 hermanos, los Esteban Iglesias (cuya tramitación del Imp de Sucesiones de la otra hna Máxima, ya estáis tramitando con Mª José de Promi de Córdoba). Tres de ellos están tutelados por la Junta de Extremadura-Comisión Tutelar de Adultos, y uno de ellos fallecido después de la adjudicación de herencia de Coria objeto de este impuesto de sucesiones. Se trata de Tomás Esteban Iglesias, del que adjunto cert defunción, últimas voluntades, certificado de discapacidad, dni y testimonio de nombramiento del cargo de tutor que ostentaba hasta su fallecimiento esta Comisión Tutelar de Adultos. Los otros dos hermanos son Soledad Esteban Iglesias, que reside en Nace (Cáceres) y José Manuel Esteban Iglesias, que reside en Villanueva de la Serena (Badajoz), en Inclusive (Aprosuba 9) Adjunto de cada uno dni, certificado de discapacidad, nombramiento de cargo de tutor de la junta y aceptación del cargo. Cuando puedas indícame vuestros honorarios. Cualquier duda la hablamos el lunes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2024-04-05','miguel, tras hablar ayer con Promi(llevan la tutela de la hna Máxima en Córdoba) comprobamos que no han abonado ni a ella ni a nosotros el dinero de la herencia de la abuela. Envío email a Rafael, rsantosrex@pajueloabogados.com, el abogado de la tía Buenos días, a fecha de hoy, y tras más de un año de la firma, siguen si estar desembolsadas las cantidades de la herencia que se firmó en Coria. Al tener ustedes los originales deben presentarlas al banco para que proceda al reparto. Adjunto la escritura y las cuentas de los tutelados por la Junta de Extremadura para que procedan a su abono ES04 2103 7130 7100 3001 2010 ------ SOLEDAD ESTEBAN IGLESIAS (28959754V) ES52 2103 7111 7100 3000 2202 ------ JOSÉ MANUEL ESTEBAN IGLESIAS (28955869L) La liquidación del impuesto de sucesiones liquidado se la remitiré en cuanto me lo remita la asesoría. ---------------------------------------------------- Llamo y contrato para liquidar el impuesto al contacto que me da Promi (MªJosé), Jesús Sánchez 606268320, jesussanchez@jssconsultores.com Buenos días, conforme hemos hablado por teléfono, necesitamos encargarte la tramitación y gestión del impuesto de sucesiones de la adjudicación de herencia firmada en Coria de la abuela de 4 hermanos, los Esteban Iglesias (cuya tramitación del Imp de Sucesiones de la otra hna Máxima, ya estáis tramitando con Mª José de Promi de Córdoba). Tres de ellos están tutelados por la Junta de Extremadura-Comisión Tutelar de Adultos, y uno de ellos fallecido después de la adjudicación de herencia de Coria objeto de este impuesto de sucesiones. Se trata de Tomás Esteban Iglesias, del que adjunto cert defunción, últimas voluntades, certificado de discapacidad, dni y testimonio de nombramiento del cargo de tutor que ostentaba hasta su fallecimiento esta Comisión Tutelar de Adultos. Los otros dos hermanos son Soledad Esteban Iglesias, que reside en Nace (Cáceres) y José Manuel Esteban Iglesias, que reside en Villanueva de la Serena (Badajoz), en Inclusive (Aprosuba 9) Adjunto de cada uno dni, certificado de discapacidad, nombramiento de cargo de tutor de la junta y aceptación del cargo. Cuando puedas indícame vuestros honorarios. Cualquier duda la hablamos el lunes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-04-05','Ana: Correo de ayer de Lourdes, TS SAD-IMAS-CC (lourdes.perez@ayto-caceres.es): "te paso la información que nos envía la empresa de teleasistencia sobre José Manuel del dia 2/4/24. JOSE MANUEL ROMERO MEDIAVILLA, con domicilio en C/ ECUADOR, 36 - 4º DCHA, nos hizo alarma para comunicarnos su intención de suicidarse. Se derivó a emergencias sanitarias" ······························································································································· Mi respuesta: "Gracias por informar. Precisamente hablé con él ayer, el lunes y creo que el miércoles, pero no me dijo nada al respecto. Con la Educadora de Futuex estuvo el lunes y también habla con ella con mucha frecuencia. Desde este programa tampoco me han comunicado nada sobre esta incidencia. Si que ha planteado otras demandas, como es habitual en él. Lo cierto es que no es la primera vez que verbaliza estas intenciones, tanto a los servicios de urgencia, como al Gabinete Técnico de la CTAEx, así como a las distintas educadoras que ha intervenido con él, y la mayoría de las veces no llega a realizar acción/intento autolítico alguno, pero claro, además de crear la alarma, nunca se sabe cuándo puede llegar a intentarlo de verdad. Perfecta la derivación a los servicios de emergencia sanitaria. Pongo en copia a mi jefa y la educadora y coordinadora del programa gestionado por Futuex para su conocimiento y para que también desde estar alerta e intervenir al respecto."','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='AVILA'and apellido2='FEMIA'),'2024-04-03','Ana: Correo de Soraya Masa, Jefa Ud. Programas Asistenciales, a Alicia Glez, Directora CSS-Plas (alicia.gonzalezt@salud-juntaex.es): "Hola Alicia, este es el caso de que te he hablado esta mañana, os lo paso para que lo vayáis viendo, porque entiendo que la orden judicial puede llegar pronto." Adjunta Informe de seguimiento de Psiquiatría, Hª Clínica y Escrito de Procuradora de la madre instando al internamiento urgente. ·································································································································································································· Correo de Soraya a Ángel, A. Jurídico - CTAEx: "después de hablarlo con Mayte y Ana, creo que lo que procede decir a Abogacía que la persona debe ingresar de forma involuntaria de inicio en la UHB que corresponda (entendemos Cáceres) para valoración y posterior derivación al Centro Socio- Sanitario de Plasencia, si procede. Creo que se debería ir contestando eso a Abogacía, y voy pasando el expediente al Centro Sociosanitario de Plasencia para que lo vayan viendo." ··································································································································································································· Correo de Alberto, Jefe Secc. Ecca.: "ANA: LA CUESTIÓN ES QUE, ANTES DE REALIZAR OPERACIONES ECO...HAY QUE HABLAR CON FAMILIA YA QUE: • TODA LA FAMILIA (TUTELADO, MADRE, PADRE, HNO. Y HNA.) ESTÁN EN LAS 3 CCC EXISTENTES COMO TITULARES O AUTORIZADOS. • LA PENSIÓN TUTELADO ESTÁ EN UNA CCC BSANTANDER, LA DEL PADRE EN OTRA CCC BSANTANDER Y LA DE MADRE EN CCC UNICAJA.  EL CENTRO DEL PADRE (1.800 €/MES APROX.) SE ESTÁ COBRANDO EN LA CCC EN LA QUE COBRA LA PENSIÓN EL TUTELADO. • LAS 3 CCC TIENEN SALDOS RELATIVAMENTE IMPORTANTES...QUE SE ESTÁN MINORANDO DEBIDO A LOS ELEVADOS COSTES DEL CENTRO DE PADRE-MADRE • HAY QUE INDICAR A LA FAMILIA QUE HAY QUE HACER CAMBIOS...CAMBIAR DOMICILIACIONES DE RECIBOS DE CENTROS O SIMILARES. ANA/MARÍA: MARÍA ESTÁ HABLANDO CON B.SANTANDER PARA EL TEMA DE TITULARES Y AUTORIZADOS...PERO NO PODEMOS DAR ÓRDENES TAN A LA LIGERA CUANDO HAY OTROS TITULARES."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2024-04-05','miguel, reenvío de nuevo a Verónica de la asesoría email y llamo a la asesoría (no está) Buenos días Verónica, necesitamos me confirmes si podéis tramitar con la notaria de Montijo (Jacinto) esta cancelación de hipoteca. --------------------------------------------------------- contestacion de la asesoria Buenos días. Disculpe el retraso en la contestación, estamos en plazo de liquidación de los impuestos trimestrales y no puede contestarle antes. He consultado en notaría sobre el asunto, y también en Ibercaja. Me dicen en notaria que el encargo de cancelación lo puede hacer tanto la titular registral actual como el prestatario , quien firma la cancelación es el apoderado del Banco , pero tienen que figurar en la escritura quién la solicita. La directora de la oficina de Pueblonuevo no va todos los días pero tengo su correo , le puedo mandar la documentación que usted envió a mi compañera para que emitan el Certificado de Cancelación Económica. No se si el prestatario sigue teniendo cuenta en Ibercaja porque le van a cobrar por el trámite de emitir el certificado e ir a notaría a firmar la cancelación , creo que los honorarios de Banco son unos 100 €, si tiene cuenta se lo cargarían ahí, en otro caso hay que abonarlo. Respecto a los costes de cancelación , hay que sumar a los gastos bancarios (100 €) , notaría unos 200 € , Registro de la Propiedad unos 150 € y Gestión 121 € , unos 600 €, redondeando , puede ser el coste total . Si me da el visto bueno para encargarnos la gestión , procedería a solicitar a la entidad , no obstante hay que firmar una solicitud que tendrán que firmar ustedes. Te reenvío de nuevo el email del 22-3-24.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-04-05','Ana: Correo de ayer de Lourdes, TS SAD-IMAS-CC (lourdes.perez@ayto-caceres.es): "te paso la información que nos envía la empresa de teleasistencia sobre José Manuel del dia 2/4/24. JOSE MANUEL ROMERO MEDIAVILLA, con domicilio en C/ ECUADOR, 36 - 4º DCHA, nos hizo alarma para comunicarnos su intención de suicidarse. Se derivó a emergencias sanitarias" ······························································································································· Mi respuesta: "Gracias por informar. Precisamente hablé con él ayer, el lunes y creo que el miércoles, pero no me dijo nada al respecto. Con la Educadora de Futuex estuvo el lunes y también habla con ella con mucha frecuencia. Desde este programa tampoco me han comunicado nada sobre esta incidencia. Si que ha planteado otras demandas, como es habitual en él. Lo cierto es que no es la primera vez que verbaliza estas intenciones, tanto a los servicios de urgencia, como al Gabinete Técnico de la CTAEx, así como a las distintas educadoras que ha intervenido con él, y la mayoría de las veces no llega a realizar acción/intento autolítico alguno, pero claro, además de crear la alarma, nunca se sabe cuándo puede llegar a intentarlo de verdad. Perfecta la derivación a los servicios de emergencia sanitaria. Pongo en copia a mi jefa y la educadora y coordinadora del programa gestionado por Futuex para su conocimiento y para que también desde estar alerta e intervenir al respecto." ······································································································································· Llamada de José Manuel con varias demandas: quiere que le demos 50€/semana para comprar comida con la educadora. ··············· Quiere que le solicite el Servicio de Comedor de la Residencia Cervantes. ············· Insiste en la necesidad de comprar la maquina de afeitar y el móvil. Ya ha quedado con la Nieves, Ed. en que acudirán el lunes a pedir presupuestos. ············· Le pregunto sobre el incidente con el TAD, sobre lo cuál vuelvo a escribir a Lourdes - IMAS y a Futuex: "Sólo comentaros que acabo de hablar con José Manuel, llamaba para demandar otras cuestiones, pero le he preguntado por el incidente. Dice que le entró mucha ansiedad y que le tocaba ya el inyectable que le administraron el miércoles día 3. Entiendo que la justificación está ahí, que ya necesitaba la medicación."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PRUDENCIO'and edp.apellido1='RODERO'and apellido2='COMERON'),'2024-04-05','Ana: Correo de Felisa Custodio, TS del CAMF (trabajadora_social_alcuescar@imserso.es), al ctutelar@ en respuesta al correo que le envió Lourdes, S. Ecca. Me pone en copia: "- He comprobado en la cartilla bancaria y debe dos mensualidades a su hijo por manutención, en concreto mayo y junio de 2023, 240 euros en total. - Debe pagar el arreglo de la silla de ruedas por el accidente que tuvo, con la indemnización correspondiente. Tengo el presupuesto con el gasto, cuando la ortopedia me mande la factura os la hago llegar. 865,40 euros fue el presupuesto que se mandó a la aseguradora del vehículo que causó el atropello. - Adjunto informe del Administrador del CAMF con la deuda pendiente que tiene con el centro y no comunicada a la unidad de recaudación ejecutiva de la Seguridad Social, por lo que se puede hacer una transferencia y ponerse al día. Importe: 5690,73 euros Mañana viene Unicaja al CAMF y se pueden hacer estos pagos con mi supervisión. Por otro lado, - Os adjunto la última notificación de embargo emitida por la Tesorería de la Seguridad Social, por la que tiene una deuda pendiente de 3296,13 euros. Supongo que será embargada de la cuenta ahora que tiene saldo. - No tiene seguro de decesos dado que los recibos eran devueltos. En su defecto hizo voluntades anticipadas donando su cuerpo a la Facultad de medicina el día que fallezca. Dice que le da igual tener o no seguro de fallecimiento. - Si lo estimáis oportuno, para tabaco y cafetería podría tener una asignación libre periódica de 50 euros en lugar de los 40 euros que propuse en mi informe."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='AVILA'and apellido2='FEMIA'),'2024-04-05','Ana: Tras revisar informe social de 2022 emitido por Eva Luz Jiménez, TS SSASB, Mancomunidad Tajo-Salor, dirigido al Juzgado, la llamo al Ayto. de Aliseda (927 27 70 02). Me dicen que Eva está de baja. No saben si la semana que viene se incorporará. ····················· En el informe social no constan los datos de contacto de Tomás, hermano de José Luis, quién ha promovido los recursos para sus padres y apoya mínimamente al hermano. Reside en Madrid. ······································································· Informo a Alberto, jefe secc. ecca. ··· La semana que viene volveré a llamar al Ayto. ······························································································································································································ Maite me facilita datos de contacto de Tomás, hermano: : 916 808 331 / 688 915 073. Correo electrónico: jtavila66@gmail.com ······························ Tras hablar con Tomás, envío correo a Alberto, Jefe Secc. Ecca.: "En relación a las cuentas, me dice que el dinero que hay en las tres cuentas bancarias es de los tres, su hermano José Luis y sus padres. Por lo que plantea una de tus mismas propuestas, que se divida a parte iguales entre los tres y un tercio se le ingrese en cuenta sólo a José Luis. Ya decidís vosotros si se le abre una nueva cuenta para él sólo y se quita como titular de las otras o cómo queréis hacerlo. En el pueblo van a reabrir sucursal del Santander (me pasará el contacto del Director, con el que ya habló de esta situación en su día) y Unicaja. En cuanto al Servicio de Ayuda a Domicilio que tenía, tuvieron que darlo de baja, pues desde que ingresaron los padres en centro José Luis no dejaba de entrar al Auxiliar. Hicieron comunicación tanto a la empresa como al SEPAD. Por lo que hay que asegurarse que ya ni cobra la prestación vinculada ni abona este servicio. *José Luis también abandonó el servicio de comedor municipal (residencia del municipio), por lo que en este concepto no deben pasarle nada tampoco ya." ··································································································································· En cuanto al ingreso de su hermano, me informa de que **hay una chica del pueblo que tiene la llave de la casa del hermano, cuando haya que activar el 112 podrá avisarla para que acuda a abrir la puerta. ············· José Luis no toma la mediación, a al cita de febrero 2024 en ESM tampoco consiguió que acudiera. No tiene conciencia de enfermedad, no quiere control, no acepta apoyos/ayuda, ni seguimiento, redes sociales... ······· Se niega a ponerse vacunas, del COVID sólo consiguieron que se pusiera 1. ······· Malcome, hace compras en el SPAR. ···· No maneja las monedas, tiene una bolsa llena. Cada vez que va a comprar acude con un billete de 50 € y todos los meses retira 600€ de la oficina bancaria. ··············· *Necesita ROPA, pues toda la que tiene o le queda pequeña o está para tirar. ··································· A él le gustaría que su hermano fuera a Centro de Discapacidad con Taller Ocupacional.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2024-04-05','miguel, hablo con Mª Victoria Tena 924-251626 y 635-146442 de la asesoria para la declaración de la renta desde 2019 sancionaron desde AEAT, ella hará las que le permita el sistema. Le explico su situación personal (usufructuaria junto a su exnuera, y le corresponde la nuda propiedad del total de bienes )los bienes inmuebles que tiene y que está pendiente de que se tramite hacer y firmar la herencia en notaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2024-04-03','-Amalia ; con respecto a la compra de vivienda en Olivenza , Miguel indica: Buenos días para gestionar la venta hay que pedir autorización judicial al juzgado porque lo exige el 287 CC al ser tutelado. Necesitaremos una tasación oficial con el precio de venta para enviársela al abogado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2024-04-05','Ana: Llamo a Alicia, TS SSASB - Alcuéscar (927 384 002): está atendiendo al público, le pasarán nota para que me devuelva la llamada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2024-04-05','miguel, Tere me reenvía email de Toni de Futuex: "Hola Teressa, buenas tardes Desde el equipo de apoyo social comunitario, se comunica la presencia de un abogado, que no entendemos muy bien,.. si está turnado de oficio, o que. El caso que llamó a la compañera, imaginamos le daria Pablo el telefono,. e informó sobre el proceso legal en curso destinado a la defensa de Pablo frente a un cargo por delito de atentado a la autoridad, sucedido en septiembre de 2022. En todo momento, se le dice que esta persona está tutelada y que seria bueno que se pusiera en contacto con el area júridica de la comisión, pero no sabemos si lo ha hecho. El abogado que se ha puesto en contacto con la educadora del equipo se llama Manuel Calvente, cuyo número facilitado es el siguiente: 670510783. Hasta la fecha, no se ha establecido una fecha para la audiencia, aunque se solicita una pena de 2 años de prisión debido a antecedentes penales previos de Pablo. En este momento, se está llevando a cabo la presentación de evidencia concerniente al estado de salud mental de Pablo, a través de informes forenses, parece ser. Es pertinente añadir que se encuentra pendiente otro caso similar, también relacionado con un supuesto atentado a la autoridad. Por otra parte, Pablo desea averiguar si tiene derecho a los fondos de la cuenta que permanece activa en Ibercaja perteneciente a su hermano, Guillermo. En consecuencia, ha iniciado un diálogo personal con un abogado, quien me ha comunicado su compromiso de analizar el caso. Asimismo, este abogado ha manifestado su responsabilidad en la representación legal de Pablo en asuntos judiciales. Le explicamos nuevamente que esto le corresponde a sus representantes legales.. pero no se, igual seria bueno que se hablara directamente con esta persona, para aclarar realmente de donde ha salido.. y que asuntos está llevando de Pablo. " ---------------------------------------------------------- Llamo al abogado Manuel Calvente 670-510783 y tras la conversación envío email a Alberto y Tere: Buenos días, he hablado con el abogado, por lo que me ha explicado él y otro abogado(del que no sabe quién es ni el número de procedimiento) han sido asignados por el turno de oficio por lo que no hay que abonar nada. Como sabéis por su capacidad económica tiene derecho al turno de oficio. Según me comenta, el lunes hablaré con él porque iba a un juicio, necesita le enviemos los informes médicos y sociales que podamos (Tere) para enviárselo el lunes, junto con su certificado de discapacidad y testimonio de incapacidad, nombramiento a la Ctaex y aceptación del cargo. Tiene en contra los antecedentes penales y ambos procedimientos pasaron de lo juzgados de 1º instancia al juzgado Penal de Don Benito (desde que se abrió la fase de juicio oral). Va a intentar la inimputabilidad recogida en el Código Penal, pero ya veremos si no acaba en la cárcel, por delito de atentado a la autoridad (se enfrentó borracho a la policía) Tere recaba todo lo que puedas y envíamelo para enviárselo al abogado el lunes. Alberto, olvídate porque no se va a abonar nada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PILAR'and edp.apellido1='JIMENEZ'and apellido2='AGUILAR'),'2024-04-05','Ana: Correo de Ángel, A. Jurídico: "En relación al alquiler de Pilar Jiménez Aguilar, os envío el nuevo contrato de alquiler y la rescisión del anterior, sin penalización. Queda pendiente: 1. Incluir en ambos contratos la fecha en la que van a abandonar la actual vivienda y la fecha en la que van a empezar en la nueva vivienda. 2. Si la renta que indican en el contrato puede asumirla Pilar, en su proporción. 3. El resto de ambos contratos están perfectos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='AVILA'and apellido2='FEMIA'),'2024-04-05','Maite: Juan Tomás, hermano de José luís. Tf de contacto 916808331/688915073. Correo electrónico: jtavila66@gmail.com.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO DAVID'and edp.apellido1='REBANALES'and apellido2='NIETO'),'2024-04-05','Alberto : ESTRELLA: EN ESTE CASO CONCRETO, SEGUIMOS INTENTANDO CARGAR EL SEGURO DE DECESO. SI LA ASEGURADORA TIENE O SE LE OCURRE UNA FORMA DE QUE TUTELADO NO PUEDA PROCEDER A LA DEVOLUCIÓN DEL RECIBO, Y PARA NOSOTROS ES VIABLE, LA APLICAMOS. ENTIENDO QUE LA LIBERTAD DEL TUTELADO, A LA HORA DE DECIDIR SI QUIERE O NO ABONAR UN SEGURO DE DECESO, NO DEBE CONDICIONAR QUE LOS CIUDADANOS, A TRAVÉS DEL PAGO DE SUS IMPUESTOS, TENGAN QUE ABONAR SU FUNERAL, CUANDO EL DISPONE DE LOS RECURSOS NECESARIOS PARA ELLO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2024-04-04','Maite: he hablado con Mercedes. Me dice que necesita dinero para ropa, una tablet u ordenador... le digo que tiene que solicitarlo a través de la trabajadora social del centro, Nieves. También me cuenta que escribió un libro hace tiempo que presentó a un certamen en Badajoz y quiere recuperarlo para volver a presentarlo. No sé si es cierto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEBASTIAN'and edp.apellido1='PAREDES'and apellido2='DICHA'),'2024-04-05','-Amalia : está en CSS Merida','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEBASTIAN'and edp.apellido1='PAREDES'and apellido2='DICHA'),'2024-04-08','email de Angel a Alberto: Buenos días, Alberto, en relación con la denuncia que presentamos al Juzgado poniendo en su conocimiento que un tutelado nuestro, Sebastián Paredes Dicha, estaba falsificando documentos del Sepad, nos han citado para el día 19/4 y el Fiscal interesa: “1º- Que se reciba declaración judicial sobre los hechos a la persona denunciante, a fin de que se ratifique, en su caso, en la denuncia y aclare el segundo apellido de Miguel Ángel Delgado; especifique los lugares donde presuntamente se está cometiendo el delito -dónde se presentan los documentos falsos; dónde se ha abierto una cuenta por parte de los investigados y cuantas otras circunstancias sean relevantes para determinar la competencia territorial- y aclare si los denunciados han conseguido o no, total o parcialmente, su propósito de extraer dinero.”','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2024-04-08','miguel, envío nuevo email a la asesoría de Montijo Proyec. Consultores >mjgabaldon@proyecconsultores.com> Buenos días, aceptamos el presupuesto. Envíennos dicho presupuesto y el modelo de solicitud de la cancelación de hipoteca para que lo firme el representante de la Comisión Tutelar. Desconocemos si la compradora tiene o no cuenta en Ibercaja, pero no creo sea relevante porque el vendedor que es quien tiene obligación de levantar la carga registral está tutelado por la Comisión Tutelar, era el prestatario y propietario de la vivienda como puede ver en la nota simple. --------------------------------------------- Envío email a la compradora Ana María Muñoz Toro >anamariamt99@gmail.com> Buenos días, como sabe intentamos en reiteradas ocasiones que Ibercaja procediese a tramitar a través de su gestoría la cancelación de hipoteca pero no habido forma que nos atendiesen y lo tramitasen. Por ese motivo hemos puesto en manos de la asesoría (que nos ha recomendado Jacinto de la Notaria de Montijo) la solicitud de cancelación de la hipoteca. Le dejo los datos por si quiere ir informándose de los avances en la tramitación que se produzca en adelante. Proyectos Consultores de Montijo (Verónica 924-454127) Llame a Verónica por si necesitan algún dato de usted.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2024-04-08','Ana: Envío correo a Juan Carlos, Aux. adtvo (juancarlos.cano@salud-juntaex.es): "Adjunto la siguiente documentación para remitir por REGISTRO a la Dirección Provincial del INSS DE Cáceres: - Comunicación de variación de domicilio y DOMICILIO A EFECTOS DE COMUNICACIONES - Testimonio de Auto de nombramiento - Acuerdo de Aceptación del cargo - Decreto de nombramiento de Directora Gerente del SEPAD - Resolución Delegación de Funciones – Presidenta de CTAEx - DNI Presidenta CTAEx (Representante Legal)"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2024-04-05','Ana: Correo de Minerva, TS CR Cervantes: "Adjunto remito, firma de uso de Cesión de Doña Mª Luisa Montaña Aliseda a su hija. Desde el centro no teníamos conocimiento de esta gestión realizada por Mª luisa hasta esta mañana que ha llegado al correo del centro esta documentación. Mª Luisa me solicita copia del documento, me decís si se la puedo dar." ······················ El documento hace alusión a la vivienda de Mª Luisa. ·············· *Lo reenvío a los A. Jurídicos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SALVADORA'and edp.apellido1='CHAVES'and apellido2='MENDOZA'),'2024-04-08','Ana: Envío corre a Belén Pavón, responsable Residencia (Belen.asoma@outlook.es): "En relación a Mª SALVADORA CHAVES MENDONZA, nos remiten desde Abogacía General de la Junta, el documento que adjunto solicitando documentación e información para proceder a la REVISIÓN DE LAS MEDIDAS JUDICIALES DE APOYO. ¿Podrías por favor indicarme si disponéis de ello en su expediente y en tal caso facilitárnoslo? Esto es lo que especifican: “1) Todos los informes médicos de los que pueda disponer o recabar respecto de D/Dª MARÍA SAVADORA CHAVES MENDOZA, o en su caso informe sobre los motivos para no hacerlo. 2) Aporte a los autos el nº del DNI, lugar y fecha de nacimiento, domicilio y teléfono de D/Dª MARÍA SAVADORA CHAVES MENDOZA. 3) Y aporte a las actuaciones el nombre DNI, lugar y fecha de nacimiento, domicilio y teléfono de todos los familiares más próximos a D/Dª MARÍA SAVADORA CHAVES MENDOZA, con objeto de ser oídos en la comparecencia que en su día se celebrará.“ El DNI sí lo tenemos, que por cierto, hay que renovarlo en julio de este año. Pero nos constan informes médicos en el expediente ni datos de familiares. Ya nos decís qué nos podéis facilitar. Y en caso de no contar con informes recientes, ¿podríais informarme del nombre del Médico de Atención Primaria para poder solicitárselos?" ····························································································································································································· Respuesta de Belén Pavón: "En relación a los informes médicos de María Salvadora, su médico de cabecera es JAVIER OLMEDO PEÑARANDA, pasa consulta aquí en Villa del Rey, martes y jueves de 10.00h a 12.00h aproximadamente, o tal vez puedas contactar con la trabajadora social de Villa del Rey para que te facilite toda su información médica, no sé como funciona el tema de informes médicos la verdad, yo cuando he tenido que solicitar una historia clínica de algún familiar mío lo he hecho a través de ventanilla de Hospital San Pedro de Alcántara. ESTE ES EL EMAIL DE LA TRABAJADORA SOCIAL: almudena@tajosalor.es Su domicilio actual es RESIDENCIA DE MAYORES DE VILLA DEL REY, AVENIDA PÁRROCO PEGUERO S/N, 10960, VILLA DEL REY CÁCERES, TELÉFONO DEL CENTRO 633 17 65 82. FAMILIARES: • Fernanda (prima que vive aquí en Villa del Rey) 619 51 33 39 • Emi (prima que vive en Madrid) 666276445 Tomo nota de que hay que renovarle el DNI en julio de este año."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2024-04-08','TERE/ALBERTO: EN PRINCIPIO NO PEDIMOS PF YA QUE DEBERÍA VALER CON LOS INGRESOS CON LOS QUE CUENTA... TERE INFORMARÁ CUANDO SE PRODUZCA EL CAMBIO. TERE CAMBIARÁ PENSIÓN A CCC B.SANTANDER ES80 0049 0301 6221 9052 4478 EN CASO DE QUE, UNA VEZ QUE ENTRE EN EL NUEVO CENTRO, SEA NECESARIO, TERE LO TRAMITARÁ. DECESO: NO TIENE...HAY QUE TENER EN CUENTA QUE DEBEMOS APARTAR MÍNIMO 3.000 €','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO MARIA'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2024-04-08','TERE/ALBERTO (2024/04/05): LA SITUACIÓN DE DIEGO SANCHEZ SANTIAGO ES EXCEPCIONAL Y ESTÁ SUPONIENDO QUE LOS GASTOS SON MUCHO MAYORES QUE LOS INGRESOS (-8.000 €/AÑO APROXIMADAMENTE). SE ACUERDA MANTENER ESTA SITUACIÓN, AL MENOS HASTA 12/2024...PARA DAR TIEMPO A OBSERVAR LA EVOLUCIÓN DE DIEGO Y DE SU SITUACIÓN ECONÓMICA (GASTOS Y NUEVOS INGRESOS (CAMBIO GRADO DEPENDENCIA, OTROS.)).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSARIO'and edp.apellido1='SOLIS'and apellido2='BERMEJO'),'2024-04-08','Ana: Envío a Felisa Custodio, TS CAMF (ctrabajadora_social_alcuescar@imserso.es): "A petición de Alberto, Jefe de la sección económica del Gabinete Técnico de la CTAEx, te paso la siguiente información (copio literalmente): 1. “ROSARIO SOLÍS BERMEJO: ANA: HAY QUE HABLAR CON CENTRO PK LA EVOLUCIÓN DEL SALDO (DE LAS 2 CCC EN SU CONJUNTO, ES NEGATIVO...PROBLEMA: HEMOS ABONADO EN AGOSTO DE 2023 VACACIONES X 2.250 € (ANA: TIENE SALDO...UNICA CONDICIÓN QUE PONEMOS ES QUE NO HAYA EVOLUCIÓN NEGATIVA A FINAL DE AÑO)” En mi opinión estas vacaciones son necesarias para ella y mientras se pueda y ella quiera, yo voy proponer que se acepte el presupuesto y asista a los viajes. Como ves Alberto no se opone, pero habría que estar al tanto con el resto de gastos para que no todos los años gasta más de lo que ingresa. No sé exactamente el saldo del que dispone." ·································································································································································································· Respuesta de Felisa: "Comparto tu criterio, de todas formas, no creo que este año pueda ir de vacaciones, tiene problemas con la cadera y son viajes muy largos. Lo tengo en cuenta." "No obstante, tienen ahorros y ambas residentes no tienen hijos y para que el día de mañana lo hereden familiares que no se ocupan de ella…."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='DEBON'and apellido2='CHENIQUE'),'2024-04-08','Ana: Envío al CAMF (trabajadora_social_alcuescar@imserso.es): "A petición de Alberto, Jefe de la sección económica del Gabinete Técnico de la CTAEx, te paso la siguiente información (copio literalmente): ... 2. Mª ISABEL DEBÓN CHENIQUE: ANA: HAY QUE VER SITUACIÓN ECO TUTELADA: EVOLUCIÓN ULTIMOS 12 MESES -1.572,59 €... YO DETECTO PROBLEMA EN VACACIONES: 2.250 € (ENTIENDO QUE ESTE GASTO, X CARACTERÍSTICAS TUTELADA, SIEMPRE VA A SER ELEVADO + TAXI (1.050 € (supongo que esto no se repetirá...o si?) + TELEFONÍA: NO SE SI TENIAMOS ACUERDO CON CENTRO (YA QUE FUNCIONA A TRAVÉS DE CONTRATO) PARA TELEFONIA...ESTAMOS ABONANDO 90,94 €/MES (EN EL 22 ERAN 60 €/MES)...ESTO SI HAY QUE CONTROLARLO...MUY CARO, NO? ANA: LO QUE QUIERO DECIR ES QUE CON GASTOS COMO ESTOS, CUALQUIER EVENTUALIDAD: TAXIS, ACOMPAÑAMIENTOS, ETC...HACEN QUE EVOLUCIÓN SEA NEGATIVA...Y CON LOS INGRESOS (Y COSTE CENTRO QUE TIENE, ES DIFÍCIL LA RECUPERACIÓN). Con respecto a Isabel, ¿podríais buscar una alternativa al contrato de teléfono, sino me temo que Alberto va a acabar “exigiendo” que se cambie a tarjeta prepago en lugar de mantener el contrato, pues el gasto actual es muy elevado. Por lo demás, plantea prácticamente el mismo problema que con Rosario, la carestía de las vacaciones en relación a sus ingresos. Pero yo me mantengo en la misma posición. Iremos viendo y tendremos que intentar controlar algo más los gastos." ································································································································································································ Respuesta de Felisa: "Le voy a decir que se vaya a Orange para intentar abaratar factura, tiene ahorros y aquí está fija y a “pensión completa”, abonando el 75 % de su pensión al centro. Tampoco creo que vaya este año de vacaciones, no le gustaron el año pasado. No obstante, tienen ahorros y ambas residentes no tienen hijos y para que el día de mañana lo hereden familiares que no se ocupan de ella…."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2024-04-08','miguel, envio email a Manuel Calvente 670510783: Buenos días Manuel, conforme hemos hablado el viernes en relación el tutelado Pablo Galan. A parte de adjuntar sentencia de incapacitación, nombramiento a la Ctaex, aceptación de cargo, adjunto los informes que me remite la trabajadora social, algunos de ellos antiguos pues no hay nada nuevo. Adjunto también a parte de certificado de discapacidad y el facultativo, el auto por el que se le ingresó involuntariamente en el Centro Socio sanitario y del cual él mismo se dio de alta. Lo intentamos comunicar al jzdo de castuera nº1 que era su juzgado de referencia para rendiciones de cuenta etc, pero se inhibieron indicando que el competente era el jzdo de 1º instancia de Cáceres, al que también notificamos vía Lexnet pero no asignaron ningún juzgado y procedimiento por lo que la comunicación de su alta voluntario no ha sido conocida y resuelta por ningún juzgado. Dejo mis datos debajo para aclarar cualquier duda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='OSCAR'and edp.apellido1='BLAZQUEZ'and apellido2='PEREZ'),'2024-04-08','Ana: Llamada de Cristina, TS URA- CSS-PALASENCIA: Óscar salió ayer de pase por la mañana para ver a su madre, residente en la localidad de Plasencia, la premisa era que regresaría al a hora de comer, pero no lo hizo. Le han llamado numerosas veces desde entonces, tanto ayer como hoy. Al principio decía que volvería más tarde, pero hoy ya dice que no va a regresar. ··· *Lleva desde ayer por la mañana sin tomar medicación. ································ *Le han dicho a la madre que tendrán que avisar a Policía o Guardia Civil ··································· Llamarán a la Guardia Civil para comunicarlo para que vayan a buscarlo y le lleven de regreso al centro. ··········································································· **Nueva llamada de Cristina, finalmente Óscar, a media mañana ha regresado al centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2024-04-08','-Amalia ; informo a todos los implicados del cambio. Escribo a Dia , no cogen tf. por email.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CIRCUJANO'and apellido2='ZAMBRANO'),'2024-04-08','-Amalia . desde CSS solicitan se le envie a la hna 50€ para abonar el taxi que la trae a verlo una vez al mes . Yo les pido a las compañeras nuevas que lo hablen con las otras TS , pq se denegó estas peticiones. Sección eco lo ha aceptado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEMESIA'and edp.apellido1='GARCIA'and apellido2='PANIAGUA'),'2024-04-08','Ana: Correo de Piedad Cabezas, TS de SSASB - Mancomunidad de Trasierra (670 29 30 45 // ssbp@trasierratierrasdegranadilla.es): "Buenos días, remito informe social de NEMESIA GARCIA PANIAGUA. Dicho informe también se ha remitido al juzgado ya que ha sido solicitado por ese organismo. También se remite el escrito en el cual se cita a esta persona a valoración en juzgado el 3 de junio. En el informe se refleja que no cuenta con nadie que la pueda acercar y a parte la persona no está para desplazarse, solicitando que se haga la comparecencia por otras vías como puede ser telemáticamente como se ha realizado en otras situaciones." ······························· Lo reenvío a la Secc. Jurídica. ··························································· Guardo Informe Social en el expdte. Según el mismo, Nemesia tiene residiendo en el C. Residencial de Mayores - Guijo de Granadilla. Presenta deterioros físicos propias de la edad, nada reseñable. Cada vez le cuesta más desplazarse, incluso con el andador. No obstante casi a diario, muy lentamente, continúa acudiendo a su casa en la que sigue acumulando basura. Pronto será necesario realizar otra limpieza en la vivienda por salubridad y para prevenir riesgos. ·············· Sigue siendo reticente a la hora del aseo personal, no obstante un día a la semana la duchan. ··············· *No mantiene contacto con ningún familiar a día de hoy.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2024-04-08','-Amalia : Se acepta desde la parte social el primer pago de extra , se envia la petiion a Lourdes siguiendo el protocolo fijado por Alberto. Tras sesión con Ceferino, este me comenta que ya quiere disponer del extra correspondiente al segundo trimestre. En este trimestre ( abril-junio) solicita un extra de 450 euros para una Nintendo Switch, juego y complementos. Cuando esté disponible en el banco me avisáis y enviáis autorización para retirar dicho dinero.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ISABEL'and edp.apellido1='OTANO'and apellido2='GRAO'),'2024-04-08','Amalia : se recibe email de su padre , se desconoce desde la CTAEX nueva sentencia . Buenos días Amalia Soy Javier Otano, padre de Macarena Otano. Todo bien? Espero que si. Tenemos nuevamente un pequeño problema con la Paga No Contributiva de Macarena y quiero comentarlo contigo. Esta mañana ha ido Macarena a retirar el dinero de la cuenta que le ingresa mensualmente la Junta y no ha podido hacerlo porque según le dicen en el banco, esa cuenta está condicionada a la autorización de una tal Estrella. Entiendo que esa persona pertenece a la Comisión Tutelar de Mayores. No entiendo muy bien porque sucede esto cuando realmente Macarena ya no está bajo la tutela de la Comisión Tutelar de Mayores, (su incapacitación fue revisada hace unos meses en una nueva sentencia judicial), y pasamos a tener Esperanza y yo Guarda de hecho sobre ella, por lo cual entendemos que la cuenta de Macarena ya no necesita autorización del tutor para su retirada. Si pudieras aclararnos qué ocurre quedaríamos agradecidos para nuestra tranquilidad y sobre todo la de Macarena. Gracias por tu atención y feliz dia. Enviado desde mi iPhone','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOLORES'and edp.apellido1='MACARRO'and apellido2='CAMACHO'),'2024-04-08','TERESA RECIBO LLAMADA DE LA TS DE LO SANTOS 45713 NATI LUNES Y MARTES RESTO DE LA SEMANA EN FUENTE DEL MAESTRE 924530122 ME COMENTA QUE DOLORE NO PUEDE SACAR DINERO Y QUE NI SIQUIERA SABE QUE ESTA CURATELADA ME COMENTA LA SITUAICON URGENTE DE LA VIVIENDA LLENA DE RATAS Y EN MUY MAL ESTADO LE COMENTO QUE PODEMOS PEDIR INGRESO INVOLUNTARIO Y QUE OTRA OPCION URGENTE ES QUE SE VARA DE ALQUILER HATA QEU PODAMOS PONER LA CASA AL DIA PUES AHORA MISMO NO TIENE NADA AHORRADO LA COMPAÑERA DE FUTUEX LA VISITA MAÑANA PARA ESTABLER PRESUPUESTOS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='DAVILA'and apellido2='HIDALGO'),'2024-04-08','TERESA Desde el Equipo de Apoyo Social Comunitario, les informamos sobre la situación actual de Rafael Dávila y la necesidad urgente de abordar el aumento de su deterioro cognitivo. Tras una evaluación reciente, hemos observado un incremento significativo en el deterioro cognitivo del Rafael, lo que nos lleva a considerar que sería beneficioso iniciar el trámite para su ingreso en una residencia de mayores. Este cambio en su condición requiere una atención más especializada y continua, que actualmente no puede ser proporcionada adecuadamente en su hogar. El día 11 de marzo de 2024, recibimos una comunicación de su auxiliar, quien informó que dejó los grifos abiertos y ocasionó un desbordamiento de agua en su vivienda. Además, durante los seguimientos que llevamos a cabo de manera semanal, hemos observado que presenta episodios frecuentes de desorientación, como dejar la puerta de su casa abierta y olvidar dónde se encuentra el interruptor de la luz. A pesar de contar con ayuda a domicilio y teleasistencia, consideramos que estos recursos no son suficientes para garantizar su seguridad y bienestar, dada la progresión de su deterioro cognitivo. Durante el seguimiento llevado a cabo el 19 de marzo de 2024, hemos constatado que había bajado los plomos de la luz, lo cual impide la provisión de asistencia remota en caso de requerirla. Adicionalmente, se ha observado que el teléfono móvil se encontraba descargado y no se hallaba el correspondiente cargador ni la caja de este. Al adentrarnos en el ámbito doméstico, hemos notado la ausencia del electrodoméstico microondas, desconociendo el motivo de su desaparición según Rafael. Tras un intercambio dialogado, ha manifestado su reconocimiento de la necesidad de recibir apoyo, considerando la posibilidad de trasladarse a una residencia como alternativa viable. Asimismo, ha expresado su disposición para iniciar los procedimientos pertinentes en tal sentido. En un seguimiento presencial fechado el 4 de abril, Rafael nos ha informado que sus arrendadores le están intimidando verbalmente con el propósito de que desaloje la vivienda debido a los daños por humedad que se han generado. Manifestó estar profundamente preocupado por esta situación y reiteró su disposición para iniciar el proceso de ingreso en una residencia asistencial, en caso de ser necesario. Ante esta situación, consideramos beneficioso iniciar los trámites necesarios para su ingreso en una residencia de mayores, donde pueda recibir la atención y el cuidado especializado que requiere en este momento de su vida. LE FACILITO MODELO DE INFORME MEDICO E INFORME SOCIAL PARA SOLICITAR RESIDENCIA VIA DECRETO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CASARES'),'2024-04-08','Ana: Tras llamada de Ángela, TS - Placeat (637 765 025), llamo y envío correo a Marina Carmen, Jefa Secc. PNC (marinac.jimenez@salud-juntaex.es): "Tal y como hemos acordado mediante conversación telefónica, te remito este correo con los datos de la persona a cargo de la CTAEx, al que se le está cobrando copago farmacéutico: JUAN JOSÉ GONZÁLEZ CASARES DNI: 46428396K Ya me dices cuando puedas cuál es el problema y si tenemos que hacer alguna gestión desde aquí para poder solucionarlo." ······················································· Respuesta de Marina Carmen: "he puesto una incidencia al INSS de Madrid para que resuelvan el problema. Te aviso cuando lo arreglen. No tenéis que hacer nada."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-04-08','Ana: Correo de Toni-Futuex: "Hemos podido constatar, ya que todos los indicios apuntaban a ello está mañana, que JMRM está ingresado en el Hospital San Pedro de Cáceres, a consecuencia de una intoxicación por ingesta medicamentosa voluntaria. Está pendiente que lo vean los psiquiatras para valorar." ······································································································ Nuevo correo de Toni-Futuex: "Nada que le dan el alta.... Que el psi considera que como tiene el juicio conservado, y es consciente de lo que ha hecho, que lo considera como un error y que el dice que no volvera a hacer, pues consideran darle el alta. La medico que lo vio en un primer momento si valoraba el ingreso pero finalmente el psiquiatra ha dicho que no, ... lamentable, pero por desgracia, habitual No se consigue localizar a catering pajuelo, vamos a intentar ahora, porque sin comida no puede estar claro.. el hermano le está dando cobertura, pero claro no puede más."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2024-04-08','ana: Envío correo a Toni-Futuex: "Cuando podáis, porfa, informarme sobre si habéis podido hacer seguimiento a Enrique en su domicilio el viernes o el lunes y, en tal caso, cómo le ha visto Clara" ················································································· Respuesta de Toni: "El viernes teniamos precisamente una reunión de equipo, y se constato con Estrella la hora de vuelta para hacerlo en todo caso hoy, pero regresaba en el autobús de primera hora, asique nada, no se ha podido hacer. En el socio , estaban al tanto, porque se lo dijimos el viernes, que era imposible, si regresaba hoy a las 9.00"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2024-04-08','Ana: Envío a Alberto, jefe Secc. ecca., correo-respuesta de Miguel: "Cuando puedas, por favor, lee la respuesta de Miguel en relación al documento que te adjunto y que te aclare él lo que necesites. Si consideráis nos reunimos cuando estemos todos en oficina. Pongo en copia a Minerva, TS del C. Residencial Cervantes en que vive Mª Luisa." ············· Respuesta de Miguel: "habría que valorar si la Comisión estaría de acuerdo en alquilar en precario o no esta vivienda, para lo cual tendrías que hablar con la parte económica." ································································································································································································ A petición de Minerva, TS C.R. Cervantes, le envío Cdo. de Discapacidad de Mª Luisa, pues no lo tienen en el expediente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2024-04-09','TERESA Vamos a parar el ingreso en residencia de Pablo, ahora mismo me dice la trabajadora social que esta muy estable y que manifiesta que no quiere irse a residencia. Además ahora le ha salido dos juicios por faltar a la autoridad de la época que estaba con el alcoholismo y como tiene antecedentes tiene muchas papeletas para que vaya a la cárcel….. veremos cómo se resuelve esto','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2024-04-09','TERESA TELFONO PROPIETARIO PISO ILDEFONSO 655576513','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2024-04-09','Lourdes : para el miércoles podrá retirar los 450€, Le quedarían para terminar el año 2580€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-04-09','Ana: Correo de ayer de Lourdes, TS SAD-IMAS-CC (lourdes.perez@ayto-caceres.es): "Buenos dias, me informa la empresa de teleasistencia de lo siguiente: Ayer JOSE MANUEL ROMERO MEDIAVILLA llevó a cabo un intento de suicidio mediante la ingesta de pastillas. Fue asistido por emergencias sanitarias. Le realizaron un lavado de estómago en el hospital."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='AVILA'and apellido2='FEMIA'),'2024-04-09','Ana: correo de Tomás, hermano de José Luis (jtavila66@gmail.com): "Como hablamos el viernes te envío el nombre y número de teléfono del agente que lleva el banco Santander en Aliseda, Victor Tomé Llanos 645911904. En Unicaja Banco el agente se llama Vidal 927277178, también tengo el informe del médico forense, además de la historia clínica resumida e informe de seguimiento del médico de cabecera por si lo necesitáis."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='ALVES'and apellido2='MATEUS'),'2024-04-09','Ana: Envío a Cristina Hdez, TS del CSS-Plas. (cristina.hernandezca@salud-juntaex.es): "A requerimiento del Juzgado, para la REVISIÓN DE SUS MEDIDAS DE APOYO, te solicitamos nos envíes Informe Social en los siguientes términos: “Informe sobre la situación actual de D. José en cuanto a: - Discapacidad que presenta - Ámbitos y extensión que resulten afectados por su discapacidad y necesidad de apoyo - Cualquier consideración que estimen conveniente sobre ella en razón al procedimiento judicial de revisión de medidas de apoyo.”','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2024-04-09','TERESA La semana pasada la compañera estuvo con Lorenzo y comentó que ya lo habían llamado para trabajar, se vuelve a las Palmas sobre el 15 de mayo. Se esta pendiente del tema para que confirme la fecha exacta cuando lo sepa y retomar el catering y que se le retire el importe que se le está dando por la comida. Hoy, estaba mucho mejor que otras veces, parece que se ha comprometido en ponerse el inyectable.. en cortarse las uñas y mantener el aseo. Ojala y asi sea, porque además no es lo habitual, que se comprometa en estas cosas, iremos viendo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2024-04-09','Ana: Vuelven a pedir desde el Juzgado los Informes para la revisión de las medidas de apoyo de Juanjo. ····· *Reenvío a la secc. Jurídica. el correo que les envié el 6/02/24 con Informe Médico e Informe Social, indicando la necesidad de solicitar el internamiento involuntario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2024-04-09','Ana: En relación al Informe que nos pide el Jdo. para la revisión de las medidas de apoyo de Guadalupe, llamo a Mari, Directora Residencia Ntra. La Luz de Malpartida de Plasencia (927 459 100, ext. 1): no obtengo respuesta. ················································································· Envío email a Ana Benavente, TS ESM-Plas (anamaria.benavente@salud-juntaex.es): "...por favor, solicites a la Psiquiatra de referencia Informe Médico relativo a GUADALUPE BARRAGÁN GARCÍA en los siguientes términos: “Informe sobre la situación actual de Dña. Guadalupe en cuanto a: - Discapacidad que presenta - Ámbitos y extensión que resulten afectados por su discapacidad y necesidad de apoyo - Cualquier consideración que estimen conveniente sobre ella en razón al procedimiento judicial de revisión de medidas de apoyo.”" ·································· *A petición de Ana Benavente, cumplimento modelo de solicitud de Informe Clínico y lo subo al portafirmas digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2024-04-09','Ana: Sheila, Directora CRR, reenvía correo que remitió al ctutelar@ el 26 de marzo: "solicita poder hacer retirada de 40€ para la compra de unas taloneras ortopédicas." ····················· Doy mi ok a la secc. ecca.','2');
