insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PILAR'and edp.apellido1='JIMENEZ'and apellido2='AGUILAR'),'2024-04-09','Ana: En respuesta al correo de Ángel, tras llamar a Pedro (646 227 862), le escribo: "Buenas Ángel, Acabo de hablar con Pedro, propietario de la vivienda. Me dice que la fecha que podemos poner es el próximo lunes día 15 de abril. No obstante, que lo que te ha enviado es un borrador y que mañana te enviará ya el contrato en firme con la fecha incluida." ························ Tras llamada de Jesú y Pili, envío nuevo correo a Ángel y a Pedro, propietario (ryoga.hibiki.330@gmail.com): "Buenas tardes Pedro y Ángel, He hablado con Pilar Jiménez y su pareja Jesús. Ahora dicen que si tienen que espera al lunes de la semana que viene para que les den la llave de la nueva casa ya no quieren alquilarla. No sé Pedro, si les puedes plantear alguna otra alternativa o si daría tiempo a que trasladasen antes." ··································································································································· Respuesta de Pedro: "Ahora dicen que no se cambian hasta el 26. Pues no quieren pagar la fianza de 250 euros, pero nosotros les devolveremos 210. Con lo que sería un desembolso de 40 euros. Con lo que me lleva a pensar que hasta andan sin 40€ de liquidez, lo que no me deja demasiado tranquila. En confianza, se lo digo, si se quieren ir son libres para hacerlo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2024-04-10','miguel, email de la hna Carmen: Buenos días Miguel Ángel, como le comenté los Hermanos García-Puente, es decir, los tíos de Enrique nos solicitan a cada uno un dinero para los gastos que los bienes heredados generan. En un principio nos pidieron a cada hermano Santos García-Puente 20€, Enrique aún no lo ha aportado y 50€ ahora para gastos de la casa en Ledesma (ibi y demás). Aporto los documentos que me han aportado nuestros tíos y justificantes de los ingresos nuestros como comprobantes. Otra cuestión: Nuestro tío mayor nos plantea que la cada de Ledesma está en semiruina y aunque varios compradores ha habido, no han podido por obstaculación de uno de los hermanos García-Puente. Entonces han cogido abogado para ver opciones. Nos han preguntado si estamos de acuerdo en demandar a este tío nuestro entre todos para que acceda a la venta y si no lo está solicitar salida a subasta por orden judicial. Nosotros hermanos Santos García-Puente estamos conformes, falta Enrique por saberlo y saber de su conformidad o no. En el caso de que sí, entonces el abogado os enviaría documento para ello. Se lo consulto yo a Enrique o ustedes? Aprovecho para preguntarle por el proceso judicial de mi hermano, de los informes que mandaron ustedes y nosotros si se sabe algo y saber si ya han realizado la subcomisión de valoración en el sociosanitario para ver futuro de Enrique. Hablo con él y me cuenta de sus permisos de salida y de su próximo traslado a otra unidad allí dentro, que no sé si es cierto. Envío segundo correo con otros documentos ---------------------------------------------------------- Adjunto los documentos para justificar el abono correspondiente de 1/5 parte de Enrique en las cuentas familiares. Quedo a la espera de lo que me digan si se lo pregunto yo o ustedes lo de la demanda a nuestro tío y posible subasta de la vivienda de Ledesma. Gracias de nuevo y saludos. Carmen Santos García-Puente Tel 606704973','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PILAR'and edp.apellido1='JIMENEZ'and apellido2='AGUILAR'),'2024-04-10','Ana: Respondo a Pedro, propietario de la vivienda, y a Ángel, A. Jurídico: "Pues no sé que decirle. Por supuesto son libres para marcharse si es su decisión. Si quieren esperar al día 26 por nuestra parte tampoco hay problema. En cuanto al dinero, la situación de Pedro la desconocemos, pues Pilar retira su asignación económica semanalmente. Ángel y Pedro, si os parece, y ellos se mantienen en dicha posición, se indica como fecha nueva el día 26."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-04-10','Ana: correo de Toni-Futuex de ayer a última hora: "Se hacen llegar prespuestos que estan pendientes para valoración. Y el informe médico tras el ingreso por ingesta. José Manuel contactó la semana pasada con la educadora para decirle que se le ha estropeado el móvil y no es capaz de hacerlo funcionar. Va a usar provisionalmente uno que le presta su cuñada. A parte de esto, también comentó con anterioridad que no le funcionaba bien la máquina de afeitar. Hoy día 9 se ha acudido al domicilio de José Manuel y se ha comprobado todo esto, por ello se acude al electrocash para pedir presupuesto de ambas cosas, se adjuntan en este correo. Se informa también de lo evaluado en torno a su estado de inestabilidad reciente. Se le pregunta si está tomando adecuadamente la medicación y reconoce que últimamente no, porque a veces se le olvida alguna toma o no siente motivación para hacerlo como debería. Además, ha tenido varios acontecimientos en su vida que le han desestabilizado, como por ejemplo enterarse de que la persona con la que ya tuvo un juicio en enero le volvio a denunciar y lo más probable es que le condenen de nuevo (a pesar de considerarse culpable). También le afecta mucho sentirse solo y ver que sus hijos no quieren saber nada de él, de hecho su hijo le ve muchas veces y ni siquiera quiere saludarle. Todo esto, a parte de su mala gestión emocional habitual y su impulsividad, provocó un episodio autolítico con la ingesta excesiva de pastillas el domingo día 7, él mismo pulso su botón de emergencia y pudieron llevarle al hospital, donde tuvo que permanecer 24 horas. Desde psiquiatría han considerado darle el alta puesto que han visto que es una persona consciente de la realidad y arrepentida por lo ocurrido, que sabe discernir que se ha tratado de un impulso y que no tiene intenciones de morir." ································ Renvío PRESUPUESTOS a la secc. ecca. Ok por Secc. Soc. ················ Guardo Informe Alta Serv Urgencia + Interconsulta UHB.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='CARVAJAL'and apellido2='CORNEJO'),'2024-04-10','TERESA RECIBO LLAMADA DEL JUZGADO N2 DE ZAFRA EN REALCION A LA PETICION DE INGRESO INVOLUNTARIO DE TOMAS ME INDICA QUE ME MANDARA UN OFICIO A MI CORREO PARA PODER ACTIVAR EL 112 Y QUE UNA VEZ ESTE IGRESADO SE RATIFIQUE COCHA: ITR523','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2017-09-22','ICIAR: Llama Gema, t.s. de Puebla de Sancho Pérez t/c 924 57 52 09, a la cual le hemos requerido el informe social de Ildefonso para la rendición de cuentas,desconoce su situación, y su familia tampoco sabe nada. se le informa que si desconoce la situación lo exprese así en el informe.Ildefonso tiene una ordende alejamiento de su madre pero esta no sabe hasta cuando está vigente dicha orden.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CASARES'),'2024-04-10','Ana: correo de Marina Carmen, Jefa Secc. PNC (marinac.jimenez@salud-juntaex.es): "Buenos días, ya está solucionado el problema." ···················· Contesto y pongo en copia a Ángela Bueno, TS PLACEAT, para su conocimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REGINA'and edp.apellido1='REINA'and apellido2='LARA'),'2024-04-10','CEE LOS ANGELES : Contestando al e-mail referido a la autorización para salidas de la alumna Regina Reina Lara escolarizada en nuestro centro, comunico que acudiremos a Alcázar de San Juan (Ciudad Real), los días 8, 9 y 10 de mayo con motivo del Proyecto EMOCION-ARTE, en el que se están llevando a cabo agrupaciones educativas de carácter cultural.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2024-04-10','Mº José: 629 78 55 81 Isabel : 655 65 51 00','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='FERNANDEZ'and apellido2='SERRANO'),'2024-04-10','Ana: Tras recibir correo de Anabel Galván, TS Madrigalejo (ssb025vegasaltas@madrigalejo.es), escribo a Alberto, Jefe Secc. Ecca, en relación al presupuesto de obra enviado ya dos veces para su valoración: "Te reenvío correo de la compañera Trabajadora Social de Madrigalejo. Necesitamos que nos des respuesta ya del presupuesto de obra que te reenvié por segunda vez el 23 de febrero. Míralo por favor y danos una respuesta. Entendemos que es muy necesario."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2024-04-10','Amalia . facilito a su hna Isabel el tf de Miguel para gestionar la venta de la casa familiar. Le hemos preguntado a él y está de acuerdo con la venta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='AVILA'and apellido2='FEMIA'),'2024-04-10','Ana: Envío correo a Alberto y María, Secc. Ecca: "En relación a José Luis Ávila Femia, me llamó ayer a última hora su hermano Tomás. En las entidades bancarias han bloqueado ya las cuentas porque al parecer José Luis acudió a la oficina y no pudieron darle el dinero. En la oficina temen la reacción de éste de persistir la situación. Entiendo que aún no tenemos acceso a las cuentas, ¿no es así? Por favor, mantenedme informada al respecto y en cuanto se pueda, de no haber ingresado en centro aún, que para variar esto parece que va lento, habrá que hacerle autorización mensual de retirada de efectivo. El viene retirando 600 €/mes, sé que es elevado para sus ingresos económicos, pero tiene dinero ahorrado y será algo temporal hasta que pueda ingresar. Estamos en coordinación con Soraya para ello." ·············································································· Respuesta de María, Secc. Ecca: "ayer estuve hablando con el director del Banco Santander, aun no tenemos acceso a estas cuentas, están bastanteando la documentación, quedó en avisarme en cuanto estuvieran listas. En Unicaja sí que tenemos acceso. En cuanto vuelva Alberto hablo con él para lo del reintegro."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='RODRIGUEZ'and apellido2='SANCHEZ'),'2024-04-10','Miguel : conforme a su sentencia no se indica nada acerca de la toma de medicación. No podemos obligar a nadie a tomar la medicación. Luisa no quiere tomar la medicación pautada en el hospital , es una decisión personal , no está desestabilizada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2024-04-10','miguel, email de Tere: Hola a todos Imposible llevar a cabo el ingreso involuntario de Aitor En comunidades terapéuticas privadas de Extremadura todas en lista de espera Para acceder por la vía pública debe asistir a las citas del ECA (equipo de conductas adictivas) ha asistido solo a dos y se niega seguir asistiendo con lo cual no pueden hacer la derivación a centro En centro de discapacidad se niegan a admitirlo estando consumiendo No me quedan mas alternativas, no se si se puede hacer activando el 112 para UHB y que pasara a UME…. Mientras tanto sigue viviendo con su madre en Navas del Madroño con todo lo que eso conlleva par su madre ( problemas de convivencia, económicas, violencia filio parental, problemas económicos) y se le da una asignación de bolsillo de 40€ semanales que saca con una tarje prepago todos los viernes. Se ha intentado fomentar la asistencia al ECA proponiéndolo mas dinero de asignación pero no ha tenido éxito También se le ha propuesto que cumpla tratamiento y después buscamos piso de alquiler y tampoco lo acepta Aitor manifiesta que él no quiere ir a ningún centro ni que nadie le ayude, quiere trabajar y vivir de alquiler y nosotros no le dejamos. Que quiere vivir libre porque lleva toda la vida condenado a estar en centros. ¿Cómo procedemos? -------------------------------------------------------- mi contestación a la parte social y Angel: Hola, si no hay más alternativas que proponer desde la parte social, tendríais que preparar un informe detallado para remitirlo al juzgado a efectos de su conocimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2024-04-10','miguel, recibo email de Amalia: Buenas Miguel , te paso los tf de las hnas de Manuel para gestionar la venta de la casa familiar , la que contactó contigo fue Natalia . Le he pasado el tuyo como indicaste. Se ha extrañado de que Manuel lo haya aceptado . No hay que pedir autorización judicial para esa venta ? No sería conveniente que firmase algún documento como que voluntariamente quiere vender ? ----------------------------------------------------- Mi contestación: Hola Amalia, no sé quién es Natalia…en la intranet sólo has dejado estos tlfnos Mº José: 629 78 55 81 Isabel : 655 65 51 00, imagino que será con ellas con quién tendré que hablar no? Para vender se necesita autorización judicial (previa tasación y otros gastos como notaría, registro, abogado, impuestos (en la venta: plusvalía, ibi, y en la compra transmisión patrimonial, suponiendo que no pida préstamo hipotecario, lo cual incrementaría el gasto) Debes hablar con Alberto previamente y explicarle qué quiere hacer Manuel…vender y después comprar…pues como digo conlleva gastos ambas operaciones, y mucha burocracia. No está de más recabar la firma del tutelado en un documento, donde solicite qué quiere hacer. Necesitaré toda la documentación de la vivienda para lo cual hablaré con los dos tlfnos que indicas…Pero tu ves hablando con Alberto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEREA'and edp.apellido1='DA COSTA'and apellido2='LORENZO'),'2024-04-09','Ana: Llamada de Guadalupe, madre de Nerea (672 397 214 = Nº de su pareja // Su nº: 601 53 85 85): solicitan poder sacar a Nerea del centro para dar un paseo por Plasencia cuando va a visitarla, ya que ella acude desde Badajoz y le gustaría estar más tiempo con ella como hace su hermana Esmeralda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEREA'and edp.apellido1='DA COSTA'and apellido2='LORENZO'),'2024-04-10','Ana: Hablo con Estrella, TS CSS-Plas (24146): La Psiquiatra propone hacer una prueba. Acordamos que en la próxima visita de la madre se le permitirá salir por Plasencia a pasear y tomar algo. En función de cómo afecten las salidas a Nerea se seguirá autorizando o no. Si fueran contraproducentes las visitas volverían a ser en el centro. ·········································································· *Se lo comunico a Guadalupe, madre de Nerea.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOLORES'and edp.apellido1='MACARRO'and apellido2='CAMACHO'),'2024-04-10','TERESA Hoy se ha hecho la primera visita a Dolores, es una señora mayor con dificultad para moverse pero que puede andar sola en distancias cortas, va con andador. Es muy coherente en su discurso aunque se distrae del tema, pero se puede mantener una conversación con ella perfectamente, además ha sido muy amable en todo momento y, aunque no entiende porque ahora no puede disponer de su dinero y demás, se le ha explicado y ha parecido comprender como van a funcionar las cosas. Lola, que así quiere que se le llame, es viuda y vive sola. La casa está en unas condiciones muy perjudiciales para su salud... (se adjuntan fotos). Tiene un perro y muchos pájaros en jaulas en el salón, los ratones campan a sus anchas por la vivienda, se ha podido ver ratones muertos por el suelo y también vivos, han pasado dos prácticamente al lado de los pies de la educadora durante la visita... Tiene acumulación de cosas y mucha mucha suciedad, la cocina es la peor parte de la casa, ahí no puede hacer de comer en esas condiciones. El perro se hace sus necesidades en la vivienda, se puede ver todo el suelo con manchas de excrementos. Hay ratoneras en las paredes, son agujeros enormes por donde salen y entran como quieren. Actualmente no tiene nadie del SAD, se ha hablado con la TS de referencia y cuenta que tuvo una chica muchos años pero ella se dio de baja hace ya un tiempo. Enviaron una sustituta y no aguantó en esa casa y se fue..., ahora no va nadie. La vivienda ahora mismo necesita una limpieza extrema y una desratización. Ya hace unos años denunció a una vecina que aprovechó para limpiarle todo mientras ella estaba en el hospital, siempre se ha negado a todo tipo de ayudas en este aspecto. Ahora parece ser que se ve en una situación extrema y el tema de la curatela la tiene un poco asustada, se ha hablado con ella sobre que la vivienda debe limpiarse a fondo y que ahí no puede seguir en esas condiciones y ha parecido aceptar. Sobre sus gastos, la casa es propia y todas las facturas (luz y demás) van directas a la cuenta. Solo necesita para la compra del día a día y para pienso para el perro y los pájaros. Ahora mismo debe 80€ en un supermercado, 60€ en la carnicería y 30€ al taxista del pueblo, de la semana pasada que no tenía dinero. Le han dado 200€ esta mañana en el banco y dice que con eso no le llega para pagar las deudas y tener para todo el mes... La TS ha informado de que le gusta comprar compulsivamente. Se le ha explicado que ese dinero ahora es del que va a poder disponer. En principio esta es la información que se ha obtenido hoy, un saludo. PIDO PRESUPUESTO DE DESRRATIZACION Y LIMPIEZA EXTREMA PIDO ALBERTO PRESUPUESTO GASTOS BOLSILLO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='PEREO'and apellido2='REBOLLO'),'2024-04-10','Ana: Correo de Paula, TO - CRR-Plas: "quería comentaros acerca de Antonio Pereo: • A los compañeros de la sección económica: como Antonio ha pasado de teléfono de contrato a teléfono de prepago, y hemos observado la cantidad real de tabaco que fuma de manera diaria, queríamos solicitar una modificación permanente de la cantidad mensual que saca Antonio, proponiendo que ésta fuera de 350 euros. En ella se incluirían los 20 euros de la recarga del teléfono y ajustaríamos la cantidad diaria/fines de semana, para que pueda optar a otras actividades en condiciones similares a otros compañeros o compañeras. • Ana: Por otro lado insiste en la posibilidad de realizar una salida a Badajoz con su hermana, que vendrá en unas semanas a visitarle a Plasencia. Sé que este tema era delicado por dificultades que tuvo en el pasado, por lo que me gustaría aclararlo de nuevo: él dice que salía a casa de su hermana durante varios días cuando estaba en el sociosanitario, pero realmente no sabemos si esto era así, por si nos lo podéis aclarar" ······························································································································································································· Mi respuesta, con copia a Amalia y a secc. ecca: "Respondo a tu correo y lo aprovecho para comunicar a la vez a las compañeras del Gabinete de la CTAEx: 1. Sección económica, si la modificación que proponen para Antonio Pereo Rebollo es viable, por mi parte ok a la misma. Subrayo en el hilo en amarillo. 2. Amalia, porfa, ya que tú conoces el caso y los antecedentes, te importaría decirnos si la información que traslada Antonio en el Centro es real y, en tal caso, si las visitas se desarrollaban de forma adecuada, o si por el contrario surgían incidente en la convivencia y se desaconsejan las mismas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2024-04-10','Ana: tras hablar con Julia, madre, y Mª Ángeles, hermana de Julia, envío correo a Toni-Futuex: "En relación a Julia Morón Hernández, como sabéis sigue en el UCI. Hasta el momento los familiares (padre, madre y hermana) se han estado turnando para quedarse en el hospital y asistir a las visitas programadas. Dada la edad de los padres, están agotados y les gustaría descansar la semana que viene, y la hermana la semana que viene, según dice, la tiente complicada para asistir. Evidentemente, les he dicho que todo el día no se puede quedar nadie ni tampoco se podrá acudir a las visitas de la tarde y noche. No obstante, sería posible que de Lunes a miércoles de la semana que viene acudirá a realizar visita a las 13 h. alguna de las educadoras del programa. Es además cuando suelen facilitar la información sobre evolución los médicos. Y me dices si cuadra en agenda y es posible."','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SALVADORA'and edp.apellido1='CHAVES'and apellido2='MENDOZA'),'2024-04-10','Ana: Llamo varias veces al Centro de Salud - Consultorio de Villa del Rey (927 185 024 // 52222): No obtengo respuesta. ····················· Envío a Juan Carlos, para REGISTRO, oficio solicitando informes médicos al Consultorio.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SALVADORA'and edp.apellido1='CHAVES'and apellido2='MENDOZA'),'2024-04-10','Ana: Llamo varias veces al Centro de Salud - Consultorio de Villa del Rey (927 185 024 // 52222): No obtengo respuesta. ····················· Envío a Juan Carlos, para REGISTRO, oficio solicitando informes médicos al Consultorio para la revisión de las medidas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2024-04-11','Ana: Envío mail a Ana Benavente, TS ESM-Plas: "Adjunto el modelo de SOLICITUD DE INFORME CLÍNICO que me enviaste cumplimentado y firmado digitalmente por la Presidenta de la CTAEx. Espero que así sea suficiente. Si lo requerís por REGISTRO, por favor, facilítame el número del buzón al que tenemos que enviároslo." ·························· Ana confirma que así es suficiente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PILAR'and edp.apellido1='JIMENEZ'and apellido2='AGUILAR'),'2024-04-11','Ana: Correo de Ángel a Pedro, propietario vivienda (ryoga.hibiki.330@gmail.com): "Envío nuevo contrato de alquiler y rescisión del anterior, debidamente cumplimentados. Una vez los reciba, por favor, envíenoslo firmados." ················· Fecha nuevo contrato: 26 de abril. ······························································································································································································· *El nuevo domicilio sita en la Calle Santa Lucía, 6 de la localidad de Ahigal (Cáceres).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2024-04-11','Ana: Remiten desde el CRR, ORDEN CLÍNICA DE RADIOLOGÍA, ORDEN CLÍNICA DE CONSULTAS EXTERNAS y NOTA DE EVOLUCIÓN de la Servicio de Cirugía Ortopédica y Trauma. ············· En esta última indica: "Debe dejar de fumar y perder peso"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOLORES'and edp.apellido1='MACARRO'and apellido2='CAMACHO'),'2024-04-11','TERESA LIMPIEZA EXTREMA Perfecto. Quedamos a las espera. 633012616 / 670278808 aquí os dejamos nuestro contacto para visitar la vivienda y hacer presupuesto de limpieza','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='RODRIGUEZ'and apellido2='GRAGERA'),'2024-04-11','Director CRR : Respuesta por no querer tomar la medicacion indicada en el hospital para su enfermedad : Ante esto estoy de acuerdo, la decisión de Luisa no es motivada por una posible desestabilización o sintomatología, sino por una decisión personal, siendo consciente de las posibles consecuencias que puede conllevar, por lo que según mi visión a nivel humanos es una opinión respetable, sin embargo, a nivel profesional tengo que comunicarlo, para que seáis conocedores. Por tanto, el comunicarlo o no a juzgados entiendo que debe ser una decisión por vuestra, en caso que lo consideréis oportuno a nivel legal.------------------------- Miguel responde que lo va a comunicar a juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='GOMEZ'and apellido2='CHAVEZ'),'2024-04-11','miguel, hablo con la notaria de Monesterio 924 516203, queda por ratificar la declaración de herederos de la madre Aurora Chavez Caballero, protocolo 305 y su cierre 352. (la del padre Manuel Gomez era el protocolo 306 y su cierre 353 de la notaria MªEnriqueta Saucedo Garcia (cuyo protocolo de ratificación hecha por Angel es 447, y cuya factura me remite a ctutelar para que la abonemos,lo demás ya está abonado) Le doy los datos para remita por correo corporativo a la notaria de Mérida la documentación para que pueda ratificar el protocolo 305 y 352 de la madre Aurora Chavez Caballero. ******************************************** Escaneo y envío certificado de nacimiento a Jose Luis de la Notaria, al que avisará la notaria de Monesterio de esta ratificación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SALVADORA'and edp.apellido1='CHAVES'and apellido2='MENDOZA'),'2024-04-11','Ana: Llamo de nuevo varias veces al Centro de Salud - Consultorio de Villa del Rey (927 185 024 // 52222) en el horario indicado, de 10 - 12 h. pero tampoco obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO MARIA'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2024-04-11','Se adjunta el informe solicitado de Diego, en el mismo documento se incluye la historia clínica resumida. Al respecto de lo de la cuidadora Petrona, su cuidadora interna y el tema de rebajar su jornada. Se le propuso, como hablamos, dado que el estado de Diego ha evolucionado favorablemente, que pasara con él desde medio día para hacerle la comida hasta la hora de la cena. Por la mañana de 9 a 11 está con él Raquel, la auxiliar del SAD, por lo que ella se encargaría del desayuno. Petrona propuso estar con él de 12:00 a 21:00 y por ello pide 800€/mes. En este dinero están incluidos festivos y fines de semana, como hasta ahora, además considera que estos días que no va la auxiliar debería ir una hora por la mañana para ver como está y ponerle el desayuno, pues Raquel solo va de lunes a viernes. No podemos cuantificar si es esto es viable, o es caro, en cuyo caso, la opción podria ser plantearle a ella, la cantidad que se puede pagar o bien, pedir presupuesto en otra empresa por unas horas. Ella queda a esperas de que se le de respuesta y, en el caso de aceptar, cuando comenzaría con este horario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE BLAS'and edp.apellido1='CAÑAS'and apellido2='LOZANO'),'2024-04-11','Ana: Tras reunirme con Alberto, Jefe Secc. Ecca, éste envía correo a Estrella: "ESTRELLA: MODIFICAMOS TRANSFERENCIA A "MADRE TUTELADO" PERMANENTE QUE PASA, A PARTIR DE 01/05/2024 A 450 €/MES......CONCEPTO Manutención y asignación mensualManutención y asignación mensual ESTRELLA: TRANSFERENCIA PUNTUAL LO ANTES POSIBLE X 420 €....ATRASOS MANUTENCIÓN." ······························································································································································································· Contesto al correo de Juan Manuel Cañas, hermano de José Blas: "Me alegra leer que tu hermano está dispuesto a ingresar en centro, yo en su día tenía entendido que estaba dispuesto a ingresar en centro pero sólo si era en Cáceres. Lo malo ahora, pues he consultado precisamente esta mañana en la Sección correspondiente, es que está muy atrás en las listas de espera de todos los centros. En el único que no está tan lejos, y así y todo hay 3 personas por delante, es el centro de Fuente de Cantos. No obstante no saben cuánto podría tardar en quedar plazas libres. En cuanto a la subida de asignación, pediros disculpas pues ha habido un error. En los próximos días se hará transferencia puntual a la cuenta de madre en concepto de 420 €....ATRASOS MANUTENCIÓN y a partir de mayo, la trasferencia periódica en concepto de ACTUALIZACIÓN DE MANUTENCIÓN con la cuantía de 450€/mes."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2024-04-11','miguel, me pidio Tere y Estrella que hagamos la herencia y venta de la vivienda para lo cual me facilitan el telefono de SSB Ayto de Monterrubio de la Serena. Tras hablar con Mª Luisa TS del SSB de Monterrubio (924-610025, ext. 314)me confirma que la notaria que va a firmar a Monterrubio es la notaria de Cabeza del Buey. Me facilita también el tfno de la persona que habitualmente va va visitar al tutelado, que por las indicaciones debe ser de FUTUEX (Maria 663851388) Teléfono del tutelado Pedro Tomás Murillo Matias 641 74 50 23','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2024-04-11','miguel, me llama la sobrina de la dueña, que se llama Maxima 639436293. Le doy email de ctutelar y envío email a la parte social y económica: Buenos días, acaba de llamarme Máxima (sobrina de la dueña de la vivienda donde está alquilada esta Curatela Representativa…su expte sigue estando en las carpetas de curatela). Esta mujer empezó siendo una tutela en 2010, en 2020 pasó a ser tutela, y ahora en 2024 tras la revisión de medidas de apoyo la nombran curatela representativa. Adjunto la escritura de contrato de arrendamiento junto el último auto dictado, donde se nos nombra curador representativo. Pide que Vanesa abandone el piso, motivo: no paga hace años el alquiler, hace meses no paga agua y se la han cortado según le dijo el operario que fue a cortarla, no sabe si debe o no la luz que dice está a nombre de ella. Parte económica: comprobad esto por favor, y si es así tenemos un problema porque habrá que abonar lo que se deba o pedir a la dueña que lo reclame judicialmente. La parte social tendría que buscarle un nuevo piso o centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2024-04-11','Ana: Llamada de Juan José, quiere ir al WOMAD - CC en mayo. Solicita un extra a tal fin. Se le confirmará más adelante que aún es pronto. ··················· Por otra parte, dice que la comida del cáterin está muy bien, pero no le entra fruta. Acordamos que él la comprará con la asignación. Pues además él hace otros "trabajillos" en la Asociación y se saca otro dinerillo para sus gastos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-04-11','Ana: Envío correo a Toni y Nieves, Futuex: "En relación a JOSÉ MANUEL ROMERO MEDIAVILLA vamos a tramitar la solicitud de Club de Comedor. Para ello necesitaríamos que, por favor, le acompañaseis: - a cita con la MEDICA DE ATENCIÓN PRIMARIA para que cumplimente el modelo de Informe Médico - a solicitar Certificado de Convivencia al Ayuntamiento. Suele ser más rápido yendo en persona que si lo pido yo por registro desde aquí. *Por otra parte, como sabéis José Manuel sigue sin cáterin. Como no sé cuánto van a tardar en conceder el Servicio de comedor de la residencia de mayores, os planteo 2 opciones: 1- Volver a intentar contactar con Cáterin Cáceres Pajuelo: 927 22 04 31 / 679 176 241 // cateringcacerespajuelo@hotmail.com 2- A unas malas, que los lunes Nieves le acompañe a retirar dinero y comprar comida para la semana. (Esta opción me gusta menos, porque los precocinados por su estado de salud no le viene nada bien. Ya me decís." ···································································································· Respuesta de Nieves, Ed-Futuex (delegadapoyo.caceres2@futuex.es): "Perfecto, le acompañaré a por ambos documentos sin problema. Respecto al catering Pajuelo, ya me he personado incluso en el establecimiento, además de llamar a todos los números e incluso al de María, que se supone que es la jefa, y por las mañanas a mí no me lo ha cogido las veces que he llamado, tampoco contesta a los mensajes de WhatsApp que le he dejado. Voy a intentar llamar esta tarde de nuevo a ver si hay suerte. Si no es posible esta opción, puedo llegar a ver viable la segunda, aunque es cierto que José Manuel no es mucho de cocinar, pero en alguna ocasión me ha dicho que lo ha hecho (quiero decir, la capacidad de hacerlo existe, pero la voluntad...es otra cosa). Por mí no tendría problema en hacer este acompañamiento. Podría ponerme con él a pensar qué alimentos comprar y qué puede hacer con ellos, por ejemplo lleva tiempo pidiendo fruta, esto es algo que le vendría genial."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA VALLE'and edp.apellido1='PATARRO'and apellido2='CARMELO'),'2024-04-11','Amalia : hablo con Natalia , TS . -Quedo pte. enviarle la autorización de salidas , para que pueda ir a su pueblo . Incluso en verano se podría gestionar que pasase allí un mes , ella podría darle ese mes de baja y con los aproximadamente 600€ que abona por la plaza , podría cubrir sus gastos en el pueblo. -La vivienda necesitaría una pequeña reforma en el patio para canalizar el agua y fontoneria y pintura. Se le podría pedir Ayudas por contingencia pero no es posible pq está empadronada en la residencia . -En el pueblo tenía una amiga , Antonia . Sacó durante el tiempo que estuvo en coma en el Hosp. de Almendralejo mucho dinero de su cuenta . Ella la puso como titular . Me va a enviar Natalia datos de esta Srña. con la idea de pedirle justificación de esos gastos por ver si puede devolver algo vía jurídica. Además al parecer le tiene cedida la casa cuando fallezca , ella dice que en Notario no firmó nada . Se le podría pedir a Antonia que lo justifique , ella indica que sí tiene esa documentación. -Les pido que hagan la solicitud de dependencia y que me la envíen junto con los informes médicos. -Quedo pte. de que me cuadre los gastos de Valle y el copago de la plaza para poner un límite en los reintegros. -Valle le gustaría volver a su pueblo , actualmente con los bajos ingresos económicos , sin ahorros , con patolgía de salud en supervisión médica , vivienda en mal estado ... no es viable . Sí podría irse por temporadas de momento e ir gestionando dependencia y otros recursos . En mi opinión estando adapatada y contenta en la residencia y en la localidad donde ha hecho amigas , creo que la mejor opción sería permanecer en la residencia y acudir a su casa en temporadas. En el pueblo antes de ingresar en el hospital era una persona en situación de exclusion por su adicción al alcohol . Actualmente y desde hace años no consume nada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOLORES'and edp.apellido1='MACARRO'and apellido2='CAMACHO'),'2024-04-11','TERESA Hola , si creemos que puede ser una buena idea, Pablo si no recuerdo mal saco unos 160 eu, la compañera habia pensado si va a ser quincenal, en unos 125€, podrian estar bien, es decir en torno a eso 125-150 a la semana, y se la acompañaria a hacer la compra. El telefono de ella, es 642597053 por si se necesita contactar. Al respecto de lo de limpiezas extrema, van el lunes a la 1, ya se ha quedado con ellos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO MARIA'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2024-04-11','TERESA ´Se ha hablado con Petrona sobre la propuesta, en un principio pedía librar un fin de semana al mes, después ha comentado que 900€ sin librar... Finalmente ha dicho que acepta los 880€ que se le han ofrecido por todos los días, fines de semana y festivos incluidos. Además comenta que quiere, a ser posible, que le den de alta (esto le hemos dicho que no sabemos si es posible o no) Si no se le da comentaba que no importa, se irá cuando le salga otra cosa que si que le den. Se le ha dicho que si tiene pensado irse debe comunicarlo con tiempo, pero dice que hay muchas chicas en su situación que estarían dispuestas y que avisaría con antelación','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='PLESA'and apellido2='GUERRA'),'2024-04-12','TERESA ARCHIBO RESOLUCION DE PNC','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE BLAS'and edp.apellido1='CAÑAS'and apellido2='LOZANO'),'2024-04-12','Ana: Correo de ayer por la tarde de Juan Manuel, hermano de José Blas (jmcl1966@hotmail.com): "Me piden desde el centro Down que os reenvíe yo la información de las vacaciones que ofrecen a los chavales, os adjunto el folleto. De aprobar el gasto, más adelante os pasaría la forma de pago." ························································ Respondo con copia a la secc. ecca: "Desde la sección económica te darán respuesta en cuanto les sea posible. Compañeras – Sección Económica: Desde la parte social, si es viable, OK al gasto por asistencia a las vacaciones." ··· *Según documento informativo Down será en un CASA RURAL en HERVÁS. Coste: 400€ aprox.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='GOMEZ'and apellido2='CHAVEZ'),'2024-04-12','miguel, quedo pendiente de que la notaria de Mérida me de fecha para ratificar la declaración de herederos que falta por firmar de la notaria de Monesterio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOLORES'and edp.apellido1='MACARRO'and apellido2='CAMACHO'),'2024-04-12','miguel, enviamos al juzgado solicitud de internamiento involuntario en centro de mayores','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-04-12','Ana: Respuesta de Minerva, TS CR Cervantes (minerva.salvador@salud-juntaex.es), a mi consulta: "Sí, José Manuel me llamó ayer, actualmente sí tenemos plazas libres para el Club de Comidas, no suelen tardar mucho en tramitarlo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='PEREO'and apellido2='REBOLLO'),'2024-04-11','Ana: respuesta de Amalia, TS CTAEx, a mí Y a CRR con copia a los A. Jurícos: "Antonio ha salido a casa de la hermana puntualmente en algunas ocasiones , en fechas señaladas como Navidades y poco más . Si consideráis que su estado de salud lo permite , se podría valorar con la hermana alguna salida, siempre con el compromiso de ella de estar pendiente de Antonio y tener controlado a dónde va en Badajoz . La hermana tenía una mala situación económica , no creo que haya mejorado ; os va a pedir que vaya con el dinero suficiente para cubrir todos los gastos . Salidas permanente de momento en mi opinión no las autorizaría . Aprovecho este email para incluir a los compañeros asesores jurídicos .Me gustaría saber si existe alguna Orden de Alejamiento de la chica a la que acosaba en Badajoz. Estuve acompañándolo en el juicio por ese asunto por el que estuvo ingresado en CSS."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2024-04-11','Ana: Respuesta de Toni-Futuex: "Nos ocupamos con alguna de las compis del equipo de caceres, que aunque no llevan el caso, sera lo mas comodo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2024-04-10','Ana: tras hablar con Julia, madre, y Mª Ángeles, hermana de Julia, envío correo a Toni-Futuex: "En relación a Julia Morón Hernández, como sabéis sigue en el UCI. Hasta el momento los familiares (padre, madre y hermana) se han estado turnando para quedarse en el hospital y asistir a las visitas programadas. Dada la edad de los padres, están agotados y les gustaría descansar la semana que viene, y la hermana la semana que viene, según dice, la tiente complicada para asistir. Evidentemente, les he dicho que todo el día no se puede quedar nadie ni tampoco se podrá acudir a las visitas de la tarde y noche. No obstante, sería posible que de Lunes a miércoles de la semana que viene acudirá a realizar visita a las 13 h. alguna de las educadoras del programa. Es además cuando suelen facilitar la información sobre evolución los médicos. Y me dices si cuadra en agenda y es posible."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2024-04-12','Ana: llamo de Julia, madre de Julia (644 89 73 39 / 644 876 893): ayer ya desentubaron a a Julia y ésta hablaba un poquito aunque le costaba y está muy ronca. ···· *Confirmo que la semana que viene, de L - X, acudirán al hospital las Educadoras de Futuex de CC para la visita de las 13 h.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='PLESA'and apellido2='GUERRA'),'2024-04-12','TERESA CONTINUO YO CON LA INTERVENCION UNA VEZ TERMINADA AL INTERVENCION INCIAL POR ANA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='BLANCO'and apellido2='GUISADO'),'2024-04-12','Ana: Desde el ayto. envían al ctutelar las factura de la obra de la casa de Felipe junto con fotos de la misma (han tapiado la puerta). Guardo las fotos en su expte. y las reenvío a Teresa, TS Novaforma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='BERMEJO'and apellido2='TELLO'),'2024-03-15','Amalia : se registra la comunicación a Clases Pasivas de que mantiene las circustancias para mantener la pension.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2024-04-12','-Amalia : Hablo con él , le han vuelto a operar por la extraccion del corta uñas del estómago , le ha dado infeccion. Solicita dinero , se lo deniego y vuelvo a explicarle su situación económica . Va a enviar pto. de tto. dental para valorarlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='PEREO'and apellido2='REBOLLO'),'2024-04-12','miguel, mi contestación a la parte social sobrre la pregunta si estaba cumplida la orden de alejamiento que en su día dicto el juzgado: Buenos días, entiendo que os referís a la ejecutoria 563/2019 (procedimientos DPA PA 235/18 Y 273/2018)dictada por el juzgado de lo penal de Badajoz nº1, que es la última constancia de ejecutorias y procedimientos que tenemos de él. En ella se dictó conforme apunte en intranet del 6-2-20 orden de alejamiento hasta 8-1-23, internamiento en CSS hasta 28-12-2019 y multa de 300€ que fue abonada. El alejamiento era de 3 años. Por tanto, que sepamos no tiene nada pendiente. Para identificar si existe algo más tendríamos que saber procedimiento y juzgado que esté conociendo una causa. ································································································································································································· Respuesta de Amalia a todos: "Hay que ser prudentes con las salidas a Badajoz."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='SANGUINO'and apellido2='LANCHO'),'2024-04-12','Ana: correo de Modesto, Residencia Sierra de San Pedro, de Casas de Don Antonio (administracion@centrodemayoressierradesanpedro.es): "Juan Sanguino Lancho lleva unos días un poco inquieto porque quiere saber el saldo que tiene y lo que cobra. Desde aquí le hemos dicho que no tiene que preocuparse por nada pero aún así insiste. Entonces por favor, si alguien nos pudiera llamar y os ponemos con el al teléfono y se lo pudierais comunicar?" ····································································· Tras consultar saldo a las compañeras de la S. Ecca, llamo a la Residencia (927 38 32 58) y hablo con Juan y le facilito la información acerca de su pensión (1750 €), del abono de la residencia (1650,50 €) y del saldo de sus cuentas (SANDANDER y UNICAJA). Así y todo pide que le enviemos los movimientos bancarios. ························ Los solicito a María, Secc. Ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='AVILA'and apellido2='FEMIA'),'2024-04-12','Ana: Correo de Alberto, Jefe S. Ecca: "ANA: PROPONE MANTENER UN REINTEGRO DE 600 €/MES A TUTELADO: OK, AL MENOS, HASTA QUE TODO SE REGULARICE....OJO: DE MOMENTO EN UNICAJA CCC FAMILIAR. MARIA/ANA: OPERATIVA ECO....ANA: SI TIENES DUDAS O ALGO QUE DECIR, YA SABES. • APERTURA NUEVA CCC UNICAJA (SOLO TUTELADO). MUY URGENTE. • ANA: CAMBIARÁ PENSIÓN TUTELADO DE B.SANTANDER A NUEVA UNICAJA....MARIA: LE PASA Nº CCC CUANDO LO TENGAMOS. • MARIA/ANA: MUY URGENTE: ORDENAR 3 TRANSFERENCIAS X 1/3 SALDO EXISTENTE EN LAS 3 CCC FAMILIARES COMPARTIDAS A CCC NUEVA UNICAJA SOLO TUTELADO. ANA: UNA VEZ QUE HAGAMOS LAS TRANSFERENCIAS A CCC SOLO TUTELADO...DEBERIAMOS QUITARLO COMO TITULAR DE LAS CCC FAMILIARES, YA QUE SI NO, EN CASO DE FALLECIMIENTO DE PADRES, TENDRÍA DERECHO A MÁS DINERO QUE SUS HERMANOS X EL HECHO DE ESTAR COMO TITULAR...QUE HACEMOS???" ····································· Mi respuesta: "Ok a todo, perfecto. Y contestando a tu pregunta, sí, una vez tenga ya su cuenta con su cuantía correspondiente, se le da de baja en las otra cuentas para que deje de figurar en las mismas." ·································································································································································································· Correo de María, S. Ecca. a Mª José, UNICAJA (mleonsan@agentes.unicaja.es): "Buenas tardes M. Jose, te envío autorización de reintegro extra por importe de 600 €, del tutelado de referencia" ················································ Llamo a Tomás, hermano de José Luis, para informarle. Se queda más tranquilo, pues esta misma mañana José Luis acudió de nuevo al banco y ante la negativa se fue de allí alterado y dando voces.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-04-12','Ana: Coreo de Lourdes, S. Ecca: "Buenos días, se acepta el presupuesto de la AFEITADORA. Del móvil dice que de momento no. Ya aviso yo a Futuex."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2024-04-12','miguel, voy a pedir abogado de oficio para tramitar la solicitud judicial de aprobación de herencia y venta. -------------------------------------------------- Hablo con la notaria de Cabeza del Buey que me confirma son los compententes (oficial Manuel 924-600089, notaria Doña Vanesa Rodriguez Jimenez), le explico y envío la documentación por email: Buenos días Manuel, le remito conforme hemos hablado la documentación de que disponemos para tramitar la herencia, y posteriormente tendremos que tramitar la venta, correspondiente a los padres fallecidos de un tutelado por la Comisión Tutelar de Adultos del Sepad. Adjunto: 1.-Certificados de fallecimiento de los padres. 2.-Certificado de nacimiento del padre 3.-Certificado de matrimonio 4.-Certificado catastral del bien propiedad del matrimonio. 5.-Sentencia de incapacitación, nombramiento a la Comisión Tutelar de Adultos y aceptación del cargo 6.-Datos acreditativos del representante de la comisión que es Doña Estrella Angeles Martinez Lavado (Gerente del SEPAD de la Consejería de Salud y Servicios Sociales de la Junta de Extremadura) No disponemos de certificado de últimas voluntades y por tanto no sabemos si dejaron o no testamento (por si pueden solicitarlo ustedes). Tampoco tenemos por ahora información sobre si dejaron alguna cuenta bancaria o no (lo averiguaremos) Cuando llegue el momento de la firma tendrán que indicarnos si podemos ratificarla desde la notaria de c/ Romero Leal de Mérida de los notarios Fdez Pugnaire-Igartua Fesser- Hernández Téllez, como hacemos habitualmente. Entiendo que al estar tutelado no es necesario que vaya a firmar, pues nunca se exige. Quedo a la disposición de la notaria para cualquier aclaración.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTA'and edp.apellido1='DIAZ'and apellido2='BORREGUERO'),'2024-04-12','Buenas , adjuntamos una pequeña nota de Justa respecto del ingreso involuntario y el ultimo infomre del psiquiatra- La direccción correcta, es C/Moreno Nieto, 71 Desde el momento que consiguió parar el proceso de internamiento no voluntario mediante recurso, su actitud hacia la intervención del equipo de apoyo social comunitario ha cambiado. Se percibe que nos oculta información, no se muestra colaboradora ante los acompañamientos que, con anterioridad si accedía, y no permite mucho que le apoyemos en las gestiones que efectúa, como administración del dinero, pedir presupuesto en dentista, óptica, etc. De sus tres hijos, solo mantiene relación con Jorge, al cual ve casi todas las semanas y habla a menudo por teléfono. Por lo que nos comenta, no es el abogado. Abogado es su otro hijo, Alonso. Contactos de sus hijos: § Alonso Ramón Díaz 681 188 756 § Jorge Ramón Díaz 634 746 174 Por lo que se ha trabajado con Justa desde el inicio de tramitación de ingreso no voluntario , en virtud de los seguimientos se considera desde este equipo que no sería buena opción que ella se enterase del día en que se va a ejecutar la sentencia. Siempre que se ha abordado el tema ha amenazado con ideas autolíticas o con irse de Montijo y que no sabríamos de ella. Proceder sin ella ser conocedora del día que se realizará será mas traumático para ella, pero nos aseguramos que no lleve a cabo ninguna de las ideas verbalizadas en varias ocasiones. Últimamente la hemos observado más estable emocionalmente y la notamos más activa. Ella misma expresa sentirse mucho mejor, incluso hace más vida social que antes. Se adjunta el último informe del psiquiatra, a dicha cita quiso acudir con el único fin de adjuntar el informe para poder demostrar que se encuentra bien y no se proceda al ingreso en centro, incluso poder tramitar la remoción de la tutela. El 17, a las 9, como hemos acorado estará por alli, la persona que la ha estado visitando, Sonia la ts,. Y se pondra ya a partide mañana con la ts del ssb para que la acompañe junto con la policia a la casa, para poder recoger la ropa, que la llevariamos a la residencia ya al dia siguiente seguramente, con la compañera de la zona de merida, que seria quien la visitaria en villafranca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTA'and edp.apellido1='DIAZ'and apellido2='BORREGUERO'),'2024-04-12','Buenas , adjuntamos una pequeña nota de Justa respecto del ingreso involuntario y el ultimo infomre del psiquiatra- La direccción correcta, es C/Moreno Nieto, 71 Desde el momento que consiguió parar el proceso de internamiento no voluntario mediante recurso, su actitud hacia la intervención del equipo de apoyo social comunitario ha cambiado. Se percibe que nos oculta información, no se muestra colaboradora ante los acompañamientos que, con anterioridad si accedía, y no permite mucho que le apoyemos en las gestiones que efectúa, como administración del dinero, pedir presupuesto en dentista, óptica, etc. De sus tres hijos, solo mantiene relación con Jorge, al cual ve casi todas las semanas y habla a menudo por teléfono. Por lo que nos comenta, no es el abogado. Abogado es su otro hijo, Alonso. Contactos de sus hijos: § Alonso Ramón Díaz 681 188 756 § Jorge Ramón Díaz 634 746 174 Por lo que se ha trabajado con Justa desde el inicio de tramitación de ingreso no voluntario , en virtud de los seguimientos se considera desde este equipo que no sería buena opción que ella se enterase del día en que se va a ejecutar la sentencia. Siempre que se ha abordado el tema ha amenazado con ideas autolíticas o con irse de Montijo y que no sabríamos de ella. Proceder sin ella ser conocedora del día que se realizará será mas traumático para ella, pero nos aseguramos que no lleve a cabo ninguna de las ideas verbalizadas en varias ocasiones. Últimamente la hemos observado más estable emocionalmente y la notamos más activa. Ella misma expresa sentirse mucho mejor, incluso hace más vida social que antes. Se adjunta el último informe del psiquiatra, a dicha cita quiso acudir con el único fin de adjuntar el informe para poder demostrar que se encuentra bien y no se proceda al ingreso en centro, incluso poder tramitar la remoción de la tutela. El 17, a las 9, como hemos acorado estará por alli, la persona que la ha estado visitando, Sonia la ts,. Y se pondra ya a partide mañana con la ts del ssb para que la acompañe junto con la policia a la casa, para poder recoger la ropa, que la llevariamos a la residencia ya al dia siguiente seguramente, con la compañera de la zona de merida, que seria quien la visitaria en villafranca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTA'and edp.apellido1='DIAZ'and apellido2='BORREGUERO'),'2024-04-12','Amalia , escribo a Toni y a Maite. Con respecto al internamiento de Justa , ayer hablé con su hijo Jorge para quemar el último cartucho en esta historia . No le facilité información alguna sobre cuándo , dónde... sería el ingreso. Pero sí le informé que el Juzgado había indicado internamiento involuntario para poder proteger a su madre , que de otra forma quedaría en la calle. La teoría de la que te hablé quedó confirmada , su hermano el abogado la tuteló con la finalidad que la Junta parase el desahucio. Cuando ha visto que esto no ha sido posible , pedía que le diéramos una vivienda o un alquiler social . Estuve hablando largo y tendido con él .. le he pedido que planteen alguna alternativa a nivel familiar , y va a valorar con los hermanos colaborar para buscar un alquiler en Montijo. Le he dado de plazo hasta el lunes . Os escribiré para indicar si seguimos según lo acordado o si realmente plantean alguna salida. Dejo en suspenso el protocolo para activar el 112 hasta el lunes. Maite, el martes lo valoramos en oficina . Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2024-04-12','Ana: Mi respuesta al correo de Miguel: "Buenos días, de nuevo, a todos, Miguel, ¿cuándo se ha aceptado la CURATELA REPRESENTATIVA dices? El Acuerdo de Aceptación que envías ni tiene fecha ni está sin firmado. Yo no tenía constancia de esto hasta ahora y por eso no se ha comenzado a intervenir por esta sección. En cuanto al impago, por supuesto ha sido a raíz de el caro de CURATELA de 2020, sólo de carácter patrimonial y para actos de cuantía superior a 3.000€…. Con respecto a lo de buscarle otro piso o centro, pues bien, centro no puede ser pues no tenemos autorización de internamiento involuntario, y a no ser que haya cambiado de idea, que me extraña, ella nunca ha querido ingresar en centro. En cuanto al piso, se derivará al Programa gestionado por Futuex para que le apoyen en la búsqueda de uno nuevo, entre otras cuestiones."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='ALVES'and apellido2='MATEUS'),'2024-04-11','Ana: Correo de Javier, TS CSS-Plas (javier.rdguezper@salud-juntaex.es): "Te has puesto en contacto con Cristina por este paciente. El juzgado ya solicitó a este Centro el informe de este paciente. Me llegó la petición del informe 2 días antes de finalización de remisión. Te adjunto el informe que envié al juzgado (por correo ordinario y electrónico) Comentarte también que se solicitó videoconferencia y ya esta concedida. Cualquier cosa relacionada con este tema ponte en contacto conmigo. "','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='ALVES'and apellido2='MATEUS'),'2024-04-12','Ana: Reenvío a la Secc. Jurídica, el Informe Social remitido por Javier, TS CSS. ················· En el mismo, hace constar: "No existen relaciones familiares. No ha recibido visitas en el últimos año." ······· El copago que realiza al centro es de 540,91€, ······ "Ingresado en CSS desde 2005... en la Unidad de Profundos desde 2023" ······ Presenta Trastorno esquizofrénico y Polimialgia reumática. ···· Completamente dependiente para todas las ABVD. ···· Traslado en silla de ruedas. No capacidad para hablar ni expresarse, ni para la toma de decisiones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO MARIA'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2024-04-12','TERESA SOLICITO REVISIOND DE GRADO POR EMPEORAMIENTO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOLORES'and edp.apellido1='MACARRO'and apellido2='CAMACHO'),'2024-04-15','TERESA Establecemos reintegro quincenal por importe de 150€ Me dice Alberto varias cosas: 1.tiene un montón de tarjetas las cuales las vamos a cancelar todas 2. El consumo de agua es excesivo para una persona, sobre 47€ mes, puede ser que tenga algún salidero? 3. Tiene contrato de teléfono con digi ver posibilidad de cambio a prepago','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2024-04-12','TERESA ACTIVO 112 YA QUE ANTE LA NEAGATVIA DE DARLE MAS DINERO SE PONE MUY AGRESIVO Y ALTERADO DANDO VOCES LO LLEVAN AL HOSPITAL DE CACERES Y ALLI EL PSQUITRA DECIDE INGRESARLO HASTA EL LUNES QUE LE BUSQUEMOS UN CENTRO ADECUADO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='LANCHO'and apellido2='SANGUINO'),'2024-04-15','Ana: Llamo a la Res. de Mayores Obra Social de de Santa Marta Magasca (927 27 81 23):Me facilita el nº de Raúl, Director del centro: 625 380 408. Le llamo: Me corrobora que a Andrés le han concedido plaza pública en su centro, recibieron la resolución el pasado viernes. Me la enviará por correo-e. ···· La cuantía de la plaza le va a variar muy poco, me lo especificará también en el correo. ······························································································································································································· En relación al correo de Estrella, TS de Malpartida de Cáceres (ssb@malpartidadecaceres.es), preguntando por la plaza pública concedida y solicitando que solicitemos traslado a la residencia de Malpartida, respondo: "Pues de que le han concedido la plaza pública a ANDRÉS me enterado por tu correo esta mañana, nosotros no hemos recibido la resolución. Hasta ahora no he conseguido hablar con el Director del Centro, Raúl, quien me corrobora que la recibieron ellos el viernes. Te explico. Hace justo un año le valoraron para revisión de grado de dependencia. Dio grado III. No sé por qué no pude hablar contigo, pero en base a los informes anteriores y a su estado en aquel momento, se decidió poner el centro en que estaba como primera opción, pues a pesar del deseo de su hermano Dionisio, nos consta que la relación entre los hermano no era buena y podría resultar contraproducente para su estado de salud."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-04-15','Ana: envío correo a Alberto, Jefe Secc. Ecca., con copia a Lourdes: "Tal y como hablamos el jueves pasado a última hora, voy a tramitar para JOSÉ MANUEL ROMERO MEDIAVILLA, la solicitud de CLUB DE COMEDOR de la Residencia de Mayores Cervantes. Me han confirmado que hay plazas y que no suele tardar mucho, pero no me dicen plazo. Mientras tanto, puesto que la Educadora no han conseguido contactar con el catering previsto, vamos a autorizar 50€/semana para que la educadora le acompañe a comprar comida semanalmente mientras le conceden el catering." ·································· Lourdes, S. Ecca., ha hecho la primera autorización de reintegro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2024-04-15','Ana: Recibo del ESM-CC (equiposaludmental.caceres@salud-juntaex.es), citación para próxima consulta de Psiquiatría el 16/04 a las 8:50 h con la Dra. Cristina Donoso. ······························· Lo reenvío a Toni-Futuex y solicito acompañamiento a la consulta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2024-04-15','Ana: En el nuevo AUTO, que ya es FIRME, especifica que se trata de CURATELA REPRESENTATIVAS “…para tomar decisiones de contenido económico, para realizar donaciones o contrato alguno, así como para efectuar disposiciones de dinero en efectivo o de otra forma, o para manejar cantidades de dinero en una cuantía superior a 50 euros semanales, procediendo que el curador, o tercera persona autorizada por este, suministre a Dª. Vanesa con periodicidad semanal la cantidad de 50 euros para que esta disponga de la misma según su voluntad, salvo que por razones justificadas de necesidad económica dicha cantidad tenga que ser destinada a satisfacer otras necesidades de Dª. Vanesa, procediendo dicha persona a distribuir dicha cantidad total dentro del periodo semanal según su criterio basado en la protección del interés de Dª. Vanesa, o a reducir dicha cantidad en caso de las razones de necesidad antedichas; que requiere de representación para tomar decisiones que impliquen habilidades jurídicas y/o administrativas, como puede ser la gestión de solicitud de prestaciones económicas, asistenciales o sociales.”','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='GATO'and apellido2='LOZANO'),'2024-04-15','Amalia : mandan pto. de gafas desde el CSS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2024-04-15','Ana: Envío correo a Toni-Futuex: "En relación a Vanesa Fernández Gómez, hay que retomar APOYO Y SEGUIMIENTO. Dime si necesitas que te haga llegar la hoja de derivación. En el nuevo AUTO JUDICIAL, que ya es firme y por fin hemos recibido la firmeza del mismo para poder comenzar de nuevo a intervenir especifica: “…para tomar decisiones de contenido económico, para realizar donaciones o contrato alguno, así como para efectuar disposiciones de dinero en efectivo o de otra forma, o para manejar cantidades de dinero en una cuantía superior a 50 euros semanales, procediendo que el curador, o tercera persona autorizada por este, suministre a Dª. Vanesa con periodicidad semanal la cantidad de 50 euros para que esta disponga de la misma según su voluntad, salvo que por razones justificadas de necesidad económica dicha cantidad tenga que ser destinada a satisfacer otras necesidades de Dª. Vanesa, procediendo dicha persona a distribuir dicha cantidad total dentro del periodo semanal según su criterio basado en la protección del interés de Dª. Vanesa, o a reducir dicha cantidad en caso de las razones de necesidad antedichas; que requiere de representación para tomar decisiones que impliquen habilidades jurídicas y/o administrativas, como puede ser la gestión de solicitud de prestaciones económicas, asistenciales o sociales.” En estos últimos años, desde que en la anterior resolución dictaminaron una CURATELA PATRIMONIAL sólo para actos de cuantía superior a 3000 € (2020) al parecer no se ha gestionado nada bien. Mi compañero Miguel recibió llamada de Máxima, sobrina de la dueña de la vivienda en la que vive de alquiler en Miajadas (639436293). Pide que Vanesa abandone el piso, motivo: no paga hace años el alquiler, hace meses no paga agua y se la han cortado según le dijo el operario que fue a cortarla, no sabe si debe o no la luz que dice está a nombre de ella. Yo he intentado hablar con Vanesa, en el número que teníamos: (654 04 65 68), pero salta una locución diciendo que tiene restringidas las llamadas entrantes, no sé si tendrá otro número para que podáis localizarla primero. Sino la Educadora que asignes tendrá que ir al domicilio directamente. ES la vivienda de siempre: C/ Donoso Cortés, nº 23, 2º. Miajadas. *Os solicitamos por favor que le informéis/aclaréis su nueva situación, imagino que habrá recibido la CURATELA, y comencéis a intervenir con ella apoyándole en la búsqueda de nueva vivienda de alquiler con las siguientes premisas que indica Alberto, Jefe de Sección Económica, dada su malísima situación económica: “SE ESTABLECE REINTEGRO PERMANENTE DE 50 €/SEMANA (217 €/MES)....EL SALDO DE HOY ES DE 260 €...” (Ésta cuantía la establece el Juez en el Auto) “CONSUMOS: PREFERENTEMENTE A PAGAR X TRANSFERENCIA UNA VEZ QUE NOS REMITAN FACTURA. MUY IMPORTANTE: SI REINTEGRO ES DE 217 €/MES + PRESUPUESTAMOS 100 €/MES DE CONSUMOS.....EL ALQUILER NO PUEDE SUPERAR LOS 250 €/MES Y NO ES VIABLE DAR UN SOLO EXTRA.” Estas son las primeras gestiones a realizar, después en función de su evolución y necesidades podéis proceder, como en el resto de los casos, prestando los apoyos necesarios. Nos iremos coordinando."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO MARIA'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2024-04-15','TERESA Se ha hablado con Raquel la auxiliar del SAD de Diego y ha comentado varias cosas. En primer lugar, que están dejando a deber en los supermercados a los que van porque no les llega con la asignación. Dicha asignación es para la comida de Diego, y el tener que comer Petrona con él hace que la compra se duplique y no llegue. Con el cambio de horario, se entiende que deberá llevar la comida de su casa y/o al menos la cena se deberá suprimir, ya que puede cenar cuando salga. Es decir, es que si tiene tambien que sufragar Diego la comida, como cuando estaba interna, no le llega.. según ha valorado la auxiliar. Que puede ir a hacer la compra con el, por ejemplo. Por otra parte, está observando que no cumple con su horario., todas las veces. Se va a su casa muchas horas del día, en especial de la tarde, dejando a Diego solo. Una vez cambie al nuevo horario habrá que estar pendiente de esto, ya que si se le va a contratar para acompañarlo y va a estar solo...(está información nos llega por la auxiliar del sad, que entendemos tampoco saca nada, minitendo) Sobre la comida se queda a la espera de ver qué opináis y comunicárselo a Petrona.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2024-04-15','TERESA Desde el Equipo de Apoyo Social Comunitario informamos acerca de la situación actual de Pedro Tomás Murillo, a quien hemos realizado un seguimiento presencial en su domicilio; En lo que respecta a la condición de la vivienda, las condiciones higenicas siguen siendo deficientes. Intentamos hacer fotos, pero nos decia "que vulneraba su intimidad" el suele tener discursos de este tipo y como no queremos tampoco alejarlo más no las hicimos. A pesar del apoyo que se le trata de proporcionar, Pedro se muestra reticente a aceptarla. Ha expresado su negativa a permitirnos intervenir en sus pertenencias o colaborar en el desalojo del domicilio. Aunque hemos ofrecido nuestra asistencia, él ha rechazado nuestras propuestas, asegurando que la situación mejorará por sí sola en la semana siguiente, lo cual no se ha cumplido. La cocina presenta un considerable nivel de desorden, con acumulación de basura y botellas vacías, mientras que el interior del frigorífico no se encuentra en condiciones adecuadas de limpieza. El salón, utilizado como espacio para dormir, está saturado de cenizas, papeles y ropa de cama. Por otro lado, la habitación, aunque algo más ordenada, aún presenta niveles significativos de polvo. En términos generales, la vivienda se encuentra sumida en un estado de desorden, con una acumulación considerable de cenizas, polvo y basura. En relación con la propuesta de ayuda a domicilio, sugerimos una intervención de dos horas y media, dos veces por semana. Observamos que Pedro se muestra receptivo ante la idea de contar con asistencia externa. Los dias en principio, le daria igual, podria ser martes y viernes por ej. En lo que respecta a la gestión de documentos relacionados con la herencia, hemos realizado un intento por localizarlos en el domicilio de Pedro. Sin embargo, estos se encuentran mezclados con reportajes realizados por él y notas de libros, lo que dificulta su identificación y recuperación. A pesar de nuestros esfuerzos conjuntos por localizarlos, únicamente hemos logrado encontrar una cartilla cerrada a nombre de sus padres. A pesar de haber abordado el tema del domicilio de sus padres con el objetivo de obtener información sobre su posible venta, desvía la conversación enfocándose en el dolor emocional asociado a dicha pérdida. En cuanto a la gestión de asignaciones y deudas pendientes, hemos observado que Pedro ha dejado de acumular nuevas deudas desde que se le ha negado el pago de las mismas. No obstante, es importante destacar que presenta niveles significativos de ansiedad, lo que se traduce en conductas compulsivas relacionadas con la ingesta de alimentos. No obstante, nos encontramos trabajando activamente en abordar esta problemática y hemos notado una mejor disposición por parte de Pedro para colaborar en el proceso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2024-04-15','Ana: correo de ESM (equiposaludmental.caceres@salud-juntaex.es): "adjuntamos cita de anulación de revisión de Francisco Cacho Garrido. Acudió el 04/04/24 por error y se realizó la revisión. Citar de nuevo revisión en Junio. Avisar de la anulación y próxima revisión también a FUTUEX. Gracias. " ····················································································· Envío correo a Toni-Futuex: "Te reenvío correo del Equipo de Salud Mental, para vuestro conocimiento y que lo téngale en cuenta en al intervención. Subrayo en el hilo en amarillo. Pongo a Nieves en copia." ········································································· *Solicito al ESM, Informe de la revisión del día 4/04.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LAZARO'and edp.apellido1='LUBIAN'and apellido2='SANTANO'),'2024-04-15','Ángel: Recibo hoy por correo, los testimonios firmes de división judicial de la herencia por el fallecimiento de la madre, Áurea Santano Gilete y de la venta del único bien de la herencia, una casa sita en calle Andalucía, 19, de Cáceres. Lázaro tiene el legado del usufructo de la casa y la herencia, junto con sus 7 hermanos. Sobre la casa hay contrato de arras para venderla por 72.000 euros. La inquilina de la casa, que es quien quiere comprarla, está buscando financiación bancaria. Una vez la consiga, hay que hacer la escritura de compraventa. En principio Lázaro obtendría por ambos derechos 26.948,57 euros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='AVILA'and apellido2='FEMIA'),'2024-04-15','Ana: Tras confirmarnos Soraya que ya podemos activar el 112, llamo a Tomás, hermano de José Luís (91 680 83 31 / 688 915 073): hablará esta tarde con la chica que tiene las llaves de casa de su hermano para que la lleve a la Guardia Civil. Me confirmará mediante correo o llamada para que después active el 112.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIO'and edp.apellido1='GUISADO'and apellido2='GUISADO'),'2024-04-15','TERESA He hablado con su médico María José Rodríguez Galán de Atención primaria de Cabeza del Buey, y me ha comentado que ella no puede hacerle desde aquí ( Cabeza del Buey la E-Consulta al Oncóloga de Badajoz. Como bien sabes, tanto Laura, como la Oncóloga de Radioterapia Carmen, ya han hecho sus respectivas consultas. Estoy de acuerdo que no vamos a esperar mas y debemos trasladarlo, para que ya sea paciente de Badajoz y así pertenezca a su área de Salud y ya se encarguen ellos de la tramitación una vez que ya esta todo preparado. He estado reunido con la Psicóloga y nuestra programación de la Semana que viene para llevarlo y hacer el traslado de información y documentación al centro de destino sería el Viernes, antes , yo no podría ir , Eugenio tiene cita el Miércoles 17 de abril en el Hospital Siberia Serena de Radiología Primero y Neumología después , con lo cual también ya se llevaría un seguimiento ,perfectamente realizado y documentado , teniendo además acceso a el cualquier profesional sanitario que pueda acceder al Sistema Jara .El Lunes procederé a retirarle los puntos de Sutura del port a cath ,también .... En fin, si os parece bien lo propongo así el lunes en coordinación y si vosotros lo veis de otra manera, pues nada se hace cuando queráis y se le suspende esa cita de Neumología y se envía la documentación al centro de referencia y se le traslada. En cuanto me digáis si aceptáis esta propuesta del viernes 19 , procedo a comunicarme con la Dirección del Centro de destino. Te agradecería le comunicaras ,por favor que no se impacienten que nuestro objetivo es llevárselo en las mejores condiciones posibles y con todas las Garantías . Un saludo y si quieres me pasas su correo o se lo puedes pasar a ella, para que este tranquila. Me reitero, a vuestra disposición , si ha de ser inmediato, inmediato sea y sin problema , se le quedaría pendiente Neumología.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='RODRIGUEZ'and apellido2='ROBLES'),'2024-04-15','-Amalia : envío las denuncias a Yolanda a su email : yolandavillegas14@gmail.com','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='RODRIGUEZ'and apellido2='ROBLES'),'2024-04-15','-Amalia : Escribo a Alberto , Maite , Estrella y los jurídicos sobre este caso. Alberto ha indicado a Estrella que no abone nada y así lo ha indicado en un email. Desde la parte social no se comparte esa decisión , solicito valoración jurídica : Buenas , antes de decidir sobre este asunto creo que sería conveniente tener la orientación jurídica . Fco. Javier tiene enfermedad mental , y no tiene carnet ( es el mismo chico del que hemos estado valorando sobre si puede obtener la renovación o no ) . Hace unos días ha cogido las llaves del coche de su mujer , que ésta tenía escondidas , y se ha ido a la gasolinera . A la hora de pagar no llevaba dinero o no encontraba el billete de 5 € que iba a gastar y la chica ha llamado a la policía. Le han puesto una multa a su nombre de 200€ por conducir sin tener ya puntos del carnet. Si se abona por pronto pago mañana se le quedaría en 100€. Y otras 2 multas , una por no tener el coche seguro y otra por no haber pasado la ITV ,éstas a nombre de su mujer que es la propietaria del coche. He hablado varias veces con los dos. La mujer dice que no tiene dinero para pagar eso , que el coche no lo utiliza hace mucho tiempo y al no tener dinero para mantenerlo , lo tiene guardado sin seguro ni ITV . Él confirma lo que ella dice , y solicita por escrito que de su dinero se abone esas multas . A la mujer se le pasa todos los meses por transferencia un dinero para cubrir gastos de manutención casa , tienen 2 hijos menores ... A él no se le da ningún reintegro , ella le da lo que puede de esa transferencia. Yolanda me pide que le hagamos una transferencia por la totalidad de las multas que vienen a su nombre que son de 1500€ una y de 200 € otra . Por pronto pago, que sería mañana la fecha tope ,se quedaría en la mitad. A nivel jurídico , se puede/ debe hacer esa transferencia teniendo en cuenta cómo ha sucedido todo y que él manifiesta que quiere abonarlo ? o no se puede hacer teniendo en cuenta el precepto de que no podemos dar dinero del curatelado a préstamo a nombre de otra persona ? Se tendría que abonar la multa que le han puesto a él a pronto pago , o dejamos que sea por procedimiento de embargo ? La mujer no puede más con la situación en la que vive , además del desgaste personal tiene el económico y la situación es bastante tensa. Me dice que si no se pudiera hacer el reintegro total , que ella pediría prestado ese dinero y que durante 8 meses se le aumente en la transferencia que se le hace 100 € más para amortizarlo. A ver qué os parece .. y decidimos con conocimiento de causa ------------------------------------------------------------ Email de Alberto del 12 de abril de 2024: TOD@S: REINTERO MI OPINIÓN...YO NO ABONARÍA NADA QUE VA A IMPEDIR QUE MAÑANA, PASADO Y AL SIGUIENTE Y AL SIGUIENTE HAGA LO MISMO. QUIEN ME ASEGURA QUE SU MUJER NO ESTÁ EN SU MISMA LÍNEA...O QUE REALMENTE VA A ABONAR MULTAS...YA NOS LA HA JUGADO EN OTRAS OCASIONES. CREO QUE DEBERIAMOS DEJAR QUE EL COBRO SE PRODUZCA EN SU MOMENTO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PRUDENCIO'and edp.apellido1='CASARES'and apellido2='MARISCAL'),'2024-04-16','-Amalia : Solicito a la TS la renovación de su DNI.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALMUDENA'and edp.apellido1='CORREYERO'and apellido2='PAREJO'),'2024-04-16','-Amalia : desde la Comisión esta propuesta podría ser una alternativa para mejorar la situación en la que se encuentra. Lo he comentado con Mª Luz , y Almudena tendría que acceder voluntariamente a este traslado . Se lo tenemos que plantear a ella , y ver si lo acepta. Si os parece bien , lo hablamos para estar coordinados y poder motivarla al cambio. Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2024-04-16','miguel, envío email a la parte económica y social: Buenos días, he hablado con Máxima, tlfno 639436293, la hija de la casera, y le explico que envíe el email que está pendiente de enviarnos, explicando que incidencias tiene con el alquiler e incluyendo las cantidades, conceptos, fechas que se deban y que me comentó el otro día. En próximos días enviará dicho email','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2024-04-15','miguel, recibo email de Alberto: LOURDES/ANA:MUY URGENTE: LOURDES: ESTABLECE URGENTEMENTE REINTEGRO PERMANENTE DE 50 €/SEMANA (217 €/MES)....EL SALDO DE HOY ES DE 260 €...XFA, DÉJALE MUY CLARO AL BANCO QUE ESE IMPORTE DEBE QUEDAR VIGENTE DESDE EL MOMENTO EN EL QUE SE LO COMUNICAS. ANA/MIGUEL: ALQUILER...ME VAIS DICIENDO CUANDO HAY QUE COMENZAR A ABONAR NUEVO ALQUILER + CONSUMOS (PREFERENTEMENTE A PAGAR X TRANSFER UNA VEZ QUE NOS REMITAN FACTURA). MUY IMPORTANTE: SI REINTEGRO ES DE 217 €/MES + PRESUPUESTAMOS 100 €/MES DE CONSUMOS.....EL ALQUILER NO PUEDE SUPERAR LOS 250 €/MES Y NO ES VIABLE DAR UN SOLO EXTRA. ANA/MIGUEL: DEUDA (ALQUILER) QUE PUEDA TENER CON ANTERIOR PROPIETARI@...NECESITAMOS UN CERTIFICADO DE DEUDA ACTUALIZADO...EVIDENTEMENTE NO VAMOS A PODER CANCELAR ESTA DEUDA EN MUCHO TIEMPO (ESTO HA DE QUEDARLE CLARO AL PROPIETARI@). ________________________________________ miguel, recibo email de Ana: Buenas, a todos, Ya he comenzado gestiones para la búsqueda de nueva vivienda y para que le pongan educadora apoyo. Miguel; supongo que del certificado de deuda que indica Alberto, te encargas tú, no? Como ya has hablado con la familiar de la propietaria, porfa le indicas lo que dice Alberto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='CARVAJAL'and apellido2='CORNEJO'),'2024-04-16','miguel, ante la imposibilidad de entrar en la vivienda para el cumplimiento de por el 112 y guardia civil de llevarlo al hospital, llamo a instancia de Maite al juzgado quienes me indican que hasta mañana no podré hablar con la que lleva el expte. Envío email a Maite: Hola Maite, el juzgado me dice que la persona que lo lleva no está hasta mañana y que tenemos que hablarlo con ella con lo que hasta mañana no podré saber si tendremos que hacer nuevo escrito o no puesto que la providencia que envió el juzgado el día 12-4-24 y que adjunto, debería ser suficiente para que la guardia civil hubiese actuado. Por otro lado al tratarse de una curatela asistencial, no veo que tengamos que involucrarnos más en relación al internamiento…La sentencia de nombramiento indica: “EJERCIDA por LA COMISIÓN TUTELAR DE ADULTOS DE EXTREMADURA, cargo que habrá de ejercer RESPETANDO SIEMPRE LA MÁXIMA AUTONOMÍA DE Don Tomás EN EL EJERCICIO DE SU CAPACIDAD JURÍDICA Y ATENDERÁ, EN TODO CASO, A SU VOLUNTAD, DESEOS Y PREFERENCIAS en la medida que sea posible. Dicha medida judicial se acuerda para aquellos aspectos tanto en el plano económico-administrativo, como en lo relacionado con otras circunstancias de su vida que revistan cierta complejidad. Así pues, precisará de apoyo el manejo de recursos sociales básicos y cuestiones jurídico/administrativas y/o de contenido económico/contractual (gestiones administrativas, bancarias, compras, ventas, gastos o inversiones, negocios y contratos, decisiones patrimoniales, manejo de dinero). De igual forma precisará de ayuda para abordar con eficacia o para afrontar la toma de decisiones ante situaciones o aspectos de su vida que revistan mínima complejidad: autocuidado y manejo adecuado de cuestiones domésticas, manejo de tratamientos médicos y decisiones sobre negativa o solicitud de los mismos, gestión de recursos, toma de decisiones en cuanto a organización y previsión de cobertura de sus necesidades, otras decisiones de cierta relevancia o trascendencia, etc. Todo ello, sin perjuicio de la necesaria autorización judicial para los actos contemplados en el artículo 287 del Código Civil”.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='LANCHO'and apellido2='SANGUINO'),'2024-04-16','Ana: correo del Ayto. de Santa Marta Magasca (aytosantamarta@hotmail.com), de ayer a última hora: "Buenas tardes. Adjunto resolución de concesión de plaza pública de D. Andrés Lancho Sanguino. Tiene que abonar 745.27 € y desde enero de 2024 está abonando por el servicio 770.00" ·································· Mi respuesta: "Muchas gracias. Entiendo que, dado que tiene efetos retroactivos desde 1/01/2024 según la RESOLUCIÓN, desde el propio Ayuntamiento se regularizará el cobro de la plaza con la correspondiente devolución de la diferencia. Pongo en copia al Jefe de la Sección Económica para su conocimiento y actualización en la correspondiente ficha. Alberto: Subrayo en el hilo en amarillo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEBASTIAN'and edp.apellido1='PAREDES'and apellido2='DICHA'),'2024-04-16','miguel, email de Angel a Abogacía (a Carolina Guillen Carolina Guillén Estévez >carolina.guillen@juntaex.es> y Contencioso Área de los Servicios Contenciosos >contencioso@juntaex.es>) sobre el juicio del viernes por supuesto delito de falsificación de documento público: En relación a este asunto, recordamos la citación señalada para el día 19/4/24, este próximo viernes. Está citada Dª. Estrella Ángeles Martínez Lavado, Directora Gerente del Sepad, porque es quien firma todos los documentos en representación de las personas tuteladas y con medidas de apoyo, pero, tal y como hacemos en el resto de actuaciones, hemos solicitado que en lugar de ella, acuda a la citación el gabinete técnico de la Comisión Tutelar y además, que estemos presente a través de videoconferencia. A día de hoy, no hemos obtenido respuesta. Ampliamos información/documentación, que hemos podido ir recabando. El tutelado, D. Sebastián Paredes Dicha, reside en el Centro Residencial J.C. Rodríguez Ibarra, de Villafranca de los Barros. Desde este centro, se nos envió un escrito, en el que ponían de manifiesto que el tutelado estaba utilizando el documento falsificado, para intentar retirar dinero de las oficinas bancarias. Que lo hacía acompañado de un amigo que conoció en el centro penitenciario de Badajoz, llamado Miguel Ángel Delgado, natural del Berlanga, con número de teléfono, 633716234. Desconocemos más datos de esta persona. Dª. María del Mar Javier Palmero, Directora de la entidad Ibercaja, de Villafranca de los Barros, sita en C/ Hernán Cortés 7, con Telf. 924524434 Móvil 600995574, y correo electrónico, mmjavier@ibercaja.es, envió correo electrónico a Mª. Carmen García Brazo, Trabajadora Social del Centro Residencial J.C. Rodríguez Ibarra (mcarmen.garciabraza@salud-juntaex.es), en el que indicaba que D. Sebastián Paredes Dicha había estado en la oficina y que llevaba una autorización del entonces Director Gerente del Sepad, D. José Vicente Granado Granado, que es el documento falsificado, para intentar retirar dinero. Hemos intentado obtener información del resto de entidades bancarias de Ibercaja que indica el informe (Zafra, Los Santos de Maimona, Almendralejo, La Zarza), pero no nos han facilitado información. Al mismo tiempo, D. Sebastián Paredes Dicha, abrió otra cuenta bancaria en la oficina del Banco Santander de Villafranca de los Barros, qué después canceló, según el Informe del centro, con el propósito de ingresar el dinero que pudiera ir recaudando de Ibercaja para pagar al Abogado, entendemos que para solicitar la revisión de sus medidas judiciales. Desconocemos de qué Abogado se trata. Ampliamos que en lo referente a la Revisión de sus medidas, el procedimiento se ha iniciado, aceptamos el cargo de Defensor Judicial, con fecha, 9/4/24. Lo lleva D. José Mª. Escalona Amor (Ref. 453/2024) (Procedimiento 151/2024, seguido en el Juzgado de Primera Instancia e Instrucción, nº 3, de Mérida. Envío Informe económico, con los movimientos bancarios de la cuenta de D. Sebastián Paredes Dicha, en Ibercaja, en el que puede observarse que se han realizado transferencias, no autorizadas desde esta Comisión Tutelar de Adultos. De estas transferencias, parte no han tenido efecto debido a la “retrocesión” de las mismas, efectuada por la entidad financiera, ante la sospecha de que podría existir alguna irregularidad. Otras, sin embargo, si se han realizado, muy probablemente debido a que se han efectuado en oficinas más alejadas de la zona en la que el tutelado es conocido. Se han realizado “sin autorización” cuatro transferencias, por un importe total de 5.150 €. Se ha recuperado, un total de 2.800 € (debido a las retrocesiones efectuadas por Ibercaja). Por tanto, el importe transferido sin autorización y no recuperado es de 2.350 €. Envío la denuncia que la Fiscalía presentó, a consecuencia de nuestra denuncia previa, con las diligencias a practicar. Pongo en copia a mi compañero Miguel, que es quien estará presente el viernes.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2024-04-16','Ana: correo de Javier, TS CSS-Plas, a la secc. ecca. y a mí: "adjunto factura de compra de las gafas de Jairo". ········ Ya están abonadas. Precio: 89,00 €.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='PEREO'and apellido2='REBOLLO'),'2024-04-16','Ana: Correo de Lourdes, S. Ecca: "Se modifica la asignación de Antonio para el mes de mayo, que será de 350€, se devuelven todos los recibos posibles de telefónica, ya que según indican tiene teléfono de prepago. Avisas tu al centro de la subida?? Y si crees conveniente del tema de teléfono, abajo en el correo hay una tabla del banco con los pagos de Masmovil." ······························ Envío correo a Paula, TO CRR Plas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2024-04-16','miguel, envio email a Tere y Maite: Buenos días, necesito para pedir abogado de oficio para tramitar la herencia del tutelado Certificado de fe de vida (certificado de que está soltero…es como una declaración jurada que le tienen que dar en el juzgado de paz de Monterrubio de la Serena). He llamado al tutelado 641745023 pero salta el contestador, para que vaya al juzgado de paz a solicitarlo y nos lo envíe. He intentado también hablar con el registro civil de Castuera (cabeza de partido) para que nos lo enviaran pero o comunica o cuelgan y no hay email al que dirigirnos. Tere, cuando puedas habla con el tutelado para que se acerque el juzgado de paz de Monterrubio de la Serena a pedir dicho certificado de que está soltero Voy a ir enviando al Colegio de Abogados la solicitud de abogado de oficio para la aprobación de herencia y autorización de venta de la vivienda (cuando se firme la escritura de herencia en la notaria de Cabeza del Buey, a la que envié el viernes la documentación para que estudiaran la herencia y vayan preparando certificado de últimas voluntades (para comprobar si tiene o no testamento…que en caso de que no lo hubiese necesitaremos testigos para firmar la declaración de herederos de los padres…y cuando ya esté eso y localizado el certificado bancario con la cuenta de los padres, se podrá preparar la herencia…y tras la firma de ella y la ratificación de dicha herencia por nosotros, es cuando el abogado solicitará la aprobación judicial de herencia y autorización de la venta) Para estos trámites tanto el colegio de abogados (para el nombramiento de abogado de oficio), como la notaria, como el abogado nos irá pidiendo documentación. Cualquier duda me vas diciendo…','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2024-04-16','Ana: En relación al Informe que nos pide el Jdo. para la revisión de las medidas de apoyo de Guadalupe, llamo a Mari, Directora Residencia Ntra. La Luz de Malpartida de Plasencia (927 459 100, ext. 1): Hablará con la TS del centro y con la Psicóloga para que lo hagan en cuanto puedan y me enviará. ·························· En cuanto a Guadalupe, me informa que sigue bien, con sus cosas. Han conseguido que reduzca mucho el consumo de tabaco, ya sólo 6 cigarrillos al día. Ahora está en constante cambio de marcas, pues no terminan de satisfacerle. Por lo demás, sin cambios.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2024-04-16','Ana: Envío correo a S. Ecca, Maite y Teresa: "Os reenvío correo de Toni con factura que hay que abonar. Corresponden a taxis que tuvo que coger Felisa Felipe Teomiro porque ingresaron a su hijo en el hospital. Puesto que Felisisi, debido a sus escasos ingresos, siempre va justa de dinero, y tuvo que ir a llevar ropa que le pidieron en el hospital, Teresa y Maite, ¿qué os parecería que fuera Aitor quién abonara estos viajes? O al menos alguno de los dos. Como estos días no está Alberto, valorarlo y ya le decís a las compañeras de la Secc. Ecca, por favor." ··························································································································································································· Llamada de Felisi, dice que echa de menos a su hijo, pero ella quiere que se ponga bien y que no fume no se "meta". No quiere que vuelva a casa, la situación ya la superaba. *Su hijo le ha dicho esta mañana, mediante conversación telefónica, que le van a dar el alta y está preocupada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2024-04-15','Ana: Llamada de Felisi: Puesto que el viernes pasado ingresaron a Aitor en la UHB, ahora está aliviada, pues la convivencia era insostenible, no podía más. Este fin de semana ha estado limpiando toda la casa, cortinas incluidas, intentando eliminar el olor a tabaco y polvo, además de la suciedad. También tiene que lavar las fundas del sofá, dice. ··· *Ya no quiere que vuelva de nuevo su hijo a casa, dice que no podía más con él. ··· Rompe a llorar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2024-04-16','Ana: Envío correo a la S. Ecca: "En relación a Antonia Bernardo Piris, comunicaros que me ha llamado esta mañana informando que: - La semana del 22 se irá a casa de sus padres (viven en otra localidad) - La semana del 29 se irá con su hija a Madrid Por tanto, a primeros de mes no estará en Plasencia para retirar el dinero. *No quiere extra para los viajes, dice que se apaña bien, pero pide que se le adelante la asignación para poder retirarla el próximo viernes 19 de abril, pues no podrá retirarlo de las fechas habituales. Confirmarme si es posible, por favor para confirmárselo a ella."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='GONZALEZ'and apellido2='NARANJO'),'2024-04-17','TERESA Informamos que desde ayer tarde, la tutelada JUANA GONZÁLEZ NARANJO está hospitalizada en el Hospital Tierra de Barros con neumonía. Está acompañada por una cuidadora.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2024-04-17','miguel, enviamos solicitud de abogado de oficio al Colegio de Abogados de Badajoz','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2024-04-16','Ana: Correo-respuesta de Toni-Futuex: "Pues mira, justo se esta intentado concertar una cita para mañana, aunque por ahora Vanesa no nos ha facilitado la dirección, está o eso parece , en Trujillo.. según la TS de Miajadas,al parecer debe vivir en Miajadas, pero está siempre o casi siempre en Trujillo y no pagaba el alquiler de Miajadas, como bien sabeis. Este es el telefono en el que estamos conectando con ella; 643 35 84 10 Ha comentado que va a empezar a trabajar en un bar de 10 a 18,00h en Trujillo, pero a ver si conseguimos concertar la visita con ella y ampliamos toda esta información, porque hasta ahora, como venia siendo la tónica anterior, está bastante esquiva."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2024-04-17','Ana: Llamada de Felisi (614 361 144): Dice que ayer por la tarde le llevó un amigo de su hijo al hospital a ver a Aitor y que le cobró "un billete de 20 y otro de 10". Que no vuelve a hacerlo. Y que se asustó mucho porque casi tienen un accidente con otro coche. ········· Que vio a Aitor mejor, más limpio y que estaba comiendo bien. Estaba pintando cuando llegó. ····················· Que le da pena de su hijo, pero que es lo mejor. ···· Aitor le ha dicho que le van a trasladar a otro centro a Plasencia. ·············· Que todavía sigue limpiando la casa, pues aún hay zonas que huelen mal por los porros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-04-17','Ana: Tras cumplimentarlos, subo al portafirmas digital la SOLICITUD DEL CLUB DE COMIDAS y la DECLARIÓN JURADA DE BIENES. ················· Redacto Informe Social para la solicitud de Club de Comidas. ·· Pendiente de resto de documentación solicitada a Futuex para poder darle registro. ································································································································································································································································ Correo de Toni-Futuex: "Creo que el ha hablado contigo de este tema y estas al tanto, se le acompañó a un notario que conocia la familia, para consultar cuánto le costaría hacer un testamento y si en el mismo existe la posibilidad de dejar como único heredero a su hermano, pues es el único que se preocupa por él, y no quiere dejar nada a sus hijos que nunca le han cuidado ni se han preocupado por él (otro asunto es la parte legitima que les corresponde pero bueno que se lo expliquen llegado el caso) El notario le dijo que sí y da las indicaciones, se hace llegar los datos de contacto, para que según indica desde la comisión os podais poner en contacto , para enviarle un correo donde se autorice la gestión y después pueda hacerse el ingreso del coste del servicio (son 69€). El contacto es: José Luis 927 24 05 77/78 notguadalupe@terra.es Explica que desde la CTAEX se debería mandar un correo especificando la voluntad de José Manuel de realizar un testamento y la conformidad de la comisión en dicha gestión, así como facilitar el número de teléfono de José Manuel para que él pueda ponerse en contacto con él directamente. Una vez se contacte con José Luis desde la CTAEX, ellos facilitarán el número de cuenta." ···································· Reenvío a los A. Jurídicos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2024-04-17','Ana: Envío correo a Maite, jefa CTAEx y a Secc. Ecca: "Me ha llamado Julia, madre de Julia Morón Hernández. Hoy ya ha salido de la UCI, la han pasado a una habitación aislada también, pero fuera de allí. Hoy es el cumpleaños de Julia y ésta le ha dicho que nos pida dinero para que le compren algún regalo que le hace ilusión. Han pedido 100€, ya le he dicho que esta cuantía no es posible, pues la situación económica sigue siendo muy precaria y se les hizo otra transferencia de 120€ el mes pasado con motivo del ingreso, para ayudar a abonar los gatos de traslado y de estar por allí. Maite, como no está Alberto, te pongo a ti para que valores con las compañeras de la sección económica. Y lo que decidáis, se le hace una transferencia a la madre. Yo no me aventuro a decir cuantía pues no sé exactamente lo que le queda en cuenta."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REGINA'and edp.apellido1='REINA'and apellido2='LARA'),'2024-04-17','Marieta Sánchez Becerra Trabajadora Social CEE Los Ángeles, Badajoz Telef. 924013432 Ext.26792 mlsanchezb05@edcaurex.es','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='AVILA'and apellido2='FEMIA'),'2024-04-17','Ana: Trasladan en ambulancia a José Luis al HSPA. ····················· A petición de Carmina, Adtvo de la UHB (56965/adminpsiquiatria.hspa@salud-juntaex.es) le envío email: "Tal y como hemos acordado, adjunto la siguiente documentación relativa a D. JOSÉ LUIS ÁVILA FEMIA, cuyo cargo ostenta la Comisión Tutelar de Adultos de Extremadura: - Testimonio de Auto Judicial de medida de apoyo, nombramiento de Curador Representativo y autorización de internamiento involuntario - Informe de Seguimiento del Equipo de Salud Mental de 2021 - Informe Médico Forense de noviembre de 2022 - Certificado de Discapacidad del CADEX + Dictamen Técnico Facultativo Es todo lo que obra en el expediente de momento, es un caso muy reciente para la CTAEx. En el Centro Sociosanitario de Plasencia me consta que ya tiene esta documentación y di por hecho que os la habían facilitado ahí también a vuestra unidad. Disculpad las molestias de no haber sido así. Ante cualquier otra cuestión, no dudéis en volver a contactar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2024-04-17','Ana: Tras llamada de Antonia, envío correo a la S. Ecca: "Me acaba de llamar Mª Antonia, que se lo ha pensado mejor y como su hija no puede afrontar todos los gatos cuando vaya a Madrid, quiere un extra de 250 € para el viaje. *Además del adelanto de la mensualidad que os puse en el correo de ayer (leed el hilo. Esto sólo obedece a que del 1 al 5 no estará en Plasencia para poder retirarlo). Por mi parte si es viable, OK al extra." ···························· Se aprueba el extra. ··········· Se lo comunico a Mª Antonia (677 80 64 45).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO'and edp.apellido1='PAJARES'and apellido2='TALAVERA'),'2024-04-17','Ana: Correo de Toni-Futuex: "Desde Novaforma se ha contactado con el programa para inforar que debe firmarse el convenio de prácticas con Seur que han buscado para Santiago Pajares, unas prácticas de paquetería que realizará durante un tiempo determinado en dicha empresa (es un convenio con Novaforma), y que necesitan la firma de su tutor/a, ellos no saben si debe ser la madre o la CTAEX. Se traslada este documento para que se pueda firmar y mandarlo de vuelta firmado. Es algo que debe hacerse con la mayor brevedad posible, ya que lo necesitan en Novaforma." ································ Respondo: "Me parece estupendo que realice estas prácticas. Pongo en copia a los compañeros jurídicos para revisen el contrato a la mayor brevedad y si todo está ok se pondrá a la firma y se devolverá firmada a lo antes posible. Pongo en copia a Teresa Nogueira, TS de Novaforma para que también esté al corriente. Un saludo y buena tarde a todos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='FERNANDEZ'and apellido2='SERRANO'),'2024-04-17','Ana: Respondo al correo de Toni-Futuex con nuevo presupuesto para obra de los escalones de la casa de Josefa mucho más económico que el anterior (TOTAL= 440€): "Qué diferencia de precio Toni! Supongo que lo que no entrará aquí es obra del muro del patio que también estaba en mal estado, no? De todas formas, con este expediente estamos en pleno proceso de “investigación”, pues ha habido movimientos extraños en las cuentas desde hace unos meses que han salido ahora a la luz al ver la valorar la viabilidad del presupuesto… espero poder darte respuesta a la mayor brevedad."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-04-18','Ana: Envío a Juan Carlos, Aux. Adtvo.: "adjunto para remitir por REGISTRO a la Sección de Centros de Mayores – SERVICIOS CENTRALES DEL SEPAD AL Nº DE BUZÓN: A11030389, la siguiente documentación para SOLICITUD DE PLAZA EN CLUB DE COMIDAS relativa D. JOSE MANUEL ROMERO MEDIAVILLA, cuyo cargo ostenta la CTAEx: - Solicitud firmada digitalmente por la Representante Legal - Declaración Jurada - Informe Médico - Informe Social - Certificado de PNC - Certificado de Convivencia - Certificado Catastral - DNI solicitante - DNI representante Legal - Testimonio de Sentencia de Nombramiento - Testimonio de Aceptación del Cargo - Decreto de nombramiento – Directora Gerente - Resolución de delegación de funciones como Presidenta de la CTAEx" ····························································································································································································· Solicito a Toni-Futuex, que cuando puedan nos remitan escaneado el DNI actualizado de José Manuel, pues el del expte. está caducado de 2022.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-04-17','miguel, recibo email de Ana que me reenvía el de Toni de Futuex: Hola, de nuevo, compañeros, Os reenvío correo de Toni en relación al deseo de José Manuel de testar. Ya le han acompañado desde Futuex a una notaría y este es el resultado. Ya me vais informando al respecto de estas gestiones/trámites. ------------------------------------------------------- Email de Toni de Futuex que reenvía Ana: Creo que el ha hablado contigo de este tema y estas al tanto, se le acompañó a un notario que conocia la familia, para consultar cuánto le costaría hacer un testamento y si en el mismo existe la posibilidad de dejar como único heredero a su hermano, pues es el único que se preocupa por él, y no quiere dejar nada a sus hijos que nunca le han cuidado ni se han preocupado por él (otro asunto es la parte legitima que les corresponde pero bueno que se lo expliquen llegado el caso) El notario le dijo que sí y da las indicaciones, se hace llegar los datos de contacto, para que según indica desde la comisión os podais poner en contacto , para enviarle un correo donde se autorice la gestión y después pueda hacerse el ingreso del coste del servicio (son 69€). El contacto es: José Luis 927 24 05 77/78 notguadalupe@terra.es Explica que desde la CTAEX se debería mandar un correo especificando la voluntad de José Manuel de realizar un testamento y la conformidad de la comisión en dicha gestión, así como facilitar el número de teléfono de José Manuel para que él pueda ponerse en contacto con él directamente. Una vez se contacte con José Luis desde la CTAEX, ellos facilitarán el número de cuenta','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-04-18','miguel, conforme indicaciones del email de Ana, envío email a la notaria en relación a la petición de la misma que nos pongamos en contacto con la misma para la firma del testamento: notguadalupe@terra.es A/A DE JOSE LUIS: Buenos días, en relación a persona tutelada por la Junta de Extremadura (SEPAD-Comisión Tutelar de Adultos), nos indican que nos pongamos en contacto con usted 927 24 05 77/78 para confirmarle que el curatelado representativo José Manuel pueda hacer el testamento. Le confirmamos que por parte de la Comisión Tutelar de Adultos no existe inconveniente a la firma del mismo, por cuanto su sentencia de incapacitación no se lo impide (adjuntamos de nuevo la misma a esta notaria y puede leer en emails de debajo…). Dichos emails se remitieron a manamor@despacho.notariado.org y a bsilos@despacho.notariado.org La factura que emitan pueden remitirla a ctutelar@salud-juntaex.es para su abono.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO'and edp.apellido1='PAJARES'and apellido2='TALAVERA'),'2024-04-18','Ana: Una vez Miguel, A. Jurídico, da el visto bueno, cumplimento los datos de Santiago y recabo firma de la Representante Legal. ··················· Envío a Toni-Futuex y Teresa, TS Novaforma: "Adjunto el CONVENIO DE PRÁCTIC AS CON SEUR, relativo a SANTIAGO PAJARES TALAVERA debidamente firmado y sellado por la Representante Legal."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='BERMEJO'and apellido2='TELLO'),'2024-04-18','-Amalia . La hna. no coge tf , imposible contactar con ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REGINA'and edp.apellido1='REINA'and apellido2='LARA'),'2024-04-18','Marieta CEE móvil 635507517','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2024-04-18','Ana: Correo de Estrella, TS CSS-Plas: "Os informo que Enrique se va esta mañana de pase, a domicilio, hasta el martes" ································· Escribo a Toni y Clara, Futuex: "Os reenvío correo de Estrella, TS del C. Sociosanitario de Plasencia comunicando nuevo pase de ENRIQUE SANTOS GARCÍA PUENTE, por favor, si es posible, organizad visitas de seguimiento en los días que va a estar allí." ······················· Respuesta de Toni-Futuex: "Se hará el seguimiento el lunes 22. Ya está gestionado desde el equipo, irán las dos compañeras como la vez anterior,."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2024-04-18','Ana: Reenvío a la secc. ecca. correo de Toni-Futuex, contestando también a Toni: "Os reenvío FACTURA de grifo y arreglo de FELISA FELIPE TEOMIRO, hay que abonarlo. Subrayo en el hilo el número de cuenta para hacer transferencia. Pongo a Toni y a Nieves en copia. Por cierto Toni, ella ya había llamado al fontanero porque el grifo estaba roto, lo cierto es que no se había aprobado previamente, pero puesto que también ha invertido parte de su asignación en ir a ver a Aitor pagando 30 € a un amigo de éste (ya le he dicho que no vuelva a hacerlo así) y se iba a ver muy apurada si pagaba esto también, que además es necesario, le dije que nos lo enviara a través de la educadora. Pero por favor, abordad, para reforzar, estas dos cuestiones, tanto lo de las visitas a Aitor como pedir presupuesto sin avisar antes aquí."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEBASTIAN'and edp.apellido1='PAREDES'and apellido2='DICHA'),'2024-04-18','miguel, para el juicio de mañana contra el tutelado por posible delito de falsedad documental envío email a abogacía miguel.prieto@juntaex.es, Estrella y Angel: Buenos días, adjunto justificante de una de las cantidades no recuperadas 1.350€. Dicha transferencia se realizó a la cuenta destinataria de Miguel Angel Delgado Jimenez, y se realizó desde la sucursal de Ibercaja de 4576, de los Santos de Maimona. Por lo tanto la información en cuanto a los movimientos desde la cuenta de Ibercaja nº ES92-2085-4511-93-0332311449 del tutelado (actual curatelado representativo) es la siguiente: 1.-Transferencias realizadas y devueltas: 17-7-23 desde la oficina de Ibercaja en Usagre por importe de 1.800€ 4-7-23 desde la oficina de Ibercaja, desconocemos la sucursal, por importe de 1.000€ 2.- 1.-Transferencias realizadas y NO devueltas: 11-7-23: desde la oficina de Ibercaja en Los Santos de Maimona por importe de 1.350€ 10-7-23: desde la oficina de Ibercaja en Los Santos de Maimona por importe de 1.000€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEBASTIAN'and edp.apellido1='PAREDES'and apellido2='DICHA'),'2024-04-18','miguel, reenvío a abogacia email de Ibercaja de Mérida De: Martinez Lozano, Jose Luis >jlmartinezl@ibercaja.es> Enviado el: martes, 16 de abril de 2024 14:39 Para: ESTRELLA MARIANA GUERRERO PEREZ >estrella.guerrero@salud-juntaex.es> Asunto: RE: MUY URGENTE !!!!SEBASTIAN PAREDES DICHA Buenos días, Efectivamente. Es al revés. Se anuló la de 1800 euros y no se anularon las de 1.000 euros ni la de 1350 euros. Estas operaciones se realizaron en la oficina de Los Santos de Maimona. He solicitado justificación de estas transferencias a la oficina pero me indican que no tiene ningún documento justificativo de esta operaciones. Un saludo José Luis Martínez Lozano Subdirector Controller 4511 Mérida Plaza de España, 21 06800, Mérida, Badajoz Tel 924 319 911 – Móvil 671 69 10 82','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LEON'and edp.apellido1='LEAL'and apellido2='PEREZ OLAGUE'),'2024-04-18','Maite:Ha llegado recibo del ayuntamiento de Vlaencia correspondiente al IBI. Lo paso a la sección econçomica para que se abone.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='BERMEJO'and apellido2='TELLO'),'2024-04-18','Pero mi opinión y creo que es de sentido común, es que el centro puede y deben adoptar medidas de apoyo y adaptación a los residentes. En este caso es tan sencillo como que le digan a la hermana que no lo traiga pues no se lo van a dar pues es perjudicial para la dieta que está haciendo… Miguel : El centro debe entender que el curador representativo (antigua tutela) está para cuestiones laborales, económicas y jurídicas, y no para preguntas cuya respuesta debe afrontar el centro que actúan como guardadores de hecho…entiendo yo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='CUENCA'and apellido2='SILVA'),'2024-04-18','En el día de la fecha se ha trasladado al paciente D. José Cuenca Silva Al Hospital De Mérida donde ha sido ingresado en el servicio de Neumología. Un saludo, Julia Marina Barrero, médico del CSS de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2024-04-16','Ana: Correo de Paula, TO - CRR: "Hola Ana, comentarte acerca de Mª Ángeles Santos Urbano. Ya sabes el deseo que ha manifestado desde su llegada de poder, cuando cumpliera los requisitos suficientes, poder ir a una residencia o similar en su pueblo o cerca, para poder visitar a su padre con mayor frecuencia (ahora muy limitada por la pernocta y por el hecho de que el padre ha estado malillo y sentía que debía estar bien para cuidar de M.Ángeles cuando ésta iba a casa). El caso es que, a petición de M. Ángeles estamos informándonos sobre de los pisos supervisados de mayores de Valverde, a través de Ana B. (TS) de Salud Mental. Por grado podría incorporarse y hay varias plazas actualmente, estamos a la espera de que nos puedan confirmar si habría posibilidad de que accediera por la edad (tiene menos de 60). Cuando tengamos más información te decimos, así como si fuera necesario algún otro requisito. Supongo que el pago es el habitual (máximo 75% de pensión, etc.) aunque también nos informaremos de manera específica."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='HERNANDEZ'and apellido2='SANCHEZ'),'2024-04-18','-Amalia , se le pone acompañamiento hospitalario 1 hora con Asinde.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='BERMEJO'and apellido2='TELLO'),'2024-04-18','-Amalia , escribo a Alberto , Maite : Buenos días , he estado hablando con la dirección y administración de la R. Mayores de Ávila donde se encuentra Jesús desde hace años para actualizar pagos. Han enviado hace un par de meses la actualización de la plaza con la subida del IPC y está pendiente de abono. Se deben 50€ al mes desde enero 2024 a abril , total 200€ en concepto de actualización conforme IPC , se puede abonar en una transferencia puntual . A partir de mayo transferencia permanente de 1600 € hasta enero de 2025 que se actualizará de nuevo el IPC ; con los siguientes conceptos: -1485€ plaza residencial -65€ gastos de bolsillo -50€ ( podología, peluquería , droguería .) Estos gastos de bolsillo no se han pagado en años porque la hermana los ha cubierto . Jesús tiene unos ingresos mensuales sin contar extras de 1605€ , 1275€ de pensiones de MUFACE ( PFHC+P ORF) y 330€ que le ingresa su hna. Ana de forma voluntaria . Ella ya no abonará ningún gasto . Tiene ahorrados 42000€ en cuenta , que se utilizarán para cubrir gastos extraordinarios puntuales , como puede ser un acompañamiento a médico , hospitalario , ropa .. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2024-04-19','Ana: correo de Toni, de ayer: "...Hoy nos ha dicho que quiere ir taxi, pero como comentabais que anda justa de dinero, se le autoriza?? En coordinación con mi compañera se ha establecido el apoyarla para que pudiera hacer los desplazamientos en autobus, que es mucho mas economico, pero ella tiene una serie de limitaciones, y habria que hacerlo supervisandola, habiamos previsto de cara a la semana que viene, si sigue ingresado. Por lo tanto con lo del taxi que le comentamos?" ·············································· Mi respuesta: "Decirle que ahora no puede permitirse el coste del taxi, que se va a abonar también lo del fontanero. Que espere a la semana que viene para que podáis apoyarla en los desplazamientos en autobús. Así también lo practica. No puede habituarse a coger taxis por el nivel de gasto que supone."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='RODRIGUEZ'and apellido2='ROBLES'),'2024-04-19','TOD@S: REINTERO MI OPINIÓN...YO NO ABONARÍA NADA QUE VA A IMPEDIR QUE MAÑANA, PASADO Y AL SIGUIENTE Y AL SIGUIENTE HAGA LO MISMO. QUIEN ME ASEGURA QUE SU MUJER NO ESTÁ EN SU MISMA LÍNEA...O QUE REALMENTE VA A ABONAR MULTAS...YA NOS LA HA JUGADO EN OTRAS OCASIONES. CREO QUE DEBERIAMOS DEJAR QUE EL COBRO SE PRODUZCA EN SU MOMENTO. 2) Para:​Amalia Diaz Gonzalez;​Maria Teresa Gomez Martin​ CC:​ESTRELLA MARIANA GUERRERO PEREZ​ Vie 12/04/2024 13:52 TOD@S: este tutelado no tiene asignación porque, en su momento y sin autorización de la CTAEX, se apropio de los ingresos derivados del alquiler del local. Si a alguno de los presente se le ocurre la forma de que el tutelado, una vez abonada la multa, proceda a volver a devolver el dinero a su cuenta, perfecto...si no es así yo no abonaría. El echo de abonar estos importes no solventa el problema...volverá a coger el coche, volverá a generar multas....hará, como siempre, lo que le venga en gana. No se tampoco, si es posible poner una denuncia o una comunicación al juzgado sobre esta cuestión. En mi opinión, deberíamos dejar que estas multas, en su momento, sean cobradas a través del oportuno expediente. Alberto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PALOMA'and edp.apellido1='RODRIGUEZ'and apellido2='JIMENEZ'),'2024-04-19','TERESA Al respecto , tema piso y casera de Paloma: En la visita de la semana pasada Paloma, contaba que no le queda nada de dinero hasta mayo que vuelva a cobrar su padre y ella, que se lo ha gastado todo pagando lo que debía y demás. Se ha hablado con la casera, Mary, y dice que no es verdad que le ha pagado, le debe 4 facturas (se adjuntan por informar), 192,64€. Ha mostrado las facturas, las pagadas las firman como que está hecho el pago. La mujer dice que está cansada ya de la situación pero es una mujer mayor y les dan pena, entiende que en algún sitio deben estar aunque preferiría que se fueran. Ha dicho que si ellos pagaran sus facturas al mes como debe ser y mantuvieran la casa más limpia no tendría problema en que se quedaran. Las paredes hay que pintarlas, Paloma dice que debe correr a cuenta de Mary, la casera, y esta dice que están así (amarillas) por culpa de Paloma que fuma todo el rato dentro de casa, por lo que considera que debe ser ella quien se encargue... Si sigue dejándole a deber facturas notificará por escrito que quiere que se marchen, hay meses que no le paga ninguna, otros que le da solo una parte, y así no quiere seguir. También comenta que se estableció una subida del alquiler a 350€ desde el mes de marzo y tanto marzo como abril le ha seguido llegando 300€, pide que se actualice a lo establecido para el próximo mes. Paloma dice que aunque la dejen quedarse se quiere ir y su padre también, pide que le busque piso fuera, que la CTAEx lo ha autorizado. Anda con mentiras todo el tiempo e intentando hacer el lío... Por otra parte, se ha hablado con Mamen y Elena, ambas TS de los SSB. Comentan que su padre tiene un servicio de acompañamiento por las tardes, va una chica ciertos días y le hace la compra, va a la farmacia si lo necesita y principalmente lo asea. Paloma ya le ha dicho varias veces que no entre a ducharlo, si continúa así lo retirarán. Ella no se encarga de asearlo, en varias visitas se le ha observado que lo tiene solo con el pañal sentado en el sofá, sin más ropa..., él no puede valerse por sí mismo, a tenerlo en cuenta de cara al cambio de vivienda si procediera. También se han visitado 2 viviendas en alquiler en Jerez entre la última visita y hoy, por si tuvieran que irse ir agilizando un poco. En ambas al comentarles la situación y quienes serían los inquilinos se han negado, todo el mundo los conoce, sobre todo a Paloma, y se niegan a alquilarles su casa. Encontrar otra vivienda en Jerez sería muy complicado... pero si se mantuvieran los pagos, podrian continuar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2024-04-19','Ana: en relación a corre-respuesta de Alberto del 21/03, envío correo a Toni-Futuex, de cara a la intervención a medio plazo: "En relación ÁNGEL FÉLIX MAILLO SANTIBAÑEZ, de cara a la intervención a medio plazo, previendo salida del centro, habrá que apoyarle de nuevo en la búsqueda de piso de alquiler. Te paso información y cálculos que hizo Alberto, Jefe Secc. Económica: ACTUALMENTE: la media de REINTEGROS MENSUALES (INCLUYENDO EXTRAS): 741 €/MES (DE ESTA FORMA SE LE AHORRA 2 PAGAS EXTRAS JUSTAS. // Se incluye en los gastos el SEGURO DE DECESO) EJEMPLO DE PRESUPUESTO DIVIDIENDO LA MISMA CUANTÍA (750€) EN LOS SIGUIENTES CONCEPTOS: ALQUILER: 350 €/MES CONSUMOS: 100 €/MES??? ----- Si los consumos se disparasen habría que bajar la asignación. REINTEGRO:300 € ----- Posiblemente a él le cueste ajustarse a esta cuantía, estando acostumbrado a manejar más del doble. Habría que trabajar con él para ver si acepta estos presupuestos y para la búsqueda del alquiler llegado el momento. Esperemos que ahora permanezca una buena temporada en el recursos residencia, donde las necesidades básicas las tiene cubiertas e interviene con él los distintos profesionales del mismo, además de seguir contando con el apoyo Clara desde el programa. Por cierto, la pongo en copia."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELA'and edp.apellido1='RODRIGUEZ'and apellido2='FIGUEREDO'),'2024-04-19','TERESA Con fecha 10 de abril de 2024, se realizó visita presencial al domicilio de Ángela Rodríguez, una vez que ha regresado, por decisión propia, después de una semana, en centro residencial Hernando de Soto de Jerez de los Caballeros. A pesar de que Vanesa, directora del centro y el resto del equipo, han intentado explicarle las ventajas de residir ahí, tal como ella ha demandado voluntariamente, tenía la decisión tomada y el martes 09, a la semana de entrar, Quini la ha recogido de regreso a su domicilio en Villanueva del Fresno. En la visita en su domicilio, nos encontramos a Ángela en la cama, pues dice que tiene mucho dolor de espalda y que, al marcharse la auxiliar, se ha echado a descansar. Y la primera razón que expone de su salida tan precipitada del centro residencial es que la han tratado mal, al no aceptar llevarla al médico con lo mal que ella se encontraba (ya sabemos de la recurrencia de las consultas médicas que tenia en su localidad). Desde el primer día ha estado demandando acudir a consulta médica, siendo esta idea obsesiva en ella. Era una de las incidencias de Ángela antes de su ingreso, hasta el punto de tener que contactar con el doctor Samino, su psiquiatra, para que modifica su pauta y poder tranquilizarla, ante las constantes llamadas a centro de salud, cualquier hora y día. Ella niega estos hechos, tan solo repite que no le han hecho caso con lo enferma que está, solo le decían que se tranquilizara y no pensara tantos en médicos, por eso decide regresar a su casa y poder pagar a Quini o bien otra mujer para estar algunas horas más acompañada. Le explicamos que son 10 euros la hora y que sumado a más horas es una situación nueva que se debe valorar y autorizar. En el día de hoy miércoles 17 de abril de 2024, se recibe llamada de Ángela para expresar su gran malestar y nerviosismo, ante el gasto, según nos cuenta, que le supone abonar los acompañamientos a Badajoz en sus distintas revisiones médicas: el lunes 15 ha tenido revisión con el psiquiatra doctor Samino y el próximo lunes 22 tiene cita para realización de prueba en endocrinología por bocio (nódulo) Hemos contactado con Quini para saber qué taxista le hace el traslado a Badajoz para valorar el abono por transferencia y así evitar cualquier dificultad, pero nos comenta Quini y también Ángela, que nos vuelve a llamar, que últimamente es Quini la que la lleva en su vehículo propio y así le acompaña en las consultas y recoge mejor la información, ya que Ángela no puede acudir sola a las consultas y no se puede permitir pagar taxi y acompañamiento. Que a ella le abona lo que factura el taxista: 55 euros y que, por tanto, es un gasto extra en la semana para Ángela con los 280 euros de asignación. Demanda insistentemente en que se suba la asignación semanal a más de 300 euros. Le hemos comentado, que ibamos a informar para que lo valorarais','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2024-04-19','-Amalia : email de Melania desde CRR . Disculpa la tardanza en responder. La semana pasada justo después de recibir tu correo ( aún no se lo había comunicado a Manuel ni me había sentado con él ) se me adelanta él comentándome que su hermana Maria José lo ha llamado por teléfono para decirle que “ ellas dos ( Maria José e Isabel ) no quieren vender el piso que tienen en Badajoz, que es la hermana de Madrid la que quiere pero que ellas no están dispuestas”. Como era de esperar, Manuel tras la llamada de su hermana, ha cambiado de opinión y me comenta que si sus hermanas no quieren vender que él tampoco… Al final, una vez más, entran en escena cambiando el rumbo de todo y descolocando por completo a Manuel… en fin. Si puedo ayudarte en algo más. Házmelo saber. Siento todo esto para finalmente nada… la hermana es tremenda..','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2024-04-19','TERESA ENVIO TARJETA ACREDITATIVA DEL GRADO DE DISCAPACIDAD A CASA DE FELIISI PARA QUE LA DELEGADA SE LA HAGA LLEGAR AL CENTRO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2024-04-19','Ana: Correo de Cristina Hdez., TS CSS-Plas: "te mando adjunto ticket de los 200€ que se sacaron para ropa en relación al paciente Martín Domínguez Palencia. Va comprando según neceita." ·············· Lo reenvío a la secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2024-04-19','Ana: Correo de María, Secc. Ecca.: "...ya esta pagado el restante que debía Saturnino a la tienda de muebles, por la compra de la lavadora y la antena TV (103,20 €) Por otro lado le veo cargos en el banco mensuales de Yoigo por 15 € y teléfono por 28 €. Le tienes tu autorizado estos gastos ¿?? Antes de hablarlo con Alberto quería verlo contigo… Ya me dices…" supuestamente son pagos pendientes de septiembre de 2022. ······················· Mi respuesta: "Pues cuando salió del C. Penitenciario de Cáceres estuvo viviendo una temporada en una vivienda familiar (herencia de su padre) en Alcuéscar, allí hizo y deshizo muchas cosas sin autorización y con el apoyo de uno de sus hermanos, Tomás. En el banco tardaron en hacer caso hasta que Óscar consiguió contactar con el Director de la oficina bancaria. En la Intranet podéis ver mis anotaciones del 10 y 14 de octubre de 2022 con correos de Alberto y de Óscar. Yo pensaba que todas esas cuestiones estarían ya abonadas… pero entiendo que sí había que abonarlo, tal y como habéis hecho, y ya supongo que es tarde, pero que habría que haber indicado a la tienda en cuestión que a partir de ahora no se le abonará nada que lo que no se haya enviado previamente, y aprobado por la CTAEx, presupuesto alguno. En cuanto a los gastos de telefonía, desde aquí no se aprobó ningún contrato de telefonía, y que yo sepa, en el penitenciario no puede usar teléfono, así que no sé quién estará haciendo uso de ello. Supongo que se puede dar de baja y devolver recibos. Y que cuando salga se compre algún teléfono, si no dispone de terminal, con tarjeta prepago."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2024-04-19','Pues cuando salió del C. Penitenciario de Cáceres estuvo viviendo una temporada en una vivienda familiar (herencia de su padre) en Alcuéscar, allí hizo y deshizo muchas cosas sin autorización y con el apoyo de uno de sus hermanos, Tomás. En el banco tardaron en hacer caso hasta que Óscar consiguió contactar con el Director de la oficina bancaria. En la Intranet podéis ver mis anotaciones del 10 y 14 de octubre de 2022 con correos de Alberto y de Óscar. Yo pensaba que todas esas cuestiones estarían ya abonadas… pero entiendo que sí había que abonarlo, tal y como habéis hecho, y ya supongo que es tarde, pero que habría que haber indicado a la tienda en cuestión que a partir de ahora no se le abonará nada que lo que no se haya enviado previamente, y aprobado por la CTAEx, presupuesto alguno. -Amalia ; Ana aclara abonos de gastos que le han llegado : En cuanto a los gastos de telefonía, desde aquí no se aprobó ningún contrato de telefonía, y que yo sepa, en el penitenciario no puede usar teléfono, así que no sé quién estará haciendo uso de ello. Supongo que se puede dar de baja y devolver recibos. Y que cuando salga se compre algún teléfono, si no dispone de terminal, con tarjeta prepago.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SEBASTIAN'and edp.apellido1='PAREDES'and apellido2='DICHA'),'2024-04-19','miguel, entro en el juicio para ratificarnos en la demanda por posible delito de falsificación en documento público, perjudicada la junta, y abogado de abogacía General miguel prieto, miguel.prieto@juntaex.es y tlfno 617-545919','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2024-04-19','Ana: Envío correo a Toni-Futuex, y S. Ecca: "En relación a JUAN CHAMORRO HOLGUÍN, recibí llamada ayer a final de la mañana de Clara, TS del Centro de Salud de Guadalupe. Después de muchos meses, volvió a su despacho. Juan dice que está sin móvil y no puede estar así. Yo pensaba, en base a estos correos que intercambiamos el mes pasado (leed el hilo por favor) que ya se le había comprado uno. Toni o compañeras de la secc. económica, ¿podríais confirmarme? En caso de no habérsele comprado, Toni, por favor, ¿podríais adquirir uno de características y precio similar al que indicabas? Y sección ecca, porfa, abonad cuando os indique Toni mediante transferencia económica."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2024-04-19','Ana: Tras hablar con Pepi, Jefa Secc. de REGA (924 00 59 64), envío correo a Alberto, Lourdes y María, secc. ecca., aclarando todos los puntos que indicaba en su correo., entre otros: Percibe PRESTACIÓN ECCA A FAVOR DE FAMILIARES. **El ingreso de la Junta corresponde a RENTA EXTREMEÑA GARANTIZADA que le finaliza este mes de abril. En REGA, en base al incremento de la pensión de este año no creen que le vuelva a corresponder, el año pasado le concedieron el mínimo. ·················· María ya ha aclarado el abono indebido de 2 mensualidades a la Empresa de SAD, que ya ha devuelto la empresa. ····················· Pido que calculen asignación para gastos de bolsillo y valore el abrir un cuenta en Unicaja o Banca Puello, pues hay oficinas en el pueblo, de su entidad bancaria no y no hay otra forma para que pueda retirar su asignación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='GARCIA'and apellido2='RAMIREZ'),'2024-04-22','miguel, llega auto denegatorio de la petición de compra e hipoteca por ser innecesario al ser una curatela, y nuestra función meramente asistencial, con lo que el curatelado puede hacer dicha compra voluntariamente. Envío email a Amalia y Alberto: Buenos días, adjunto contestación del juzgado a la petición de autorización que hicimos para la compra e hipoteca de bien del curatelado Antonio Garcia Ramirez. El Auto resuelve que no es necesario y deniega la petición. Por lo tanto el curatelado puede comprar libremente. Parte económica y social tendréis que establecer las condiciones de esa compra (limite de compra e hipoteca que quiera hacer el curatelado), pero ya digo que nuestra función es meramente asistencial. *************************************************** contestación de ALberto: TOD@S: PERSONALMENTE YO NO ENTRARIA EN COMPRAS E HIPOTECAS...DIFICULTA NUESTRAA GESTIÓN Y, SI EN UN MOMENTO DADO LA SITUACIÓN DE ESTA PERSONA VARÍA A PEOR, SERÍA UN PROBLEMA ENORME (DESCONOZCO SUS CARACTERÍSTICAS, SI CONSUME, ETC). DICHO ESTO, SU SITUACIÓN ECO ES EXCELENTE (MOTIVADO X SUS GRANDES INGRESOS Y PK, AL VIVIR CON SUS PADRES, NO TIENE GASTOS). SITUACIÓN 22/04/22: • SALDO: 131.554,89 € (+ 16000€ EN ÚLTIMO AÑO....MOTIVADO X LO YA EXPRESADO). • PENSIÓN: 1.951,78 € X 14 PAGAS. • GASTOS: INFERIOR A 1.000 €/MES (INCLUYE UN REINTEGRO DE 850 €/MES). ________________________________________ *************************************************** contestación de Amalia: Buenos días , si el juzgado ya ha respondido en la línea de que el curatelado no necesita autorización judicial para la compra ,y que puede decidirlo libremente , no hay nada más que se tenga que decidir al respecto. El límite económico de la compra y la hipoteca tendrá que decidirla él y la familia que creo que aportaban una parte , con la valoración de Sección económica . El precio de la vivienda y todos estos datos se los han enviado a Miguel . Tendrá que pasarlo a Alberto para su valoración . Desde la parte social no tenemos nada más que aportar en la compra de una vivienda . La pensión que percibe es de Incapacidad permanente , los ingresos son vitalicios y tiene suficiente ahorros ********************************************************* mi contestación: Hola de nuevo, adjunto el contrato de compra y arras que enviaron la familia para que veáis las condiciones. Desde la parte jurídica, tras el Auto dictado, no vemos inconveniente alguno para que pueda comprar e hipotecar, y por tanto entiendo no nos podemos oponer a la voluntad del curatelado, siempre que pueda permitírselo económicamente *************************************************** Contestación de Alberto: PERFECTO. PUES CONFORME A LA ASISTENCIA QUE SE LE PRESTE, QUE NOS VAYAN INDICANDO EL IMPORTE A ABONAR, CUANDO Y A QUIÉN ABONARLO ******************************************************** envío email a Marisol Marisol Garcia Ramirez >marisolgarram@gmail.com>: Buenos días Marisol, ya tenemos resolución del juzgado acerca de la compra. Quedamos pendiente de nos indiques los importes que necesita José Antonio en la compra, así como que nos facilitéis los datos de la persona de notaria con la que se tramite la compraventa para lo que puedan ir necesitando de la Comisión. Si lo abona él la cantidad debe ser él el único titular.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARCO ANTONIO'and edp.apellido1='BENITEZ'and apellido2='PIN'),'2024-04-22','miguel, llega del juzgado denuncia que interpuso el curatelado en email de Residencia Inclusives >residencia@inclusives.org> Buenos días Adjunto se envía documento del Juzgado a nombre de Marco Antonio Benitez Pin en relación a la denuncia que formulo por la ocupación de su casa en Mérida. Dicha denuncia obra en vuestro poder ya que fue enviada en su dia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2024-04-22','Ana: Envío correo a la atención de Mary, Directora, al correo de la residencia (administracion@residencialaluz.com): "...En relación a GUADALUPE BARRAGÁN GARCÍA, te remito cédula de citación del Juzgado para la revisión de las medidas, a continuación de la cual viene un oficio solicitando también informe. ¿Sería posible que se le acompañase desde el centro a la cita? Si no es posible, la otra opción es abonar un acompañamiento a algún/a Auxiliar de confianza, para lo que tendríais que indicarnos importe y aportar a posteriori la Declaración Jurada de la Auxiliar y añadir en la misma el número de cuenta para abonárselo mediante transferencia. Ya me dices cuando puedas. Aprovecho para recordar la necesidad del informe que te solicité por teléfono para el mismo procedimiento." ····················································································· Respuesta de Mary - Directora Res. (direccion@residencialaluz.com): "La citación que me adjuntas el juzgado ,ya la recibí y envié el informe solicitado. Acompañará un auxiliar y ,al igual que en farmacia o servicios de podología y peluquería, incluso de las revisiones médicas, se emite una factura , así se ha estado haciendo siempre que ha habido algo. No obstante si quieres que se haga de otra forma ya me dices."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-04-22','Ana: Reenvío correo de Miguel, A Jurídico, a Toni y Nieves, Futuex: "...me ha llamado Jose Luis Gilarte de la notaria de Virgen de Guadalupe (Cáceres) para decirme que vaya José Manuel previa cita a preparar el testamento cuando pueda. Lógicamente, y así se lo ha explicado la notaria, aunque desherede a sus hijos, no significa que este testamento puedan impugnarlo algún día sus hijos. Como sabes, de las 3 partes que tiene una herencia: libre disposición, mejora y legítima, ésta última no puedes quitársela a los herederos salvo causa justificada (sentencias judiciales, etc) Por tanto es más que probable que como mínimo los hijos de José Manuel tengan derecho al menos a dicha legítima."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='GARCIA'and apellido2='RAMIREZ'),'2024-04-22','Amalia : Miguel da la respuesta del juzgado con respecto a la compra, no necesita ni la autorización judicial . Envío mi respuesta , y Miguel da la suya de conformidad a la compra . Hola de nuevo, adjunto el contrato de compra y arras que enviaron la familia para que veáis las condiciones. Respuesta Miguel : Desde la parte jurídica, tras el Auto dictado, no vemos inconveniente alguno para que pueda comprar e hipotecar, y por tanto entiendo no nos podemos oponer a la voluntad del curatelado, siempre que pueda permitírselo económicamente. Mi respuesta : El límite económico de la compra y la hipoteca tendrá que decidirla él y la familia que creo que aportaban una parte , con la valoración de Sección económica . El precio de la vivienda y todos estos datos se los han enviado a Miguel . Tendrá que pasarlo a Alberto para su valoración . Desde la parte social no tenemos nada más que aportar en la compra de una vivienda . La pensión que percibe es de Incapacidad permanente , los ingresos son vitalicios y tiene suficiente ahorros . Alberto : TOD@S: PERSONALMENTE YO NO ENTRARIA EN COMPRAS E HIPOTECAS...DIFICULTA NUESTRAA GESTIÓN Y, SI EN UN MOMENTO DADO LA SITUACIÓN DE ESTA PERSONA VARÍA A PEOR, SERÍA UN PROBLEMA ENORME (DESCONOZCO SUS CARACTERÍSTICAS, SI CONSUME, ETC). DICHO ESTO, SU SITUACIÓN ECO ES EXCELENTE (MOTIVADO X SUS GRANDES INGRESOS Y PK, AL VIVIR CON SUS PADRES, NO TIENE GASTOS). SITUACIÓN 22/04/22: SALDO: 131.554,89 € (+ 16000€ EN ÚLTIMO AÑO....MOTIVADO X LO YA EXPRESADO). PENSIÓN: 1.951,78 € X 14 PAGAS. GASTOS: INFERIOR A 1.000 €/MES (INCLUYE UN REINTEGRO DE 850 €/MES).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='BERMEJO'and apellido2='TELLO'),'2024-04-22','Ok, pues entonces no es posible tramitar la herencia porque necesitamos alguien que nos facilite información y documentación. Respuesta de Miguel sobre el tema de la herencia de los padres y hermana de Jesús : Desde mi punto de vista debemos esperar porque tiene dinero suficiente, no hay a quién dirigirnos para recabar documentación y antes o después los demás herederos moverán la herencia porque estarán interesados que se haga.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2024-04-22','-Amalia , queda autorizada la salida al norte de Extremadura en verano , pedirán el reintegro en su fecha.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RICARDO'and edp.apellido1='ROCHA'and apellido2='BARCO'),'2024-04-22','Amalia , escribo a Rafa Camps : Adjunto remito un recibo de la comunidad a nombre de Ricardo Rocha Barco por un importe de 550€ por si sabéis algo de este incremento en la cuota.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='CARVAJAL'and apellido2='CORNEJO'),'2024-04-22','miguel, llamo al jzdo nº2 de Zafra y envío email a la parte social con lo que me comentan: Buenos días, acabo de hablar con el jzdo nº2 de Zafra, y donde digo digo digo Diego…el otro día uno del juzgado (no la que lleva el expte) me dijo que la Autorización de Entrada en Domicilio la pedían desde allí y que entre el viernes y lunes tendrían respuesta, hoy dice la que lleva el expte que no es así… En definitiva que tenemos que pedir nosotros al jzdo Decano Contencioso Administrativo la autorización de entrada en domicilio particular, la cuestión es que no sabemos cuánto van a tardar en contestarnos o si nos darán vista para que expliquemos porqué queremos entrar… Ya le he dicho al juzgado nº2 de Zafra que deberían haberlo solicitado ellos como medida cautelar de protección… Voy a preparar dicho escrito para enviarlo al jzdo Contencioso Administrativo de Badajoz lo antes posible… Por otro lado me dicen que hay dos sentencias antiguas condenatorias penales de Natalia Mejias Millon y Beatriz Mejias, del 2022 q nos comunicaran pronto…se han equivocado y lo han comunicado y les ha sido rechazado a las direcciones de ambas…Nos las van a mandar aunque en el caso de una de ellas, no sé cuál, la multa ha prescrito y la responsabilidad civil no. Una vez nos llegue la sentencia y después la Ejecución abonaremos las cantidades a que se las haya condenado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2024-04-22','El jueves de la semana pasada empezó un curso de jardinería, aquí en plena inclusión con nosotros, pero es que no me ha dado tiempo de contároslo, porque siempre vamos a la carrera, el jueves tuve un curso estuve todo el día fuera, en fin...que hasta hoy no he podido contároslo. Y me dijo Marta que os dijera, que ella hace el curso con la condición de que la beca se la ingresaran a ella, (a otra cuenta que tiene), para que pudiera disponer de ese dinero, sin que vosotros se lo administraseis. A mí, me extrañó que ella pudiera tener otra cuenta, ya que está incapacitada legalmente, pero si ha ido a otro banco, dónde no saben que está incapacitada, ella habrá entregado su dni y listo. Decidme en qué número de cuenta le tienen que ingresar esta beca. Adjunto cartel del curso. Respecto al informe social, a lo largo de esta semana os lo envío.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2024-04-22','Ana: Envío correo a la S. Ecca: "Como veis en el correo de Teresa, Juan no ha podido retirar su asignación. Tiene una autorización permanente semanal desde hace mucho, no sé qué es lo que habrá pasado en el banco. Cuando podáis, por favor, mirad cuál ha sido el problema e intentad solucionarlo lo antes posible por favor. Pongo en copia a Clara, TS del Centro de Salud de Guadalupe, que se lo ha comunicado a Teresa. Clara, comunicarte también que el miércoles, la educadora de Futuex le llevará el nuevo móvil a Juan." ············································· Correo de Toni-Futuex: "Se recoge mañana. Ahora a ver como lo encontramos, está un poco rebelde ultimamente Juan, y rechaza los seguimientos, vamos a ver como va. Te mantendre informada"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GILES'and apellido2='SALAZAR'),'2024-04-23','TERESA Desde Plena Inclusión Cabeza del Buey os ponemos en conocimiento de un nuevo incidente producido entre dos de nuestros residentes de RAIL, no es el primero que se produce y estamos preocupados con los posibles resultados si esta situación se mantiene. Adjunto "Diligencia de inicio por denuncia de infracción penal mediante comparecencia" interpuesta en el Cuartel de la Guardia Civil de Cabeza del Buey, de Rosa Ruiz Romero residente de RAL de Plena Inclusión Cabeza del Buey, por agresión de Ramón Giles Salazar producida el pasado sábado 13 de abril en el parque de la localidad. Rosa Ruiz estuvo acompañada en las diligencias por la directora de residencia M.ª Llorens Aliseda y por la trabajadora social Lola Casallo Ugía. Asimismo Rosa estuvo acompañada en el centro de salud el lunes 15 de abril, donde manifestó la agresión a la médico del Centro de salud de la localidad, que elaboró un parte de lesiones que se entregó en el Cuartel de la Guardia Civil el día de la comparecencia. Resaltar que las disputas entre Ramón y Rosa se están convirtiendo en algo habitual y que alteran de manera importante la convivencia del resto de residentes del centro. Es importante, por ello, hacer lo posible para que el traslado de Ramón a otro centro cerca de su localidad, ya solicitado, se haga efectivo a la mayor brevedad posible.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RICARDO'and edp.apellido1='ROCHA'and apellido2='BARCO'),'2024-04-23','-Amalia , pido y archivo en su expediente los acuerdos de la comunidad de vecino con derrama .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTA'and edp.apellido1='DIAZ'and apellido2='BORREGUERO'),'2024-04-23','Amalia : envío email a Jaime , TS S. Mayores : Buenos días , desde el Juzgado de 1ª Instancia de Montijo se ha iniciado procedimiento de revisión de medidas judiciales a Dña. Justa Diaz Borreguero . Ante la inminente resolución judicial que puede cambiar sustancialmente su situación jurídica se decide desde esta Comisión , tras valoración con el letrado de la Junta que va a llevar este caso , la suspensión del internamiento involuntario en la plaza del Centro Residencial de La Coronada que se le había asignado hasta la emisión del nuevo fallo judicial . Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2024-04-23','TERESA ENVIO PIA FIRMADO Y CONTRATO DE SAD A LA SECCION DE DEPNECIA DE VILLANUEVA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='CARRERA'and apellido2='PEREZ'),'2005-04-21','Solicitada PNC. Ingresa en Aprosuba 9 de Vva de la Serena. Concedida la Autorización. Se solicita autorización judicial para el ingreso en Aprosuba 9 de Villanueva de la Serena','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='CARRERA'and apellido2='PEREZ'),'2024-04-09','TERESA ARCHIVO RESOLUCION DENEGATORIA PENSION DE ORFANDAD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTA'and edp.apellido1='DIAZ'and apellido2='BORREGUERO'),'2024-04-23','Amalia : envio informe a Angel , Maite y Toni . se adjunta informe sobre la situación actual de Justa solicitado por J.M. Escalona .Está elaborado por las compañeras de Futuex que han estado haciendo seguimientos y he aportado datos de contactos tf. de los hijos y la información que por tf me han trasladado éstos . Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2024-04-23','miguel, envío email a la parte social Buenas tardes, al haber fallecido Tomás Esteban Iglesias quien por ley hereda son los padres. La madre falleció estando divorciada, lo sabemos por la escritura de herencia de la abuela que se firmó en Coria. Los padres de se llaman Tomás Esteban Lopez y Margarita Iglesias Sanchez como podeis ver en la partida de nacimiento. Se casaron en 1970 en Coria, el padre nació en 1951 en Cáceres y la madre en 1950 en Cilleros. Parece ser según me ha comentado Chema Tovar que la madre falleció en malas condiciones (creo llevaba mala vida por lo que he oído), creo que falleció en una cuneta. *Según los dni de los hnos: Soledad nació en Carcaboso Tomás y José Manuel en Coria Máxima en Guijo de Coria La cuestión es saber si el padre está o no vivo para poder tramitar la herencia a favor de los hnos de Tomás. Cheva Tovar dice que fue una vez por allí pero no volvió. He hablado con Coria y con Carcaboso y no hay rastro del padre, Tomás Esteban Lopez…El registro civil de Cáceres no me coge el tlfno…No puedo pedir catastro, nota simple de rgtro de propiedad, o certificado de fallecimiento del rgtro civil: sin saber el dni del padre. Por tanto necesito saber: 1.-Si está o no vivo el padre para lo cual debéis preguntar a José Manuel…yo preguntaré a Chema Tovar si puede averiguar algo en Cáceres. 2.-A ver si podéis lograr averiguar el dni del padre. Cualquier duda o lo q se os ocurra decídmelo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2024-04-24','Ana: Correo de ayer de Ana Benavente: "Tras hablar con Mónica, la compañera de los Pisos Tutelados me dice que Mari Ángeles tendría que pagar 392, 73 euros al mes, al percibir menos del SMI. 517,90x14 = 7250,60 :12= 604,21x65% = 392,73 euros mensuales Creo que está muy bien Ana. Ya concretamos" ··········333 Mi respuesta: "Pues siendo así, dado que es su deseo, si tanto el Equipo Técnico del CRR consideran la conveniencia de este cambio de recursos y desde el Equipo de Salud Mental también lo veis apropiado y no creeis que le persjudique en modo alguno este cambio, sino, todo lo contrario, por parte del Gabinete Técnico de la CTAEx no habrá inconveniente alguno. Pongo en copia a Paula, CRR. Por cierto, ¿te encargas de hacerme llegar la solicitud y/o resto de documentos de ingreso? Porque a estas plazas no se accede por Dependencia, no? Lo digo porque M Ángeles sólo tiene Grado I y sería un problema. Te lo digo porque esta semana como sabéis con el curso no llego a mucho y la próxima la he pedido de vacaciones, por tanto no podría hacerlo hasta después. Ya me decís."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2024-04-24','Ana: Correo de María, S. Ecca, con copia a Clara, TS C. Salud - Guadalupe (isabel.garcial@salud-juntaex.es): "Buenos días, Juan Chamorro saco su asignación semanal de 80 € ayer lunes a las 11:16 . He comprobado su cuenta y cada lunes retira su asignación sin problema."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GILES'and apellido2='SALAZAR'),'2024-04-24','TERESA Adjunto envío derivación al Servicio de Cirugía Generar Digestiva. Esta mañana Lola Casallo la trabajadora Social me ha dado una carta de Ramon del Área de salud de Llerena -Zafra, la cual te adjunto . Parece ser que Ramon cuando se va a su casa, su madre (según informe ) o familiares lo llevan a su medico de familia o a los distintos Hospitales del SES , pero aquí al centro ,no aportan ningún tipo de informe de las asistencias sanitarias que se le realizan, y aunque, bien es verdad, que constan en su Historia Clínica , al no tener conocimiento de dichas asistencias, no podemos actuar de forma efectiva. Dicho esto, el paciente ha sido estudiado en el área, tanto por su médico en su día, como por el especialista en Medicina Interna y el equipo de cirugía como consta en su Historia clínica . Se remite de forma Preferente , aun en ausencia de clínica para nueva valoración y reevaluacion, y que por la propia seguridad del paciente y del equipo que lo atiende , se valore de nuevo la decisión de no intervenir por el elevado riesgo del paciente, situación que ha de decidir la de intervenir o no , quien ostente la responsabilidad de la toma de decisiones. Quedo a vuestra disposición para lo que estiméis necesario. ( Esta todo informado) Un saludo Teresa','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='ALBA'and apellido2='GRAGERA'),'2024-04-24','-Amalia : hablo con Reme y se llega a los siguientes acuerdos que reenvio a ctutelar : no se acepta esta petición, la chica que propone Bartolomé es una auxiliar del SAD . Tampoco se acepta la subida de los 120€ . Se va a autorizar una desratización de la casa, pasarán pto. Y va a mirarle un movil y una tarifa baja , el que tiene no funciona y no puede estar incomunicado viviendo solo. Su amigo Alonso , que vive con él , está hospitalizado .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2024-04-24','miguel, tras hablar con la notaria de Coria, me envian la documentación que tienen. La declaración de herderos de la abuela era del 2018 protocolo 1296 del notario Andrés Diego Pacheco, siendo la herencia que se firmó por la tía y nosotros en nombre de los hnos Soledad, José Manuel y Tomás, ya que Máxima fue ratificada por la fundación de Córdoba(Mª José). En dicha declaración se indicó que Margarita la madre de los Esteban Iglesias premurío a los abuelos. Susana de la notaria de Coria me envía email con certif nacimiento de todos, de matrimonio-divorcio de los padres, defunción de la madre Margarita. sggarcia4@despacho.notariado.org, susana not coria 927500772 Adjunto envío la documentación solicitada. El teléfono de su tía, Isabel Iglesias, es 638006339. Saludos Susana ------------------------------------------------- Hablo con Isabel, la tía de los hnos Esteban Iglesias y envío email a Jose Luis Gilarte de notaria de Caceres Jose Luis Gilarte >jlgilarte@despacho.notariado.org> que está preparando la declaración de herederos de Tomás Esteban Iglesias: Buenos días José Luis, adjunto la documentación que me remiten desde la notaria de Coria de cuando se firmó la herencia de la abuela de los hermanos tutelados. En ella verás el certificado de defunción de la madre Margarita Iglesias Sánchez dni 75995980R se divorció del padre Tomás Esteban López del que no logramos encontrar su paradero (lo último que sé es que se fue a Barcelona). Sabemos que nació en Cáceres. Tal vez en Cáceres, en el registro civil aparezca su defunción si es que se ha producido. La notaria de Coria me ha dado el tfno de la tía de los hnos Esteban Iglesias, quien me confirma que el padre los abandonó a ellos y la madre y se fue a Barcelona donde rehízo su vida con otra mujer y del que no sabe nada hace más de 35 años. La madre Margarita murió en Coria en extrañas circunstancias y según dice la tía renunció a la patria potestad de los hijos y nunca se ocupó de ellos. La tía no quiere saber nada de sus sobrinos y tampoco le daría mucha fiabilidad a lo que cuenta porque también tiene dos hijos discapacitados y aunque ella habla con coherencia se nota no está bien. Dime cuándo puedas qué se puede hacer. --------------------------------------------------- Envío email a la parte social: Hola compis, lo último que he averiguado del padre es que se fue a Barcelona, según me ha comentado su tía, la cual no quiere saber nada de sus sobrinos. Os adjunto la documentación que me ha enviado la notaria de Coria y el email que envio a la notaria de Cáceres que iban a preparar la declaración de herederos. Estoy a la espera de q la notaria me confirme si se va a poder o no preparar la declaración de herederos. Voy mientras pidiendo al registro civil de Cáceres el certificado de defunción de este hombre por si hubiese fallecido y el registro tuviese constancia. Cualquier duda lo hablamos. ---------------------------------------------------- Pongo a la firma oficio dirigido al Ayto de Coria que me dijeron que si lo acredito me pueden facilitar el dni del padre. Pongo oficio al registro civil de Cáceres porque al ser el lugar donde nació, caso de que haya fallecido tendrán el certificado de defunción del padre. (lo pongo a la firma)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA'and edp.apellido1='GONZALEZ'and apellido2='NARANJO'),'2024-04-24','TERESA Comunicamos que la tutelada JUANA GONZÁLEZ NARANJO, falleció ayer a las 20.00h de la tarde en el hospital Tierra de Barros de Almendralejo. Será enterrada hoy día 24 de Abril a las 17.00h. El centro contactó con el único familiar, su primo Jose María González, para informarle del fallecimiento. Será enterrada en el cementerio de Ribera del Fresno.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2024-04-24','Amalia : escribo a la TS del Ctro. Pto. : He hablado con J.R.J. me dice que ha sido trasladado al M. 6 porque ha dado positivo en drogas. Me ha pedido que se le de dinero extra para pagar deudas contraídas , no podemos abonar este tipo de deudas . De su reintegro mensual que lo abone como considere. Saludos. marga.TS.16918 >marga.TS.16918@dgip.mir.es> ​ -------------------------------------------------- Marga , me pasa información de juicios pendientes : El jurista me ha pasado esta información de Jonatan Si necesitáis más datos, decidme por favor Un saludo Marga De: Miguel Angel Camacho González-Mellado Enviado el: miércoles, 24 de abril de 2024 11:28 Para: marga.TS.16918 >marga.TS.16918@dgip.mir.es> Asunto: INFORMACION DE JONATAN RAMIREZ JUAREZ Buenos días Para mantener informado a las personas interesadas en el seguimiento del penado Jonatan Ramirez Juarez Decir que tiene 2 juicios pendientes en JUNIO 2024 Citaciones Tribunal Causa Fecha J.PENAL BADAJOZ 2 P. Abreviado/283/2023 J.PENAL BADAJOZ 2 28/06/2024 Acusado J.PENAL BADAJOZ 2 P. Abreviado/291/2023 J.PENAL BADAJOZ 2 28/06/2024 Si Acusado Que actualmente cumple Ejecutoria 3/2022 J.PENAL MERIDA 1 Violencia fisic C PN 0 12 1 (años , meses, días ) Ejecutoria 401/2022 J.PENAL MERIDA 2 Quebrant cond C PN 0 9 0 Ejecutoria 401/2022 J.PENAL MERIDA 2 Amenazas dl C PN 0 3 0 Ejecutoria 693/2021 J.PENAL BADAJOZ 1 Hurto C PN 0 6 0 ( SOLO EN ESTA TIENE UNA R.C. DE 6.041,28 €) Ejecutoria 38/2023 J.I. BADAJOZ 4 Hurto T PN 0 0 15','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA FE'and edp.apellido1='GUISADO'and apellido2='GUISADO'),'2024-04-15','Informamos de la renuncia que ha realizado María del Mar auxiliar quien desempeñaba el rol de ayuda a domicilio para Marife Guisado Guisado. María del Mar (que es la misma auxiliar que lleva a Rafael Davila) notificó su decisión de renunciar el pasado jueves 11 de abril, alegando que en repetidas ocasiones se le negó la entrada al domicilio de Marife bajo el argumento de haber causado daños en la cocina. Esta situación se suma a varios desacuerdos previos relacionados con el gasto de productos de limpieza y el deterioro de utensilios. Es una pena, porque ellas solian rechazar a todas las auxiliares y a esta la habian aceptado... pero María del Mar ha optado por poner fin a su relación laboral con el mencionado domicilio. El viernes 12 de abril, se mantuvo una conversación con Pedro, de la empresa a atencion a la dependencia extremeña, encargado de la ubicación de profesionales de ayuda a domicilio, con el propósito de iniciar el proceso correspondiente para encontrar un reemplazo adecuado. Pedro ha manifestado la necesidad de consultar con el equipo y se ha comprometido a notificarnos tan pronto como se disponga de un profesional disponible para ocupar el puesto vacante. La verdad que va a ser dificil, pero bueno veremos...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2024-04-15','TERESA Marta ha solicitado participar en un curso de jardinería organizado por Plena Inclusión, el cual se llevará a cabo desde el 19 de abril hasta el 31 de julio. El horario establecido para dicho curso será de 9:00 a 14:00 horas. Al completar el curso, Marta recibirá un título de certificación, así como una compensación económica de 300 euros, los cuales tiene la intención de destinar como gastos de bolsillo para el mes de julio. Desde el equipo, consideramos que esta iniciativa podría resultar beneficiosa tanto como incentivo para Marta en su continuo proceso de formación y desarrollo personal, así como para fortalecer el vínculo y la confianza mutua en nuestra relación. Aspiramos a que esta colaboración no sea percibida como un enfrentamiento, sino como un apoyo para su crecimiento y bienestar. Además, Marta ha expresado su interés en adquirir un teléfono nuevo. Tambien estamos pendiente de que faciliten el numero de cuenta, para que valoreis el pago, de algo que nos indico la madre que habia roto... de algun desperfecto que ha generado, que no es la primera vez, no obstante cuando tengamos todo lo psamos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINA AMELIA'and edp.apellido1='TORRADO'and apellido2='LEON'),'2024-04-24','TS de la R. M . CASer .Elisabeth - Teléfono: 693 754 274','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2024-04-22','Ana: Correo de Paula, TO - CRR: "te comento respecto a M. Angeles: son pisos supervisados en su localidad Valverde del Fresno, en Cáceres. La Trabajadora Social de los pisos se llama Mónica y su teléfono es el 678967103. Se contactó con ella y confirma que M. Angeles puede acceder a los pisos, tal y como tú adelantabas por sus circunstancias. Como M. Angeles quiere y hay plaza, sugerimos que podáis contactar directamente"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2024-04-25','Ana: Respondo al correo de Consuelo, Psicóloga - Coordinadora del Centro de Acogida de "Personas Sin Hogar" de Cáritas (C/. Fabián de Monroy nº2, bajo) - (cizquierdo@caritasplasencia.org) al ctutelar@: "Aquí no ha llegado ningún presupuesto previo de tratamiento bucodental relativo a Ángel Félix Maillo Santibáñez. Si ha acudido a alguna clínica dental y disponéis de uno, por favor, enviadlo a este mismo correo a la Atención de la Sección Económica, quién estudiará si es viable, según su capacidad económica, y en tal caso se podrá abonar mediante transferencia bancaria a la propia clínica para que puedan hacerle el tratamiento. Por cierto, ayudas no hay para su perfil. Es él mismo quien asumiría el gasto, si puede asumirlo." ················································ Nuevo correo de Consuelo al ctutelar@: "Buenos días, remitimos el presupuesto de Angel Félix Maillo. Si llamáis a la clínica para que os pasen el número de cuenta, podrías hacer la transferencia y el empezar a pedirse citas. Comunicarnos, por favor, la decisión que toméis. El está , ahora que puede, muy interesado en arreglarse la dentadura."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2024-04-25','Ana: Correo de Sheila, Directora CRR: "Me pongo en contacto contigo por la persona usuaria ANTONIA CANELADA DEL RIO. Tras valoración por Equipo Técnico del CRR de Cáceres, se considera la necesidad de solicitar la revisión de grado PIA por empeoramiento con el fin de que Antonia se traslade a una residencia de mayores para cubrir sus necesidades asistenciales." ····················· Mi respuesta: "Aprovecho antes de irme al curso para contestarte. De acuerdo, no hay inconveniente, pero como ya sabes, necesitamos Informes Médicos que justifiquen ese empeoramiento más el anexo "Informe de Salud" del Modelo de Dependencia. Cuando nos lo habéis llegar preparo la solicitud de la revisión."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2024-04-25','Ana: envío correo a Belén, TA HSPA (belen.plasencia@salud-juntaex.es): "Adjunto: - Solicitud de la T3 debidamente firmada y sellada por la Representante Legal - DNI de Julia - DNI Presidenta CTAEx - Decreto Nombramiento - Resolución Delegación de Funciones - Testimonio de Auto de Nombramiento - Testimonio de Aceptación del cargo Ante cualquier cuestión, no dudéis en volver a contactar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REGINA'and edp.apellido1='REINA'and apellido2='LARA'),'2024-04-25','-LLama Elvira , Educadora Social del CEE Los Angeles ( se llevaba a Regina el año pasado ) Discrepa de la opinión de que la niña pase los fines de semana con 3 familias que no conoce y no da tanta importancia a que obtenga el titulo de FP Basica de agrojardinería . La invito a que tengan una reunión en el centro multiprofesional y aclaren cual sería la mejor decisión para la chica .','2');
