insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2024-04-25','Ana: correo de ESM-CC (equiposaludmental.caceres@salud-juntaex.es): "Buenos días, adjunto remito informe de seguimiento de la consulta de Psiquiatría con la doctora Donoso el pasado 04/04/2024 así como fecha de la próxima consulta de revisión del paciente Francisco Cacho Garrido."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='BARROS'and apellido2='CORDERO'),'2024-04-26','Ana: Envío correo a Marisa, Directora Residencia, y Ana, TS SSASB: "En relación a Jose Antonio Barros Cordero, a petición de Abogacía General de la Junta de Extremadura, te solicitamos INFORME SOCIAL actualizado para proceder a la revisión de las medidas judiciales de apoyo. Pongo en copia a Marisa, de la Residencia, para que esté al corriente. Próximamente se citará a Juan Antonio para la revisión." ······························ Les envío nuevo correo: "Perdonad, tenía otro correo con la Providencia de Citación. ¿Podríais organizar el acompañamiento? Si fuera necesario el abono del mismo, sólo tenéis que indicar a la Sección Económica el coste y remitir después la Declaración Jurada de la persona que le haya acompañado con el número de cuenta. Se abonaría mediante transferencia bancaria."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='MIRANDA'and apellido2='ROSADO'),'2024-04-26','-ESTRELLA/AMALIA: OK A SUBIDA REINTEGRO TUTELADA....PASARÍA A 310 €/QUINCENA (ANTERIOR 280 €/QUINCENA). HA PASADO DE ABONAR UNA MEDIA DE 50 €/MES X CONSUMOS A MÁS DE 150 €/MES.....FACTURA ÚLTIMO BIMESTRE 424,81 €.------- LO HE HABLADO CON CATALINA , UTILIZA BRASERO DE 2 FASES LA ANIMO A COMPRAR UN RADIADOR DE ACEITE MÁS ECONÓMICO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2024-04-26','Ana: Reenvío a Alberto, correo de Margarita, TS SSASB: "Hola Ana, buenos días: te escribo de nuevo en relación al usuario D. MATEO RUANO MORENO DNI 007419953S que se encuentra en la Residencia "Balcón de Extremadura" de Montánchez ocupando plaza de válido y que como tenía retenido unas cuantías económicas, tratamos de que de su pensión mensual pueda abonar el pago de la plaza, según certificado del INSS, en este año tiene una pensión de 1.875,46€/mes, con 14 pagas, le correspondería abonar el 75% de esta cantidad, por lo que se requiere que nos enviéis desde la sección económica de vuestro servicio la situación real del usuario para poder aplicar la cuota mensual a pagar en el centro,"','2');
