insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2024-04-26','Ana: Se acepta presupuesto para TRATAMIENTO BUCODENTAL.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='MEGIAS'and apellido2='MILLON'),'2024-04-29','TERESA Quería poner en conocimiento de la comisión tutelar que ayer ha ingresado un varón de 20 años ( A .P T) que proviene viene de otro centro con medias cautelares por agresión a una chica con la que anteriormente mantuvo una relación sentimental. Esta mañana acuden a mi despacho Natalia y A. comentándome que son pareja y que quieren iniciar una relación sentimental. En primer lugar, les comentamos que se acaban de conocer y primero deberían ser amigos y ver si caen bien, son afines, etc y que en el caso de que deseen ser pareja citaríamos a ambas familias para que fuesen conocedoras y consentidoras de la situación, teniendo en cuenta que el viene con medidas cautelares de otro centro y que Natalia presento una denuncia contra un residente con el que también mantuvo una relación sentimental. Entiendo que de forma inmediata debemos tomar medidas de reducción de daños relacionados con posibles embarazos no deseables o posibles contagios de enfermedades de trasmisión sexual. La reducción pasa por que dispongan de métodos barrera (preservativos), que se encuentren gestionados por profesionales a disposición de ellos. Como centro nos preocupa la situación, con los antecedentes que ambos presentan y que entendemos que debemos trasladar a estancias superiores debido a las posibles consecuencias que la combinación de ambos perfiles pueda presentar juntos en este centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GILES'and apellido2='SALAZAR'),'2024-04-29','Desde Plena Inclusión Cabeza del Buey os ponemos en conocimiento de un nuevo incidente producido entre dos de nuestros residentes de RAIL, no es el primero que se produce y estamos preocupados con los posibles resultados si esta situación se mantiene. Adjunto "Diligencia de inicio por denuncia de infracción penal mediante comparecencia" interpuesta en el Cuartel de la Guardia Civil de Cabeza del Buey, de Rosa Ruiz Romero residente de RAL de Plena Inclusión Cabeza del Buey, por agresión de Ramón Giles Salazar producida el pasado sábado 13 de abril en el parque de la localidad. Rosa Ruiz estuvo acompañada en las diligencias por la directora de residencia M.ª Llorens Aliseda y por la trabajadora social Lola Casallo Ugía. Asimismo Rosa estuvo acompañada en el centro de salud el lunes 15 de abril, donde manifestó la agresión a la médico del Centro de salud de la localidad, que elaboró un parte de lesiones que se entregó en el Cuartel de la Guardia Civil el día de la comparecencia. Resaltar que las disputas entre Ramón y Rosa se están convirtiendo en algo habitual y que alteran de manera importante la convivencia del resto de residentes del centro. Es importante, por ello, hacer lo posible para que el traslado de Ramón a otro centro cerca de su localidad, ya solicitado, se haga efectivo a la mayor brevedad posible.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2024-04-29','TERESA DE NUEVO HA VUELTO A AGREDIR ARCHIVO INFORME DE ALTA DEL HOSPITAL Y ESCRITO A FISCALIA ESTA PENDIENTE LE ASIGNEN PLAZA RESIDENCIAL','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2024-04-29','Maite: Julia ha llamado para preguntar cuando se va al centro( plaza T3). He hablado con Belén , trabajadora social del hopital San Pedro de Alcántara (Ext 24012) para informarme. Están a la espera de que se produzca una vacante para hacer el traslado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='CARVAJAL'and apellido2='CORNEJO'),'2024-04-29','miguel, envío email a la parte social y a Angel con la llamada que recibo de Tomás Carvajal: Hola, Tomás me ha llamado 924098058, para decirme que le tiene manía a Caramiñana, el Ts, y que lo sabe Mariví (la concejala) y que llama para decir que hay que anular el judicio por falta de testigos…(Que yo sepa no hay ningún juicio, salvo el internamiento que tenemos en marcha). Que le pregunte a la Teresa que ella sabe que juicio y que le diga que no tiene para comer hasta el jueves… Por ahora, como sabéis no podemos hacer nada hasta que el juzgado dicte la orden de alejamiento. Mañana hablaré con el Jzdo Decano Contencioso Administrativo a ver si pueden agilizar el trámite.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA REMEDIOS'and edp.apellido1='LOZANO'and apellido2='MUÑOZ'),'2024-04-25','miguel, recibimos por carta pantallazo del juzgado donde pone motivo devolución: "debe presentarse como demanda iniciadora de expte" *********************************************************** Presentamos de nuevo vía lexnet solicitud de transmisión de vehículo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2024-04-30','miguel, Juan Carlos envía por tramita solicitud al rgtro civil de Cáceres el certificado de defunción del padre. Y envía al Ayto de Coria solicitud del número del dni, a efectos de que podamos localizar si sigue vivo o no el padre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALMUDENA'and edp.apellido1='CORREYERO'and apellido2='PAREJO'),'2024-04-29','Amalia : Almudena ya está organizado el traslado para el próximo lunes 29 de abril al CRR Plasencia . Estamos dándole apoyo para el traslado, el cual se hará mediante taxi ya que tiene muchas pertenencias y tiene dinero suficiente en el centro para hacer frente a esto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA REYES'and edp.apellido1='TARDIO'and apellido2='NUÑEZ'),'2024-04-30','TERESA RECIBO LLAMADA DE LA RESIDENCIA INFORMANDO QUE REYES ESTA INGRESADA CON NEUMONIA EN EL HOSPITAL DE LLERENA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2024-04-30','miguel, me llama la sobrina, Josefa Perez Montalban, 661268500, para preguntar si puede firmar su tía un testamento. Le confirmo que según la sentencia de incapacitación no hay inconveniente que lo haga siempre que el notario no ponga inconveniente. Lo normal es que pida informe médico. Me dice que el notario de talarrubias donde va a firmar le pide dichos informes médicos. Le digo que si necesita el notario sentencia de incapacitación me llame para enviarsela por email','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='CARRERA'and apellido2='PEREZ'),'2024-04-30','TERESA Roberto demanda con frecuencia querer irse a Zafra. Tenemos información por familiares (tio Julian Telf. 615 987 069 y prima Mª Ángeles 636 529 619) que en el domicilio familiar, solo queda su hermano Miguel quien tiene un problema importante de adicción a las drogas, de hecho está vendiendo todo el mobiliario para su consumo. La actitud de otros familiares es muy positiva con respecto a Roberto pero les da miedo que cuando vaya a Zafra se junte con su hermano. Roberto quiere que se le traslade a la residencia de Plena Inclusión de Zafra y así poder estar cerca de su familia. Es una demanda reiterada por su parte y que tendréis que valorar si es viable. Para ello os mando los teléfonos de los familiares por si queréis indagar más sobre la conveniencia o no.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='GIRALDO'and apellido2='BECERRA'),'2024-04-29','miguel, Tere me reenvía la denuncia de la vecina. Él está en la UHB de Llerena y le van a dar el alta porque el psiquiatra (me comenta Maite) no cree que esté desestabilizado a nivel clínico. El problema es que tiene amenazada a la vecina y su familia. Me pide Tere lo internemos y me envía informe social, faltaría el Médico, que me comenta que lo deja solicitado. Lógicamente no podemos pedir dicho internamiento hasta que tenga el alta hospitalaria. Mientras la denuncia interpuesta por la vecina seguirá su trámites y quedamos pendiente que el juzgado nos comunicará dicho juicio penal','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2024-04-30','miguel, llamo a juan pablo serrano muñoz Tfno/Fax: 924 247335 Móvil: 646740735, email 3116@icaba.com; quien me confirma lo que ya me dijo: que no se puede desahuciar porque no hay convenio regulador del arbitraje, y portanto cualquier abogado podría oponerse y ganarlo, con la consiguiente nueva imposición de costas. Le comento que sigo pendiente de noticias del abogado Jorge Calvo, que quedó en enviar la resolución de la reclamación a su seguro de responsabilidad civil y del cual no hemos obtenido respuesta, ni tampoco nos ha enviado minuta de honorarios correctamente redactada (procedimientos, importes, conceptos) por lo que no hemos podido abonarla. Si algun dia nos llama le pediremos nos acredite la resolución del expte de incidencia al seguro y caso de ser desestimatorio, nos aporte correctamente esos honorarios.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2024-04-30','miguel, envío email a Carlos Arjona, email juridico@liberalyarjona.com Buenos días Carlos, soy compañero de Angel Marin de la Comisión Tutelar de Adultos. El otro día me dieron tu email para ponerme en contacto contigo para que te envíe la documentación para que estudies, para solicitarte presupuesto para tramitar la aprobación de herencia de una de las herederas (curatelada por esta Ctaex, Soledad Esteban Iglesias). La herencia de la abuela que adjunto verás que heredaron dos hijas Isabel que sigue en vida y los herederos de la otra hija, Margarita, cuyos 4 hijos eran Tomás (antiguo tutelado de esta Ctaex y hoy está fallecido en Cáceres, posteriormente a la ratificación de la herencia que adjunto), José Manuel (que reside en Villanueva de la Serena) y Soledad que reside en Cáceres capital. Al ser competente el juzgado de residencia de la persona curatelada necesitaríamos entiendo abogado y procurador de Cáceres y de Villanueva de la Serena. Dígame si es posible unificar a ambos hermanos Soledad y José Manuel en su persona o por la distancia no merece por aumento del coste en honorarios. Quedo pendiente me remita presupuesto y quedo a su disposición para aclarar cualquier duda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='LEAL'and apellido2='BENITO'),'2024-04-30','miguel, envío email de Juan Pablo Serrano Muñoz (abogado) JUAN PABLO SERRANO MUÑOZ >3116@icaba.com>, para que tramite aprobación judicial de herencia: Buenas tardes Juan Pablo, conforme hemos hablado por teléfono te adjunto documentación para que puedas estudiar y preparar solicitud judicial de aprobación de la herencia de los padres y hermana de la tutelada por la Ctaex, Doña Sonia Valcarcel Vidal, para lo cual te adjunto testimonio de incapacitación, nombramiento y aceptación del cargo. Ella se encuentra residiendo actualmente en el Centro Residencial de Caser de Olivenza. Por favor, estudia el caso y envíame cuando puedas presupuesto junto con los datos del procurador/a que vaya a actuar en el procedimiento. Muy agradecido por todo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='RAMOS'and apellido2='BLANCO'),'2024-04-30','Buenas , acabo de llegar a la oficina , la visita ha sido intensa pero bien. Alberto ha salido del Ctro. penitenciario donde ha estado 9 meses , está en condicional ,lleva la pulsera en el pie y tiene obligatoriamente que estar desde las 22.00h a las 10.00 en casa del padre . Ha estado presente en la reunión su padre. Sin consumo de drogas durante esos meses . Ahora pasa allí todo el día , está en Pza. Virgen de Botoa nº4,2ºA de Badajoz. Ha venido Teresa de Futuex , lo voy a incluir al programa de seguimientos . Hemos tratado tema ocio , estudios , trabajo , revisión de sentencia .. Se concretan próximos seguimientos, en mayo tiene cita en ECA para control del consumo drogas , psiquiatría y revisión CADEX . Quiere renovar el carnet de conducir , se valorará en unos meses , de momento se va a postponer. Solicita subida de la asignación de 120€ a la semana a 150€ , con el compromiso de dejar 10€ semanales al padre para que a final de mes pueda comprar algo que le haga falta. Solicita extra para ropa , calzado y un portátil . He pensado que podría adelantarse el extra de verano y así se lo he dicho . Quedo pte. recibir ptos. No habrá más extras hasta diciembre . Cuando lleguen lo pasaré a Sección eco para valoración. En estos meses hay que hace un seguimiento más intenso , no puede consumir , o volvería al Ctro. penitenciario . Desde Futuex se van a realizar actividades de búsqueda de empleo ( SEPE , Fundación Sorapán, bolsa de trabajo del Ayto ..) Actividades de ocio y tiempo libre , le gusta la música ,pintura .. Se le va a acompañar a ECA y ESM ..','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2024-05-02','miguel, mandamos por lexnet contestación-alegaciones al jzdo de Sevilla nº6, para el procedimiento de revisión de medidas de apoyo, no oponiendonos a que asuma el cargo de tutor su hno.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2024-04-30','miguel, envío email a Buenos días Carlos,juridico@liberalyarjona.com soy compañero de Angel Marin de la Comisión Tutelar de Adultos. El otro día me dieron tu email para ponerme en contacto contigo para que te envíe la documentación para que estudies, para solicitarte presupuesto para tramitar la aprobación de herencia de una de las herederas (curatelada por esta Ctaex, Soledad Esteban Iglesias). La herencia de la abuela que adjunto verás que heredaron dos hijas Isabel que sigue en vida y los herederos de la otra hija, Margarita, cuyos 4 hijos eran Tomás (antiguo tutelado de esta Ctaex y hoy está fallecido en Cáceres, posteriormente a la ratificación de la herencia que adjunto), José Manuel (que reside en Villanueva de la Serena) y Soledad que reside en Cáceres capital. Al ser competente el juzgado de residencia de la persona curatelada necesitaríamos entiendo abogado y procurador de Cáceres y de Villanueva de la Serena. Dígame si es posible unificar a ambos hermanos Soledad y José Manuel en su persona o por la distancia no merece por aumento del coste en honorarios. Quedo pendiente me remita presupuesto y quedo a su disposición para aclarar cualquier duda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2024-05-02','miguel, email de Alberto: MIGUEL: EL SALDO HOY 02/05/2024 ES DE 5.000 € APROX. (DEBE TENER ALGUNA RETENCIÓN QUE NO FIGURA EN LOS MOVIMIENTOS. SITUACIÓN ECO: A PESAR DE PAGAR UNA ALQUILER, LA SITUACIÓN ES CORRECTA. PERO HAY QUE TENER EN CUENTA QUE APENAS AHORRA DINERO Y QUE, EN CASO DE TENER QUE ASUMIR UN GASTO EXTRAORDINARIO ELEVADO, SE RESENTIRÍA. MIGUEL: SI ME PIDES ESA INFORMACIÓN PARA EL TEMA DE LA HERENCIA...SI ESTA ES POSITIVA Y LE MERECE LA PENA ACEPTARLA...CREO QUE PODRÍA PERMITÍRSE ABONAR UNA GESTORÍA (SEGÚN EL PRESUPUESTO, CLARO). TERE: HEMOS AVERIGUADO ALGO SOBRE ESTO???...C.ELECTRONICO DE 02/04/2024: ESTÁ ABONANDO IBERDROLA X OTRA VIVIENDA QUE NO ES LA DE ALQUILER (C/ Carrera, 13 de Monterrubio de la Serena (Badajoz): YA SE SOLICITÓ BAJA EN 05/2019...PERO SE SIGUE ABONANDO...ESTRELLA: GESTIONA DE NUEVO LA BAJA, XFA...SALVO QUE TERE INDIQUE LO CONTRARIO ------------------------------------------------------- mi contestación:','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VALLE'and apellido2='SIMON'),'2024-05-03','TERESA Estamos con la gestión de la plaza residencial para Jose Mª y resulta que no esta empadronado en zafra. En la próxima visita acompañarle a hacer esta gestión al ayuntamiento. saludos enviar empadronamiento a seccioncentros.badajoz@salud-juntaex.es jose Mª 20542','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2024-05-03','Amalia : Hablo con Jose Vicente , tf 613816265 , quiere que se le suba la asignación mensual. Se le dan 450€ de los 517€ que percibe por PNC . El resto se le guarda para cubrir el recibo del TF. EL S. Decesos se lo abona el padre . He solicitado a S. eco que le suban aunque sea 20€ más para que le puedan quedar 70€ para gastos de tabaco . 400€ abona por el centro donde está . Su intención es permanecer allí. Ha buscado abogado de oficio , ya han contactado con Angel para remover la curatela y que la asuma su padre . Voy a indicar a Futuex que le haga alguna visita , aunque no es el pérfil para hacer seguimiento . Sobre todo con la idea de que hagan seguimiento con el ESM . Paso el caso a la zona de Tere para seguimiento . Cubiertas necesidades de residencia y manutención y gastos de bolsillo ( aunque pide más )','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='GARCIA'and apellido2='RAMIREZ'),'2024-05-02','miguel, la hermana me envía email con datos de las condiciones de préstamo de Ibercaja y Caja Rural: Buenos días, Miguel Tal y cómo hablamos la semana pasada te envío los datos solicitados para avanzar con la operación de la compra del Piso de Jose Antonio Garcia. Adjunto documentación. Precio vivienda 120.000 € En principio Jose Antonio tenía pensado entregar 80.000 € y solicitar 50.000 € de préstamos hipotecario . A ver las condiciones económicas que ofrecen los dos bancos a los que hemos solicitado información y observar que los tipos de interés que ofrecen no se encuentra en el mejor momentos, hemos pensado que mejor sería entregar 100.000 € y pedir préstamo de 30.000€ . De este modo queda en su cuenta otros 30.000 € para cubrir imprevistos y siempre con la premisa de continuar ahorrando. -------------------------------------------------------- Reenvío a parte eco y social: Buenos días adjunto propuesta de compra y préstamo que nos envía la hermana del curatelado José Antonio. Corresponde al expte donde el juzgado contestó: “A la vista de lo expuesto, la autorización que se interesa se reputa innecesaria por cuanto la Comisión Tutelar no ostenta la representación del curatelado, y por ende no le es de aplicación lo dispuesto en el ART. 287 del CC, que lo es de forma exclusiva a los curadores representativos, siendo así que la función de aquella es de “asistencia al curatelado” en la realización de los actos relacionados en el precepto citado, en este caso, asistencia en la celebración del contrato de compraventa y en la del préstamo hipotecario” Queda pendiente la hermana que le confirmemos si estaríamos de acuerdo en que aportase 100.000€ en la compra y pidiese 30.000€ en el préstamo. -----------------------------------------------------------','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='GARCIA'and apellido2='RAMIREZ'),'2024-05-03','miguel, envío nuevo email a la parte eco y social: Buenos días, añadir a mi email de ayer, que entiendo que debemos recoger en documento a firmar por José Antonio, donde redactemos las condiciones de la compra y el préstamo, para lo cual necesito me digáis si a aparte de dar o no el ok a que aporte 100000€ de la cuenta y pida unos 30.000€, la Comisión tiene que decidir qué gastos asociados a la misma estamos de acuerdo que se hagan: seguro de vida, seguro de vivienda, comisiones de mantenimiento de cuenta si lo abre en Ibercaja, amueblar la nueva vivienda, otros, etc. Si queréis el martes a primera hora nos reunimos y dejamos decidido este asunto. --------------------------------------------------------- Envío email a la hna, Marisol marisolgarram@gmail.com: Buenos días Marisol, los gastos de tramitación que adjuntas quedan claro, pero qué otros gastos hay que afrontar? Hay que dejar detallado en un documento a firmar por José Antonio todos los gastos de compra y préstamo, donde luego no se pidan más cantidades. Por ejemplo, gastos de arreglos o de amueblar la nueva vivienda, los gastos bancarios (tasaciones, seguros, etc…) Necesito un desglose de los mismos -------------------------------------------------- Contestación de Alberto: En relación con la posible compra de una vivienda que, en principio, podría alcanzar un valor de 120.000 €, y con la formalización de una hipoteca (previsiblemente 30.000 € aprox.), que afectaría la vida del tutelado, a todos los niveles y durante muchos años, entiendo que hemos tenido en cuenta los antecedentes que dieron lugar a la incapacitación que en su momento se decretó para esta persona: Cualquier cálculo que se realice a nivel económico, cualquier proyección que se haga y que tenga extensión en el tiempo queda totalmente invalidada en caso de que esta persona recaiga en los problemas incluidos en la sentencia inicial de incapacitación. Desconozco las herramientas o confianza en familia (aunque parece que el informe social de 01/2023 si tiene esa confianza), u otros recursos de los que dispongamos en la CTAEX, como para tener el grado de seguridad suficiente que nos permita apoyar sin reservas esta operación que va a afectar durante muchos años a esta persona. Po experiencias anteriores sabemos de los problemas tan graves que, entre otros, a nivel económico, tienen personas con consumos. Situación ECO actual: muy positiva: • SALDO: 130.000 € aprox. • Previsión muy positiva debido a que, además de tener una buena pensión (1.951,78 €/mes x 14)...NO tiene ningún gasto asociado/domiciliado a su CCC...EXCEPTO sus reintegros (850 €/mes) y poco mas (pago habilitado...). Los datos iniciales sobre los que nos basamos para valorar la cuestión relacionada con la HIPOTECA (lo que la hermana del tutelado le ha remitido a MIGUEL de la entidad financiera IBERCAJA - no dispongo de datos de la otra entidad CAJA RURAL) son: • Importe inicial: 40.000 € • Plazo: 96 cuotas (8 años). • Interés fijo: 7,5 % • Cuota: 555 €/mes aprox. En mi opinión, en condiciones normales y si la situación ECO se mantiene como hasta ahora (incluyendo, por supuesto, el pago de vivienda e hipoteca), no debería haber ningún problema para asumir este gasto. Otros gastos como seguro vida/vivienda: también deberían de poder asumirse sin problema. Los gastos "logicos" asociados a la decoración/muebles de la vivienda. En relación con esto último MIGUEL/AMALIA: alguien había comentado que la familia iba a aportar algo para esta cuestión ... eso se mantiene??? MIGUEL: ASUMIMOS QUE LOS IMPORTES INCLUIDOS EN LA TABLA ANTERIOR, SON AQUELLOS QUE SE ESTABLECERÁN EN LAS ESCRITURAS (pendientes de el importe definitivo de la provisión de fondos y de los gastos reales) MIGUEL: ENTENDEMOS QUE TODAS LAS CONDICIONES Y CLÁUSULAS QUE SE INCLUYAN EN LAS ESCRITURAS Y QUE CONLLEVEN CUALQUIER TIPO DE OBLIGACIÓN PARA EL TUTELADO SERÁN REVISADAS X LA CTAEX. ________________________________________ mi contestación a Alberto y parte social: Hola Alberto, en relación a lo que comentas, entiendo que con la resolución judicial y un documento que redactemos en la Ctaex muy exhautivo de gastos, debería bastar para que la Comisión cumpla con su parte. En principio creo que con ello sería suficiente y si en un futuro deja de pagar, pues como a cualquier persona le embargarían y llegado el caso le ejecutarían la vivienda, lo cual se asemeja a multitudes de casos de la Ctaex, y ese toro ya lo torearíamos… Creo que debemos pensar en presente para lo cual, que nos firme un documento y para ello he enviado este email a la hermana: "Buenos días Marisol, los gastos de tramitación que adjuntas quedan claro, pero qué otros gastos hay que afrontar? Hay que dejar detallado en un documento a firmar por José Antonio todos los gastos de compra y préstamo, donde luego no se pidan más cantidades. Por ejemplo, gastos de arreglos o de amueblar la nueva vivienda, los gastos bancarios (tasaciones, seguros, etc…) Necesito un desglose de los mismos.”','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIO'and edp.apellido1='GUISADO'and apellido2='GUISADO'),'2024-05-03','TERESA Os informo que esta tarde, sobre las 15:00, recogeré a Eugenio en la Residencia para ir a visitar el Aeropuerto de Badajoz, y merendar fuera. Está muy ilusionado con ver "los aviones" como él dice, y creo que puede ser motivador, realizar actividades que puedan sacarle de la rutina y hacerle los días aquí más llevaderos, ya que echa bastante de menos a su grupo, y su Centro de Cabeza del Buey.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2024-05-03','-Amalia , escribo a Alberto , Tere y Toni Futuex . Plan de intervención terminado y pasa el caso a la zona de Tere . Te comento sobre este caso que pasará ya a la zona de Don Benito. Salió del Ctro. Penitenciario de Badajoz en marzo , estuvo en el de Cáceres y el ultimo mes pidió traslado al de Badajoz . Creo que pudo ser porque dejaría deudas en el de CC , lo que no entiendo es como se lo concedieron, lo alejaron de su domicilio y hubo que pagar más de taxi en el traslado a su casa . Se le concedió un extra al salir para que se comprase un movil y se pagase el taxi que lo llevó a Helechosa de los Montes , donde tenía intención de vivir con el padre. Se hizo un Plan de intervención y económico , pero allí duró un par de semanas . Se ha ido a vivir a un centro en Don Benito , no sé si habrá algún curatelado más allí . El centro se llama : Reeducación de emociones Luis Rojo , C/ Las Arenas , Finca Los Chopos , Don Benito . Hablé con Julian el Dtor del centro y me indicó el perfil que atienden , EMG , Mujeres V.Gº , adicciones... Abona de copago de plaza 400€ al mes en efectivo , el Dtor . no quiere transferencia . Se le dan 450€ de los 517€ que percibe por PNC . El resto se le guarda para cubrir el recibo del TF. EL S. Decesos se lo abona el padre . Hablo a menudo con Jose Vicente , tf 613816265 , quiere que se le suba la asignación mensual. . He solicitado a S. eco que le suban aunque sea 20€ más para que le puedan quedar 70€ para gastos de tabaco , no he obtenido respuesta aún , Alberto lo iba a valorar pero esto es lo de memos porque con 50/70€ para él va a seguir siendo insuficiente . Va a ir al SEPE a preguntar sobre la compatibilidad de la PNC , sabe hacer esas gestiones , que vaya y lo pregunté él . ( hubo un fallo judicial de una persona que lo demandó y el juzgado lo dió por compatible en ese caso, pero no se si se extiende la sentencia o no . ) Ha buscado abogado de oficio , ya han contactado con Angel para remover la curatela y que la asuma su padre . Aunque no es el pérfil para hacer seguimiento continuo; su sentencia indica curatela patrimonial y de salud ,lo incluyo en el programa de acompañamientos de FUTUEX ,sobre todo con la idea de que hagan seguimiento con el ESM . Queda hecho el Plan de Intervención inicial , pensiones , centro ... cubiertas necesidades de residencia y manutención y gastos de bolsillo ( aunque pide más ). También solicita comprar una scooter , un móvil ... De momento se le va a denegar , a esperas también de la remoción de la curatela.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='GIRALDO'and apellido2='BECERRA'),'2024-05-03','TERESA RECIBO LLAMADA DEL DOCTOR IDILIO DE LA UHB DE LLERENA ME INDICA QUE ESTA ESTABLE Y TRANQUILO LE COMENTO POSIBLE DIRIVACION A UME, ME DICEN LO VAN A VALORAR','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTA'and edp.apellido1='DIAZ'and apellido2='BORREGUERO'),'2024-05-03','-Amalia : escribe email su hijo Jorge con información sobre una vivienda para alquilar , le escribo indicando que toda intervencion quedará pte. del fallo judicial de remocion de medidas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MORA'and apellido2='GARCIA MORA'),'2024-05-06','TERESA REGISTRO NO ACPETACON PIA SAD POR ELEVADO COPAGO TRAS REVSION','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2024-05-03','miguel, recibo email de Carlos Arjona Buenas tardes, Por cada uno de los dos procedimientos de aprobación de herencia, aplicando descuento del 50% sobre el módulo del ICAC, nuestro presupuesto sería de 220 Euros cada uno de los expedientes, es decir, en total 440 Euros. No se puede unificar, pero podemos tramitar ambos nosotros sin problema, por lo que hemos hecho un descuento importante como si se hicieran juntos. Quedo a la espera, Saludos, Carlos Arjona','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2024-05-06','miguel, mi contestación: Buenos días, perfecto Carlos, necesitaría me enviaras un presupuesto, hoja de encargo, para que lo firmase la representante de la Comisión. Necesito me indiques tu teléfono pues tengo que consultarte algo sobre este asunto. ------------------------------- Contestación de Carlos Arjona (Abogado) Llamame al 679290698 a partir de las 11.30 que ahora tengo una firma en Notaria -------------------------------- Le llamo y le explico la situación, para que él pida certificado de defunción en persona, porque lo pedimos con registro de salida y no nos lo han enviado. Caso que el padre hubiese fallecido se podrá tramitar la declaración de herederos de Tomás sin más. Caso contrario él podría tramitar una Declaración Judicial de Ausencia. ---------------------------------------------------- Envío email a Carlos Arjona (abogado): Buenos días Carlos, conforme conversación telefónica te envío documentos relacionados con la herencia de la abuela y los trámites realizados para intentar localizar al padre de Tomás que también se llama/ba Tomás Esteban. Cuando lo hayas estudiado indícame qué necesitas o si es una autorización mándame un borrador para que lo firme nuestra representante.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIO'and edp.apellido1='GUISADO'and apellido2='GUISADO'),'2024-05-06','TERESA Te informo que nos han llamado para empezar ya el tratamiento de radioterapia de Eugenio, lo empieza el Lunes 13 de mayo a las 19:00 horas será de lunes a viernes laborables y 25 sesiones. . Los traslados se realizarán en ambulancia. Estamos en la búsqueda de acompañante , cuando sepamos os pasamos datos para realizarle los pagos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALMUDENA'and edp.apellido1='CORREYERO'and apellido2='PAREJO'),'2024-05-06','613 37 55 11','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='CUENCA'and apellido2='SILVA'),'2024-05-06','Amalia : ingresado en Hospital Merida , se le pone acompañamiento hospitalario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='JIMENEZ'and apellido2='NAVARRO'),'2024-05-06','Felisa Jiménez Navarro está en el hospital. Vamos a contratar acompañamiento durante las 24 horas, ya que he llamado al hospital y me han dicho que también necesita a una persona durante la noche.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUSTAVO ALFREDO'and edp.apellido1='CASTAÑO'and apellido2='SOTO'),'2024-04-25','Ana: Correo de Toni, Futuex, al ctutelar@, con copia a mí: "Al respecto de Gustavo Castaño Soto, le han indicado que la oficina donde retira el dinero habitualmente va a estar cerrada de obras dos meses, y que tendra que sacar en la de Av de la Hispanidad, por si fuera necesario que se hiciera autorización de nuevo, a dicha sucursal, ya que los bancos ya sabéis como funcionan a veces... El no para de solicitar un extra de 200 euros para ropa, está acostumbrado a esta dinámica, ya que es la que ha seguido durante todos estos años que ha estado en el centro penitenciario de Sevilla (solicitaba un extra e iba a comprar la ropa que necesitaba). No sabemos si es viable según sus posibilidades económicas o si se valora concedérselo, puesto que insiste bastante, de aceptarse o tanto de lo contrario , se ruega nos podais informar, para trasladárselo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUSTAVO ALFREDO'and edp.apellido1='CASTAÑO'and apellido2='SOTO'),'2024-04-30','Ana: correo de Alberto, jefe secc. ecca: "ANA: TE ADJUNTO EL CORREO QUE SE CRUZÓ CON AMALIA, PARA ESTABLECER LA RELACIÓN ECO A MANTENER CON ESTE TUTELADO (HA SALIDO HACE POCO DE PRISIÓN, CREO QUE TRAS 10 AÑOS RECLUIDO)...COMO SE INDICA, ES COMO SE HA ACTUADO Y SE ESTÁ ACTUANDO HASTA AHORA (VEO QUE TE ACABAN DE PASAR EL EXPEDIENTE). ESTO SE RELACIONA CON EL TEMA DE UN REINTEGRO PUNTUAL QUE PIDE DE 200 € PARA ROPA QUE NOS MANDA FUTUEX. LOURDES: OK A LOS 200 € PARA ROPA SI ANA NO TIENE INCONVENIENTE. ANA: REITERO EL ACUERDO AL QUE SE LLEGÓ...EN CÓMPUTO ANUAL NUNCA NEGATIVO...SI LO ESTIMAS OPORTUNO GASTAMOS SUS INGRESOS, PERO...TENIENDO EN CUENTA QUE: • EL REINTEGRO ES ELEVADO. • AUN NO PODEMOS CUANTIFICAR LOS CONSUMOS PK LLEVA MUY POCO TIEMPO EN LA VIVIENDA. • AMALIA HABLÓ EN SU DÍA DE "AYUDA A DOMICILIO"...AÚN NO SABEMOS NADA DE ESTO (IMPORTANTE: OBSERVA CORREO INICIAL)...LO DIGO PK DEPENDIENDO DE ESTE COSTE Y DE LOS CONSUMOS HABRÁ QUE TOCAR EL REINTEGRO"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUSTAVO ALFREDO'and edp.apellido1='CASTAÑO'and apellido2='SOTO'),'2024-05-07','Ana: Respondo correo a Alberto, con copia a Lourdes: "Entiendo que los 200€ que solicitan para ropa, son los mismos que, según me dijo Amalia, os solicitó en marzo. Si aún no se le ha concedido, mantengo el ok al mismo. Por mi parte no hay inconveniente en mantener el plan de intervención a nivel económico que acordasteis Amalia y tú, y cuando sea necesario se ajusta. En cuanto a la autorización a la otra oficina bancaria, por las obras en la que sacaba habitualmente, supongo que está ya enviada."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GONZALEZ'and apellido2='GONZALEZ'),'2024-03-19','Ana: Correo de Toni-Futuex: "En el dia de ayer, se acude en taxi, a recoger Carmen Gónzalez que tenía programada la salida de la UNIDAD DE ALCOHOLISMO, del sociosanitario de Plasencia. Las auxiliares comentan que su comportamiento estos 30 días ha sido muy bueno y que ha colaborado mucho, ella dice no tener abstinencia al alcohol.. Su aspecto físico es bueno, ha perdido 8 kilos almenos. A la llegada al domicilio se encuentra su pareja Enrique esperándola y se les apoya en organizar todo lo referente a la medicación que tiene que tomar durante algunos dias (en el ingreso además ha sufrido una broncolitis, de la que ya está practiamente recuperada). Se adjunta informe de alta"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-05-07','Ana: Llamada de José Manuel (627 788 797): Ayer comenzó en el COMEDOR del C.R. Cervantes. Dice que estuvo a gusto y que la comida estaba muy rica. Esta mañana no ha acudido a desayunar porque le dolía la cabeza. ·················· *Se está planteando irse a vivir a un pueblo de alquiler, pues dice tener problemas en el barrio con un vecino que le ha amenazado de muerte. Al parecer en su día José Manuel le vendió una barra de sonido que dejó de funcionar y quiso recuperar el dinero que José Manuel ya no tenía. ················· Por otra parte dice que un amigo le ha cambiado la encimera de la cocina, pues la suya estaba hinchada. Aún no se lo ha cobrado, le ha dicho que son 130 €. Le digo que sin presupuesto, factura, recibí, ni nada, el Jefe de Secc. Ecca. no lo va a aceptar. Una vez más lo ha hecho por decisión propia, sin consultar previamente a la CTAEx. ··················· Por último dice que necesita ropa para el verano. Le digo que aguante un par de semana y después pida presupuesto con Nieves, Ed. Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2024-05-07','Ana: Llamada de Felisi (614 361 144): sólo para hablar de todo un poco y desahogarse por todas las experiencias vividas en los últimos años con su hijo. Dice que está muy a gusto sola y que aunque echa de menos a Aitor, no quiere que vuelva. ·············· Le gustaría hacer otras actividades, pero los horarios de bus para ir a Arroyo de la Luz no le cuadran.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2024-03-19','Ana: Correo de Toni-Futuex: "La cuñada de Juanjo sigue muy insistente en que no es suficiente con la compra del armario y que necesita que desde la CTAEX le ingresen más dinero por Juanjo, ya que es una persona muy demandante y siempre le pide mucho dinero para comprar sus cosas (refrescos, zumos, actividades de ocio...). Además de esto, según ella comenta, tiene un comportamiento bastante agresivo con toda la familia que convive en el domicilio, incluso con vecinos del barrio (con quienes a veces tiene discusiones y trifulcas por las que su familia debe dar la cara). Desde el equipo no hemos constatado estas conductas, en nuestra presencia nunca. Lo que quieren principalmente es que se agilice el ingreso en un centro, a pesar de que se le explica, que al rechazarlo el proceso que esta en marcha pero tardará.. y mientras tanto le suban la asignación que le dan a ella por estar al cargo de Juanjo (o así lo comunica ella). Los mensajes a la educadora sobre estos temas son constantes (diarios), por ello se traslada esta información a la CTAEX y se solicita, si es posible, que os pongais contacto con ella para que puedan explicarle las posibilidades economicas con las que cuenta el tutelado."','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='GARCIA'and apellido2='MORENO'),'2024-03-19','Ana: Correo de Toni-Futuex: "Se visita a Pilar en su domicilio, estaba junto con Abraham, y se aborda con ellos sobre el tratamiento de diálisis. Lo que el otro día parecía sugestión por parte de Abraham, para evitar el tratamiento, hoy se valora que han hablado tratado el asunto y llegado el momento aceptan que Pilar se someta al tratamiento. Abraham tiene mucha dependencia de su madre, por lo que le da miedo que el tratamiento empeore su estado o la vuelva más dependiente, por ello, Abraham desea postergarlo todo lo posible en el tiempo, pero no muestra una negación al proceso de diálisis. Además, se le ha explicado que Pilar acudiría en transporte sanitario, que la recogen en su puerta, puede ir sola con el tiempo, aunque al principio él le quiere acompañar, en función de la evolución puede que acuda menos días... Al parecer Abraham le ha comprado recientemente alimentos más adecuado a su patología, y se ha aprovechado, de nuevo, para ofrecerle la opción del catering para Pilar cuando salga la convocatoria, esta vez no han rechazo la propuesta, aun así se les ha dado tiempo para que lo piense, asimismo se le han explicado los beneficios y el funcionamiento del programa. Queda pendiente de que me confirmen si lo desea solicitar Pilar. Abraham comunica a la educadora que Pilar tiene el DNI caducado desde más o menos un año. Por lo que, se pedirá cita cuanto antes para renovárselo. Para las fotos no han puesto impedimento en pagarlas, ni la tasa del DNI (alrededor de 12€). En lo que si, insisite, como hizo tiempo atrás es en que se solicite una vivienda social para su madre, se le explica las dificultades que esto supone, (ademas que como es un tema recurrente se ha abordado en el pasado) y más con la edad que tiene su madre, para moverla de domicilio, pero el parece no entenderlo. Casi todo, lo que plantea, está siempre relacionado con el dinero, de su madre."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2024-05-07','Ana: Llamada de Gloria, Técnica Valoración de Dependencia - SSTT - CC (64736): me enviará la Aceptación PIA. Está esperando que cierren el ciclo de gestión de Discapacidad que cuando rechazó plaza anteriormente lo dejaron abierto. Habrá que solicitar de nuevo perfil al CADEX y esto puede tardar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FAUS'and apellido2='LEMUS'),'2024-05-07','-Amalia : trasladado del Puerto a Ctro. penitenciario de Caceres . Activado cuenta peculio .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FAUS'and apellido2='LEMUS'),'2024-05-07','Escribo a Seccion eco : Rafael ha sido trasladado del Ctro. Penitenciario del Puerto al Ctro. Penitenciario de Caceres , hay que anualar cuenta peculio en uno y activarla en el otro. Me dicen desde Caceres que tenéis el email de otros casos . Le vamos a subir un poco , 80€ semanales . Va a pedir un extra pero lo hacemos más adelante , seguro que pide otra TV .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MOYA'),'2024-05-07','Respondo a las preguntas de la sección económica: 1. Con respecto a la domiciliación de los pagos todo sigue a nombre de su abuela y/o su madre, pero la comunidad conoce los datos de José María y entiende que como heredero debe responder por los pagos de la comunidad. 2. José María tiene la mayor parte de la herencia y un tanto por cierto más reducido pertenece, por una parte, a su hermano y por otra parte a su tía, hermana de la madre del usuario. Su tía sí es conocedora de la deuda, pero informa que no se hará responsable, pues argumenta que en su momento fue a un notario a rechazar la herencia. Con el hermano no tenemos comunicación, pero parece ser que tampoco quiere responsabilizarse.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2024-05-07','Ana: Llamada de Pilar, Directora Res. FEMAR - Logrosán (639 58 54 89). Valentina ha fallecido esta mañana. Se ha desplomado cuando se dirigía al servicio. ··· Cuando ha llegado el médico ya no se podía hacer nada. No saben si habrá sido un infarto. ······················· Tenía Seguro de Decesos en OCASO, tras llamar al mismo envío correo a María, Secc. Ecca: "Me comunican desde la Residencia FEMAR de Logrosán, que esta misma mañana ha fallecido VALENTINA FERNÁNDEZ TREJO. Como tenía seguro en OCASO, ya he hablado yo el seguro para comunicarlo y dar el contacto de la residencia, pues cuando llaman a esta compañía les dicen que sólo pueden dar estos comunicados los familiares. Enviarán el Certificado Médico de Defunción y desde la resistencia les solicitarán también a los profesionales del seguro la necesidad del Certificado de defunción del registro." ··························································· Por la tarde desde la residencia nos remiten CERTIFICADO MÉDICO DE DEFUNCIÓN. Causa: Insuficiencia Cardiaca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2024-05-07','Ana: Llamada de Mª Ángeles, TS Hptal. de Coria (77227): Julia está en urgencias, se ha caído esta mañana y la han llevado al hospital. Está llorando porque dice que no puede volver a casa. ···················· Al parecer le dieron el alta porque tuvo una buena mejoría y dejó de dar puntuación para T3 y la mandaron de alta a casa. ··············· A día de hoy no reúne criterio para ingresar en ningún recurso residencial. ···················· Hablo con Maite, Jefa de sección CTAEx, habló el viernes con la TS de Cilleros. Le pueden asignar SAD, 3 h. Pero la Aux. disponible tiene que coger ahora vacaciones, por lo que no saben qué día podrá comenzar el servicio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='AVILA'and apellido2='FEMIA'),'2024-04-18','Ana: Puesto que Mª Carmen, TS HSPA, está de vacaciones, hablo con Luli, TS - HSPA (56348): Estará pendiente del Ingreso de José Luis en la UHB.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='AVILA'and apellido2='FEMIA'),'2024-04-19','Ana: Llamada de Luli, TS - HSPA (56348): Actualmente José Luis presenta un BROTE PSICÓTICO. Le van a administrar Poliporidona, Inyectable cada 3 - 6 meses. El Dr. Ignacio Torres - Psiquiatra, planeta darle el alta en cuanto esté estabilizado y mandarlo a casa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2024-05-07','TERESA RECIBO LLAMAD DE JOSE VICENTE ME INDICA QEU ESTA EN HELECHOSA Y QUE NO TIENE DINERO SOLICTA PARA COMPRAR COMIDA Y ARRELGAR EL PISO EN EL QEU VA A VIVIR ME LLAMA M DEL MAR LA TRAAJADORA SOCIAL DE HERRERA 81926, ME COMENTA QUE LE HA LLAMADO JOSE CON LA MISMA QUE NO TIENE DINERO ACORDAMOS QEU LE VISITEPARA CONFIRMAR DONDE VA A VIVIR Y VER QUE DINERO LE DAMOS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='AVILA'and apellido2='FEMIA'),'2024-05-07','Ana: Puesto que mañana dan el alta a José Luis en el HSPA, tras hablar con Maite, Jefa Secc. y Toni-Futuex, envío correo a Alberto, Jefe Secc. Ecca: "...se le puede hacer una autorización de retirada de un extra de 200 € para esta semana, por si le hiciera falta. Es posible que aún le quede dinero de la retirada anterior (mes pasado), pero no lo sabemos con seguridad. Desde Futuex van a informarnos mañana de las opciones de servicio municipal de comida y otras opciones (acuerdo de comidas en un bar del municipio) y en función de todo esto, y la información que tengáis del gasto de suministros (movimientos bancarios) podremos establecer un presupuesto aproximado de gastos." ··············· Maite confirma que mañana Lourdes realizará autorización de retirada de extra de 200€. ·············· confirmo también a Toni.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='AVILA'and apellido2='FEMIA'),'2024-04-24','Ana: Luli, TS HSPA, me comunica que el Psiquiatra mantiene la intención de darle el alta en las próximas semanas. ··············· Le ha facilitado mi número para que contacte conmigo. ·· Puesto que tengo curso presencial le llamo varias veces al final de la mañana sin éxito.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='AVILA'and apellido2='FEMIA'),'2024-05-07','Ana: correo de Tomás, hermano de José Luis, del pasado viernes día 3 (en mi ausencia), con REQUERIMIENTO de fecha del mismo día del Jugado nº 7 de Cáceres para que el SEPAD proceda al internamiento no voluntario en centro adecuado. ··············· No lo envío a Maite y a Soraya porque al parecer también lo tiene ya.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MOYA'),'2024-05-07','miguel, respondo a Amalia, Alberto, Angel, y Sandra ssanchez@inteligencialimite.org> Buenas tardes, necesitamos contestar al juzgado en este asunto, ya que como mínimo la deuda recaería en los dos hermanos. ****************************** email que reenvia Amalia de Sandra Buenas. Respondo a las preguntas de la sección económica: 1. Con respecto a la domiciliación de los pagos todo sigue a nombre de su abuela y/o su madre, pero la comunidad conoce los datos de José María y entiende que como heredero debe responder por los pagos de la comunidad. 2. José María tiene la mayor parte de la herencia y un tanto por cierto más reducido pertenece, por una parte, a su hermano y por otra parte a su tía, hermana de la madre del usuario. Su tía sí es conocedora de la deuda, pero informa que no se hará responsable, pues argumenta que en su momento fue a un notario a rechazar la herencia. Con el hermano no tenemos comunicación, pero parece ser que tampoco quiere responsabilizarse. Cualquier duda estamos a vuestra disposición. Un saludo. El 02/05/2024 a las 10:10, Amalia Diaz Gonzalez escribió: Buenas , el Jefe de Sección económica hace estas preguntas , te las paso por si puedes contestarlas . Saludos. OBSERVACIÓN: • A DÍA DE HOY NO TIENE DOMICILIADO NINGÚN PAGO RELACIONADO CON COMUNIDAD DE PROPIETARIOS...X TANTO DESCONOZCO SI SIGUE ACUMULANDO DEUDA. • NO TIENE MÁS HERMANOS/HEREDEROS CON LOS QUE COMPARTIR EL PAGO DE LA DEUDA??? Sandra, necesitamos saber los nombres completos de la abuela fallecida, de la tía que renuncia a la herencia y del hermano que no quiere saber nada. En concreto, necesitamos algo que acredite la existencia del hermano y sus datos personales, nombre apellidos, dirección, teléfono, libro de familia... En cuanto a la tía que renunció a la herencia necesitamos que nos envie la escritura notarial de la renuncia de la herencia o bien los datos del notario, protocolo y fecha en que lo firmó','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2024-05-06','Ana: correo de Lourdes, Secc. Ecca. a Jurídicos, con copia a Alberto y a mí: "Con fecha, se envió a Unicaja de Miajadas, un oficio modificando el reintegro permanente a 50€ semanales, tal y como indican en el auto 26 de fecha 12 de abril. Pues el resultado es que al entrar en la cuenta para comprobarlo no han hecho caso, de tal modo que ha retirado la totalidad del saldo. Reenvío correo a Miajadas, y esto me vuelven a responder, lo anoto en negrita y azul. Si os parece, Miguel o Angel, podríais explicarle la sentencia???"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='AVILA'and apellido2='FEMIA'),'2024-05-07','Ana: Correo de Toni-Futuex, a Maite, que me reenvía Toni: "... Hoy en el seguimiento, el psiquiatra ha explicado que va a proceder al alta mañana y que si en dos dias, como maximo, no quisiera recibir ningun tipo de apoyo, el va a explicitar en el informe que debe informarse a 112 y volver inmediatamente a la unidad. Que está con un buen soporte de medicación y que en resumen el perfil de persona que ellos han visto en la unidad no tienen nada que ver con lo que describen otros profesionales comunitarios. La idea es que desde el equipo de apoyo social comunitario, estemos alli a las 10.30 h mañana, las dos personas que han estado visitándolo estos dias. Él en principio está receptivo. No sabemos de las posibilidades económicas de cara a la provisión de apoyos, en cuanto al alimento y etc. Pero nos hemos adelantado a sondear, si hubiera algun servicio de catering o bar o algo similiar, y hemos encontrado uno, que pudiera venir bien, Restaurante y Catering los ALISOS, carretera de Alburquerque, s/n, telefono 636630840 nos indican que sirven menús diarios por 12 compuesto de dos platos, pan y postre y que no sirven a domicilio pero que la persona puede ir a recogerlo alli sin problemas y que aceptarian el pago por transferencia. Creemos que dado que no existen habilidades para gestionarse por si mismo, en este sentido, podria ser una opción, siempre y cuando el estuviera dispuesto a acudir a por la comida y que fuera economicamente viable. ..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='AVILA'and apellido2='FEMIA'),'2024-04-25','Ana: puesto que Maite y yo estamos en curso presencial, Soraya Masa, Jefa U.PP.AA, solicita a Toni-Futuex, que comiencen a visitar mañana mismo a José Luis en el hospital, de cara a continuar trabajando con él en el domicilio una vez procedan al alta en el hospital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MOYA'),'2024-05-08','miguel, información que llega de Sandra Sánchez >ssanchez@inteligencialimite.org> Os hago llegar los nombres y apellidos de los familiares de José María: - Abuela: Manuela Cordero Moya - Tía: Isidora Rodríguez Moya - Hermano: Juan Manuel Molina Rodríguez Ambos hermanos no mantienen ningún tipo de relación, por lo que no sabemos ni dirección, ni teléfono... Lo único que sabemos es que el hermano parece ser que reside o ha residido en el barrio de los colorines de la localidad de Badajoz. Por otro lado, tanto la tía de José María como el propio usuario nos contaron que cuando falleció Isabel, madre de ambos hermanos, Juan Manuel entró en la casa y se llevó toda la documentación relativa a la abuela, madre, familia y del propio inmueble. Hemos intentado conseguir documentación pero nos resulta muy complicado ponernos en contacto. Por último, indicar que he hablado con la tía del usuario y comenta que ella no tiene documentos de ningún tipo. Explica que no le importaría volver a la notaría donde firmó la documentación de renuncia para volver a solicitar la documentación pertinente. ----------------------------------------------- mi contestación: Buenos días Sandra, gracias por las gestiones, a ver si la tía supiera una dirección o teléfono del hermano. En cuanto a la tía, tiene que ir a la notaria y que le den una copia de la renuncia de la herencia. Toda esta información cuando la tengamos la enviaremos al juzgado a ver si logramos que no ejecuten por el total de la deuda de la Comunidad a José María','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2024-05-08','miguel, me llama Belén la hermana de la tutelada 664725794 email Belen Solana chanclon >solanachanclonbelen@gmail.com> me comenta que le cumple el impuesto de sucesiones y que mañana va a hablar con la notaria porque le dijeron que se firmaba esta semana y ni a ella ni a mi nos han dicho ni enviado nada. Tendrá que pedir prorroga del impuesto de sucesiones porque seguramente no le de ya tiempo a liquidarlo antes del 19','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2024-05-08','Ana: llamada de Mª Ángeles, TS HCC: Julia está de nuevo en el servicio de urgencias desde esta madrugada, pues se han caído tanto ella como su padre al intentar ayudarla. La madre ha claudicado y se ha trasladado a casa de su otra hija. ····· Me envía los informes de Urgencias y escrito suyo. ················································ Envío correo a Soraya Masa, Jefa Ud. PP.AA., Maite, Jefa CTAEx y Pedro Sánchez, TS de SS.TT.: "Tras intercambiar varias llamadas tanto ayer como hoy con Mª Ángeles, Trabajadora Social del Hospital de Coria, y dadas la últimas incidencias relativas a JULIA MORÓN HERNÁNDEZ, os envío, en el documento adjunto: - Informe del Servicio de Urgencias de 07/05 - Informe del Servicio de Urgencias de 08/05 - Escrito de la Trabajadora Social Pongo en copia a Pedro, TS de los Servicios Territoriales – SEPAD, pues sé que ha hablado también con Mª Ángeles respecto a la situación insostenible que presenta Julia. Quien a día de hoy no da perfil para recursos residenciales de mayores ni para plazas sociosanitarias y no tiene recursos económicos para poder costearse un plaza privada. Pedro plantea solicitar PLAZA PARA PERSONAS CON DISCAPACIAD RAL, pero sabemos que esto tardaría y además, cuando lo solicité en su día nos dijeron que no daba perfil, por eso se le derivó finalmente a CRR. La otra opción que se le ocurre a priori son los centros gestionados por congregaciones religiosas, tipo Casa de la Misericordia, éstas concretamente atiende sólo a hombres. No sé si el Hospital Santiago de Zafra o qué otras opciones pudiera haber. Tampoco sé si se puede convocar alguna Comisión Sociosanitaria de Área." ····························································································································································································· *Llamo a Susana Cortés, TS Casa Hptal. Santiago de Zafra (607 33 19 63): han tenido muchos ingresos recientemente y no sabe si quiera si tiene cama. Lo va a hablar con el Director y Sonia. ······················································································································ Llamo al Centro La Providencia , de Rivera. Me pasan con María Cadena: No tienen plazas libres actualmente. ····················· Informo de todo a Mª Ángeles, Esther, Maite, Soraya y Pedro. ·········································· Llamo a Centro Cottolengo La Fragosa, de entrada dice que va a ser muy complicado pues van a operar a "la hermana" que tendría que atenderle pero que le envíe Informe de Salud completo d Informe Social. ··························· Susana, TS Hptal. Santiago de Zafra, también pide que les envíe informes. ························ Informo de nuevo a Mª Ángeles, Esther, Soraya, Maite y Pedro.','2');
