insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN PABLO'and edp.apellido1='ESTEBAN'and apellido2='CORRAL'),'2024-05-08','TERESA ARCHIVO RESOLUCION DE ORFANDAD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MOYA'),'2024-05-08','Os hago llegar los nombres y apellidos de los familiares de José María: - Abuela: Manuela Cordero Moya - Tía: Isidora Rodríguez Moya - Hermano: Juan Manuel Molina Rodríguez Ambos hermanos no mantienen ningún tipo de relación, por lo que no sabemos ni dirección, ni teléfono... Lo único que sabemos es que el hermano parece ser que reside o ha residido en el barrio de los colorines de la localidad de Badajoz. Por otro lado, tanto la tía de José María como el propio usuario nos contaron que cuando falleció Isabel, madre de ambos hermanos, Juan Manuel entró en la casa y se llevó toda la documentación relativa a la abuela, madre, familia y del propio inmueble. Hemos intentado conseguir documentación pero nos resulta muy complicado ponernos en contacto. Por último, indicar que he hablado con la tía del usuario y comenta que ella no tiene documentos de ningún tipo. Explica que no le importaría volver a la notaría donde firmó la documentación de renuncia para volver a solicitar la documentación pertinente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2024-05-08','-Amalia : email del Dtor de CRR Mérida , Javier quiere dejar el recurso : Os quería comentar la situación actual de Javier para que de manera conjunta podamos ver cual es la mejor manera de intervenir. Desde hace aproximadamente 3 semanas, Javier viene verbalizando su intención de abandonar el recurso, esto está siendo motivado por un aumento de su sintomatología de perjuicio “siente un gran malestar por la convivencia en el centro” (no siendo algo real), llegando a tener miedo de reaccionar de manera inadecuada. Durante este tiempo se ha intentado trabajar con el desde regulación emocional para manejar su malestar, concienciación de sintomatología (no siendo consciente), lo cual tiene resultado de manera puntual. Concretamente tuvo un ingreso de 5 días (siendo alta el 1-5), el cual se produjo de manera voluntaria al exponerle que la intencionalidad era disminuir su malestar. Tanto las pautas, intervenciones realizadas, como el ingreso no han facilitado el cambio de opinión de Javier, manteniendo su intencionalidad de irse. Teniendo en cuenta el histórico de abandonos de recursos de Javi, y entendiendo que lo mejor para el no es un abandono del recurso, se nos plantea una posible alternativa, con el objetivo de poder dilatar una posible alta prematura o incluso que pueda cambiar de opinión. El objetivo a plantear seria un PROCESO TERAPEUTICO DE ALTA, a través ayudarle a búsquedas de alquileres en Mérida, hacer salidas progresivas, derivación a CRPS y trabajar durante este proceso objetivos concretos para poder dar el alta, al igual que un plan de prevención de recaídas. Como os comento el objetivo principal no es el hecho de que Javier sea alta terapéutica, sino evitar otra posible salida del recurso sin previo aviso, con lo que esto pueda generar de manera negativa hacia él. Por lo que me gustaría conocer vuestra opinión antes de realizar una intervención con Javi, él también está a la espera de que se le pueda dar una alternativa a su estancia actual, por lo que si os parece, si necesitáis cualquier información adicional estoy a vuestra disposición.','2');
