insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2024-05-09','miguel, reunión entre las 3 partes, social Ana, eco Alberto y jurídica yo, conclusiones en email de Alberto: ANA/MIGUEL/ALBERTO: • RESIDE EN CENTRO Y, EN PRINCIPIO NO VA A VOLVER AL DOMICILIO. • A NIVEL ECO, LA SITUACIÓN NO ES ADECUADA....CON EL NIVEL DE GASTOS QUE TIENE ESTANDO EN CENTRO, LA EVOLUCIÓN ES NEGATIVA. • ANA: TIENE UN NIVEL DE INGRESOS MUY BAJO (DESEMPLEO) + ANA TIENE QUE GESTIONAR ESTA CUESTIÓN PK HA DEJADO DE COBRAR EN 02/2024. • OPINIÓN INICIAL: NO ES VIABLE PAGAR 4.000 € A SU HERMANO, X CUESTIONES ECONÓMICAS, Y ADEMÁS PARA SEGUIR COMPARTIENDO VIVIENDA CON SU HERMANA. o ES POSIBLE QUE LA MEJOR OPCIÓN SEA PROCEDER A LA VENTA/ADJUDICACIÓN A OTRO DE LOS HERMANOS. DE LA VIVIENDA X PARTE DE LOS 3 HERMANOS, PARA UN POSTERIOR REPARTO. • MIGUEL: HABLARÁ CON LA ABOGADA PROPONIENDOLE LAS 2 OPCIONES PUNTO ANTERIOR + QUE NO SE ACEPTA PROPUESTA ENTREGA A HERMANO DE 4.000 €. ________________________________________ ANA: IMPORTANTE: EN 02/024 DEJA DE PERCIBIR EL DESEMPLEO....FALTA PARTE DE FEBRERO Y MARZO, ABRIL, MAYO ENTEROS.... Valor Observaciones Importe 09/05/2023 DESEMPLEO (PRESTACIONES) 480,00 09/06/2023 DESEMPLEO (PRESTACIONES) 480,00 10/07/2023 DESEMPLEO (PRESTACIONES) 480,00 09/08/2023 DESEMPLEO (PRESTACIONES) 480,00 08/09/2023 DESEMPLEO (PRESTACIONES) 480,00 09/10/2023 DESEMPLEO (PRESTACIONES) 480,00 09/11/2023 DESEMPLEO (PRESTACIONES) 480,00 11/12/2023 DESEMPLEO (PRESTACIONES) 480,00 09/01/2024 DESEMPLEO (PRESTACIONES) 480,00 09/02/2024 DESEMPLEO (PRESTACIONES) 176,00 ANA/MIGUEL: CON INDEPENDENCIA DE LA FALTA DE INGRESOS DESDE 02/2024...LA EVOLUCIÓN DEL SALDO ES Y VA A SEGUIR SIENDO NEGATIVA...MEJORARIA SI DEJAMOS DE ABONAR: • IBERDROLA • IMPUESTOS VIVIENDA • SEGURO VIVIENDA ANA: AL MENOS, QUE EL CENTRO SEA CONSCIENTE DE LA SITUACIÓN ECO. MIGUEL: COMENTA ESTO CON LA ABOGADA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATAN'and edp.apellido1='GARCIA'and apellido2='TERRON'),'2024-05-09','Ana: Llamada de Anabel, TS SSASB - Miajadas (927 90 12 38 // 683 51 19 55): le informo que aún estamos pendiente de recibir el TESTIMONIO DE LA FIRMEZA, está solicitado, pero el Jdo. no lo ha enviado. Mi compañera Inés va a volver a reclamarla. ···························· Se trata de una CURATELA ASISTENCIAL para los ámbitos "ECONÓMICO, JURÍDICO, ADMINISTRATIVO Y CONTRACTUAL"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2024-05-09','Ana: Envío correo-e a Belén Plasencia - TS HSPA (56341/belen.plasencia@salud-juntaex.es ): "Tal y como hemos acordado mediante conversación telefónica, te solicito INFORME MÉDICO DEL ALTA, del Servicio de Neumología, relativo a JULIA MORÓN HERNÁNDEZ, cuyo cargo ostenta la COMISIÓN TUTELAR DE ADULTOS DE EXTREMADURA." ······································································································································ Correo de Esther, TS de Cilleros (tsocial@ayuntamientodecilleros.es): "acabo de hablar con el médico, le voy a mandar los modelos de informes tanto del SEPAD como del MADEX, me ha dicho que intentará hacerlos cuanto antes, como muy tardar los tendría mañana a primera hora. también me ha comentado que él había estado trabajando en la asistida y que en el centro había veces que ingresaban a personas por orden judicial y los tenían que coger si o si si no había plazas, se podría barajar esa opción? no obstante voy a preguntar por un grupo de wpp donde estamos trabajadores sociales de toda la comunidad a ver si hay algún recurso donde podría encajar el perfil de Julia y te voy diciendo, ya que desde el centro de salud también me presionan en buscar algo urgente porque llama a urgencias para que la cambien el pañal y la ayuden a levantarse." ···························· Mi respuesta: "La opción de internamiento involuntario, a día de hoy no es posible porque no tenemos autorización judicial de ingreso involuntario, se podrían solicitar si ella no quisiera ingresar, que no es el caso, además los trámites de estas características (Jurisdicción Voluntaria) son muy lentos, habría que solicitarlo de forma motivada aportando todos los informes, pero como te digo, de entrada ella quiere ingresar, por tanto no es internamiento involuntario. Imagino que aunque necesita pañal, seguirá sin dar puntuación en la herramienta de T3, no? Lo digo porque si el personal de enfermería del centro de salud viera que da puntuación igual se podría volver a intentar." ············································································· Ana: Nuevo correo de Esther, TS: "acabo de estar hablando con Julia, me dice que se encuentra en casa de su hermana, que le ha dado una segunda oportunidad. Se la oye animada y contenta de estar con su madre y su hermana, no se el tiempo que durará. Ella continua queriendo irse a un centro, me comenta si fuera posible ir al centro donde se encuentra uno de sus hermanos, en Arevalo, Mentalía la he entendido, no se si es posible. He quedado con ella que voy hacerla una visita al domicilio mañana. Me ha comentado que iba a ir Clara la educadora hoy. Querían la ayuda a domicilio pero tengo el problema que la auxiliar coge vacaciones el martes y no tengo sustituta, por lo que hasta primeros de junio no hay servicio. En cuanto tenga los informes médicos te los hago llegar." ··················· Con respecto a otro correo de Esther, contesto: "con respecto a esto, he estado hablando con mi jefa y con la Jefa de Unidad de Programas Asistenciales de los Servicios Sociales del SEPAD, me dice que es perfil de Salud Mental, y que si vuelve a “liar” alguna en casa, que los propios familiares o tú si eres conocedora, actives al 112 para que la deriven a Psiquiatría y valoren la necesidad de ingreso en UHB. Pues es perfil de Salud Mental, no de Discapacidad…" ·························································································································································································· Envío al Hospital Santiago de Zafra: "Conforme a conversación mantenida ayer con Susana, adjunto: - los últimos informes médicos del servicio de urgencias del hospital de Coria - Escrito de la Trabajadora Social del hospital de Coria - Certificado de Discapacidad - Dictamen Técnico del CADEX Quería enviaros el ultimo informe de alta del servicio de neurología de su ingreso en el hospital, pero no me lo han enviado todavía."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-05-09','Ana: Reenvío a Secc. Ecca. correo de Minerva, TS del C.R. Cervantes: "Don José Manuel Romero Mediavilla ha ingresado como usuario del Club de Comidas el día 06/05/2024 La compañera de administración necesita los datos bancarios de José Manuel para incluirlo en facturación, cuando puedas me los facilitas La cuota mensual va a ser de 201,23 Euros Este mes se le va a cobrar menos como ha ingresado más tarde, este mes serán 190,04 Euros"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2024-05-09','miguel, tras hablar con la abogada Maria José, 666753922 envío email a la parte social Ana, y económica Alberto: Hola, he hablado con Maria José la Abogada, a la que le he comentado la situación actual social y económica del curatelado. Parece ser que el motivo de los pagos de recibos de Oar, luz, etc es porque nuestro curatelado tiene el derecho de habitación y funciona igual que un usufructo, es decir, a él le pasan el 100% de los gastos de la tasa de basura, ibi, etc. Me comenta que el curatelado ya ha hecho testamento en su totalidad a la hermana (la que vive en Cataluña). Comentaros que esta curatela proviene de una remoción de cargo del hermano que ahora reclama su parte de la vivienda y herencia. Compruebo en la sentencia que funciona como una tutela porque requiere las mismas autorizaciones judiciales que la tutela. La abogada me comenta que la hermana se ha quedado viuda y seguramente no disponga de dinero para la compra de la vivienda y por otro lado no quiere venderla, cree ella. Comprobamos también que no se han revisado en el juzgado las medidas de apoyo conforme la nueva ley 8/21, con lo que no sabemos cómo quedará a día de hoy si como curatela representativa o asistencial. Por tanto, ella hablará con el juzgado para que revisen las medidas de apoyo porque va a tener que pedir la autorización de venta de inmuebles. Me da una posible solución, que es vender la única rústica titularidad del curatelado y llegar a un acuerdo con la hermana para que sin vender asuma los gastos de la vivienda, imagino que previo compra de su parte al hermano. De esta forma quedarían sólo José Manuel y su hermana como titulares de la vivienda (su hna en 2/3). Yo veo bien esta solución de vender la tierra que tiene y si la hermana asume el gasto de la vivienda pues ya no sería un problema para la comisión. También le he comentado lo de que va a tenerse que dar de baja la luz de la vivienda. Decidme si veis bien esta posible solución.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2024-05-09','TERESA Según veo en el informe de la trabajadora social Tomas está muy mal…. Me imagino que no quiere ni ir a centro ni a cedex para control de la adicción Hemos contratado ayuda a domicilio, a ver si con este apoyo al meno mejora la situación de la vivienda… Se me ocurre que podíamos hacer una gestión parecida a la que hacemos con Pablo para el control del dinero y de alimentos, ¿crees que estaría dispuesto a funcionar así? No se si esta en el punto de pedir un ingreso involuntario o se puede intentar trabajar con él. Ya me va informando de la evolución y de como va la ayuda a domicilio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOLORES'and edp.apellido1='MACARRO'and apellido2='CAMACHO'),'2024-05-07','miguel, Inés envía por lexnet la solicitud de internamiento involuntario','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='PLATA'and apellido2='MACEDO'),'2024-05-09','Amalia : escribo emaial a S. juridica y J.Sección: adjunto documentación que incluye el Informe social en el que se justifica la necesidad de ingresar a Manuela ( C.R.) en centro de discapacidad adecuado a sus necesidades . Problema uno , ella voluntariamente no quiere ingresar en ningún centro. Problema dos , diagnosticada con un 65% G .Discapacidad por Retraso Mental Leve y Tno. de ansiedad. No sabemos si el centro adecuado sería de la Red de Discapacidad o de Salud Mental . Como para ingresar en CRR o Piso supervisado de Salud Mental se exige la voluntariedad absoluta , ni con la Orden Judicial podría ingresar . Por lo tanto habría que solicitar Centro de discapacidad y que al menos , en el caso que el juez lo concediese ,habría alguna opción. Yo voy a ir tramitando la solicitud en Dependencia , cambio PIA que está en suspenso de SAD a ingreso en centro discapacidad . Desde dependencia lo envian al CADEX para que nos valoren el pérfil del centro adecuado. Voy a solicitar al ESM informes médicos , cita para intentar compensar ,parece ser que ha dejado el tratamiento pautado , y que valoren si necesitase ingreso en UHB previo a supuesto ingreso en Ctro. Discapacidad. Resumiendo , habría que solicitar Ctro. de discapacidad para esta chica . Está viviendo sola en Gévora , tiene 49 años , sin red familiar ni social de apoyo , pide por las calles a pesar de que se le da un reintegro de 600€ al mes . Va por la calle sin asear y tiene deudas en establecimientos de la pedanía . Al parecer , no debe estar tomando el medicamento pautado desde psiquiatría y los vecinos han informado a la alcaldesa de que la ven mal . Ha perdido muchos kilos de peso en los últimos meses y no tiene supervisión de ninguno de los hermanos . Desde que falleció la hermana que la cuidaba deambula por el pueblo y por Badajoz . Rumorología de posible adicción .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='AVILA'and apellido2='FEMIA'),'2024-05-09','Ana: Envío a Toni, Futuex: "Por favor, cuando puedan las compañeras que visitan a José Luis, que le lleven este documento impreso para que lo firme. Es la solicitud de CRR. Una vez firmado, enviárnoslo escaneado a color para que también lo firma la Representante Legal."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2024-05-09','Ana: Tras conversación con Clara, TS CS Guadalupe y el Dr. Adolfo, llamo al Dr. Miguel Medina, Psiquiatra ESM Trujillo (54507): Me enviará Informe que emitió para el ingreso de ayer. ··············· Clara me enviará otros informes. ··························· Recibo la Denuncia que interpuso Adolfo - Medico, en la Guardia Civil.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='AVILA'and apellido2='FEMIA'),'2024-05-09','Ana: Correo Toni-Futuex, sobre regreso a casa de José Luis: "mañana compilamos la información junto con los informes y las citas que se han recabado hoy, y hacemos una nota para pasarla. Pero comento brevemente primeras impresiones: - No han retirado los 200 eu , porque tiene dinero de sobra. - Compra en el spar, y corrobado con la tienda, hace compras equilibradas y generalmente de todo lo necesario, tiene cercania y confianza con ellos, y se le ha pedido si pueden por favor supervisar un poco que compra. -La casa no estaba en malas condiciones, efectuo una limpieza un familiar, una cuñada creo, y estaba bien. - El parece conservar habilidades mininas para autogestionarse en cuanto a la alimentación (al contrario que lo que decian todos los informes de la ts). Se iba a cocinar un plato de pasta, y ha realizado perfectamente los pasos previos para cocer la pasta...etc. - El prefiere por ahora, cocinar el, hasta que tenga el catering del ayuntamiento. No quiere ir a recoger la comida del bar. - No fuma, como nos habian dicho, tambien la ts. Sus unicos gastos en principio, van a ser lo de alimentación, de ahi que tuviera tanto dinero en efectivo, porque le debe sobrar de las retiradas (suponemos). - Nos ha sorprendido gratamente, que con las unicas personas con las que ha interactuado de la localidad (Spar) lo han saludo con cariño. El al parecer tiene la rutina, de ir a por el pan, todos los dias, e ir comprando, en casa tenia algunos botes y latas. -El hermano ha estado en la casa, si se ha percibido una cierta presion respecto de como hacia las cosas Jose Luis, llegando a manifestar que a el "no le interesa que esto funcione, porque lo que el quiere, es que su hermano este en un centro". La impresion, si lo comparamos con otras realidades ni de la casa, ni de las competencias de Jose Luis, no ha sido mala, no sabemos como pueda evolucionar, pero por el momento parece que puede gestionarse. El viernes se hará otro seguimiento."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='GARCIA'and apellido2='RAMIREZ'),'2024-05-10','miguel, envío el documento de compromiso de pago y visto bueno de la compra y prestamo firmado por ambas partes curatelado y ctaex a su hermana Marisol','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALMUDENA'and edp.apellido1='CORREYERO'and apellido2='PAREJO'),'2024-05-13','-Amalia ,hablo con Paula para definir el presupuesto .Quedo pendiente que me va a enviar email con la cuantía y la entidad donde podrá retirarlo acompañada de un profesional. Se está adaptando bien al centro . Sale mucho con Antonio Pereo al que conoce del CSS .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='PLATA'and apellido2='MACEDO'),'2024-05-10','Amalia : envio email a Ana TS de Gevora y a Mar del ESM, en cuanto tengamos los informes médicos se los paso a Miguel para solicitar INt. Inv. Tengo que cambiar el PIA . "junto con tu Informe social y los informes médicos que se necesitan vamos a solicitar internamiento involuntario en centro de discapacidad . Es poco probable que el juez lo autorice , teniendo en cuenta que la nueva legislación ( Ley 8/2021 de 2 de Junio ) se basa en los deseos , voluntad y preferencia de la persona con discapacidad. Ayer hablé con Mar , la TS del ESM de Ciudad Jardín sobre esta chica. Su psiquiatra está unos días fuera , y nos remitirán esos informes a su vuelta . Hoy tenemos cita tf. con su médico de AP , en la misma línea. Le van a dar resultados de analíticas , ha bajado mucho de peso y le están haciendo pruebas . No quiso acudir a la cita presencial que tenía asignada. También le pedí a Mar que en la próxima cita , si pueden , le hagan analítica para valorar posible consumo de drogas . Voy a solicitar cambio de PIA para solicitar recurso residencial de discapacidad a la espera de ese fallo judicial . Estos trámites se alargan bastante , por eso , la primero línea de intervención era centrarnos en intentar que cogiera confianza con la Delegada tutelar y que voluntariamente solicitara ese ingreso. Pero no acepta la ayuda , no quiere quedar con ella . Se pasa el día en Badajoz pidiendo por la zona de la Estación de autobuses . Aunque el juez autorice el ingreso , todos los centros son de puertas abiertas , por el modo de vida que lleva , creo que es un perfil difícil de adaptarse a un entorno residencial . Por favor , comunica esta información a la educadora del Programa familia para que también sea conocedora de cómo va todo el proceso . Estuve hablando ayer con ella y con la delegada del alcalde. Seguimos hablando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='GONZALEZ'and apellido2='FERNANDEZ'),'2024-05-10','TERESA Comunico a vivienda la ocupacion de la vivienda por parte de su hermano Antonio con autorizacion de Jose','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MURILLO'and apellido2='ROMANO'),'2024-05-10','AEXPAINBA : Informaros que, desde el 1 de mayo, Juan José Murillo Romano ha comenzado a trabajar por el curso formativo de RAEES que está realizando. Adjunto contrato laboral. Con este contrato, el SEPAD reclamará mensualmente el 50% de la nómina por la ocupación de la plaza de vivienda tutelada. En cuanto tenga la nómina os la haré llegar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MURILLO'and apellido2='ROMANO'),'2024-05-10','Amalia : escribo a Alberto con esta subida en los ingresos de los que informa la entidad ." desde el 1 de mayo, Juan José Murillo Romano ha comenzado a trabajar por el curso formativo de RAEES que está realizando. Adjunto contrato laboral. Con este contrato, el SEPAD reclamará mensualmente el 50% de la nómina por la ocupación de la plaza de vivienda tutelada. En cuanto tenga la nómina os la haré llegar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2024-05-10','TERESA Envio por registro solicitud tarjeta transporte','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2024-05-10','Amalia , remito email a Dtor CRR y S. Salud Mental del SEpad : "Buenos días, paso a comentaros sobre la propuesta planteada. Antecedentes previos : antes de pasar al CRR , Javi tenía una trayectoria de multitud de alojamientos . Ha estado viviendo en Barcelona , donde al parecer siguen viviendo sus hermanos , aunque la relación entre ellos estaba prácticamente rota. Estuvo viviendo en una casa que tiene el padre en un pueblo de Cáceres , convivió con él un tiempo hasta que falleció y se quedó allí a vivir una temporada . La casa la tenía en unas condiciones pésimas. Se fue a otras ciudades y estuvo viviendo en centros para transeúntes . Antes de ingresar en CSS , su intención era la de regresar a Barcelona. El expediente lo estuvo llevando mi compañera Ana , que por zonificación lleva la zona de Cáceres ,por si consideráis necesario alguna información más específica. No creo que este chico tenga capacidad y funcionalidad para poder llevar una vida autónoma en domicilio y menos sin supervisión. Si deja el CRR , que por supuesto es voluntario , se puede intentar ver la opción que plantea Javier , pero no va a resultar fácil que funcione. Si él está de acuerdo y colabora ,se podría buscar un alquiler en Mérida y se le pueden facilitar servicios como el de SAD y visitas de la delegada tutelar sobre todo de cara a mantener la adherencia al tratamiento y seguimiento en el ESM . Tened en cuenta que en CRR no hay copago , pero si se va a un piso de alquiler tiene que cubrir estos gastos + suministros + manutención + gastos de bolsillo.. con los ingresos que percibe de pensión. Por nuestra parte colaboraremos en la intervención que consideréis más beneficiosa para él . Un saludo . --------------------------------------- ​ ​Propuesta de Dtor CRR : Os quería comentar la situación actual de Javier para que de manera conjunta podamos ver cual es la mejor manera de intervenir. Desde hace aproximadamente 3 semanas, Javier viene verbalizando su intención de abandonar el recurso, esto está siendo motivado por un aumento de su sintomatología de perjuicio “siente un gran malestar por la convivencia en el centro” (no siendo algo real), llegando a tener miedo de reaccionar de manera inadecuada. Durante este tiempo se ha intentado trabajar con el desde regulación emocional para manejar su malestar, concienciación de sintomatología (no siendo consciente), lo cual tiene resultado de manera puntual. Concretamente tuvo un ingreso de 5 días (siendo alta el 1-5), el cual se produjo de manera voluntaria al exponerle que la intencionalidad era disminuir su malestar. Tanto las pautas, intervenciones realizadas, como el ingreso no han facilitado el cambio de opinión de Javier, manteniendo su intencionalidad de irse. Teniendo en cuenta el histórico de abandonos de recursos de Javi, y entendiendo que lo mejor para el no es un abandono del recurso, se nos plantea una posible alternativa, con el objetivo de poder dilatar una posible alta prematura o incluso que pueda cambiar de opinión. El objetivo a plantear seria un PROCESO TERAPEUTICO DE ALTA, a través ayudarle a búsquedas de alquileres en Mérida, hacer salidas progresivas, derivación a CRPS y trabajar durante este proceso objetivos concretos para poder dar el alta, al igual que un plan de prevención de recaídas. Como os comento el objetivo principal no es el hecho de que Javier sea alta terapéutica, sino evitar otra posible salida del recurso sin previo aviso, con lo que esto pueda generar de manera negativa hacia él. Por lo que me gustaría conocer vuestra opinión antes de realizar una intervención con Javi, él también está a la espera de que se le pueda dar una alternativa a su estancia actual, por lo que si os parece, si necesitáis cualquier información adicional estoy a vuestra disposición.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='PLATA'and apellido2='MACEDO'),'2024-05-10','Email de Ana : Muchas gracias por toda la información, no he querido llamarte ni molestarte porque todas las semanas hablo con Gloria y ya me ha comentado que le pasa las notas a su Coordinadora y que ella te lo manda a tí. Te comento, que la última vez que vi a Manoli fue el día 23 de abril, cuando yo entraba en Gevora, estaba en la parada de autobus por lo que fui a por ella y ya aproveché para hablar y decirle que fuese al médico porque desde que no la veía había perdido mucho peso. Esa misma mañana fue a pedir cita al médico y le dieron para el día 25 de abril por lo que llamé a Gloria y a Rosi (auxiliar de SAD) para comunicarselo, además ese mismo día tenía ayuda a domicilio y la mandé a casa para que se aseara. Al día siguiente llamé a Rosi y me dijo que no estaba en casa a su hora. El día 25 si fue al médico, que le dijo que le había mandado yo para que le hiciera una analítica y la acompaño Gloria. Afortunadamente a las citas médicas y de salud mental suele asistir. Sé que fue a hacerse la anaítica y una placa de torax. Pendiente de resultados, que Gloria hoy tenía cita telefónica con el médico de familia. Su hermano Alfonso, su mujer Maribel y Dioni tuvieron entrevista conmigo el día 08 de abril ya que solicitaron cita para comentar la situación de su hermana (creo que ha sido por la alarma social, es decir, que la gente del pueblo les ha ido diciendo el estado de Manoli) Les dí el tfno de la Comisión Tutelar de Adultos por si querían notificar la situación y el de Gloria. Te comento que todas las personas que estábamos trabajando con ella tanto Bea, Petri, Rosi (auxiliar de sad), Gloria y en este caso yo, no quiere saber nada. De hecho, la llamo todas las semanas por lo menos una vez y nunca me coge el teléfono. En Badajoz, la he visto en un par de ocasiones y sé que suele estar por el centro todas las tardes porque dos compañeros ya la han visto en varias ocasiones. Sobre este tema: Aunque el juez autorice el ingreso , todos los centros son de puertas abiertas , por el modo de vida que lleva , creo que es un perfil difícil de adaptarse a un entorno residencial . Te entiendo perfectamente pero intentar explicárselo a la gente que no trabaja con este tipo de población es muy complicado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2024-05-13','-Amalia : Desde el CRR insisten en la necesidad de reparar la vivivenda , le afecta en su estado animico y es su deseo repararlo . Tengo fotos enviadas por el Dtor en el correo y archivo la solicitud por escrito que ha hecho ella. Les pido presupuestos para pasar a la Seccion eco y valorar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MOYA'),'2024-05-13','-Amalia : envio a Estrella la factura de la limpieza del piso para que lo abone, la de las cerradura ya se le enviaron el 22 de marzo desde la entidad .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MURILLO'and apellido2='ROMANO'),'2024-05-13','La dirección de empadronamiento de Juan José Murillo es: C/ José Alcoba Moraleda, Nº 1, 1ºB. CP: 06011 Badajoz. Esta es la dirección de las viviendas tuteladas. A efectos de notificaciones la mejor dirección es la de la Asociación Aexpainba: C/ Antonio Martínez Virel, Nª 12. CP: 06011 Badajoz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FRAIRE'and apellido2='ROMAN'),'2024-05-13','-Angel : El tutor de Antonio Fraire Román era el padre, Antonio Fraire Doblado. Se acordó removerle del cargo y, mientras se resolvía el procedimiento, nos nombraron curadores provisionales. De este nombramiento nuestro, que aceptamos (el Juzgado nos envió testimonio, de fecha, 27/5/22, en el que constaba nuestra aceptación) es el que nos contestaron con un oficio en el que nos indicaban que era firme. Una vez resuelto el procedimiento X59 REVISION MEDIDAS 0000262 /2022, mediante el Auto 420/22, de 22/11/22, nombran curador al hermano, Manuel. Este nombramiento hemos pedido testimonio de su firmeza, el 2/3/23 y, al menos yo, no veo en su expediente que lo hayamos recibido. He llamado al Juzgado y me dicen que lo enviaron a Abogacía, el 23/10/23. Van a volver a enviárselo. Por lo tanto, entiendo que ya no somos nada de Antonio. -----------------------------------------------','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FRAIRE'and apellido2='ROMAN'),'2024-05-13','-Amalia , ya no somos curadores de Antonio , doy de baja en el acompañamiento de Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ISABEL'and edp.apellido1='OTANO'and apellido2='GRAO'),'2024-05-13','-Amalia : ya no somos curadores , han nombrado a sus padres . Doy de baja al acompañamiento Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='MOYA'),'2024-05-13','miguel,recibimos email de Sandra: Buenas tardes. Adjunto el certificado de defunción de Mª Isabel Rodríguez Moya (madre del usuario) y el libro de familia. Por el momento no hemos podido obtener más documentos. Informar que el libro de familia no está mal escaneado, sino que el documento que hemos encontrado es una fotocopia que ya está así. Al igual ocurre con la segunda página del certificado de defunción. ------------------------------------------------------------- mi contestación a Sandra y partes económica y social de la Ctaex: Hola Sandra, aunque se ve mal el libro de familia, sólo acredita a su madre, que al menos se ve que estaba divorciada…y sólo aparece inscrito en dicho libro de familia José Maria. Todo esto lo estaba tramitando Asesoría Menaya (Joaquin), así que cuando tengamos la documentación necesaria se la enviaremos a ellos. Necesitamos lo mismo que te indiqué en el email último pues al ser la herencia de los abuelos necesitaremos (la notaria lo pedirá para hacer la herencia): 1.-certificado de defunción de abuelos y padres del tutelado, por ahora sólo sabemos el nombre de la abuela, Manuela Cordero Moya 2.- copia de la escritura de renuncia de la herencia de su tía Isidora Rodríguez Moya 3.-datos de contacto de su hermano Juan Manuel Molina Rodríguez (que no aparece por ningún lado, ni siquiera en el libro de familia) 4.-Tendríamos también que acreditar el divorcio de los padres mediante certificado literal de matrimonio del registro civil Si no logramos a tiempo acreditar los certificados de definición de los abuelos, los padres, la renuncia en escritura notarial de la tía, y la localización del hermano, no podremos oponernos a la reclamación judicial que hace el juzgado y me temo que acabarán embargando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2024-05-09','Ana: Llamada de Pilar, Directora Res. FEMAR - Logrosán (639 58 54 89): ayer procedieron al entierro de Valentina, acudió ella. Llegó a un acuerdo con el seguro para cumplir el deseo de Valentina de ser enterrada con su padre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTINA'and edp.apellido1='FERNANDEZ'and apellido2='TREJO'),'2024-05-14','Ana: Envío a A. Jurídicos la consulta de Pilar, Directora Residencia Femar (residenciafemar2019@gmail.com): "Tras el fallecimiento de nuestra residente Valentina Fernández Trejo, tutelada por la Administración, nos hemos planteado la posibilidad de donar sus pertenencias a Cáritas, por lo que solicitamos vuestra autorización para ello."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2024-05-14','Ana: Guardo en el expediente Informe de Alta de Neumología remitido por Belén, TS de la UHB. "...ingresada por insuficiencia respiratoria grave secundaria a neumonitis química por broncoaspiración de carbón activo en el contexto de administración del mismo tras intoxicación medicamentosa con ideación autolítica" ·········· La mayor parte del ingreso lo pasa en la UCI. Después la suben a planta donde realizan interconsulta a Psiquiatría ajustándose el tratamiento. ·········· Duración del ingreso: 20/03/24 - 02/05/24.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2024-05-14','Ana: Llamada de Felisi (614 361 144): se siente muy sola, retoma la idea de hace tiempo de querer mudarse a El Casar de CC. Echa mucho en falta las clases para adultos a las que iba allí, las amigas, los parques y los paseos. *Le gustaría irse incluso aunque su relación con Jesús no funcionara. ···················· A parte está molesta con su hermana, porque ésta no quiere vender la casa de la herencia de su padre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-05-14','Ana: Llamada José Manuel (627 788 797): Desde el jueves pasado ha dejado de acudir al Club del Comedor porque dice que le cuesta mucho. Ayer tenía que haber ido a firmar la renuncia al servicio y tampoco fue. Ahora pide 50 € para comprar comida. ·········· Con la ayuda de Nieves, Ed. de Futuex, quiere solicitar el Catering Municipal, pues se ha vuelto a abrir el plazo para el servicio gratuito.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='AVILA'and apellido2='FEMIA'),'2024-05-14','Ana: Envío a Paulina (paulina.navarrete@salud-juntaex.es): "Adjunto la siguiente documentación, relativa a D. José Luís Ávila Femia, cuyo cargo ostenta la CTAEx: - Comunicación de variaciones (Datos bancarios y Medidas de Apoyo) - Alta de tercero - DNI – Representante Legal (Directora Gerente del SEPAD) - Decreto Nombramiento Directora Gerente del SEPAD - Resolución Delegación de Funciones para remitir por registro a la Secretaria General de Servicios Sociales, Inclusión, Infancia y Familia ; Dirección. C/ Antonio Rodriguez Moñino. DIR3 A1103010." ·································································································································································································· Llamo a Toni-Futuex: José Luis se negó la semana pasada a firmar la solicitud de ingreso en CRR. Llamaron el mismo viernes a la UHB y se lo comunicaron a la TS. ············ De momento está aceptando las visitas de seguimiento sin problemas. Le han estado visitando Sonia, TS y Nieves, Ed. La semana pasada acudieron 2 días. También fueron ayer y acudirán mañana. Después continuará Nieves yendo sola. José Luis parece estar adaptándose muy bien al domicilio. Presenta un mínimo de HH para desenvolverse. El día que le dieron el alta en el hospital estaba el hermano Tomás y al parece expresó "Yo no quiero que esto funcione", insiste en que tiene que ingresar en un centro. ····· Uno de los delirios que presentaba José Luis consiste en asustarse de su propia imagen, por lo que tiene todos los espejos pintados y escritos. ····· Ayer tuvo cita en enfermería, también acudió y todo bieN. ··············· La semana que viene tiene cita en el ESM. ························ Dice también que al volver del hospital llevaba encima más de 1000 € (los tuvo todo el tiempo en la UHB). Así y todo la semana pasada acudió al banco él solo y retiró los 200€ que estaban autorizados. ······················ Ha aceptado el cáterin municipal y mientras se gestiona está cocinando él cosas sencillas. ································································································································································································· Subo al portafirmas digital la SOLICITUD DE SERVICIO MUNICIPAL DE COMIDAS A DOMICILIO. ·············································· *Envío a la Secc. Ecca. el documento de AUTORIZACIÓN PARA DOMICLIACIÓN DEL ABONO DEL SERVICIO DE CÁTERIN MUNICIPAL.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MORENO'and apellido2='FOLLARAT'),'2024-05-14','miguel, recibo email de Maria Cadenas María Cadenas >trabajadorasocial@providencia.es> Buenos días Miguel, He llamado al juzgado y me comenta la funcionaria que lleva el expediente que esta pendiente de que resuelva el Juez. Ella se lo entregó el 2 de Mayo. De todas formas he vuelto a escribir al secretario judicial que conocemos para ver si puede hacer algo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2024-05-14','TERESA La madre de Coral Nevado quiere que vaya a pasar su cumpleaños al domicilio familiar y por supuesto ella como loca por ir. Sería del 25 al 29 de mayo, para que lo tengais en conocimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2024-05-14','Ana: En relación al correo de Ángel con requerimiento del Juzgado de más informes, envío correo a Toni-Futuex: "En relación a JUAN JOSÉ MASEDA DEL SOL, 2 cuestiones: - Necesitamos que nos enviéis INFORME ACTUALIZADO FIRMADO relativo a su situación actual (lugar de residencia, relaciones que mantiene, convivencia, actividades que realiza) y NECESIDADES DE APOYO que presenta para la revisión de las medidas judiciales de apoyo. Hace unos meses enviamos al Juzgado Informe Médico e Informe de la Trabajadora Social del Centro Ocupacional al que asiste hace años, pero al parecer les resulta insuficiente. Por cierto, sería conveniente resaltar la necesidad de ingreso en recurso residencial. - Por otra parte, Juan José al parecer tenía seguimiento por el ESM de Cáceres, pero hace años que dejó de acudir por voluntad propia. Sería conveniente que se retomara este seguimiento por el equipo. Así que, por favor, cuando podáis solicitar cita al médico de atención primaria para su derivación al mismo y comenzar a abordar con él esta necesidad." ······················································· Envío correo a Jurídicos con datos personales y de contacto que solicita el Juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MORENO'and apellido2='FOLLARAT'),'2024-05-13','miguel, recibo email de Maria Cadenas María Cadenas >trabajadorasocial@providencia.es> Buenas tardes Miguel, Me ha llamado la familia de M.Isabel Moreno preguntándome si hay noticias nuevas de lo que tienen pendiente. Cuando puedas me informas','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2024-05-14','miguel, me llaman de la Asesoría Sanchez 927501139 para decirme que van a intentar presentar el impuesto de sucesiones de la herencia de la abuela en Coria(donde falleció la abuela). Prepararan las liquidaciones y me la enviarán para su firma. ------------------------------------------- Llamo al registro civil de Cáceres para preguntar si me han enviado el certificado de defunción y me dan un email registrocivil.caceres@justicia.es: Buenos días, hemos solicitado hace 3 semanas certificado de defunción a nombre de Don Tomás Esteban López. Adjunto oficio y justificante de registro de salida. Necesitaría me indicaran si nos lo han remitido ya vía carta a: Comisión Tutelar Adultos-SEPAD (Junta de Extremadura) Avda de las Américas 4 06800, Mérida (Badajoz) Si es posible rogaría lo remitiesen también a este email, pues nos urge.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2024-05-14','tersa Hola Teresa, Pedro no maneja nada de dinero, por lo de las adicciones, se va con el, a comprar todo, y se le ve una vez a la semana aprox. El no gestiona nada del dinero que se retira, solamente el dinerillo que se saca de exraperlo, por cuñas en la radio y cosas asi que le piden de vez en cuando. Lo de CEDEX se valoró pero no es viable porque tendria que ir a controles a Castuera y no tiene opcines ecoomicas de coge taxis dos dias en semana, y en bus no hay horarios. Lo del centro, pues bueno, parece que si está ultimamente por la labor.. aunque no podemos garantizar que llegado el momento, no se negara, sobretodo por su autonomia y su grado de autonomia que es bastante alto. En los ultimos seguimientos hemos observado un deterioro significativo en el estado emocional de Pedro, quien manifestó su deseo de ingresar en un centro residencial que le provea de las limitaciones necesarias para su bienestar, las cuales él mismo no puede proveerse cuando esta en ese estado.. Durante el ultimo seguimiento Pedro reveló haber vendido la casa de sus padres en una notaría a un hombre que le debía dinero, donde, en lugar de recibir un pago monetario, fue compensado con sustancias estupefacientes. Actualmente, carece de cualquier documento que avale esta transacción, aunque disponemos de la dirección de la notaría involucrada: calle Santa Ana en Castuera. Es importante destacar que Pedro continúa mostrando un patrón de consumo activo, y su domicilio actual no cumple con los estándares mínimos para una habitabilidad adecuada. El dia 2 de Mayo se ha iniciado la implementación de los servicios de ayuda a domicilio y la casa si estaba en unas condiciones aceptables cuando fue para allá la auxiliar. En síntesis, Pedro ha expresado su disposición actual de ingresar voluntariamente en un centro residencial fuera de la localidad de Monterrubio, con el objetivo de distanciarse de aquellas personas que influyen en su consumo. Cabe señalar que ya ha intentado un ingreso voluntario con anterioridad, el pasado 6 de marzo, aunque fue dado de alta el mismo día. Cuando acudió a urgencias hospitalarias- Pedro admite conocer y ser capaz de disimular su estado psicológico cuando se lo propone.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL MAR'and edp.apellido1='DE LA MORENA'and apellido2='MARTINEZ'),'2024-05-14','TERESA DESDE EL CENTRO NOS PASAN PRESUPUESTO DENTAL INSAUMIBLE EL PAGO PUES NO TIENE DINERO SUFICIENTE AHORRADO DESDE EL CENTRO INFORMAN al igual que las prestaciones están mal distribuidas, ya que la orfandad que solo cobra Julia seria a repartir entre el resto que tienen PF, necesitaríamos que entre los hermanos se pudieran hacer préstamos para poder solventar la problemática que presenta, en la masticación, deglución y en la propia alimentación. Ha tenido una significativa pérdida de peso en los últimos meses y es a causa del malestar, náuseas y arcadas que le produce comer con la dentadura, ya que se le mueve constantemente por mucho pegamento que se ponga. De ahí la urgencia del caso, si necesitas que te envié informes acreditando esta situación, me dices para que el asesor lo tenga en cuenta. EL GASTO DE TODOS LOS HERMANOS SUPERA CON CRECES LOS INGRESOS AHORA ES INASUMIBLE EL GASTO DENTAL SE COMUNICA AL CENTRO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FERNANDEZ'and apellido2='MERCHAN'),'2024-05-14','-Amalia , quedo pte. enviar los datos a la empresa SADEX , se ha caido y han contratado unas horas de acompañamiento . Enviará la factura a final de mes .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='DIAZ'and apellido2='ROMERO'),'2024-05-14','-Amalia : se le concede traslado a AEXPAINBA en Badajoz , se hará el 21 de junio cuando acabe el colegio en Montijo . Ya lo saben las 2 entidades.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEREA'and edp.apellido1='DA COSTA'and apellido2='LORENZO'),'2024-05-14','Ana: Correo de Lourdes, Secc. Ecca: "se autoriza el extra para ropa de Nerea. Según leo en el correo, su hermana hace la compra y posteriormente se la abonamos" ································································································································································································ Llamada de Guadalupe, madre de Nerea (601 53 85 85): se queja porque en el CSS le han dicho que ya no se hacen videollamadas y como vive en Ba le gustaría poder hacer de vez en cuanto alguna con su hija.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2024-05-14','miguel, email de Tere Hola¡ Con respecto a la vivienda de los padre de Tomas te paso la última información recibida .. Durante el último seguimiento Pedro reveló haber vendido la casa de sus padres en una notaría a un hombre que le debía dinero, donde, en lugar de recibir un pago monetario, fue compensado con sustancias estupefacientes. Actualmente, carece de cualquier documento que avale esta transacción, aunque disponemos de la dirección de la notaría involucrada: calle Santa Ana en Castuera. ------------------------------------------------------- llamo a la notaria de Castuera y hablo con la notaria Elsa Caballero 924-760707; email emcaballero@notariado.org que me confima que firmó con procolo 3 el 8-1-24 compraventa con pago anticipado en 12 meses a 850€ al mes. Le envío email acreditando la representación legal del tutelado: Buenas tardes Elsa, conforme hemos hablado, te adjunto testimonios de incapacitación, nombramiento y aceptación de cargo de tutor por la Comisión Tutelar de Adultos de la Junta de Extremadura. Necesitaríamos nos remitíais una copia de la compraventa para poder hablar con la compradora. Te mantengo informada de lo que vayamos averiguando','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2024-05-14','Ana: Correo de Ana Castillo, TS Fundación Autismo Sur (teayudamos@autismosur.es): "me puse en contacto con la sección económica e hicieron el trámite de manera inmediata. Ale bien, esta tarde tenemos la sesión con el especialista y en cuanto tengamos informes te los hago llegar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2024-05-15','Ana: Envío correo a la secc. ecca.: "...esta factura habría que abonarla a la mayor brevedad, pues Carlos lleva varias semanas ilocalizable sin teléfono y, porfa, confirmad a Mamen, Educadora de FUTUEX, cuando esté abonada, pero sólo a la dirección que os indico: tienzanavarromamen@gmail.com..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='COMENDADOR'and apellido2='GARCIA'),'2024-05-14','Ana: Correo de Lourdes, Secc. Ecca. a Alberto, con copia a mí: "He estado hablando con María, hermana de Juan. • La COMUNIDAD DE REGANTES, hay que seguir pagándolo, es un pago de las tierras. • IBERDROLA- es de la vivienda de Peraleda de la Mata, no vive nadie, ni se espera que vaya a vivir, se puede dar de baja. • Me dice que Juan Comendador, piensa que es dueño de la totalidad de la herencia de sus padres, tierras y vivienda, pero la realidad es que sus padres le dijeron que mientras viviera allí, nadie le podría echar. • Los herederos que son 4 con él, ( JUAN, MARIA, OTRO HERMANO Y LOS SOBRINOS DE UN HERMANO FALLECIDO.), todos menos JUAN, quieren venderlo todo, pero dicen que es imposible porque se cree dueño de todo. • Del dinero que le ingresa Alejandro Zamora Garcia por encargarse de las tierras, y además la usa en beneficio suyo, dice su hermana, que eso habría que repartirlo entre cuatro. • Que todos los gastos de la vivienda le aparecen a él, por que es el que estaba viviendo allí."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='COMENDADOR'and apellido2='GARCIA'),'2024-05-15','Ana: Respuesta de Alberto: "LOURDES: DAMOS DE BAJA IBERDROLA...SI HAY PROBLEMAS X TITULARIDAD CONTRATO (QUE ESTÉ A NOMBRE PADRE/MADRE) Y NO PODEMOS, SE AVISA A HERMANA X SI QUIERE GESTIONAR ELLA LA BAJA PK EN UN PERIODO RAZONABLE, VAMOS A DEJAR DE PAGAR." ······················· Correo de Alberto al S. Jurídica: "AREA JURÍDICA: OS REMITO CORREO ELECTRÓNICO CON EL RESUMEN QUE NOS TRASLADA HERMANA DEL TUTELADO EN RELACIÓN CON UNA POSIBLE HERENCIA...NO INDICO QUE SE GESTIONES...ÚNICAMENTE PARA QUE TENGAIS CONOCIMIENTO" ················· Respuesta de Ángel, A. Jurídico: "En relación con la herencia de los padres de Juan, él y los hermanos la aceptaron en escritura pública en el año 2011. De Juan Comendador García, hemos solicitado asistencia jurídica gratuita para vender las siguientes fincas: o 25% de plaza de garaje en la c/ Cadenas 28 de Peraleda de la Mata (Cáceres), referencia catastral 9544239TK8194S0001PL. o 25% de vivienda en la c/ Cadenas 30 de Peraleda de la Mata (Cáceres), referencia catastral 9544240TK8194S0001GL o 25% de fincas rústicas de Peraleda de la Mata (Cáceres), referencia catastral 10143A502001810000RK y fincas registrales nº 3.994 y 3.995"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2024-05-15','Ana: Tras hablar con Mariángeles, TS HCC, y con Maite, Jefa CTAEx, envío correo a Soraya y Maite: "Estoy cumplimentando la solicitud de dependencia para Julia Morón Hernández, pero estos son los informes de salud que me han enviado. Yo creo que no van a valorarla o si la valoran (pues sí hace 2 años de la solicitud anterior) no creo que dé grado. Ojalá me equivoque. Con respecto centro de discapacidad, también lo voy a solicitar, pues no quiero que desde el Gabinete de la CTEAx quede ninguna opción sin tocar, que por otra parte, viendo el Informe de Salud, sé que hay motivo de exclusión. En cuanto a la situación actual de Julia, viene reflejada en el Informe Social que aporta también la compañera del SSASB de Cilleros: vive con el padre, quién por su edad y estado de salud, además de por la patología que presenta Julia, no la puede atender. La madre, además de ser mayor y necesitar atención, ha claudicado y se ha marchado a casa de su otra hija. Julia estuvo hospitalizada más de mes y medio en el Hospital San Pedro de Alcántara, en UCI la mayor parte de este tiempo, por "... insuficiencia respiratoria grave secundaria a neumonitis química por broncoaspiración de carbón activo en el contexto de administración del mismo tras intoxicación medicamentosa con ideación autolítica" Adjunto informe también. La situación es cada ves más insostenible, acude casi a diario al hospital de Coria, haciendo uso inadecuado de los servicios de urgencia y ambulancia. Allí, una vez valorada, tranquila, no encuentran criterio clínico ni para ingreso en dicho hospital ni para derivación al Hospital San Pedro de Alcántara para que valoren ingreso en la UHB y le dan el alta. Voy a llamar ahora a la Médico de Cilleros, que al parecer quiere hablar también conmigo, pues no entiende que no se le encuentre centro a esta persona. Nadie entiende que a día de hoy no cumple requisitos de ingreso para ningún recurso. He llamado a Marisa, TS de Salud Mental también, pero no he conseguido contactar. Soraya, ¿sería posible convocar una Subcomisión? Yo sinceramente no sé qué más hacer. Pues tampoco ve nadie la necesidad de activar el 112 para valoración de ingreso en UHB… se lo diré a la médico que quiere hablar conmigo pero en el hospital no lo han contemplado." ····························································································································································································· Llamo a Toni-Futuex, intentarán cambiar la agenda de Clara, nueva Ed. zona de Coria, para que mañana acompañe a Julia a la cita de Enfermería de Salud Mental. Aprovecharán para intentar hablar con el Psiquiatra y con Marisa, TS, para posible derivación a UHB o proponer convocar subcomisión. ································· Informo a Esther, TS Cilleros y Mariángeles, TS HCC (mangeles.ramosg@salud-juntaex.es)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2024-05-15','TERESA ENVIO SOLICITUD DE VALORACION DE DEPENENCIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2024-05-07','Ana: Reenvío correo de Estrella Durán, TS CSS, a A. Jurídicos: "Cristina (T.S. de URA) y yo vamos a participar como ponentes en unas Jornadas de Salud Mental y nos gustaría hacer entrevistas a varios pacientes, entre ellos Martín Domínguez Palencia tutelado por la CTA. Supongo que tenemos que pedir permiso, no?" ···································· Respuesta de Miguel: "Buenos días se trata de una curatela que todavía no ha sido revisada sus medidas de apoyo conforme la actual ley 8/21. Basta con la firma de él a la propuesta desde el centro de participar en dichas jornadas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='OSCAR'and edp.apellido1='BLAZQUEZ'and apellido2='PEREZ'),'2024-05-15','Ana: envío a Cristina Hdez., TS del CSS el Certificado de Discapacidad para poder ser usuario del PADDI.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISMAEL'and edp.apellido1='LOPEZ'and apellido2='IGLESIAS'),'2024-05-15','-Me llama Fernando , TS de C.S. Ciudad Jadín. Está en Ctro peniteniario y saldrá en breve , un voluntario ha preguntado por él . Estuvo antes de la incapacitación viviendo en un coche detrás del Ctro. Salud , por O. de alejamiento de los padres. Ha estado allí un par de veces para ver cómo podía desbloquear la cuenta bancaria.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='AVILA'and apellido2='FEMIA'),'2024-05-15','Ana: envío a Toni-Futuex: "Adjunto: - Solicitud del Servicio a Domicilio - Autorización de cargo en cuenta del servicio municipal de comida a domicilio Para que lo lleven las compañeras al Ayto. de Aliseda y lo registren allí directamente. Porfa, enviarnos después copia, si es posible."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2024-05-16','Ana: Recibimos RESOLUCIÓN de la REVISIÓN DEL GRADO DE DISCAPACIDAD de la Delegación Territorial de Inclusión Social, Juventud e Igualdad de Málaga. Le reconocen un grado del 94 %, desde el 16/04/2021. ························ Guardo en el expte. digital y lo envío a Ana, TS Autismo Sur para su expediente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2024-05-16','Ana: Envío a Paulina Navarrete (paulina.navarrete@salud-juntaex.es): "Adjunto para remitir por REGISTRO a la UNIDAD DE GESTIÓN DE ACCESO Y VALORACIÓN DE DEPENDENCIA, la siguiente documentación relativa a Dª. JULIA MORÓN HERNÁNDEZ, cuyo cargo ostenta la CTAEX: - Solicitud de revisión/valoración de Dependencia - Anexo II: Informe de Salud - Hoja de Tratamiento Médico - Informe de alta del Hospital San Pedro de Alcántara - Anexo IV: Informe Social - Documentación relativa a la Representante Legal: o DNI o Decreto de nombramiento de Directora Gerente del SEPAD o Resolución de delegación de funciones de Presidenta de la CTAEx El Código del buzón de registro para Revisiones de GRADO: A11032816" ····································································································································· Envío a la Adtvo. del ESM - Coria (juanamaria.morcillo@salud-juntaex.es): "Tal y como he hablado con Marisa, TS del Equipo de Salud Mental, te envío adjunta: - la solicitud de Informe del Servicio de Psiquiatría de los últimos seguimientos realizados a Julia Morón Hernández. - Copia de DNI de Julia - Copia del DNI de la Representante Legal - Decreto de Nombramiento - Resolución de delegación de funciones" ······························································································································································································· Envío a Paulina Navarrete, Adtvo. UD. PPAA (paulina.navarrete@salud-juntaex.es): "En relación a Dª. JULIA MORÓN HERNÁNDEZ, cuyo cargo ostenta la CTAEx, adjunto la siguiente documentación, para remitir a la GERENCIA TERRITORIAL de Cáceres. Plaza Hernán Cortés, 1. CP: 10001 – Cáceres, no tengo el número de buzón, espero que no tengas dificultades para encontrarlo, - Solicitud Admisión en Centro Att. Personas con Discapacidad - Informe Médico – Anexo a la solicitud - Informe Social – Anexo a la solicitud – Situación de emergencia - Informe médico de alta hospitalaria - DNI solicitante - Certificado de Convivencia Ayuntamiento de Cilleros - DNI representante legal - Decreto de nombramiento de la Directora Gerente del SEPAD - Resolución de delegación de funciones como Presidenta de la CTAEx"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2024-05-16','Ana: Correo de Marisa Olivera, TS del ESM - Coria (maria.olivera@salud-juntaex.es // 70841/70858): "El psiquiatra de Julia ya no trabaja en este Equipo desde febrero y no hay sustituto. Había otro psiquiatra y también se ha marchado la semana pasada. Solo hay un psiquiatra que viene a realizar peonadas una tarde a la semana. En relación al informe, si quieres, puedo enviarte el modelo de solicitud y se lo envíes a la administrativa del Equipo. No sé cuándo os podrán enviar el informe. Yo me voy de vacaciones la semana que viene. Desde aquí, en estos momentos, podemos hacer muy poco. Lo siento."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FERMIN'and edp.apellido1='GARCIA'and apellido2='PABLOS'),'2024-04-29','Ana: Correo de Teresa Nogueira: "Buenas tardes, Fermin esta en el hospital no sabemos si le van a tener que ingresar, lo comento por el tema del acompañante, habrá que contratar a alguien, de momento ya se ha avisado a una cuidadora mientras le realizan las pruebas, ya os seguimos informando."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FERMIN'and edp.apellido1='GARCIA'and apellido2='PABLOS'),'2024-05-16','Ana: consulto por mail a Teresa y Amalia si alguna de las dos ha cumplimentado y enviado la DECLARACIÓN DE PNC de 2024.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE BLAS'and edp.apellido1='CAÑAS'and apellido2='LOZANO'),'2024-05-14','Ana: Correo de la secc. ecca. a Juan Manuel, hermano de José Blas, con copia a mí: "Buenos días, se modifica la permanente, será efectiva a partir de junio. Para solventar este mes, se hace una puntual con la diferencia, 450-240= 210€ en esta semana. Sobre lo que pregunta sobre dinero de su madre retenido y otros pagos, pongo en copia a mi compañera Ana, por si me puede indicar algo, ya que no tengo conocimiento sobre lo que solicita."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2024-05-16','Ana: Envío correo al Habilitado Gómez-Bascuñana (gomezbascunana@gmail.com): "Buenos días, se modifica la permanente, será efectiva a partir de junio. Para solventar este mes, se hace una puntual con la diferencia, 450-240= 210€ en esta semana. Sobre lo que pregunta sobre dinero de su madre retenido y otros pagos, pongo en copia a mi compañera Ana, por si me puede indicar algo, ya que no tengo conocimiento sobre lo que solicita."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='VALERO'and apellido2='AGUEDO'),'2024-05-13','Amalia ; escribo a Pilar Salguero , la semana pasada quedamos pendiente que nos dierais la respuesta definitiva para el caso de Regina Reina, si se acepta o no que pudiera permanecer en el piso que gestiona HOFA con plaza privada, abonando Regina el copago de esa plaza. Necesitamos la respuesta para poder valorar todas las alternativas posibles, si en Junio tiene que dejar su plaza actual en el piso, como nos habéis transmitido. Con respecto a Natalia Valero, te confirmo que tiene un 42% de Grado de Discapacidad y no ha dado ningún grado de dependencia. Por lo tanto, la plaza de la red de discapacidad del SEPAD habría que solicitarla por emergencia social. Para ello necesitamos un Informe Social de Natalia en la que se exponga el motivo de dicha emergencia, en este caso, sería la necesidad de que salga del centro de menores de Olivenza donde tiene la plaza actualmente y la imposibilidad de permanecer en ella por el criterio de excepción, que en este caso sería por razones de formación. Quedamos a la espera de recibir este informe para presentar la solicitud. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REGINA'and edp.apellido1='REINA'and apellido2='LARA'),'2024-05-16','Amalia ; escribo a Pilar Salguero y Mayte : la semana pasada quedamos pendiente que nos dierais la respuesta definitiva para el caso de Regina Reina, si se acepta o no que pudiera permanecer en el piso que gestiona HOFA con plaza privada, abonando Regina el copago de esa plaza. Necesitamos la respuesta para poder valorar todas las alternativas posibles, si en Junio tiene que dejar su plaza actual en el piso, como nos habéis transmitido. Con respecto a Natalia Valero, te confirmo que tiene un 42% de Grado de Discapacidad y no ha dado ningún grado de dependencia. Por lo tanto, la plaza de la red de discapacidad del SEPAD habría que solicitarla por emergencia social. Para ello necesitamos un Informe Social de Natalia en la que se exponga el motivo de dicha emergencia, en este caso, sería la necesidad de que salga del centro de menores de Olivenza donde tiene la plaza actualmente y la imposibilidad de permanecer en ella por el criterio de excepción, que en este caso sería por razones de formación. Quedamos a la espera de recibir este informe para presentar la solicitud. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2024-05-16','Ana: Correo de Estrella Durán, TS CSS Plas: "Os informo que Enrique Santos irá de pase a domicilio del 20 al 27 de mayo." ·············· Reenvío a Toni-Futeux, y solicito organicen el seguimiento en el domicilio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MANUEL'and edp.apellido1='CIEZAR'and apellido2='PLAZA'),'2024-05-16','Ana: envío a Javier, TS CSS (javier.rdguezper@salud-juntaex.es): "Adjunto el consentimiento de ANESTESIA LOCAL relativo a JUAN MANUEL CIÉZAR PLAZA, debidamente firmado y sellado por su Representante Legal."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='ASENSIO'and apellido2='GARCIA'),'2024-05-17','TERESA Con motivo del próximo viaje a Lourdes (del 26 de Junio al 1 de Julio) que realizará la tutelada CARMEN ASENSIO GARCÍA, se informa de que el coste total del viaje es de 545€.','2');
