insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA REMEDIOS'and edp.apellido1='LOZANO'and apellido2='MUÑOZ'),'2024-05-20','Amalia : pido a Antonia contrato nuevo y nomina y D. rentas , para comunicarlo a PNC.Hace las declaraciones de renta ella sola , pide cita . Las entrega directamente con la D. tutelar en Badajoz. Apoyo para ayudarla a buscar un alquiler más económico , 475€ al mes va a ser dificil de mantener. Solicita un extra para esta semana y se le va a subir a 50€ semanales la asignación para el próximo mes, ya no le dan los alimentos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MANUEL'and edp.apellido1='CIEZAR'and apellido2='PLAZA'),'2024-05-21','Ana: envío a Javier, TS CSS (javier.rdguezper@salud-juntaex.es): "No sé si habréis recibido la citación en el centro también, pero por si acaso, te traslado petición de mis compañeros Asesores Jurídicos para que, por favor, organicéis acompañamiento: ”Cítese a D. MANUEL CIEZA PLAZA a fin de que el próximo día 10/07/2024 A LAS 11:00 Horas acuda a reconocimiento médico forense en la sede de los juzgados de Plasencia”','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2024-05-21','Ana: correo de ayer de Alejandra, Secc. Ecca., desde ctutelar@: "Ya se ha realizado la transferencia. Adjunto justificante de pago." puso en copia a Mamen, Educadora- Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FERNANDO'and edp.apellido1='FEBLES'and apellido2='GONZALEZ'),'2024-05-21','Ana: en relación al correo de Ángel de ayer: "Ana, si conoces datos de familiares, indícamelos para remitírselos a Abogacía." ··············· Respondo: "Según consta en el Informe Social del CAMF de Alcuéscar más reciente que tenemos (Rendición de 2022): “Posible abandono y/o negligencia durante su infancia, según consta en el expediente.” , “…Carece de apoyo familiar. No mantiene ningún tipo de contacto”."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2024-05-21','Ana: correo de Esther, TS SSASB Cilleros (tsocial@ayuntamientodecilleros.es): "quería comentarte que ayer me dijo Julia que tiene consulta de psiquiatría aquí en Coria el jueves a las 17:00 horas, me comento que ya había solicitado la ambulancia para venir. No obstante a ver si puedo hablar con Clara hoy y que me dice. también comentarte que ahora estaba de nuevo en casa de la hermana, pero ayer a última hora me volvio a llamar y me dijo que su hermana le había dicho que se fuera con su padre otra vez, no se como estará hoy, si tengo un hueco la llamaré a última hora, pero tengo varias visitas esta mañana y no se si me dará tiempo. También quiero hablar con Marisa." ······························································································································································································· Envío a la Adtvo. del ESM - Coria (juanamaria.morcillo@salud-juntaex.es): "¿Podríais por favor corroborarme que JULIA MORÓNI HERNÁNDEZ, cuyo cargo ostenta la CTAEx, dispone ya de Psiquiatra e referencia en el Equipo de Salud Mental y que tiene cita el próximo jueves a las 17 h? Es que Marisa la semana pasada me dijo que aún no había psiquiatra y esta información se la ha facilitado la propia Julia a la Trabajadora Social de su pueblo." ······························· Respuesta de Juana María: "la cita es el 23/Mayo,le llamé yo por teléfono para confirmar la asistencia y lo cogió su madre." "Vienen dos Psiquiatras algunas tardes para hacer peonadas, hasta que venga los titulares." ····························································································································································································· Envío correo a Toni-Futuex y Clara, nueva Ed. de Coria (delegadapoyo.coria@futuex.es): "En relación a Julia Morón, me informa la Trabajadora Social de Cilleros, que Julia le ha dicho que tiene cita en Psiquiatría el jueves 23 de mayo a las 17 h. He consultado a la administrativo del equipo de salud mental y me confirma día y hora. Al parecer acuden dos Psiquiatras algunas tardes para hacer peonadas, hasta que haya titulares. No creo que sea viable el acompañamiento al ser por la tarde, pero os lo comunico por si hubiera posibilidad, sería conveniente que alguien le explicara al Psiquiatra la situación actual. Por otra parte, acabo de hablar con Julia madre. Me dice que ayer, de nuevo, Julia regresó a casa con su padre. Esto me temo que va a ser un continuo. Ayer por lo visto llamaron a la Guardia Civil, pero no hubo ningún cambio. Sólo que éstos dijeron que por qué la Junta no hace nada si tiene la tutela… lo de siempre. En relación a la cuestión económica, sabéis que hasta ahora se le hacía transferencia mensual a su madre para que le administrara dinero para gastos de bolsillo (ella dice que le daba 30 € al mes) y el resto para manutención. Puesto que la situación ha cambiado, no me parece lógico seguir haciendo la transferencia a su madre y tengo la impresión de que el padre no se iba a implicar en esto. Por todo ello, quería plantearos la posibilidad de hablar con tienda del pueblo para acordar abonar mediante transferencia las compras que necesite (alimentación e higiene) y abonar mediante transferencia. Acordando, eso sí, un máximo a la semana. Y hacer autorización para retirada de efectivo para otro tipo de gatos. **Para tabaco ya no debería tener, pues tras su ingreso en UCI no debería volver a fumar. *Sería bueno también que se le apoyara en estas compras semanales en caso de llegar al acuerdo con el establecimiento."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2024-05-21','Ana: Correo de Toni-Futuex, del viernes al ctutelar@ con asuntos de varias personas: "Juanjo González lleva tiempo precisando de una revisión de podología, pues tiene un problema en los pies (pies cabos) que requieren de cierto seguimiento para que no le cause demasiado dolor. Dice que lleva mucho iempo sin mirarlo y que le gustaría hacerlo cuanto antes porque muchas veces le cuesta andar (suele cojear bastante), pues además necesita unas plantillas específicas las cuales hace tiempo que no tiene. Se traslada esto a la CTAEX para saber si se podría afrontar este gasto de podología, para pedir presupuestos en caso afirmativo. Por otro lado, también Juanjo solicita un extra para comprar algo de ropa y unas zapatillas para el verano, se calcula que puedan ser aproximadamente unos 100 euros (entre las zapatillas y la ropa). Además igual que en el caso anterior, sus familiares solicitan un extra para poder hacer frente a las salidas de la feria de Cáceres, a la que acude varios dias con sus compañeros." ················· Comunico a secc. ecca. que por mi parte ok a la solicitud','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE BLAS'and edp.apellido1='CAÑAS'and apellido2='LOZANO'),'2024-05-21','Ana: Correo de Toni-Futuex, del viernes al ctutelar@ con asuntos de varias personas: "Solicita extra para feria de Cáceres, que es la ultima semana de Mayo, su madre nos comenta que siempre va con sus compañeros del centro ocupacional casi todos los días que dura la feria, y esto supone un gasto que no puede afrontar ella sola. Además comunican a la educadora que en el mes de mayo hay varios eventos a los que José va a asistir y necesitaría contar con algo de dinero de bolsillo, son los JEDES (Juegos Extremeños del Deporte Especial) además de las ferias de Cáceres a finales de mayo. Para ambos acontecimientos, se ha calculado que pueda necesitar entorno a 80 euros, cuarenta para cada cosa. Por otra parte, también comunican la necesidad de comprar ropa de verano: chaqueta vaquera (sigue utilizando abrigos de invierno), bañadores, pantalones cortos, sandalias, camisetas y ropa interior, además de una maleta (para las vacaciones de verano, organizadas por el centro de Down también) y una mochila (para el día a día, lleva varios años con la misma y está deteriorada). Para todo esto se ha calculado un presupuesto aproximado de 250 euros, y se ha pensado que sería adecuado poder retirarlo junto con el dinero que usará para los eventos anteriormente mencionados, y que su madre los guarde para dárselos cuando llegue el momento, y con la educadora que pueda ir a comprar la ropa. En total solicitan un extra de unos 330 euros. Se ruega, se estudie, y en función de lo que se considere, si bien se aprueba o por el contrario no se considera se nos pueda indicar para comunicarselo." ························· Comunico a la secc. ecca. OK por mi parte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-05-21','Ana: Correo de Toni-Futuex, del viernes al ctutelar@ con asuntos de varias personas: "...que puede resultar más efectiva es solicitar de nuevo el catering del ayuntamiento, y mientras se reactiva de nuevo este servicio poder hacer la compra con él cada semana, se solicita pueda retirar semanalmente 50 euros extras, como se ha estado haciendo durante dos semanas, se le acompañaria desde el equipo a esta retirada y supervisión en la compra, para invertir los 50 euros en alimentos." ···················· Comunico a secc. ecca. OK por mi parte. ····················································· En cuanto a la propuesta de volver a autorizar 50€/semana para comprar comida mientras se tramita el cáterin municipal, Maite me comunica que Alberto, Jefe S. Ecca. ha dicho que NO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUSTAVO ALFREDO'and edp.apellido1='CASTAÑO'and apellido2='SOTO'),'2024-05-21','Ana: Correo de Toni-Futuex, del viernes al ctutelar@ con asuntos de varias personas: "Se adjunta también la factura de la ropa de Gustavo Castaño Soto, del extra que se solicitó para ropa y que fue aprobado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LEON'and edp.apellido1='LEAL'and apellido2='PEREZ OLAGUE'),'2024-05-21','na: Correo de Toni-Futuex, del viernes al ctutelar@ con asuntos de varias personas: "se adjunta la factura del presupuesto de dentista, para León Leal Perez Olagüe, que solicitó también y fue aprobado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOLORES'and edp.apellido1='MACARRO'and apellido2='CAMACHO'),'2024-05-21','TERESA TELEFONO TS DE SASB 924544368','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2024-04-29','Ana: correo de Lourdes, secc. ecca: "Ya está abonada la factura de acompañamiento del 13 de noviembre de 2023. YA POR FIN… Hablando con Sergio, de la entidad me ha explicado el tema de la comunidad, que él cree que pudiera ser así… • dividen dos comunidades; una por bloque, y otra para todas las 100 viviendas, porque tienen una piscina. Las dos se corresponden con la Calle Donoso Cortés."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LIBERTAD'and edp.apellido1='GARCIA'and apellido2='MARQUEZ'),'2024-05-21','TERESA ME LLAMA MERCEDES DEL PI LLERENA PARA COMUNICARME QUE LIBERTAD SE QUIERE IR A VIVIR CON SUS PADRES EN SU SENTENICA NO PONE NADA QUE LA RENTENGA ACORDAMOS QUE SE MARCHES UN TIEMPO A VER COMO LE VA ANTES DE RENUNCIAR A LA PLAZA ELABORAMOS PRESUPUESTO PARA GASTOS EN EL DOMICILIO FAMILIAR','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='GIRALDO'and apellido2='BECERRA'),'2024-05-21','miguel, envío email a Alberto, y Tere: Buenos días, tras hablar con el juzgado me envían por fax los importes que a día de hoy se deben de la ejecutoria en la que él quedó que iría abonando y ha dejado de pagar. Los importes que se deben a día de hoy son 3.790,23 € en concepto de responsabilidad civil y 3.362,48€ en concepto de costas. Me dice en el juzgado que si queremos fraccionamiento que hagamos una propuesta y la enviemos al Juzgado. Alberto ya nos dices si se puede pagar y cómo para comunicarlo al juzgado. ****************************************** Le han dado el alta el 13-5-24 en la UHB, a la espera que lo ingresen en la UME. Tere va a pedir informe social en ese sentido para comunicarlo al juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-05-21','Ana: Llamada de José Manuel (627 788 797): el viernes pasado presentó en el registro de Edificio Usos Múltiples, la solicitud del CÁTERIN MUNICIPAL. La semana pasada cambió la luz a su nombre y ayer solicitó el Bono Social. ···············','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2024-05-21','Ana: En relación con la situación económica de Montaña, llamo a Rosana, Directora de la Res (699 19 81 86). Tras hablar con ella, llamo a María, hija de Joaquina (871 114 458), pero no obtengo respuesta. ·························································································································································································· Envío correo a Alberto y Lourdes, S. Ecca: "Sólo comunicaros que he conseguido hablar ahora con la Directora de la Residencia, que esta mañana no obtuve respuesta. Entiende la situación, y que nos podrá solicitar ningún extra, pero también entiende a Joaquina, que se lamenta porque no tiene ni un euro en su día a día. Según me informan las compis esta mañana tiene en la cuenta a día de hoy 276,57€, algo más que el mes pasado que tenía -5, pero evidentemente poquísimo. No obstante, puesto que el mes que viene percibirá la paga extra podrá contar con algo más. A ver cómo evoluciona el tema de deudas y si pronto se le puede dar al menos algo. Los acompañamientos a citas médicas ya se están haciendo con Futuex, como indicamos. Lo único, que como bien informó Lourdes, el agua no se puede dar de baja y los abonos de la propiedad (IBI) habrá que seguir abonándolos también… En cuanto a la hija, María, la he llamado en varias ocasiones y no he obtenido respuesta. Así que no he podido plantearle nada ni de la vivienda ni de la herencia, ni de si puede apoyar económicamente a su madre de forma temporal, aunque sólo fuera para gastos de bolsillo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='SOLANILLA'and apellido2='LUJAN'),'2024-05-15','Ana: respuesta de Julia, Coord. Casa Misericordia: "Lo más conveniente es que le hagáis una transferencia y se lo damos nosotros, como ya sabes, el manejo de dinero supone para él un gran problema y seguimos trabajando en ello....." ··············· Lo reenvío a la secc. ecca. para que les hagan la transferencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2024-05-21','miguel, hablo con Carlos Arjona679290698 y me confirman que a nivel nacional no aparece la defunción del padre de Tomás Esteban por lo que va a iniciar el procedimiento de desaparición, para lo cual necesita el nif, el cual solicité yo al ayto de Coria, donde se casó y divorció de la madre de los hnos Esteban Iglesias. Le envío de nuevo todo lo que remiti al Ayto de Coria para que me remitieran el nif sin que hasta la fecha me hayan remitido nada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2024-05-22','miguel, contesto a Carlos Arjona (abogado)juridico@liberalyarjona.com Buenos días Carlos, te adjunto las prorrogas del impuesto de sucesiones de Tomás que presentamos y de la que no hemos obtenido respuesta de la oficina liquidadora de Cáceres, que entendemos competente pues es ahí donde falleció Tomás (hijo). Como sabes de la otra herencia (la de la abuela firmada en Coria y de cuyo desbloqueo bancario se está intentando encargar Asesoría Sanchez de Coria, que ha unificado los trámites para los hermanos de Tomás (hijo): Soledad, y José Manuel (cargo de tutor-curador representativo por esta Comisión) y Máxima (cargo ostentado desde la fundación Promi de Córdoba). Echa un vistazo y si crees que podemos liquidarlo y puedes encargarte tú o a través de alguna asesoría de ahí previo presupuesto dimelo y te enviamos lo que necesites. Paralelamente ves preparando la demanda por desaparición, y envíame en cuanto tengas todo los datos del procurador para que nuestra representante, la Gerente del SEPAD, vaya al juzgado de Mérida para hacer el poder apud acta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2024-05-21','miguel, recibo email de Carlos Arjona (abogado)juridico@liberalyarjona.com Se puede prorrogar 6 meses más la presentación del impuesto, siempre que se pida 1 mes antes del vencimiento. Pero más no se puede prorrogar. En cualquier caso, el impuesto yo creo deberíamos liquidarlo con lo que tenemos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2024-05-22','TERESA Buenas tardes Teresa, muchas gracias por la documentación, en principio Elena Durán ingresará en nuestro centro el jueves, si no hay cambios hasta entonces. He pensado que si vemos que se adapta (esperaremos unas semanas) podríamos pedir para que ocupe plaza de Residencia de Apoyo Extenso, creo que igual si lo solicitáis vosotras puede ser más rápido, ya que en un año cumple 60 años y no podría tener acceso a este tipo de plaza. No sé que te parece, de todos modos hablaríamos más adelante, cuando veamos como se adapta al centro y si no decide irse de nuevo a su casa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='GARCIA'and apellido2='MORENO'),'2024-05-22','Ana: Correo de Toni-Futuex: "Por una casualidad, teneis la hoja de cita de nefrología de M Pilar García Moreno, para el 22/05/2024 a las 13:00 en el Hospital San Pedro de Alcántara?? Ya sabemos que no es lo normal, pero por si acaso, desde nefrofologia os dieran seguimiento de estas citas, por el tema de la dialisis. Es que la educadora está intentando que Abraham se la envíe para saber concretamente que consulta es y que no pase como la última vez que no supo explicarselo y llegaron ellos antes y entraron solos. Y es que eso es justo lo que queremos evitar, ya que tienen pensado ir a las 12:00 siendo la consulta a las 13:00, y nos resulta un poco extraño en ellos irse con tanto tiempo de antelación. No obstante la compañera se va a ir a esa hora, e intentara por todos los medios hablar con la nefrologa, porque tenia pedida una analitica de 24 horas de orina, para esta consulta, que Abraham no ha pedido .. porque estuvieron el otro dia en urgencias y segun el, "ya le habrian hecho pruebas" , tenemos por lo tanto bastante interes en comunicarle todo esto, pero ya sabes lo complicado que es intervenir con Pilar con las injerencias dle hijo." ··························································································································································································································································· Llamo a la Dra. Sandra Gallego, Nefróloga del HSPA (56274): no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='INOCENCIO'and edp.apellido1='MARTINEZ'and apellido2='NOVAS'),'2024-05-22','TERESA fallecimiento se produjo el viernes día 17 de mayo 2024','2');
