insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='MOLINA'and apellido2='VAZQUEZ'),'2024-05-22','Ana: Javier Rodríguez, TS del CSS-Plas. (javier.rdguezper@salud-juntaex.es), nos remite factura-ticket del calzado comprado para Francisco ya pagado en efectivo, para archivar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2024-05-22','Ana: Javier Rodríguez, TS del CSS-Plas. (javier.rdguezper@salud-juntaex.es), nos remite factura-ticket del calzado comprado para José Luis, ya pagado en efectivo, para archivar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='AVILA'and apellido2='FEMIA'),'2024-05-22','Ana: Guardo en el expediente el correo de seguimiento remitido por Toni-Futuex. José Luis asiste sin problemas a las revisiones de enfermería y toma la pastilla del corazón. No así la que le han recetado en Psiquiatría. Lo verbalizó en la última consulta en Salud Mental al Dr. Goenaga, quién le recomendó que la tomara. ·················· Próxima consulta en 2 meses.················ En el correo añaden: "Durante estos últimos días que se han realizado seguimientos en la localidad, se ha podido percibir que el entorno acepta con bastante normalidad la presencia de José Luis, incluso con afecto, muchas personas lo interpelan en la calle, cuando va con la educadora, para interesarse por como se encuentra y mostrar su intereses hacia él. En las visitas realizadas hasta el momento no se ha detectado la alarma social que se esperaba en un principio. También influye que José Luis mantiene un comportamiento bastante normalizado y estable, no se podría decir que está socializando (ya que no creemos que sea uno de sus focos de interes) pero en los momentos que utiliza los recursos comunitarios no tiene problemas para relacionarse y desenvolverse con normalildad."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2024-05-22','Ana: Llamada de Miguel Ángel (658 544 068), ayer salió del C. Penitenciario de Ba, aquí no habían comunicado nada. ······ *Dice que antes de salir, en la garita, le dijeron que tenía un quebrantamiento de abril de 2023, pero que no sabe de qué. ············· Ahora está en la estación de autobuses, porque se va a su pueblo, Aliseda, a ver a su madre (la orden de alejamiento expiró en marzo de 2024). *Va a solicitar a sus familiares que le dejen quedarse en "LA CASILLA", tiene luz y agua. ············· Activaremos de momento la AUTORIZACIÓN para retirada de efectivo de 80€/semana, tal y como tenía antes de su ingreso en C. Penitenciario, en la Oficina de Aliseda, Pza. Extremadura nº 13. ·········· Acudirá al C. Salud para que le asignen MAP y para que le deriven al ESM. ······························································································································································································ Envío correo a Alberto, Secc. Ecca. y a Maite, para que esté al corriente, solicitando envíen AUTORIZACIÓN DE RETIRADA SEMANAL de 80€ en la oficina de Aliseda, para retirar a partir del próximo lunes 27. ····························································································································································································· Envío correo a Toni-Futuex, exponiendo la nueva situación y: "Solicitamos: - Retoméis las visitas de seguimiento a partir de la semana que viene. - Si es posible, y finalmente se queda a vivir en Aliseda, le acompañéis/apoyéis a realizar las siguientes gestiones: o Solicitud de servicio de comedor municipal (después si es necesario se reajustará la asignación, él cuenta ya con ello) o Le asignen médico de atención primaria en el centro de salud y que éste le derive al ESM para retomar su seguimiento (Él tuvo en su día seguimiento con el Dr. Goenaga, y a principios del año pasado le atención la Dr. Cristina Donoso."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOLORES'and edp.apellido1='MACARRO'and apellido2='CAMACHO'),'2024-05-24','TERESA ACORDAMOS HACER LIMPIEZA EN VIVIENA Y HACERLA EN DOS PAGOS JUNIO Y DICIEMBRE CON LA EMPREA LIMPIEZA EXTREMA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2024-05-24','TERESA M antonia ha ingresado en el hospital santiago de Zafra, ocupa plaza privada y hay que pagarla por transferencia Adjunto datos bancarios Coste de la plaza El 75% de su pensión asciende a 388,42€ (pagar a partir del mes de junio) Hay que hacer autorización para dinero de bolsillo de 50€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2024-05-28','Ana: En relación al correo de Toni, le respondo: "En relación a Miguel Ángel Ramos Andrés, te reenvío correo con derivación remitida justo hace un año. Puede ser que en su día no lograseis dar con él. Espero que con la hoja de derivación y el correo con la información de la situación actual, os sirva para comenzar a intervenir. Si necesitas algo más, dímelo." ························································································································································································ Ante el correo de Mª Carmen Rodríguez Gía, TS HSPA - UHB (mariac.rodriguez@externos.salud-juntaex.es): "• El paciente Miguel Ángel Ramos Andrés comenta que le estáis buscando un rr residencial. Necesito conocer la realidad de esta información." Llamo a Mª Carmen (56283): ingresado desde el día 23/05/24. ·························································································································································································· Envío correo a la sección económica: "se trata de ENVIAR AUTORIZACIÓN A LA MISMA ENTIDAD pero a la OFICINA BANCARIA DE CÁCERES: Unicaja Banco Cáceres, C/ Antonio Hurtado nº 2. MIGUEL ÁNGEL RAMOS ANDRÉS finalmente no va a residir en el pueblo en la casita familiar, de momento se quedará en Cáceres. En aproximadamente 2 días le darán el alta en la UHB, donde lleva ingresado unos días, y se quedará en la ciudad de Cáceres. Por favor, en cuanto podáis, enviar la autorización de retirada de efectivo (asignación) a la oficina de la dirección indicada."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2024-05-28','Ana: Ante el correo de Rosana, Res. Amada Corral de Alcuéscar (a.corral@grupociudadjardin.com): "hable con la chica que realizo los primeros acompañamientos de consulta y me confirma que de los tres que realizo solo le pagaron uno." ················· Respondo: "En tal caso, ¿podríais enviarnos de nuevo las declaraciones juradas? Pongo en copia a mi compañera Lourdes, de la sección económica. Lourdes, ser refieren JOAQUINA MAYORAL PIZARRO. ¿Puedes comprobar los pagos, por favor?"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2024-05-28','Ana: Correo de Mª Carmen Rodríguez Gía, TS HSPA - UHB (mariac.rodriguez@externos.salud-juntaex.es): "• Que el paciente Francisco Cacho Garrido, ingresó en la UHB del HSPA el viernes 24/5/2024 y será dado de alta esta misma semana." ······························ Llamo a Mª Carmen (56283): ingresó con un episodio hipomaníaco. Aún no saben qué día le darán el alta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2024-05-28','Ana: Envío correo a Cristina Hdez, TS CSS - Plas. (cristina.hernandezca@salud-juntaex.es) con copia a los A. Jurídicos: "Como ves, puedes leer en el hilo, y en el documento adjunto, nos solicitan desde el juzgados “Todos los informes médicos de los que pueda disponer o recabar respecto de D/Dª MARTIN DOMINGUEZ PALENCIA”. Por favor, ¿podrías trasladárselo tanto al Médico Somático como a su Psiquiatra de referencia? Necesitamos que nos los envíen a la mayor brevedad. Gracias de antemano. Pongo en copia a mis compañeros Jurídicos y añado el resto de información que solicitan: - Lugar y fecha de nacimiento: Cáceres - 07/09/1964 - Domicilio: Centro Sociosanitario de Plasencia. Ctra. De Cáceres s/n. CP: 10600 – Plasencia (Cáceres) - Teléfono: Actualmente se le puede localizar en el teléfono del Centro Sociosanitario: 927 42 88 00 En cuanto a los familiares, según me confirma el propio hermano, que acabo de hablar con él, sólo son dos hermanos y sus padres ya fallecieron, por lo que no cuenta con más familiares: - Gonzalo Jesús Domínguez Palencia, hermano o Teléfono: 927 23 75 73 // 600 70 22 55 o Fecha nacimiento y lugar: 5/12/1958 – Cáceres o Domicilio: C/Italia nº 31, Cáceres. CP: 10002 o DNI: 06971576T"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2024-05-28','miguel, insistentes llamadas e emails de la hna Belén para que insista en me envíe el borrador de lo que esté haciendo la notaria de virgen de guadalupe, NOTARIA DE DON JOSE CARLOS LOZANO GALAN & DON IGNACIO FERRER CAZORLA & DON CARLOS DEL SOLAR BARROSO TELEFONO.- 927 240 577 / 78. Envié el viernes email a Jordi de la notaria, sin contestación hasta hoy y llamadas a la notaria sin éxito de que me coja el tlfno. Me escribe email JORDI DE ACOSTA REDONDO ext 2017 Adjunto le envío el borrador de la escritura de Toma de posesión de Legado. No está puesta su intervención todavía. Se ha demorado el asunto porque he estado en contacto con la parte que ya firmó la herencia, ya que no hay dinero suficiente en las cuentas para pagar todos los legados. Me han dicho que los herederos quieren garantizar los legados de Belén y María del Carmen, pero claro, en la escritura de herencia han reflejado y repartido las cantidades del banco, por lo que hay que solucionar eso primero. Le iré informando de como avanza. Le adelanto el borrador para que puedan solicitar la autorización judicial. --------------------------------------------- Contestación a Jordi de la notaria: Buenos días, gracias Jordi, pues quedo pendiente de me indiquéis fecha de firma, que en caso de ser por la mañana intentaré ir presencialmente (con la autorización con firma electrónica de la vicepresidenta y gerente del SEPAD Doña Mª Angeles Martinez Lavado (con funciones delegadas de la presidenta Consejera de Salud y Servicios Sociales Doña Sara Espada)o bien ratificaríamos desde la notaria de Mérida de Don Gonzalo Fernández Pugnaire como habitualmente hacemos. ----------------------------------------------------- Recibo email de Belén la hna de la tutelada: Yo cuando llegue le llamo cojemelo y hablas con él hoy lo voy a reglar para que se lo mandé o que me dé una esplicacion el porque no se lo manda cojeme el teléfono Miguel tengo a la una con el notario ******************************************************* Envío email a la hermana Belén Belen Solana chanclon >solanachanclonbelen@gmail.com> Hola, ya me ha enviado el borrador y le he dicho que cuando se vaya a firmar me avise. Dice que está pendiente de saber cómo vais a recibir ese dinero porque la cuenta bancaria ya fue repartida con la herencia. Quedo pendiente de que él me diga la fecha de firma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2024-05-28','Ana: Me llama desde el teléfono de su madre, ayer a pesar de ser el primer día en la Comunidad Terapéutica, por la tarde noche se fue del centro, le acercaron en coche a la estación de autobuses y se fue para su casa. ·············· Ahora dice que tiene intención de acudir al ECA y quiere alquilarse una vivienda en Las Navas del Madroño u otros pueblos cercanos. ··············· Ahora pide 150 €/semana para comida en lugar 100 que tenían autorizado anteriormente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2024-05-27','Ana: Correo de Estrella, S. Ecca: "he anulado la permanente de 40 €/semanal. Y he enviado al banco un reintegro puntual de 80 €. Según correo mas abajo de Ana."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2024-05-28','Ana: Mª Carmen Rodríguez Gía, TS HSPA - UHB (mariac.rodriguez@externos.salud-juntaex.es): mañana le dan el alta a Juan y se vuelve a su casa. Mantiene las mismas ideas delirantes que cuando ingresó. Piensa que es Otorrinolaringólogo y Neurólogo. Su Psiquiatra ha sido el Dr. Derecho. ···· *Le pido que por favor nos envíen INFORME DE ALTA. Dice que lo hablará con el Psiquiatra. ······························································································································································································ Llamo a Clara, TS C. Salud (53107), no obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2024-05-24','Ana: Correo de Cristina Hdez, TS CSS - Plas. (cristina.hernandezca@salud-juntaex.es): "te comunico salida excursión el 30 de mayo del paciente Martín Domínguez Palencia para JORNADAS DEPORTIVAS"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='JIMENEZ'and apellido2='PICON'),'2024-05-28','Ana: Escribo a Toni-Futuex: "En relación al correo que te reenvío de la residencia Parque del Príncipe, te lo reenvío para solicitar, que en cuanto os sea posible, paséis a hacer visita y seguimiento a MARÍA JIMÉNEZ PICÓN, y por favor, os indiquen las prendas de ropa que necesita así como su talla y acudáis a pedir presupuesto a algún establecimiento en que se pueda abonar mediante transferencia bancaria y nos lo hagáis llegar (a la sección económica, por favor) Una vez abonado, como en otros casos, podréis recoger la ropa y llevársela a María."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='DA SILVA'and apellido2='BAUTISTA'),'2020-10-26','Ana: Correo de Toni-Futuex: "Te envio en un informe bastante exhaustivo, con capturas de pantalla y demas imagenes, sobre las quejas públicas en rrss que está haciendo el hermano de Catalina y otros asuntos, y que todo esto fue tratado junto con la ts de la localidad el pasado viernes, por parte de la compañera del equipo de apoyo social comunitario, Gloria, que es quien hace el seguimiento. A la cita del INSS de mañana, está organizado que vaya en bus a caceres y alli se encuentra con la compañera."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='DA SILVA'and apellido2='BAUTISTA'),'2024-05-28','Ana: Envío correo a Toni-Futuex: "Te envío CITACIÓN para RECONOCIMIENTO MÉDICO FORENSE de CATALINA DA SILVA BAUTISTA, para que podáis por favor, organizar el acompañamiento a la misma, que tendrá lugar el 13 de junio a las 12 h." ························ Respuesta de Toni: "ok sin problema, lo anotamos"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='DOMINGUEZ'and apellido2='PALENCIA'),'2024-05-29','Ana: Envío a los A. Jurídicos, los informe médicos facilitados por Cristina Hdez., TS CSS-Plas. ····· Los guardo también en el expediente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2024-05-29','Ana: Envío a Toni-Futuex, correo de Ángel, A. Jurídico: "Te envío Oficio del Juzgado de Instrucción 4, de Badajoz, comunicando la puesta en libertad de Miguel Ángel Ramos Andrés. Tiene obligación de acudir al Juzgado los días 1 y 15 de cada mes y se le prohíbe acercarse a Águedo Carayol González y Alan Pérez Pérez, a sus domicilios, lugares de trabajo y cualquier otro donde se encuentren, a una distancia de 500 metros y prohibición de comunicar con ellos." ············· Y añado que Miguel Ángel está ingresado en UHB.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2024-05-29','Ana: Comunico a Toni-Futuex, el ingreso de Francisco en la UHB. ··································································· Reenvío a Toni-Futuex, correo con citación: "Reenvío correo con citación para la TS del ESM de CC el próximo 3 de junio a las 13:oo h." ························································ Recibo Informe de Alta de la UHB. Le han dado de alta hoy mismo. Guardo informe en el expte. digital y se lo reenvío a Toni-Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2024-05-29','Ana: Envío correo a Alberto, Jefe S. Ecca., con copia a Toni-Futue y a Maite, Jefa CTAEx: "Tal y como hemos hablado: - Hay que DAR DE BAJA la TRANSFERENCIA en concepto de MANUTENCIÓN que se le hace periódicamente a la madre, pues ya no convive con ella y ésta no le está aportando nada. - Hay que hacer una autorización de retirada de efectivo semanal de 70 €, de los cuales 50€ se destinarán a alimentación e higiene y 20 para gastos de bolsillo. (*La cuantía equivale a los 300€ mensuales que se transferían a la madre dividido entre las 52 semanas anuales) Pongo en copia a Toni de Futuex, para su conocimiento y para que, por favor, cuando pueda comunique los datos de las personas que realizará los acompañamiento al banco y a comprar comida a las sección económica (ctutelar@salud-juntaex.es) También pongo en copia a Maite para que esté al corriente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2024-05-29','Ana: Tras reunirme con Alberto, le envío correo con copia a Teresa y Maite, CTAEx y a Toni-Futuex: "En relación a AITOR MORENO FELIPE, tal y como hemos acordado antes: - Se retoma la aportación semanal para gastos de alimentación e higiene: 100 €/semana, en esta ocasión podrá retirarlo ACOMPAÑADO DE LA EDUCADORA que le acompañará a hacer la compra junto con su asignación semanal en la oficina del pueblo (mientras esta siga abierta). AsÍ evitamos problemas con el supermercado de la localidad. - Asignación semanal: 20 € o Por tanto: RETIRADA DE EFECTIVO DE 120€/SEMANA ACOMPAÑADO - Se ha valorado también una transferencia periódica de 50 € a su madre para colaborar en los gastos de mantenimiento y suministros de la vivienda. Estas primera cuestiones se mantendrán mientras Aitor permanezca en el domicilio de la madre. Las retiradas podrán realizarse a partir de la semana que viene (Alberto: habrá que dejar abierta la autorización toda la semana, pues no sabemos qué día abre la oficina bancaria) Por otra parte: - La compañera de Futuex apoyará a Aitor a buscar una vivienda de alquiler en otro municipio a ser posible. Presupuesto a tal fin: Entre 250 y 300 € - En cuanto a la demanda de Felisa, madre de Aitor, de pintar la vivienda, pues debido al elevado consumo de tabaco y otras sustancias por parte de Aitor, las paredes han amarilleado, Toni, os solicitamos, por favor, que cuando sea posible, pidáis presupuesto a empresa/autónomo para pintar la vivienda. Este gasto correría a cargo de Aitor. Toni nos enviará los datos de la Educadora para hacerlos constar en la Autorización Bancaria."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2024-05-29','Ana: En relación a un problema en el brazo que comunica Jesús Manuel por mail (Tendinitis), consulto a Toni-Futuex. ············· Respuesta de Toni: "Se le ha visto esta mañana por este asunto y se ha comprado esta mañana a acudido a cita de consulta médica en Plaza de Argel y que realmente si es cierto que tiene como una tendinitis y que tiene un brazo prácticamente inmóvil, si se ha constado que este asunto médico digamos es cierto y que le incapacita para desarrollar con normalidad actividades de la vida diaria. Como al médico ha acudido solo, se ha pensado en todo caso, solicitarle una cita telefónica, por si pueden emitir una nota con el diagnostico y tratamiento y demás. Mientras se ha acudido a la farmacia, donde se adjunta la medicación que ha retirado ya (antinflmatarios y su medicación antipsicotica) la medicación no le ha costado nada, por sus coberturas. Pero el solicita un extra, digamos para paliar este estado de relativa incapacidad en la que se encuentra , es decir, no puede por ejemplo cocinar o hacer determinadas cosas en casa, asique utilizaria este dinero para por ejemplo comprase algun plato de comida preparada o cosas de este tipo. Incluso indica, que consume tabaco para entubar y que con el brazo asi, le cuesta poder hacerlo que tambien tiene que comprar tabaco ya entubado..... A ver, sabemos que frecuentemente puede hacer demandas económicas, pero es cierto que la circunstancia de dolor y dificultad para mover el brazo en este caso, si la hemos podido constatar. Por lo tanto si se considera viable, solicitamos se pudiera estudiar, el que tuviera alguna cantidad que se considera extra en su asignación para almenos la próxima semana, mientras vuelve a tener otra movilidad en ese brazo,." ······················································································ Finalmente: Se autoriza 50€/semana para gastos de alimentación, pues no puede cocinar con el brazo así. Lo retirará acompañado de la Educadora, quien le acompañará a adquirir los alimentos. ···· Nieves Villaverde es la Ed-Futuex de referencia y quien le acompañará a retirar el dinero. ··········· Se facilitan los datos a la S. Ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2024-05-29','Ana: Envío correo a la secc. ecca.: "Os reenvío correo de la residencia Amada Corral, Alcuéscar, relativos al cobro y regularizaciones de la plaza residencial de JOAQUINA MAYORAL PIZARRO."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2024-05-29','Ana: Comunico a Toni-Futuex por mail el alta de Juan Chamorro (correo con varios). ···························· Llamo a Clara, TS C. Salud (53107), no obtengo respuesta. ····························································································································································································· Guardo en el expdiente digital INFORME DE ALTA DE LA UHB, remitido por Mª Carmen, TS HSPA (mariac.rodriguez@externos.salud-juntaex.es).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='POZAS'and apellido2='GOMEZ'),'2024-05-30','Ana: Javier, TS CSS (24205), comunica que esta madrugada (1:45 h) ha FALLECIDO Ángel. Lo han comunicado a la familia y ésta quiere enterrarlo en su pueblo Valverde de la Vera. *No consta seguro de decesos, pero cuenta con recursos económicos más que suficiente para abonar el traslado del cuerpo y el sepelio. ······················ Contactan con la Funeraria desde el centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2024-05-30','miguel, tras recibir varios emails de la hermana Belén, entre otro preguntando por nuestra solicitud de autorización judicial, envío email a Jordi,jaredondo2@despacho.notariado.org Buenos días Jordi, he intentado localizarte sin éxito vía telefónica. Me comenta Belén que ya se firmó ayer la escritura. Necesitáis que hagamos algo desde la Comisión Tutelar de Adultos?. No sería necesario solicitar autorización judicial al tratarse de la firma de un legado, y entiendo que tampoco necesitáis sea ratificada la escritura por la Comisión Tutelar de Adultos. Necesitaría saber finalmente cómo va a recibir su parte Maria del Carmen, se le va a ingresar en su cuenta? Cuando puedas contéstame al respecto. Si hay que abonar algo puedes remitir la factura de la parte de Maria del Carmen al email ctutelar@salud-juntaex.es para su abono.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='AVILA'and apellido2='FEMIA'),'2024-05-30','Ana: Envío a Juan Carlos, Adtvo (juancarlos.cano@salud-juntaex.es): "Adjunto la siguiente documentación, relativa a D. José Luís Ávila Femia, cuyo cargo ostenta la CTAEx: - Oficio – comunicación ERROR ENTIDAD BANCARIA - Nuevo Alta de tercero para remitir por registro a la Secretaria General de Servicios Sociales, Inclusión, Infancia y Familia ; Dirección. C/ Antonio Rodriguez Moñino. DIR3 A1103010." ·········································································································································· Envío a Alberto, Jefe Secc. Ecca: "En relación con JOSÉ LUÍS ÁVILA FEMIA, puesto que parece que está funcionando en domicilio desde el alta de la UHB y por tanto, de momento al menos, no va a ingresar en centro, hay que establecer una asignación para su manutención, consideramos que debe ser quincenal. Finalmente no hemos podido verificar el precio exacto del Servicio de Cáterin pero rondan en torno a 150€/mes. De todas formas como la idea es ajustarlo a días sueltos y no toda la semana lo iremos viendo. En principio calcula la asignación en torno a eso. Por favor, intentad que pueda ir a retíralo el lunes y COMUNICA LA CUANTÍA A FUTUEX: Nieves delegadapoyo.caceres2@futuex.es y Toni: areasocial3@futuex.es"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SONIA'and edp.apellido1='VALCARCEL'and apellido2='VIDAL'),'2024-05-22','miguel, datos del abogado Juan Pablo Serrano Muñoz email 3116@icaba.com, la procuradora Maria Nieves Torres Mata, numero 234 del colegio de procuradores de Badajoz','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2024-05-17','Ana: Correo de Javier, TS CSS-Plas, en relación al acompañamiento al Juzgado: "Precisamente hoy se ha organizado. Le acompañará Futuex y está pedido el transporte para la ida y vuelta."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2024-05-30','Ana: Escribo Ana, Directora Res. Mayores (anatdelat@hotmail.com): "Sólo comentarte que volví a comentar con Alberto, Jefe de la Sección Económica, la posibilidad de subir la asignación a Isabel los 25 € que ella pide, pero me da literalmente esta respuesta: “NO ES VIABLE LA SUBIDA...EN CASO DE SUBIR EL REINTEGRO EN 25 €/MES (ACTUALMENTE TIENE 100 €/MES)...LA EVOLUCIÓN SALDO SERÍA NEGATIVA...EN ÚLTIMOS 12 MESES: - 432 € (EN CASO DE AUTORIZAR SUBIDA REINTEGRO SERÍA UN DESFASE MÁS IMPORTANE). INGRESOS: PNC 608,30 €/MES X 14 GASTOS: • CENTRO: 461,29 €/MES • REINTEGRO (INCLUYENDO EXTRAS): 122 €/MES ---- REALMENTE NO SE ESTAN RESPETANDO LOS 100 €/MES. • FARMACIA: 51 €/MES ---- HA SUBIDO MUCHÍSIMO EN LOS ÚLTIMOS 12 MESES. • OTROS (DECESO, TAXI, OTROS...): 55 €/MES. • TOTAL: 689,29 €/MES” Sí que es cierto que Isabel tiene ahorros, por lo que se podrían asumir gastos extraordinarios puntuales, así que esos podría solicitarlos (para ropa, taxis u otras cuestiones) pero a él le da miedo tirar mucho de los ahorros porque cuando hacen falta hacer acompañamientos hospitalitos, por ejemplo, supone un gasto muy elevado y sólo contamos con lo que cada cuál tiene en su cuenta, la CTAEx no tiene partida presupuestaria para asumir absolutamente nada. Pongo en copia a Clara, educadora del Programa de Apoyo Comunitario para que esté al corriente y también pueda abordar esta cuestión con ella."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2024-05-30','Ana: Alejandra, S. Ecca. me comunica que desde el 25 de marzo están ingresando en la cuenta de Mª Ángeles su pensión y la de su hermano José Luis ············ Llamo a Marina Carmen Cintas, Jefa Secc. PNC (924 00 59 22): No obtengo respuesta. ··········· Llamo a María Bueno, TS PNC (66031): me indica que mejor lo hable con Marina Carmen, que es algo que ha hecho ella.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2024-05-30','Ana: Comunico a Clara, TS C. Salud (53107) que ayer dieron el Alta a Juan. Dice que no lo entiende, que estaba fatal. Se lo comunicará a Adolfo, Médico. ··················· *Cuando tengamos informe de Alta de la UHB, se lo comunicaremos al Juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='GARCIA'and apellido2='RAMIREZ'),'2024-05-30','miguel, envío email a la parte económica con copia a la social, Alberto y Amalia: Buenos días Alberto, te reenvío la modificación en contrato de arras indicando el importe de la señal de 3.000€ y la cuenta en que abonarlo ES2401824499740201585689. Parte económica haced por favor la transferencia a esa cuenta con el siguiente concepto: contrato señal compra vivienda finca nº 33639. ********************************************* email de la hna Marisol a la asesoria Buenos días, Agustín, afernandez@moraferasesoria.com Tal y cómo hemos comentado telefónicamente, aceptamos el presupuesto que nos envió 26/10/23 y que hoy nos ha confirmado el total de 10.934,00 € . Por nuestra parte, damos conformidad al último contrato de Arras recibido para que sea firmado la próximas semana y damos orden a la comisión tutelar para que emitan transferencia bancaria mañana 01.06.2024. Pongo en copia a Miguel Fernandez de Llera , asesor jurídico de la comisión tutelar. Estamos en contacto para las próximas gestiones hasta la firma de las escritura. Muchas gracias, Marisol García Ramirez Tfno. 618 75 61 39 ************************************** email de Marisol: Buenas tardes Miguel, Adjuntamos nuevamente el contrato de Arras recibido por parte del Vendedor ampliando la información que solicitabas. Si por vuestra parte lo veis correcto, Jose Antonio firmaría el día 07.06.2024 y se debería emitir transferencia bancaria el día 10.06.2024. Gracias por confirmar, Marisol Garcia Ramirez ****************************************** email del vendedor a la hna Marisol juanmiguelcontador@gmail.com> Buenos días, Marisol. Te reenvío contrato de arras, con las siguientes modificaciones: • Identificación de la cuenta bancaria del vendedor. • El concepto de transferencia “como pago a cuenta y en concepto de arras o señal” se encontraba recogido en el párrafo primero, segunda cláusula. • Se incluye, en el citado párrafo, la fecha de la transferencia y en el encabezado la fecha de la firma. Pudiéndose adelantar o atrasar, una vez que la Comisión inste a la entidad bancaria a hacer la transferencia, a no ser que tengan que indicar una fecha concreta. Y adjunto: 1. Certificado Titularidad de la cuenta. 2. Justificante, cargo por adeudo, del pago de la cuota de la comunidad del mes de mayo. El Certificado de Eficiencia Energética, se encuentra en trámite, se suele entregar en notaría, igualmente que el Certificado de la comunidad de vecinos de estar al corriente con la comunidad, en notaría exigen fecha del mes de la firma. Sin otro particular, quedamos a la espera de la conclusión de la Comisión Tutelar. Un saludo. Juan Miguel Contador Aragüete 620 847 630 ******************************************** email de Marisol: Buenos días Miguel: Me indican lo siguiente desde la comisión tutelar: "Falta por identificar la cuenta bancaria del vendedor, concepto de transferencia, titularidad de la cuenta, y fecha en que ha de estar hecha la transferencia (ya que desde la Comisión se instará a la entidad bancaria a hacer la transferencia, la cual puede ser que no lo tenga hecho en el mismo día) e incorporar certificado energético y certificado de la comunidad de vecinos de estar al corriente con la comunidad, que lo pedirá la notaría. En cuanto modifiquen y nos envíes el contrato de arras para lo remitimos a la parte económica Gracias por enviar documento corregido y los documentos que nos solicitan, Quedamos pendiente,','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2024-05-31','miguel, me llama el abogado Javier Lozano, 980-516824 de todos los hermanos menos uno porque están tramitando la venta de la vivienda de tíos, y padre de Enrique. Le comento que no dispone de capacidad económica para contratar y gastos de venta. Me dice que quitando los honorarios del procurador lo demás se podría abonar tras la venta (gastos de abogado y trámites que le corresponda al curatelado) Parece ser que es una vivienda en Ledesma que ha sido valorada ya por hacienda, que ha sufrido desprendimiento de parte del tejado y techo, con la consiguiente disminución de precio que ya se verá. Le he dado el email para que comience enviandome el presupuesto del procurador. Envío email a la parte económica y social para informar de que vamos a contratarle y saber el saldo a fecha de hoy para cuando haya que pagar al procurador.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2024-05-31','TERESA Como sabéis ayer, ingresaba Aitor en CT, se desplazó desde el sociosanitario de Plasencia, entendemos que desde allí se informó de todo. Pues nada que el tema es que hoy está en Navas del Madroño. Ayer cuando llegó al centro, le dejaron irse. En una comunidad terapéutica, si no estas dispuesto a rehabilitarte , pues obviamente te dejan marchar. El caso es que es desesperante. Es un circulo vicioso. Felisi, al parecer que ha sido quien ha informado está fatal... es incapaz de no permitirle estar en su casa, aunque es su mayor tormento. En este sentido le comenta a la compañera que Ana, le ha comentado que se puede ir a vivir a otro sito buscarse otro alquiler?? nos ha parecido extraño, porque sabemos que está fatal de dinero y ademas que la casa es de proteccion social y si se va suponemos la perderia, pero por estar seguras de que no existe otra posibilidad. En este sentido y dado que la convivencia con ellos ya sabemos que no puede funcionar, seria factible que Aitor viviera en otro lugar de alquiler?? no sabemos tampoco si es viable esto.. O si hay que comunicar al juzgado algo o lo que sea. Cualquier cuestión o plan de actuación que se vaya a plantear, estamos a dispoción. Saludos!','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2024-06-03','miguel, recibo email de Belen la hermana: Ya lo he mandado al correo que me ha puesto y si hay que abonar por la escritura eso te lo dirá el Yordi como debes hacerlo y el dinero el banco de la Caixa bank de Cáceres al lado de Eroski por el hotel Extremadura también deberéis ir al castrazto para la mitad de la casa de la calle corte que te lo esplique Yordi el teléfono del banco no me lo sé si no te lo facilitaba pero está por el hotel estremadura un saludo Miguel y al final podemos solicitar la herencia para sus hijos si se puede --------------------------- Email a Jordi de la notaria con copia a Belen: Me comenta Belén que ya se firmó ayer la escritura. Necesitáis que hagamos algo desde la Comisión Tutelar de Adultos?. No sería necesario solicitar autorización judicial al tratarse de la firma de un legado, y entiendo que tampoco necesitáis sea ratificada la escritura por la Comisión Tutelar de Adultos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN PABLO'and edp.apellido1='ESTEBAN'and apellido2='CORRAL'),'2024-06-03','TERESA Esteban Corral (pendiente cobrar Orfandad, solo tenía PF) ESTE SI APARECE UNA NUEVA PENSION DE 877,60€ ADEMAS DE LA 705,80€ QUE YA TENÍA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANASTASIO'and edp.apellido1='VAQUERIZO'and apellido2='PIZARRO'),'2024-06-03','TERESA Referente a la vivienda de Anastasio, en la gestión presencial respecto a las humedades de la vivienda que se realizó junto a Jorge Hermosa, aparejador, se recogió la siguiente información: La vivienda se encuentra en muy mal estado, tiene muchas humedades, el techo en mal estado por donde se filtra el agua y las paredes que dan para la vecina son las que se encuentran en peor estado, se nota la filtración del agua. Jorge Hermosa nos indica que hace muchos años, cuando Anastasio le vendió a su prima la parte trasera de la vivienda, no se realizó segregación del terreno y eso podría ser un problema a la hora de la venta. Su prima ahí realizó una cochera. Dadas las condiciones en las que se encuentra la vivienda y los problemas que ocasiona a la vivienda colindante, Jorge también nos mencionó valorar la posibilidad de poner en venta la vivienda o realizar una hipoteca inversa. Comenta que su empresa compra viviendas viejas y deshabitadas en el pueblo para después reformarlas y venderlas. A fecha de hoy, Jorge Hermosa nos contacta para indicarnos que tiene a unas personas interesadas en la compra de la vivienda, nos habla de la posibilidad de compra Entre 30.000 y 35.000€. Estamos a espera que nos envíe el informe y la factur del mismo con los datos de Anastasio. Son 150€ + IVA. el teléfono de contacto de Jorge Hermosa es: 656610205, por si valorais ampliar la información sobre la posible venta, dados los problemas que da está vivienda, si esto fuera factible, seria tal vez una opción.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2024-06-03','TERESA no se consigue visitarla la mayoria de ocasiones, se le ha visitado un par de veces, después se ha seguido intentando pero ha sido imposible. Se le avisaba previamente y decía que no habría problema, pero el día de la visita no respondía a las llamadas ni mensajes, esto ha pasado en un par de ocasiones. Se le ha buscado por la zona por donde suele pasear con los perros y no se le ha visto, a la puerta no se le ha querido tocar por sus reacciones en otra ocasiones. Más tarde a veces contestaba diciendo que no había visto el teléfono o que estaba dormida, otras ni contestaba. En otra ocasión al contactar con ella para visitarla comentó que no se encontraba en Monesterio, que iba a pasar unos días fuera. Se ha estado en contacto con Jose, el TS de referencia, todo el tiempo. Esta semana se volverá a intentar.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2024-06-03','no se consigue visitarla la mayoria de ocasiones, se le ha visitado un par de veces, después se ha seguido intentando pero ha sido imposible. Se le avisaba previamente y decía que no habría problema, pero el día de la visita no respondía a las llamadas ni mensajes, esto ha pasado en un par de ocasiones. Se le ha buscado por la zona por donde suele pasear con los perros y no se le ha visto, a la puerta no se le ha querido tocar por sus reacciones en otra ocasiones. Más tarde a veces contestaba diciendo que no había visto el teléfono o que estaba dormida, otras ni contestaba. En otra ocasión al contactar con ella para visitarla comentó que no se encontraba en Monesterio, que iba a pasar unos días fuera. Se ha estado en contacto con Jose, el TS de referencia, todo el tiempo. Esta semana se volverá a intentar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2024-06-03','TERESA Confirmamos la baja de Mª Elena Duran Duran a fecha de hoy. Lo hemos comunicado a la UHB de Llerena y hemos contactado con su hermano, que vendrá a por ella a lo largo del día. Lleva sus pertenencias, documentos y medicación hasta la cena del miércoles. Vamos a intentar contactar con la trabajadora social de Fuente de Cantos para comunicarlo. Adjuntamos también el importe de los gastos de residencia y otros (recarga móvil) pendiente de abonar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2024-06-03','TERESA Soy Alexandra, me gustaría hablar con vosotras detenidamente, pero os escribo para manteneros informadas, porque no he podido llamaros. Os cuento novedad importante, para adjuntar al informe que ibais a mandar al juzgado, para solicitar internamiento involuntario. Me ha comentado la trabajadora social de los servicios sociales de base, que ha oído que: "Marta está metida en asuntos bastante turbios ya que consume heroína" . El mismo día que me comentaba la trabajadora social esto, la madre de Marta vino a mi despacho y me contó lo mismo. Yo no sé si es cierto, ya que no lo he visto con mis ojos, pero las amistades del novio de Marta sí sé que lo consumen, pues en este pueblo todos nos conocemos. Por lo tanto, Marta lo tiene bastante fácil, muy accesible para ella. La madre me cuenta que: "todo el verano, con todo el mes de agosto de vacaciones, no la quiero en casa, porque me monta espectáculos todos los días y ya estoy cansada". Legalmente Marta puede hacer lo que quiera, nadie la puede obligar; pero estando incapacitada legalmente, con necesidad de unos apoyos, nombrados judicialmente y teniendo una discapacidad intelectual reconocida; creo que deberíamos de hacer algo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2024-06-04','Ana: Correo de ayer de Esther, TS SSAB - Cilleros: "Te quería comentar una cosa con respecto a Julia, ella insiste en querer aceptar la ayuda a domicilio municipal (la solicitud ya la tengo firmada por la comisión) por que ella es consciente que la vivienda necesita limpieza y también la vendría bien para el tema de la comida, aunque su padre deja la comida hecha cuando se marcha por la mañana y también por la compañía aunque sea una hora, porque es lo que demanda Julia. Ahora mismo tengo hueco en la ayuda domicilio casi todos los días, pero claro eso supone un coste mensual que va a depender de los ingresos de Julia. Teniendo en cuenta que ella percibe 470,60 euros de la prestación familiar, la hora le saldría a 2,59 euros, que en el caso de coger una hora diaria de lunes a viernes supondría un coste de 51,80 euros al mes. Si me das el visto bueno podría concede la ayuda a domicilio sin problema. El único inconveniente es el padre, que no quiere que entre la persona que hay de ayuda a domicilio, que es un señor, en el domicilio, pero como el padre no está en la vivienda en toda la mañana pues entiendo que no habrá problema. En relación a la situación de la vivienda, comentarte también que el lunes tengo pendiente una visita al domicilio para realizar una informe a vivienda por la situación en la que se encuentra la vivienda, ya que ha habido quejas de los vecinos por la suciedad y el peligro de que pueda ocurrir algo. Ya se que esto no te compete pero para que tengas la información." ·········································· Mi respuesta: "Perfecto, muchas gracias por informar. Por nuestra partes se acepta el Servicio de Ayuda a Domicilio Municipal. Lo único que podría ocurrir es que el Jefe de la Secc. Económica decida reajustar su asignación semanal, que ya nos dirá, pero por lo demás, sin problema por nuestra parte. Lo del padre ya… no sé qué decirte, la usuaria sería ella, pero no sé sí él puede impedirlo y espero que no monte ningún escándalo ni similar. Ya nos confirmas cuando puedas si será factible y en tal caso cuando empezaría." ····················································· Envío correo a Alberto, Jefe S. Ecca: "A Julia le van a conceder SERVICIO DE AYUDA A DOMICILIO municipal, supondrá un coste de 51,80 euros al mes, entiendo que puede asumirlo. Ya me dices." ··························································································································································································· Envío un correo a Soraya Masa, con copia a Maite, Jefa Secc: "No sé si Maite te ha enviado al final el audio, la pongo en copia. Julia Morón está ingresada desde esta madrugada en la UHB del Hospital San Pedro de Alcántara de Cáceres. El Psiquiatra de referencia es Nacho. Me dice la compañera, Mª Carmen, que Julia ha llegado en un estado muy descuidado de higiene y sin control de la medicación. La realidad es que su situación es casa es cada vez más insostenible, como ya os comenté la madre claudicó y se fue a vivir con la otra hija, sin intención ninguna de regresar. El padre también es mayor, él no está en condiciones de atenderla, además sale de casa por la mañana y no regresa hasta por la tarde noche, pasando todo el día sola. No se encuentra en condiciones para el autocuidado y tampoco cuenta con ningún apoyo familiar ni social. Adjunto los últimos informes de Psiquiatría, ESM, así como un suplemento que añadió después la facultiva. No sé si sería posible una derivación a UME, por falta de apoyo sociofamiliar, inadaptación al entorno y necesidad de tratamiento rehabilitador. Sería además una buen oportunidad para que le valorasen por dependencia, a ver si al menos da grado I. Ya nos dices cómo lo ves y si puedes hablar con Nacho."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMELO'and edp.apellido1='GRACIA'and apellido2='REDONDO'),'2024-06-04','miguel, recibo email de lourdes ctaex de ctutelar enviado por el cuartillo: Te reenvío el correo con el documento adjunto. Comentar también que Carmelo desea que todos sus bienes sean para su sobrina Mónica. Él lo manifiesta constantemente. ¿Cómo hay que proceder? ----------------------------------------------- mi contestación: Buenos días, en relación a la pregunta de la sobrina de D. Carmelo, confirmarles que no puede hacer testamento conforme se indicaba en su sentencia de incapacitación. Si bien las medidas de apoyo han sido modificadas, ignoramos su contenido y estamos a la espera de que el juzgado nos remita el Auto o Sentencia de dicha revisión de medidas de apoyo. Por otro lado, vamos a solicitar a través del decanato del juzgado de nuevo los 3.000€ ya que como pueden ver el jzdo pide que se haga por demanda. Si siguieran insistiendo en dicha demanda tendría que ser la sobrina quien lo tendría que pedir porque nosotros somos asesores jurídicos y no podemos actuar como abogados procesalmente hablando, y abogacía de la junta sólo representa a la Comisión Tutelar en los nombramientos y remociones de cargo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='RAMOS'and apellido2='BLANCO'),'2024-06-03','-Amalia : ha vuelto a ingresar en Ctro . penitenciario de Badajoz , no ha cumplido con el estipulado por la condicional . Ya tiene activado cuenta peculio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='OSCAR'and edp.apellido1='BLAZQUEZ'and apellido2='PEREZ'),'2024-06-04','Ana: Envío correo a Cristina, TS CSS (cristina.hernandezca@salud-juntaex.es): "Aquí tienes la aceptación de plaza, debidamente firmada y sellada por la Representante Legal. Por favor, una vez registrado, envíame el justificante del registro para el expediente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2023-09-13','Ana: Ana Mª Benavente, TS ESM-Plas, nos remite Informe Clínico de Psiquiatría del HVP - Plas. ··············· Guardado en el expte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2024-06-04','Ana: Recibo Informe de Psiquiatría - CSS, con propuesta de irse a vivir a piso de alquiler de forma independiente. Reenvío a Maite, Jefa Secc.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='AVILA'and apellido2='FEMIA'),'2024-06-05','Ana: en relación a la asingación quincenal, tras reunirme con Alberto, Jefe S. Ecca, envío correo a Toni-Futuex: "En principio, teniendo en cuenta (groso modo, pues de algunas cuestiones no tenemos la información exacta aún) suministros, cáterin y otros posibles gastos, se le autorizarán 300 € mensuales que podrá retirar de forma quincenal, 150€/quincena. Hoy podrá retirar los 150€ correspondientes a la primera de junio y a partir del día 17 periódicamente cada 15 días. En cuanto al Cáterin, pues se mantiene los presupuestado y según vayáis viendo los días que se no pida comida porque cocine él y cómo vaya funcionando se puede volver a reajustar la asignación si fuera necesario. Así mismo, si necesitase extra para ropa (creo recordar que su hermano me dijo en su día que iba a necesitar) no dudéis en enviar presupuesto, pues con sus ahorros no habría ningún problema." ·························································································································································································· Correo de Alberto: "ANA: SE ESTABLECE UN REINTEGRO PERMANENTE DE 150 €/QUINCENA, REVISABLE SEGÚN SE VAYA DESARROLLANDO SU SITUACIÓN. CÁLCULO APROXIMADO INICIAL: • CATERING: 150 €/MES. • CONSUMOS: 100 €/MES • OTROS: 50 €/MES" ·································································································································································································· Envío a Ángel y Miguel, Aserores Jurídicos: "En relación a José Luis Ávila Femia, en cuyo AUTO DE MEDIDAS DE APOYO y nombramiento se autorizaba el ingreso involuntario, os adjunto, para ENVIAR Y COMUNICAR AL JUZGADO, INFORME DE ALTA DE LA Unidad de Hospitalización Breve de Psiquiatría (UHB), del hospital San Pedro de Alcántara. Como podéis leer en el informe, el facultativo decide dar el alta por: - Cumplimiento de objetivos - NO existir indicación de internamiento involuntario en esos momentos Indican, además del seguimiento por su Médico de Atención Primaria y Equipo de Salud Mental, una serie de recomendaciones tales como: - Evitar consumo de sustancias psicoactivas - Evitar consumo de cafeína y teína - Mantener un nivel adecuado de actividades sociolaborales Dado que en el seguimiento que se puede proporcionar desde el Programa del convenio acordado entre la Junta de Extremadura y Futuex, sólo se le puede visitar semanalmente (máximo 2 veces en semana) no es posible el seguimiento diario acerca del consumo o no de las referidas sustancias. Y en cuanto a la actividad sociolaboral, ni qué decir tiene que en su localidad de residencia, Aliseda, no existen opciones para abordar esta cuestión, más aún para el perfil de José Luis, quién no ha trabajado nunca, no cuenta con formación reglada ni ocupacional y presenta discapacidad intelectual leve además de su patología psiquiátrica. No obstante, se propondrá a la educadora del programa conveniado que le visita, que intente abordar esta cuestión y valorar con él intereses e inquietudes al respecto. Comunicar también que se le ha ofrecido solicitar plaza en el CENTRO RESIDENCIAL DE REHABILITACIÓN, de Salud Mental, el cuál requiere su voluntariedad, y se niega a firmar dicha solicitud. Para el resto de recursos en los que podría ingresar involuntariamente, nos indican que a día de hoy no cumple criterios." ········································································· Envío a Toni y Nieves, Futuex, correo al respecto de la indicación médica de "mantener actividad sociolaboral"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2024-06-05','Ana: Corre de ayer de Estrella, TS CSS-Plas (estrella.duranc@salud-juntaex.es): "Mañana miércoles se va de pase a domicilio Enrique Santos hasta el martes día 11" ···························· Lo reenvío a Toni y Clara, Futuex y pido organicen visitas de seguimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='TEJADA'and apellido2='FERNANDEZ'),'2024-06-05','Ana: Envío correo a Mª de la Cruz, TS de Cruz Blanca (trabajosocialcf-caceres@cruzblanca.org) las AUTORIZACIONES para la administración de la VACUNA FRENTE AL NEUMOCOCO, debidamente firmadas y selladas por la representante legal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2024-06-05','Ana: Tras hablar con Clara, TS CS, envío correo a Toni-Futuex: "en relación a Juan Chamorro Holguín, me transmiten que tiene las siguientes citas en Salud Mental de Trujillo: - Enfermería: Día 7 de junio a las 9:20 h - Psiquiatría: Dia 7 de junio a las 10:00 h Tiene que ir al centro de salud a por el volante para la ambulancia. Por favor, si podéis habladlo con él y organizad el acompañamiento." ···························································································································································································· Envío correo a Miguel, ASesor Jurídico CTAEx: "Tal y como hablamos la semana pasada, te envío adjunto el Informe de Alta de la UHB relativo a JUAN CHAMORRO HOLGUÍN, el día 29 le dieron el alta y regresó a su casa, con el compromiso, como puedes leer en el Informe, de: - Tomar la medicación oral - Cumplir con la administración de tratamiento intramuscular - Seguimiento en Salud Mental - NO CONSUMIR SUSTANCIAS PSICOACTIVAS La realidad es que Juan siempre ha rechazado el apoyo que podría recibir desde los recursos comunitarios (por ejemplo servicio de ayuda a domicilio o cáterin) y sólo acepta, con muchas reticencias, el seguimiento puntual que se le puede llevar a cabo desde el programa gestionado con Futuex conveniado con la Junta. Pero este seguimiento es escaso e insuficiente, no pudiendo garantizar con el cumplimiento de la toma de medicación de forma adecuada (pautada), el no consumo de sustancias tóxicas, ni otras cuestiones diarias relativas a hábitos de vida saludable, es decir directamente relacionadas con su salud (higiene, alimentación, sueño…) Adjunto también la DENUNCIA por agresión al Médico del pueblo, previa al ingreso."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2024-06-05','Ana: Guardo en el expdiente digital el INFORME DE ALTA DE LA UHB - HSPA (ingresado del 23 al 29 de mayo), remitido por Mª Carmen, TS del UHB. ·········· Tiene requerimientos judiciales que cumplir en ESM y ECA (Es conocedor de ello).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2024-06-05','Ana: Envío correo a Rosana, Directora Residencia Amada Corral (a.corral@grupociudadjardin.com) y Ana Mª, TS SSASB Alcuescar (tsocial7@mancomunidadsierrademontanchez.es): "En relación al correo remitido sobre DEUDA de JOAQUINA MAYORAL PIZARRO, me confirman desde la sección económica que Joaquina tiene abonados todas las mensualidades de su plaza en la residencia, incluida la de mayo. Me han mostrado todos los recibos y movimientos bancarios. Debe haber habido un error en el Ayuntamiento."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL'and edp.apellido1='POZAS'and apellido2='GOMEZ'),'2024-06-05','Ana: Envío a María, S. Ecca., el Cerficado Médico de Defunción y el Certificado Literal de Defunción del Registro Civil, facilitados desde el CSS.','2');
