insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2024-06-06','Ana: Correo de Esther, TS SSASB (tsocial@ayuntamientodecilleros.es): "ayer hable con las compañeras del hospital y me dijeron que si no había centro, probablemente le darían el alta y regresaría al domicilio, por estar pendiente por recuperar el tema de la ayuda a domicilio o algún recurso para poder gestionar mientras este en el domicilio. Si retomamos el tema de la ayuda a domicilio te digo cuanto supondría mensualmente, pero no es mucho." ········································· Mi respuesta: "En teoría Nacho, Psiquiatra de la UHB, quiere convocar una subcomisión, era una de nuestras propuestas, lo hablé con Mª Carmen (la pongo en copia). Esta información me la dio ayer Soraya Masa, Jefa de Unidad de Programas Asistenciales, que contactó con él. Yo sinceramente esperaba que la subcomisión tenga lugar antes del alta, pues si el dan el alta es volver al mismo punto de partida, sin los apoyos necesarios en su casa. Pongo en copia también a Marisa, compañera de Salud Mental, Mariángeles, compañera del Hospital de Coria y a Maite, mi Jefa." ···················· Mª Ángeles, TS HCC (mangeles.ramosg@salud-juntaex.es) // Marisa, TS ESM Coria (maria.olivera@salud-juntaex.es) // Mª Carmen TS HSPA (mariac.rodriguez@externos.salud-juntaex.es)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2024-05-29','Ana: Correo de Esther, TS SSASB (tsocial@ayuntamientodecilleros.es): "ante la imposibilidad de contactar telefónicamente, te informo de que me ha llamado la madre de Julia para el tema de renunciar a la aportación económica que le pasais de Julia, yo le he comentado que ya te había comunicado la situación, y no se si es necesario que tengáis esa renuncia. También hemos hablado sobre lo que te informe ayer de la denuncia que le había interpuesto su hermana, y es que ellas no pueden más con la situación. Si bajan al pueblo Julia las persigue y ayer la hermana la denunció porque no paraba de seguirlas y el hijo de la hermana, que también tiene una discapacidad, debido a la situación de estrés se autolesionó y la hermana manifiesta que esas actitudes no las va a consentir."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2024-05-28','Ana: Correo de Esther, TS SSASB (tsocial@ayuntamientodecilleros.es): "Te informo que se ha puesto en contacto conmigo el sargento de la Guardia Civil de Cilleros para informarme de que la hermana de Julia la ha denunciado por amenazas, la citarán del juzgado. La hermana solicita una orden de alejamiento porque no quiere que se acerque a su casa. Ayer la hermana me comento de estas amenazas y que Julia publica fotos de la hermana en sus redes sociales. No se hasta donde puede llegar la situación con Julia." ·········································································································································· Tras llamada de Mª Ángeles, TS HCC, me envía correo con ESCRITO comunicando las últimas incidencias, la noche anterior Julia pasó en urgencias y ha acudido varias veces a su despacho. ··············· Guardo en expdiente digital. ······· El médico de urgencias se le ha quejado diciendo que es un caso claro social y que no puede acudir a urgencias cada vez que discuta con sus familiares.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='DELGADO'and apellido2='RODRIGUEZ'),'2024-06-06','TERESA Jose Antonio Delgado es el siguiente: 924 72 36 61','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOLORES'and edp.apellido1='MACARRO'and apellido2='CAMACHO'),'2024-06-06','TERESA Ayer se realizaron las tareas pendientes de limpieza en la casa de Dolores Macarro, por parte de la empresa, y hubo algunos graves inconvenientes que se han ido gestionando mas o menos, te detallo: En el día de ayer han realizado la limpieza en la casa de Dolores, pasó el día en la residencia y casi a las 10 de la noche se le recogió de la misma para llevarla a la casa. Era una cosa excepcional, pero dadas las horas, y que la empresa tenia que entregar las llaves se decidio hacer asi. Tras una caída que ha tenido recientemente la movilidad por sí sola es muy muy complicada, en la residencia la llevaban en silla de ruedas porque le cuesta andar y necesita ayuda para levantarse, moverse... Al llegar a la vivienda la empresa no había acabado y no se hacían responsables de que entrara Dolores sola cuando acabarán, por lo que pidieron a la educadora que se quedara esperando. Terminaron de echar ciertos productos de desinfección y mientras esperan fuera, los de la empresa, Dolores y la educadora, se escuchó gritar al perro de Dolores. Al entrar vimos que había muerto... la casa estaba teniendo pequeños cortocircuitos y las superficies daban calambre, se había electrocutado. La instalación eléctrica de la casa está en muy malas condiciones. A Dolores no se le comunicó que el perro había muerto, se ha hecho hoy.. está muy muy cabreada, responsabilizando a la educadora y la empresa de todo, el perro llevaba con ella toda la vida. Anoche ya que era peligroso que pasara allí la noche, se llamó a los servicios de emergencia sin éxito, comentaban que se bajaran los plomos y se llamara a la compañía eléctrica, la policía local tampoco acudió, al menos para facilitar el traslado de Dolores a un hostal. Se llamó a varios y a la residencia por si, debido a la situación, podría pasar la noche allí, comentaron que no y se consiguió un hostal en Zafra, era el más cercano. Aunque finalmente se recibió una llamada de la residencia, que habían hablado con su superior y aceptaban que se quedara debido a la gravedad y las horas, bajo nuestra responsabilidad por supuesto. Ha pasado la noche allí y se encuentra bien, aunque muy cabreada. Se ha hablado con la TS y se podría solicitar una estancia temporal, máximo 2 meses, hasta solucionar el tema de la electricidad de la vivienda o se le encuentre otro sitio. Desde la residencia comentan que las plazas de estancia temporal están cubiertas, por lo que no se sabe muy bien qué va a pasar... Han ido desde los servicios municipales para recoger el perro muerto, hoy. Te vamos informando, de si puede quedarse en la resi, que seria lo ideal SOLICITO PLAZA RESIDENCIAL A TRAVES DE DEPENDENCIA POR CAMIBO DE PIA Y ADJUNNTO AUTORIZACION DE INGRESO INVOLUNTARIO ACTUALMETE TIENE PVSAD PERO DEJO DE PRESTAR EL SERVICIO DE ENERO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='MARIN'and apellido2='LAUREANO'),'2024-06-06','Ana: Remito a Flori, Res. Padre Damián de Plasenzuela (residenciaplasenzuela21@gmail.com): "Adjunto el CONSENTIMIENTO INFORMADO para la ADMINISTRACIÓN DE LA VACUNA FRENTE AL NEUMOCOCO, debidamente firmada y sellada por la Presidenta de la CTAEx."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2024-06-06','Ana: Correo de Mª Josefa del Castillo, Psiquiatra (mariajose.gomezd@salud-juntaex.es): "Por la presente os convoco a la Subcomisión de Caso Clínico de JMSB el día 12.06.2024 a las 8.30h, a petición de la Dra. Maria Isabel Rubio Merino. Envio informe del paciente. Remitiré enlace para realizar la reunión vía TEAMS." ···················· Se modifica el horari a las 8:45 h. ···· Puesto que yo tengo curso a las 9:00 h asisitá Maite, Jefa CTAEx a la subcomisión.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IGNACIO'and edp.apellido1='RODRIGUEZ'and apellido2='ALCANTARA'),'2024-06-06','Ana: correo de Sonia Bernabé, Asindi: "Hola Ana, te escribo para informarte que esta mañana ha dado positivo en covid Ignacio Rodriguez Alcántara. De momento, tiene síntomas muy leves. Seguiremos pendientes de su evolución."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2024-06-06','Ana: Envío correo a Pedro Garvi, Coord. Progr. Personas sin Hogar de Cáritas (pgarvi.cdcoriacaceres@caritas.es) solicitando Cerficado acogida en Centro Vida para poder comunicar al Juzgado.','2');
