insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MATILLAS'and apellido2='JIMENEZ'),'2024-06-11','Ana: Reenvío a Alberto, Jefe Secc. Ecca, correo de Pilar, Directora Hogar San Vicente de Paúl: "Te reenvío otro correo de Pilar, Directora del Hogar San Vicente de Paúl, reiteran una vez más la SOLICITUD DE CITA CON LA SECCIÓN ECONÓMCA para Mª del Carmen Matillas Jiménez, subrayo en amarillo en el hilo. Pongo en copia a Maite y a Pilar. Alberto, por favor, da respuesta a la mayor brevedad." ······························································· Tal y como me pide Alberto, le facilito el número de Pilar, Directora HSVP, para llamarla él.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LIBERTAD'and edp.apellido1='GARCIA'and apellido2='MARQUEZ'),'2024-06-11','TERESA Como te comenté tenia pensado venirse el jueves o el viernes de la semana pasada pero finalmente no se vino porque se dio un golpe en un pie y tiene un dedo astillado y tenia que hacer reposo. Ella dice que va todo bien, que va a esperar a que mejore el pie para venir a ver a Juan (su pareja que es usuario de la vivienda tutelada). Con respecto al presupuesto yo creo que sería conveniente que le paséis al menos 40€ euros todas las semanas porque cómo le paséis todo el dinero del mes junto no va a saber administrarlo y lo va a gastar rápido','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2024-06-11','Ana: Reenvío a Pedro Garvi el correo que le remití la semana pasada al nuevo correo que me indican: pgarvi@caritascoriacaceres.es ······························································································································································································· Respuesta de Pedro: "Pues sobre Miguel Ángel decirte poco, entró el miércoles, pero se ha ido el sábado (quería consumir). Y ale hemos comunicado a Mamen que ha abandonado el centro." ························· Pido que me pongan esta misma información en un breve informe para comunicar al Juzgado.','2');
