insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2024-06-11','Ana: en relación a los correos de Alberto y Lourdes (Vanesa ha dejado de percibir la PNC, la última nómina fue la de abril), llamo a Marina Carmen Cintas, Jefa de Secc. Prestaciones I - PNC (924 00 59 22) me informa que a Vanesa le han SUSPENDIDO el cobro de la pensión, por no haber presentado la documentación requerida en 2023 ni en su momento ni en nuevo requerimiento en 2024. ········ Le piden información acerca de los distintos contratos de trabajo que ha tenido así como del Certificados del INGRESO MÍNIMO VITAL que también solicitó y ha percibido. ····························· Para que me envíen la carta tengo que enviar un oficio solicitando duplicado y adjuntando la nueva resolución judicial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAIMUNDO'and edp.apellido1='PEREO'and apellido2='REBOLLO'),'2024-06-11','Ana: Envío correo a Paula, TO; Carolina, Directora; y Bea, Psicóloga - CRR: "En relación a ANTONIO PEREO REBOLLO, y a petición del Juzgado, os solicitamos INFORME ACTUALIZADO de la situación en los siguientes términos: “Informe sobre la situación actual de D. Antonio en cuanto a: - Discapacidad que presenta - Ámbitos y extensión que resulten afectados por su discapacidad y necesidad de apoyo - Cualquier consideración que estimen conveniente sobre ella en razón al procedimiento judicial de revisión de medidas de apoyo.” Para adjuntar al resto de documentación requerida para la REVISIÓN DE SUS MEDIDAS DE APOYO”','1');
