insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2024-06-11','Ana: Llamo a Marina Carmen Cintas, Jefa de Secc. Prestaciones I - PNC (924 00 59 22) en relación al cobro de la PNC de José Luis, en la cuenta de Mª Ángeles. Me comunica que sus órdenes de transferencia están bien hechas al banco, que debe ser error de la entidad bancaria. ·································· Lo comunico a Alejandra, Adtvo. Secc. Ecca. *Comprueba y las órdenes de pago no son de la Seguridad Social, sino de Antonio, padre de Mª Ángeles. ··············································· Llamo a Antonio, padre de Mª Ángeles (619 90 84 26), no entiende lo que le trato de explicar. ······ Alejandra intentará hablar con el banco para que den de baja esa orden.','2');
