insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-06-12','Ana: Correo de María, S. Ecca., a Nieves, Futuex: "se adjunta autorización de reintegro puntual del tutelado de referencia, por importe de 120 €. También envío autorización de transferencia puntual por la compra del móvil, por importe de 149,9 €, desde la cuenta de la persona tutelada D. Jose Manuel Romero Mediavillla. Ruego me envíe justificante una vez realizada."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SALVADORA'and edp.apellido1='CHAVES'and apellido2='MENDOZA'),'2024-06-12','Ana: En relación al correo de Belén Pavón, responsable Residencia (Belen.asoma@outlook.es): "Te escribo en relación a María Salvadora Chaves Mendoza, estamos preocupados en el centro residencial donde reside actualmente porque suele salir a pasear a horas de mucho calor, a primera hora de la tarde, por ejemplo, ella es diabética y además, muchas de las veces que sale a la calle y aunque lleva andador se cae, este es un pueblo muy pequeño por lo que puede que no se encuentre con quien pueda socorrerla. Mi pregunta es: ¿hay alguna manera de que desde la comisión tutelar se le restrinjan los horarios de salida del centro? Sé que cuando yo llegue a este centro en febrero de 2022, me comunicaron que ella no tiene permitido ir a su casa o al cementerio, pero no tengo constancia de restricción de horas de salida." ···················································· Respondo: "En relación a la situación que planteas, te envío adjunta una AUTORIZACIÓN GENERAL DE SALIDAS para que desde la DIRECCIÓN DEL CENTRO tengáis potestad para decidir sobre las salidas de Mª Salvadora Chaves Mendoza, de modo que en los horarios que consideréis inadecuados por poder afectar negativamente su salud o por el riesgo que supone para su integridad, podáis restringir esas salidas posponiéndolas a un horario más adecuado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2024-06-12','Ana: Respondo al correo de Esther, TS SSASB Cilleros (tsocial@ayuntamientodecilleros.es): "Sí, sigue ingresada. Y ya aprovecho para comunicarte que la SUBCOMISIÓN DE JULIA, está programada para el próximo martes día 18 a las 13 h. Marisa, compañera de Salud Mental está también convocada, esperemos que se tengan en cuenta nuestro criterio, que es compartido. Pongo en copia a Mariángeles, compañera del Hospital de Coria para que esté al corriente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MATILLAS'and apellido2='JIMENEZ'),'2024-06-12','Ana: Correo de Alberto, Jefe S. Ecca: "HE HABLADO CON PILAR (671016615) (DIRECTORA HOGAR SAN VICENTE DE PAUL). HEMOS QUEDADO EN LO SIGUIENTE: • HAGO INFORME ECO ACTUALIZADO Y LO MÁS SENCILLO POSIBLE SOBRE LA SITUACIÓN ECONÓMICA ACTUAL DE TUTELADA. • ELLA LO COMPARTIRÁ CON TUTELADA, PARA EXPLICARLE AQUELLO QUE LE GENERE DUDAS. • PRINCIPAL CUESTIÓN QUE PREOCUPA A TUTELADA: PODER ARREGLAR LA VIVIENDA DE SU PROPIEDAD EN PLASENCIA. • POSTERIORMENTE BUSCARÁN PRESUPUESTOS PARA ARREGLOS PARA DEMOSTRARLE QUE NO TIENE PORQUE PREOCUPARSE. SI FINALMENTE PILAR CONSIDERA QUE ES MEJOR QUE SEA YO QUIEN HABLE CON TUTELADA, PUÉS ASÍ LO HARÉ EN ESTE CASO."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2024-06-12','Ana: En relación al correo pendiente de Paula, TO CRR-Plas: "Buenos días, nos ponemos en contacto para ofrecer información acerca de Isabel Cano y su proceso de recuperación. Como se acordó en las intervenciones realizadas a partir de la subcomisión de casos de Isabel junto al equipo de salud mental, con el Dr. Mora como psiquiatra, se ha vinculado su evolución en autocuidado (evitar autolesiones, cuidado de su salud, cuidado personal), compromiso de participación en grupos y roles diversos y evolución personal, a la posibilidad de ir a piso supervisado dependiente del CRR de Plasencia, acordando una temporalidad de al menos 6 meses del mantenimiento de los logros (especialmente respecto a la no aparición de autolesiones). Debemos informar de la buena evolución de Isabel en este sentido, su compromiso y motivación a este respecto, por lo que, atendiendo a la temporalidad (mediados de junio se cumplen los 6 meses de sostener las acciones nombradas en el párrafo anterior), a finales del mes de junio procederíamos a realizar el paso de Isabel a piso supervisado. Esto tiene una implicación económica, debiendo hacerse cargo de algunos gastos mensuales propios como medio de intervención de cara al aprendizaje de autoadministración económica de necesidades y gestión del hogar. Así se estiman unos 430 euros en total (incluyendo necesidades de higiene, 180 euros de gastos mensuales específicos para alimentación-limpieza-hogar, tabaco, actividades individuales y grupales de ocio, actividades en la comunidad con otros objetivos...). Como siempre, la evaluación con Isabel se va a realizar de forma constante, en forma de seguimientos, para dar los mejores apoyos posibles en un paso importante para su autonomía personal y teniendo presente la posibilidad de retornar a CRR en caso de necesidad, para recibir los apoyos correspondientes. Esperamos vuestra respuesta a esta buena noticia." ································································································································································································· Respondo: "Sí que es una buena noticia tan buena evolución! Nos alegramos, ojalá y que continúe así e incluso siga la evolución positiva. Precisamente he hablado con ella esta mañana y se muestra ilusionada con el cambio de recurso. Por mi parte, si es viable, ok a este incremento de su asignación para hacer frente a los gastos que le supone la nueva situación. Pongo en copia a Alberto, para que pueda valorarlo y ACEPTAR EL PRESUESTO como Jefe de la Sección Económica. Pongo en copia también a Maite para su conocimiento."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='VALLE'and apellido2='SIMON'),'2024-06-13','Ana: Correo de ayer de Sheila Rguez., Directora Técnica CRR-CC (crr@grupociudadjardin.com): "La persona curatelada, FELIX VALLE SIMÓN, ha expresado en atención con Equipo Técnico, su deseo de poder acudir a un dermatólogo privado para poder ser intervenido del quiste sebáceo que presenta próximo al ojo derecho al haber aumentado de tamaño considerablemente. En consulta con dermatología en la sanidad pública, a la que acude por un problema en una uña de la mano, lo han valorado y al ser intervenciones de estética (por ser una afección benigna) no se realiza eliminación en Seguridad Social, instándole a realizar de manera privada. Félix expresa su deseo de poder retirar dicho quiste debido al aumento de su tamaño. Quedamos a la espera de indicaciones para poder darle respuesta." ················································································ Mi respuesta: "Félix puede acudir a una consulta de dermatología privada para que le den presupuesto. Cuando nos lo enviéis, el jefe de sección económica valorará la viabilidad. Por mi parte, si es viable, no hay inconveniente en que le realicen dicha intervención. Ante cualquier otra cuestión, no dudéis en contactar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='PEREO'and apellido2='REBOLLO'),'2024-06-13','Ana: Envío a los A. Jurídicos el Informe para la revisión de las medidas de apoyo remitido por el CRR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2024-06-13','Ana: Correo de ayer de Pilar Martín, TS ESM-CC (pilar.martinp@salud-juntaex.es): "LE HE TENIDO ESTA MAÑANA, SE ENCUENTRA PENDIENTE DE LA REVISIÓN DE LAS MEDIDAS DE APOYO. HE LLAMADO AL MINISTERIO FISCAL Y ME HAN DICHO EL PROCEDIMIENTO SE ENCUENTRA EN EL Nº2 Y ES EL NºDT5-663/23. INTENTA QUE EL GABINETE JURÍDICO SE PONGA EN CONTACTO CON ELLOS Y A SER POSIBLE SE LE CITE CON EL FORENSE Y SE AGILICE TODO DADO QUE AHORA SE ENCUENTRA EN CENTRO VIDA DURANTE JUNIO. POR CIERTO ME DICE QUE NO QUIERE IR A PS NI A CRR. QUE EN JULIO SE VA A CADIZ Y EN AGOSTO-SEPTIEMBRE A MADRID. DURANTE ESOS MESES PIENSA NO HACER CONTROLES, NIEGA CONSUMO, SOLO PORROS." ················································ Mi respueta: "Gracias por informar. ¿Podrías, por favor, enviarnos un breve informe con la información que nos indicas en el correo? Es importante que también comuniquemos todo esto al Juzgado. Voy a pedir también a Cáritas certificado de estancia en su centro (no sabía que estaba en este recurso). Pongo en copia a mis compañeros Asesores Jurídico, para que puedan leer tu correo y actuar en consecuencia."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='NUÑEZ'and apellido2='BONO'),'2024-06-13','miguel, hablo con el abogado José Fernando Garcia Espinosa (924232797 y 630145336) email 2554@icaba.com y jfgarciaespinosa@icaba.com) del procedimiento DPA DILIGENCIAS PREVIAS PROC. ABREVIADO 0001717 /2021, del jzdo de 1º instancia e instrucción nº3 de Badajoz, y me confirma que el procedimiento todavía está sin resolver. Le envío sentencia de incapacitación y nombramiento de la Ctaex para me comente el estado en que se encuentra el procedimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAUL'and edp.apellido1='GIL'and apellido2='SANZ'),'2024-06-14','miguel, Buenas tardes, Sergio Claro que conozco que la oficina envía la documentación solicitada y que hace todo lo que está en su mano pero está resultando muy difícil acabar con ésta testamentaria y hay que averiguar exactamente qué falta… Las liquidaciones de los impuestos de sucesiones se hicieron con todos los certificados que Caixa aportó, contemplo la posibilidad de que pudiera haber algún error en las liquidaciones al no haberse incluido algún producto y es por ello por lo que acudo a que alguien confeccione las complementarias, para ello, vosotros me facilitáis los certificados de los seguros de vida de Teresa Sanz, Maximo Gil y sus hijos, ésta persona me indica que están declarados estos certificados en las respectivas declaraciones, aparentemente corroboro yo misma que están declaradas esas cantidades, es más, en la liquidación de Raúl Gil Sanz se declara una cantidad superior a los certificados que aportáis, no sé si es que falta algún certificado o se ha especificado una cantidad mayor… Me habéis pedido la designación de herederos de éstos productos, cuando es la oficina la que tiene que tenerlos o averiguar por los testamentos quienes son los herederos, me habéis pedido el dictamen de Testamentaría cuando, lógicamente, no obra en mi poder. Respecto a poneros en contacto con los tutores legales, os recuerdo que es la Junta de Extremadura y que yo estoy en contacto con su departamento jurídico para coordinar que los bienes de mis tios en Caixa, acaben en una cuenta a nombre de mis primos, sus herederos. La Junta de Extremadura y yo desconocemos qué productos tenían mis tios, únicamente a través de los certificados emitidos por vosotros sabemos de ellos y aparentemente, están declarados en los impuestos de Sucesiones. Gracias, Sergio, seguimos en contacto','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='GIL'and apellido2='SANZ'),'2024-06-14','miguel, Buenas tardes, Sergio Claro que conozco que la oficina envía la documentación solicitada y que hace todo lo que está en su mano pero está resultando muy difícil acabar con ésta testamentaria y hay que averiguar exactamente qué falta… Las liquidaciones de los impuestos de sucesiones se hicieron con todos los certificados que Caixa aportó, contemplo la posibilidad de que pudiera haber algún error en las liquidaciones al no haberse incluido algún producto y es por ello por lo que acudo a que alguien confeccione las complementarias, para ello, vosotros me facilitáis los certificados de los seguros de vida de Teresa Sanz, Maximo Gil y sus hijos, ésta persona me indica que están declarados estos certificados en las respectivas declaraciones, aparentemente corroboro yo misma que están declaradas esas cantidades, es más, en la liquidación de Raúl Gil Sanz se declara una cantidad superior a los certificados que aportáis, no sé si es que falta algún certificado o se ha especificado una cantidad mayor… Me habéis pedido la designación de herederos de éstos productos, cuando es la oficina la que tiene que tenerlos o averiguar por los testamentos quienes son los herederos, me habéis pedido el dictamen de Testamentaría cuando, lógicamente, no obra en mi poder. Respecto a poneros en contacto con los tutores legales, os recuerdo que es la Junta de Extremadura y que yo estoy en contacto con su departamento jurídico para coordinar que los bienes de mis tios en Caixa, acaben en una cuenta a nombre de mis primos, sus herederos. La Junta de Extremadura y yo desconocemos qué productos tenían mis tios, únicamente a través de los certificados emitidos por vosotros sabemos de ellos y aparentemente, están declarados en los impuestos de Sucesiones. Gracias, Sergio, seguimos en contacto','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2024-06-14','Ana: Envío correo a Juan Carlos Cano, Aux. Adtvo.: "En relación a VANESA FERNÁNDEZ GÓMEZ, cuyo cargo ostenta la CTAEx, adjunto la siguiente documentación para remitir por registro a la Secretaría General de Servicios Sociales, al Servicio de Prestaciones - Pensión No Contributiva. (Tienes la información más completa en el propio oficio): - Oficio-solicitud - Auto de revisión de las medidas de apoyo - Firmeza del Auto - Acuerdo de Aceptación del Auto" ······························································································································································································· Hablo con Vanesa (643 35 84 10): le explico la nueva situación, Mamen, Educacora, ya ha comenzado a visitarla y le ha explicado. ·········· En cuanto a suspensión de la PNC dice haber enviado la documentación a una dirección de correo electrónico, pero no por registro a la Secretaría General. También le ha facilitado la documentación a Mamen, Ed. ···· Le explico que hablé yo con PNC, he solicitado copia de la carta que el enviaron e intentaremos ayudarla para volver reactivar la pensión. ··················· Está preocupada porque dice que no tiene dinero y tiene cosas que pagar. ··································································································································· Solicito a Ton y Mamen, Ed. Futuex (delegadapoyo.caceres@futuex.es) la documentación que Vanesa dice haberle facilitado y en su defecto que le ayuden a recabarla y nos la hagan llegar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2024-06-14','Ana: Comunico a Futuex la anulación de la cita programada de Psiquiatría. Nos enviarán nueva cita. ····································································································································· *Solicito a Pedro Garvi, Coordinador de Cáritas, Certificado de Ingreso en Centro Vida. ············································································· Envío a los A. Jurídicos: "Os reenvío informe que nos facilita la TS del Equipo de Salud Mental de Cáceres para que remitáis al juzgado, leed lo que pone, por favor, pues entiendo que es necesario explicar que no podemos impedir que se traslade a otras comunidades autónomas, ni podemos controlar que consuma cannabis ni tampoco obligarle a ingresar en Comunidad Terapéutica ni en los recursos residenciales comunitarios de Salud Mental, para los que ser requiere la voluntariedad de la persona. Por tanto, es muy difícil ejercer el cargo sin una colaboración mínima por su parte. *He solicitado a Cáritas el certificado de estancia en Centro Vida." ·································· Nº de Fco: 643 79 34 75','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LEON'and edp.apellido1='LEAL'and apellido2='PEREZ OLAGUE'),'2024-06-13','Ana: Correo de Sara, enfermera de la Residencia Santa Ana (malpartida@nexusintegral.com): "comunicarle que la informacion que tenemos de Leon es que continua ingresado y esta en tratamiento, por via telefonica no nos dan mas informacion al respecto, he dejado el numero de la residencia pero solo un medico al inicio del proceso se puso en contacto con nosotros para indicarnos que la evolucion era lenta y para conocer su estado fisico en el residencia. D e vez en cuando me pongo en contacto con Nieves su cuidadora, que va a verlo pero solo tiene la información que Leon le da y es que esta mejor."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2024-06-12','Ana: correo de Pilar Martín, TS ESM-CC: "LE HE TENIDO ESTA MAÑANA, SE ENCUENTRA PENDIENTE DE LA REVISIÓN DE LAS MEDIDAS DE APOYO. HE LLAMADO AL MINISTERIO FISCAL Y ME HAN DICHO EL PROCEDIMIENTO SE ENCUENTRA EN EL Nº2 Y ES EL NºDT5-663/23. INTENTA QUE EL GABINETE JURÍDICO SE PONGA EN CONTACTO CON ELLOS Y A SER POSIBLE SE LE CITE CON EL FORENSE Y SE AGILICE TODO DADO QUE AHORA SE ENCUENTRA EN CENTRO VIDA DURANTE JUNIO. POR CIERTO ME DICE QUE NO QUIERE IR A PS NI A CRR. QUE EN JULIO SE VA A CADIZ Y EN AGOSTO-SEPTIEMBRE A MADRID. DURANTE ESOS MESES PIENSA NO HACER CONTROLES, NIEGA CONSUMO, SOLO PORROS"','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2024-06-14','TERESA MARIA HA INTENTADO SUICIDARSE, ME LLAMA LA TS DEL HOSPITAL DE LLERENA PARA INFORMARME QUE ESTA INGRESADA Y LA VAN A VALORARN PARA UME. DERIVO A FUTUEX PARA QUE LE LLEVE ROPA Y TABACO HABLO CON SU MADRE PARA EL TEMA DEL PERRO Y ME DICE QUE ELLA NO SE PUEDE HACER CARGO ENVIO INFORME DE LA SITUACION AL AYUNTAMIENTO PARA QUE ACTUEN ACORDE A LA NUEVA LEGISLACION YA QUE LA PROTECTORA DE ANIAMALES NO TIENE PLAZA PARA RECOGER LOS DOS PERROS QUE TIENE EN EL DOMICLIIO NI MARIA TIENE DINERO PARA PAGAR UNA GUARDERIA CANINA. TIENE CITA EN CADEX EL LUNES, LA LLEVARAN EN AMBULANCIA DESE EL HOSPITAL','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2024-06-14','Ana: Pedro Garvi me remite Certificado de Ingreso, pero hay un error en las fechas. ···· Solicito lo rectifique y nos lo reenvíe de nuevo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN PABLO'and edp.apellido1='ESTEBAN'and apellido2='CORRAL'),'2024-06-14','miguel, email informativo de Tere: Tfnos de contacto: ts de plena inclusión 924620400 / ts de Puebla de Alcocer 924 65 41 11 Estas personas seguro te pueden facilitar el teléfono de la exnuera Ella no se va a poner en contacto contigo porque no le interesa, están haciendo las cosas por su cuenta porque el padre quería que todo fuera para su hijo y la exnuera y demás familiares están moviendo hilos para aprovecharse. Esteban Bonilla Pablo: es el padre de Juan Pablo Falleció el 29/11/2023 Esteban Herrera Mariano: es sobrino de Juan Pablo Herrera Bravo Pilar: ex nuera del padre de Pablo, esta señora junto con los nietos de Pablo están averiguando la herencia y posiblemente han pedido pensión de orfandad para Juan Pablo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2024-06-14','Ana: Tras hablar con Mª Carmen, TS UHB - HSPA (56283), envío correo-respuesta a Esther, TS SSASB Cilleros (tsocial@ayuntamientodecilleros.es): "De momento, sigue en la UHB y la idea es que permanezca allí hasta que tenga lugar la comisión. Al parecer tiene sus momentos. En teoría está compensada a nivel psicopatológico pero también me dicen que está súper demandante y que ayer se comió una goma de borrar… En fin, seguimos en contacto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LEON'and edp.apellido1='LEAL'and apellido2='PEREZ OLAGUE'),'2024-06-14','Ana: Correo de Sara, enfermera de la Residencia Santa Ana (malpartida@nexusintegral.com): "HOY NOS HA LLAMADO UN MEDICO PARA INFORMARNOS QUE ESTA MEJOR AUNQUE AUN SIGUE CON ALTO FLUJO Y DIFICULTAD PARA EXPULSAR FLEMAS, QUE PROBABLEMETE LA SEMANA QUE VIENE LE DEN EL ALTA HOSPITALARIA, UN SALUDO"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='LARA'and apellido2='SERRANO'),'2024-06-14','Ana: en base a la modificación de las medidas, actualmente CURATELA REPRESENTATIVA, recibimos el Inorme de Consolación, TS de SSASB. José continúa en la Residencia de Torres de Don Miguel, está bien adaptado. No cuenta con apoyos sociofamiliares. ··· El contacto con los familiares se limita a llamadas esporádicas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2024-05-24','Ana: Correo de Maite, Jefa CTAEx: "Ha llegado hoy del juzgado la comunicación de su puesta en libertad."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MURILLO'and apellido2='ROMANO'),'2024-06-14','miguel, email de Sandra Sandra Sánchez >ssanchez@inteligencialimite.org> que reenvía Amalia: Informaros que en el día de hoy le he hecho llegar al abogado de Juan José los siguientes informes para que los pueda presentar en el juzgado según sentencia: - Informe expedido por parte del equipo técnico de ECA. - Informe del médico psiquiatra de la unidad de salud mental del centro de salud valdepasillas. - Informe expedido por parte del servicio de habilitación funcional (tratamiento psicológico) de la Entidad Aexpainba. Hay que presentarlos por trimestre, por lo que los siguientes informes los enviaré en el mes de septiembre. Adjunto los informes que he presentado. --------------------------------------------- mi contestación a Sandra: Buenos días Sandra, qué abogado es ese? El que tramitó el procedimiento penal al que fue condenado? Puedes decirnos quién es y sus datos de contacto por si necesitamos algo? ------------------------------------------- Contestación de Sandra: Así es, es el abogado que ha llevado todo el procedimiento judicial de Juan José. Informaros que ya ha presentado dichos informes al procurador del juzgado para su trámite. Os adjunto todos los datos que solicitáis: Francisco J. Fernández ESTUDIO DE ABOGADOS C/ Zurbarán núm. 1, 2º-7 06002 Badajoz Tel. 924 261 289 algabayfernandez.abogados@hotmail.com Cualquier cosa que necesitéis estoy a vuestra disposición.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2024-05-06','Ana: Se autoriza compra de zapatillas por inporte de 29€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN PABLO'and edp.apellido1='ESTEBAN'and apellido2='CORRAL'),'2024-06-14','miguel, llamo a Elvira Ts de Castilblanco 924654111 y a la exnuera Pilar 646-813861. Pongo email a Alberto y Tere con el resultado de lo hablado con Elvira y Pilar: Hola, aunque prefiero hablarlo en persona porque es un asunto enredoso, os intento indicar la información que he conseguido. Elvira Trabajadora Social de Castilblanco 924654111 (Puebla de Alcocer es donde está Juan Pablo), tras exponerle la situación de no tener nada, me indica que el lunes intentará enviarme todo lo que tiene, sí me dice que tiene certificado de defunción del abuelo Esteban Bonilla Pablo y la abuela. Dejó una vivienda en c/ Buenavista de Castilblanco y una cuenta con bastante dinero (tal vez un fondo de inversiones en Ibercaja de Castilblanco, cuya oficina solo abre lunes, miércoles y jueves). Me buscará el teléfono del sobrino de Juan Pablo y nieto de Esteban Bonilla. Me da el tfno de Pilar (exnuera) 646-813861 Llamo a la exnuera Pilar: un poco reticente pues no entiende que se nombrara a la Ctaex, sin que nadie les dijese nada, intentaron hablar con el Centro y al no cogerle el tlfno la Ts, dejó recado grabado sin que nadie les haya contestado. Su hijo (creo tiene 2 por lo que comenta de 34 y 17 años) mayor, es el que ha recabado toda la documentación de la herencia. Le dejo mis datos email y tlfno y el tlfno de Tere. Problema: su hijo trabaja en industria cárnica con horario comercial de 8 a 3h y de 5 a 8h y por tanto será complicado hablar con él. Se lo intento explicar y que vea que estamos de su parte pues a todos nos interesa resolver la herencia. En cuanto a la familia, los abuelos dejaron 3 hijos: Carlos que falleció en julio o agosto de 2013 (sin hijos ni testamento-lo puede acreditar el sobrino del tutelado-hijo de Pilar); Mariano (exmarido de Pilar) al que se le ve deambulando por ahí, divorciado, dejó deudas y en la estacada a la familia. Verbaliza al su hijo que estaría dispuesto a renunciar a la herencia. Y Juan Pablo, del que dice Pilar que su hijo quiere ocuparse de cuidar del tutelado y que se preocupa por él. Parece ser que el abuelo deja un testamento en que aparecen Carlos, Mariano y Juan Pablo formalizado en mayo de 2013, y fallece en noviembre de 2023. Pilar se queja de que el hijo ha tocado con muro y se ha jartado porque tras tener toda la documentación y aunque estaba de autorizado en cuenta del abuelo de Ibercaja, ésta no le facilita nada. Se queja de que el abuelo dejó 9000€ y se ha estado cargando todo en esa cuenta y aunque no saben cuanto hay dice que casi no queda nada (esta queja es contra la Ctaex, pues ese dinero sería para la administración de la herencia y no para los gastos personales del tutelado). Por tanto, quedo pendiente de la documentación e información que nos remita Elvira y de que tras lo que hable la exnuera Pilar con su hijo, éste se ponga en contacto con Tere o conmigo por tlfno o por mi email. En cuanto sepa algo os voy informando. Aquí el escollo es Mariano (exmarido de Pilar y padre del sobrino que ha tramitado la recopilación de papeles pero no los ha llevado a ningún lado) porque dice Pilar que ni come ni deja comer…Esto ya lo veremos cuando llegue el momento, porque intentaremos que la notaria redacte una renuncia de herencia y se acerque a firmarla. Si queréis el martes lo hablamos en persona.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2024-06-17','Ana: Correo de Esther, TS SSASB (tsocial@ayuntamientodecilleros.es): "como te comenté en su momento buscamos a una chica para que la ayudase con la limpieza de la vivienda y el aseo de ella. La chica en cuestión solo fue en día, y estuvo trabajando dos horas. La chica pasa por aquí a preguntar por Julia, para poder cobrar esas dos horas que ha estado en el domicilio de Julia, que asciende a 20 euros la cuantía que la debe Julia, no se si vosotros podeis autorizar ese pago o por el contrario no se como lo va a percibir. Se que lo mismo no te compete a ti esta situación, pero no se tampoco muy bien como proceder, ya que el padre es imposible contactar con él y la madre pues no se quiere hacer cargo de nada." ·················································· Mi respuesta: "En teoría ese servicio lo aceptó el padre y por tanto debería abonarlo él, es más, yo pensaba que eso ya estaría abonado. Menos mal que no continuó, pues la situación económica de Julia es bastante precaria. No obstante, pongo en copia a la sección económica, para que lo valore (subrayo en amarillo en el hilo, sólo son 20€), a ver si aceptan que lo abone ella, pues la chica que realizó ese trabajo no tiene culpa y al final el servicio lo recibió principalmente ella. En caso de que se acepte este gasto, necesitaríamos que nos enviases una DECLARACIÓN JURADA de ese servicio de “apoyo personal” con los datos de la persona en cuestión, las horas, el importe y el número de cuenta bancaria para que se le abonara mediante transferencia. Quedamos a la espera de confirmación por parte de la sección económica." ·························· Comunico a Esther, TS, que se acepta el abono del servicio privado de auxiliar. ··························· Reenvío a la secc. ecca. la DECLARACIÓN JURADA para que abonen cuando puedan.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS MARIA'and edp.apellido1='GRANDE'and apellido2='VICARIO'),'2024-06-17','Ana: Envío a la Residencia Virgen de la Montaña (virgendelamontana@grupociudadjardin.com): "Adjunto la autorización para la administración de la vacuna frente al neumococo debidamente firmada y sellada por la Representante Legal."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2024-06-17','Ana: Llamada de Felisi (614 361 144): No aguanta la convivencia con su hijo, está fumando muchos porros, la casa huele mal de nuevo, no se asea, ayer se quedó en la cama todo el día, se levantó a la 20:00h. ····· Dice también que se queda todas las semanas 50 €. **Se siente desesperada. ······························································································································································································· Envío correo a Toni y Nieves, Ed. Futuex (delegadapoyo.caceres2@futuex.es): "Quería preguntaros cómo va la búsqueda de vivienda para Aitor. Acabo de hablar con Felisi y se muestra muy desesperada con la convivencia con su hijo. Dice que está fumando de nuevo muchos porros y que la casa ya huele mal. Él para variar no colabora en nada en casa, pasa gran parte del día acostado hasta que sale con sus amigos. ¿Por cierto, cuánto dinero se está quedando de la cuantía autorizada para comida y sus gastos? Según su madre son 50 €. Es importante que se le encuentre una vivienda y que Felisa pueda volver a vivir sola y sin las preocupaciones y problemas que le genera su hijo. Sí él quiere llevar ese estilo de vida que lo lleve, pero que deje de perjudicarle a ella. También quería pediros, por favor, que me enviéis el informe médico de la consulta en el Otorrino de Felisi. Y cuando acuda Nieves a visitarles que escanee y nos enviéis las cartas que dice haber recibido del Juzgado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2024-06-17','Ana: Llamada de Felisi (614 361 144): No aguanta la convivencia con su hijo, está fumando muchos porros, la casa huele mal de nuevo, no se asea, ayer se quedó en la cama todo el día, se levantó a la 20:00h. ····· Dice también que se queda todas las semanas 50 € de la asignación. ································································································································································································ Envío correo a Toni y Nieves, Ed. Futuex (delegadapoyo.caceres2@futuex.es): "Quería preguntaros cómo va la búsqueda de vivienda para Aitor. Acabo de hablar con Felisi y se muestra muy desesperada con la convivencia con su hijo. Dice que está fumando de nuevo muchos porros y que la casa ya huele mal. Él para variar no colabora en nada en casa, pasa gran parte del día acostado hasta que sale con sus amigos. ¿Por cierto, cuánto dinero se está quedando de la cuantía autorizada para comida y sus gastos? Según su madre son 50 €. Es importante que se le encuentre una vivienda y que Felisa pueda volver a vivir sola y sin las preocupaciones y problemas que le genera su hijo. Sí él quiere llevar ese estilo de vida que lo lleve, pero que deje de perjudicarle a ella. También quería pediros, por favor, que me enviéis el informe médico de la consulta en el Otorrino de Felisi. Y cuando acuda Nieves a visitarles que escanee y nos enviéis las cartas que dice haber recibido del Juzgado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2024-06-17','TERESA TELEFNO JOSE 676258493','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2024-06-17','TERESA - Residencias caninas y demás no es posible por el tipo de perros (el otro que tiene además de Nerón también es de las mismas caracteristicas) - La madre lo único que ha hecho es llamar y amenzar a la policia, porque dice que según la nueva ley (que no se , si sera la protección animal o cual) es el ayuntamiento quien debe hacerse cargo y la policia local, dice qeu no tiene donde meterlos, y que ademas en el caso que tuvieran que intervenir, no se los devolverian a Maria, o bien lo sacrifican o lo que sea, obviamente esto no nos parece tampoco lo mejor, teniendo en cuenta que ahora dice Idilio, que la derivación va a ser muy muy complicada y que posiblemente en unos dias, le darán el alta. A pesar de que nos conocedores de que las ideas autoliticas continuan. -Se ha hablado con Maria también, que propone que hablemos con su vecina y que le digamos que se le pagaria lo que sea por ir a echarles comida, que o bien ella cuando salga o su madre lo pagaria, esto parecia lo mas razonable, pero es que esta señora, se va fuera el fin de semana, al principio no queria pero luego ha dicho que dadas las circunstancias que bueno que se ocuparia, pero es que no esta estos dias. -Tambien se ha intentando contactar con un amigo, de ella que estaba al tanto, pero está trabajando y no conseguimos aún hablar con el. - Como ultima medida vamos a volver a hablar con Maria, por si ella conociera a alguien en el pueblo que pueda ir estos dias, hasta que vuelva la vecina, para echarles comida. - La policia dice, que sino se da otra solución, tendran que ir el lunes y llevarselos, porque se sienten amenzados con la posibilidad de que la madre les denuncie... pero imaginate si le matan a los perros, la que se puede liar... Creo que no se me escapa nada, asi mas o menos está el asunto, vamos a intentar que alguien pueda ir a echarles comida, y a ver que conseguimos... ENVIO ESCRITO AL AYUNTAMIENTO COMUNICANDO LA SITUACION','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2024-06-17','Ana: Correo de Miguel, A. Jurídico: "Buenos días Ana, necesitamos nos indiques con quién podemos hablar para nos remitan testamentaria de la madre fallecida (certificado de defunción, últimas voluntades, testamento, certif bancario, nota simple…., lo que nos puedan aportar) y poder coordinarnos con su hermano José Manuel. Veo en el expte que ya se tramitó por la Ctaex la herencia del padre." ································ Envío correo a Cristina, Ed. Asociación Vera (educadorasocial@asociacionvera.com): "Recurro a ti, en base a la petición que me hace mi compañero Miguel, porque no sé en este caso con quién más hablar o a quién recurrir. A ver si tú sabes con quién podemos hablar o cómo podemos hacer para conseguir la documentación que necesitan mis compañeros jurídicos, si no la conseguimos no podrán tramitar la herencia de la madre. La cuenta bancaria donde estaba la madre aún tiene dinero y no sé qué más propiedades habrá. Subrayo en el hilo en amarillo Gracias de antemano y buen día."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2024-06-17','Ana: Correo de Felisa Custodio, TS CAMF (trabajadora_social_alcuescar@imserso.es) a los A. Jurídicos, con copia a mí: "me pregunta la residente si ya está hecha la renuncia ante notario y si le pueden mandar una copia, sus hermanos ya lo han hecho."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='YOLANDA'and edp.apellido1='CALDERA'and apellido2='MARTIN'),'2024-06-17','Ana: Correo de Estrella Durán, TS CSS-Plas: "Supongo que seréis conocedoras de que Yolanda Caldera Martín, va a ingresar de nuevo en la UHDAC..." ··············· No sabíamos nada, desde el CAMP no nos lo había comunicado. Tampoco las incidencias previas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LEON'and edp.apellido1='LEAL'and apellido2='PEREZ OLAGUE'),'2024-06-17','Ana: Llamo al HSPA (927 25 62 00), me pasan con Despacho Médico de NEUMOLOGÍA (51352), pero no obtengo respuesta. Intento llamar más tarde al despacho sin éxito. ····· Hablo con otro médico, no es el que le lleva, le pasará nota al Dr. Manuel Hdez. Valle - Neumólogo, para que se ponga en contacto conmigo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2024-06-17','Ana: Tras hablar con Mª Luisa, envío correo a Toni y Nieves, Ed. Futuex (delegadapoyo.caceres2@futuex.es) con copia a Minerva, TS CR Cervantes: "En relación a Mª LUISA MONTAÑA ALISEDA, nos ha llamado solicitando: 1- Traslado de centro. ---- Le he explicado que ya hace mucho tiempo que está tramitada la solicitud, pero dadas sus circunstancias (ingresó de forma involuntaria, vía Decreto) el proceso se enlentece y tiene prioridad las personas con dependencia (ella no tiene grado reconocido). Parece haberlo entendido, no sé cuánto le durará. 2- Solicita un aumento de la asignación para comprarse ropa interior y para darle dinero a su hija. ---- En cuanto a esta cuestión, le he dicho: a. Que su hija ya es mayor de edad y tiene que ser ella la que cubra sus propias necesidades. Además, dada la trayectoria de su hija, no se le debería facilitar dinero así como así. Y en caso de que presente una necesidad real y ella quiera ayudarla, debe de llegarnos la solicitud por otra vía, con justificación de profesionales de qué cuantía requiere y para que la necesita, para que desde la sección económica tengan justificación al respecto de cara al juzgado. b. Si necesita ropa, Nieves, Educadora del Programa de Apoyo Comunitario le acompañará a solicitar presupuesto y nos lo hará llegar. Una vez abonado a la tienda mediante transferencia, podrán acudir a recogerla. Pongo en copia a Minerva, Trabajadora Social del Centro Residencial para que esté al corriente y para que os podáis coordinar con ella en cuanto a la necesidad de ropa de María Luisa. Considero conveniente aprovechar para solidar todo lo que necesite en estos momentos, no sólo ropa interior si fuera el caso."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2024-06-17','Ana: Estrella, TS - CSS Plas me comunica que ha ingresado Miguel Ángel en UME. ······························································································································································································ Envío correo a Alberto, Jefe Secc. Ecca: "Acaban de comunicarme que MIGUEL ÁNGEL RAMOS ANDRÉS ha ingresado en Unida de Media Estancia del Centro Sociosanitario de Plasencia. Puesto que ha llegado sin dinero y necesitará para gastos de bolsillo, HAY QUE ENVIAR AUTORIZACIÓN GENERAL DE CENTRO. Tras hablarlo con la TS y teniendo en cuenta sus escasos ingresos, proponemos: - 200 €/mes para gastos de bolsillo - Si necesita ropa o algo más, que nos consulten previamente y se autoriza según necesidad/viabilidad. Para que lo podáis especificar en el correo que enviéis al Socio." ······························································································································································································ Envío correo a Toni-Futuex: "No sé qué compañera tenía asignado a MIGUEL ÁNGEL RAMOS ANDRÉS. Tan sólo informaros que me acaban de comunicar que hoy ha ingresado en el Centro Sociosanitario de Plasencia, derivado por la UHB (yo no sabía que había estado allí ingresado de nuevo…). Si aún no habéis podido contactar e intervenir con él, creo que es un buen momento para empezar. Sería conveniente trabajar con él para que pudiera aceptar una derivación a CRR cuando se pueda proceder a su alta. También lo he comentado ya con Estrella, sino volverá a situación de calle y vuelta a empezar…"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANTIAGO EDUARDO'and edp.apellido1='MAYORAL'and apellido2='SUAREZ'),'2024-06-17','Ana: Correo de Lourdes, Secc. ecca: "Ok a la ropa, se hace transferencia a la cuenta de Aspace."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='AVILA'and apellido2='FEMIA'),'2024-06-17','Ana: Envío correo a Alberto, Jefe S. Ecca: "Te reenvío coreo con documento de cobro indebido de Dependencia relativo a JOSÉ LUIS ÁVILA FEMIA, es anterior a estar el cargo aceptado por la CTAEx (marzo y abril de 2023) No es mucho: 300 + 80 €."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2024-06-18','miguel, recibo email de Carlos Arjona (abogado) He estado en Coria y ni en el Registro Civil, ni en el Juzgado (buscando el divorcio suyo) han logrado localizarme el DNI. Mañana hablamos y comentamos opciones, porque el miedo que tengo es que como no haya muerto se quede con todo,','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='GARCIA'and apellido2='RAMIREZ'),'2024-06-17','miguel, envío email a la oficina de Mérida a Carmen Becerra cbecerra@ibercaja.es por que Maria Soledad Fermoselle no está: le reenvío email que envíé a José Luis (documentación acreditativa de nuestra representación y la innecesariedad de asistencia en la compraventa y el ptmo personal), junto con los modelos de transferencia que vamos a poner a la firma. aunque envíe y hablé con la oficina de Mérida de ibercaja (José Luis) toda la documentación relacionada con Auto de innecesariedad de pedir autorización judicial, junto con sentencia de incapacitación, nombramiento, aceptación de cargo, documento privado de compromiso de pago de dicho ptmo personal, y portanto no es necesario el firmar por parte de la Ctaex la documentación del ptmo y la compraventa, me envía este email Marisol el 14-6-24: Buenas tardes, Miguel Nos informan desde Ibercaja ( Maria Soledad Rubiales Fermoselle), que José Antonio puede pasar por la oficina a Firmar el Préstamo personal 30.000 € el próximo Lunes o Martes, después dicho Documentos debe ser Firmado por, María Ángeles Estrella Lavado, Directora Gerente del Servicio Extremeños de Promoción de la Autonomía y Atención a la Dependencia (SEPAD). Nos puedes informar cómo procedemos con esta gestión. ¿Debe ir Maria Estrella en persona a Ibercaja? ¿Se puede firmar el documento a través de firma digital u otro dispositivo? La intención es cerrar esta gestión lo antes posible, para que haya saldo suficiente en la cuenta para el día de la firma de las escrituras. Marisol me envía los datos de nuevo de la oficina de Badajoz de Ibercaja y persona de contacto: Te dejó el contacto solicitado: María de la Soledad Rubiales Fermoselle Gerente de Banca Personal Oficina 4570 Badajoz Avenida Ricardo Carapeto Zambrano, nº 39 06008, Badajoz Tel 924 252 911- Fax 924 242 540','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='GARCIA'and apellido2='RAMIREZ'),'2024-06-11','miguel, hablo con José Luis jlmartinezl@ibercaja.es de la oficina de Ibercaja de Mérida y le aclaro que no es necesaria la intervención de la Ctaex ni en la Compraventa ni en el ptmo personal: Buenos días José Luis, conforme hemos hablado telefónicamente adjunto la solicitud de autorización para la compra e hipoteca que se hizo al juzgado junto con la documentación que se adjuntó, unido al auto denegatorio en el sentido que el juzgado lo estima innecesario y por tanto el curatelado (curatela asistencial) puede firmar por si mismo sin necesidad del juzgado ni de la comisión tutelar de adultos. Adjunto también documento privado firmado por el curatelado José Antonio Garcia Ramirez y el justificante de transferencia de la señal. Quedo a vuestra disposición para aclarar cualquier duda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2024-06-18','Ana: Correo de Ángel, Asesor Jurídico: "Os envío Auto de revisión de medidas de Ramos Bargón. “Se procede a la constitución de la CURATELA asistencial para la conducción en la vida cotidiana (vestido, higiene, compras, citas médicas) y la CURATELA representativa (referida al aspecto económico, administrativo, contractual, jurídico, tanto en relaciones públicas como privadas, o institucional, además de en el control y seguimiento del tratamiento médico)”. Inés, por favor, cuando puedas, solicita testimonio de firmeza del Auto (tiene fecha de 31/5/24), y una vez lo tengamos, acepta el cargo. Alberto y Ana. No obstante lo anterior, ya sabéis que el recurso no suspende la ejecución del Auto, así que podemos actuar, hasta donde nos dejen."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CESAREO'and edp.apellido1='PANIAGUA'and apellido2='CALLE'),'2024-06-18','Ana: A petición de Ángel, A. Jurídico, envío un correo a la dirección de que disponemos de la Asociación "NUNQUAM SANTIS" (hildegardamil@hotmail.com): "En relación a CESAREO PANIAGUA CALLE, residente en su recurso y cuyo cargo ostenta la Comisión Tutelar de Adultos de Extremadura, reenvío correo de mi compañero Ángel, Asesor Jurídico de la CTAEx, con diligencia de ordenación relativa a la revisión de las medidas de apoyo señalando para el día 10/10/2024 a las 11:30 horas reconocimiento personal. Por favor, háganselo llegar a Cesáreo y apoyen en el desplazamiento y asistencia al Juzgado. Solicitamos así mismo, si tienen conocimiento de la existencia de familiares, nos comuniquen los datos de contacto de los mismos para hacerles conocedores de la vista, pues también deberían asistir. Ruego confirmación de recepción de este correo." ······································································ Reenvío correo a Toni - Futuex y especifico: "En relación a CESÁREO PANIAGUA CALLE, te reenvío correo remitido a la ASOCIACIÓN "NUNQUAM SANTIS". Según consta en la base de datos el domicilio es: Ctra. De Pasarón, de la localidad de BARRADO (Cáceres). De este chico no tenemos teléfono de contacto directo. He intentado sin éxito, en varias ocasiones desde febrero, contactar con el Padre Miguel Muñoz (679 077 448), sin éxito. Dado que al correo anterior que envié no obtuve respuesta, os solicitamos que, por favor, cuando os sea posible, acudáis a dicha localidad e intentéis localizar al propio Cesáreo y/o al Padre Miguel para hacerles llegar la diligencia de ordenación adjunta. Así mismo, indaguéis si existen familiares directos y, de existir, si tiene contacto de los mismos, para que se le pueda informar acerca de esta citación a la que también están llamados." ····················································································· *Respuesta de Toni: "Intentaremos hacerselo llegar, anotado. Pero si es cierto que nos estaba siendo muy complejo poder ver a este señor, por la falta de colaboración del cura, entre otras cosas, asique no me extraña nada, lo que comentas. Ahora estamos empezando con la primera fase de evaluación del programa y como se recoge en el proyecto, hay que tener un número de usuarios adscritos, entonces pues hacemos altas y bajas, y a Cesareo lo ibamos a proponer como baja, por que se han intentado en varias ocasiones y es bastante dificil acceder a el, es un hombre mayor, con un grado moderado/alto de discapacidad, y realmente en este sistema donde vive, está integrado (está en huerto y determinadas cosas) si es cierto que el sistema es un tanto extraño, el cura que lo lleva es muy hermetico y cuesta acceder a ellos, son un poquito sectarios, pero eso es que pasa aveces en este tipo de "recursos" asique por esto desistimos de los seguimientos regularmente, pero si, sin duda, hacemos está gestión puntual."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CASTILLO'and edp.apellido1='SOLIS'and apellido2='MELENDEZ'),'2024-06-18','ALBERTO: ESTRELLA: NOSOTROS NO HEMOS GENERADO NINGÚN PROBLEMA...LA CUESTIÓN LA HA SUSCITADO LA ENTIDAD FINANCIERA. DESDE UN PRIMERO MOMENTO SE ESTABLECIÓ QUE EN CCC CAIXABANK ES20 2100 5698 9401 0045 7918 (SOLO TUTELADA): LE TRANSFERIAMOS 1.000 €/MES DESDE IBERCAJA (PENSIÓN). MARIDO TRANSFERÍA 130 €/MES A CCC CAIXABANK. EN ESTA CCC CAIXABANK CARGABAN TODOS LOS RECIBOS ASOCIADOS A GASTOS COMUNES. SE ESTABLECÍA UN REINTEGRO PERMANENTE DE 1.000 €/MES. HABLA CON CAIXABANK Y LUEGO DECIDIMOS. ACTUALIZAR AUTORIZACIÓN REINTEGRO.??? O TRAMITAR TARJETA PREPAGO. ??? ESTRELLA: CUANDO ESTO SE VAYA ACLARANDO HAY QUE HABLAR CON AMALIA/TUTELADO PARA QUE LES QUEDE CLARO COMO HACER LOS REINTEGROS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LEON'and edp.apellido1='LEAL'and apellido2='PEREZ OLAGUE'),'2024-06-18','Ana: puesto que ayer no me devolvieron la llamada, llamo al HSPA, al Despacho Médico de NEUMOLOGÍA (51352 / 51346), pero no obtengo respuesta en ninguno de los dos números. ······························································································································································································· Correo de Sara, enfermera de la Residencia Santa Ana (malpartida@nexusintegral.com): "ME HAN LLAMADO DEL HOSPITAL PARA COMUNICARME QUE LE DAN EL ALTA A LEON LEAL PEREZ OLAGUE, VENDRA CON OXIGENO UNAS 16 HORAS AL DIA, NO SE SI PRECISAS ALGO MAS ME COMENTAS." ·············· Solicito nos envíen escaneado el Informe de Alta que entiendo le darán en mano a León.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2024-06-18','Ana: Correo de Estrella Durán, TS CSS-Plas.: "veo que Miguel Ángel Ramos Andrés ha ingresado por cumplimiento de medida de seguridad de internamiento dictada en ejecutoria 253/2022" ·················· Reenvío a los A. Jurídicos. ················ Correo de Ángel: "...teníamos conocimiento de la Ejecutoria nº 253/22, en la que se suspendía por plazo de 2 años la ejecución de la pena privativa de libertad de tres meses impuesta, condicionada a que durante dicho periodo de suspensión no volviera a delinquir, pues de hacerlo y ser condenado por ello, se podría decretar la revocación de la suspensión y acordar la ejecución de la pena suspendida. Del ingreso no teníamos conocimiento. Si ha ingresado entiendo que será porque ha incumplido la condición que le pusieron."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2024-06-18','-Amalia : escribo a la RM y le paso documentación. He pedido ingresos actualizados a la S. eco para calcular el copago . Escribo a CRR y le doy contactos para organizar el traslado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARMEN'and edp.apellido1='PARRA'and apellido2='PEGUERO'),'2024-06-18','Ana: Llamada de Adriana Ramos, Directora de la Residencia de Mayores Virgen de la Luz - Arroyo de la Luz (Nº directo: 675 82 91 35 // Nº Residencia: 927 27 22 29 / 616 296 044). La TS se llama Merche (trabajadorasocialresidencia@arroyodelaluz.es). ··················· Han recibido Resolución Judical de medidas de apoyo CURATELA ASISTENCIAL Y REPRESENTATIVA. ············ Puesto que sólo nos consta como Defensa Judicial nos enviarán el documento. ····················································· Carmen se ingresó con un Deterioro Cognitivo. Está muy adaptada al centro. ······················· Les informo que una vez firme la sentencia y aceptado el cargo se les solicitará Informe Social y otra documentación para la confirmación del inventario. ················································································ Correo de Adriana, Directora RRMM (direccionresidencia@arroyodelaluz.es)al ctutela@, a la Att. de los A. Jurídicos, con copia a mí: "Carmen Parra Se encuentra interna en la Residencia Publica de Mayores "Virgen de la Luz" de Arroyo de la Luz desde el 4 de diciembre de 2023, ocupando una plaza pública y no teniendo familiares en el Centro, así como apenas conocidos en la localidad. El proceso de medidas judiciales de apoyo comenzó anteriormente por parte de los Servicios Sociales de Base.Al notificarnos dicha resolución (aun no firme) de curatela y donde se establece la representación y asistencia para todas las actividades que no pueda realizar por sí misma es el motivo por el que nos ponemos en contacto con ustedes. Les envio la Resolución, así como el modelo del consentimiento para la vacuna del neumococo para que en su caso cuando lo estimen oportuno puedan enviarnoslo. Les mando tambien el correo de la Trabajadora social (Merche) de esta Residencia"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2024-06-18','Ana: en relación al correo recibido ayer del Puesto de la Guardia Civil de Navas del Madroño, C/ Isabel Herrero 73 C.P. 10930 ☎️ 927375014 (cc-pto-navasmadrono@guardiacivil.org): "Podéis llamar mañana por la mañana, al Puesto de la Guardia Civil de Navas del Madroño 927.37.50.14, para tratar un tema de AITOR MORENO FELIPE. MUCHAS GRACIAS." ····························· Llamo y me informan que Aitor está denunciado por ESTAFA. La denuncia está interpuesta en Albacete por un DELITO LEVE - ONLINE: Puso un producto a la venta en Wallapop por 70€, la persona interesada se lo pagó y él no le entregó nada. ···· La Guardia Civil tiene que investigarlo y le tomarán declaración el jueves 20 entre las 9:00 y las 10:00 h. ····················································· Comunico a Futuex y pido que Nieves, Ed. le acompañe. Solicito confirmación de dicho acompañamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGELA'and edp.apellido1='RODRIGUEZ'and apellido2='FIGUEREDO'),'2024-06-18','TERESA TELFNO QUINI CUIDADORA 642781990','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2024-06-18','Ana: Juan Carlos Cano, Aux. Adtvo. (juancarlos.cano@salud-juntaex.es) me remite Justificante del regitro que le remití para PNC solicitando copia de la carta. ··············· Guardo en el expte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2024-06-18','TERESA Por medio de la presente le comunicamos que el paciente Jose Vicente Vicente acudió ayer a Urgencia de Mérida, para valoración por psiquiatría. Se trata de un paciente que en estos momentos no tiene criterio para hospitalización por psiquiatría. El paciente está Tutelado por la Junta de Extremadura, su padre lo saco de la casa por lo que está en situación de calle en estos momentos y a pesar de todas las gestiones realizadas desde la noche de ayer y la mañana no han respondido a esta problemática. Por lo que pongo en conocimiento que el paciente esta de alta y retorna a Don Benito porque el día de hoy tiene cita con si ESM. Teléfonos a los cuales nos comunicamos sin respuesta: 663851388 924003804 Padre 618867743.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2024-06-18','TERESA envio por registro solicitud de revison PIA para que le asignen centro residencial de discapacidad para llevar a cabo el ingreso involuntario','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIO'and edp.apellido1='GUISADO'and apellido2='GUISADO'),'2024-06-18','TERESA Eugenio ya ha terminado aqui su tratamiento y mañana a las 11:00, vendrá un taxi a recogerlo, Salustiano, y Lorena Conejo, que le acompañará en el traslado hasta su Centro de Plena Inclusión de Cabeza del Buey. Por favor tened preparada toda su medicación, informes, Tarjeta sanitaria y demás para el traslado. Una vez se marche notificaremos la BAJA T3 AL SEPAD, PARA QUE NOS ENVÍEN UN NUEVO T3.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2024-06-18','TERESA He conseguido plaza en RM MUNICIPAL DE BARCARROTA (Tipo T4, baja intensidad de cuidados) para Elena. Lo que sí me exigen es que en el informe de psiquiatría se especifique que "no padece alteraciones comportamentales que vayan a afectar al normal desarrollo y convivencia de un centro residencial" También necesitamos la herramienta T4 para justificar (te la adjunto para que la haga enfermería , todos los valores serán 1 dado que la señora no precisa de ese tipo de atenciones). En cuanto lo tengas me lo pasas por correo electrónico y adelante!! El ingreso no voluntario actualmente no procede que lo notifique el centro si la señora se muestra interesada en el ingreso, pero desde la Comisión podréis solicitar que os revisen la sentencia que tiene antigua y añadirlo (si lo consideran pertinente), sino estaremos entrando y saliendo de los centros, no queda más remedio. Por otro lado, voy a notificarlo también a la residencia para que vaya conociendo el caso y daré tu teléfono de contacto si te parece bien A LA ESPERA DE RESOLUCION PARA HACER EL TRASLADO A LA RESIDENCIA DESDE EL HOSPITAL DE LLERENA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2024-05-22','Ana: Correo de Felisa Custodio, TS CAMF-Alcuéscar (trabajadora_social_alcuescar@imserso.es): "Buenos días, la madre de la residente mencionada falleció el pasado 05/02/2024. Les adjunto: - Certificado de defunción de la madre. - Certificado carencia de seguro de fallecimiento. - Certificado no otorgamiento de testamento. - Certificado de saldo de su madre por importe de 461 euros. - Certificados de préstamos de la madre, pendiente de devolución 8741 euros y pendiente de devolución tarjetas por importe de 184 euros y 6847 euros respectivamente. - Movimientos de la cuenta bancaria desde el 06/02/2024 de la madre. - Abogado que está tramitando documentación a la hermana de Carmen, llamada Rocío Gómez. Dada la deuda que ha dejado su madre, me dice la residente que quiere renunciar a la herencia, son cinco hermanos en total. Ruego nos indiquen como debe hacer o si el trámite ante el notario lo debe realizar la CTAEX. Muchas gracias. Saludos." ······························································································································································································· Respuesta de Ángel, A. Jurídico: "En relación a su correo electrónico, precisamos que Dª. Carmen renuncie formalmente a la herencia de su madre. Envío un modelo para que lo firme y nos lo devuelvan."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2024-05-24','Ana: Correo de Felisa Custodio, TS CAMF-Alcuéscar (trabajadora_social_alcuescar@imserso.es): "adjunto documento firmado por la residente. Me pide que una vez hecha la renuncia ante notario, nos remitan una copia del documento."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2024-05-22','Ana: Ana, TS de Autimos Sur, me remite INFORMES MÉDICOS DEL INSTITUTO NEUROLÓGICO DE BARCELONA de la dos primeras sesione. Guardo en el expte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='PLATA'and apellido2='MACEDO'),'2024-06-18','-Amalia : escribo a Ana Mariscal . Buenas , qué tal ? Te reenvío email de Mar , la TS del ESM de C. Jardín. Vamos a pedir plaza en ECA para intentar tratar , si ella colabora , su problema de adicción al juego . Te voy contando la evolución . A nivel de psiquiatría está compensada , le han cambiado la medicación a inyectable mensual . Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='MARIN'and apellido2='LAUREANO'),'2024-06-18','Ana: Correo de Teresa, TS CTAEx: "Me ha llamado la TS del hospital San Pedro de Alcántara. Esta ingresada Rosa, me preguntan cómo actuar si fallece. Le he informado que contraten el servicio con una compañía y te pasen la factura. Desconocen si hay familiares para avisarles" ······································ Rosa tiene 99 años. no tiene seguro de decesos, pero tiene dinero más que suficiente para abonar los gastos del SEPELIO llegado el caso. ···························································································································································································· Correo de Obdulia, TS HSPA (obdulia.romero@salud-juntaex.es): "Informo que la paciente arriba indicada, se encuentra ingresada en este HSPA desde el día 08.06.2024, se le ha aplicado medidas de confort, situación que he comentado con tu compañera Teresa, indicando como proceder para enterramiento, sin aclarar donde se procedería ese enterramiento.       Esperando contestación a la mayor brevedad posible." ············································································· Mi respuesta: "He intentado contactar sin éxito con la residencia de mayores en que vivía Rosa. Pues aquí desconocemos dónde quería ser enterrada. Hace mucho tiempo que Rosa no tenía contactos con familiares, ya ni la llamaban ni visitaban. He conseguido contactar con un sobrino, Natalio, quién también desconche esta información, pero me ha dicho que aunque la hermana de Rosa es muy mayor intentará hablar con ella para comunicarle la triste noticia y preguntale al respecto. Puesto que mañana yo asistiré toda la mañana a unas jornadas de trabajo y mi jefa está enferma, pongo en copia a otra compañera, Amalia, para que esté al corriente y llegado el caso pueda hablar contigo. Amalia, le he facilitado tu número a Natalio, sobrino de Rosa, para que mañana nos indique la localidad para el sepelio. Rosa no tiene seguro de decesos, pero puede asumir sin problemas el gasto de la funeraria, tanto para el entierro en sí como para el traslado del cuerpo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2024-06-18','Ana: REUNIÓN UHB, ESM, U.PP.AA. y CTAEx: Una vez contextualizada la situación en que se encuentra Julia, se decide que desde la UHB se procederá a derivación UME. Si se acepta, comunicaré a Dependencia cambio de domicilio y solicitaré que le valoren en el propio CSS por la Instrucción 47.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2024-06-18','Ana: Llamada de Cristina Donoso, Psiquiatra ESM-CC (54605): ha hablado con Francisco, no acudirá a la consulta programada de mañana porque se encuentra en Cádiz. Le ha dicho que la semana que viene volverá a Cáceres una semana, pero que después se volverá a marchar a Cádiz. ···· No lo ha notado bien del todo. Está un tanto EUFÓRICO. ······· Le ha dado nueva cita para el próximo martes día 25 a las 10:30 h. Intentará reconducirlo al plan inicial para que regrese a Cáceres y derivación a Comunidad Terapéutica. ·········································· Comunico a Toni- Futuex y solicito acompañamiento a la consulta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2024-06-18','Ana: Correo de Estrella Durán, TS CSS: "Mañana se va de pase Enrique 10 días a domicilio." ···················· Reenvío a Toni y Clara, Ed. Futuex, para que organicen las visitas de seguimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='VALERO'and apellido2='AGUEDO'),'2024-06-18','-Amalia : Pido a Pilar Salguero de nuevo el informe para justificar la emergencia social al perder la plaza en menores. Me dice que eso no pueden ponerlo por escrito . Vuelve a llamarme , han cambiado de opinión y aceptan que se quede allí un año más. No presento la petición de plaza por emergencia , la pediré para entrar en la lista y sólo la ciudad de Badajoz y OLivenza .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='MARIN'and apellido2='LAUREANO'),'2024-06-19','Ana: Correo de Alfredo, director del CRR (residenciaplasenzuela21@gmail.com): "Como te dije es bastante difícil que nos den información sobre Rosa Marín, la única forma de obtener algo de información es cuando la enfermera va a la doctora y busca la información en el jara.. Te informo que han visto que le han puesto una sonda nasogastrica, debido a la negativa de ingesta de alimentos y líquidos. Poco más te puedo decir. Cuando tenga más noticias te iré informando." ················································ Mi respuesta: "Gracias por informar. Precisamente ayer a última hora se puso en contacto conmigo una de las Trabajadoras Sociales del hospital, al parecer está ya muy delicada y posiblemente fallecerá en los próximos días u horas. Intenté contactar contigo pero saltó el buzón de voz y te dejé un mensaje. Puesto que no tiene seguro de decesos le dijimos que pueden llamar a una funeraria, pues tiene dinero más que suficiente tanto para el traslado del cuerpo como para el sepelio. Pero no sabemos si en algún momento ella ha expresado el deseo de dónde quiere ser enterrada, para comunicarlo al hospital. Por favor, si lo sabéis, comunícamelo antes de las 8:50 por esta vía o por teléfono, que después me tengo que marchar a unas jornadas de trabajo. Si es más tarde, díselo a mi compañera Amalia, que está ya al corriente. Estos son sus datos de contacto: amalia.diaz@salud-juntaex.es / 924 00 60 30"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2024-06-19','Ana: Confirmo a la guardia civil (cc-pto-navasmadrono@guardiacivil.org) el acompañamiento de Nieves a Aitor a la tomas de declaración de mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2024-06-19','miguel, envío email a Alberto y Tere, con copia a Maite y Angel: Buenos días, tras enviar en abril a la notaria de Cabeza del Buey la documentación que teníamos d ela herencia de los padres del tutelado, me han contestado hoy que al tener testamento se podía firmar la herencia. El problema que tenemos es que cuando desde la parte social nos avisasteis de que había vendido una vivienda en Castuera parece ser que era cierto, la vendió según me dijo la notaria Elsa Caballero (emcaballero@notariado.org , 924-760707), siendo la compraventa hecha el 8-1-24, protocolo 3. La compradora Yolanda (desconozco los apellidos) compró a 850€/mes de forma previa, sin que lo acreditase. He enviado el 14-5-24 tras la conversación con esta notaria de Castuera, la documentación acreditativa de la incapacitación, nombramiento y aceptación del cargo de la Ctaex. El 14-6-24 envío nuevo email a la notaria sin respuesta. Hoy llamo a la notaria y no me lo cogen. Motivo por el cual he llamado al tutelado Pedro Tomás Murillo Matías 641-745023, el cual me comenta que tuvo una recaída en aquellos momentos y al coincidir que nadie le visitó, se estuvo drogando, verbalizando que la venta fue amañada y le engañaron tanto la compradora como la notaria porque estaba drogado. Le he pedido que se acerque a la notaria y que les diga que me envíen todo lo firmado por él, porque si bien es cierto que sabemos que se ha hecho una venta, dónde está la herencia previa de los padres?(que es la documentación que os digo envíe para la fueran preparando a la notaria de Cabeza del Buey). Creo que hay motivos suficientes para intentar impugnar dicha venta vía judicial e incluso solicitar al juzgado que si ha habido posible delito de engaño y/o estafa sea decidido por el mismo. Quedo a la espera que el tutelado consiga la/s escritura/s de compra y herencia. Desconozco si nos la querrán cobrar (él dice que no le dieron nada). Si acaso nos requieren el pago no deberían ser más de 30 o 40€ cada copia simple de cada escritura. Tere si te llaman o envían algo avísame.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN LUIS'and edp.apellido1='LOZANO'and apellido2='ORDOÑEZ'),'2024-06-20','miguel, recibo email de Ale la compi, Hablé ayer con la hermana (620811035 es el número que responde). LA HERENCIA YA ESTA HECHA. Le digo que me envíe al correo electrónico la documentación, me dice que no tiene correo electrónico…. Le hablo por wasap para que me pase fotos (porque dudo que tenga los documentos en pdf en el móvil) y estoy pendiente de respuesta… CUANDO LAS TENGA TE LO HAGO SABER. Y ME DICE QUE LA CASA DE VILLAGONZALO C/ LAS CRUCES, Nº2 ES PROPIEDAD DE NUESTRO TUTELADO. ¿CÓMO NO NOS CONSTA? ************************************* mi contestación con copia a Alberto, parte social, Maite y Amalia, y Angel: Buenos días, os informo, he llamado a la abogada, que me ha localizado Ale (la compañera), Julia Ferreira 924-301759 quién antes de aceptar el cargo la comisión de curador representativo, tramitó la herencia vía judicial. La documentación de la herencia familiar se la llevó ayer por la tarde Maria José, y me comenta Ale que no tiene forma de enviarnos dicha documentación para saber qué bienes ha heredado. La abogada se muestra colaboradora y en unos días me enviará lo que haya en el juzgado y hablará con la hermana del curatelado, Maria José para que le acerque de nuevo la documentación que pueda haber de dicha herencia para enviármela. En cuanto a la vivienda que me preguntaba Ale, sita en c/ las cruces nº2 de Villagonzalo, me comenta la abogada Julia que hubo muchos bienes en la herencia y ésta puede ser la que ellos llaman la casa grande y que seguramente se adjudicó el curatelado Juan Luis Lozano Ordoñez (no José Luis), y también cree que debe haberse inscrito todo en el registro de la propiedad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2024-06-20','TERESA RECIBO LLAMADA DE LA PSIQUIATRA DE LA UHB DE MERIDA, ME DICE QUE TIENE EN OBSERVACION A JOSE VICENTE Y QUE NO TIENE CRITRIO PARA INGRESO QUE LE BUSQUE UN RECURSO PORQEU NO TIENE DONDE IR HABLO CON CASA DE ACOGIDA DE CACERES, TIENE UNA PLAZA LO VAN A VALORAR MIENTRAS TANTO SE LE PROPONE PASAR LA NOCHE EN UN HOTAL A LO CUAL SE NIEGA Y ME DICE QEU SE VA DE NUEVO CON SU PADRE Y QUE VA A BUSCAR UNA HABITACION PARA ALQUILAR EN DON BENITO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2024-06-21','miguel, email de Toni de Futuex: En relación a la gestión para apoyar a Pedro Tomás Murillo e intentar recopilar la información tanto de la compra venta como de la herencia, de acuerdo, se intenta la gestión sin problemas. Solicitar unicamente una aclaración, hay que intentar ir con el a la notaria de Castuera y también a la notaria de Cabeza del Buey no? por los documentos de la compra venta y la herencia respectivamente? al residir en Monterrubio de la Serena, tendremos que ver si hay opción de bus o si no , gestionaremos servicio de taxi para ir con el,. Intentaremos que colabore para ello, cada vez que hemos indagado tanto sobre la herencia como la supuesta venta, ha eludido el tema, manifestando que estaba muy drogado y no recuerda nada de la herencia de sus padres, ni sabe si firmo nada. Esto puede ser cierto, pero al respecto de la venta, mantenemos ciertas reservas, en torno a la supuesta coacción que ha expresado, creemos que pudo ser una estratagema para obtener dinero para los consumos y que fuera una operación realizada voluntariamente. Lo que si es rotundamente falso, es que en ese momento de esta venta no recibiera el apoyo semanal de este programa, en la figura de la educadora de la zona de Don Benito, que lo viene visitando con una regularidad, semanal generalmente, desde el 1 de Diciembre del 2023. (Antes al acudir desde Badajoz, se le veia una vez a la quincena, aproximadamente). Adjuntamos el diario de campo, donde se observa que tuvo seguimientos presenciales dias antes y también posteriores a esta operación de compra/venta, este documento es donde se viene reflejando brevemente lo observado en los seguimientos, compartido en la herramienta con vosotros, que se viene elaborando desde el inicio del proyecto. Creemos que en este momento continua en un consumo activo, en el momento que realizó esa operación y en la actualidad, no estando dispuesto a recibir un tratamiento especifico para rehabilitarse por completo, como pudiera ser acudir a una comunidad terapéutica.Si bien a pesar de estas conductas, tiene muchas habilidades conversacionales y posiblemente intelectivas, y capacidad para autogestionarse en según que aspectos, por lo que es razonable pensar que esta operación de venta, la mantuviera en secreto ocultandosela a la persona de apoyo, asi como a otros profesionales de la localidad (pero fue precisamente a traves de los rumores en la localidad, donde la trabajadora social del ssb empezó a tener esta sospecha). No nos consta si está recibiendo o recibió dinero por aquella operación, habitualmente miente y manipula la información. De hecho, no tiene dinero de libre disposición, acordado como medida para minimizar que tome sustancias, y se le apoya en las retiradas, compras, y etc. En el dia de hoy, y suponemos tras la conversación con Miguel, se ha puesto en contacto con la educadora para ahondar en que cuando realizó esa operación no se encontraba plenamente consciente y llega a afirmar que fue manipulado tanto por la compradora como por la notaria para firmar, según el, manipularon su firma y las escrituras reales de la casa en cuestión. Por otro lado, menciona tambien que la persona a la que vendió la casa puede tener audios donde Pedro confirma la venta de esta propiedad... (hasta el dia de hoy no habia dicho nada relativo a este asunto de la venta) Es por todo ello y fudamentandonos en los seguimientos que desde hace años viene realizando el equipo de apoyo social comunitario con este caso, no podemos afirmar con rotundidad que fuera coaccionado para la venta de este inmueble, o que fuera una operación voluntaria realizada para la obtención de dinero o para saldar deudas contraidas con los consumos. Ninguno de los supuestos van a ser confirmados, en cualquier caso , por el. Enviaremos la información que se obtenga de las notarias en cuanto se ralice la gestión. -------------------------------------------------- Mi contestación con copia a Tere y Maite: Buenos días Toni, sólo hay que acompañarle a la notaria de Castuera a retirar una copia simple de la compraventa protocolo 3 de 8-1-24 de la Notaria Elsa Caballero, que firmó en la notaria de Castuera. Si os piden ingresar algún importe sobre la marcha que nos lo digan y se haga transferencia por la Comisión. A parte de la compraventa, seguramente firmó una herencia previa, que lo pregunte y que le den también esa copia simple de la herencia de sus padres. Una vez tengáis las dos, si él quiere denunciar que le engañaron, tendríais que acompañarle a poner la denuncia a la policía o guardia civil indicando las dos escrituras que acreditan que transmitió la vivienda sin recibir dinero, según él estaba drogado y le engañaron. Luego escaneadlas y enviádnosla junto copia de la denuncia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2024-06-20','Maite: he entregado la elección de centro a la sección de discapacidad. Lo hemos dejado abiertos a todos para tener mas posibilidades.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2024-06-21','TERESA En el día de ayer, cuando Adolfo se personó en el despacho, venía en unas condiciones pésimas de aseo e higiene, desprendía un fuerte olor corporal signo de falta de aseo. En el día de hoy, se ha recibido whatsApp de la trabajadora Social del Centro de Salud en la que nos pone en conocimiento que en la noche de ayer estaba por la calle en malas condiciones y que avisando a la policía lo llevaron a urgencia y de ahí al Hospital Tierra de Barros y apreciaron falta de aseo y signos de que no se estaba tomando la medicación, determinaron que no era para psiquiatría de Mérida. El hermano, que supuestamente se encargaba de apoyarle, se fue a Palma el 5 de mayo. La comida se la llevan diariamente desde un bar. Teniendo en cuenta la falta de medicación, de aseo personal y de la vivienda y su no asistencia a las consultas de psiquiatría, todo ello manifestadoi asi mismo por Patricia, la profesional de Futuex que realiza el seguimiento de Adolfo, sería necesario y conveniente retomar este tema y que se busque alternativa de centro donde pueda ser atendido y recibir las atenciones medicas y de alimentación y aseo que precisa. El Tlf de la Yohana, la DUE que conoce el caso y que atendió ayer a Adolfo es 676399558 Espero que podáis hacer algo y que podamos aprovechar que no está el hermano para retornar al planteamiento del principio respecto a la intervención que se merece y requiere Adolfo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='AVILA'and apellido2='FEMIA'),'2024-06-24','Ana: Estrella, Secc. Ecca. me confirma que ya está abonado el cobro indebido de José Luis.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2024-06-24','Ana: Correo de Toni, Futuex, al ctutelar@: "se tiene conocimiento hoy a través de la cuñada de Juanjo Maseda, Azucena, que se pone en contacto con la educadora para comunicarle que Juanjo necesitaría un extra para comprar unas zapatillas y ropa de verano para Juanjo. La educadora contacta también con Juanjo y él confirma que necesita zapatillas, ropa de verano y unas sábanas también de verano, él pide aproximadamente 100 euros para todo esto. Se envía propuesta para valoración de la CTAEX. Se le acompañará a la retirada en caso de aprobrarse y a la compra" ························ Se acepta presupuesto. Estrella, S. Ecca. hará la autorización para la retirada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALMUDENA'and edp.apellido1='CORREYERO'and apellido2='PAREJO'),'2024-06-21','Ana: Correo de Paula, TO CRR (tocupacional.crrplasencia@grupo5.net): en las últimas intervenciones hemos elaborado con Almudena un presupuesto que recoge las necesidades, dinero de bolsillo y una valoración anual para desembolsos más puntuales. Así hemos estimado: Podólogo 20; Depilación completa 60; Pañales 60; Bolsillo (max 4/día) 124; teléfono 10; Higiene 50; actividades de ocio u otras 50; estimando así una cantidad mensual de 370 euros. Así mismo, estimamos un extra "anual" hasta dic/ene de 600 euros, para compra de ropa de temporada, calzado, prendas más especiales o similares. Esperamos vuestra respuesta para confirmar con Almudena o aclarar si es necesario alguna cuestión. Os recordamos la importancia de realizar la autorización para extracción del dinero en la misma oficina que en la última ocasión y a las mismas personas ya comunicadas (Félix Macías y Carolina Monroy) cuyos datos constan en correos anteriores." ····························································································································································································· Respuesta de Amalia: "Me parece bien el presupuesto establecido para Almudena Correyero , la Sección económica gestionará la autorización. Con ésto se finaliza el Plan de Intervención Inicial en centro por mi parte , el caso pasa a la zona de mi compañera Ana para seguimiento . Esperemos que aproveche esta nueva oportunidad para hacer el cambio que necesita , y se distancie de Miguel Ángel . "','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LEON'and edp.apellido1='LEAL'and apellido2='PEREZ OLAGUE'),'2024-06-24','Ana: Guardo en el expediente el Informe de Alta del Serv. de NEUMOLOGÍA del HSPA, remitido desde la Res. Nexus Residencial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALMUDENA'and edp.apellido1='CORREYERO'and apellido2='PAREJO'),'2024-06-24','Ana: Correo de Amalia, TS CTAEx: "La parte económica ya ha gestionado el reintegro para Almudena . Por el momento el cambio al CRR de Plasencia está siendo positivo. Con ella se trabaja bien siempre que no aparezca su amigo Miguel Ángel , que es el mismo que otra curatelada denunció por V. Género. Al alejarla de Don Benito , sólo ha ido una vez a verla . Viaja en autobús y a Plasencia ya no tiene la facilidad para viajar . Lo último que se descubrió la semana pasada , cuando fueron a gestionar lo del reintegro , se le han cargado desde febrero diferentes facturas a nombre de unas personas que desconocemos . De tf, Sanitas ... Ale ha podido devolver todos esos recibos . He preguntado al CSS y al CRR de Mérida y nadie conoce a esas personas . Alguien ha utilizado su Nº de cuenta para cargar esos recibos . Ella tampoco sabe quienes pueden ser y su padre tampoco. Se ha notificado a la entidad bancaria para que estén pendientes."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='LOPEZ'and apellido2='GILARTE'),'2024-06-24','Ana: Tras recibir llamada de Rosa, Técnica de Protección de Menores - SSTT CC (64851), envío correo a la Secc. Jurídica: "Me preguntan desde menores si hemos recibido ya el auto de nombramiento de Curador del menor ALEJANDRO LÓPEZ GILARTE. Este chico cumple la mayoría de edad el 7 de septiembre. Ya les he explicado que hasta que no tengamos la firmeza y cumpla la mayoría de edad no se podrá aceptar el cargo. Ya me decís cuando podáis." ·················································· *Alejandro reside en Plasencia, en el mismo piso que residía su hermano. ······· Ya han solicitado plaza en D. Discapacidad. Están pendiente del perfil del CADEX. ··· Dejarán la solicitud abierta a todos los centros, aunque lo ideal sería que le dieran plaza en el mismo centro en que vive su hermano Darío, también a cargo de la CTAEx (Vivienda Tutelada de Inclusive de Vva. De la Serena) ················································································ Respuesta de Ángel, A. Jurídico CTAEx: "Tenemos el Auto, pero no es firme, lo hemos solicitado recientemente"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PILAR'and edp.apellido1='JIMENEZ'and apellido2='AGUILAR'),'2024-06-24','Ana: Tras recibir llamada de Pilar (722 14 55 10), envío correo a Alberto, Jefe S. Ecca: "Te envío la solicitud a ti directamente porque entiendo que en este caso tendrás que actualizar la ficha y valorar tú. Pilar Jiménez Aguilar, solicita extra para ropa de verano. Se le ha formalizado recientemente el seguro de decesos. También hay pendiente abonar a su pareja, Jesús, la parte proporcional de la fianza del alquiler (creo que lo teníais anotado). Calcula cuánto se le puede dar, pues le hace falta." ···························································································································································································· Respuesta de Alberto, Jefe S. Ecca.: "SALDO: 537 € A 24/06/2024. INGRESOS: PNC BASICA: 517 €/MES. GASTOS: REINTEGRO 304 + ALQUILER/CONSUMOS 170 + DECESO 12 + OTROS 15: 501 €/MES. ALE: OK A REINTEGRO "EXTRA ROPA VERANO" X 150 €....SALVO QUE ANA PREFIERA UNA CANTIDAD MÁS BAJA U OTRA LIGERAMENTE SUPERIOR. ANA: ESTA PERSONA NO VA MAL, PERO EL SALDO PARA CUALQUIER EVENTUALIDAD QUE PUDIERA SURGIR ES TOTALMENTE INSUFICIENTE...SI SEGUIMOS COMO HASTA AHORA: SIN APENAS EXTRAS..EN UN PARA DE AÑOS, PODRÍA ESTAR RAZONABLEMENTE BIEN."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL MAR'and edp.apellido1='CAMPOS'and apellido2='ENCINAS'),'2024-06-24','Ana: Recibo Informe Social solictado para la revisión de las medidas. ································ Tras recibir tb llamada de Mª del Mar (648 625 099), envío correo a la Secc. Jurídica: "Os envío el Informe Social pendiente para la revisión de Medidas de María del Mar Campos Encinas. Precisamente me ha llamado hace un momento comunicando que le ha llegado una carta del Juzgado citándola para el día 27 a las 13:30 h, me pregunta para qué es, yo entiendo que es para la revisión de las medidas. Confirmádmelo cuándo podáis."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2024-06-24','Ana: envío correo a Estrella Durán: "En relación a Enrique Santos García Puente, te adjunto la solicitud debidamente firmada y sellada por la Representante legal y el justificante de haber abonado las tasas (modelo 50) ya diligenciado por el banco. Cuando regrese Enrique ya podrá firmarla y junto con la foto podréis registrarla." ································································································································································································ Tras recibir llamada de Enrique (634 417 155), y hablar con Estrella Durán, TS CSS, envío correo a Estrella, Ana Benavente, TS ESM, Puerto, TS SSASB, Clara y Toni - Futuex: "Os escribo, más que nada, para que estéis al corriente sobre la incidencia de hoy relativa a ENRIQUE SANTOS GARCÍA PUENTE. Enrique se fue de pase a su casa durante 10 días el pasado miércoles 19. Según me dice, en el Centro Sociosantario le dieron 70 €, de los cuáles manifiesta que sólo le queda “3-4 €”. En cuanto al tabaco, dice que sólo le dieron 2 paquetes y que por tanto tuvo que comprar 8 en el estanco, así que se ha gastado 40 € en este concepto. De los 10 paquetes en total, expresa que sólo le queda paquete y medio. También dice que no pudo comprar el billete de ida y vuelta, que sólo pudo comprar el de ida. Por lo que ahora llama para pedir dinero. Eso sí, dice que comida tiene de sobra, que compró lo que le indicaron en la lista. Como vemos, cada vez que la estancia es superior a 4-5 días, la gestión no es la adecuada, gastando más de lo que debe, consumiendo más tabaco que en el centro y volviendo a pedir más dinero. Tal y como le había dicho a él, he llamado a Estrella, me corrobora que Ana, Terapeuta del Sociosanitario, ya había hablado con él esta mañana y que le ha dicho que no se le va a conceder más dinero, pues se le había dada dinero suficiente para los gastos que habían calculado para estos días. Manteniéndonos en la decisión del equipo del centro he devuelto la llamada a Enrique diciéndole que no se le va a dar más dinero y proponiéndole que devuelva un paquete de tabaco en el estanco para que tenga dinero para el billete de bus de vuelta. Dice que no puede devolverlo porque ya lo ha abierto… como podréis imaginar no le ha gustado nada las decisión tomada. Insiste en que no tiene para regresar, que el billete a Plasencia cuesta 2,20 € (creo que ha dicho) y 1.05 € el del bus urbano. Con esas cuenta le he dicho que con el dinero que dice que le queda (3-4 €) debería tener para regresar, al menos a Plasencia y, en el peor de los casos, desde la estación podría ir caminando hasta el centro. Por supuesto se ha enfadado y ha colgado el teléfono. A ver cómo sigue estos días. Si no me equivoco, el miércoles irán a visitarle Clara y Gloria, del programa de apoyo comunitario gestionado por Futuex."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='PLATA'and apellido2='MACEDO'),'2024-06-25','Manuela continua en la misma situación. Nos traslada una enfermera en incluso está pidiendo dinero por las salas del Hospital Perpetuo Socorro. Todo el día en la calle. Le solicité cita con ECA- Los Pinos. Cita con Trabajo Social el día 9 de Julio a las 10:00h. Solicito a FUTUEX acompañamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-06-25','Ana: Llamada de José Manuel, dice que ha ya cobrado la paga extra y quiere comprarse un altavoz. Enviará un presupuesto. ························ Por otra parte dice que no ha hecho la revisión del gas (butano) desde que falleció su padre, por lo que no le sirven tampoco el butano a casa. *Le digo que es peligroso e importante hacerla. ····· Solicitará presupuesto a la empresa y nos lo enviará.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUSTAVO ALFREDO'and edp.apellido1='CASTAÑO'and apellido2='SOTO'),'2024-06-25','Ana: Correo de Amalia, TS CTAEx, a Toni Futuex y a mí: "Me ha llamado Gustavo , este expediente lo llevé yo hasta marzo . Es el chico que salió del Ctro. Penitenciario de Sevilla y está viviendo en un piso familiar en Cáceres . Solicita un extra de la paga doble de 300 € para retirar el día 15 de julio, para hacerlo coincidir con los 300 quincenales que retira al mes . Se le aceptó un extra de 200€ para el día 1 de julio para compras de ropa y demás. En total se le darían 500€ de extra en julio de los 800€ que percibe de pensión. Tiene ahorros también y todos los meses le quedan en cuenta alrededor de 150€ tras pagar los suministros que tiene domiciliados. Me dice que necesita ese dinero para pagar una avería del aire acondicionado , comprar alguna cosa que le falta de mobiliario de la casa y para invitar a su madre y hermanos a comer por su cumpleaños. Me comenta que recibe a menudo la visita de la D. Tutelar y que está muy contento con ella . Os paso este email a las dos para que comprobéis la información que me ha trasladado y se valore ese extra. Si lo que me ha comentado es verdad yo lo veo bien. Ana , si das el OK se lo remites a S. Eco para que lo pueda gestionar ." ·············································· Respuesta de Toni: "Por parte del equipo, en virtud de los seguimientos, si lo veis factible, no parece bien. Se organiza bastante bien, y suele aceptar el apoyo con buen grado, colaborando y generalmente justificando todo el gasto que pide." ····················································· Envío propuesta a Alberto, Jefe Secc. Ecca y añado: "Te reenvío correo de Amalia con propuesta de EXTRA para GUSTAVO ALFREDO CASTAÑO SOTO. Viendo lo que expone Amalia y que desde Futuex nos comunican que está funcionando bien, aceptando el seguimiento y los apoyos y administrándose adecuadamente, por mi parte OK al extra solicitado. Ya me dices cuando puedas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2024-06-25','Ana: Tras informarme María, Secc. Ecca, envía correo a Alberto con copia a mí: "Hola Alberto, sería posible darle a esta señora algo de dinero, aunque sean 20 o 30 € al mes, para gastos de bolsillo, su situación económica sabemos que no está bien... Ana esta al corriente de todo esto. Nieves de Futuex me ha llamado para proponerlo, ahora ha cobrado la extra y tiene en el banco 1475 € de saldo. Lleva desde 10/2023 en la residencia de Alcuescar, y no ha tenido nunca ningún extra...."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO DAVID'and edp.apellido1='REBANALES'and apellido2='NIETO'),'2024-06-25','ya he contactado con vivienda , efectivamente faltan unos recibos por pagar . He solicitado que me lo actualicen y nos van a enviar el total de lo que se debe . Si se puede , ahora que tiene algo ahorrado , lo suyo sería regularizar el pago de vivienda. Aunque está a nombre de su madre Petra Nieto , viven los dos y sI se la quitan se quedarían en la calle. Estoy de acuerdo en anular la tarjeta , aunque creo que ya se intentó en alguna ocasión y se busca las mañas para conseguirlo de otra forma. De hecho , muchos de esos pagos los hace con una tarjeta de compra de Carrefur. Ya fuimos a hacerle una visita hace unos meses y su colaboración va a ser nula . Entre la discapacidad que tiene y sus hábitos , es complicado . La madre también tiene una discapacidad , perciben 420€ cada uno de PNC . Y con eso cubren todos los gastos en común. La madre me comentaba que ella está pagando todo , comida , suministros.. porque él se gasta el dinero en compras . Tenía una TV más grande que el sofá y no había comida en la nevera. Seguimos..','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='YOLANDA'and edp.apellido1='CALDERA'and apellido2='MARTIN'),'2024-06-25','Ana: Envío correo a Tere, TS y A. Jurídicos CTAEx: "En relación a YOLANDA CALDERA MARTIN, me pregunta Soraya si se ha solicitado ya al Juzgado autorización de internamiento involuntario para que pueda ingresar de nuevo en la UHDAC. Según dice Soraya el viernes pasado Maite le dijo que ya estaba hecho. Pero dice que hay que enviarle reporte a Estrella, TS de referencia de la UHDAC en el CSS. Lo he comentado con Ángel y dice que no ve nada en el expediente. Miguel no sé si tú has hecho algo al respecto. También he hablado con Teresa y ella no sabe tampoco. Si aún no se ha hecho, Tere, habrá que solicitar Informe Médico al CAMP de Plasencia para que se pueda adjuntar al escrito para el Juzgado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANDRA'and edp.apellido1='GONZALEZ'and apellido2='ESCASO'),'2024-06-25','-Amalia : envío email a Eva y Estrella : Hemos recibido esta comunicación , no sabemos a quién pertenece porque no han puesto el nombre de la persona , sino de la Rpte. Legal. Como piden nominas del Ayto . De Montijo imagino que será de SANDRA GONZALEZ ESCASO. Os lo envío para que podáis remitir lo que solicitan a PNC . La declaración de la renta se lo pregunto a mi compañera Estrella, lo estaba gestionando una gestoría y si estuviera hecha me encargo de registrarla.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2024-06-25','Ana: Llamada de Raquel, TS SSASB (605 429 865), me pasa a Juan, pide 200 € para ropa para retirar mañana mismo, que hay mercadillo. .... Le indico que seguramente no será posible para mañana mismo, pues requiere unas gestiones previas y la firma de la representante legal. ·························· Hablo con Raquel más tarde. Expresa que como retire él sólo el dinero, es posible que se lo gaste en máquinas tragaperras. *Lo ideal es que le acompañen. Pediré a Futuex que el miércoles de la semana que viene acompañen a Juan a retirar el dinero y a comprar la ropa en el mercadillo. ·································································································································································································· Correo de Toni- Futuex, a última hora: "Como sabes, está siendo muy complicado, el seguimiento con Juan en los ultimos tiempos, porque entre otras cosas, rechaza frontalmente a la compañera de la zona (sobra decir, que no hay ningun motivo que lo justifique) no le deja ni que hable directamente se va de donde está. Todo posiblemente tiene que ver con su delirio generalmente constante, pero es cierto que hasta ahora, en todo el tiempo que se le ha visitado, no habiamos percibido que personalizara su frustración en nadie. Ha ido más allá con un medico de primaria, como comentamos, al que parecer agredió. Y creemos que tiene una orden de alejamiento (desde ssb nos piden que si podemos confirmar que tiene orden de alejamiento, pero no sabemos si a esto os han dado traslado o como poder averiguarlo). Uno de los motivos, que están dificultado la intervención, es el dinero, Juan cree que la compañera le debe llevar dinero y aunque esto sabemos que no es asi, y que no tiene ninguna lógica, es una de las cosas que dice. Aunque tal vez, si podria considerarse valorar, el abono de determinadas deudas que ha ido contrayendo y que tambien al final inciden sobre el rechazo social en la localidad. Sabemos que el tiene su asignación y que no deberia pedir en ninguna tienda nada sin dinero y que no se lo deberia fiar sobretodo, pero si que viene arrastrando algunas deudas, las dejamos por aqui por si se valora el abono. El jueves, haremos una intervención en equipo, con las dos educadoras (la antigua y la nueva) a ver si conseguimos trabajar en la adherencia nuevamente de Juan, pero está muy negado. Tambien se reuniran con la ts del ssb y con la del cs, por si pueden colaborar, según manifiestan y ya lo han hecho en otras ocasiones les resulta tambien muy complicado trabajar con el. Aunque son cuestiones distintas, lo que desde nuestro punto de vista, deben realizar los servicios comunitarios in situ, y los servicios de apoyo que puede poner a disposición la comisión, con este programa, a distancia. A ver el jueves como va la cosa, te iria comentando En cuanto a las deudas pendientes, testeadas hace ya un par de meses, (esperemos que no se hayan incrementado) : 1. Estanco: 13€ (Número de cuenta IBAN: ES16 0030 5107 1902 9344 5273) 2. Arreglo del calentador de agua: 54,45€ (Número de cuenta IBAN: ES18 0049 1328 4128 1007 2570) 3. Aún estamos a la espera de recibir la factura correspondiente al importe pendiente en un bar, por lo que les solicitamos su colaboración para determinar el curso de acción adecuado. El total acumulado de las deudas asciende a la cantidad de 67,45 euros."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2024-06-26','Ana: Envío correo a Toni, Futuex, con copia a Clara, Ed. (delegadapoyo.plasencia@futuex.es) y a Critina Hdez, TS CSS: "En relación a JAIRO PUERTAS MARTÍN, se ha llegado al acuerdo con el Centro Sociosanitario de darle la oportunidad de irse a vivir a piso de alquiler manteniéndole en hospitalización parcial. Dado que percibe PNC con Complemento a 3ª persona, podría invertir en torno a 350 € en alquiler (hay que tener en cuenta que a este gasto habría que sumar los gastos de suministros, móvil, alimentación, gastos de bolsillo, así como ropa, calzado y otras cuestiones cuando sea necesario). Él siempre dice que no le importa compartir piso. Os solicitamos, por favor, que le apoyéis en la búsqueda de nueva vivienda y nos hagáis llegar presupuestos así como el contrato llegado el momento. Pongo en copia a Clara, Educadora, y a Cristina, TS de referencia del C. Sociosanitario."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='PLATA'and apellido2='MACEDO'),'2024-06-26','Hola Amalia, buenos dias Hemos anotado la citas para ECA, y se le apoyara en el seguimiento, pero tenemos serias reservas que vaya a acudir, o mas bien, no sabemos bien como poder comunicarle la información, porque no la encontramos en domicilio, ni yendo a distintas horas del dia. Es por ello, que hemos pensado desde el equipo, que alomejor se podria valorar, como una opción el que solo pudiera dinero acompañada, es decir no solo como un elemento de control para el tema del juego patologico, sino poruqe tal vez de esta manera nos garantizaríamos poder verla e intentar trabajar con ella determinadas cosas, ella obviamente imaginamos que no querrá pero en este momento no vemos otra opción.. te lo paso, para que se pueda valorar esta propuesta. Hacemos breve nota, para informar de los datos obtenidos en los últimos seguimientos que se han realizado con Manuela o con profesionales del entorno. Contactar con ella es imposible, como decimos, evita los seguimientos además de no estar localizada por vía telefónica, su teléfono sale apagado quizás pueda deberse a rotura del terminal y ella no se preocupa por dicha situación. El día 13 de junio se consigue localizar a Manoli en el Centro de Salud Ciudad Jardín, ese día tiene consulta en psiquiatría y de forma general suele asistir, aunque no respeta los horarios. El psiquiatra no valora ingreso involuntario ya que indica que no tiene patología de salud mental y no está desajustada en este sentido (aun viendo la falta de higiene personal, el bajo peso que nuestra por la falta de una alimentación saludable, su adicción al juego y sus conductas diarias de mendicidad). Le administran Abilify Maintena 300 mg, en la consulta ella reconoce la adicción a las máquinas tragaperras y que utiliza la mendicidad para obtener dinero. Si bien, el reconocimiento desde nuestro vista, no implica el que quiera revertir esta conducta, de ahi que no sabemos exactamente como ira lo de ECA. El inyectable se lo ponen amenzandola que si no la ingresasn, y asi accede. La administración de este inyectable es mensual necesitando retirarlo de la farmacia con anterioridad y debe ser puesto en el centro de Salud de Ciudad Jardín siendo difícil que Manoli adquiera la responsabilidad de llevarlo a cabo con continuidad además de no aceptar los apoyos para facilitarle que continue con esta pauta médica. Se adjunta informe de psiquiatría al email. Desde el programa vamos a su médico de familia el 20 de junio para obtener todos los datos posibles de su situación médica, nos facilita la última analítica realizada la cual la adjuntamos al email. La médico no nos puede facilitar más datos ya que Manoli no acude a su médico hace meses. Hace semanas habia otra facultativo que si nos indicó que ralizaria un informe, pero se marchó y no lo hizo. En la analítica se muestran parámetros alterados posiblemente por la falta de alimentación adecuada. Próximas citas: 11 julio enfermería salud mental (administración inyectable), 8 de Julio ECA 24 septiembre revisión psiquiatría. En relación a la dificultad para poder realizar seguimientos con ella, desde el programa valoramos que tal vez la única manera de localizarla pudiera ser teniendo como pauta obligatoria la retirada de su pensión en la entidad bancaria con acompañamiento semanal o quincenal según se estime desde el área económica. Aprovechando estas retiradas para trabajar otras pautas de autonomía personal y poder llevar un mejor seguimiento médico. Facilitamos los datos de las profesionales de Futuex, que cubririan este acompañamiento, por si se estima favorable esta posibilidad, para hacer la autorización, como en otros casos : Gloria Águedo Marín (Terapeuta Ocupacional): DNI 80054156B Teresa Pacheco Cruz (Monitora – Educadora): DNI 0881380C --','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='JIMENEZ'and apellido2='PICON'),'2024-06-26','Ana: Envío a Toni-Futuex, HOJA DE DERIVACIÓN AL PROGRAMA, para visitas de seguimiento, en todo lo relativo a su estado de salud, y para gestiones puntuales, tales como compra de ropa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='PLATA'and apellido2='MACEDO'),'2024-06-26','Buenas Toni , Me parece una propuesta estupenda, que os va a facilitar mantener el seguimiento . Aunque sea para ir a retirar el dinero tendrá que aceptar obligatoriamente que se le acompañe. Se lo paso a la Secc. Eco para que en julio el reintegro mensual de 600€ ( si no recuerdo mal esa es la cantidad exacta ) , pase a ser quincenal de 300€ y que tendrá que ir obligatoriamente acompañada por alguna de las delegadas tutelares de las que se facilita su identificación. Me dicen que Manuela se viene a diario de Gévora en el primer autobús a Badajoz , y se queda por la zona de la estación de autobuses a pedir . Ha llegado incluso a pedir dentro del H. Perpetuo Socorro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DEL MAR'and edp.apellido1='CAMPOS'and apellido2='ENCINAS'),'2024-06-26','Ana: Tras hablarlo con Ángel, A. Jurídico, confirmo a Mª del Mar (648 625 099), que a la cita en el Jdo. de mañana acudirá algún abogado de Abogacía General de la Junta. ································· Envío correo a Mamen, Educadora Futuex (delegadapoyo.caceres@futuex.es) explicándoselo también. ············ Respuest de Mamen: "Mañana acompañaré a M.ª del Mar, y después, pasamos una nota recogiendo los sucesos. Aprovecho para comentarte que M.ª del Mar funciona estupendamente, se le está apoyando en distintas áreas, una de ellas el área laboral, debido a la autonomía que presenta dentro de su diagnóstico."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='VAZQUEZ'and apellido2='MUÑOZ'),'2024-06-26','Amalia : adjudicación de la plaza de Centro Ocupacional y Residencia de Apoyo Limitado para Jonathan Vázquez Muñoz en La Luz , pido calcular copago .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2024-06-26','Ana: Envío correo a los A. Jurídicos consultando si hemos recibido ORDEN DE ALEJAMIENTO del médico del pueblo al que agredió. ····························· Envío correo a Toni-Futuex: "Sí, sé qué Juan rechaza a la educadora nueva, María, si no me equivoco. Ayer mismo él me lo manifestó mediante llamada de teléfono desde el despacho de la TS del SSASB. También decía que no quiere “ni a esa ni a nadie”, como siempre no quiere seguimiento ni control de ningún tipo. Sigue sin aceptar ningún recurso comunitario y, a excepción de con Teresa, en general nunca ha “congeniado” con ninguna otra delegada de apoyo. Entiendo que no es por la compañera en cuestión, quedad tranquilas ambas. En cuanto a la reunión de mañana, me lo han dicho tanto Raquel, SSASB, como Clara, C. Salud. Yo no puedo ir presencialmente ese día, tenemos que estar obligatoriamente una aquí y soy la única que está el jueves, pero si en la sala que os reunáis hay ordenador con webcam intentaremos conectarnos por meet para poder estar aunque sea así. Si no fuera posible, no pasa nada, se levantará acta de la reunión y ya me la harán llegar. Entiendo que será positivo acordar el modo de coordinación entre la Educadora con Raquel y Clara y de actuar con respecto a Juan. *Recordad que es una Curatela de tipo Sanitaria y que en este casi se controla el dinero en base a la misma, porque sino no se podría garantizar mínimamente su bienestar. En relación a las deudas, ¿tenéis documentos de alguna de ellas y/o los datos de contacto de los establecimientos? Más que nada por si la deuda ya fuera mayor y porque necesitamos los justificantes. Sólo tenemos lo que tú anotas en el correo. Voy a pasárselas a Alberto, jefe S. Ecca., con el OK al abono de las mismas por mi pate, aunque sabéis que él tiene la última palabra. Pero con la propuesta/requisito, de que acudáis acompañando a Juan a los distintos establecimientos informando que se abona pero que será la última vez que se haga sin presupuesto y aprobación previa desde aquí. *Se me ocurre que como vais mañana, si os da tiempo, es buen momento para hacerlo, para que él vea que se le apoya y se va a abonar y ya de paso solicitáis la facturas actualizadas y los contactos, por si fuera necesario. *Por último, Juan solicita un EXTRA DE 200 € para ropa, para comprar en el mercadillo del pueblo de los miércoles. Al igual que se le aprobó el año pasado, se le va a aprobar. Lo pidió ayer a última hora y quería tenerlo para esta misma mañana. Ya le dije que eso no era posible y tendría que esperar pues requiere una serie de gestiones. *Como Raquel después, cuando volví a hablar con ella cuando no estaba Juan, me dijo que de nuevo gasta mucho en las máquinas tragaperras, no nos parece buena idea que retire el dinero él solo sin saber su destino. Por tanto, SOLICITAMOS que el miércoles de la semana que viene se le acompañe a retirar el dinero y a comprar la ropa y calzado que necesite en el mercadillo y pidáis recibos/factura. Porfa, confírmame esto último para que, María, compañera de la Sección Económica pueda especificar la fecha en la autorización que enviará al banco, y comunicádselo a Juan mañana por favor. Pongo en copia a María, Ed., María, compañera de secc. ecca. y a Maite, jefa de sección."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2024-06-27','Ana: Reenvío a Clara, TS C.Salud, Toni-Futuex y María, Ed. Fututex la respuesta de Ángel, A. Jurídico "No me consta que se haya dictado orden de alejamiento. La denuncia la enviamos al Juzgado el 5/6/24.". Pido se lo reenvíen a Raquel, SSASB, o me faciliten su dirección de correo. ······························································································································································································· Se mantiene reunión en el C. Salud de Guadalupe con todos los profesionales que intervienen o han intervenido con Juan desde el ámbito comunitario. ················· *Devuelvo a Clara, TS C.S. el ACTA DE LA REUNIÓN firmada por todas las personas asistentes, en la que se solicita se convoque SUBCOMISIÓN DE CASOS DE SALUD MENTAL. ·················· Ella la remitirá a Pablo, TS del ESM-Trujillo. ·········································································· * Juan tiene CITA para el INYECTABLE el 8/07. En agosto con la Enfermera de Salud Mental y en Septiembre con el Dr. Miguel Medina, Psiquiatra ESM.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2024-06-26','Ana: correo de Myriam Abrio - Centro Vida - Caritas: "comunicarte que Paco está en Centro Vida con nosotros de nuevo (en principio solo hasta el próximo lunes 29/06/2024) para que tengas dicha información, ya que tengo entendido que no tiene móvil por lo que me imagino que no habrás podido contactar con él en un tiempo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2024-06-27','Ana: Llamo a Myriam Abrio, TS Centro Vida - Caritas (605 68 05 53 / 927 23 50 82): me informa que "Paco" está de nuevo con ellos desde martes al final de la mañana. No dijo nada de que tenía cita programada para ese mismo día a las 10:30 h y no quiso asistir. ······ Intentarán trabajar con él para que se quede más días y para que vuelva a adherise al tratamiento médico y seguimiento en el ESM. ···················· *Me enviará Certificados de estancia. ····································································· Envío mail a Toni y Nieves - Futuex: "Me comunican desde Centro Vida, Cáritas, de Cáceres, que Francisco Cacho está de nuevo en su recurso. En principio hasta el lunes, si consiguen trabajar con él para que está más tiempo así será. Os lo comunico para que podáis retomar el seguimiento. Está sin teléfono, pues al parecer lo vendió. Pero podéis acercaros allí o contactar con él a través del propio centro."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2024-06-27','TERESA El expediente de este señor quedamos que iba a ser valorado por salud mental que tenía un cita (no recuerdo para qué mes). También se había tramitado la Dependencia y se estaba a la espera de la valoración. He visto que en el programa aparece un SIN GRADO con fecha de valoración 13/06/2024 por lo que por esa vía poco se puede hacer ya. Con respecto a nuestra solicitud, con las alteraciones comportamentales no se podía coger, por eso se esperaba a que pasara por salud mental y ver cómo se adhería al nuevo tratamiento, para que nos pudieran certificar que ya no tenia alteraciones ¿cómo está eso? Te he llamado pero a lo mejor estas de viaje ... Como urgente no se puede tramitar porque está en centro residencial. De momento se tiene en lista de espera.....pero de plazas de asistidos (es muy difícil que entre rápido). Insisto en que si el hombre no tiene deterioro cognitivo (que lo indican sus informes con interrogación¿?) lo estamos perjudicando porque el listado de asistidos por esta vía no se mueve mucho....sin embargo por autónomo, sería diferente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO MARIA'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2024-06-27','TERESA DATOS AUXILIAR QUE CUIDA A DIEGO LOS FINES DE SEMANA Adoración Cuéllar blanca Le decimos Dori ES7230010015031520029328 ese es el número de cuenta,muchas gracias,si quieres te mando su número de teléfono por cualquier cosita 645 864 076','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2024-06-27','Ana: tras recibir llamada de Juanjo (643 641 375), envío correo a Toni-Futuex: "En relación a Juan José Glez Carrero, me ha llamado preocupado porque le dio a Nieves hace 2 semanas el recibo para abonar el IBI y aún no está abonado, quiere pagarlo ya pues le da miedo que pase el plazo y haya que abonarlo después con recargo. ¿Podrías por favor enviárnoslo a la atención de la sección económica al ctutelar@salud-juntaex.es?" ······················································································· María, S. Ecca. tras hablar con el entidad bancaria, envía a la oficina correo autorizando carguen en cuanta el IBI.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2024-06-25','Ana: Llamada de Cristina Donoso, Psiquiatra ESM (54605) comunica que Francisco ha acudido a primera hora por allí para comunicar que no iba a asistir a la consulta programada de las 10:30 h. ····· Les ha informado también que ha vendido el teléfono, por lo que no se le puede localizar. ······· *Volverán a reprogramar la cita para el mes de julio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2024-06-27','Ana: Llamo a Myriam Abrio, TS Centro Vida - Caritas (605 68 05 53 / 927 23 50 82): me informa que Pedro Garvis está de vacaciones. Me enviará ella el certificado firmado de estancia de Miguel Ángel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='SOLANILLA'and apellido2='LUJAN'),'2024-06-27','Ana: Correo de Pilar Martín: "SU PSIQUIATRA PLANTEA LA DERIVACIÓN A CRR. TE RUEGO QUE ME LLAMES AL 45612 O AL 695-194-573 PARA HABLAR DEL TEMA." ········································· Intento llamarla varias veces sin éxito. ······················· Respondo al correo: "Lo cierto es que Sergio lleva mucho tiempo ya demandando el CRR, por tanto, si el Psiquiatra lo ve procedente y él lo firma no vamos a poner impedimento."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2024-06-27','Ana: Llamo a Consuelo, Psicóloga y Responsable del Centro de Acogida Temporal de Cáritas- Plasencia (927 42 04 48): Salió de Centro de Personas sin Hogar el 31 de mayo de 2024, se fue de manera voluntaria, en teoría porque había venido una amiga suya. A pesar de que había consumido el 28 de mayo se le dio otra oportunidad. Debido a la expulsión de su "amiga" del centro decidió marcharse otra vez. Estas conductas están dentro de su dinámica habitual, hace muchos años que le conocen con múltiples ingresos en su recurso. ····· Sus salidas suelen estar unidas a un consumo... *Necesitaría una COMUNIDAD TERAPÉUTICA, pero él no lo acepta. ····· Cuando está en el Centro sí acepta asistir al ECA, pero luego deja de asistir. ······························· Según su normativa tienen que pasar 4 meses tras las salidas voluntarias para que puedan volver a ingresar. ······························· Me enviará Cdo. de estancias de este año.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2024-06-28','TERESA INFORMACIÓN DE SEGUIMIENTO El día 21 de junio de 2024, José Vicente Vicente se pone en contacto con nosotros para informarnos que ha pasado la noche en el Hospital de Mérida, mientras supuestamente se le asigna una plaza en un albergue. Una vez hizo esta operación. Sin embargo, minutos más tarde, se nos comunica que ha sido expulsado del hospital y que los profesionales le han indicado que debe regresar a su domicilio habitual en Helechosa de los Montes. Ante esta situación, José Vicente se encuentra muy agitado y menciona que su objetivo es ir a la sede de la Comisión, de la cual creemos que desconoce su ubicación exacta, con la intención de solicitar dinero. El día 24 de junio de 2024, contacta con la educadora para informarle que tiene previsto visitar pisos de alquiler en la zona de Don Benito. Cabe mencionar que el costo aproximado del alquiler será de 250 euros mensuales. La tarde del 25 de junio, el padre de José Vicente se ha puesto en contacto para informar que, debido a encontrarse en situación de calle, ha decidido regresar a casa. Para poder costear el autobús hacia su pueblo, ha tenido que vender su teléfono móvil, lo cual explica por qué no ha respondido a nuestras llamadas. Asimismo, su padre ha expresado su deseo de tomar medidas legales contra la comisión tutelar. Ahora nos comunica una ts de Talarrubias que puede que hubiera una plaza de CRR para el, vamos primero de todo a sonderarlo a ver si el está, dispuesto,.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2024-06-28','Ana: Contactos de Raquel, TS SSASB Guadalupe: 605 429 865 // ssbvilluercas@yahoo.es ································································································································································································· Guardo en el expte. digital de Juan Informa del Dr. Medina, Psiquiatra, ESM, junto con las siguiente citaciones: 12 Septiembre citas en ENFERMERÍA Y PSIQUIATRÍA - ESM. ······················································· Envío correo a Clara, C.Salud, Toni y María, Futuex y Raquel, TS SSASB: "Acabo de leer este correo que me enviaron precisamente ayer mientras manteníamos la reunión. Como podéis ver en el documento adjunto le cambian la cita de enfermería. La de Psiquiatría no sé exactamente el día que la tenía, así que no sé si es la misma. Yo deduzco, por el cambio de cita de enfermería de Salud Mental, que Juan tendrá que ponerse el inyectable mensual de agosto en el centro de salud de Guadalupe."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2024-06-28','Amalia , consulto a Eva por la P. Orfandad que ha dejado de percibir , por si sabe algo al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2024-06-28','Ana: En relación al correo de Estrella, TS CSS: "Te escribo porque volvió Enrique del pase y dice que se le ha roto la puerta de la casa, la del jardín sí está cerrada con candado. Él por ahora no va a ir de pase. Os lo digo para vuestro conocimiento, por si puede ir alguien de Futuex con cerrajero a arreglarla...." ····················· Lo reenvío a Toni-Futuex y añado: "Te reenvío correo de Estrella, TS del C. Sociosanitario. ¿Es posible que Clara acuda a con algún profesional a la vivienda de Enrique para éste valore el arreglo de la puerta? Necesitamos que nos envíe presupuesto y se arregle la misma."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2024-06-28','Ana: En relación al correo de ayer de Estrella Durán, TS CSS Plas. (estrella.duranc@salud-juntaex.es): "Acaba de ingresar Julia Morón en nuestro centro. Viene sin dinero, sin tabaco y sin ropa de verano. Ella ha dicho que vendría su "tutora" a traerle todo esto...entiendo que será Educadora de Futuex, si no es así, tendréis que enviarnos la autorización para sacar dinero del banco..." ········································ Envío correo a Alberto, Jefe Secc. con copia a Estrella: "te reenvío coreo de Estrella, TS C. Sociosanitario. Dadas las circunstancias de su casa (su madre claudicó y se fue a vivir con la otra hija y no quiere regresar de ninguna de las maneras con el marido, ni siquiera a buscar pertenencias de Julia. Con el padre no se puede contar para estas cosas, de hecho la educadora consiguió acudir con él al domicilio y, según me informaron ayer desde el hospital, lo único q pudo conseguir fue un par de bolsas con ropa en muy mal estado, me dijeron literalmente que “no sirven ni para trapos”… Por tanto, hay que hacer una AUTORIZACIÓN GENERAL AL CENTRO para que puedan retirar para sus gastos de bolsillo y para que, poco a poco, pueda ir comprando ropa. Pongo “poco a poco” por las precaria situación económica de Julia y sus escasos ingresos (PFHC). *Yo en cuanto pueda, le solicitaré PNC, ahora que no conforma unidad de convivencia con los padres, sólo espero que no regrese al domicilio, primero por ella misma y su salud y segundo porque habría que volver a cambiar la pensión. Pongo a Estrella en copia para su conocimiento. PD: Estrella, aunque requiera acompañamiento de la educadora, si así lo estimáis, para comprarle ropa, el dinero, como en los otros casos, lo retiráis desde ahí." ····························································································· *Finalmente se autorizan 120 € para gastos de bolsillo (retirada permante) y un EXTRA de 250€ para ropa de verano. ···························································································································· Envío correo a Toni y Clara, Ed. Plas. FUTUEX: "Dada la necesidad de Julia Morón Hernández de comprar ropa, os comunicamos que se ha autorizado 250€ en tal concepto, que podrán retirar desde el C. Sociosanitario el próximo lunes. Os solicitamos que, en cuanto os sea posible, Clara acompañe a Julia a comprar ropa en Plasencia, además en estas fechas puede aprovechar las rebajas. Hemos estimado lo siguiente: - Chanclas de estar por casa (1 par) - Sandalias (1 par) - Sujetadores (3 – 4) - Bragas (10 – 12) - 4 – 5 mudas para el día a día (que ella elija: vestido o camisetas/blusas y pantalones/faldas que pueda combinar) Por favor, coordinaros con Estrella para el día y hora. La pongo en copia."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2024-06-28','Ana: En relación a la autorización general de centro, envío correo a Alberto y Ale, S. Ecca.: "Acabo de hablar con Estrella. Puesto que Julia, por su estado de salud no debería fumar mucho y dentro del socio va a tener poco gasto, hemos considerado que se le autorice 120€/mes para gastos de bolsillo. Así va a ahorrando para cuando pueda ir a otro centro y tenga otra serie de gastos. *A parte, van a hacer un listado de ropa y calzado que necesite y habrá que realizar una a autorización extraordinaria en este concepto cuando nos lo envíen."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='GARCIA'and apellido2='RAMIREZ'),'2024-06-27','miguel, firmo junto al curatelado la compraventa de la vivienda con protocolo 2538 del notario de Badajoz D. Agustin Sanabria Crespo y lo comunico a la parte económica y social','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='PEREO'and apellido2='REBOLLO'),'2024-06-28','Ana: Correo de Paula, TO CRR Plas (tocupacional.crrplasencia@grupo5.net): "os adjunto la solicitud que Antonio Pereo realiza al CRR de Plasencia de su deseo de comer alimentos sólidos aún sin usar la prótesis dental. Nos consta que en el sociosanitario de Mérida él tenía las mismas dificultades con la prótesis dental que en la actualidad (hemos buscado diferentes alternativas de solución, pero ninguna logra que la dentadura quede fijada para lograr una masticación adecuada). Allí se le permitía comer sólidos sin la prótesis, realizando la masticación con las encías. En CRR de Plasencia se ha tratado de que use la prótesis, pero ante las dificultades objetivas él se negó de forma contundente a usarla, por lo que se le pidió dieta de fácil masticación, que la mayor parte de las veces es en forma de comida caliente triturada. Con el tiempo esta situación está resultando intolerable para Antonio, por lo que solicita por escrito comer sólidos asumiendo la responsabilidad de las posibles consecuencias. Como Antonio tiene medidas de apoyo no teníamos claro si debíais ratificar esta decisión/solicitud, por lo que procedemos a realizaros esta consulta para poder actuar en consecuencia. Yo me voy de vacaciones durante el mes de julio, por lo que he puesto en copia a mis compañeras Carolina (directora del CRR) y a Beatriz (psicóloga) para que, si respondéis "a todos" puedan recibir el correo con vuestros comentarios. Esperamos vuestra respuesta, un saludo." ·········································································· Mi respuesta: "Tal y como yo lo veo, dado que él entiende los riesgos, atendido a sus deseos y preferencias, por mi parte no hay mayor inconveniente en que coma sólido. No obstante, pongo en copia a mis compañeros Asesores Jurídicos, por si tienen algo que objetar o añadir."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2024-06-28','Ana: Guardo en el expediente digital el Certificado de Estancia en centro (del 4 - 8 de junio 2024) con especifición de obtetivo de la intervención y motivo de abandono del recurso, que me remite Myriam, TS C. Vida (mabri@caritascoriacaceres.es) ······························································································································································································ Envío correo a Estrella Durán, TS y Montse, Administrativo - CSS Plas (montserrat.martinl@salud-juntaex.es) "En relación a MIGUEL ÁNGEL RAMOS ANDRÉS, necesitaríamos que nos enviaseis un CERTIFICADO DE INGRESO EN CENTRO con la fecha del mismo y a ser posible, el motivo del ingreso (derivación, cumplimiento de medida o lo que sea…)."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2024-06-28','Ana: Guardo en el expediente digital el Certificado de Estancia en centro (del 29 - 30 de abril 2024) con especifición de obtetivo de la intervención y motivo de abandono del recurso, que me remite Myriam, TS C. Vida (mabri@caritascoriacaceres.es) ··························· Puesto que "Paco" está de nuevo en el recurso, pido a Myriam que la semana que viene nos envíe otro confirmando si sigue o se ha marchado (en principio tenía intención de marcharse el lunes)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='IGLESIAS'and apellido2='MENDOZA'),'2024-06-19','Ana: Correo de Javier, TS CSS Plas (javier.rdguezper@salud-juntaex.es): "Te comunico el fallecimiento de Mercedes Iglesias Mendoza el dia 13/06 Tan pronto como tenga el certificado de defunción te lo hago llegar"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='IGLESIAS'and apellido2='MENDOZA'),'2024-07-01','Ana: Envío a María el Certificado Literal de defunción que remite Javier, TS CSS Plas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2024-07-01','Ana: Envío correo a Toni y Nieves - Futuex: "En relación a JESÚS MANUEL RAMOS BARGÓN, ¿podríais decirme cómo evoluciona con respecto a la tendinitis del brazo? Esta semana se le va a volver a autorizar al retirada del extra de los 50€ en tal concepto, pero me preguntan desde la sección económica si aún es necesario, pues como sabéis su ingresos no son precisamente elevados. Ya me decís cuando podáis."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2024-07-01','Ana: correo pendiente de Lourdes, Secc. Ecca.: "Hola han devuelvo el recibo de la mensualidad del mes de junio por falta de fondos, tiene 298,73€ y la mensualidad es de 373,42€. Han cargado OAR del IBI 2024, por importe de 352,87 €" ····································· *Llamo a Alicia Cano, TS SSASB - Alcuéscar (927 38 40 02) para tramitar la solicitud del INGRESO MÍNIMO VITAL. ·········································· *Tras hablar con ella, envío correo a Alberto y Lourdes, S. Ecca: "aunque reúne el resto de requisitos y por sus ingresos le correspondería, es motivo de exclusión el hecho de ser beneficiaria de servicio residencial… Van a mirar la opción de Prestación de contingencias, pero esto es un pago único puntual en x concepto, con lo cual le serviría ahora pero no se puede volver a solicitar para lo mismo. Yo la única solución que veo sería la VENTA DE SU VIVIENDA, para que tuviera liquidez y dejara de tener los gastos asociados a la vivienda. Pongo en copia a los jurídicos en relación a esta opción, para ver cómo proceder."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2024-07-01','Ana: Correo de Estrella Durán, TS CSS Plas. (estrella.duranc@salud-juntaex.es): "ha ido Desi al final a Hacienda, le salía a pagar 35 euros, así que le recomendaron que no la presentara ya que no está obligada a ello."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2024-07-01','Ana: correo de Paula, TO CRR Plas. al ctutelar@: "contactamos con vosotras para comunicar la fecha de traslado de Mª Ángeles a los pisos supervisados de Valverde. Para asegurar que pueda tener todo preparado y despedirse de la manera adecuada, hemos fijado el jueves 4 de julio como fecha para realizar el cambio. Mª Ángeles irá en taxi hasta allí para facilitar el traslado de su equipaje. Si por alguna de las partes hubiera alguna dificultad con esta fecha, no dudéis en contactar para que podamos valorar otra más conveniente. Yo estaré de vacaciones durante el mes de Julio por lo que, adjunto en el correo está la dirección de Carolina Monroy la directora, así como de Beatriz, psicóloga del CRR. para que podáis incluirlas en las respuestas o contactar directamente con ellas en mi ausencia" ····················· Correo de Mónica Hernández, TS Sierra de Gata (mhernandez@sierradegata.es): "Apuntamos por tanto el día 4 de julio como fecha de entrada en los pisos tutelados. Como nos comentáis vendrá en taxi. Si es posible que esté en Valverde sobre las 10:30- 11:00 ya que los ingresos se suelen realizar sobre hora." ···································· Respondo a todas: "Muchas gracias por las gestiones en mi ausencia. Ya estoy de vuelta del todo, espero que sin contratiempos y hasta que me vaya unos días de vacaciones. Confío en que tanto el traslado de Mª Ángeles como la adaptación a la residencia, vayan muy bien. Mónica, por favor, la documentación que haya que remitir (contrato de admisión al centro, reglamento de régimen interior u otra, así como lo relativo al cobro de la plaza, házmelo llegar a la dirección de correo desde la que te escribo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2024-07-01','Ana: Envío correo a A. Jurídico: "En relación a Miguel Ángel Ramos Andrés, y el requerimiento que nos realizaba el Jugado sobre la intervención con él, os envío: - CERTIFICADO DE ESTANCIA EN CENTRO VIDA - INFORMA DE INGRESO EN CENTRO SOCIOSANITARIO PARA CUMPLIMIENTO DE MEDIDAS En el primero especifican el objetivo de intervención con él, así mismo el motivo por el que abandonó el recurso. *En esta misma línea, por si queréis especificar, se iba a trabajar con él desde el Programa de Apoyo Comunitario a través del Convenio-Programa firmado entre la Junta y Futuex, mediante las visitas de seguimiento y apoyo . Desde el mismo se retomará su intervención con él en el centro actual."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2024-07-01','Ana: Se autoriza EXTRA DE VERANO de 200€ que podrá retirar el lunes 8/07.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='DIEZ'and apellido2='SANTIAGO'),'2024-07-01','Ana: Correo de Diana Gonzalez al ctutelar@ (diana.gonzalezj@salud-juntaex.es): "AL CREAR LA PLAZA PUBLICA EN ROSETTA NO NOS DEJA VALIDAR LA SOLICITUD PORQUE FALTA EL CERTIFICADO DE DISCAPACIDAD. NO SE SI LO TENEIS PARA PODER ADJUNTARLO AL EXPEDIENTE." ···························································· Respondo: "Adjunto el CERTIFICADO DE DISCAPACIDAD relativo a PILAR DIEZ SANTIAGO. ..." ································ Respuesta de Diana: "LO HE SUBIDO A ROSETTA Y SE ENCUENTRA EN LISTA ESPERA DE PLAZA PÚBLICA"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2024-07-01','Ana: llamada de Aitor (613 694 469), está agobiado porque quiere independizarse y dice que Nieves, Ed. Futuex, aún no le ha encontrado piso. Quiere ir a una inmobiliaria. Le digo que primero hable con Nieves para acordar el día que le venga bien para que le acompañe en la búsqueda y gestiones. ······························································································································ Tras nueva llamada de Aitor, envío correo a la secc. ecca. con copia a Futuex: "En relación a AITOR MORENO FELIPE, solicita EXTRA DE 150 € PARA ROPA DE VERANO. Por mi parte se acepta este presupuesto, pero con la condición de que acuda a retirarlo y comprar la ropa con Nieves, Educadora de Futuex. Pongo a Toni y Nieves en copia para que estén al corriente. Por favor, confirmad si es viable y, en tal caso, informarles a ellas de las fechas en que podrían ir a retirarlo para que organicen su agenda. Nieves, porfa, cuando nos confirmen, informa a Aitor de la cuantía aprobada."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2024-06-29','Ana: Correo de Myriam, TS C. Vida - Cáritas (mabri@caritascoriacaceres.es): "adjunto certificado de estancia en Centro Vida de Francisco ya que ha decidido marcharse hoy mismo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2024-07-01','Ana: Envío correo a Toni y Nieves - Futuex, con copia a Dra. Cristina Donoso (cristina.donoso@salud-juntaex.es): "En relación a Francisco Cacho Garrido, informaros que nos han comunicado desde Centro Vida, Cáritas, que el mismo viernes pasado se marchó del recurso. Desconocemos su paradero. No sé si habrá contactado contigo Nieves. Desde Salud Mental, como ya os comenté, iban a reprogramarle la cita para julio, pero no sé si permanecerá por Cáceres o se habrá vuelto a marchar fuera. Por favor, intentad contactar con él y trabajar para que vuelva a asistir a las consultas con el Equipo de Salud Mental y a adherirse al tratamiento. Nieves sé que contigo había establecido buen vínculo, a ver si acepta el seguimiento y tu apoyo. Yo también intentaré hablar con él. Pongo en copia a la Dra. Cristina Donoso, Psiquiatra, para su conocimiento."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-06-28','Ana: Se aprueba el presupusto de revisión y arreglo de la fuga del gas de la cocina de José Manuel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUELA'and edp.apellido1='PLATA'and apellido2='MACEDO'),'2024-07-02','645 538693 Sol, de la tienda .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2024-07-02','Ana: Respondo al correo de Toni-Futuex: "Se le ha aprobado el extra de verano de 200€, que podrá retirar la semana que viene junto a su retirada habitual. Creo que ayer se lo confirmaron mis compañeras. Lo de seguir dándole los 50 €/semana se valorará aparte, no obstante, no se podrá mantener mucho tiempo. Porque lo ideal sería cáterin, pero él ya dijo que no quería… En cuanto a la pensión de alimentos de sus hijos, me confirman desde la sección económica que sí se lo siguen pasando. Pido a los compañeros Asesores Jurídicos que retomen este asunto." ···························· Envío mail a los A. Jurídicos: "Si no recuerdo mal, vosotros en su día estuvisteis viendo la posibilidad de que JESUS MANUEL RAMOS BARGÓN dejase de abonar la Pensión de Alimentos a sus hijos. ¿Cómo está este asunto? No sé si podéis retomar algo al respecto." ·································· Respuesta de Ángel, A. Jurídico: "Lo solicitamos en su día y lo desestimaron. No obstante, lo he vuelto a retomar, solicitando de nuevo asistencia jurídica gratuita. No han designado Abogado de oficio." ······························· Lo reenvío a Toni y Nieves para que se lo comuniquen a Jesús Manuel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='RAMIREZ'and apellido2='JUAREZ'),'2024-07-02','-Se ha trasladado el expediente de PNC a Madrid .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUSTAVO ALFREDO'and edp.apellido1='CASTAÑO'and apellido2='SOTO'),'2024-07-02','Ana: Respondo al correo pendiente de Alberto, Secc. Ecca. (día ): "Pues la vivienda en la que vive es una propiedad de la familia. Entendemos que es la madre la que se está asumiendo los otros gastos de suministros. De hecho la mujer le dijo a Amalia, que quería poner la vivienda a nombre de Gustavo Alfredo, pero tenía que volver a hablarlo con sus otros hijos. Miguel le dio orientaciones sobre las gestiones a realizar al respecto. Desde el penitenciario nos han avisado de que le siguen ingresando el dinero todos los meses en la cuenta peculio, pero María me ha dicho que ha solicitado online la baja de la transferencia."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='BERNARDO'and apellido2='PIRIS'),'2024-07-02','Ana: Envío correo a Alberto, Jefe S. Ecca: "He recibido llamada de Mª Antonia Bernardo Piris. Necesita un par de extras: - Ella vive en Plasencia, pero tienen que intervenirle en Badajoz de un trozo de raíz de una muela que le dejaron una vez al extraérsela. Es en la seguridad social, pero el especialista está allí. Será ambulatoria, pero necesitará quedarse allí a dormir en un hostal, por lo que solicita 150 € para el viaje y el alojamiento (será en las próximas semana, pero no le han confirmado aún el día exacto de la intervención. - Quiere 300 € para irse de vacaciones unos días. Por mi parte ok a ambas cosas. Porfa, si se aprueban, comunicadle a ella qué día podrá ir a retirarlo (927 612 261)" ··································· Respuesta de Alberto, con copia a Ale, S. Ecca: "ALE: REINTEGRO XPUNTUAL X 450 € LO ANTES POSIBLE. INCLUYE: • 150 ESTANCIA BADAJOZ TRATAMIENTO DENTAL SSOCIAL. • 300 VACACIONES. ALE: AVISAMOS A TUTELADA Porfa, si se aprueban, comunicadle a ella qué día podrá ir a retirarlo (927 612 261)"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2024-07-02','Ana: Conversación con Estrella, TS CSS (24146): Además de los 200€ autorizados para gastos de bolsillo, solicitan un extra de 100€ para ropas de verano (2 bermudas y 2 camisetas) y para una radio. ··························· Comunico a la secc. ecca. ······· Por mi parte OK.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2024-07-02','Ana: Tras recibir llamada de Estrella, TS CSS, y Miguel Ángel, envío correo a la secc. ecca: "A parte de los 200€ habituales para gastos de bolsillo, solicitan un EXTRA DE 100 € para ropa y una RADIO. Por mi parte OK."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2024-07-02','Ana: Tras recibir llamada de Carlos, envío correo a la secc. ecca.: "También ha llamado Carlos Glez. Leo, puesto que no ha solicitado ningún otro extra para este verano, solicita 20 € para comprarse un libro. Por mi parte ok al mismo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2024-07-02','Ana: Correo de Lourdes, S. Ecca. a Nives y Toni - Futuex: "Buenos días, a partir del jueves puede retirar el extra Aitor de 150€ para ropa. Nieves, ya informas a Aitor y le acompañas a la compra."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDRO'and edp.apellido1='TORRES'and apellido2='VILLEGAS'),'2024-07-02','Ana: Tras hablar con Mai, Jefa Secc. RR. Mayores (68496), envío correo a Tensi, TS (ssbtensi@riberosdeltajo.es): "Tan sólo comunicarte que me acaban de llamar de la sección de mayores para comunicarme que de las tres residencias que se solicitaron, Isidro está el primero en Mirabel, como de momento no hay más opciones, van a resolverlo. En cuanto me remitan la resolución me pongo de nuevo en contacto contigo y con el centro en cuestión."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2024-07-02','Ana: correo del ESM - CC (equiposaludmental.caceres@salud-juntaex.es): "Adjunto remito Informe de seguimiento en consulta de la dra. Donoso así como fecha de la próxima cita del paciente Francisco Cacho Garrido." Informan de la no asistencia a la última cita (día 25 de junio) y la repogramación de la misma. ······························································································································ Correo de Toni-Futuex: "Hoy se le va intentar ver en ECA, dice que si seguirá acudiendo a controles. Se le va apoyar en tema de comprar móvil para que almenos este comunicado. Ayer contactó con la compañera del equipo a través del móvil de Mediavilla. Como sabemos es muy autonómo y tiene habilidades, para buscar apoyos donde el mejor considera en función de sus propias necesidades, y es posible que se mantenga en este dinámica de calle y de ingreso en centro vida mientras pueda hacerlo. Aveces busca y facilita la intervención y sin embargo otras veces es imposible, no obstante no dejaremos de intentar almenos cierto contacto. A ver si podemos hacer lo del movil y vamos comunicandolo." ························· Respondo: "Por favor, comunícame sí ha asistido hoy al ECA y si ha permitido el acompañamiento de la compañera." ····························································································································································································· Envío correo a los A. Jurídicos: "...os remito: - 2 Certificados de Estancia en Centro Vida de Cáritas. En ambas ocasiones, como podéis leer, se ha marchado de forma voluntaria al “no soportar la abstinencia del consumo de sustancias”. - 2 Informes de Psiquiatría del Equipo de Salud Mental de Cáceres: o El del día 17/06/2024 le atendieron por teléfono, porque él comunicó que no iba a acudir a la cita programada del día siguiente. El paciente informó que estaba en Cádiz, con intención de volver a vivir allí, pero dijo que regresaría a la semana siguiente a Cáceres, por lo que le reprogramaron la cita. o En el del día 25/06/2024, al final del mismo, podéis leer que no se presentó a la cita programada, acudió, eso sí, a primera hora para comunicar que no iba a asistir… - Correos, en PDF, intercambiados con Futuex, sobre seguimiento/apoyo a Francisco. *Confirman que en el día de hoy NO ha asistido al control que tenía programado en el EQUIPO DE CONDUCTAS ADICITVAS. Para comunicar al Juzgado la imposibilidad de intervenir con él por su falta de adherencia a los tratamientos, tanto en Salud Mental como en el Equipo de Conductas Adictivas, el abandono de los recursos residenciales y la falta de colaboración y contacto con el programa de apoyo comunitario así como con la Trabajadora Social del Gabinete Técnico de la CTAEx. En los últimos meses no acepta los apoyos/recursos comunitarios existentes."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MELLADO'and apellido2='GUARDABRAZOS'),'2024-07-02','Ana: Correo de Cristina, Ed. Asoc. Vera (educadorasocial@asociacionvera.com): "Adjunto envío ATESTADO Nº 40-2024 y PARTE JUDICIAL DE LESIONES. Denuncia interpuesta por Mª del Carmen Mellado Guardabrazos a un compañero usuario de Asociación Vera Plena Inclusión por tocamientos sexuales no consentidos." ································ Reenvío a los A. Jurídicos. ··································································································································································································· Reenvío otro correo de Cristina, Ed. Asociación Vera, a los A. Jurídicos: "A ver, os reenvío ahora este AUTO, no sé si lo hemos recibido aquí, me lo envían desde Asociación Vera, pero no entiendo que nombren a la CTAEx GUARDADORA… la CTAEx a mi entender no ejerce, ni puede, ninguna GUARDA…."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA VALLE'and edp.apellido1='PATARRO'and apellido2='CARMELO'),'2024-07-02','miguel, email de Tere Hola Tras hablar con Olga la trabajadora social, te comento La dirección de la vivienda es Avda. Constitución, 14 Valencia del Ventoso CP: 06330 Es propietaria de una vivienda de planta baja, situada dentro del casco urbano de Valencia del Ventoso, cuenta con 5 habitaciones o estancias, distribuidas en dos dormitorios y una salas de estar, cocina y cuarto de baño. Desde su ingreso la vivienda permanece cerrada, desconociendo en el estado que se pueden encontrar el equipamiento básico. En la última visita (2020), disponía del equipamiento básico, no todo estaba en buen estado, ya que había sido cedido por personas de la localidad, por la situación precaria en la que vivía. Las llaves de dicha vivienda están en el Ayuntamiento de Valencia del Ventoso, a petición de Mª del Valle, ya que no quería que nadie entrara en su vivienda, y cambió la cerradura el mismo día que ingresaba en el centro. Mª del Valle es viuda, sin hijo y sin ninguna familia directa. Cuando Mª del Valle vivía en Valencia del Ventoso, mantenía relación de “amistad” con una vecina de la localidad. Esta persona expresa en diferentes entrevistas en mi despacho: - “Que es la propietario de la vivienda del Mª del Valle”. Según indica Mª del Valle, ella no tiene las escritura de la vivienda, la tiene su “amiga-vecina”. Desconoce si ella es propietaria o no. Como ves la amiga ha intentado aprovecharse de Valle y se desconoce si finalmente le dio la vivienda a la amiga o no. Actualmente Valle reside en piso tutelado y no tiene ninguna relación con la “amiga” pues ya si es consciente de que ha estado aprovechándose de ella. Te paso el teléfono de Olga la trabajadora social de Valecia del Ventoso: 924 56 21 27 / 924 56 00 60 A ver qué podemos hacer con la vivienda…. ------------------------------------------ llamo a Olga Ts del Ayto 924-562127: me confirma que no tiene documentación, que los que estaban anteriormente pusieron en contacto de fiscalia todo (pero que seguramente no sería posible localizar escritos)Dice que posiblemente lo que se firmara se hizo en la notaria de fuente de cantos Consulto a Catastro y aparece ella con 100% usufructo y Antonia 100% nuda propiedad. Me dice que hay 2 ptmos personal, o hipotecario, entidad??(no sabemos importe ni quien aparece de titular de los mismos) que se cargan en la cuenta de la curatelada. Quedamos en que le envío el certificado de catastro, y ella intentará localizar escritos o contacto realizado con fiscalia y remitirles dicho certificado de catastro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2024-07-02','Ana: llamada de Doroteo (609 928 621): de momento no hay plaza en el CRR de CC, está en lista de espera.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2024-07-02','Ana: Llamada de Cristina, Ed. Asoc. Vera (681 143 911): Ha conseguido contactar con el hermano de Antonia en relación a los documentos que necesitamos para la tramitación de la herencia de la madre fallecida. ······ Cree que va a conseguir que le lleve los documentos en agosto, cuando vayan a recoger a Antonia para llevársela al pueblo unos días. ····· *No obstante, el hermano ponía la condición de que se le ayude a él también ha hacer los trámites.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO DAVID'and edp.apellido1='REBANALES'and apellido2='NIETO'),'2024-07-02','​REINTEGRO X 200 €/MES....A TRAVÉS DE TRANSFERENCIA PERMANENTE A SU MADRE DESDE 01/08/2024. IMPORTANTE: LO PRIMERO ES ABONAR EL ALQUILER DE LA VIVIENDA. ALE: CADA 6-7 SEMANAS REVISAS X ENCIMA LA CCC TUTELADO PARA VER SI HAY ALGUNA IRREGULARIDAD. CON INDEPENDENCIA DE ESTO, CUALQUIER DOMICILIACIÓN DISTINTA A LA DE ALQUILER VIVIENDA O SEGURO DECESO, LA DEVUELVES CON CARÁCTER INMEDIATO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='MARIN'and apellido2='LAUREANO'),'2024-06-20','Ana: Correo de Amalia en mi ausencia, a la residencia de mayores: "He recibido llamada de un sobrino de Rosa , Natalio tf 639532039 Me dice que la familia querría que se enterrase en su pueblo Oliva de la Frontera , donde tiene algunos familiares. Os facilito su tf para que podáis contactar con él directamente ."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MATILLAS'and apellido2='JIMENEZ'),'2024-06-20','Ana: Correo de Alberto, Jefe S. Ecca, a Pilar, Directora del Hogar San Vicente de Paul (direccion.hgsvplasencia@gmail.com): "Buenos días Pilar. Tal y como quedamos en la conversación telefónica mantenida, te adjunto informe económico, lo más simplificado posible, relativo a Dª. MARÍA CARMEN MATILLAS JIMÉZ. Te adjunto también movimientos bancarios (último año) de la cuenta principal, para que María Carmen tenga una información más completa. Cualquier duda o aclaración me dices."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='LANCHO'and apellido2='SANGUINO'),'2024-07-02','Ana: Correo pendiente de Estrella, TS SSASB - Malpartida de CC (ssb@malpartidadecaceres.es): "cuando puedas mira estas facturas, tengo al hermano de Andrés como loco, le pasan a él el cargo de la residencia de su hermano, por favor hablar con el centro.tampoco pagáis las facturas de luz de su casa, la deuda, pendiente, miar eso también, no dejan de llegar correos a mi correo" ·········································· Lo reenvío a Alberto, Jefe S. Ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-06-19','Ana: Correo de Pilar Martín, TS ESM CC (pilar.martinp@salud-juntaex.es): "ME DICE EL JOSE MANUEL QUE QUIERE SOLICITAR DE NUEVO CENTRO RESIDENCIAL (CRR), EL RIESGO QUE VEO ES QUE DE HACERLO NOS PROPONGAN QUE SE HAGA UNA SUBCOMISIÓN DE GESTIÓN DE CASOS Y SE PROPONGA LARGA ESTANCIA EN EL SOCIOSANITARIO (PABELLÓN DE CRÓNICOS). YA ME DICES. POR CIERTO, QUE EL GABINETE VEA SI ESTABA CITADO COMO TESTIGO Y COMO INCAUSADO EN OTRO, DADO QUE ME DICE QUE NO ACUDIÓ PARA QUE NO DERIVE EN UNA MULTA Y POR VER LAS CAUSAS QUE TENGA PENDIENTES. UN SALUDO." ··················································· Nuevo correo de Pilar: "ME DICE RAQUEL QUE NO SOLICITEMOS CRR HASTA QUE SE TENGA LA RESOLUCIÓN DEL MINISTERIO FISCAL DEL PACIENTE. HABLA CON RAQUEL Y CON EL GABINETE JURÍDICO VUESTRO PORFA"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2024-07-02','Ana: Envío correo a Alberto, Jefe Secc. Ecca: "...vuelve a estar en situación de calle, abandonó voluntariamente el recurso residencial de Cáritas. Llamó la semana pasada solicitando: - Extra de 200€, pues necesitaba comprar, entre otras cosas, saco de dormir y algo de ropa. *Por mi parte ok a este extra. - También solicita 250 € para ferias - A parte pide 200 € semanales…. Percibe una PNC con completo de Tercera Persona (776,85 € x 14). Esto si quieres lo vemos ahora o mañana, como prefieras."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2024-07-02','Ana: Respuesta de Miguel, A. Jurídico, a mi correo de ayer: "hay que pedirla abogado de oficio si queréis solicitar la venta. Alberto o Lourdes enviadnos un pantallazo con lo que cobra y el saldo que tiene a día de hoy" ···································· Alberto; Jefe S. Ecca., le facilita la información que solicita.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2024-07-03','Ana: Correo de Miguel, A. Jurídico: "os remito: - 2 Certificados de Estancia en Centro Vida de Cáritas. En ambas ocasiones, como podéis leer, se ha marchado de forma voluntaria al “no soportar la abstinencia del consumo de sustancias”. - 2 Informes de Psiquiatría del Equipo de Salud Mental de Cáceres: o El del día 17/06/2024 le atendieron por teléfono, porque él comunicó que no iba a acudir a la cita programada del día siguiente. El paciente informó que estaba en Cádiz, con intención de volver a vivir allí, pero dijo que regresaría a la semana siguiente a Cáceres, por lo que le reprogramaron la cita. o En el del día 25/06/2024, al final del mismo, podéis leer que no se presentó a la cita programada, acudió, eso sí, a primera hora para comunicar que no iba a asistir… - Correos, en PDF, intercambiados con Futuex, sobre seguimiento/apoyo a Francisco. *Confirman que en el día de hoy NO ha asistido al control que tenía programado en el EQUIPO DE CONDUCTAS ADICITVAS. Para comunicar al Juzgado la imposibilidad de intervenir con él por su falta de adherencia a los tratamientos, tanto en Salud Mental como en el Equipo de Conductas Adictivas, el abandono de los recursos residenciales y la falta de colaboración y contacto con el programa de apoyo comunitario así como con la Trabajadora Social del Gabinete Técnico de la CTAEx. En los últimos meses no acepta los apoyos/recursos comunitarios existentes."','2');
