insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2024-07-03','Ana: Llamo a Ángel Félix (643 622 174), en relación a su propuesta ecca. ya valorada con Alberto, pero el teléfono está apagado. ·············································································· Envío un mail a Yessica, TS Comedor Cáritas - Plas.(ydearriba@caritasplasencia.org): "Disculpa que te moleste, te escribo para pedirte un favor. No sé si ÁNGEL FÉLIX MAILLO SANTBAÑEZ está acudiendo al comedor social. Me llamó la semana pasada para comunicar que estaba de nuevo en situación de calle. Ya hablé con Consuelo, Psicóloga del CAT, al respecto. Ángel Félix solicitó un par de extras y subida de asignación. Ya tengo respuesta de la sección económica y le he llamado él antes un par de veces y el teléfono está apagado. Por favor, si acude por ahí, ¿podrías decirle que le he llamado por ese motivo? Por si puede ponerse en contacto conmigo él mañana."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2024-07-03','Ana: Correo de Estrella Durán, TS CSS-Plas: "Julia Morón está sin gafas, tiene los cristales sin montura (no puede estar sin ellas porque tiene muchas dioptrías y no ve apenas), así que va a salir ahora mismo con Educadora de Futuex a encargarla en Óptica Díaz. Le he dicho que nos hagan factura con número de cuenta y luego os la envío para su pago, vale??" ···················································· Mi respuesta: "Ok Estrella, ya lo he hablado con mis compis de la S. Ecca. Enviad el presupuesto que le den hoy, si puede ser, y la factura cuando acuda a recogerlas. Si en la óptica lo aceptan, por supuesto, se puede abonar mediante transferencia bancaria. Pongo a Clara en copia."','2');
