insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='IGLESIAS'and apellido2='MENDOZA'),'2024-07-04','Ana: Llamada de Catalina Mendoza, hermana de Mercedes (927 12 70 17): enviarán la factura de lo relativo al sepelio de Mercedes con el nº de cuenta para el ingreso. Ellos tenían un nicho famiar, pero de la obra, la lápida y el entierro lo se ha encargado un vecino del pueblo. ········································· *Envío correo a Javier, TS del CSS Plas (javier.rdguezper@salud-juntaex.es): "queríamos preguntaros por la factura relativa al ataúd y al traslado del cuerpo de Dª. Mª Mercedes Iglesias Mendoza, por favor, cuando podáis hacédnosla llegar pues mi compañera lo necesita para adjuntarlo en la rendición final al Juzgado. ······························································································································································································ Respuesta de Javier: "Adjunto factura de los gastos de la funeraria y su pago. También va el ingreso del sobrante de los gastos de bolsillo y/o podólogo. ( 4 euros)"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='TEJADA'and apellido2='FERNANDEZ'),'2024-07-04','Ana: Correo de Mª Cruz, TS Hermanos de la Cruz Blanca (trabajosocialcf-caceres@cruzblanca.org): "Algunos de nuestros residentes van a irse 11 días a otra de nuestras casas familiares de vacaciones, y te remito las autorizaciones pertinentes para que nos las firméis cuando podáis" ······································································· Envío la Autorización debidamente firmada y sellada.','2');
