insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSEFA'and edp.apellido1='DOMINGUEZ'and apellido2='BLANCO'),'2024-07-04','TERESAÇ Como sabes Josefa está en tratamiento oncológico, y hoy tenía revisión. Ha acabado con los ciclos de quimioterapia, ha ido todo muy bien y han decidido operarla, en principio, para el día 26 de julio para extirpar tumor, analizar ganglios centinelas y reconstruir pecho. La han puesto como urgente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2024-07-04','Ana: Envío a Juan Carlos, Aux. Adtvo. (juancarlos.cano@salud-juntaex.es): "envío adjunta la siguiente documentación para remitir por Registro a la Unidad de Gestión de Acceso y Valoración de Dependencia del SEPAD: - Solicitud de Revisión de la situación dependencia por empeoramiento y solicitud de revisión PIA. - Informe de Salud - DNI de la Representante Legal - Decreto de Nombramiento de Directora Gerente del SEPAD - Resolución de delegación de funciones como Presidenta de la Comisión Tutelar de Adultos de Extremadura"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='GUILLEN'and apellido2='LOBATO'),'2024-07-04','miguel, envío email a ANA MARIA MONTSERRAT DE PABLOS GOMEZ >anam.depablos@salud-juntaex.es>; MARIA MAGDALENA CASTILLO SANCHEZ >magdalena.castillo@salud-juntaex.es> y a Tere: Buenos días, he llamado a Manuela Lobato 927-592331 quien me confirma que no tienen documentación alguna de la herencia de los padres y que no nos pueden ayudar. Cree que los papeles que hubiese se llevaron al centro. Necesito me localicen si había alguna cuenta bancaria a nombre de los padres, ya que necesitamos certificado de saldo bancario y me remitan dni de ellos para intentar localizar en catastro la vivienda de Valencia de Alcantara. Si tuviesen una nota simple, ibi, o certificado de catastro mejor. Una vez tenga la documentación se la remitiremos a una gestoría para la tramiten. Si conocen alguna de confianza dígannoslo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2024-07-04','Ana: En relación al correo de Margarita Montero, TS Mancomunidad Integral Sierra de Montánchez (tsocial4@mancomunidadsierrademontanchez.es): "...como tenía retenido unas cuantías económicas, tratamos de que de su pensión mensual pueda abonar el pago de la plaza, según certificado del INSS, en este año tiene una pensión de 1.875,46€/mes, con 14 pagas, le correspondería abonar el 75% de esta cantidad, por lo que se requiere que nos enviéis desde la sección económica de vuestro servicio la situación real del usuario para poder aplicar la cuota mensual a pagar en el centro" ··············································································· Respondo: "...Te envío adjunto el RECIBO que nos facilitó el habilitado de Mateo en el mes de marzo, en el que se especifica la retención que le practican y el LÍQUIDO QUE PERCIBE: 1.022,74 € /mes. Espero que esto te sirva."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2024-07-04','Ana: Correo-respuesta de Yessica, TS Comedor Cáritas - Plas.(ydearriba@caritasplasencia.org): "trasladé la información a Ángel Félix por whatsapp, me comenta que necesita que le busquéis una habitación o algo. Me dice que hoy intentará llamaros, pero que está en el hospital porque echa flemas, según me dice ha echado sangre en las flemas, y la verdad es que tiene un deterioro físico muy grande, pero aquí en Plasencia es difícil que le alquilen habitación o vivienda, porque es muy conocido y la gente no se fía, porque esto, al ser muy pequeño, pues nos conocemos prácticamente todos." ·································································································································································································· Tras llamar a Ángel Félix (643 622 174), respondo el correo a Yessica con copia a Toni y Clara, Futuex: "Muchas gracias por ayudarnos en la comunicación con Ángel Félix. Precisamente acabo de hablar con él, está ingresado en el Hospital Virgen del Puerto. Dicen que le han visto una mancha en el pulmón. A ver qué tal evoluciona. La “propuesta” que realizaba con exigencias la semana pasada, ya no le interesa… Ahora, como te dijo a ti ayer, quiere que se le busque una habitación. Pongo en copia a la educadora y coordinadora el programa de apoyo comunitario gestionado por Futuex (Convenio firmado con la Junta), para que le apoyen en la búsqueda de habitación (no es la primera vez que se pide y se le intenta ayudar en este aspecto… siempre sin éxito). No obstante, su curatela es de tipo económica, y según su resolución judicial (Auto de nombramiento) tiene capacidad para desenvolverse en el resto de áreas. Por lo que él mismo podría buscar y enviar el precontrato para que se apruebe la cuantía y se abone desde el Gabinete Técnico de la CTAEx. *Cuando le he transmitido justo eso por teléfono, que cuando le den el alta puede buscarlo él mismo con el apoyo de Clara, Educadora, me ha colgado el teléfono. Si cuando salga del hospital decide buscar habitación de alquiler, dado que en Plasencia como expresas es difícil, igual debe buscar en otra localidad, de hecho él mismo lo ha propuesto en otras ocasiones, sin llegar a materializar nada después… Por favor, Clara, cuando retoméis el contacto y el apoyo, tened esto en cuenta. Si bien, sabemos que normalmente no aprovecha el apoyo que se le brinda desde el programa."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2024-07-04','Ana: Correo de Sheila, Directora CRR (crr@grupociudadjardin.com) con copia a Secc. Acceso a Salud Mental: "Tal y como os comenté la semana pasada, la persona usuaria CONSUELO NEVADO PACHECO tuvo un incidente el 26 de junio por lo que ha sido expulsada de forma temporal desde el 28 de junio hasta el 5 de julio de 2024, realizando estancia en domicilio familiar. Concretamente, la incidencia que traslada el equipo es la siguiente: "En el taller hay que indicarle que se marche al estar dirigiéndose inadecuadamente a Mª Ángeles. Al no controlar su estado e ir en aumento con insultos se activa protocolo, tras ello pega a Mª Ángeles en el patio dándole golpes en el brazo. Acude el PAC y tras valoración (nos dejan copia del informe) deciden acudir al HSPA, acude acompañada de la monitora. Tras valoración en urgencias del HSPA el Dr. Molina decide no realizar ingreso." A su regreso, os contamos evolución."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2024-07-05','Ana: Envío a Juan José, Dpto. de Admisión del CSS-Plas. (juanjose.sanchez@salud-juntaex.es): "Adjunto la solicitud de incorporación a la lista de espera para la intervención de Septoplastia y los consentimientos informados pertinentes, relativos a D. Alfonso Marín de Cáceres, debidamente firmado y sellado por su representante legal."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATAN'and edp.apellido1='GARCIA'and apellido2='TERRON'),'2024-07-05','Ana: Llamada de Francisco Javier, hermano de Jonatan (642 758 460): dice que su hermano está en los pisos de Miajadas. Tiene discapacidad y 34 años. Según expresa, su hermano no quiere seguir viviendo allí y quire irse a vivir con él. *Él quiere asumir el cargo, pero tiene 29 años y no tiene estabilidad laboral. **Le explico que la CTAEx aún No ha aceptado el cargo pues no hemos recibido la firmeza, peo en cuanto llegue se aceptará. ··············· Le indico que debe dirigirse al Juzgado para solicitar la remoción y proponerse él como Curador, pero que sería bueno que tuviera una situación más estable. ····································· Sus padres son mayores, su madre está en una residencia y su padre también presenta problemas de salud. Eran los antiguos tutores.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2024-07-05','Ana: Contesto al correo de Mónica Hernández, TS Sierra de Gata (mhernandez@sierradegata.es): "¿qué tal han ido las primeras horas de Mª Ángeles en vuestro centro? Gracias por informar. Te contesto por aquí a las dudas, pero si quieres que lo hablemos para explicarme mejor, puedes facilitarme un número de teléfono y te llamo en cuanto pueda. 1- La asignación mensual de Mª Ángeles era "tan alta" en el CRR porque en este recurso no se abona la plaza, ahora hay que reajustarlo. Lo paso al Jefe de la Sección Económica, pues como tú bien dices, al abonar el 65% de sus ingresos hay que reducirlo bastante. En teoría para ella no debe ser un problema, pues ese tema ya lo abordaron con ella desde el Equipo Técnico del CRR. 2- Para la retirada de su asignación periódica, si puedes acompañarla tú sería perfecto. Nos tendrías que facilitar tus datos (nombre, apellidos y DNI) para indicarlos en la Autorización que se envía desde aquí al banco. 3- A Fututex les aviso yo para que retomen las visitas y el apoyo en vuestro centro. ¿Podrías facilitarme el nombre y la dirección exacta del mismo? 4- En cuanto a los acompañamientos médicos, lo que solemos hacer en estos casos es, que desde de las residencias, avisándonos previamente, buscan a alguna persona de confianza que haga ese servicio de acompañamiento, nos envían a posteriori una DECLARACIÓN JURADA firmado por la persona con la fecha, precio y nº de cuenta para abonarle el servicio mediante transferencia desde aquí. Algunas cobran con precio por servicio completo y otras por horas (que suele estar entre 9-10 €/hora). Para el desplazamiento también contactan desde los centros con algún/a taxista de confianza y del mismo modo se abona el servicio mediante transferencia una vez recibida la factura a nombre de Mª Ángeles. Todo esto siempre y cuando ella pueda asumir estos gastos. No obstante ahora debe tener ahorros y en cualquier caso lo iremos viendo y valorando. *En cuanto me diga Alberto, Jefe de la Secc. Económica de cuánto podría disponer al mes y esté lista la autorización de retirada de efectivo te lo hacemos saber." ······································································································································ Tras hablar con Mónica, Res. Mayores de Valverde del Fresno (927 51 06 37 - Lunes, Miércoles, Jueves y Viernes), envío a Alberto las opciones de pago de la plaza y los documentos pertinentes. *Solicito además que recalcule la asignación para gastos de bolsillo, de esta cuantía abonará también peluquería y podología cuando la necestite. ··········································································· Mónica me informa: "Mª Ángeles ha pasado bien el primer día. El contacto que yo he tenido con ella de momento también bien. Está respetando los horarios de comida, y en el tiempo libre se va a casa de su padre. Seguimos con las mismas rutinas que en el CRR en cuanto a la administración de tabaco y del dinero diario." ································································································································································································ Cumplimento y subo al portafirmas digital el contrato de la RR.MM. ································································································································································································· Envío correo a Toni-Futuex: "En relación a MARÍA ÁNGELES SANTOS URBANO, comunicaros que ayer ingresó en la Residencia de Mayores de Valverde del Fresno, sito en la C/ Libertad S/N (Pisos Tutelados) de dicha localidad. La persona de contacto es Mónica. Teléfono: 927 51 06 37 Solicitamos retoméis allí las visitas de seguimiento y los apoyos. Estos últimos serán puntuales, cuanto necesite ropa y otras gestiones."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2024-07-05','Ana: llamada de Aitor (613 694 469): ha quedado hoy con Nieves, Ed. para ir a buscar vivienda de alquiler. ············· Vuelvo a explicarle que no se puede autorizar un gasto mayor en este concepto porque sino no tendría para el resto de gastos (suministros, comida, etc.)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='IGLESIAS'and apellido2='MENDOZA'),'2024-07-05','Ana: Llamada de Teresa, sobrina de Mercedes (626 30 32 72), vuelvo a explicarle lo mismo que ayer a su madre, pues ésta tiene 80 años y no se entera muy bien, según expresó. Verbaliza también que hay más hermanos y sobrinos, pero éstos nunca mostraron el más mínimno interés.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2024-07-05','Ana: correo de Ángel, Asesor Jurídico: "Ana, citan a José Luis Murillo Horrillo a examen judicial, en la revisión de medidas. Inés, cuando puedas, por favor, solicita nuestra asistencia a través de videoconferencia." ··························································································································································································· Envío correo a Javier, TS CSS-Plas (javier.rdguezper@salud-juntaex.es): "Como en otras ocasiones, ¿podéis organizar el acompañamiento a al examen judicial para la revisión de las medidas judiciales de apoyo?','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2024-07-05','Ana: Envío correo a Alberto, Jefe S. Ecca.: "...dejamos en stad by lo que hablamos el otro día, en estos momentos se encuentra ingresado en el hospital y además parece ser que ha cambiado de idea"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CASADO'and apellido2='CARRION'),'2024-07-05','Ana: Correo de Cristina Hdez., TS CSS Plas (cristina.hernandezca@salud-juntaex.es): "Necesito documentación de certificado de Discapacidad de Antonia Casado Carrion para solicitar cita en el programa PADI del centro de Salud. " ·································· Respondo: "Adjunto: - Certificado de Discapacidad del CADEX - Dictamen Técnico Facultativo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2024-07-05','Ana: correo de Alberto, Jefe S. Ecca.: "ANA: YA SE QUE ES DIFÍCIL, PERO EL PROBLEMA NO ES EL DEJAR DE ABONAR DEUDAS...EL PROBLEMA ES NO DISPONER DE DINERO PARA ABONO CENTRO EN EL QUE RESIDE. ANGEL/ANA: PENSIÓN. • EL ESTÁ COBRANDO ACTUALMENTE DE PENSIÓN CLASES PASIVAS "RETIRADOS": 1.022,74 €/MES • TENDRÍA QUE COBRAR X ESTE CONCEPTO EN 2024: 1.881,39 €/MES • LA DIFERENCIA PROVENÍA DE LA RETENCIÓN DERIVADA DEL PAGO DE PENSIÓN MANUTENCIÓN HIJO....PERO ESTE HIJO...NO ESTABA FALLECIDO?????? • ESTO HABRÍA QUE VERLO PK SOLUCIONARÍA EN GRAN PARTE LOS POROBLEMAS ECO QUE TIENE Y QUE TENDRÁ (DEUDAS). SALDO HOY: 5.712,14 € PREVISIÓN A 12 MESES: -1.312,84 €/AÑO." ·································· Respuesta de Ángel: "Pues llevo tiempo intentando que dejen de retenerle los 781,32 euros. He escrito y hablado con: • Juzgado de Instrucción nº 2 de Cartagena, que fue quien acordó retener esa cantidad de su pensión. • Audiencia Provincial Sección nº 5 de Cartagena, que declaró insolvente a Mateo, por Auto de fecha 31/3/2003, y se procedió al abono de la condena por el Estado, como responsabilidad civil subsidiario, consignando la suma de 180.000,00 euros en concepto de principal y 10.391,25 euros en concepto de intereses, cantidades que fueron entregadas a los perjudicados (a los hijos de D. Mateo Ruano Moreno, D. José Mateo y D. Javier Ruano Gallego) y resolviendo que en el presente procedimiento no existe orden alguna a la Habilitación de Clases Pasivas para la retención que se le practica a D. Mateo Ruano Moreno en su pensión de retiro. Con fecha más reciente, 1/9/23, la Audiencia, en contestación a nuestro escrito, ha emitido un oficio en el sentido que os digo aquí, es decir, que no existe orden alguna a la Habilitación de Clases Pasivas para la retención. • El habilitado de clases pasivas, D. Juan Luis Gómez-Bascuñana Delgado, con el que es muy difícil poder hablar porque casi nunca está. Le he enviado correos adjuntándole toda la documentación, para que se deje sin efecto esa retención, pero ya veis que se la siguen reteniendo. Me dijeron desde la Audiencia Provincial sección nº 5, de Cartagena, que debido a la antigüedad del Auto (31/3/23), se encontraba archivado a Zaragoza y que lo iban a pedir y que nos contestarían. A día de hoy no hemos recibido contestación. Hoy he vuelto a llamar a la Audiencia Provincial sección nº 5 de Cartagena, me indican que ya se dirigieron a clases pasivas para indicarles que no había orden alguna a la Habilitación para que continuaran realizando la retención. Van a volver a enviarles un escrito reiterándoselo. En cuanto a los hijos, Javier Ruano Gallego, falleció el 25/2/2007, y el otro, José Mateo Ruano Gallego, de 41 años, trabaja, siendo independiente económicamente." ······························································································································································································ Nuevo correo de Ángel, A. Jurídico: "Me da que esto es más cuestión del habilitado, por las evasivas telefónicas y de correo electrónico, porque nunca está y porque el Juzgado (la Audiencia Provincial), ya le ha comunicado que no hay orden de retención y que el procedimiento está archivado. Van a volver a reiterárselo. En cuanto a la devolución de los recibos, también lo he pensado, amparándonos en la resolución de la Audiencia Provincial. Y en cuanto a la devolución de lo que ha abonado, es el siguiente paso, porque el Auto que le declara insolvente es de 31/3/2003… y desde entonces, o desde que llevamos ejerciendo el cargo al menos, 2020, le retienen estas cantidades. Exigiremos no solo la devolución de lo cobrado indebidamente, sino también la responsabilidad que le corresponda a Clases Pasivas y al tal Juan Luis Gómez-Bascuñana Delgado. Por cierto Alberto, confírmame que le siguen reteniendo esas cantidades en el banco, con un movimiento de cuentas de lo que va de año, por ejemplo. Y envíame también un extracto del banco actualizado a este mes de junio, porque que el que veo es de abril. Es para enviárselo a la Audiencia Provincial por correo electrónico y que vuelvan a requerir a clases pasivas que dejen de retenerle a Mateo esas cantidades."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2024-07-08','TERESA EMAIL DE LA TS DE LA CTLG Hoy he hablado con el padre de Manuel. Me dice que él no puede vivir con ellos porque lo dice la sentencia de tutela. Desconocía esto, pensé que él vivías con sus padres. Lo he hablado con el paciente y dice que él estaba en casa de sus padres cuando ingresó en la CTLG (yo en ese momento estaba de comisión en otro puesto de trabajo) motivo por el que lo desconocía. Os lo comento para que lo sepáis ME PLANTEAN QUE EN BREVE LE DARAN EL ALTA PORQUE YA NO AVANZAN CON EL','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2024-07-05','Ana: Correo-respuesta de Puerto Paniagua, TS SSASB (ssb5@mancomunidadvalledelalagon.es) al correo sobre la última incidiencia: "Gracias Ana, pero nada nuevo, pues ésta es su forma de proceder de toda la vida con su familiar..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2024-07-08','Ana: Correo de Estrella Durán, TS CSS Plas. (estrella.duranc@salud-juntaex.es) al ctutelar@ con copia a mí: "Adjunto remito factura de la montura de las gafas de Julia Morón, para que se la abonéis a la Óptica." ··················· *El coste de montura son 35€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2024-07-08','Ana: Recibimos RESOLUCIÓN DEL INSS - INCREMENTO DE LA PENSIÓN DE INCAPACIDAD PERMANENTE TOTAL a 772,00 €/mes por cumplimento de edad. ·········································································································································· Envío correo a Alberto, Jefe S. Ecca. con copia a Ana, Directora de la Res (anatdelat@hotmail.com): "Hemos recibido RESOLUCIÓN DEL INSS de INCREMENTO DE LA PENSIÓN DE INCAPACIDAD PERMANENTE TOTAL a 772,00 €/mes por cumplimento de edad. Pongo en copia a Ana Sánchez, Directora de la Residencia para su conocimiento y porque entiendo que tendrán que reajustar el cobro de la plaza, pues al incrementar los ingresos incrementarán también el coste. Alberto, no sé si con este incremento habrá opción de aumentar su asignación periódica tal y como solicitaba la propia Isabel. En correo del 30 de mayo nos indicaste que no era viable, no sé si con este incremento será viable o no. Ya nos dices cuando puedas." ···························································································································· Respuesta de Alberto: "ANA: OK A SUBIDA REINTEGRO EN 25 €...EN CUANTO SE INCORPORE LOURDES, VALE? ANA: SI HABLAS CON CENTRO RECUÉRDALES QUE NO SE ADMITIRAN GASTOS MAYORES QUE INGRESOS EN CÓMPUTO ANUAL!!!... ANA: TEN EN CUENTA QUE CENTRO COBRA EL 65 % DE LAS 14 PAGAS (SÓLO INFORMATIVO). LOURDES: SUBIMOS REINTEGRO A 125 €/MES (ANTERIOR 100 €/MES???) - RECARGA TARJETA??? LOURDES: XFA...NO ENCUENTRO EL ESCRITO QUE DICE QUE SU REINTEGRO ES DE 100 €/MES...SOLO ENCUENTRO EL DE 80 €/MES...YA ME DICES." ·························· Comunico a Ana, Directora Res. por mail.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='VALLE'and apellido2='SIMON'),'2024-07-08','Ana: Correo de ayer de Sheila Rguez., Directora Técnica CRR-CC (crr@grupociudadjardin.com): "Con respecto a la persona usuaria Félix V. y las consultas de dermatología privadas, se ha contactado con dos diferentes para preguntar precios. En ambas la metodología es la misma. Se paga la primera consulta de evaluación con precio de 100 €, a partir de ahí se realiza presupuesto según la necesidad de cada paciente. Si no necesita quirófano la retirada ronda entre 50-100€ más. Si se necesita quirófano puede aumentarse el precio unos 500€. hasta no acudir a valoración no podremos saber. En una de las clínicas nos dan cita para el martes 9 de Julio. ¿Os parece adecuado que acudamos y os mandemos el presupuesto que realicen en dicha clínica de las necesidades que presenta Félix y en función de ello nos decís si necesitáis otro presupuesto más? Por la situación del cobro de 100 € cada primera consulta de evaluación. Al tratarse de un tema importante para la persona usuaria y generar incertidumbre y aumentar su sintomatologái, agradeceremos la premura en poder darle una respuesta." ······················································ Lo reenvío a Alberto, Jefe S. Ecca. indicando el ok por mi parte para que acuda mañana a la consulta. ·································· *Respuesta de Alberto, Jefe S. Ecca: "ANA: OK 100 € PRIMERA CONSULTA." ····················· *Estrella habla directamente con Sheila, Directora del CRR. Acudirán mañana a la consulta y enviarán la factura con nº cuenta para abonarl mediante transferencia. ··············································· *Finalmente nos comunican desde el CRR que se pospone la cita de dermatología. Nos mantendrán informados.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2024-07-08','Ana: Dentro del límite que establece Alberto, propongo, en correo a Alberto y Alejandra, S. Ecca: "...autorizamos 145€/mes para gastos de bolsillo, para que pueda contar con unos 120€ cada 6 meses apróx para ropa o lo que pueda necesitar aparte de casi la extra que ahorra." ·································································································································································································· Correo de Ana Mónica Hernández, TS Sierra de Gata (mhernandez@sierradegata.es): "He hablado con la responsable de la residencia en cuanto al tema de peluquería y podología. Me comenta que la peluquera que viene al centro por cortar cobra 7€. Si ella quiere ir a alguna de las peluquerías que hay en el pueblo, ya no sabemos los precios, porque depende también de lo que se haga.En cuanto a la podología, si es sólo cortar las uñas, me dice la responsable que ella se encarga de cortárselas como se lo hace al resto de residentes, pero si ya es tema de durezas u otras cosas no sabe los precios exactos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALONSO'and edp.apellido1='ORTIZ'and apellido2='GERMAN'),'2024-07-08','-Amalia Alonso sufrió el sabado descompensacion psiquiatrica , acudió el médico pero no lo ingresaron . Agredió a las hermanas. Tiene G.III , hariamos cambio PIA por E.Social para ingreso en R. Mayores si accede voluntariamente. Si no , lo pediríamos via judicial . Solicio visita de Futuex , y he pedido I. Social y I. medicos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATHAN'and edp.apellido1='VAZQUEZ'and apellido2='MUÑOZ'),'2024-07-08','-Alberto me informa que hay otra CCC en la que no están las monjas donde se le ingresaba la P.V.S del SEPAD cuando estaba en domicilio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE DOLORES'and edp.apellido1='VARGAS'and apellido2='CHAVERO'),'2024-07-08','-Hablo con Carlos F. para que desbroce el solar , serán 80€ Me enviará fotos con el resultado. Me dice que en la casa vivia José con un hermano que ya falleció . Va a preguntar si hay más herederos . Habría una casa y tierras que regularizar a su nombre. Escribo a Estrella para que ingrese los 80€','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2024-07-08','miguel, email de Tere: Me ha llamado M Jesús (610843541), esta preocupada porque le ha llegado una demanda por parte del padre de su hija en la cual parece ser que le pide custodia. Mª Jesus tiene una hija de pocos meses de una pareja que tuvo la cual denuncio por malos tratos. Me pide que le gestionemos un abogado de oficio. *************************************************** mi contestación: Hola, sólo teníamos en el expte un oficio, pero como no sabemos el contenido del procedimiento, me ha dicho la del jzdo que nos enviarán por Lexnet la demanda y lo que haya hasta ahora. Te iré informando. ************************************** su contestación: Pero hay que pedirle abogado de oficio para que le defienda no? ************************************* Me llama la tutelada, Tere la da mi tlfno ***************************************** Mi contestación a Tere e Inés: Buenos días Inés, pon un oficio al juzgado con el siguiente contenido “ En relación al procedimiento FIL FILIACION 0000170 /2024 del que está conociendo este juzgado de 1º instancia e instrucción nº1 de Almendralejo, contra la tutelada por esta Comisión Tutelar de Adultos Doña Mª Jesús Cruz Esperilla, se solicita a este juzgado que se paralice todo tipo de actuaciones hasta que desde este juzgado se solicite abogado y procurador de oficio, dando plazo suficiente para que el abogado que sea nombrado pueda contestar a la demanda. Se hace saber además a este juzgado que Doña Maria Jesús Cruz Esperilla vive actualmente con su tía y su hija en otra dirección cuyo certificado acreditativo del ayto de Almendralejo será aportado en próximos días por esta Comisión Tutelar de Adultos a este juzgado. Rogamos que todo lo concerniente a este procedimiento sea notificado al abogado de oficio que se nombre, a la tutelada y a esta Comisión Tutelar de Adultos, vía Lexnet a ésta última.” Tere, he hablado con Maria Jesús 610843541 para informarle que hace un rato nos ha remitido el jzdo vía Lexnet toda la documentación que por ahora hay del procedimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2024-07-08','Ana: Tras hablar con Ángel Félix (643 622 174), pidió el altal voluntaria en el hospital, envío correo a Albero y Estrella, S. Ecca.: "Acabo de hablar con ÁNGEL FÉLIX MAILLO SANTIBÁÑEZ, ya ha salido del hospital, está de nuevo en situación de calle, hasta septiembre le han dicho que no podría volver al Centro de Acogida Temporal de Cáritas. Retomamos lo hablado previamente: MODIFICAMOS REINTEGRO PERMANENTE A 185 €/SEMANA a partir del mes que viene. **Y para esta semana se autoriza un EXTRA DE 350€ para ropa, saco de dormir y el resto de cosas que necesitaba + “ferias”. Indicadme qué día podrá ir a retirarlo para que se lo comunique. (Esto también lo habíamos hablado y lo autorizaste Alberto. Son 100 € menos de lo que él pedía de extra).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2024-07-08','Ana: En relación al correo de Toni aportando la documentación que le requieren a Vanesa para la reactivación de la PNC + Facturas de agua, le contesto: "Gracias Toni. Ya tenemos también la respuesta al oficio que envié yo a PNC, así que intento que hoy mismo se envíe por REGISTRO la documentación. Preparo ahora el oficio. En cuanto a las facturas de agua, se las reenvío a la sección económica. Espero que les sirvan así. Por cierto, ¿sabéis si acudió finalmente a hacer la Declaración de la Renta? Ya me decís, pues como no haya acudido va a ser otro problema." ······························································································································································································ Reenvío facturas de agua a las S. Ecca. ····································································· Respuesta de Alejandra: "Estamos pendiente de cuando tenga ingreso y procedemos a pagarla." ···· Se abonará mediante transferencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='YOLANDA'and edp.apellido1='CALDERA'and apellido2='MARTIN'),'2024-07-08','Ana: Correo de Estrella Durán, TS CSS Plas.: "Como sabes, ingresó Yolanda Caldera en la UHDAC de nuevo, con previsión de quedarse para siempre, entiendo que habrá que pasarle la cuota mensual, igual que a Andrés Silva y a Carlos Alberto Vicente..." ························ Pido a Estrella que nos informen de la cuantía que le corresponde abonar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN CARLOS'and edp.apellido1='RUBIO'and apellido2='GALAN'),'2024-07-09','miguel, me llega la solicitud de ibercaja para que firme la gerente como representante de la ctaex la solicitud de autorización de cancelación registral, que pongo a la firma y se la devuelvo a la asesoria Proyec. Consultores >mjgabaldon@proyecconsultores.com> Buenos días, adjunto firmada la solicitud de cancelación. Ruego agilicen los trámites ya que llevamos mucho tiempo para levantar esta carga.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2024-07-08','Ana: respuesta de Javier Rodríguez, TS del CSS-Plas. (javier.rdguezper@salud-juntaex.es): "El día 3/07 se solicitó videoconferencia para esta citación. No obstante, estamos pendiente de remitir al juzgado la identificación de familiares. Pronto lo haremos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MORENO'and apellido2='FOLLARAT'),'2024-07-09','miguel, me remite JOSE SANTIAGO LAVADO >2981@icaba.com> el Auto denegatorio de la solicitud judicial de aclaración-rectificación de la autorización de venta de los bienes de la herencia que se firmó, debido al tiempo transcurrido y que requeriría estudio de nuevo de toda la documentación con lo que habria que iniciarse de nuevo el procedimiento. ****************************************************** Llamo a Coro para que hable su hermano con el notario de los Santos de Maimona (Carlos Duro) y que vean opciones para evitar empezar de nuevo con solicitud al colegio de abogados de abogado de oficio y comenzar de nuevo un procedimiento judicial de solicitud de autorización de venta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CIPRIANO'and edp.apellido1='MIGUEL'and apellido2='BAZAGA'),'2024-07-08','Ana: Correo de Estrella Durán, TS CSS (estrella.duranc@salud-juntaex.es) a Miguel, A. Jurídico, con copia a mí: "Desde el Centro Socio-Sanitario de Mérida, nos instan al traslado a nuestro centro de Cipriano Miguel Bazaga. Nos gustaría que nos enviaseis la resolución judicial para comprobar, que efectivamente, ha terminado la orden de alejamiento que tenía de otra paciente de este centro." ····························· Miguel realiza consulta a Fiscal de Plasencia. Pte. de respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2024-07-09','Ana: Envío correo a Mónica Hernández, TS Sierra de Gata (mhernandez@sierradegata.es): "desde la sección económica se autoriza un REINTEGRO PERMANENTE MENSUAL de 145 €/mes a partir del 1/8/24, que podréis retirar del 1 – 10 de cada mes. En julio ya retiró sus 300 € en Plasencia antes de ingresar en vuestro recurso. Con esta cuantía podrá ahorrar casi una paga extra al año y además, podrá contar con dos extras anuales de unos 100-120€ para ropa o lo que pueda necesitar. Si surgen otras necesidades nos vais informando y se va valorando conforme a sus ahorros."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CIPRIANO'and edp.apellido1='MIGUEL'and apellido2='BAZAGA'),'2024-07-09','miguel, recibí ayer email de Estrella del CSS de Plasencia, y me llamó después porque verificar si pueden o no trasladar del CSS de Mérida al CSS Plasencia: Buenos días. Desde el Centro Socio-Sanitario de Mérida, nos instan al traslado a nuestro centro de Cipriano Miguel Bazaga. Nos gustaría que nos enviaseis la resolución judicial para comprobar, que efectivamente, ha terminado la orden de alejamiento que tenía de otra paciente de este centro. ******************************************** Tras enviar email y hablar por tlfno con el Fiscal de Plasencia me confirma las dos ejecutorias que tenía que ya están archivadas. ************************************************** contesto a Estrella del CSS Plasencia con copia a Ana Ts: Buenos días Estrella, me acaba de llamar el fiscal de Plasencia José Manuel Rubio, que ha comprobado que no hay nada pendiente. Había dos ejecutorias que actualmente están archivadas del jzdo Penal 1, la Ejecutoria 543/19 y 268/22 (ésta última ha sido archivada el 12-6-24). Por tanto, podéis proceder sin problema con el traslado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2024-07-09','Ana: Envío a Juan Carlos, Aux. Adtvo para que remita por registro: "En relación a VANESA FERNÁNDEZ GÓMEZ, adjunto la siguiente documentación para remitir a la Secretaría General de Servicios Sociales, Inclusion, Infancia y Familia: - Oficio aportando documentación requerida - Nóminas y liquidación El Cruce - Nóminas Adi & Salou - Nóminas Vaquero Cuesta - Nómicas relativas a Dª. Mª Estrella Gómez Sánchez"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOLORES'and edp.apellido1='MARAVER'and apellido2='NORIEGA'),'2005-04-21','Se ha aceptado y jurado por Acuerdo de 13.03.00. Se ha solicitado informes y Certificado pensión.Recibidos. Se solicita autorización judicial para ingreso en Centro.','2');
