insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2024-07-09','Ana: Tras hablar con Esther, Pensiones de Orfadad de INSS (927 60 00 56), y con Rafa, Control de pensiones (927 62 00 65), le envío un correo a éste último (rafael.sanchez1@seg-social.es): "Tal y como hemos acordado mediante conversación telefónica, envío adjunta la siguiente documentación relativa a D. ALEJANDRO MONTERO VÁZQUEZ, cuyo cargo ostenta la CTAEx: - Justificante de Registro de fecha 12/02/2024 - Oficio aportando documentación - Resolución de Revisión del Grado de Discapacidad - Testimonio de Aceptación del Cargo de Tutor Rogamos se revise su expediente para que pueda volver a percibir la pensión de orfandad."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MORENO'and apellido2='ACERA'),'2024-07-09','Ana: Conversación con Maite Cañadas, CR Conventual S.Fco.-Plas.(21860): Joaquina está muy bien. Puesto que tienen la autorización General de centro y Joaquina tiene mucho dinero, le compra las cosas que necesita y desea (gafas de sol, sombreros entre otros).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='REY'and apellido2='CAMPON'),'2024-07-09','Ana: conversación con Maite Cañadas, Directora de la Residencia "San Francisco" de Plasencia (927-017340), Luisa ha estado hospitalizada, me enviará Informe médico y documentación relativa al acompañamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-07-09','Ana: Llamada de Juan José Molina, Psiquiatra ESM-CC (56813), referente de José Manuel y Coordinador. Entiende que José Manuel ha "quema" todos los recuross comunitarios. Es un riesgo para sí mismo y para los demás. Si descartamos CRR y otros centros abiertos como las Casas de la Misericordia (el Alcuéscar ya manifestaron en su día que no tiene cabida) no quedan más opciones. En centro de mayores seguramente alteraría la convivencia y generaría problemas al resto de residentes. Además no ha sido capaz ni de adaptarse al Comedor del Centro Residencial Cervantes, no aguantó ni dos semanas. ··· El apoyo ambulatorio que recibe (Futuex, SAD, ESM) resulta insuficiente. ····· Juan José entiende que la única alternativa que queda para él es Larga Estancia del CSS, pero él no quiere. *Nos mantendremos todos en el mismo discurso y si de aquí a unos meses la situación se hace más insostenible se convovará una SUBCOMISIÓN y si fuera preciso se redactarán los informes necesarios para solicitar al Juzgado Ingreso Involuntario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2024-07-08','Ana: Correo de Clara, TS C.Salud (isabel.garcial@salud-juntaex.es): "Está Juan Chamorro en el despacho, me pide que te trasmita que él " no es minusválido y que no tiene derecho a cobrar la pensión. Qué quiere incorporarse al mercado laboral. Qué no quiere depender de los Asuntos Sociales, Qué sí jurídico no hacer nada, se va a tener que buscar un abogado de pago".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2024-07-10','miguel, recibo email de Elsa la notaria, Elsa María Caballero Pascual >emcaballero@correonotarial.org> No, no hay herencia previa. Como ponemos en la escritura de venta, carece de titulo fehaciente de adjudicación. Manifestaba que la había heredado. Lo cual no deja de ser positivo, porque ahora que me doy cuenta, la escritura de venta no se puede inscribir porque es primer título, es decir, es la primera vez que se hacía escritura, y para inscribir son necesarias dos escrituras. Así que los compradores no han podido inscribir. ****************************************** mi contestación: Buenos días Elsa, gracias por la información. Justo es la conclusión a la que llegué…al no haber título previo no es título suficiente para inscribir…y a mi entender es impugnable al ser una persona que por ley requiere autorización judicial conforme el 287 CC','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2024-07-10','TERESA ARCHIVO RESOLUCION DE DISCAPACIDAD Y ENVIO TARJETA DE DISCAPACIDAD A JOSE EL TS PARA QUE SE LA HAGA LLEGAR','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='INES'and edp.apellido1='MUÑOZ'and apellido2='ALIAS'),'2024-07-10','Ana: Envío correo-e a María Gía., Directora del C.R. Fco. de Asís, Aldea del Cano (centrofranciscodeasis@gmail.com): "Adjunto la Autorización para la administración de la vacuna frente al NEUMOCOCO, debidamente firmada y sellada por la Representante Legal."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2024-07-10','Ana: Respuesta de Rafa, Control de pensiones INSS - CC (927 62 00 65 // rafael.sanchez1@seg-social.es): "Hablaré con el Subdirector si es necesario pasar el expediente por el E.V.I. para incapacitar al huérfano de manera absoluta (esto retrasaría un poco más la rehabilitación) o bien podemos rehabilitarla directamente con esta documentación. Te comento lo que sea por aquí."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2024-07-10','Dejó de percibir P. Orfandad en Dic 2023 . Gestionada la revisión con el INSS , se le ha dado de baja porque estaba aprobada como menor de edad y ha llegado a la fecha límite de los 25 años . He hablado con Plena Inclusión Montijo y van a devolver el dinero de copago de la plaza de los meses de enero a julio que lo han calculado teniendo en cuenta las 2 pensiones , PFHC y P.Orf. Si luego el INSS acepta la revisión con carácter retroactivo tendremos que abonarlo de nuevo . El mismo caso ha ocurrido con su hermano gemelo Alejandro Montero , Ana está haciendo las gestiones con el INSS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SANDRA'and edp.apellido1='GONZALEZ'and apellido2='ESCASO'),'2024-07-10','Eva ha enviado las nominas a PNC , sigue teniendo la pension suspendida. Lo está gestionando Eva.','2');
