insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2024-07-10','Ana: Corre de ayer de Estrella, TS CSS-Plas (estrella.duranc@salud-juntaex.es): "Informo que Enrique se va de pase desde hoy hasta el lunes que viene." ······························· Reenvío a Toni y Clara, Futuex, solicitando organicen visitas de apoyo y seguimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='CALVO'and apellido2='GONZALEZ'),'2024-07-10','-Amalia : escribo a S. eco y jurídica : He hablado con PNC con varios técnicos y finalmente con la Jefa de Sección de Nóminas . Queda confirmado que desde el servicio de PNC la prestación se está ingresando desde 2017 en la cuenta de Ibercaja que termina en 527 como se solicitó desde la Sección Eco . En 2022 se volvió a solicitar ese cambio , porque a nosotros no nos constaba y seguía ingresándose en otra cuenta , pero ya se estaba ingresando en la de Ibercaja ( Este cambio lo hice yo y envié incluso modelo de alta a terceros , tengo guardado el registro ) . PNC confirmó que era la misma cuenta en la que ya se estaba ingresando. No es necesario volver a solicitar el cambio , es la cuenta en la que lo están ingresando desde 2017. El problema está en la entidad bancaria , tendréis que averiguar porqué se le ha ingresado en otra cuenta . Me dicen desde pensiones que se les ha dado el caso de que había una orden interna para ese cambio ... a saber lo que ha podido ocurrir aquí. Sea como fuere , el dinero que haya podido ahorrar Luis no creo que tenga que repartirse entre los 3 hermanos ,no es parte de la herencia del padre , se puede demostrar que ese dinero corresponde a su pensión . Puede necesitarlo , es un hombre joven . Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JOSEFA'and edp.apellido1='MOYA'and apellido2='GARCIA'),'2024-07-10','TERESA Vamos a dar de baja a los suministros de la vivienda de Josefa puesto que va justa de dinero. En la cas solo vive ella no hay ningún problema en darle de baja Y YA NO VA A VOLVER AL DOMICILIO','2');
