insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDRO'and edp.apellido1='TORRES'and apellido2='VILLEGAS'),'2024-07-10','Ana: en relación al ingreso en la plaza pública concedida, llamo a la RR.MM. Los Canchos de Mirabel (927 45 01 53), hablo Jesús, responsable. Su nº directo: 609 23 52 90. ········································· Llamo a Tensi, TS SSASB, al Ayto. Cañaveral (927 300 006): Ha estado en contacto con Esther, TS SSASB de Mirbel / Serradilla / Torrejón el Rubio (927 40 70 02). Ya lo tiene todo medio organizado. Ya han marcado la ropa en los PP.TT. con el nº asignado en la resid. Plantean que el ingreso se lleve a cabo mañana jueves día 11 que estará Esther allí. ··············· Está previsto que le traslade la Concejala. Si hubiera algún problema llamarían a un taxi. ··································· Llamo de nuevo a Jesús, Responsable de la Res. de Mirabel, confirmamos que el ingreso será mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALONSO'and edp.apellido1='ORTIZ'and apellido2='GERMAN'),'2024-07-10','-Amalia : hablo con Reme , va a pedir cita con su doctora para ver si con un tratamiento se le puede compensar y mantener en domicilio . Voluntariamente no quiere ingresar ni él ni lo quieren las hermanas . Vamos a probar con tto. ambulatorio , si no funciona volveriamos a retomar la solicitud de R.M. por PIA emergencia pidiendo autorización judicial.','2');
