insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2024-07-10','Ana: Envío correo a Cora, Aux. Adtvo. ESM-Trujillo (cora.sanchez@salud-juntaex.es): "En relación a este paciente y las citas que nos enviaste, he intentado hablar con Pablo, Trabajador Social, sin éxito, quizá está de vacaciones. ¿Podrías, por favor, confirmarnos si la cita de enfermería de agosto sigue en pie o si con la que enviáis de septiembre se modifica la de agosto?"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='MONTAÑO'and apellido2='MONTAÑO'),'2024-07-16','-Amalia, citan a Joaquín para reconocimiento por su SS el día 6/11/24, lo comunico al CSS Mérida donde se encuentra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2024-07-10','Ana: Correo de Estrella Durán, TS CSS-Plas (estrella.duranc@salud-juntaex.es): "Por fin, hemos convencido a Alfonso de que se compre ropa (le está toda pequeña y va enseñando la tripa), lo hemos puesto como condición para irse de pase el finde con su madre. No sé si puede hacer un gasto extra para tal fin, de unos 200 euros, para que sea retirado por la Educadora de Futuex y lo acompañe a la tienda a comprarla...." ········································ Se acepta el presupuesto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CIPRIANO'and edp.apellido1='MIGUEL'and apellido2='BAZAGA'),'2024-07-10','Ana: correo de Estrella Durán, TS CSS Plas (estrella.duranc@salud-juntaex.es), al ctutelar con copia a mí: "ha ingresado procedente del CSS de Mérida, Cipriano Miguel Bazaga. Haced el favor de enviar la autorización para poder sacar dinero del banco. Recordad que en dicha autorización debe indicarse el número de cuenta y la cantidad mensual a retirar." ································································· Otro correo de Estrella, TS: "veo que tiene pedida una revisión del grado de dependencia. Lo he comunicado a las compañeras de Dependencia, y me piden que mandéis un cambio de residencia...." ······························· *Se le solicitó a fecha de 15/11/2022 desde el CSS de Mérida. ··········· Subo al portafirmas digital la Comunicación de variación de domicilio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CIPRIANO'and edp.apellido1='MIGUEL'and apellido2='BAZAGA'),'2024-07-11','Ana: envío a Juan Carlos, Aux. Adtvo (juancarlos.cano@salud-juntaex.es): "En relación a Cipriano Miguel Bazaga, cuyo cargo ostenta la CTAEx, adjunto COMUNICACIÓN DE CAMBIO DE DATOS para remitir por registro a la Sección de Dependencia de Plasencia." ······································································································································· Correo de Estrella Durán, TS CSS: "va a pasar al Psicogeriátrico, así que lo va a llevar mi compañero Javier. Su número es 24205."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2024-07-11','Ana: Envío a Juan Carlos, Aux. Adtvo (juancarlos.cano@salud-juntaex.es): "Adjunto oficio para remitir por REGISTRO al Servicio de Prestaciones Sociales y Ayudas de la Secretaría General de Servicios Sociales, Inclusión, Infancia y Familia (Buzón: A11030105), la siguiente documentación relativa a VANESA FERNÁNDEZ GÓMEZ: - Oficio aportando documentación - Certificado de empresa y finiquito empresa Bubu"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-07-11','Ana: Tras hablar con Maite, Jefa CTAEx, y con Nieves, Ed. Futuex (663 851 769), envío correo a Toni - Futuex: "...- Se acepta el presupuesto de la VITROCERÁMICA. El horno NO SE VA A COMPRAR DE MOMENTO, si más adelante demuestra que cocina y le va a dar uso volverá a valorarse. Además tiene muchos gastos ahora. - Se acepta también unos días de VACACIONES EN HERVÁS, pero SÓLO 2 NOCHES. Tras la experiencia del año pasado cuando pidió ir a Olivenza, donde tras haber abonado 4 noches sólo aprovechó 2, hemos decidido hacer la prueba. Si todo va bien podrá aprobarse otra salida más adelante. - Paso también a la secc. económica el recibo de la contribución para que se la abonen a su hermano." ······························ *Se lo comunico a José Manuel y envío correo a la sección económica con los documentos para el abono.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUSTAVO ALFREDO'and edp.apellido1='CASTAÑO'and apellido2='SOTO'),'2024-07-11','Ana: Correo de Toni-Futuex: "le preocupa mucho que todo este en orden y se está ocupando de cuidar todo aquello que tiene que ver con su domicilio, por ello desde el equipo de apoyo se le acompaña a GeFiscal, para pedir asesoramiento sobre seguros de hogar y aquí le dan dado varios presupuestos distintos. Consideramos que si seria importante, siempre que la comisión la valore, el que tenga una póliza de seguro de hogar. También se ha pedido presupuesto de un horno, puesto que es el único electrodoméstico que le faltaría en la vivienda y le gustaría tenerlo. Se adjuntan ambos presupuestos a este correo para que se valore desde la CTAEX; en el caso del horno, se ha acudido como en otras ocasiones a Electrocash la cuenta bancaria sería: ES29 2103 3283 3800 3490 4013." ······························································································································································································ Envío correo a la Secc. Ecca. con copia a Toni-Futuex: "Os reenvío correo de Toni – Futuex, con presupuestos relativos a GUSTAVO ALFREDO CASTAÑO SOTO. Ya sé que Alberto no está estos días ni la próxima semana. Supongo que tendrá que valorarlo él, pues ya se han concedido 2 extras este verano. Por mi parte, si es viable, ok a ambos presupuestos, si es viable entiendo que es mucho mejor que tenga seguro de hogar y el horno, si cocina es más que coherente que quiera tener uno. Pongo en copia a Toni. Por favor, Toni, explicarle que puede tardarse unas semanas en dársele respuesta pues no son cuestiones urgentes y Alberto no está. Por cierto, no sé quién es la educadora de referencia en este caso."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2024-07-12','miguel, enviamos al colegio de abogados de caceres solicitud de abogado de oficio para solicitar autorización de venta de inmueble','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='CASQUERO'and apellido2='JAEN'),'2024-07-11','-Amalia , solicito a May por email que me confirme los centros residenciales que tiene pedidos Antonia para dar la información a la sección de salud mental .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='GOMEZ'and apellido2='SANCHEZ'),'2024-07-12','Ana: Envío correo a Raquel Navarro, TS C. Salud de La Mejostilla, CC (raquel.navarro@salud-juntaex.es / L-X-V): "Ayer volví a preguntar a mis compañeros de la sección Jurídica en relación al DAVID GÓMEZ SÁNCHEZ. Te reenvío el hilo con las respuesta. A ver si pronto se resuelve todo esto y podemos empezar a intervenir." ··································· Respuesta de Inés, S. Jurídica: "...vamos a tener que hacer una reclamación por escrito y enviarlo vía Lexnet, por teléfono es imposible,.. ya lo intenté tb hace unos días …sin éxito…" ························ Respuesta de Miguel, A. Jurídico: "mañana llamo al Servicio Común de Ordenación, que es donde dicen en el jzdo 1º inst nº4 nos tenían que haber contestado, y sí les consta que desde febrero está solicitado. Me han dado los siguientes teléfonos Inés, para que lo apuntes para posteriores peticiones de los jzdos de Cáceres… Servicio Común de Ordenación 927-620406;927620407;927-620408; 927-620437. Con lo que me digan mañana os digo…"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='GOMEZ'and apellido2='SANCHEZ'),'2024-01-31','Ana: Correo de Raquel Navarro, TS C. Salud de La Mejostilla, CC (raquel.navarro@salud-juntaex.es / L-X-V): "...ha fallecido el padre de David, para ver si hay alguna novedad sobre las medidas de apoyo, ya que ahora tiene que hacer muchos trámites" ·········································· De momento sólo es DEFENSA JUDICIAL.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2024-07-11','TERESA Acabo de hablar con Alexandra. El ingreso se va a realizar el lunes 15 de julio. Hay que comunicarlo al 112. Para que estén el 15 de julio a las 9:15 en la dirección Plena Inclusion, C/ Europa 18 ( Edificio de abajo). Persona de contacto Alexandra ( trabajadora social). Envíalo hoy si puedes o mañana a primera hora. Se lo comunico a Rosa de Fuente de CAntos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2024-07-12','Ana: Correo de Sonia Bernabé - TS y Directora - Asindi (trabajosocial@asindi.e.telefonica.net): "te mando el calendario para las próximas visitas a la familia de Roberto y Justo Hernández Castaño. Como en otras ocasiones, si hay algún cambio os lo comunicamos." ·························· Guardo en el expte. digital.','2');
