insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISIDRO'and edp.apellido1='TORRES'and apellido2='VILLEGAS'),'2024-07-11','Ana: Correo de Tensi, TS Casas de Millán (ssbtensi@riberosdeltajo.es): "comentarte que Isidro ya se encuentra en los Centro Residencial de Mirabel, he hablado con la compañera y me ha comentado que el ingreso bien y se ha quedado tranquilo, aquello es mucho más grande y con más personas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='JIMENEZ'and apellido2='PICON'),'2024-07-11','Ana: Correo de Pilar Cerrillo, TS Res. Parque del Príncipe - Grupo Ciudad Jardin - (calidad@grupociudadjardin.com): "hemos vuelto a tener problemas con la sobrina de las dos hermanas, supongo que la compañera de FUTUEX te habrá contado. Te pongo en antecedentes, son dos hermanas, Isabel y María, a esta última la tenéis tutelada vosotros. Isabel esta muy malita, ayer su sobrina estaba con ellas en la habitación cuando llegó la compañera de FUTUEX a ver a María y traerle unas zapatillas que necesitaba. Su sobrina se enfado mucho, no la dejo salir de paseo, no quiso que se le trajera ropa de color e insulto y hablo de muy malas maneras a la compañera de FUTUEX, además de insultar gravemente ("cacho puta" e imbécil) a la responsable del centro delante de trabajadores y familiares. No se si se podrá hacer algo al respecto, por si se lo puedes comunicar al gabinete jurídico. Entiendo que no se le puede prohibir ver a su tía Isabel pero no se si María está en la misma situación al estar tutelada. Por otro lado, se la podría prohibir la entrada al centro?"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORA'and edp.apellido1='GUTIERREZ'and apellido2='GARCIA'),'2024-07-12','Ana: Reenvío correo de Raquel Vadillo, Res. Catalina Curiel (rvadillo@residenciacatalinacuriel.es) a la secc. ecca.: "Os reenvío correo de la Residencia Catalina Curiel. Ya sé que Alberto, Jefe de Secc. Ecca. no está, pero como podéis leer en el hilo, Flora Gutierrez García necesita unos zapatos especiales, por tanto, si es viable económicamente, que imagino que sí, desde la sección social se da el ok al presupuesto adjunto (232 €). En caso de ser viable, por favor, contestar a Raquel Vadillo, Residencia, una vez hecha la transferencia para que puedan retirar los zapatos. La pongo en copia en el correo. Por cierto, habrá que llamar a la ortopedia, pues veo que en el presupuesto no consta el número de cuenta."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='GARCIA'and apellido2='MORENO'),'2024-07-12','Ana: Envío a Juan Carlos Cano, Aux. Adtvo. (juancarlos.cano@salud-juntaex.es): "Adjunto la siguiente documentación relativa a MARÍA PILAR GARCÍA MORENO, cuyo cargo ostenta la CTAEx, para remitir por REGISTRO al IMAS (Instituto de Asuntos Sociales) del Ayto. de Cáceres: - Solicitud del Servicio de Comidas a Domicilio (Cáterin) - Informe de Salud - DNI de la solicitante - DNI de la Representante Legal - Decreto de Nombramiento - Resolución de Delegación de Funciones - Resolución Reconocimiento Grado y Nivel Dependencia". ······································································· Envío correo a Mamen, Ed. Futuex (delegadapoyo.caceres@futuex.es): "Sólo comunicarte que ya he enviado para registro la solicitud con toda la documentación pertinente, excepto Vida Laboral de Abraham, que también la piden... supongo que nos la solicitarán para subsanar la solicitud, así que cuando vayas verla o hables con ellos, por favor, díselo para que la vaya solicitando."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2024-07-12','Ana: Correo de Felisa Custodio, TS CAMF (trabajadora_social_alcuescar@imserso.es) a los A. Jurídicos, con copia a mí: "me vuelve a preguntar la residente por la renuncia de la herencia de su madre fallecida, el 05 de agosto se cumplen los seis meses del fallecimiento, está bastante preocupada por la deuda que tenía su madre."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2024-07-11','Ana: respuesta de Cora, Aux. Adtvo. ESM-Trujillo (cora.sanchez@salud-juntaex.es): "Sí de momento conserva las 2 citas, la de agosto y la de septiembre. Pablo está aquí en Trujillo los martes y jueves, el resto de días creo que va a Miajadas. El teléfono de Pablo de aquí es el 54509."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2024-07-12','Ana: Envío correo a Clara, C. Salud, Raquel, SSASB, María y Toni - Futuex: "En relación a JUAN CHAMORRO HOLGUÍN, os reenvío respuesta que me dan desde Salud Mental a mi consulta sobre la cita de agosto en la consulta de enfermería. Subrayo en amarillo. María y Toni, por favor, tenedlo en cuenta para acompañarle, si os lo permite, a la cita de agosto también."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GILES'and apellido2='SALAZAR'),'2024-07-15','TERESA Desde Plena Inclusión Cabeza del Buey adjuntamos el informe de seguimiento del equipo técnico de observación en relación a Ramón Giles Salazar, donde se detallan las alteraciones conductuales continuadas y las veces que se ha activado el 112 como consecuencia de las mismas. Resaltar que las disputas entre Ramón y sus compañeros de residencia (en especial con Rosa Ruiz Romero) se están convirtiendo en algo habitual y que alteran de manera importante la convivencia del resto de residentes del centro. Es importante, por ello, hacer lo posible para que el traslado de Ramón a otro centro cerca de su localidad, ya solicitado, se haga efectivo a la mayor brevedad posible.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA VALLE'and edp.apellido1='PATARRO'and apellido2='CARMELO'),'2024-07-15','TERESA He intentado llamarte pero no consigo contactar. Tras hablar con la trabajadora social de Valencia del Ventoso y con mi compañera Amalia, todas valoramos que no es un riesgo que Valle vuelva a vivir sola en el pueblo debido a los antecedes de alcoholismo que ha tenido. Desde que ha ingresado en la residencia su evolución ha sido muy favorable. Planteamos la opción de que continúe en la residencia con posibilidad de que pueda ir de visita al pueblo de vez en cuando. Con respecto a la plaza residencial vemos que paga el 80% incluidas pagas extra, su situación económica no es muy buena tenemos que mantener la vivienda (suministros, impuestos…) hay posibilidad de que se le baje el tanto por ciento que paga? Estamos gestionando el acceso a las cuentas para ver movimientos, tu sabrías decirme los gastos que tiene de medicinas, podología, peluquería, ocio…, como esta disponiendo ella ahora del dinero? Necesito esta información para poder elaborar un presupuesto y que los gastos no superen a los ingresos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='JIMENEZ'and apellido2='PICON'),'2024-07-15','Ana: Correo del día 11 de Pilar Cerrillo, TS Res. Parque del Príncipe - Grupo Ciudad Jardín (calidad@grupociudadjardin.com): "Te pongo en antecedentes, son dos hermanas, Isabel y María, a esta última la tenéis tutelada vosotros. Isabel esta muy malita, ayer su sobrina estaba con ellas en la habitación cuando llegó la compañera de FUTUEX a ver a María y traerle unas zapatillas que necesitaba. Su sobrina se enfado mucho, no la dejo salir de paseo, no quiso que se le trajera ropa de color e insulto y hablo de muy malas maneras a la compañera de FUTUEX, además de insultar gravemente ("cacho puta" e imbécil) a la responsable del centro delante de trabajadores y familiares. No se si se podrá hacer algo al respecto, por si se lo puedes comunicar al gabinete jurídico. Entiendo que no se le puede prohibir ver a su tía Isabel pero no se si María está en la misma situación al estar tutelada. Por otro lado, se la podría prohibir la entrada al centro?" ···································· Reenvío correo a los A. Jurídicos y llamo a Pilar. Cuando nos digan los A.Jurídicos le informaré. ·············································································································· Envío correo a Toni-Futuex: "Nos comunican desde la Residencia Parque del Príncipe un incidente acaecido con Carmen, la sobrina de Dª. María Jiménez Picón, que afectó directamente a la Educadora. Cuando podáis, por favor, pasarnos nota del incidente, para tener constancia del mismo. Por cierto, no sé cuál de las compañeras la visita, ya me dices cuando puedas."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2024-07-12','miguel, remito a Inés para su envío por lexnet: procedimiento civil de solicitud judicial de nulidad de escritura de venta','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2024-07-15','Ana: Envío correo a la secc. ecca: "Me ha llamado Alberto, el nuevo presidente de la comunidad de vecinos (927 00 14 83) en la que vive CARLOS GLEZ. LEO, me comunica que Carlos DEBE MÁS DE 1.000€ de la comunidad. La cuota mensual es de 65€, pero además llevan meses abonando una derrama por la instalación de ascensores de la que quedan varios años por pagar. Me facilita el contacto de del Administrador de fincas, para que se le solicite las facturas y número de cuenta para abonarlo mediante transferencia: ADMINISTRACIONES EUGENIO CANTERO. TLF. 927 22 37 06"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2024-07-15','Ana: En respueta a las peticiones en diversos correos de Azucena Merino, cuñada de Juanjo, le envío correo: "Tras consultarlo con la sección económica: 1- Se aprueba la SUBIDA DE 20€ más al mes para Juanjo. De modo que A PARTIR DEL MES DE AGOSTO podrá retirar 80€/mes para gastos de bolsillo. 2- Se aprueba también una pequeña subida en concepto de manutención, siendo a partir de agosto de 475€/mes 3- Solicitaremos a la Educadora del programa de apoyo comunitario que nos confirme la necesidad del mobiliario que solicitáis y le le acompañe a pedir presupuesto." ··············································································· Lo reenvío a Toni y Nieves, Futuex. ·································································································································································································· En relación al nuevo requerimiento de informes por parte del Juzgado, reenvío a Toni-Futuex, el correo remitido el 14/05/2024: "En relación a JUAN JOSÉ MASEDA DEL SOL, te reenvío el correo que te envié a mediados de mayo. Necesitamos por favor que nos envíes el Informe solicitado a la mayor brevedad. Pongo en copia a Maite y a su educadora de referencia."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2024-03-19','Ana: Correo de Toni-Futuex: "La cuñada de Juanjo sigue muy insistente en que no es suficiente con la compra del armario y que necesita que desde la CTAEX le ingresen más dinero por Juanjo, ya que es una persona muy demandante y siempre le pide mucho dinero para comprar sus cosas (refrescos, zumos, actividades de ocio...). Además de esto, según ella comenta, tiene un comportamiento bastante agresivo con toda la familia que convive en el domicilio, incluso con vecinos del barrio (con quienes a veces tiene discusiones y trifulcas por las que su familia debe dar la cara). Desde el equipo no hemos constatado estas conductas, en nuestra presencia nunca. Lo que quieren principalmente es que se agilice el ingreso en un centro, a pesar de que se le explica, que al rechazarlo el proceso que esta en marcha pero tardará.. y mientras tanto le suban la asignación que le dan a ella por estar al cargo de Juanjo (o así lo comunica ella). Los mensajes a la educadora sobre estos temas son constantes (diarios), por ello se traslada esta información a la CTAEX y se solicita, si es posible, que os pongais contacto con ella para que puedan explicarle las posibilidades economicas con las que cuenta el tutelado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='GARCIA'and apellido2='MORENO'),'2024-07-11','Ana: Conversación con Mamen, Ed. Futuex (663 85 17 69): confirmo que no tiene reconodido grado de discapacidad, por lo que no puede ser usuaria del PADDI (Unidad de Salud Bucodental para Personas con Discapacidad). ·········· Por indicación de la Nefróloga, tiene que extraerse las piezas dentarias antes de comenzar con la diálisis. *Las extracciones las cubre igualmente la Seg. Soc. ···· Ya han comenzado a extraerle 2 piezas/semana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2024-07-15','Ana: Llamada de Sheila, Directora Técnica del CRR (676 682 793): le han comunicado a última hora desde el ESM, que Juan Mario ingresa en el CSS - Plas. este miércoles día 17. No le han especificaco en qué unidad. ···················· Acordamos que el traslado se hará en taxi, pues tiene que llevar maletas. Lo gestionarán ellas. Enviarán la factura después. ··········· A él aún no se lo han comunicado. Se lo dirán mañana. ··············· *Mañana hablaré con Eva o Raquel, de la secc. de acceso a recursos de salud mental, pues no sabemos si ellas están al corriente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MONTAÑA'and edp.apellido1='GONZALEZ'and apellido2='ROLO'),'2024-07-15','Ana: Envío correo a Mamen, Ed. Futuex: "me confirman una compañera de la sección económica que no le han hecho aún ningún ingreso de 300€ para ropa y calzado que me dijiste. Le he pedido que por favor, lo mire de vez en cuando y no aviste cuando le hagan el ingreso para poder hacer la autorización de retirada de efectivo al tal fin y que vaya contigo a retirarlo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MONTAÑA'and edp.apellido1='GONZALEZ'and apellido2='ROLO'),'2024-07-11','Ana: Conversación con Mamen, Ed. Futuex (663 85 17 59): me comunica que a Montaña le han concedido una subvención de 300€ para ropa y calzado. No sabe cuándo se lo ingresarán. Acordamos que llegado el momento ella acompañará a Montaña a retirar el dinero y a comprar, pues debe presentar las facturas como justificación. ······························· Por otra parte, le envió a Toni, Coordinadora Futuex un presupuesto de Tapa de WC que aún no hemos recibido. ········ Montaña quiere irse pronto a vivir a su piso de nuevo y le falta la tapa en el baño..','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='INOCENCIO'and edp.apellido1='MARTINEZ'and apellido2='NOVAS'),'2024-07-16','miguel, Tere me envía del centro carta de seguro de deceso de mapfre que no indica el tutelado ni el fallecido. Tras consulta al expte veo se llama de segundo Novas y no Novoa como aparece aqui en la intranet. Contesto a Tere para que averigue a quién se refiere el fallecimiento y que le manden la documentación que haya de testamentaria (certificado de defunción, etc)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='ALCANTARA'),'2024-07-16','Ana: Envío a Sonia Bernabé, AUTORIZACIÓN para la SALIDA al Hotel Rural Duende del Chafaril, en San Martín de Trevejo del 16 al 19 de julio. La aportación ecca. es de 350€ para los gastos de alojamiento y gastos personales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2024-07-16','Ana: Envío a Sonia Bernabé, AUTORIZACIÓN para la SALIDA al Hotel Rural Duende del Chafaril, en San Martín de Trevejo del 16 al 19 de julio. La aportación ecca. es de 350€ para los gastos de alojamiento y gastos personales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='JIMENEZ'and apellido2='PICON'),'2024-07-16','Ana: Guardo en el expte. digital en PDF, el correo de Toni-Futuex, con la incidencia acaecida con Carmen, sobrina de María en la Res. Parque del Príncipe. ················· *La educadora de referencia es Mamen. ···························· Reenvío el correo a los A. Jurídicos y a Maite. ·········· Tendremos que acordar modo de actuar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOLORES'and edp.apellido1='MARAVER'and apellido2='NORIEGA'),'2024-07-12','TERESA El viernes pasado estuvieron familiares de Dolores hablando conmigo para hacerme llegar el deterioro tan rápido que está teniendo. Por fotos que me enseñaron la verdad que en pocos meses se aprecia un que ha dado un bajón importante. ¿ hay alguna causa que justifique este deterioro? ¿ La ha visto el médico en estos últimos meses para valorar este deterioro? También me comento que en al última salida cuando llego a casa iba con una bronquitis bastante importante y que el centro no la había llevado al médico y que apenas lleva ropa y además un camisón que no era suyo. En general da una impresión de desatención hacia Dolores. Ya me cuentas como está para poder hablar con la familia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOLORES'and edp.apellido1='MARAVER'and apellido2='NORIEGA'),'2024-07-15','TERESA Pues sé que el director (Florencio Tena) ha hablado con su sobrina el miércoles o jueves y le ha pasado los informes médicos que tiene desde marzo en relación a la bronquitis. En cuanto al deterioro, a nivel cognitivo y motor, Mª Dolores está como siempre. Ha estado haciendo mucho ejercicio con la fisioterapeuta, ya que el gusta mucho hacerlo. A nivel cognitivo no se aprecia mayor deterioro que el esperable por su discapacidad y enfermedad mental. No sé a qué se debe esta queja, ya que su familia no pasa el tiempo suficiente con ella como para valorarlo. Del camisón, no sé. Normalmente en verano, para estar más cómoda suele estar con un vestido fresco. Dudo mucho que la cuidadora que le preparó la ropa fuese descuidada en ello. Si llevaba poca ropa es porque no avisan con suficiente antelación como para que la cuidadora le prepare una maleta (llamaron a las 8 y algo y se la llevaron a las 12) y tampoco especifican el tiempo que se la llevan (por lo general, en dos día está de vuelta). Espero haber podido aclarar las dudas. Cualquier cosa que necesitéis podéis solicitárnoslo . Mª Dolores puede ser visitada en cualquier momento por la CTA si lo creéis oportuno.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='COLCHON'and apellido2='CARMONA'),'2024-07-16','TERESA Me ha llamado la policía local de Almendralejo pues ha sido avisada por la comunidad de vecinos ya que estaban preocupados porque ayer vieron llegar en malas condiciones a Bartolomé y no lo han vuelto a ver. Ha ido esta mañana el auxiliar de ayuda a domicilio y no le abre la puerta Se ha personado la policía y ha entrado en la vivienda con una llave que tiene una vecina, en el domicilio no hay nadie y refiere haber restos de sangre en varias habitaciones como si se hubiera hecho una herida. Entiendo que habrá que ponerlo en conocimiento del juzgado pues ahora mismo no sabemos donde se encuentra ni en qué estado FUTUEX El ultimo seguimiento fue el dos de julio, que estaba todo bien, de hecho estaba interesado en pedir un presupuesto de unas gafas de sol (que no hemos enviado aun porque le dijeron el precio en la tienda pero aun no habian dado el presupuesto) pero vamos estaba todo dentro de la normalidad. La compañera que lo ve, no esta estos dias por ingreso de un familiar, pero intentaremos a ver si con alguna otra persona del equipo averiguamos algo más,ya he leido tambien lo de la policia y que ahora mismo no sabemos nada de donde está.. Supongo que los tenéis pero pasamos los teléfonos de contacto que tenemos : Teléfonos de contacto: • Bartolomé: 673 48 60 21 • Antonia Morán (trabajadora social, SSB): 924 67 05 07 • Servicios Sociosanitarios San Judas, María (empresa ayuda domicilio): 605 87 42 32 • Elkin (auxiliar de ayuda a domicilio): 669 35 03 53 • Cati (vecina de Barto): 675 81 49 37 • Administrativa salud mental Almendralejo: 924 66 03 54 • FEAFES Almendralejo: 924 66 46 77, personas de referencia: Laura (orientadora laboral) y Elena (trabajadora social).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2024-07-16','Ana: Estrella, TS CSS - Plas. (estrella.duranc@salud-juntaex.es): nos comunica que Eugenia ha ingresado en UME. ················· La demanda de empleo, si le toca renovarla ahora, tendrá que comunicar en el SEXPE el cambio temporal de residencia por motivos de salud. ······ Si Eugenia no tiene el justificante en papel lo solicitará a la residencia de mayores. ······························································································································································································ Envío correo a Toni y Clara, Futuex: "Sólo comunicaros el ingreso a día de hoy en UME de Eugenia Pacheco Vicente, por favor, retomar su seguimiento y apoyos en dicho centro. Entendemos que en unos meses, cuando se estabilice a nivel psicopatológico, podrá retornar a la Residencia de Hervás." ···························································································································································································· Envío correo a la Secc. Ecca: "Os comunico que EUGENIA PACHECO VICENTE ha ingresado en la Unidad de Media Estancia del Centro Sociosanitario. Por tanto, hay que enviar NUEVA AUTORIZACIÓN GENERAL AL BANCO y al C. Sociosanitario, para que puedan retirar su asignación. *Ella tiene autorizado 20€/semana para gastos de bolsillo, pero tendréis que calcular por las 52 semanas anuales, para que lo saquen en una única retirada mensual. *Recordad que en la Autorización debéis especificar: - Nº de cuenta - Cuantía"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2024-07-16','Ana: Tras hablar con Sheila, Directora CRR (676 682 793 / crr@grupociudadjardin.com): le envío correo a ella con copia a Raquel Gómez (raquel.gomeza@salud-juntaex.es): "Tal y como hemos acordado te reenvío el correo de la Psiquiatra de referencia comunicando la cancelación de la subcomisión por derivación a UME. Pongo en copia a Raquel, Sección de Acceso a Recursos de Salud Mental, para solicitar que no le den de baja hasta que no esté valorada y confirmada la derivación a Larga Estancia (subrayo en amarillo en el hilo)." ············································ *Juan Mario ingresará mañana antes de las 13:30 h.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2024-07-16','Ana: Correo de Estrella Durán, TS CSS Plas. (estrella.duranc@salud-juntaex.es): "Julia Morón está demandado que venga de nuevo Clara, a comprar con ella una radio, cepillo y pasta de dientes...." ··································· Mi respuesta: "Si crees que Julia puedes asumir la compra con su asignación para gastos de bolsillo (de este mes o el próximo), no hay ningún problema. Pongo en copia a la coordinadora de Futuex para que le acompañe cuando pueda volver a visitarla. Si por el contrario, para la radio, necesitase un extra, que le acompañe igualmente a pedir presupuesto para que lo valoren en la sección económica. Ya sabes que la situación económica de Julia no es buena y sería conveniente ahorrarle algo de dinero." ········································· Respuesta de Estrella: "Sí, tiene dinero todavía de los 250 euros que se extrajeron para gastos extras." ············································· Reenvío a Toni-Futuex. ·············· Toni confirma que tenía programado acudir mañana. Le acompañarán a comprar lo que necesita y demanda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2024-07-17','Ana: Correo de ayer por la tarde de Sheila, Directora CRR (crr@grupociudadjardin.com): "Era para informarte de que volví a hablar con la UME sobre la persona usuaria JUAN MARIO SAN ROMAN BLASCO; no nos hacen informe ni documento de aceptación de plaza. Me refieren que con "acuerdos verbales" es suficiente, al ser derivación directa por su psiquiatra de referencia. Por otro lado, se concreta que dada la premura del aviso, se hará el traslado el jueves, por facilitar la organización, por lo que si te parece bien, podemos concertar la llamada pendiente para informar a Juan Mario a las 10:00." ······································· Llamo al CRR, hablo con Juan Mario, la conversación va bien y se muestra contento con la llamada hasta que le informo de la decisión de Psiquiatría de que ingrese mañana en el CSS. Él no quiere ingresar allí y no quiere seguir hablando conmigo. ······················· Hablo despúés con Sheila, abordarán esta cuestión con él.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2024-07-17','Ana: Envío a Toni cita en Dermatología de Julia, especifico: "Adjunto la cita de Dermatología relativa a JULIA MORÓN HERNÁNDEZ. Por favor, confírmame si podréis cuadrar el acompañamiento en la agenda. La cita es el martes 6 de agosto a las 9:10 h."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='GUILLEN'and apellido2='LOBATO'),'2024-07-17','miguel, email de Tere: Hola Miguel Me ha dado este teléfono la compañera del Camp de Don Benito Juan Jose Mojena Lobato:626 23 62 77 Este hombre ha llamado a Magdalena para decirle que la cuenta por la que pasan los recibos de la vivienda esta casi sin saldo y pronto se pondrá en números rojos A ver si él te puede facilitar la información que necesitas ------------------------------------------------------------ mi contestación con copia a Alberto: Buenos días, Tere, pongo en copia a Alberto. He hablado con el primo Juan José Mogena Lobato 626236277, que me dice que hay una cuenta en Unicaja con 3 titulares nuestro Tutelado y dos tías más. Me dice que la vivienda de los padres en Carbajo (Cáceres) es el único inmueble que dejaron y que la cuenta por la que cargaban recibos de luz, no de ibi(no sabe donde lo cargaban) está apunto de quedarse a 0€. A nombre del tutelado catastralmente no tiene bienes a su nombre. Información que tenemos: libro de familia y certificados de defunción de los padres. Le pido mínimo referencia catastral de la vivienda (preguntara en ayto) Justificante de número de la cuenta y titulares, y como una de las tías falleció le pido lleve al banco ese certificado de defunción. La otra tía es la madre de este primo Juan José, que tiene 89 años. Ya le he dicho que tendremos que cambiar domiciliación de pagos que haya y que tendremos que cancelar esa cuenta lo antes posible, antes de que se quede a 0€ Le pido también los dni de los padres Fernanada Lobato Pintor y Bruno Guillen Mogena para intentar localizar la vivienda en catastro y registro de la propiedad. Una vez lo tengamos todo contrataremos una gestoría (tiene saldo suficiente en cuenta) para tramite liquidación de impuesto de sucesiones y herencia en juzgado, y una vez firmada solicitaremos tras contratar abogado y procurador la correspondiente aprobación de herencia y si la Ctaex lo entiende necesario solicitaríamos también la autorización judicial de venta. Le he dejado mi número de tlfno e email para me envíe lo que consiga, aunque dice que estará pocos días y me enviará lo que pueda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='CUENCA'and apellido2='SILVA'),'2024-07-17','Ana: Correo de Verónica, TS del CSS - Mérida (veronica.fernandezsa@salud-juntaex.es): "remito informe de José Cuenca Silva. Este señor ayer acudió a consulta médica de medicina interna en el hospital de Mérida. Está pendiente de que le citen para tres pruebas debido a la gravedad/ importancia de la posible patología. Para una de estas pruebas, EBUS, debe acudir acompañado de su representante legal al hospital. Por lo tanto, necesitamos que gestionéis muy urgentemente con la Doctora Laura Moya Ramírez este tema." ······································································ Respondo: "Informarte que la persona física que ostenta la representación legal es un cargo político y no acude a los hospitales ni a consultas médicas de ningún tipo. Los consentimientos informados para todas las pruebas se firmarán sin ningún problema. Y si necesita acompañamiento hospitalario, y económicamente puede asumirlo, se puede gestionar a través de empresa privada o a través de alguna persona de confianza con quién podáis contactar desde vuestro centro. Estos servicios se abonan a posteriori mediante transferencia y si es con empresa necesitamos que enviéis presupuesto previo a nombre de José a la atención de la sección económica a la siguiente dirección: ctutelar@salud-juntaex.es Por otra parte, si tienes el contacto directo de la Dra. Laura Moya Ramírez, por favor, facilítanoslo podremos llamarla para explicárselo. Ante cualquier cuestión no dudes en volver a contactar por esta misma vía o a través de teléfono." ····························································································································································································· Llamo al Serv. de Medicina Interna del Hospital de Mérida (81131), la Dra. Laura Moya Ramírez está ocupada. Le pasarán nota para que me devuelva la llamada. ······························ Recibo la llamada de la Dra. Laura Moya (684 003 821), le habían dicho que el tutor era el hermano, por eso pedía que le acompañase a la cita. ···· Acaban de enviar los CI a la TS del CSS, cuando nos lo envíen se los devolveremos firmados para que los lleven en mano el día de las pruebas. ································ *Desde el CSS confirman que lo acompañará a las pruebas personal del centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='IGNACIO'and edp.apellido1='RODRIGUEZ'and apellido2='ALCANTARA'),'2024-07-17','Ana: Correo de Sonia Bernabé, ASINDI (trabajosocial@asindi.e.telefonica.net) a la secc. ecca. y a mí: "os escribo para comunicaros que al trasladarnos que quieren ver a su hermano, hemos contactado con el hermano de Ignacio e Isabel Rodriguez Alcántara. Nos ha dicho que le gustaría verlos y si podría ser el día 20 de julio. Como en otras ocasiones hemos pedido presupuesto y nos dice el taxista que el coste total de llevarles hasta Plasencia y traerles sería 322,24 € (161,12 € cada servicio, es decir, ida y vuelta). Esperamos que se pueda autorizar el viaje para que pasen unas horas con su hermano, sobrina y cuñada en Plasencia." ·············································· *Tras hablarlo con Lourdes, S. Ecca., ésta envía correo a Sonia: "se acepta el presupuesto para que los hermanos Rodriguez Alcántara puedan ir a visitar a su familia. Una vez realizado el servicio de taxi, enviadnos factura y procedemos al pago. Se abona el desplazamiento desde la cuenta de Isabel." ······ Se hará así porque, al contrario que Ignacio, Isabel tiene balance económico positivo, pues ella cobra la PNC e Ignacio PFHC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='RODRIGUEZ'and apellido2='ALCANTARA'),'2024-07-17','Ana: Correo de Sonia Bernabé, ASINDI (trabajosocial@asindi.e.telefonica.net) a la secc. ecca. y a mí: "os escribo para comunicaros que al trasladarnos que quieren ver a su hermano, hemos contactado con el hermano de Ignacio e Isabel Rodriguez Alcántara. Nos ha dicho que le gustaría verlos y si podría ser el día 20 de julio. Como en otras ocasiones hemos pedido presupuesto y nos dice el taxista que el coste total de llevarles hasta Plasencia y traerles sería 322,24 € (161,12 € cada servicio, es decir, ida y vuelta). Esperamos que se pueda autorizar el viaje para que pasen unas horas con su hermano, sobrina y cuñada en Plasencia." ·············································· *Tras hablarlo con Lourdes, S. Ecca., ésta envía correo a Sonia: "se acepta el presupuesto para que los hermanos Rodriguez Alcántara puedan ir a visitar a su familia. Una vez realizado el servicio de taxi, enviadnos factura y procedemos al pago. Se abona el desplazamiento desde la cuenta de Isabel." ······ Se hará así porque, al contrario que Ignacio, Isabel tiene balance económico positivo, pues ella cobra la PNC e Ignacio PFHC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2024-07-16','Maite: he hablado con Alexandra de Plena Inclusión Cabeza del Buey. El ingreso fué tranquilo. El 112 la recogió en el centro ocupacional. Alexandra le explicó que tenia que ir a un centro pq no tiene donde alojarse , y el kuez lo autorizado. No se negó pero lloró. EL viaje hasta Fuente de Cantos lo hizo muy bien. Allí la esperabala educadora de FUTUEX , María. Fueron a comprar ropa y unh bikini pq por la tarde iban a la pisicina. También hablécon Rosa, directora de la residencia Fraco Asuar . Me dijo que estaba tranquila. Pregunta cuando puede ir de visita a casa . hemos acordado que de omento este fin de semana permanecerá en el centro. He enviado correo a la sección económica para uqe hagan cambio de oficina y se autorice la retirada de 20 e a la semana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA TERESA'and edp.apellido1='NEVADO'and apellido2='MARTIN'),'2024-07-17','Ana: Correo de Cristina Hdez, TS CSS-Plas (cristina.hernandezca@salud-juntaex.es): "Te comunico que este mes sacaremos 200€ extras para comprar ropa de verano para María Teresa Nevado Martín. Ella sale y elige su propia ropa en tiendas del centro. Una vez tengamos ticket y o facturas de la ropa te las mando."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2024-07-17','Ana: Correo de Cristina, Ed. Asoc. Vera (educadorasocial@asociacionvera.com): "Solicito aprobación de gastos de acompañamiento de Dña. Mª Antonia Bravo Patillas a Consulta médica para poner máquina de control de sueño al Hospital Quirón en la ciudad de Cáceres el miércoles 24 de julio, a esta cita no la podemos acompañar desde el centro porque no tenemos personal suficiente para realizar el acompañamiento. El coste del acompañamiento es de 60 € por el viaje y 10 € la hora. Cuando se realice acompañamiento se enviará Declaración Responsable de la persona que le acompaña con el número de cuenta para proceder al pago."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2024-07-17','Maite: he hablado con Manuela, jefa de sección de acceso a recursos de discapacidad para que le reservan la plaza de CO de momento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MANUEL'and edp.apellido1='CIEZAR'and apellido2='PLAZA'),'2024-07-17','Ana: subo al portafirmas digital la solicitud de REVISIÓN PIA para acceso a plaza pública en C. Residencial de Mayores.','2');
