insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EDUARDO RODRIGO'and edp.apellido1='RIVERA'and apellido2='TORIO'),'2024-07-17','Ana: Envío a Teresa, TS NOVAFORMA (trabajadorasocial.novaforma@gmail.com), la Aurorización para asistir al viaje a Chipiona del 29 de julio al 2 de agosto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='COLCHON'and apellido2='CARMONA'),'2024-07-17','TERESA Tenemos información sobre Bartolomé, que alomejor estais al tanto pero bueno, por si acaso te adelanto las averiguaciones, resumidas mientras elaboramos nota mas extensa. Hemos ido a salud mental de Almendralejo, por si le hubiera dado alguna crisis o alguna cosa, no hay psiquiatra pasa como en Zafra, pero el trabajador social si nos comunica que el dia 15 lo ven en urgencias en el centro de salud y presenta un traumatismo craneoencefalico, lo derivan al hospital. Al parecer, no se está poniendo el inyectable, ya que en Junio ha ido voluntariamente a la enfermera de salud mental y le han reprogramado las citas tanto de psiquiatria como de inyectable. Pero no consta cuando fue la ultima vez, a nosotros tampoco desde el equipo, ya que el es autonomo y en ocasiones, no nos permite apoyarle en las citas medicas. Hemos ido al hospital de Almendralejo, pero nos comentan que está en el de Mérida al no haber camas (y suponemos por las circunstancias de posible descompensación) lo mandaron al hospital de Mérida. Se ha considerado, ir al hospital de Mérida y la información que nos dan es que, ha tenido una crisis por el consumo de tóxicos, ha dado positivo entre otras cosas a cocaina. De ahi el golpe en la cabeza, se dio contra la mesilla creen, él no recuerda nada, ni como llegó al centro de salud ni al hospital. La psiquiatra dice que ahora mismo tiene un cuadro confusional y que el niega todo, niega los consumos, y que no se ponga la medicacion y todo. Por lo que ahora mismo tiene que estar alli para valoracion, en funcion de eso decidirán si derivarlo algun sitio o ver como va evolucionando. Está como desorientado y débil. Asique nada, intentaremos ir preguntando y yendo al hospital, el viernes cuando regrese la otra compañera. Y te vamos informando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='CANELADA'and apellido2='DEL RIO'),'2024-07-17','Ana: Respondo al correo de Sheila, Directora del CRR (crr@grupociudadjardin.com): "Sin problema, podemos solicitar la revisión del Grado de Dependencia, eso sí, como sabéis necesitamos el Informe de Salud para poder presentar la solicitud. Cuando nos lo hagáis llegar cumplimentaré y presentaré la solicitud para revisión por empeoramiento y revisión de PIA para optar a plaza residencial de mayores. En cuanto a la cuestión económica, ya lo he estado hablando con una de las compañeras de dicha sección. Mañana te darán respuesta."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2024-07-17','Ana: Correo de Ana, TS Fundación Autismo Sur (teayudamos@autismosur.es): "Tuvimos cita con el neurólogo privado, Dr Peña, y nos ha comentado que sería necesario hacerle una analítica con ciertos valores a Ale para ir descartando otros problemas de salud. Se lo comentamos a su médico de la Seguridad Social y como son unos valores muy específicos no se lo pueden realizar en el centro de Salud. Hemos buscado una clínica que realiza analíticas con esos valores, te envío presupuesto para que lo valoréis con la sección económica. Con respecto a Ale, está muy bien, bastante estable." ································································ Reenvío correo para valoración a la sección económica.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2024-07-17','Ana: Subo al portafirmas digital la ACEPTACIÓN PIA para el MANTENIMIENTO DEL SERVICIO de C.O. remitido por Manuel Andrés Casado, TO - EVD CC (manuel.casado@salud-juntaex.es)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2024-07-18','miguel, email de Toni de Futuex: Sobre Mª ELENA, el procedimiento de internamiento lo están gestionando en el juzgado de Llerena, no en el de Zafra. Comentaba que le aparece que tiene abiertos dos procedimientos, que se debe preguntar o llamar a Llerena. Ha facilitado los dos números para preguntar directamente: ITR 0000412/24 ITR 0000448/24 Nº de registro: 0000412/24','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='CARVAJAL'and apellido2='CORNEJO'),'2024-07-18','miguel, Tere reenvía email de Toni de Futuex: Sobre TOMÁS CARVAJAL, también se ha preguntado por la situación de su internamiento. Comentaba la mujer que ha atendido que el juez no está de acuerdo en entrar al domicilio porque considera que no es ningún "delicuente", que pueden cogerlo en otro momento por la calle y no tener que llegar a eso, (no sabemos como pretenderán hacerlo así, es inviable) Se le ha comentado la situación y que puede suponer un peligro, además de las cartas y amenazas a los profesionales que trabajan con él, a lo que han respondido simplemente que sí, que ya lo saben todo, que hablará con el juez a ver que considera. Pero vaya, si no hemos entendido mal, está paralizado porque el juzgado no considera hacer nada mas...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2024-07-18','Ana: Envío a Juan Carlos Cano, Aux. Adtvo (juancarlos.cano@salud-juntaex.es): "Adjunto ACEPTACIÓN PIA para MANTENIMIENTO DEL SERVICIO DE CENTRO OCUPACIONAL relativo a JUAN JOSÉ MASEDA DEL SOL para remitir por REGISTRO a: SEPAD GERENCIA TERRITORIAL DE CÁCERES Plaza Hernán Cortés, 1. CP: 10001 – Cáceres Código SIREX: A11030403"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOLORES'and edp.apellido1='MACARRO'and apellido2='CAMACHO'),'2024-07-18','TERESA Sobre Dolores Macarro, se le ha visitado recientemente y está muy bien, es espectacular el cambio desde que está en la residencia! Está cuidada y atendida que era lo que necesitaba, dice que está tan bien que no quiere volver a su casa. Comentaba la supervisora que su estancia temporal se termina en menos de 3 semanas y llegado ese momento tiene que irse..., sería una pena que tuviera que volver a su casa, volvería a las condiciones pésimas en las que estaba, además del tema de la electricidad que no se ha solucionado. Se ha intentado hablar con la TS por si podía informar de algo pero no ha sido posible porque está de vacaciones. comentamos esto para infomar y ver que se puede hacer, o el tramite necesario para hacer la estancia definitiva, si se pudiera PENDIENTE DE FIRMAR PIA PARA QUE LA PONGAN EN LA LISTA DE RESIDENCIA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2024-07-18','miguel, llamo al jzdo de Llerena y envío email a la parte social con copia a Toni de Futuex: Buenos días, he hablado con el juzgado de Llerena y me comentan que efectivamente ellos tramitaron el ITR 412/24 pero que ya está finalizado porque correspondía a mayo, fecha en la que estaba hospitalizada Elena en el Hospital de Llerena y el ITR 448/24 fue cuando se dío orden por ITR urgente del tralsado del hospital de Llerena al centro residencial casa Santiago Zafra es donde se encuentra ella actualmente, es así? Por tanto el jzdo de Zafra no se ha enterado porque posteriormente en Junio hemos solicitado por Lexnet al jzdo Decano de Zafra una nueva solicitud de internamiento involuntario, basado en la preocupación desde la parte social a que voluntariamente se fuera a casa. Entiendo que no lo van a tramitar porque ya se encuentra internada en dicho centro casa Santiago de Zafra de forma involuntaria, por que como digo fue por orden del jzdo de Llerena en procedimiento 448/24. Por lo tanto salvo que me digáis que está en su domicilio no insistiremos en el nuevo procedimiento de internamiento involuntario solicitado al juzgado Decano de Zafra (competente por ser donde actualmente reside Elena Duran)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2024-07-18','Ana: Correo de Sheila, Directora CRR (crr@grupociudadjardin.com): "Informar de que con Juan Mario San Román Blasco, por el momento, va a acudir al sociosanitario de forma voluntaria. Por tanto, se ha quedado con el taxista a las 12:00 para su traslado. Irá acompañado a Plasencia por un monitor. Por otro lado, se ha confirmado con el taxista que hará factura para que se lo abonéis desde la CTAEX. Os iremos informando de la evolución del proceso."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TEODORO'and edp.apellido1='MARTIN'and apellido2='SANCHEZ'),'2024-07-18','Ana: Javier, TS del CSS - Plas. (javier.rdguezper@salud-juntaex.es) dice haber llamado al CADEX y le han dicho que tiene reconocida discapacidad. En cambio no consta ni en nuestro expediente ni el suyo. ··················· Jaime, Aux Adtvo. Secc. Social enviará oficio al CADEX solicitándo el Cdo. y el Dictamen Técnico. ································································································································································································ Envío a Estrella, S. Ecca: "Te reenvío correo del compañero del C. Sociosanitario de Plasencia con presupuestos dentales (lee el hilo porfa, es un mismo presupuesto divido en dos) y dale ok cuando puedas a Javier (javier.rdguezper@salud-juntaex.es), yo creo que no tiene dificultades económicas y no le supone mucho gasto. Ya os coordináis vosotros para el abono." ···························································································································································································· Envío a Fco. Javier, TS CSS-Plas CI para anestesia y para tratamientos bucodentales (PROFILAXIS Y CURETAJES), debidamente firmado y sellado por la Representante Legal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MANUEL'and edp.apellido1='CIEZAR'and apellido2='PLAZA'),'2024-07-18','Ana: Remito a Juan Carlos Cano, Aux. Adtvo (juancarlos.cano@salud-juntaex.es) SOLICITUD DE REVISIÓN PIA, para remitir por registro a la Ud. de Acceso y Valoración de Dependencia.','2');
