insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2024-07-18','Ana: Envío a Javier Rodríguez, TS del CSS-Plas. (javier.rdguezper@salud-juntaex.es): "Adjunto: - Consentimiento Informado para Tratamiento Odontológico - Consentimiento para tratamiento de datos" ······························································································································································································· Envío correo a Estrella, Secc. Ecca: "Envío otro presupuesto de tratamiento odontológico relativo a JOSÉ LUIS MURILLO HORRILLO, creo que no hay problema, por mi parte, al igual que en otro caso, ok al mismo. Por favor, confírmale a JAVIER, TS del C. Sociosanitario (javier.rdguezper@salud-juntaex.es)"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='AYUSO'and apellido2='TENA'),'2024-07-18','Ana: A petición de Francisco Javier, TS del CSS, solicitaremos plaza en centro de mayores. En el equipo consideran que en un centro de mayores tendrá mejor cubiertas sus necesidades. ·································· Subo al portafirmas digital ACEPTACIONES PIA, para: 1. Mantenimiento de Plaza en CSS y 2. Solicitud Plaza Pública SAR Mayores.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='GARCIA'and apellido2='MORENO'),'2024-07-18','Ana: Guardo en el expediente digital la VIDA LABORAL de Abraham Mendo Gía, hijo de Pilar, que presentaremos al IMAS-CC, para adjuntarla a la solicitud de Caterin Municipal cuando nos la reclamen para subsanar. Cuando registramos la solicitud no la teníamos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2024-07-18','Ana: Envío a la Secc. Jurídica: "Os reenvío el INFORME solicitado al Programa de Apoyo Comunitario gestionado por Futuex, en base al convenio firmado entre esta entidad y la Consejería de Salud y Servicios Sociales de la Junta de Extremadura para remitir al Juzgado para la REVISIÓN DE LAS MEDIDAS JUDICIALES DE APOYO." ································································· *Guardo el informe en el Expte. Digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='COLCHON'and apellido2='CARMONA'),'2024-07-18','TERESA ENAIL ANTO TS SSAB ALMENDRALEJO Teresa, nos han comunicado que Bartolomé Colchón ha ingresado está mañana en UCI del hospital de Mérida, ha comenzado a convulsionar porque al parecer tiene un hematoma cerebral a consecuencia del traumatismo craneoencefalico. Su estado es bastante grave Nos han preguntado si tenia familiares o alguien a quien poder avisar o informar. A nosotros no nos consta, creemos que algun primo en Almendralejo pero no sabemos si tienen mucha relación. Mañana por la mañana a primera hora volveremos a preguntar por su estado. Esperemos que pueda remontar...','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FLORENCIA'and edp.apellido1='DAVILA'and apellido2='GARCIA'),'2024-07-19','Ana: envío a Lucía Román, Centro de Mayores de Santiago de Alcántara (luciaasoma.santiago@hotmail.com): "Adjunto AUTORIZACIÓN PARA LA ADMINISTRACIÓN DE LA VACUNA FRENTE AL NEUMOCOCO debidamente firmada y sellada por la representante legal"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2024-07-19','Ana: Conversación con Alberto,presidente de la comunidad de vecinos (927 00 14 83), hay problemas en varias viviendas, incluida la de Carlos, con la TV, no se vé. Acudirá un Técnico, avisarán el día antes a Carlos para que esté en casa. ··········· Hablo con Carlos al respecto, pues no quería que acudieran de ninguna empresa a su casa sin autorización por la CTAEx.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARCELO'and edp.apellido1='MANZANO'and apellido2='PEREZ'),'2024-07-19','Ana: escribo a la Res. Real de Navalmoral (direccion@residenciareal.com ): "En relación a Dº. MARCELO PÉREZ MANZANO, cuyo cargo ostenta la Comisión Tutelar de Adultos de Extremadura, y a instancia de mis compañeros Asesores Jurídicos, os solicito nos hagáis llegar a la mayor brevedad INFORME SOCIAL para aportar al Juzgado en el PROCEDIMIENTO DE REVISIÓN DE LAS MEDIDAS. Por favor, dado que en las próximas semana yo no estaré, enviadlo a la atención de la Sección Jurídica a la siguiente dirección: ctutelar@salud-juntaex.es"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2024-07-19','Ana: Llamada de Estrella Durán, TS CSS Plas (24146), ayer ingresó Juan Mario, por lo pronto todo bien. Le informo sobre lo tratado con Sheila, Directora del CRR y Raquel, U.G.PP.AA., sobre la necesidad de valoración de acceso a Larga Estancia y la no conveniencia de que regrese al CRR. ·········································································································································· A petición de Eva y Raquel, Secc. Acceso a RR Salud Mental (U.G.PP.AA.), escribo a ADMISIÓN del CSS - Plas (admision.cssplasencia@salud-juntaex.es): "Buenas tardes Juanjo y Fernando, Solicitaros que, cuando podáis, nos enviéis CERTIFCIADO DE INGRESO EN VUESTRO CENTRO relativo a JUAN MARIO SAN ROMÁN BLASCO."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2024-07-19','Ana: Conversación con Estrella Durán, TS CSS Plas. (24146): hablará con la Psiquiatra y con la Médica Somática para que nos faciliten, al menos Informe de Salud, para solicitar la REVISIÓN DEL GRADO DE DEPENDENCIA (dio sin grado) y así poder solicitar plaza en CRR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2024-07-19','Ana: Se autoriza compra de móvil (159 €), el suyo se ha estropeado y está incomunicado. ················· Lo comunico a Nieves, Ed. Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='BARROS'and apellido2='CORDERO'),'2024-07-19','Ana: Envío correo a Ana, TS SSASB (ssb@mancomunidadhurdes.org) y Marisa, Residencia Madre Fca. de Azabal (residenciamadrefranciscazabal@hotmail.com): "Me pongo en contacto de nuevo con vosotras en relación al INFORME SOCIAL solicitado a fecha de 26 de abril de 2024 (reenvío correo), para reiterar la necesidad de que nos enviéis dicho informe a la mayor brevedad para el procedimiento de REVISIÓN DE MEDIDAS DE APOYO. Puesto que en las dos próximas semanas yo no estaré, agradecería lo remitieseis directamente a la atención de la Sección Jurídica a la siguiente dirección: ctutelar@salud-juntaex.es"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2024-07-19','Ana: Tras hablar con Nieves, Ed. Futuex, envío correo a Alberto, Jefe S. Ecca. y al ctutelar@: "En relación a JESÚS MANUEL RAMOS BARGÓN, me informa Nieves, Ed. Futuex, que la lesión que tiene en el hombro es crónica, por una calcificación. Su MAP tiene intención de derivarle al REHABILITADOR. Dada su situación económica y que no es sostenible por mucho tiempo el extra semanal de 50€ para comida preparada, planteamos la posibilidad de aumentarle un poco su asignación periódica y dejar de darle a partir de agosto esos 50€ semanales añadidos. De modo que sea un gato que pueda soportar y le facilite un poco la situación. Ya me confirmáis a vuelta."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='JIMENEZ'and apellido2='PICON'),'2024-07-19','Ana: En relación al correo de ADMINISTRACIÓN del C.R. Parque del Principe (parquedelprincipe@grupociudadjardin.com), respondo: "El incidente nos lo comunicó la Trabajadora Social, Pilar Cerrillo (le pongo en copia), y puesto que la coordinadora del Programa Conveniado entre la Junta de Extremadura y Futuex y gestionado por esta última entidad aún no nos lo habían comunicado, le pedimos que nos informaran al respecto y así lo hicieron. Esperemos que no vuelvan a suceder este tipo de situaciones. Como sabéis, en atención a vuestro Reglamento de Régimen Interior, podréis tomar las medidas oportunas con cualquier persona que incumpla el mismo, suponemos que tenéis derecho de admisión. Esto es lo que nos ha transmitido Ángel, Asesor Jurídico del Gabinete Técnico de la CTAEx. Eso sí, queríamos pediros que, por favor, facilitéis el encuentro de Mamen, Educadora de dicho programa y Dª. María Jiménez Picón, en alguna estancia a parte o en momentos en los que no se encuentre Carmen en vuestro centro para que la intervención de Mamen con D.ª María no se encuentre comprometida y para evitar así mismo exponer a la Educadora a este tipo de trato por parte de la sobrina de la residente. Pongo también en copia a Mamen y a Maite, Jefa de Sección del Gabinete Técnico de la CTAEx para que estén al corriente. Ante cualquier otra cuestión, no dudéis en volver a contactar." ···················································· Su respueta: "Perfecto, ya he hablado con Mamen y las visitas serán a otro orario que su sobrina no puede aceder al centro, y por supuesto desde el centro se están tomando las medidas oportunas para hacerlo todo legal y correctamente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-07-19','Ana: Correo de Toni-Futuex: "Se ha gestionado la reserva de dos noches de hotel en Baños de Montemayor para José Manuel Romero Mediavilla, en el Hostal Rural el Molino, donde han preferido contactar directamente con la CTAEX a través del correo electrónico para enviar los datos necesarios para el pago de la reserva. (se les ha facilitado el correo de ctutelar) Se ha reservado para los días 31 de julio al 2 de agosto, de miércoles a viernes. Son dos noches con desayuno incluido, 104 eu por noche. Si se considera necesario , si se aprueba, que pudiera contar con dinero en efectivo para poder comer algo más por allí y desenvolverse. Se ha pensado que podrían ser unos 50 euros aproximadamente para los dos días, se traslada la propuesta para valoración." ············· Reenvío a la secc. ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='IGLESIAS'and apellido2='CALZAS'),'2024-07-19','Ana: Correo de Ángela Bueno, Directora de Asuntos Sociales - PLACEAT, al ctutelar@: "A LA ATENCIÓN DE LA SECCIÓN ECONÓMICA Buenos dias, informar que tenemos organizada unas vacaciones a la playa para el mes de septiembre, concretamente a Chipiona del 16 al 22 de septiembre, con un coste de 430€, y a la que María quiere ir. Preguntar si puede ser, que pueda afrontar el gasto, y de ser asi facilito el numero de cuenta de Placeat donde abonar el coste, es del Banco Santander ES06 004 900 59892511105485" ·································· Respondo a todos: "por mi parte si es vibale ok al viaje"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='AYUSO'and apellido2='TENA'),'2024-07-19','Ana: Envío a Juan Carlos Cano, Aux. Adtvo. (juancarlos.cano@salud-juntaex.es): "Te adjunto 2 ACEPTACIONE PIA distintas (1- Solicitud de Servicio de Atención Residencial // 2- Mantenimiento del Servicio), relativas ambas a Dª. ANTONIA AYUSO TENA, cuyo cargo ostenta la CATEx, para remitir por REGISTRO a la Sección de Dependencia de Plasencia: S.E.P.A.D. Sección de Dependencia V Ctra. de Cáceres s/n. 10600 PLASENCIA Código de registro SIREX: A11030404"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DESIDERIA'and edp.apellido1='BARBERO'and apellido2='BUENO'),'2024-07-19','Ana: Correo de Estrella Durán: "Te informo que Desi ha pasado a hospitalización parcial, vendrá los lunes, miércoles y viernes."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='COLCHON'and apellido2='CARMONA'),'2024-07-22','TERESA tras realizar seguimiento de evolución del estado de salud de Bartolomé Colchón, en la mañana de hoy, se acude a la UCI para saber el estado actual del tutelado. Nos comentan que se encuentra bajo un pronóstico grave. Ingresó en UCI por presentar convulsiones y episodios epilépticos constantes. Por lo que decidieron sedarle e inducirle el coma. Actualmente, se siguen manifestando esa actividad epiléptica. El doctor comenta que si se despierta del coma, podría tener lesiones cerebrales importantes. La educadora ha dado el teléfono de contacto por si cambiara la situación. Además, creemos importante tener información sobre su seguro de deceso si así lo consideráis, para que, en el caso de que desgraciadamente fallezca durante el fin de semana, se les pueda dar información, para que gestionen todo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2024-07-22','TERESA EMAIL ALEXANDRA CABEZA DEL BUEY Adjunto justificantes de faltas de asistencia de 2024, registro de entrega de dinero de 2024, justificante de envío de paquete (coste 28€), justificante de demanda de empleo con usuario y contraseña para renovar online la demanda (María Chaparro ya lo sabe y lo habrá comunicado al centro nuevo) y por último justificante del envío por Bizum de 181,35€ a María Chaparro en concepto de dinero de Marta, que era todo el dinero que teníamos aquí de ella. Aprovecho para comunicaros que Marta tenía cita en el juzgado de primera instancia e instrucción de Castuera nº1 para comparecencia a la semana que viene. Me he puesto en contacto con el Juzgado (Genaro) y he comunicado que se encuentra en Fuente de Cantos y en principio está todo solucionado y no tienen que comparecer nio hacer nada de momento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MESA'and apellido2='CANDIL'),'2024-07-22','miguel, Buenas tardes, me ha llamado de nuevo la trabajadora del Cam de Don Benito, de la que no teníamos datos, y que ha llamado a Eduardo, Secretaría, a nosotros, etc, y de la cuál por fin he conseguido la información que necesitamos. Se llama Beatriz Díaz 658782491. Dice que la denuncia, se la dio a Montse sobre noviembre del año pasado. A nosotros no nos ha llegado. Me confirma que el denunciado es Juan José Mesa Candil, del que me identifica ella el procedimiento DPA Diligencias Previas Abreviado nº 637/23 del juzgado de 1º instancia e instrucción nº3 de Don Benito. Según confirmó el otro día Maite con Soraya sigue en lista de espera en la UHDAC tras la orden de internamiento que tenemos de hace meses. He hablado con el juzgado y me dicen que están con las pesquisas con la denunciante Beatriz Diaz, que al producirse los hechos en el Cam quiere un abogado de abogacía, y al llamar tanto al SEPAD como a abogacía le dicen que tiene que ir precedido de una petición y que sea solicitada esa solicitud a abogacía por la Gerente Estrella. El juzgado me dice que no era necesario abogado al ser la perjudicada, no obstante parece ser que ella a día de hoy sigue asistida con el que le asignaron (dice Beatriz) de oficio, pero que después le han denegado, y ella todavía no ha renunciado a él, como paso previo a que pida el abogado de abogacía de la junta. El procedimiento a día de hoy está a la espera de terminar las pesquisas con la denunciante Beatriz, que tiene cita con el forense próximamente. Entiendo que la parte social debéis de hablar con Soraya, pues es posible que el juzgado nos pregunte porqué no ha sido internado ya en la UHDAC. Cuando el juzgado nos comunique este procedimiento le solicitaremos abogado de oficio a Juan José Mesa Candil.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MURILLO'and apellido2='ROMANO'),'2024-07-22','miguel, email de Sandra Sandra Sánchez >ssanchez@inteligencialimite.org> : Así es, la condena de prisión sigue estando suspendida. Juan José durante los próximos 2 años deberá asistir de forma obligatoria a terapia psicológica y psiquiatra y además todos los análisis del CEDEX deben mantenerse sin consumo de alcohol y estupefacientes. Cada 3 meses seguiremos remitiendo los informes de progresión al juzgado. El próximo será en el mes de septiembre. El abogado de Juan José explica que no debemos preocuparnos por este procedimiento, pues es una corrección puntual que no cambia la resolución de la sentencia. --------------------------------------------------------- Buenas tardes. Adjunto procedimiento abreviado emitido por el abogado de Juan José Murillo Romano. Es la corrección de un error en su sentencia pero no afecta en nada al resultado, ya que debe cumplir la misma pena.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2024-07-23','TERESA Teresa. Ildefonso ha agradecido a un vecino de Valencia del Ventoso en el día de hoy. El señor va hacia el hospital. Según me cuenta la alcaldesa no lleva herida, pero le ha dado un puño y lo ha a caído para atrás y van a verlo en el hospital al señor. Ildefonso se ha encerrado y casa. Ayer por la noche sobre las 2.30 de la madrugada estaba discutiendo con una antigua amiga/conocida de él. Con muchas voces. Ella comenta que no quiere relación con él, pero el insiste... Ildefonso ha dejado su perro a esta amiga,... Los vecinos de esta han llamado hoy al ayuntamiento por el escándalo de ellos discutiendo, el perro toda la noche en la casa ladrando... Cada día una cosa con él. Yo estoy de vacaciones. Pero mañana por la mañana podríamos hablar después de las 10. Mañana me dirá la guardia civil que pasa si hay alguna diligencia o que.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='DOMINGUEZ'and apellido2='MARTIN'),'2024-07-23','TERESA Decirte que me acaba de llamar el padre de Manuel, dice que le ha pedido el dinero que llevaba, unos 257 euros y no ha querido dárselo, refiere que se lo gasta en un par de días, le ha dicho que así no se va a quedar en su casa y se ha ido. El padre no sabe como contactar con vosotros porque no usa el correo electrónico y me ha dicho que, por favor, le llaméis. Su teléfono es 623247979, se llama también Manuel. Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='GUILLEN'and apellido2='LOBATO'),'2024-07-24','miguel, tras hablar ayer con el primo Juanjo y Unicaja de Valencia de Alcantara, éste me envía las dos cuentas a nombre del tutelado y los movimientos de cuenta Envío email a Alberto y Tere: Buenos días, a efectos de la tramitación de la herencia de los padres, y con la ayuda del primo que se persono en Unicaja de Valencia de Alcantara me comentan la existencia de dos cuentas en que aparece el tutelado, y veo que en una la tenéis de titulares con las otras dos tías, una de ellas fallecidas, la otra en vida con 89 años. La otra cuenta que está en Don Benito y no sé si está controlada. A efectos de cualquier cancelación de cuenta me dicen que os debéis dirigir a la oficina de Don Benito (aunque una de las cuentas esté en Valencia de Alcantara) Ya tengo en su carpeta de herencia la documentación enviada por su primo de las gestiones de localización de la vivienda cuyo catastro dejo en dicha carpeta, y que está a nombre de la madre al 100%, la madre fallece en 1995 y el padre en 1977 El problema está, según dice el primo, en que la cuenta en la que aparece con sus tías quedan menos de 200€, y para cancelarla tendrían que ser la madre viva de este primo Juanjo (de País Vasco), la otra tía fallecida (pero tiene creo 2 hijos) y nuestro tutelado. Me envían movimientos de la cuenta para lo veáis parte económica pues tiene domiciliado varios recibos y habría que tenerlos controlados si vamos a hacer la herencia…o se cancela o hay que poner dinero en ella… Al tener capacidad económica, vamos a delegar las gestiones de tramitación de herencia en alguna gestoría. -------------------------------------------------------- Francisco Javier Ocaña Calderón Valencia de Alcántara 927 580 547 fjocanac@unicaja.es "Buenos días. Según conversación telefónica, adjunto el IBAN de las 2 cuentas en vigor del cliente de referencia donde se detallan los números de cuenta y la titularidad de cada una de ellas. Así mismo, adjunto los movimientos de 1 año de ambas cuentas. Me acercan a la oficina el certificado de defunción de MARIA LOBATO PINTOR y lo adjunto a sus efectos. Por último, les comunico que todas las siguientes gestiones la deben realizar desde su oficina de Don Benito con correo electrónico buzon7108@unicaja.es Sin otro particular..." ----------------------------------------------------- Nuevo email a Alberto y Tere: Alberto, necesitaría saber qué cuentas puedan proceder de la madre… Tere, aunque la madre es la única titular de la vivienda, nos harán tramitar la herencia del padre, que ignoro si se tramitó en el pasado…A ver si te saben decir algo desde el centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO'and edp.apellido1='BLANCO'and apellido2='LUQUE'),'2024-07-24','-Comunicación desde ap.3 Buenos días. Ayer por la noche, prácticamente al finalizar el turno de la tarde, sobre las 21:50 horas, la profesional Isabel Barbero, cuidadora de residencia, sufrió una agresión a manos del usuario del servicio de RAE Diego Blanco Luque. La profesional le indicó al usuario que se tenía que duchar y éste respondió de forma agresiva cogiéndola por los pelos y arrastrándola por el salón. Tuvieron que intervenir varios trabajadores tanto del turno de tarde como del de noche, que acababan de llegar, para que la soltara. Se llamó al 112 y policía. Los médicos que acudieron, inyectaron Valiun 10 a Diego Blanco, pues consideraron que no le iban a hacer nada más en urgencias. También asistieron a la trabajadora agredida, que estaba con un ataque de ansiedad y dolorida. Hoy no acudirá al servicio de Centro ocupacional a la espera de ver como evoluciona en el día de hoy y se va a intentar hablar con su psiquiatra. ------------------------- Rectifico una información actualizada: Diego Blanco actualmente no está en revisiones de Salud Mental por lo que no tiene psicquiatra asignado; fue dado de alta en el servicio de psiquiatría por la estabilidad clínica y porque con la medicación que toma por parte de neurología no consideraban que le pudiese aportar mucho a nivel farmacologico. Se va a hablar con el psiquiatra que le llevaba, pues conoce su trayectoria y está al tanto de sus anteriores agresiones. --------------------- Disculpad, me comunica la enfermera que se ha liado con las altas y Diego Blanco actualmente si está en alta en Salud Mental, teniendo su próxima cita el 24 de septiembre. Se ha hablado con su psiquiatra hoy sobre lo ocurrido ayer y nos dice que, como ahora se va a casa unos días, si no hay alteración, se mantiene la cita para esa fecha, si vuelve a darse una alteración de conducta, en ese caso, que volvamos a contactarle para adelantar la cita. Él no muestra ningún tipo de arrepentimiento y eso es algo que nos preocupa, pues en otras ocasiones, cuando ha tenido alteración de conducta, después se ha mostrado arrepentido y triste. Os traslado, por otra parte, que la trabajadora ha estado en mutua y le han dado de baja médica, está magullada, con chichones en la cabeza y con ataques de ansiedad, pero nada grave que lamentar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='SERRANO'and apellido2='GARCIA'),'2024-07-24','-Amalia ; contesto email a Rosa , con respecto a tu solicitud de extra , te reenvío email de la Sección Económica , no tienes autorizado ningún extra . Un saludo. PROPUESTA INICIAL ECO: OTORGAR LIBRE DISPOSICIÓN A TUTELADA X IMPORTE DE 750 €/MES...A TRAVÉS DE REINTEGRO EN DOS PAGOS X 375 €/QUINCENA . NO ABONAR SUPERMERCADO.....LO ABONARIÁ TUTELADA DE LOS 750 €. SE AVISARÁ A SUPERMERCADO Y SE LES INFORMARÁ DE QUE NO SE LES ABONARÁ NADA X NINGÚN CONCEPTO. DEBEN COBRAR EN EFECTIVO DE LA TUTELADA. NO ABONAR NI UN SOLO EXTRA....TODO EXTRA (VETERINARIO, ROPA, COMIDA, CALZADO, OCIO...) LO ABONARÁ LA TUTELADA DE LOS 750 € RESTO: SEGUROS, IMPUESTOS, CONSUMOS, TELEFONIA (SE RECUERDA QUE SI EL IMPORTE SUPERA LOS 12 €/MES SE PROCEDERÁ A DEVOLUCIÓN SIN PREVIO AVISO), ESTÁ DOMICILIADO ÁREA ECO, COMPROBARÁ LA CUENTA Y SI APARECE CUALQUIER CARGO SIN AUTORIZACIÓN SE PROCEDERA A DEVOLUCIÓN SIN PREVIO AVISO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FAUS'and apellido2='LEMUS'),'2024-07-24','-Trasladado de Ctro. Penit. Cáceres al de Badajoz , solicito a S. eco nuevo cambio en la cuenta peculio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA REMEDIOS'and edp.apellido1='LOZANO'and apellido2='MUÑOZ'),'2024-07-25','-Amalia , han regulado su PNC , hay un cobro indebido de mil y pico que ya se ha abonado . Desde abril a Dic de 2024 la cuantía será de 143€ aproximadamente , compatible con el trabajo que finaliza en esa fecha.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REGINA'and edp.apellido1='REINA'and apellido2='LARA'),'2024-07-25','-Amalia :Ya se ha firmado la documentación para el ingreso , contrato y demás . Lo envió Tere al centro. Se va a ir de vacaciones con la familia de acogida para regresar el 1 de septiembre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANASTASIO'and edp.apellido1='VAQUERIZO'and apellido2='PIZARRO'),'2024-07-24','email de Eva eva maria gonzalez falcon >eva_barbara_2000@hotmail.com> Buenos dias, Rogaria se pusieran en contacto con nosotros, debido a que la vivienda vuelve a filtrar humedades a la nuestras, hace unos meses se lo comente, pero no hemos tenido noticia, hemos hablado con el albañil que lo hizo, y nos comentan que nos tenemos que poner en contacto con ustedes, rogaria la máxima urgencia, pues al final nuestra fachada es la mas perjudicada, y no tenemos porque sufrir dicha situación, me he comunicado también con Sonia, y me comenta que se estaba realizando un informe, del cual no tiene noticia, ni del estado de la situación, supongo que tendrán mi teléfono de contacto 629464556, rogaria se contactaran lo antes posible, ------------------------------------------------------- contestacion Tere Buenos días Voy a llamar al albañil ---------------------------------------------------- contestacion de Eva De acuerdo, adjunto el estado de la vivienda. ----------------------------------------------------- miguel, recibo email de Tere Esta vivienda se barajo la posibilidad de venta según veo en la intranet sabes algo ¿ tenemos de nuevo quejas por las humedades -------------------------------------------------------- mi contestacion Hola Tere, de este expte sólo sé que tuvo unas ejecuciones judiciales q se estaban abonando, pero nada de ninguna venta. Veo en la intranet apuntes tuyos pero no tengo emails para tramitar nada. Veo apuntes del año 22 que intercambié contigo y la hija de la vecina para presupuestos de reparación y aclaraciones de Oscar sobre los motivos por los que se dejó de pagar el seguro de hogar. Adjunto que a nombre de él no hay nada con lo que si hay algo a lo mejor es de padres, y claro habría que tramitar la herencia para lo cual alguien nos tendrá que remitir nota simple y/o certificado de catastro de quienes sean titulares de la vivienda ( a ver quién está pagando el IBI), certificado de defunción de titular, certificado de saldo bancario y movimientos de la cuenta del último año al fallecimiento del titular de la vivienda… No tiene hermanos?','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SATURNINO MIGUEL'and edp.apellido1='SALGADO'and apellido2='JIMENEZ'),'2024-07-25','-Remoción del cargo de la CTAEX a su hermano .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2024-07-26','miguel, email de la hna Belen: El legado se ha dado el dinero de las escrituras después hay que ir hacienda a la propiedad y al banco y luego te mandan una carta para a ver lo que hay que pagar pero eso se paga con la herencia de mi hermana cuando nos den el dinero también tenemos q... ---------------------------------------------------- Yo cuando quiera te mando las escrituras lo pague Llo en efectivo un saludo ------------------------------------------- Buenas tardes Miguel e mando el papel del notario que me dio de mi hermana yo le dije que te lo dijera y a mí no me dijeron nada lo tuve que pagar yo de mi dinero para que le dieran las escrituras y te voy a dar mi cuenta para que se me ponga de lo de ... ----------------------------------------- Miguel en la misma notaría dónde se ha hecho el legado llamas a la notaría y hables con la que cobra las escrituras yo si quieres te mando lo que hicimos por correo un cordial saludo yo lo pague en mano y me lo tendrais que mandar a mi banco yo tengo t... --------------------------------------------------- En la misma notaría lo he pagado yo de todamanetasv ----------------------------------- Mi contestación: Hola envíame lo que se firmó. Intento hablar con la notaria de virgen de guadalupe pero no cogen los tfnos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='RIVERA'and apellido2='DIEZ'),'2024-07-26','TERESA Te escribo referente a Loli Rivera, después de reunión de valoración de equipo, me plantean varias cuestiones para trasladaros: _ se observa un decaimiento y episodios de “despistes” con desorientación temporo-espacial, tendencia a la somnolencia por el día y vigilia por la noche,… por lo que se valora visita al neurólogo. Debido a las listas de espera que existen y que su médico actualmente está de vacaciones, se sugiere la posibilidad de pedir una cita por privado para no demorar la valoración. Sería posible? _ como sabéis el mes de agosto, los servicio diurnos paramos por vacaciones y eso va a afectar en la rutina diaria que Loli mantiene y nos preocupa que ambas cosas, interfieran en ese proceso que estamos observando… por lo tanto, se valora la posibilidad de contratar a una “auxiliar” por horas que haga un acompañamiento individualizado a Loli para salidas de ocio, pequeñas compras que ella viene realizando durante todo el año de productos de aseo y de alimentación,… sería viable??? _ retomando el tema de su piso… se valora que la vivienda necesita una limpieza general. Ella acude de vez en cuando para revisar sus pertenencias y estar un rato allí. Habría posibilidad de contratar por horas a alguien que haga esa tarea _Por último, nos encantaría poder TENER UNA REUNIÓN CON VOSOTRAS, tal y como hemos hablado en otras ocasiones, para hablar sobre el piso y la idea de futuro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='PEREZ'and apellido2='LIMA'),'2024-07-26','Amalia : ACLARACION PENSIONES Percibe 446€ PNC y 220€ P. Orfandad Simple. Hablo con PNC para hacer la consulta , PNC es compatible con P. Orfandad pero la PNC se ve disminuida , de ahí que en la mayoría de los casos sea más beneficioso pedirles PF y P. Orf.Como la P.Orf es poca cuantía le interesa más mantener la PNC aunque sea reducida pero son 14 pagas . Si la P. Orf fuese absoluta o con cuantía muy alta hay que valorarlo , pq en ese caso puede resultar más beneficiona la PFHC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='PEREZ'and apellido2='LIMA'),'2024-07-26','Amalia : ACLARACIÓN SOBRE EL CAMBIO DE DOMICILIO Este chico entra y sale del piso de Caritas en Badajoz muy a menudo , dependiendo de la demanda en el piso. Actualmente está en piso alquilado en C/ Fuerte , 13 , 2º b Me dicen que al estar curatelado , toda la documentacion se envia a la CTAEx , sería conveniente comunicar el camibo de domicilio actual , aunque la D. anual no tendrá problemas en llegar a la CTAEX .','2');
