insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2024-07-29','TERESA RECIBO LLAMADA DEL ILDEFONSO PARA DECIRME QUE LE HAN MULTADO POR TIRAR UNA LATA EN LA PLAZA DEL PUEBLO Y QUE NO TIENE DINERO PARA PAGARLA, LE DIGO QUE ME MANDE LA DENUNCIA. OLGA LA TS HA VUELTO HOY DE VACACIONES, VA HABLAR CON LA POLICIA PARA INFORMARSE DE COMO ESTAN LA COSAS POR EL PUEBLO CON RESPECTO A ILDELFONSO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MORA'and apellido2='GARCIA MORA'),'2024-07-29','TERESA LE DAN PLAZA EN LA RESIDENCIA LA SALUD DE VILLANUEVA INGRESA EL PROXIMO DIA UNO, PRECIO DE LA PLAZA 1250€ hacemos este mes como siempre le compro todo por mes y le cubro lo q necesite si sobra el dia uno se entrega en el centro pero sobra poco de su sobre solo tengo 15 eu hasta q cobre . Porque hay q pagarle el tlf entonces este mes su asignacion igual 900 le compro todo para un mes q el centro no tenga q comprarle nada y si hace falta lo hago yo como siempre con lo q sobra y luego al mes siguiente tu ya lo organizas tranquilamente y asi al centro no se lo complicanos. Yo le llevo a cobrar. Compro el tabaco del mes y lo entrego en el centro con lo q hay quedarle cada dia. Le llevo la medicación de como lo toma . Dejo mi tlf para cualquier duda o q me necesiten para algo. Le aporto los informe medicos y atiendo cualquier dudas q tengan. Que te parece? Como un mes mas como hacia con Juan carlos y ya al siguiente tu lo miras aun asi yo siempre estare por si me necesitas. A Juan carlos hay q pagar de la asignación de éste cobro 150 eu por q se paga a mes vencido, que lo hemos hablado ahora.','2');
