insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOBAL'and edp.apellido1='CASQUERO'and apellido2='GARCIA'),'2024-06-01','Amalia : Con esta fecha se va a vivir a un piso de alquiler con Gregorio Lopez Cabrera . Sin embargo ha seguido pagando la plaza en el centro , no se le ha dado de baja , el centro no lo ha comunicado?? lo hablo con S.discapacidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO DAVID'and edp.apellido1='REBANALES'and apellido2='NIETO'),'2024-07-30','2024/07/30 AMALIA/ALE/ALBERTO: CORREO ANTERIOR...NO ES VIABLE...AMALIA: TUTELADO AMENAZA A SU MADRE. SE DECIDE: DARLE TOTALIDAD PENSIÓN INCLUIDAS PAGAS EXTRAS. EXCEPTO EL ALQUILER VIVIENDA SOCIAL (25 €/MES) Y SEGURO DECESO (11 €/MES). COMUNICACIÓN A JUZGADO DE ESTA ACTUACIÓN Y SU JUSTIFICACIÓN. NUEVA ACTUACIÓN: ALE: REINTEGRO PUNTUAL PRESENCIAL SEMANA A SEMANA X 105 €/SEMANA ALE: MIENTRAS REINTEGRAMOS CONFORME A PUNTO ANTERIOR...INTENTAMOS AVERIGUAR CON EL B.SANTANDER LA OPCIÓN DE UTILIZAR ALGÚN TIPO DE MECANISMO (TARJETA PREPAGO, APP, OTROS) QUE PERMITA REALIZAR LOS REINTEGROS SIN QUE SEAN PRESENCIALES. IMPORTANTE: NO POSIBILIDAD DE MODIFICACIÓN LIMITACIÓN X TUTELADO + NO POSIBILIDAD DE ENDEUDAMIENTO DE NINGÚN TIPO + NO POSIBILIDAD UTILIZACIÓN PAGOS ONLINE','2');
