insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOBAL'and edp.apellido1='CASQUERO'and apellido2='GARCIA'),'2024-07-30','-Amalia . Desde el 1 de junio de 2024 se ha ido a vivir a un piso de alquiler con Gregorio Lopez en Badajoz. Percibe 1048€ de una nómina ( CEEmpleo ) No le han dado de baja el mes de junio y julio por los que se han abonado 1600€ que le tienen que devolver. Segunda ha sacado 2000€ por una deuda que tenía con el centro y le restan otros 1000€ . Nos tienen que justificar ese dinero . Para estar al día , el centro le debería ingresar 583€ No he podido contactar con el centro .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GREGORIO'and edp.apellido1='LOPEZ'and apellido2='CABRERA'),'2024-06-01','-Amalia . Deja la VT del CTro . la Luz y pasa a un piso de alquiler desde el día 1 de junio con Cristobal Casquero . Pagará 250€ por el alquiler . LLega la sentencia con la revisión le quitan todas las medidas de apoyo ya no está curatelado. El centro nos preguntó si él podía firmar la baja en la vivienda al no tener ya medidas de apoyo y lo firmó él .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2024-07-30','TERESA RECIBO CORREO DE MARISA TS DE VILLAFRANCA Esta mañana hemos estado en el domicilio de Adolfo : Charo, la compañera del centro de salud. El auxiliar de Ayuda a Domicilio, la educadora de Futuex y yo. Hemos intentado coordinarnos con Adolfo en relación a las actuaciones a realizar tanto en el domicilio como en su atención personal. De principio Adolfo ha accedido a: • ducharse cuando este el auxiliar y como mínimo cada 2 días. El auxiliar le facilitará la ropa limpia a ponerse. Toda vez esté duchado y con ropa limpia irá con él a una peluquería para cortarse el pelo y afeitarse. • va a facilitar el que semanalmente se cambie la ropa de cama. • a que se tire todo lo de la nevera y a comprar junto con la educadora o con el auxiliar un mínimo de productos de alimentación y en pocas cantidades para que no se estropee. • accede a que una empresa de limpieza arregle la habitación suya y la que era de su madre, al igual que la cocina. que se revise la ropa y se tire la que no sirva y la otra se lave y se ordene en el armario. • él se ha comprado hace una semana un ordenador de segunda mano y por ahora no haría falta comprar uno, pero si una pantalla ya que la que tiene es pequeña y antigua y él pasa muchas horas frente al ordenador. • se ha comprometido a aceptar la ayuda de la educadora y el auxiliar y dejarlos entrar en el domicilio • accede a que le pidan nuevamente cita en salud mental y a tomarse la medicación. Esperemos que podamos hacer lo acordado y que él responda. de principio voy a contactar con la empresa de limpieza y arreglos para que me den presupuesto. Ya os iré informando.','2');
