insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2024-07-31','-Email del CTro. penitenciario : Todos los meses le llegan 400€ y le pagan 80€ a la semana. Los meses de cuatro semanas gasta 320€ y los de cinco semanas los 400€, que por eso se piden, para que ninguna semana le falte. Eso genera un pequeño remanente los meses de cuatro semanas, pero nos viene bien para estas cosas. Te adjunto el extracto para que lo veas. Con el dinero que ahorra de esa semana de pico le compran alguna pequeña cosa que solicita , siempre piden autorización primero . Se le ha autorizado unos auriculares y una radio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CASTILLO'and edp.apellido1='SOLIS'and apellido2='MELENDEZ'),'2024-07-31','TOD@S: AMALIA INDICA (SEGURO QUE DESDE HACE TIEMPO), QUE PADRES TUTELADA ESTÁN FALLECIDOS...QUIZÁS DEBIERAMOS INICIAR LOS TRÁMITES DE LA HERENCIA. ÁREA JURÍDICA TIENE TRÁMITES INICIADOS A ESTE RESPECTA DE HACE BASTANTES AÑOS. ÁREA JURÍDICA: EN CASO DE QUE INICIEMOS ESTO, LA TUTELADA CUENTA CON RECURSOS SUFICIENTES COMO PARA CONTAR CON AYUDA EXTERNA..','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='VICHO'and apellido2='ALFONSO'),'2024-07-31','-Email , CTro penti. Alicante , lo vuelven a trasladar al de Sevilla. " Precisamente acabo de saber que ayer salió Alfonso Vicho trasladado al Hospital Psiquiátrico de Sevilla. Llegará en unos días. El teléfono de ese centro es: 95.561 66 66. Lo que no sé es cuánto tiempo se quedará allí. De momento el dinero que le hayáis mandado aquí se le transfiere a Sevilla. Ya tienes tú que quedar de acuerdo con las compañeras de allí sobre si cambiar o no la transferencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA TRINIDAD'and edp.apellido1='SAAVEDRA'and apellido2='PARRA'),'2024-07-31','TERESA TERE/ESTRELLA: ACABAN DE LLAMAR DE IBERCAJA BARCARROTA...SE HA PRESENTADO TUTELADA CON FACTURA X 1.815 € DE UNA EMPRESA DE ELECTRICIDAD PARA CARGO EN CUENTA...SE HA INFORMADO AL BANCO QUE NO SE PUEDE ACEPTAR DICHA FACTURA. • TERE: ENTENDEMOS QUE TAMPOCO HEMOS AUTORIZADO NADA DE ESTO? • TERE: NO SE VA A PROCEDER A ABONAR ESTA FACTURA SALVO QUE ACUERDES CON TUTELADA QUE SE LE VA A REDUCIR REINTEGRO EN DICHO IMPORTE, EN CÓMODOS PLAZOS. o EJEMPLO: ACTUALEMENTE TIENE REINTEGRO DE 275 €/QUINCENA (550 €/MES).  LE PODEMOS PASAR EL REINTEGRO A 450 €/MES...225 €/QUINCENA...Y CON LOS 100 € QUE BAJAMOS ABONAMOS LA DEUDA EN 18 MESES....PLANTEASELO!!!...ES UNA FORMA DE QUE ELLA SIENTA QUE SUS ACTOS REPERCUTEN EN SU DÍA A DÍA. ESTRELLA: HA AVERIGUADO QUE TUTELADA A CONTRATADO EN 02/2024 CON COFIDIS LA COMPRA DE LIBROS, COLCHÓN, ROBOT COCINA X 2.011 € • TERE NO AUTORIZÓ NADA, NI TIENE CONOCIMIENTO DE ESTE GASTO. • SE HAN DEVUELTO VARIOS RECIBOS. • ESTRELLA: VA A SEGUIR DEVOLVIENDO TODOS LOS RECIBOS Y HA COMUNICADO A COFIDIS LA SITUACIÓN DE TUTELADA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='ALBA'and apellido2='GRAGERA'),'2024-07-31','-Amalia , envio email a S. eco : Buenas , os detallo lo comentado con Reme , la TS del SSASB sobre las actuaciones pendientes con Bartolomé: -El vecino solicita permiso para tirar y hacer de nuevo y más alta la pared medianera que da con la casa de Bartó . Este es el presupuesto , él abonará la totalidad de la obra . He pedido que nos envíe un email en el que lo indique por escrito . No tenemos que abonar nada de esta obra . -Ayer pasé un email para abonar 151€ del tto. de desratización de la casa para que se gestione el abono. -El ayto . va a proceder a desescombrar el patio y nos pasará el pto. para que lo abonemos , hay riesgo de incendio y es obligatorio limpiarlo. Saludos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CASTILLO'and edp.apellido1='SOLIS'and apellido2='MELENDEZ'),'2024-07-31','-Amalia , quieren hacer gestiones del tramite de la herencia de los padres de Castillo . Piden información al respecto , les escribo lo siguiente: Cuando Castillo llegó a la CTAEX ya era huérfana absoluta De hecho , nosotros fuimos nombrados tutores por una remoción del cargo de su anterior tutor que fue un primo suyo. Desconozco las causas . De los padres no puedo aportar información alguna , mira en su expediente papel , quizás ahí encuentres alguna documentación del principio que te pueda ayudar. Hace mucho tiempo que fallecieron. Sus primos , sobre todo un tal Antonio , son los que le han ayudado con ese tipo de gestiones. De hecho , se opusieron cuando les dijo que se iba a casar con Ángel , ellos tenían la creencia de que cuando falte Castillo , las tierras , la casa ... de los padres pasarían a ellos . No estaban de acuerdo en las decisiones que ella misma tomaba para arreglar la casa de los padres o cuando solicitaba algo de dinero. Desconozco si Castillo ha hecho algún trámite de esa herencia o si existe algún testamento. Tiene una sentencia en la que nombran a la CTAEX curador sólo para periodos de crisis','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REGINA'and edp.apellido1='REINA'and apellido2='LARA'),'2024-07-31','-Amalia : Escribo a S. eco : os paso email del centro con la cantidad exacta que tiene que abonar del copago de la plaza mensual, 75% de la PNC. Del mes de julio , entiendo que hay que abonar la mitad , porque el ingreso es desde el 15 de julio . Me dicen que ellos trabajan con trasferencia permanente , poneros en contacto por email para que os faciliten los datos que necesitéis para ello. El reintegro mensual quedará pendiente a que regrese Regi , que está de vacaciones. Saludos','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REGINA'and edp.apellido1='REINA'and apellido2='LARA'),'2024-07-31','-Amalia : escribo a S. eco para que procedan a abonar el 75% de la PNC para la plaza . Del mes de julio será la mitad . El reintegro mensual lo dejamos para la vuelta de las vacaciones. Lo harán por transferencia pte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO DAVID'and edp.apellido1='REBANALES'and apellido2='NIETO'),'2024-07-31','-Amalia : hablo con Petra , ha acompañado al hijo a sacar los 100€ semanales. Están más tranquilos . Aparte , ella le da 8.50€ al día . Su sobrina sigue viviendo con ella desde hace 9 años.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FAUSTINA'and edp.apellido1='GORDO'and apellido2='MARTINEZ'),'2024-08-01','-Amalia : la han ingresado en H. G. Merida , sigue en CSS','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DIEGO MARIA'and edp.apellido1='SANCHEZ'and apellido2='SANTIAGO'),'2024-08-01','TERESA NUEVA SITUACION • REINTEGRO PERMANENTE (LUNES-VIERNES) X 500 €/MES - X RAQUEL GUERRERO GONZÁLEZ??? • REINTEGRO PERMANENTE (FIN SEMANA) X 320 €/MES - X RAQUEL GUERRERO GONZÁLEZ??? • TOTAL REINTEGROS PERMANENTES: 820 €/MES??? • REINTEGRO X ALIMENTACIÓN SE MANTIENE (434 €/MES)??? • AYUDA DOMICILIO SE MANTIENE (470 €/MES)??? • CONCLUSIÓN SÓLO NOS AHORRAMOS 60 €/MES (880-820)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2024-07-16','Ana: Correo de ayer de Toni-Futuex: "Se solicita el que se pueda pagar por transferencia a esta tienda con la que se suele trabajar, el abono del presupuesto solicitado hoy de urgencia para Francisco Cacho ya que lleva semanas incomunicado e ilocalizable puesto que vendió el móvil y no lo ha recuperado, tampoco ha hecho nada por contactar con la educadora de alguna manera. Desde el equipo de apoyo se ha procurado saber de él llamando a los recursos de emergencia social de la ciudad de Cáceres, donde confirmaron que estaba yendo al CES a dormir. Hace dos días la educadora se encontró con Francisco por la calle, él se alegro de verla y le avisó que en dos días iba a ponerse el inyectable a salud mental. Hoy mismo la educadora a acudido al centro para poder verle y hablar con él, le ha dicho que si quiere que se pida un presupuesto de un móvil, él dice que sí porque no quiere estar incomunicado, y se queda con él en un punto concreto a una hora el viernes de esta semana, día 2. Se adjunta presupuesto para valoración de la CTAEX, se ha quedado con él el viernes día 2 para que no pase mucho tiempo entre medias y se le olvide o no quiera ir al encuentro porque cambie de opinión, seria perfecto si tuvieramos alguna respuesta para este dia, puesto que si no, tememos volver a perder el contacto con el." ··············································· *Se autoriza la compra del móvil (129,90 €)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MAYORAL'and apellido2='PIZARRO'),'2024-08-01','Ana: Correo de Lourdes, S. Ecca., de ayer, a Alberto, Jefes Secc. y a mí: "He contactado con PEPE 656941560, presidente de la comunidad de vecinos. Explica que hay un pago mensual de 60,40€ de comunidad. El segundo pago de 19,93€ que desde este mes ha pasado a 20€ es una deuda muy antigua que tiene Joaquina, y que han decidido que se vaya pagando en muy poquita cantidad. Ahora mismo, en este mes de agosto este señor estará fuera, de vacaciones, va a pedir a la inmobiliaria que realiza las gestiones de estos pagos, que de momento lo paralicen, y en septiembre solicitará la cuentas exactas de lo que debe. Dice que nos volvamos a poner en contacto con él y vemos cómo podemos organizar los pagos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='SERRANO'and apellido2='TRANCON'),'2024-08-01','Ana: Correo de Cristina, Ed. Asoc. Vera (educadorasocial@asociacionvera.com) al ctutelar@ y a mí: "Adjunto Declaración Jurada del acompañamiento de D. Agustín Serrano Trancón por un importe de 45 €"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2024-08-01','Ana: Correo de Cristina, Ed. Asoc. Vera (educadorasocial@asociacionvera.com) al ctutelar@ y a mí: "Adjunto... Declaración Jurada del acompañamiento de Dña. Mª Antonia Bravo Patillas por un importe de 140 €."','2');
