insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2024-08-01','Ana: Lourdes, Secc. Ecca., envía autorización firmada para asistir a un viaje programado a la playa en Almería durante una semana en agosto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTHER'and edp.apellido1='GARCIA'and apellido2='MARTIN'),'2024-08-01','Ana: Correo de Felisa Custodio, TS CAMF del día 30/07: "Estimados compañeros/as, os adjunto citación que ha recibido hoy la residente, día 30 de julio, la cita era para el 26/07/24, a los efectos oportunos. Saludos." ·················· Aunque también lo ha enviado al ctutelar@, lo reenvío igualmente a los A. Jurídicos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2024-08-01','Ana: Envío correo a Cristina Hdez, TS URH (cristina.hernandezca@salud-juntaex.es): "En relación a tu correo de ayer, te reenvío el correo que me envió el martes Carmen, la hermana de Enrique. Independientemente de que deba abonar el gasto que ha realizado de agua, totalmente desproporcionado, máxime teniendo en cuenta los días que va de pase, queríamos proponeros la necesidad de replantear la conveniencia de los pases de salida. Por nuestra parte, dado el mal uso del agua que ha realizado en las últimas salidas entendemos que debe abordarse con él esta cuestión y que, como mínimo, deben restringirse sus salidas durante una temporada. Además, mientras no tenga agua en la vivienda tampoco debería ir. Con respecto a este último asunto, dado que el apartamento al que va lo construyó su abuelo en el terreno del domicilio familiar sin los permisos correspondientes, no pudieron darle de alta los suministros, por eso están enganchados al de la vivienda de la madre, no obstante ya he enviado consulta a los Asesores Jurídicos, para ver si hay alguna opción. Por otra parte, son varias ya las incidencias protagonizadas en distintas salidas a su casa y ésta es la última dificultad que estamos encontrando. Es notoria su dificultad de autocontrol en diversos aspectos y no acabamos de ver que tenga verdadera capacidad para vivir de forma independiente. Pongo en copia a Maite, Jefa de Sección y a las compañeras de Futuex para que estén al corriente. Ya nos transmitís que opináis al respecto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2024-07-30','Ana: Correo de Carmen, hermana de Enrique (maluker6@hotmail.com): "hoy nos ha llamado el Ayuntamiento de Valdeobispo para decirnos que ha llegado una factura de 1500 euros de agua, el único que usa el agua es nuestro hermano Enrique, como sabéis la casa que él disfruta en los permisos tiene el agua conectada al domicilio que era de nuestra madre. Sé por él que tiene puesto riego para el jardín suyo, vete a saber cómo lo tiene puesto... He llamado al Sociosanitario y he hablado con T.S. Cristina de la URA y la he informado que he mandado hoy al fontanero que corte la llave general del agua, que la vivienda familiar a partir de hoy 30 de julio de 2024 no tiene agua, para que si le dan permisos que sepan que no habrá agua. Estando mi madre viva pasó algo similar porque él se obsesiona con el riego y derrocha el agua, que además él no está pagando directamente. En agosto iré a buscar la factura y os la haré llegar para que por favor él la abone. Si quiere ir al apartamento tendrá que tramitarse un contador propio o alguna otra solución, Enrique carece de autocontrol y él miente, te dice que él no riega o que no hace tal cosa."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2024-08-01','Ana: Correo del martes 30/07 de Fátima, TS sustituta-vacaciones (fatima.martin@salud-juntaex.es): "Comunico que Eugenia Pacheco Vicente será dada de ALTA de la Unidad de Media Estancia del Centro Sociosanitario de Plasencia, el próximo 31 de Julio. Para su traslado de nuevo al Centro Residencial de Mayores de Hervás, he coordinado con la Dirección de dicho Centro, y con Clara de FUTUEX. Será trasladada en un vehículo privado (taxi) que ha sido gestionado desde la residencia. Posteriormente deberán enviar a C.T la factura."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MONTAÑA'and edp.apellido1='GONZALEZ'and apellido2='ROLO'),'2024-08-01','Ana: Tras hablarlo con Alberto, Jefe de la secc. ecca., le reenvío correo de Laura, TS IMAS (laura.dominguez@ayto-caceres.es): "te adjunto información sobre Montaña González Rolo, está pendiente del cobro de un ayuda de 300€, pero en tesorería sale que tiene deudas con el Ayto y en hacienda debe haber algo también. Lo he puesto también en conocimiento de Mamen (la educadora de futuex) habría que pagar o fraccionar esas deudas para poder cobrar la ayuda." ········ Le especifico: "...Será necesario hacer consultas y ver si Montaña puede asumir o al menos fraccionar el pago de la deudas pendientes." ···· *Pongo en copia a Laura, TS y a Mamen, Ed. Futuex. ································ *Alberto lo pasa a Estrella, para que haga las consultas pertinentes en Ayto. y Hacienda.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2024-08-01','Ana: Respuesta de la sección ecca. el 25/07: "Buenos días, se autoriza el presupuesto para la analítica de Alexandru. Enviad factura y numero de cuenta para abonar, una vez realizado la misma"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2024-08-01','Ana: Respueta de Alberto; Jefe S. Ecca., del día 25/07: "LOURDES: ABONAMOS LOS 50 € "ALIMENTACIÓN" PARA EL MES DE AGOSTO......A PARTIR DE AHÍ TENEMOS QUE FIJAR MODO ACTUACIÓN CON ANA. ANA: LO HEMOS VISTO LOURDES Y YO...LA FICHA SE ACABA DE HACER X SI QUIERES VER SUS GASTOS FIJOS: ALQUILER, CONSUMOS, TELEFONO, MANUTENCIÓN HIJOS, GUITARRA (AHORA NO LA ABONA, PERO LLEVA MUCHOS AÑOS CON ESTO, ASÍ QUE LO RETOMARÁ), OTROS. VARIOS: • LA COSTUMBRE ES DARLE 2 EXTRAS AÑO.....EN PRINCIPIO MANTENDRÍAMOS ESTO • 375 € VERANO • 375 € INVIERNO • REINTEGRO PERMANENTE ACTUAL: 75 €/SEMANA (325 €/MES) • EL MÁXIMO QUE PODRÍAMOS SUBIR ES A 95 €/SEMANA (412 €/MES)  DE ESTA FORMA PODRIAMOS MANTENER LOS EXTRAS DE VERANO E INVIERNO.  NO HABRÍA NI UN EXTRA MÁS....ESTO TIENE QUE QUEDAR MUY, MUY CLARO.  EL AHORRO SERÍA INFERIOR A UNA SOLA PAGA EXTRA: 780 €/AÑO." ············································· Respondo: "Por mi parte ok a todo. Continuamos el mes de agosto tal cual y con los cambios planteados a partir de mes de SEPTIEMBRE. Pongo en copia a Nieves, Educadora de Futuex, para que esté al corriente y pueda informar a Jesús Manuel y dejarle claras las condiciones."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='IGLESIAS'and apellido2='CALZAS'),'2024-08-01','Ana: Correos respuesta de Alberto (29/07): "LOURDES/ANA: PREVIO AUTORIZACIÓN VACACIONES: • ES LA PRIMERA VEZ QUE PAGARIAMOS VACACIONES X ESTE IMPORTE. • SI SE ABONAN, CON LOS GASTOS QUE TIENE, EL BALANCE SERÍA NEGATIVO...SÓLO TIENE SALDO DE 6.000 €/APROX....EN MI OPINIÓN NO DEBERIAMOS, SALVO QUE RECORTEN DE OTRAS COSAS. • DUDA ANA/LOURDES: o LE ESTÁN PASANDO TODOS LOS MESES: o PRECIO CENTRO: 542,25 € o CUOTA "FUNDACION 427231 76112640M": 50 €/MES....ANA: ESTO SE PUEDE ELIMINAR O TRAE CUENTA MANTENERLO." ···················· "DADO QUE TIENE UN INGRESO: Valor Observaciones Importe 31/08/2023 CENTRO ESPECIAL DE EMPLEO "PLA 600 LOURDES: HABLAS CON CENTRO Y LE INDICAS QUE PODRÍA IR DE VACACIONES CON CARGO A ESTE COBRO, PERO QUE EN AÑOS POSTERIORES NO PODRÁ SER SALVO QUE TENGA INGRESOS SIMILARES. ANA: XFA, LO QUE VIENE EN EL CORREO ANTERIOR SI QUE HAY QUE VERLO...SI MERECE LA PENA MANTENER LOS 50 €/MES DE SOCIO." ··································································································································································································· Envío correo a Ángela Bueno, Placeat (directora@placeat.org): "En relación a Mª ROSA IGLESIAS CALZAS, me plantean desde la sección económica, dados sus escasos ingresos, si es realmente necesario abonar la cuota mensual de socios. Así pues, os solicitamos nos detalléis por escrito la finalidad de dicha cuota y los beneficios específicos que le supone abonarla."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2024-08-01','Ana: Correo respuesta de Alberto, Jefe S. Ecca.: "ANA: OJO! YO NO TENGO UNA SOLUCIÓN...PERO COMO VAMOS A DAR DE ALTA LOS SUMINISTROS???...ESTAMOS VIENDO LA IMPOSIBILIDAD DE AUTOCONTROL DE ESTA PERSONA...ESO SUPONDRÍA QUE CADA PERMISO HABRÍA QUE ABONAR 1.500 €....VALE, A SU NOMBRE Y TODO CORRECTO, PERO 1.500 € DE CONSUMOS???...ESTO NO ES VIABLE!!! ANA: SALE MÁS ECO QUE EN LOS PERMISOS SE VAYA A LA PLAYA...ALLÍ HAY UN MONTÓN DE AGUA GRATIS. PAGO FACTURA AGUA UNA VEZ RECIBIDA: SI ÁREA JURÍDICA NO TIENE INCONVENIENTE EN EL PAGO DE ESTA FACTURA YO PIENSO LO MISMO QUE ANA...DEBERÍA ABONAR FACTURA Y PUEDE HACERLO. ANA: SI AREA JURÍDICA NO PONE INCONVENIENTE AL PAGO DE ESTA FACTURA EN CONCRETO, SE LA PASAS A MARÍA. MARÍA: ABONAMOS ESTA FACTURA CUANDO ANA TE LA PASE. OPINIÓN: NO CREO QUE DEBAMOS DE DAR DE ALTA SUMINISTROS DE UNA PERSONA QUE DEMUESTRA SU INCAPACIDAD DE AUTOCONTROL...QUIZÁS SE PUEDA COMUNICAR AL JUZGADO QUE NO DA ESE ALTA X ESE MOTIVO"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MORA'and apellido2='GARCIA MORA'),'2024-08-01','TERESA INGRESA EN RESINDENCIA LA SALUD DE VILLANUEVA DE LA SERENA PRECIO PLAZA 1250€7MES QUEDO PENDIENTE PEDIR REVISION DE GRADO EN UN AÑO A VER SI DA GRADO II Y LE PUEDO PEDIR PLAZA PUBLCIA QUEDA EN LISTA DE ESPERA VIA DECRETO EN LA FELIPE TRIGO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2024-08-02','Ana: Respondo al correo de Fátima, TS de CSS, en sustitución de Estrella (fatima.martin@salud-juntaex.es): "En relación a tus consultas, ya lo hablé yo con Estrella antes de nuestras vacaciones: - Con respecto a Julia Morón Hernández, desde el Equipo de Salud Mental de Coria, le solicitaron plaza en CRR por emergencia social en noviembre de 2023, pues no tiene grado de dependencia, pero dado que cambió la normativa, le denegaron por no tener grado de dependencia reconocido. *Lo que acordé con Estrella Durán es que hablaría con la Psiquiatra y con la Médica Somática para que nos faciliten, al menos, Informe de Salud, para solicitar la REVISIÓN DEL GRADO DE DEPENDENCIA (cuando se le valoró dio sin grado)."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TEODORO'and edp.apellido1='MARTIN'and apellido2='SANCHEZ'),'2024-08-02','Ana: Correo de Jaime, Aux. Adtvo. CTAEx, a Javier, TS CSS Plas.: "Te envío el certificado de discapacidad y el dictamen técnico facultativo de Teodoro Martín Sánchez. Adjunto PDF."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2024-08-02','Ana: envío correo a Toni y Mamen, Ed. Futuex: "Os reenvío correo del Equipo de Salud Mental con nueva cita de Psiquiatría para CARLOS GLEZ. LEO el próximo jueves 22 de agosto de 2024 a las 9:10 h, para que organicéis su acompañamiento." ······························································································································································································· Correos respuestas de Alberto: "ESTRELLA: MODIFICAMOS EL REINTEGRO PERMANENTE EN CUANTO TE INCORPORES DE VACACIONES...PASA A 60 €/SEMANA (260 €/MES)....ANTERIOR 95 €/SEM (412 €/MES). EN CUANTO LO TENGAS LISTO AVISAS A ANA PARA QUE AVISTE A TUTELADO." ············ "ESTRELLA: ABONAMOS FACTURA ARREGLO ANTENA TV 223,85 €...AVISA A ANA CUANDO ESTÉ HECHO, XFA."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='COLCHON'and apellido2='CARMONA'),'2024-08-02','TERESA Buenas, se comunica actualización de la situación sanitaria d Bartolomé Tras realizar seguimiento a Bartolomé Colchón en el hospital de Mérida, y tras los últimos hechos acontecidos, se combina por parte de los médicos la necesidad de que Barto, ingrese en un recurso residencial, al menos hasta que sepamos cuáles van a ser sus secuelas finales. Actualmente ya no está UCI, pero de momento, no puede caminar, y sus necesidades básicas no podrán ser cubiertas en su domicilio tal y como lo hacía antes. El doctor, nos afirma que si se mantiene tal y como está hoy, en breve podrían darle el alta. Tras esta información se gestiona con la trabajadora social del hospital los posibles recursos para el caso de Bartolomé. Hay dos opciones: 1: Solicitar una plaza sociosanitaria de emergencia. Para ello necesita llegar a una puntuación 20. Test que pasa la enfermera a Barto y una serie de documentación que ya la educadora de zona de Mérida ha enviado (dni, tarjeta sanitaria y un informe sobre Bartolomé). 2: Traslado al hospital rivera de Almendralejo. En esta opción no es necesario pasar ningún Baremo. Creemos q lo gestionaría la ts del hospital Habiendo obtenido toda la información la trabajadora social, estamos a la espera de cuál será la opción más recomendable para el tutelado. A sabiendas que esto serán puntual hasta que veamos las secuelas que le quedarán. Además, añadir que aún no tenemos informes médicos de su situación actual. Cuando lo tengamos, lo enviaremos para ampliar la información. La trabajadora social del hospital de merida, Gemma, está al tanto de todo y podrá ampliaros la información La compañera del programa estará al tanto e iremos informando tb','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2024-08-01','Ana: Correo del día 29/07 de Alberto, Jefe S. Ecca., con copia a Estrella: "ACABO DE ACTUALIZAR LA FICHA Y ES INSOSTENIBLE...REINTEGRO PERMANENTE DEBE BAJAR DRÁSTICAMENTE Y LOS EXTRAS DESAPARECER. • COBRA PNC BÁSICA. • EL BALANCE PARA 1 AÑOS ES DE - 1.300 € APROX. • REINTEGRO PERMANENTE: ACTUAL 95 €/SEM (412 €/MES)------CON EL NIVEL DE GASTOS ACTUAL Y SIN NINGÚN EXTRA NO DEBE SUPERAR LOS 60 €/SEMANA (275 €/MES)" ·························· Mi respuesta a ambos: "De acuerdo, ya se lo he explicado a Carlos también, que dadas las circunstancias y los últimos gastos “sobrevenidos” (deuda comunidad + arreglo por corte de cable de antena) habrá que bajarle su asignación semanal a 60€. *Por favor, confirmarle a partir de qué semana tendrá lugar dicha bajada para que lo sepa él antes de irse al banco." ·································································································································· Otro correo de Alberto del mismo día: "ANA/ÁREA JURÍDICA: NOS LLEGA COMUNICACIÓN ADMINISTRADOR FINCAS VIVIENDA TUTELADO GONZALEZ LEO: • INFORMAN QUE TUTELADO HA CORTADO CABLES ANTENA Y HA DEJADO SIN TV A UNA GRAN PARTE VECINOS. • INCLUYE FACTURA ARREGO X 224 € APROX. • IMAGINO QUE LA C.VECINOS TENDRÁ RAZÓN, PERO: • Y SI NO ES CIERTO? • Y SI ES CIERTO, QUIEN NOS ASEGURA QUE SI ARREGLAMOS AVERÍA, TUTELADO NO VA A VOLVER A CORTAR CABLES? ANTES DE PROCEDER AL PAGO...QUE ENTIENDO QUE DEBEMOS HACERO...QUIERO SABER VUESTRO PARECER. • ANA: PODRÍAS HABLAR CON TUTELADO PARA VERIFICAR QUE LAS COSAS SON ASÍ? • ÁNGEL/MIGUEL: SI TENÉIS ALGO QUE DECIR...EXPONEDLO, XFA. ESTRELLA: SI ANA/ÁREA JURÍDICA NO TIENEN INCONVENIENTE, ABONAMOS FACTURA.". Respondo a todos: "He hablado con el Presidente de la Comunidad de Vecinos y con el propio Carlos. La foto del cable cortado que adjuntan es de la vivienda de Carlos. El día que acudieron el presidente y el técnico a su casa, él mismo reconoció que lo había cortado él y a mí también me lo ha reconocido. Que un día que no se veía bien la televisión comenzó a pelar el cable y al final terminó por cortarlo… Dice que no lo volverá a hacer y si tuviera problema con la imagen de nuevo lo comunicará al presidente de la comunidad para que se avise a un técnico. *Por tanto, hay que abonar también esta factura. Pongo en copia a Mamen, Educadora de Futuex, para que esté al corriente."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MONTAÑA'and edp.apellido1='GONZALEZ'and apellido2='ROLO'),'2024-08-02','Ana: Envío correos a Estrella, Secc. Ecca., con copia a Alberto, Jefe: "En relación al correo que te reenvió ayer Alberto sobre las averiguaciones de deuda de MONTAÑA GONZÁLEZ ROLO, te envío CARTA DE PAGO EJECUTIVA DEL OAR que ha que ha solicitado la educadora de Futuex junto con Montaña. Con respecto a la de Hacienda, aunque han acudido, le han dicho que hay que solicitarlo desde aquí, no le han dado nada. No obstante, el Certificado es positivo al parecer." ······························ "te reenvío nuevo coreo de la educadora con los documentos pertinentes para solicitar el fraccionamiento y el certificado de Hacienda."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='CAMARA'and apellido2='MORENO'),'2024-08-02','Ana: Recibimos INFORME SOCIAL solicitado para la RENDICIÓN ANUAL DE CUENTAS. ············· Guardado en carpeta de Rendiciones en su expediente digital. ··································· Según el mismo: ingresado definitivamente en el CSS desde 1994. ···· Actualmente estable. ············· Participa en las actividades ocupacionales del centro. ··················· Actualmente no recibe visitas y tampoco hay registros de llamadas interesándose por él. ················· Hace años y ocasionalmente le visitaba su hermano Jesús.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2024-08-05','Ana: ÇConforme a indicación de Alberto, envío a María, S. Ecca., la factura del agua para que la abone cuando pueda. ······ Reenvío el correo a Miguel para que confirme que desde la secc. jurídica no ven inconveniente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='BLANCO'and apellido2='GUISADO'),'2024-08-05','Ana: Correo a Teresa Nogueira, TS Novaforma (trabajadorasocial.novaforma@gmail.com): "Felipe Blanco quiere ire a su pueblo el dia 15, por lo que solicitamos un extra de 230 para pagar el acompañante , flores para la virgen y comida, si puede ir esta semana sería estupendo." ························ Reenvío la petición a la Secc. Ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REGINA'and edp.apellido1='REINA'and apellido2='LARA'),'2024-08-05','-Amalia : escribo a Casa Hospiatal Santiago , quedo pte. del nuevo empadronamiento para comunicarlo a PNC !! Os paso toda la documentación necesaria para su expediente . En las medidas de apoyo el juzgado solicitaba al Centro donde residía informes semestrales , por lo tanto , entiendo que ahora tendréis que enviarlo desde ahí. Desde la CTAEX se envía un informe anual al juzgado , y para ello se os pedirá informe a vosotros , se duplica un poco la información pero uno será cada 6 meses y el otro anual . Os envío el cdo. empadronamiento que he encontrado en su expediente , no sé si hay alguno posterior . Lo recomendable sería cambiar el domicilio de empadronamiento . Cuando lo tengáis me lo pasáis para comunicarlo a PNC . Para todo lo relacionado con la parte social tenéis que escribirme directamente a mi email. El de ctutelar lleva la parte económica . Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATAN'and edp.apellido1='GARCIA'and apellido2='TERRON'),'2024-08-05','Ana: Amalia me reenvía correo de Francisco Manuel Gómez Jiménez, Técnico Gerencia Territorial de BA (francisco.gomezj@salud-juntaex.es // 924939334): "me comenta Jonatan que quiere solicitar traslado y que está tutelado. No se si estás trabajando, puedes ponerte en contacto con él para tramitar su solicitud si lo consideras. Si me necesitas para facilitar los trámites, dime tú." ···························································· Mi respusta a Fco. Manuel: "este cargo de CURATELA se ha aceptado por la CTAEx el día 1 de agosto. Estamos en fase de inventario, apenas tenemos información aún. No obstante me pondré en contacto con la Trabajadora Social de referencia de Miajadas y con el recurso residencial para ir recabando información y poder comenzar a intervenir lo antes posible." ····························································································································································································· Llamo a Anabel, TS SSASB Miajadas (Tfno.: 927 347 000 Ext.: 3401) - Puesto que no obtengo respuesta, le escribo (servicios.sociales@miajadas.org): "...comunicarte que el cargo de CURATELA ASISTENCIAL relativo a JONTAN GARCÍA TERRÓN, ha sido aceptado el jueves pasado, día 1 de agosto. Como sabes ahora mismo estamos en fase de inventario, en breve recibiréis oficio solicitando documentación e información que dispongáis para el mismo. Por otra parte, me han escrito de Servicios Territoriales de Badajoz comunicando que Jonatan les ha llamado porque quiere solicitar traslado. Como aún no sé más de este expediente, ya lo hablamos en cuanto estemos la dos disponibles."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2024-08-05','TERESA Felisa Bruno Saavedra va para la UHDAC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NELSON JOSE'and edp.apellido1='CAMPOS'and apellido2='DIAZ'),'2024-08-05','TS CSS : El paciente sigue en lista de espera en el CRR de Mérida. He preguntado a Raquel por la posición en la que se encuentra, pero no me lo ha dicho. Así que, seguimos esperando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2024-08-05','Ana: Mª Luisa solicita a través de la educadora de futuex comprarle a su hija un móvil como regalo de cumplaños. ··· Por mi parte ok al presupuesto que facilita Nieves, Ed. Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2024-08-05','Ana: Juanjo solicita 50 € para poder asistir a una excursión a la playa (ida y vuelta en el día). En esta cantidad se incluyenlos gastos de bolsillo. ············ Por mi parte, si es viable, ok al extra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='IGLESIAS'and apellido2='CALZAS'),'2024-08-05','Ana: Correo de Ana Isabel Amor - Placeat (ana@placeat.org): "Buenas tardes, nos informan que ha fallecido el tío de María (Isidro), y su hermano Jesús quiere que asista al funeral. Solicitan la salida para ir desde esta tarde 5/08/24 sobre las 18h, hasta mañana 6/08/24, después del funeral, a las 13h aproximadamente. No hemos podido informar antes, ya que esto ha sido a las 14.50h de hoy. La Gerencia de Placeat y la Dirección de residencia toman la decisión de permitir la salida de Maria Rosa Iglesias Calzas, haciendo firmar a su familiar Jesús Iglesias Calzas el registro de salidas con familiares de RAL Placeat."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='LANCHO'and apellido2='SANGUINO'),'2024-08-06','Ana: Correo del día 23/07, de Estrella, TS del SSASB Malpartida de Cáceres (ssb@malpartidadecaceres.es): "en relación a Don Andrés Lancho Sanguino, su hermano ha denunciado a la residencia donde se encuentra, en relación a cobros indebidos (según su criterio) lo que te remito para conocimiento vuestro, ya que vosotros también estáis en la cuenta de Andrés" ······························ Reenvío a los A. Jurídicos. ································································································································································································ En relación a los correos remitidos por Estrella, TS Malapartida, sobre las facturas pendientes de electricidad, respondo: "Gracias de nuevo por estos correos con la información que nos facilitas. He comprobado en el Certificado Catastral y la dirección no se corresponde exactamente con la que indica en el correo de la empresa de electricidad, pues pone: “ CL PIÑUELAS 2 Es:1 Pl:01 Pt:A “. ¿Estás segura que es la vivienda de Andrés Lancho Sanguino? De todas formas pongo en copia a Alberto, jefe de la sección económica y a los Asesores Jurídicos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2024-08-06','Ana: Llamada de Doroteo (609 928 621): Solicita extra de entre 250-300€ para dar como regalo de BODA a su sobrina, que se casa el día 24 de agosto. ··········· **Paula, TO CRR, lo comunicará por escrtio. ·············· **Una opción es que coja esa cuantía de su extra anual, pues aún le quedan algo más de 700€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2024-08-06','Ana: Llamada de Mª José Trillo, Res. Hervás (927 47 34 10): Comunica que a pesar de haber regresado Eugenia el jueves pasado día 1/08, por alta en UME, no llegó bien. Ayer tuvieron que llamar al 112, el médico acudió y le puso un inyectable para que se quedase más tranquila. ····················· Pregunta si podemos pedirle un cambio de centro. Le recuerdo que el cargo de Eugenia es una CURATELA para el ámbito PATRIMONIAL. ········ El traslado tendría que solicitarlo ella misma. ····················· Recomiendo que continúen activando el 112 cada vez que sea necesario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATAN'and edp.apellido1='GARCIA'and apellido2='TERRON'),'2024-08-06','Ana: correo de Anabel Gil, TS SSASB Miajadas (servicios.sociales@miajadas.org): "Respecto a Jonatan lo mas importante ahora mismo es poder conocer cual es el alcance de las deudas/embargos que pueda tener y poner orden en ese sentido, nosotros no le estamos cobrando nada por el piso y la directora del Centro ocupacional le saca de su cuenta 150€ todos los meses para que pueda ir teniendo para sus gastos personales, efectivamente me dijo que queria un traslado a Badajoz, es verdad que él alli participaba en una banda de musica, en un equipo de futbol, en carnavales, ... y aqui le cuesta un poco integrarse en las actividades de la localidad, pero me da miedo la utilización que puedan hacer de él la familia, tengo entendido que le utilizaban para cuidar a otros familiares y todas las deudas que ahora tiene son fruto de la utilización de sus datos para comprar vehiculos respecto de los que luego no pagaban los impuestos correspondientes, y de otras deudas desde luego de las que él no es responsable pero que figuran a su nombre. Yo le dije que en septiembre retomaríamos el tema del traslado, queria dar tiempo a poder hablar con vosotros y a que tuvierais el cargo aceptado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL ANGEL'and edp.apellido1='RAMOS'and apellido2='ANDRES'),'2024-08-06','Ana: Reenvío a Clara, Ed. Futuex, con copia a Toni, correo de Estrella, TS del CSS Plas: "Ya tenemos los 100 euros para gastos extras de Miguel Ángel Ramos Andrés. Estoy intentando contactar con Clara para que vaya ella a hacer dichas compras, ya que él no puede salir del centro..., pero no me coge el teléfono. A ver si puedes tú contactar con ella. Yo no vuelvo a trabajar hasta el lunes 12, si viene antes de ese día que llame a la Supervisora de la unidad, Nuria Bravo" ·································· *Respuesta de Toni-Futuex: "Buenas pues irá una compañera que está para la suplencia de agosto para intentar gestionar esto"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NEMESIA'and edp.apellido1='GARCIA'and apellido2='PANIAGUA'),'2024-08-06','Ana: Tras conversación con Piedad, TS SSASB Guijo de Grandilla (927 67 00 59), envío correo a Clara, Ed. Futuex (delegadapoyo.plasencia@futuex.es): "Tras conversación con Piedad, TS de Servicios Sociales de Guijo de Granadilla, te reenvío correo de Alejandra, compañera de la Sección Económica, con la respuesta a Toni adjuntando el justificante del abono de la ropa que se solicitó para NEMESIA GARCÍA PANIAGA. *Como puedes ver lo abonó el mimos día que Toni envió el presupuesto y ese mismo día le envió el justificante (26/06/2024). Pongo en copia a Toni, pues entiendo que se le pasó comunicártelo en su día." ······································ Envío nuevo correo a Clara, Ed. Futuex: "Al parecer falta otro presupuesto de faldas y blusas que pediste, pero ese aquí no ha llegado. El correo de Toni del día 26/06, sólo contenía el presupuesto de los 42 € (que acabamos de revisarlo), y no hay ningún otro coreo con presupuesto de ropa para Nemesia. Puesto que Toni está de vacaciones, ¿podríais enviárnoslo tú directamente? Le pongo en copia a ella de nuevo para su conocimiento." ············································································ Respuesta de Toni-Futuex: "...Sobre otras cosas q necesitan según dicen, pues vamos a esperar a la segunda quincena q vuelve mi compañera y vemos si se tiene que pedir nuevo presupuesto o ya está pedido. Y si es super urgente hemos dicho en la resi que avisen y vemos cómo hacer presupuesto de lo q falte o llevar esto si no estuviera x un acaso."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2024-08-06','Mariloli ingresó a mediados de junio en la R. Mayores de La Piedad en Almendralejo. Le han cargado en su cuenta de Ibercaja ( terminada en ...33) 96€ del mes de junio. Se cargará a mes vencido por copago mensual 722€ sin contar con la P. extras , que no se le tocan. Tiene unos gastos aproximados domiciliados ( s. decesos y gastos derivados de su piso ) unos 110€ mensuales . Con las 2 extras ahorraría 1600€ , con los que cubriría esos gastos domiciliados . Se le abonarán 90€ de gastos de bolsillo al mes , que es lo que le queda una vez abonado el copago . La autorización para ese reintegro lo retirará en la oficina de Ibercaja , sito en C/ Real de Almendralejo. Para el mes de agosto , y dado que en Julio no se le ha dado nada , solicito se haga una autorización puntual de esos 90€ para que los pueda retirar el 12 de agosto , coincidiendo con las ferias del pueblo. Si a Alberto le parece bien , y autoriza este reintegro permanente, se hará para empezar el mes de septiembre , para que pueda retirarlo en los primeros días del mes','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2024-08-06','Ana: Tras hablar de nuevo con Ángel Félix y valorarlo con Maite, Jefa CTAEx, éste envía correo a la secc. ecca: "Se autoriza un extra de 100€ para Angel Maillo destinados a la compra de mochila, zapatillas y viaje al Valle para buscar casa de alquiler."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-08-06','Ana: Envío correo a la secc. ecca: "Tras hablar con José Manuel y valorarlo con Maite, Jefa Secc., os envío solicitud de EXTRA PARA EXCURSIÓN de José Manuel a Chipiona. SE ACEPTA PRESUPUESTO TOTAL DE 50€ (25€ de la excursión + 25 para gastos de bolsillo). Adjunto documento con la información y enlace a la Web de la entidad que lo organiza con la publicidad de la misma: https://www.humilladerocaceres.org/2024/07/27/excursion-a-chipiona/ El dinero puede retirarlo el propio jueves, pues el pago tiene que hacerlo ese día por la tarde."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2024-08-06','Ana: Llamada de Felisi, madre de Aitor (614 361 144): Sigue igual, cada día la conviviencia con su hijo se vuelve más complicada. Ya no toma la medicación y consume porros de nuevo. ········· En cuanto a la búsqueda de vivienda de alquiler para Aitor la educadora le dice que está siendo muy complicada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2024-08-06','Ana: Llamada de Felisi (614 361 144): Sigue igual, cada día la conviviencia con su hijo se vuelve más complicada. Ya no toma la medicación y consume porros de nuevo. ················ En cuanto a la búsqueda de viviena para Aitor, la educadora le dice que está siendo muy complicada. ··········· *Le pregundo por la FACTURA DE TAXI que ha llegado a su nombre al ctutelar@ para ir a un centro comercial a Cáceres. Reconoce que no debería haberlo hecho pero que se hizo caso de su hijo. Dice que no lo hará más. ····················· *María, secc. ecca., habló con el taxista, ya le ha avisado que sin autorización previa no volerán a pagarse. El taxista lo comunicará a sus compañeros también.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-08-02','Ana: Llamada de José Manue: dice que el día 22 de julio tuvieron que operarle de urgencias de apendicitis. Tiene pendiente ir a quitarse las grapas. ··············· Le pregunto por el viaje a Baños de Montemayor. De las 2 noches pagadas sólo se quedó una. Dice que se gastó parte del dinero de bolsillo el día antes del viaje el Cáceres y el resto el primer día en Baños. Como se quedó sin dinero y se aburría decidió volverse al día siguiente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2024-08-06','Ana: Correo de Ana, TS Fundación Autismo Sur (teayudamos@autismosur.es): "El viernes día 9 tiene la analítica Ale Costi. En cuanto tengamos la factura os la reenviamos para realizar la transferencia."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2024-08-06','Ana: Correo de Paula, TO - CRR Plas (tocupacional.crrplasencia@grupo5.net): "comentaros salidas de algunas personas: • Isabel Cano: saldría del 9 al 12 de Agosto a Trujillo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='PEREO'and apellido2='REBOLLO'),'2024-08-06','Ana: Correo de Paula, TO - CRR Plas (tocupacional.crrplasencia@grupo5.net): "comentaros salidas de algunas personas: • Antonio Pereo: saldría del 15 al 18 de Agosto a casa de su hermana en Badajoz. Así mismo el sábado día 10 tiene una salida sin pernocta a la playa como ya os informó Carolina, la directora."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-08-07','Ana: Nieves, Ed. Futeux (delegadapoyo.caceres2@futuex.es) nos remite CITACIÓN para comparecencia ante MÉDICO FORENSE para el día 19/8/2024 a las 9:15 h, en el instituto de medicina legal de CC. ····························· Toni-Futuex responde a mi consulta: "Si, irá con su educadora de referencia que ya estará de regreso para esa fecha"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='ASENSIO'and apellido2='GARCIA'),'2024-08-07','TERESA Informamos que la tutelada Carmen Asensio García, se desplazará en taxi a Villanueva de la Serena el lunes 12 de Agosto. Estará con la familia de sus hermanos biológicos hasta el día 16.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA PRISCILA'and edp.apellido1='SAQUERO'and apellido2='SANCHEZ'),'2024-08-07','Ana: Maite nos envió a Alberto, A. Jurídicos y a mí, correo remitido por Soraya en que adjuntan una carta del alcalde: "...después de haber recibido el informe de los Técnicos Municipales y las quejas de los vecinos, respecto al estado que se encuentra el inmueble de la Calle Río, 1, de nuestra localidad, cuya heredera es su tutelada, que además se encuentra en nuestro Piso Tutelado Municipal como usuaria. El estado del inmueble, es una parte mayor, se puede declarar ruina. ..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATAN'and edp.apellido1='GARCIA'and apellido2='TERRON'),'2024-08-07','Ana: Llamo a Anabel, TS SSASB Miajadas (Tfno.: 927 347 000 Ext.: 3401): No le van a cobrar este año (2024) la plaza del Vivienda Tutelada pues conocen la delicada situación económica que presenta. Es fundamental ver el alcance de las deudas OAR, HACIENDA Y SEGURIDAD SOCIAL. *No sabe si también tendrá algún prestamo de alguna financiera. ················ *El hermano y la cuñada están intentando convencerle para que solicite que ellos sean los tutores. Pero éstos son los responsables de todas sus deudas, pedían todos los préstamos y compras a su nombre además de gastarse toda su pensión. ··············· La Directora del CO de Miajadas le saca al mes de su cuenta 150€ para sus gastos personales y el resto de la pensión (PNC sin complemento) lo dejan para lo que van embargando. ····························· Envío correo a Alberto, Jefe de Secc. Económica, comunicando esta situación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIPE'and edp.apellido1='BLANCO'and apellido2='GUISADO'),'2024-08-07','Ana: Reenvío a Teresa Nogueira, TS Novaforma (trabajadorasocial.novaforma@gmail.com) correo remitido por Alejandra, S. Ecca. al banco: "Envío autorización firmada de REINTEGRO PUNTUAL de 230 € para retirar por su cliente citado en una única vez en los días 7 a 13 de agosto."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SALVADORA'and edp.apellido1='CHAVES'and apellido2='MENDOZA'),'2024-08-07','Ana: Me informan las compañeras de la S. Ecca., que se le concedió un EXTRA DE VERANO de 100€, en mi ausencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2024-08-07','Ana: Correo de Fátima, TS CSS Plas. (fatima.martin@salud-juntaex.es) del 23/07, en sustitución de Estrella: "A petición del Dr. Fernando Gabriel Luque Molina, se comunica que el paciente Juan Mario San Román Blasco, con antecedentes de Esquizofrenia y Trastorno por consumo de sustancias, presenta una evolución tórpida en el curso de su enfermedad, con resistencia al tratamiento farmacológico hasta la fecha, por lo que decidimos iniciar tratamiento con clozapina. Se ha explicado al paciente de manera detallada los efectos adversos y los riesgos más comunes conocidos, así como otros extraordinarios pero potencialmente graves (especialmente agranulocitosis y convulsiones, por lo que se realizan controles estrictos), los síntomas para una detección precoz de los efectos adversos hematológicos, los beneficios esperables de la terapéutica a realizar, la posibilidad de que pueda ser necesario algún procedimiento diferente y la existencia de otras alternativas al tratamiento, mostrándose de acuerdo el paciente con iniciar dicho tratamiento."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2024-08-07','Jose Vicente me llama que esta en la calle, ha visto un hotel en villanueva. se le paga una semana, quiere buscar piso de alquiler Se renueva una semana mas a al espera de que la seccion economica autorice alquilar piso se le ha tramitado orfandad simple, a la esepra de resolucion','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GABRIEL'and edp.apellido1='SOBRINO'and apellido2='TARDIO'),'2024-08-07','Ana: Se autorizaron vacaciones en Hotel Rural de San Martín del Trevejo del 30 de julio al día 2 de agosto. Coste: 350 € (incluidos gastos personales).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADOLFO'and edp.apellido1='GARCIA'and apellido2='CRUZ'),'2024-08-07','TERESA he estado hoy en casa de Adolfo junto con la empresa que realizaría los arreglos en casa de Adolfo. Va a presentar presupuesto con: • arreglo de albañileria y pintura en el dormitorio de Adolfo, en la entrada, en la 2ª habitación ya que hay humedad y algo en el salón. • limpieza de los dos dormitorios, salón, cocina y cuarto de baño. • ordenar y organizar la ropa tanto personal como de cama. El ordenador no es necesario comprarlo y lo de la pantalla lo dejaremos para más adelante ya que Adolfo aún no se ha duchado ni un solo día a pesar del compromiso adquirido, además de que el auxiliar le limpio la nevera y hoy estaba otra vez llena de cosas que ha comprado sin control y otras de restos de comida ya pasado. ( te adjunto foto) si sería necesario el comprar un armario pequeño para su habitación, el que tiene esta inservible y el que hay en la habitación de la madre es de los antiguos de 4 cuerpo que no cabria en su habitación, y no podemos utilizarlo ya que Adolfo no entra en dicha habitación y lógicamente estaría entonces la ropa en un lugar no accesible para él. Si os parece bien lo del armario, pido presupuesto a una empresa aquí en Vfca o bien lo veis vosotros directamente o a través de la educadora.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CASARES'and apellido2='GARCIA'),'2024-08-07','Ana: correo de Mamen, Ed. Futuex(delegadapoyo.caceres@futuex.es) al ctutelar@ y a mí: "Adjunto presupuesto de ropa de verano, calzado y maquina de afeitar para Rafael Casares García. Tras la demanda e insistencia desde la residencia Amada Corral de Alcuéscar. Personalmente, en coordinación con las trabajadoras de la residencia, me he encargado de comprobar que la necesidad es real." ······················ Si es viable, ok por mi parte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2024-08-07','Ana: correo de Mamen, Ed. Futuex(delegadapoyo.caceres@futuex.es) al ctutelar@ y a mí: "Adjunto presupuesto de ropa de verano y sandalias para Mateo Ruano Moreno. Tras la demanda e insistencia desde la residencia Balcón de Extremadura de Montánchez. Es importante cubrir la necesidad de Mateo, ya que el calzado que utiliza actualmente le ha provocado heridas, además de la ropa de verano que apenas tiene. Personalmente, en coordinación con las trabajadoras de la residencia, me he encargado de comprobar que la necesidad es real."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='BARROS'and apellido2='CORDERO'),'2024-08-07','Ana: Guardo en el expte. INFORME remitido el día 22/07, por la Residencia de Tercera Edad Madre Francisca de Azabal (residenciamadrefranciscazabal@hotmail.com) para la revisión de la medidas de apoyo. ············ Ya estaban en copia los A. Jurídicos. ··························································· *Según el informe: "... se encuentra perfectamente adaptada a la vida social de la residencia. Participa en las actividades del centro y tiene su grupo de compañeros frecuentes. Su hermana es la persona que se ocupa de las necesidades que tiene Jose Antonio fuera de la residencia."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2024-08-08','TERESA CORREO DEL HOTEL Avisarles de que lamentablemente tenemos que cancelar la ampliación de reserva por motivos de mal comportamiento del huesped: A forzado la ventana de la recepción del hotel y ha estado intentando robar en el interior de la recepción. Lo sentimos pero queda prohibida su entrada en el hotel. También avisarles de que quiere estafarles, ya que nos ha pedido que le demos a él el dinero que ustedes han pagado y que no le digamos que se va, ya me lo pidió esta mañana y le dije que si se iba yo les iba a avisar a ustedes y les devolvería el dinero a ustedes, no a él. Esta tarde lo ha estado diciendo también antes de que se lo llevara la policía. En caso de haber hecho alguna transferencia le será devuelto el dinero con la mayor brevedad posible.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MONTAÑA'and edp.apellido1='GONZALEZ'and apellido2='ROLO'),'2024-08-08','Ana: Llamo a Pilar Martín, TS ESM (54612), le informo que Montaña está teniendo respuestas y reacciones poco habituales con la educadora de Futuex que no hace pensar que pueda estar descompensándose. Quizá necesite que le reajusten la medicación. Su Psiquiatra de referencia es el Dr. Enrique Goenaga. Hablará con él para ver la posibilidad de adelantarle la cita.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='AVILA'and apellido2='FEMIA'),'2024-08-08','Ana: Envío a Juan Carlos Cano, Aux. Adtvo: "En relación a D. José Luis Ávila Femia, cuyo cargo ostente la CTAEx, adjunto para remitir por registro a: GERENCIA TERRITORIAL DE CÁCERES. Plaza Hernán Cortes, 1 10001-CÁCERES CÓDIGO REGISTRO SIREX: A11030403 la siguiente documentación: - Aceptación PIA - DNI Representante Legal actual - Decreto Nombramiento Directora-Gerente del SEPAD - Resolución de Delegación de funciones como Presidenta de la CTAEx" ·································································································································································································· *La solicitud de revisión PIA la hicieron las compañeras al estar yo de vacaciones (30/04/24). Modelo de solicitud en el expte. sin firmar. ··················· Me ha enviado la Aceptación PIA, Alberto Arias Bueso - TO EVD Brozas (alberto.arias@salud-juntaex.es).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2024-08-08','miguel, llega email de Belén a través del ssb@malpartidadecaceres.es remitiendo documentación de liquidación de Imp Sucesiones, factura notarial (pago adelantado por su hermana Belén), escritura de aceptación del legado y testamento de su tío. Pido los datos de contacto de la Caixa a Belen para el desembolso del legado, que es: Ana Maria Acedo Rato, Subdirectora Cabezarrubia (Caceres), email amacedo@caixabank.com; 927-629016; 628-985320 ***************************************************** Envío email a Caixa Bank amacedo@caixabank.com Buenos días, en relación al legado de una cuenta abierta en la Caixa ES78 2100 7616 5402 0003 1404, a nombre del fallecido D. Benito Solana Rollizo, adjunto testamento, escritura de toma de posesión de legado, documentación de liquidación del impuesto de sucesiones, sentencia de incapacitación y nombramiento a la Comisión tutelar de adultos de la junta de Extremadura y el acuerdo de aceptación del cargo. Ruego nos indiquen si necesitan algo más para proceder al abono en la cuenta la tutelada por la Junta de Extremadura, Doña Maria del Carmen Solana Chanclon. El ingreso del legado a favor de esta tutelada, deberán realizarla en la cuenta de su titularidad en Unicaja ES12 2103 7114 0000 3009 4618 ************************************************* Envío email a Ale para que abone la factura de notaria a Belén *********************************************** email de Belén: El teléfono del banco para que le deis vosotros la cuenta de Maricarmen ya lo hemos solucionado ********************************************************* Envío email a Belén Belen Solana chanclon >solanachanclonbelen@gmail.com> Hola Belén, adjunto justificante de transferencia de la factura de notaria que se te debía. Quedamos a la espera que la Caixa, a la que he enviado un email haga el abono del dinero en su cuenta a tu hermana Maria del Carmen.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARCELO'and edp.apellido1='MANZANO'and apellido2='PEREZ'),'2024-08-08','Ana: Reenvío a Miguel, A. Jurídico, el INFORME SOCIAL remitido por Fernando Gago, TS de la RR.MM. Real de Navalmoral(tsnavalmoral@residenciareal.com)para la revisión las medidas de apoyo. ······································· El Informe Social se guardó también en la carpeta de rendiciones pues se usará para la de este año. ···························· *Según el mismo, Marcelo tiene 75 años, presenta Grado II de Dependencia. ··· Recurso activo: Plaza T4 desde el 17/08/2018, "...se mantiene estable, con buen estado físico en general, con deambulación autónoma sin ayudas, independiente para la mayoría de ABVD. ... puntuación en I. Barthel: 90/100". "... mantine contacto con moderado y es visitado ocasionalmente por su prima, normalmente en el exterior del centro para pasear y almozar...", "siempre se mantien cerca de su hermana Conchi, que se muestra muy protectora..." (Conchi reside en la misma residencia).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='VALLE'and apellido2='SIMON'),'2024-08-08','Ana: Correo de Sheila a la atención de Estrella, S. Ecca., al ctutelar@ el día 22/07 , con copia a mí: "Adjuntamos factura referente a la cita mantenida el viernes día 19 de Julio y que está pendiente de pago. En dicha consulta se procedió a la extirpación de una lesión en el párpado que afectaba a la movilidad. Con respecto a la lesión cercana al ojo, debe ser extirpada en quirófano. Dicha consulta será, como aparece en la documentación adjunta el 24 de Septiembre. el presupuesto total de dicha intervención rondará los 500 euros aproximadamente. En la documentación adjunta se envía también documento a cumplimentar y firmar por la comisión para la realización de la intervención. Félix se encuentra más tranquilo sabiendo que ya tiene fecha para la extirpación y habiendo comenzado ya toso el proceso. Trasladamos para que surta los efectos oportunos. Quedamos a la espera de indicaciones por vuestra parte si fuera necesario." ································································································································· Escribo a Alberto y a Estrella, Secc. Ecca.: "Ya sé que Estrella ya ha abonado la factura de la primera consulta en Dermatología (50€). Pero como podéis leer en el hilo, la intervención de fecha 24 de septiembre cuesta 500€, creo que es viable, no obstante, por favor, confirmar cuando podáis que se puede realizar para enviarles el Consentimiento Informado."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2024-08-08','Ana: Tras llamada de Felisa (614 361 144), envío correo a la secc. ecca: "En relación a: - FELISA FELIPE TOMIRO y - AITOR MORENO FELIPE Solicitan un EXTRA para las fiestas de su pueblo y para comprar el bono de los Toros. Mirad por favor si se les puede dar algo, como en años anteriores, y cuánto. *Si bien es cierto, ambos han hecho uso de taxi sin autorización que ha habido que pagar pues era la primera vez que hacían algo así."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2024-08-08','Ana: envío correo a la secc. ecca: "En relación a: - FELISA FELIPE TOMIRO y - AITOR MORENO FELIPE Solicitan un EXTRA para las fiestas de su pueblo y para comprar el bono de los Toros. Mirad por favor si se les puede dar algo, como en años anteriores, y cuánto. *Si bien es cierto, ambos han hecho uso de taxi sin autorización que ha habido que pagar pues era la primera vez que hacían algo así."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2024-08-08','Ana: Envío correo a Gloria Aguedo, TO Futuex (areasocial5@futuex.es) con copia a Nieves, Ed. y Toni, Coordinadora: "Creo que Nieves estás ya de vacaciones. Entiendo, por otro correo que has enviado, que estás ejerciendo funciones de coordinación en ausencia de Toni, así pues me dirijo a ti por si es posible que realices esta gestión, sino esperaremos a que Toni regrese. Las pongo a ambas en copia. En relación a FRANCISCO CACHO GARCÍA, y a petición del Juzgado, necesitamos que nos enviéis breve informe indicando que de nuevo está en situación de calle en la ciudad de Cáceres (si os consta que sigue por allí) o dónde esté si conocéis su paradero, pues le hemos enviado certificado de Cáritas comunicando su abandono del recurso para personas sin hogar, pero al parecer no es suficiente. Si es posible, hacédnoslo llegar a la mayor brevedad."','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2024-08-08','Ana: Envío a los A. Jurídicos: "...los datos de los familiares con los que convive, y únicos que disponemos,: - David Maseda del Sol, hermano. DNI: 289585B - Azucena Merino López, cuñada. DNI: 76041803P. Tlf. De contacto: 625 367 302. Dirección de correo-e: azuydavid153@gmail.com - Ángel Maseda del Sol Merino, sobrino, hijo del matrimonio anterior. Menor de edad. Por otra parte, según informe social aportado, tiene otros dos hermanos: Tomás y Valeriano Maseda del Sol. Tenía otro hermano, Rafael, ya fallecido. *Según el mismo informe, todos los miembros de la familia (hermanos y cuñada) presentan discapacidad intelectual. Padres fallecidos. Espero que estos datos sean suficientes."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2024-08-09','Ana: Correo de Azucena Merino, cuñada de Juanjo (azuydavid153@gmail.com): "Hola a ver si se puede hacer algo Juanjo por todo la lia y estos ya no se aguanta más a ver si pueden lo del centro a ver si no tardará mucho." ······················ Mi respuesta: "El centro ya está pedido desde hace tiempo, sólo queda esperar, no depende de nosotras. De todas formas, solicitaré que la educadora intervenga con él al respecto." ······························································································································································································ Envío correo a Nieves y Toni-Futuex: "Os reenvío correo de Azucena, cuñada de Juan José Maseda del Sol. Por favor, leed el hilo. Yo ya le he contestado recordando que el centro ya está pedido desde hace tiempo, sólo toca esperar. Eso sí, a vuestro regreso de vacaciones, Nieves, sería necesario que intervinieras con él al respecto para que module su comportamiento en casa y mejore con ello la convivencia. También habría que seguir trabajando la importancia de que acepte la plaza una vez se la concedan para que no vuelva a ocurrir como la vez anterior."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2024-08-09','el pasado 05.08.2024, Felisa Bruno Saavedra, usuaria del proyecto mi casa de Plena Inclusión Don Benito ha ingresado en la UHDAC. En las últimas fechas venía estando bastante inestable, lo que a la vez producía episodios de inestabilidad también en la otra usuaria de la Vivienda Inés. Finalmente, ha sido necesario el ingreso en la UHB de Mérida de Felisa Bruno, ,que posteriormente ha pasado a la UHDAC una vez que ya se había acordado con la Unidad dicho ingreso. El ingreso de Felisa en la UHDAC, deja una vacante en la vivienda de MI CASA en Don Benito. Con el fin de poder valorar la adecuación de la usaría NEREA DA COSTA LORENZO a participar en el proyecto, en los adjuntos os envío información sobre la persona, a saber:','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ELENA'and edp.apellido1='DURAN'and apellido2='DURAN'),'2024-08-09','TERESA SOLICITO ORFANDAD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2024-08-09','TERESA El martes viene la familia de Marta para llevarla a su casa y han pedido dinero para la gasolina. Le vamos a dar 50€ que tenemos guardados.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FAUSTINA'and edp.apellido1='GORDO'and apellido2='MARTINEZ'),'2024-08-09','Amalia : Se abona factura de casi 1000€ por acompañamiento hospitalario. Ya está de alta','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIO'and edp.apellido1='GUISADO'and apellido2='GUISADO'),'2024-08-09','TERESA Ca epidermoide canal anal pT2Nx p16 neg. Ha recibido QRT en CHUB. Tras simulación virtual mediante TC con el paciente inmovilizado, sobre cuyas imágenes se determinan órganos críticos y volumen/es blanco. Se planifica radioterapia de intensidad modulada e imagen guiada con CBCT diario. Los volúmenes irradiados, fraccionamiento y dosis total administrada a cada uno fueron los siguientes: - PTV F1 36 Gy: Cadenas ganglionares inguinales y pélvicas electivas.Dosis administrada de 36 Gy mediante haces de fotones de 6 MV de acelerador lineal, conformados, a una dosis por fracción y día de 180 cGy, cinco días a la semana en 20 sesiones. - PTV F2 9 Gy: Cadenas ganglionares pélvicas electivas. Dosis administrada 9 Gy mediante haces de fotones de 6 MV de acelerador lineal, conformados, a una dosis por fracción y día de 180 cGy, cinco días a la semana en 5 sesiones. La irradiación se completó entre los días 13/05/24 al 14/06/24 en 24 fracciones alcanzándose una dosis total de 43.2 Gy, teniendo que suspender última sesión por importante radiodermitis G2. 5-Fluorouracilo 1000mgr/m2/dia en IC desde dia 5-8/06/24 y del 20 al 23/6/24: Dosis 1700mgr. Acude a reevaluación. No cambios clínicos, no toxicidades al tto. ANALÍTICA: hb 10,7, IST en límite bajo normalidad, CREAT 2,5, fg 27 mil/min. TC DE TORAX/ABDOMEN/PELVIS SIN CONTRASTE del 29-07-2024: Se compara con estudio previo de marzo del 2024, siendo superponible al mismo. No se aprecian lesiones sospechosas d malignidad. Cito en 3 meses con RMN y A-MT.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MELLADO'and apellido2='GUARDABRAZOS'),'2024-08-09','Ana: Reenvío a los A. Jurídicos, la comunicación de la Asociación Vera, con Informe, Parte Médico y Denuncia ante la Guardia Civil como víctima de Abuso Sexual ejercido por otro usuario del centro. *Las cámaras del centro lo han grabado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2024-08-08','Ana: Envío correo a Gloria Aguedo, TO Futuex (areasocial3@futuex.es) con copia a Toni: "a petición del Juzgado, necesitamos que nos enviéis breve informe indicando que de nuevo está en situación de calle en la ciudad de Cáceres (si os consta que sigue por allí) _o dónde esté si conocéis su paradero_, pues le hemos enviado certificado de Cáritas comunicando su abandono del recurso para personas sin hogar, pero al parecer no es suficiente. Si es posible, hacédnoslo llegar a la mayor brevedad. " ························ Respuesta de Toni-Futuex: "El lunes se procedió a la compra del teléfono como sabes estaba ilocalizable y la compañero lo encontró de casualidad por la ciudad. Consiguió quedar con él para el lunes y se aprobó el presupuesto de compra en electrocash por vuestra parte. Te paso el número (esperemos que aún lo tenga y no lo haya vendido ni nada de esto) es el 614 22 90 61 La compañera que está haciendo suplencias intentará verlo esta semana y la próxima (que solo tiene 3 días laborables) por actualizar la información (a ver si aún en Cáceres y en la situación de calle o donde está) Y con la información q se recoja en el equipo, el mismo lunes 19 se hace informe preciso para juzgado, es tb cdo su persona de referencia regresa y podamos recabar la máxima información sobre el, aunque es cierto que como sabéis ha sido prácticamente imposible saber nada de él estos últimos meses ."','2');
