insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='AYUSO'and apellido2='TENA'),'2024-08-09','Ana: Conversación con Alicia y Lola, Secc. de acceso a recursos de PP.MM.: Antonia está la primera en la lista de espera para la RR.MM. Felipe Trigo. No entienden muy bien esta petición, pues está en la Ud. de Psicogeriatría. Quizá lo mejor es hacer sólo el mantenimiento de plaza. ······ Replanteamos la propuesta, pues compruebo que Antonia tiene ya 97 años y un cambio de recurso a esta edad puede ser contraproducente. ························· Hablaré con Maite, Jefa Secc. CTAEx y TS del CSS. ············ *De momento lo dejarán en Stand By.','2');
