insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2024-08-12','Ana: Reenvío a A. Jurídicos, correo de Felisa Custodio, TS CAMF (trabajadora_social_alcuescar@imserso.es), y pido le den respuesta: "me pide la residente de nuevo que les pregunte por el asunto en cuestión que desde el 24 de mayo no sabe nada y ya han pasado los seis meses desde el fallecimiento de su madre. Sludos." ················ Respuesta de Ángel: "Estamos esperando que la Notaría nos de fecha para poder formalizar en escritura la renuncia."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CATALINA'and edp.apellido1='DA SILVA'and apellido2='BAUTISTA'),'2024-08-12','Ana: Recibimos por REGISTRO (TRAMITA)Informe Social SSASB comunicando: "Que Dña. Catalina Da Silva Bautista con DNI 07045093D, tutelada por la Comisión Tutelar de Adultos de Extremadura, durante años ha sido usuaria del Servicio de Ayuda a Domicilio del Ayuntamiento de Valencia de Alcántara. Sin embargo, tras varios enfrentamientos personales con la auxiliar, este última debido a la gravedad de los mismos se negó a acudir con ella. Por lo que se encuentra sin este servicio desde el 4 de junio de 2024. Quedando a su disposición para cualquier duda o aclaración. Lo que informa, a los efectos correspondientes, en Valencia de Alcántara a 9 de agosto de 2024" ··································································································································································································· Envío correo a Toni-Futuex con copia a la Educadora (delegadapoyo.coria@futuex.es): "En relación a CATALINA DA SILVA BAUTISTA, residente en Valencia de Alcántara en su domicilio, os adjuntamos comunicación de la Trabajadora Social del SSASB recibida por registro. Al parecer, la Catalina lleva más de dos meses sin el Servicio de Ayuda a Domicilio. Nosotras no teníamos conocimiento de ello, no sé si en el programa estabais al corriente. Por favor, en cuanto os sea posible, realizad nueva visita de seguimiento y haced valoración sobre el estado de la vivienda y si tiene capacidad para permanecer en estado óptimo en su vivienda si este apoyo. Así mismo, ¿podríais acudir a los Servicios Sociales para consulta si hay posibilidad de reanudar el servicio en un futuro y/o volver a solicitarlo de nuevo? Pongo en copia a la compañera de la zona (creo que aún es Clara, no sé cuándo se reincorpora Nadia."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE BLAS'and edp.apellido1='CAÑAS'and apellido2='LOZANO'),'2024-08-12','Ana: llamada de Juan Manuel, hermano de José Blas (687 819 309): Les ha surgido la oportunidad de vender una casa de su padre, de la que son herederos su madre, él y Juan José. Es una buena oportunidad que no esperaban, a pesar de estar deteriorada le ofrecen buena cuantía. Tanto su madre como él quieren venderla, pero falta la conformidad en relación a Juan José. ···························· Puesto que no consigo pasar la llamada a Ángel, A. Jurídico, le facilito su número.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='IGLESIAS'and apellido2='CALZAS'),'2024-08-12','Ana: Envío a Antonio, Adtvo. U.PP.AA. (antonio.suareza@salud-juntaex.es): "Adjunto la siguiente documentación relativa a Dª. MARÍA ROSA IGLESIAS CALZAS, cuyo cargo ostenta la CTAEx, para remitir por REGISTRO a Servicio Territorial de Cáceres. Plaza Hernán Cortés, 1. C.P. 10001- Cáceres. DIR3 A11030102 : - Solicitud de PNC – Invalidez - Copia DNI de la interesada - Certificado de Discapacidad – CADEX - Testimonio de Auto de Nombramiento de Tutor - CTAEx - Acuerdo de aceptación del cargo - Copia DNI de la Presidenta de la CTAEx - Decreto de nombramiento - Resolución de delegación de funciones - Resolución de suplencias – Consejería Gracias de antemano."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2024-08-12','Ana: Estrella, TS del CSS, me remite Informe de Salud para valoración de Dependencia, pero no está firmado ni sellado. Pido que nos lo vuelva a firmar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='AYUSO'and apellido2='TENA'),'2024-08-12','Ana: Tras hablar con Maite, Jefa de Secc. CTAEx, llamo a Fátima, TS CSS-Plas (en sustitución de Fco. Javier): Le informe, que a no ser que el traslado lo haya solicitado la propia Antonia, no vamos a aceptar el cambio a la RR.MM. Felipe Trigo, con 97 años lo vemos contraproducente. ························ Fátima no trabaja estos dos próximos días. El viernes lo hablará con el equipo y me llamará al respecto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2024-08-12','Maite: José Vicente no para de llamar pidiendo que le demos dinero para alquilar un piso que tiene  apalabrado. Hemos decididido darle su pensión íntegra y que la adminstre como quiera. Se va a comunicar al juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='DIEZ'and apellido2='SANTIAGO'),'2024-08-13','Ana: Correo del viernres 9/08, de Salvador Fernández, Neuropsicólogo R.M."Las Eras" - Asociacion Mensajeros de la Paz Extremadura (rmhernanperez@mensajerospazex.es): "Buenas tardes, Pilar ha acudido hoy a consulta de psiquiatría en Plasencia. Adjunto informe con el ajuste de tratamiento. También adjunto el informe de situación actual y su escrito anexo que ha llevado a consulta. La próxima consulta será el 3 de febrero de 2025" ············· *Pero no adjunta Informe de Psiquiatría, lo que adjunta es la NOTA DE TRATAMIENTO, le ha reajustado la medicación. Guardo todo en el expediente digital. ··································································································································································································· Envío correo a Ana Benavente, TS ESM-Plas. (anamaria.benavente@salud-juntaex.es): "Espero que estés bien. No sé si estarás de vacas, pero cuando te sea posible, ¿podrías solicitar a la Dra. Rosa María Galindo, el Informe de Psiquiatría de la consulta del pasado viernes día 9/08/2024, relativa a Dª. PILAR DIEZ SANTIAGO, cuyo cargo de CURATELA REPRESENTATIVA ostenta la CTAEx? Adjunto: - el modelo de solicitud que me remitiste en su día firmado digitalmente por suplencia de la Representante Legal (Directora Gerente del SEPAD) - Resolución del Régimen de Suplencias de la Consejería vigente" ······································································································································· Ana Benavente, TS ESM-Plas, me remite INFORME CLÍNICO de la Dra. Galindo. Guardo en el expte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2024-08-13','ALBERTO : PTO. PERMANENTE TRAS EL PASO A R.MAYORES : CONFORME A LA NUEVA SITUACIÓN: CENTRO: 722 €/MES + REINTEGRO: 90 €/MES + VIVIENDA: 110 €/MES: EL AHORRO ANUAL ES INFERIOR A 600 €. X TANTO...A TUTELADA/CENTRO, TIENE QUE QUEDARLE MUY CLARO QUE EL NIVEL DE VIDA QUE LLEVABA HASTA AHORA O LAS PRETENSIONESE QUE PERÍOCIAMENTE EXPONE EN CUANTO A LOS ARREGLOS DE LA VIVIENDA...YA NO SON POSIBLES. A NIVEL ECO NO HAY INCONVENIENTE EN QUE GASTE SUS INGRESOS...PERO NO SE PERMITIRÁ QUE HAYA BALANCE NEGATIVO EN NINGÚN MOMENTO....X TANTO...REITERO QUE A TUTELADA/CENTRO LES TIENE QUE QUEDAR CLARO QUE EL MÁXIMO DE EXTRAS....INCLUIDAS SALIDAS, VACACIONES, VIVIENDA, OTROS...NO PUEDE SUPERAR ESOS 600 €/AÑO. EL SALDO EXISTENTE A DÍA DE HOY SE DEBE RESERVAR PARA FUTUROS GASTOS ASOCIADOS A SU SALUD: EJEMPLO: ABONO AUDIFONOS X 2.300 € EJEMPLO: INGRESO EN OTROS CENTROS X PROBLEMAS DE SALUD...LO SUSTITUIRIAMOS X ACOMPAÑAMIENTOS O SIMILARES. A MODIFICAMOS REINTEGRO PERMANENTE A LOS 90 €/MES (ANTERIOR 450 €/MES) QUE SE PROPONEN.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='VALLE'and apellido2='SIMON'),'2024-08-13','Ana: Correo de Alberto, Jefe de Secc. Ecca.: "ANA/ESTRELLA: OK A PRESUPUESTO 500 € DERMATOLOGÍA." ·············································································· Envío a Sheila, CRR CC (crr@grupociudadjardin.com) el documento de Cláusula de Consentimiento Informado y Autorización de tratamiento de datos de la Clínica de dermatología. ··· Informo que se ha autorizado el pago y que se encargará de abonarlo Estrella, compañera secc.ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2024-08-13','Ana: Correo de Alberto, Jefe de S. Ecca: "2024/08/12 (MAITE/ÁNGEL/ALBERTO): CON INDEPENDENCIA DE QUE YA EXISTEN COMUNICACIONES PREVIAS AL JUZGADO X LA MALA "PRAXIS" DEL TUTELADO, SE HA DECIDIDO: • COMUNICAR AL JUZGADO QUE X LOS MOTIVOS QUE SE INDIQUEN (MAITE ELABORA INFORME Y REQUIERE "OK" DEL TUTELADO), SE PROCEDE A ESTABLECER UN REINTEGRO PERMANENTE X LA TOTALIDAD DE LA PENSIÓN (MAITE ACORDARÁ CON TUTELADO LOS TÉRMINOS). • A LOS POCOS AHORROS CON LOS QUE CUENTA EL TUTELADO (DERIVADOS DE SU ESTANCIA EN LA CARCEL) NO SE LE PERMITIRÁ EL ACCESO, BAJO NINGÚN CONCEPTO Y SE MANTENDRÁN PARA HACER FRENTE A POSIBLES E INELUDIBLES GASTOS QUE HUBIERA QUE AFRONTAR O A EMBARGOS O SIMILARES."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MINERVA'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2024-08-13','NUEVO TF DE LA MADRE DE MINERVA , PEPI 672952970.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='PEREO'and apellido2='REBOLLO'),'2024-08-13','Ana: Correo de Paula, TO - CRR Plas (tocupacional.crrplasencia@grupo5.net): "os informo de que por motivos de salud física de la hermana de Antonio Pereo Rebollo la salida para los días del 15 al 18 se aplaza de manera indefinida. Si se fijaran nuevas fechas en el futuro os vamos informando."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2024-08-13','Ana: Estrella Durán, TS CSS Plas., me envía el Informe de Salud - Anexo II, para solicitar nuevamente valoración de Dependencia. ···································· Cumplimento la solicitud de valoración de dependencia y la subo al portafirmas digital. ··········································· Envío a Antonio Suárez, Adtvo. de la U.G.PP.AA (antonio.suareza@salud-juntaex.es): "Hoy te envío, para que cuando puedas, registres en TRAMITA, la siguiente documentación relativa a JULIA MORÓN HERNÁNDEZ, cuyo cargo ostenta la COMISIÓN TUTELAR DE ADULTOS: - Solicitud de Revisión de Dependencia – Anexo I - Informe de Salud – Anexo II - DNI de la persona física que ejerce el cargo actualmente - Decreto de nombramiento - Resolución de Delegación de funciones - Resolución del Régimen de Suplencias de la Consejería vigente Para remitir a UNIDAD DE GESTIÓN DE ACCESO Y VALORACIÓN DE DEPENDENCIA al Buzón de Revisión de GRADO: A11032816" ··· *En la solicitud indico sea valorada por la INSTRUCCIÓN 47.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MINERVA'and edp.apellido1='MARTIN'and apellido2='BLANCO'),'2024-08-13','Amalia : Soliicito a Futuex que haga seguimiento en la casa . Voy a poner SAD privado unas horas para ducharla y preparar su ropa , en un lavanderia privada .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='RODRIGUEZ'and apellido2='ROBLES'),'2024-08-13','tf Fco. Javier 699346264 LLama para pedir dinero , se le deniega.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA PRISCILA'and edp.apellido1='SAQUERO'and apellido2='SANCHEZ'),'2024-08-13','Ana: Correo de Ángel, A. Jurídico CTAEx, a Alberto, Maite, Miguel y a mí: "En relación con este asunto, la vivienda en cuestión sigue inscrita, tanto en el Registro de la Propiedad, como en el catastro, a nombre de la madre y los herederos de ésta. La única heredera es la curatelada. No está hecha la herencia. El Ayuntamiento nos comunica que el estado en el que se encuentra es muy defectuoso, pudiendo iniciar un expediente de ruina, nos dan 3 meses para que actuemos. He hablado con el Alcalde y me comenta que la vivienda se encuentra en muy mal estado, por fuera, porque por dentro no han podido acceder. Que hace unos 10 años tuvo oportunidad de entrar en la vivienda y ya entonces había grietas en las paredes/techos, con lo que ahora debe estar aún peor. Que los tejados, una parte son de uralita, otras de tejas, que los techos son de palos de madera, que probablemente estén descolgados. Las fotos que pueden verse en la fachada, en el Google maps son del 21, ya puede observarse que están en mal estado, con humedades. Que en el municipio han reparado viviendas en mismas circunstancias y que siendo más pequeñas que esta, se gastaron más de 50.000 euros. Por otro lado, el expediente de ruina es aún más costoso. Por este motivo y si os parece bien, antes de proceder a tomar un camino u otro, vamos a autorizar al Ayuntamiento para que puedan entrar en la vivienda y nos envíen un informe técnico, tanto del interior, como del exterior y, una vez tengamos esa información, estaremos en disposición de, bien reparar/ruina o renunciar a la herencia."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MARIO'and edp.apellido1='SAN'and apellido2='ROMAN BLASCO'),'2024-08-13','Ana: envío a Toni-Futuex, "...nueva DERIVACIÓN AL PROGRAMA, relativa a D. JUAN MARIO SAN ROMÁN BLÁSCO, residente actualmente en el Centro Sociosanitario de Plasencia."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2024-08-14','Ana: Envío correo a Carmen, hermana de Enrique (maluker6@hotmail.com): "Espero que esté bien. Tan sólo comunicarte que mis compañeras de la sección económica ya han abonado la factura del agua (1574,05€). Pongo en copia a Cristina, Trabajadora Social de referencia del Centro Sociosanitario en la actualidad, para su conocimiento." ······························································································································································································· Enío a Jaime, Aux. Adtvo. CTAEx (jaime.munoz@salud-juntaex.es): "adjunto la siguiente documentación: - Solicitud de REVISIÓN del grado de dependencia por empeoramiento (Anexo I) - Informe de Salud (Anexo II) - Testimonio de Auto de medidas de apoyo - DNI – Representante Legal - Decreto nombramiento Directora Gerente – SEPAD - Resolución Delegación de Funciones como PRESIDENTA de la CTAEx - Resolución de suplencias de los órganos de la consejería vigente - Para remitir por REGITRO a UNIDAD DE GESTIÓN DE ACCESO Y VALORACIÓN DE DEPENDENCIA - Buzón de Registro de Revisión de GRADO: A11032816" ······························································································································································································ Envío nuevo correo a Jaime - CTAEx: "Adjunto la siguiente documentación relativa a D. ENRIQUE SANTOS GARCÍA PUENTE: - Solicitud de RECONOCMIENTO DEL GRADO DE DISCAPACIDAD - Informe de Psiquiatría - Testimonio de Auto de medidas de apoyo - DNI – Representante Legal - Decreto nombramiento Directora Gerente – SEPAD - Resolución Delegación de Funciones como PRESIDENTA de la CTAEx - Resolución de suplencias de los órganos de la consejería vigente Para remitir por REGITRO a la atención del Sr. Director del CADEX del CADEX de Cáceres."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='GONZALEZ'and apellido2='BERMEJO'),'2024-04-24','Ana: Correo de Alexandra Alfonos Maextre, TS RR.MM. Coria (alexandra.alfonso@coria.org) a Miguel, A. Jurídico: "Soy Alexandra, Trabajadora Social de la Residencia de Mayores de Coria. Hace unos días, nos llamaron desde el Juzgado de esta localidad para hacer una revisión de medidas de un residente nuestro: FRANCISCO JAVIER GONZALEZ BERMEJO con DNI: 76009172-Z. El motivo por el que me pongo en contacto con usted, es porque me comenta la Médico Forense que Francisco está incapacitado, de ahí la revisión de medidas, y que la tutela la tiene la Comisión Tutelar de Adultos. Le solicito una copia de la sentencia de incapacitación y me comenta que la debo solicitar a la Comisión Tutelar de Adultos que ejerce su tutela. Desde este Centro se desconocía la situación, ya que este residente ingresó por Decreto.Me pongo en contacto con la compañera de la Comisión Tutelar y me dice que igualmente no tienen constancia de la situación de este residente y es quien me aconseja que le escriba."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='GONZALEZ'and apellido2='BERMEJO'),'2024-07-19','Ana: Correo remitido desde el ctutelar@ a Alexandra, TS RR.MM. Coria, con copia a Miguel, A. Jurídico, y a mí: "En relación con su correo, envío sentencia de incapacitación de Francisco Javier González Bermejo y nombramiento de tutor a la Comisión Tutelar de Adultos de Extremadura, así como Auto de incompetencia territorial de los Juzgados de Navalmoral de la Mata, a favor de los de Coria, al residir Francisco Javier en la Residencia de mayores de esta localidad. Actualmente, se está tramitando en los Juzgados de Coria, el procedimiento de revisión de las medidas judiciales acordadas. Por este motivo, precisamos que nos envíen, a la mayor brevedad posible, un Informe que incluya: ..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN LUIS'and edp.apellido1='LOZANO'and apellido2='ORDOÑEZ'),'2024-08-14','-Amalia . Realizado el Plan de Intervención. Contacto con la TS del CSS ( Mª Angeles Galindo) que es donde reside hace años . Su anterior tutora era la hermana , ejercía mal el cargo. Sin relación con familiares, una sobrina empieza a visitarlo. Tiene P. Jubilación pte. de 680€ y muchos ahorros y una casa en Villagonzalo. La Dtra. del CSS tiene autorización para sacar el dinero que precise , no tiene ropa , calzado .. y debía al centro un dinero , poco, que la hermana no había abonado. Cancelarán la deuda en el próximo reintegro. Tiene S. decesos. Muy adaptado al centro , no quiere tener salidas terapeuticas con Futuex.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='PEREO'and apellido2='REBOLLO'),'2024-07-15','Ana: Correo de Carolina Monroy, Directora CRR Plas (direccion.crrplasencia@grupo5.net): "Te escribo para informarte que desde el CRR algunas personas usuarias están organizando un viaje a la playa de forma autónoma a través de una agencia de viajes de un día de duración (ida y vuelta en el mismo día a Cádiz). Antonio Pereo es una de las personas interesadas a ir, y aunque no conlleva pernocta nos gustaría inforaros para que valoreis si os parece correcto. Por nuestra parte no hay problema y creemos que se encuentra estable como para poder ir junto con 5-6 compañeros y pasar un día en la playa. La agencia que lo organiza es Viajes Rubio, el 10 de agosto. Con un precio de 40 € (autobús), luego han buscado un restaurante en la misma playa a la que van que tiene un coste de 14,50 €. No necesitamos extras especiales, considerando que sí es capaz de hacer el ahorro suficiente hasta la fecha y lo sobrante del mes podría participar sin problemas. Sólo queriamos informaros por si veis alguna objeción."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE BLAS'and edp.apellido1='CAÑAS'and apellido2='LOZANO'),'2024-08-14','Ángel: Recibo la llamada del hermano, Juan Manuel (687819309), está interesado en formalizar la herencia de su padre fallecido en 2021 y poner en venta una casa, en la que viven su madre y José Blas. Tienen oferta de compra por 90.000 euros. La idea es que con lo que obtentan de la venta, se vayan a vivir a otra casa, según él, comprándola. Me facilita su correo (jmcl1966@hotmail.com) y le envío correo, para que me remita toda la documentación de la que disponga y estudiemos el caso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CESAREO'and edp.apellido1='PANIAGUA'and apellido2='CALLE'),'2024-08-14','Ana: envío correo a Toni, Futuex, con copia a Maite, Jefa CTAEx: "En relación a la citación que adjunto y que ya te envié a fecha de 18 de junio, quería preguntarte si llegasteis a contactar con CESAREO PANIAGUA y/o con el cura de la entidad para entregarle dicha citación y ver si podéis retomar el seguimiento. En caso contrario, necesitaríamos nos enviaseis un informe con los intentos realizados y los resultados obtenidos, firmado, para poder comunicar al Juzgado la imposibilidad de contactar con él y hacerle llegar la cita."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2024-08-13','Maite: José Vicente ha remitido un escrito a través de la trabajadora social de los servicios sociales de Villanueva de la Serena( Mª José), solicitando gestionar su pensión de forma íntegra. Se lo hemos pedido nosotros para enviarlo al juzgado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2024-08-14','Maite: Se ha acordado lo siguiente: TODAS: CUALQUIER REIVINDICACIÓN ECONÓMICA SOLICITADA X EL TUTELADO, SERÁ REMITIDA DE FORMA AUTOMÁTICA A LA TRABAJADORA SOCIAL DE REFERENCIA O A MAITE. TAL Y COMO SE HA PACTADO CON EL TUTELADO: • REINTEGRO PERMANENTE X 500 €/MES ENTRE EL DÍA 25 DE CADA MES Y EL 15 DEL MES SIGUIENTE. ESTRELLA: TRAMITA ESTO XFA, A PARTIR DEL 25/08/2024. • NO SE ABONARÁ NI UN SÓLO GASTOS EXTRA...ES IRRELEVANTE QUE TENGA ALGO DE DINERO AHORRADO...NO SE AUTORIZARÁ REINTEGRO O PAGO ALGUNO BAJO NINGÚN CONCEPTO. • SE DEVOLVERÁN INMEDIATAMENTE Y SIN NINGÚN AVISO, CUALQUIER DOMICILIACIÓN O RECIBO QUE PUDIERA CARGARSE EN CUENTA...A DÍA DE HOY NO SE HA AUTORIZADO NINGUNO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2024-08-14','Ana: Llamada de Doroteo (609 928 621): ha tenido reunión con Paula. Ésta le ha dicho que como no puede justificar el gasto como regalo de boda de su sobrina, no se lo van a dar del extra anual. ································· Envío correo a Alberto, Jefe S. Ecca.: "... pide un EXTRA en concepto de REGALO DE BODA, de entre 250-300 €. Por mi parte, si es viable, ok a este extra. Ya me decís si se concede y cuándo podría ir a retíralo para comunicarlo al CRR." ········································· Respuesta de Alberto, Jefe Secc: "CLARO QUE ES VIABLE, PERO EN TEORÍA ESTO SE CORRESPONDE CON EL EXTRA ANUAL...NO DEBERÍAN SOLICITARNOS NADA...EXCEPTO EL EXTRA ANUAL!!! SE LES ABONO (DESCONOZCO SI TODO O PARTE): EXTRA ANUAL EL 23/02/2024 X 900 €" ························ Escribo a Paula, TO CRR (tocupacional.crrplasencia@grupo5.net): "Te reenvío correo-respuesta de Alberto en relación al EXTRA que solicita DOROTEO DÍAZ CERRO. Por tanto el regalo a su sobrina, al igual que la comida a la que quiere invitar a sus hermanos, debe asumirlo con el dinero que tiene en el centro restante de su extra anual (él me dijo que aún le quedan 700€). Por favor, comunicárselo también a él."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2024-08-14','Ana: Subo al portafirmas digital la SOLICITUD DE REVISIÓN DEL GRADO DE DEPENDENCIA. *Marco también la solicitud de Serv. Att. Residencial de Salud Mental, pues verbalizó en el CRR la aceptación de ingreso en CRR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA PRISCILA'and edp.apellido1='SAQUERO'and apellido2='SANCHEZ'),'2024-08-14','Ana: Correo de Alberto, Jefe S. Ecca: "SALDO BANCARIO 14/08/2024: 70.230,55 € EVOLUCIÓN : ACTUALMENTE INGRESOS=GASTOS APROX. EDAD: 83 AÑOX APROX."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FEDERICO'and edp.apellido1='APONTE'and apellido2='SOLIS'),'2024-08-14','Amalia : contacto con EVa , TS Ctro Salud para que nos pase informe social EXT 84925 Los lunes va al Ctro. Salud de Guareña.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2024-08-14','Ana: Correo de Sonia Bernabé, TS Asindi: "te escribo para comunicarte que tenían que irse los hermanos Justo y Roberto Hernández Castaño para ver a su madre pero no va a poder ser. He hablado con la madre y me dice que hay discusiones en la casa del hijo donde está viviendo ahora mismo y no cree conveniente que vayan. Ha preguntado a su hija que vive en Cáceres si podrían ir a pasar un fin de semana y, por lo visto ha alquilado la habitación que tenía libre, entonces tampoco puede ser. Le he insistido en que les llame o haga videollamadas para que mantenga el contacto porque ella quiere. Está preocupada porque no ve solución. Quiere alquilar una casa pero dice que el dinero que cobra no le da para el alquiler y poder comer y otros pagos,... Bueno, voy a llamar a Merche de Cruz Roja para que sepa que no hay servicio. En Septiembre volvemos a intentarlo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROBERTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2024-08-14','Ana: Correo de Sonia Bernabé, TS Asindi: "te escribo para comunicarte que tenían que irse los hermanos Justo y Roberto Hernández Castaño para ver a su madre pero no va a poder ser. He hablado con la madre y me dice que hay discusiones en la casa del hijo donde está viviendo ahora mismo y no cree conveniente que vayan. Ha preguntado a su hija que vive en Cáceres si podrían ir a pasar un fin de semana y, por lo visto ha alquilado la habitación que tenía libre, entonces tampoco puede ser. Le he insistido en que les llame o haga videollamadas para que mantenga el contacto porque ella quiere. Está preocupada porque no ve solución. Quiere alquilar una casa pero dice que el dinero que cobra no le da para el alquiler y poder comer y otros pagos,... Bueno, voy a llamar a Merche de Cruz Roja para que sepa que no hay servicio. En Septiembre volvemos a intentarlo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2024-08-14','Ana: Correo de Estrella Durán, TS CSS- Plas (estrella.duranc@salud-juntaex.es): "Adjunto remito los documentos necesarios cuando ingresan en la UHDAC para la firma de su tutora, relativos a Felisa Bruno Saavedra. Cuando estén firmados, me los reenvías por favor" ······························································································································································································· Nuevo correo de Estrella, TS: "ésta venía con una ortodoncia puesta, se ha quitado el "alambre", solo le quedan los braker. Desde el equipo se está valorando el quitárselos, de hecho el lunes llamaré a la clínica Vivanta de Plasencia para tal fin. Lo comunico para el tema de pagos etc..." ····················· Mi respuesta: "He hablado con Maite sobre la ortodoncia, pedid la cita y que valoren en la clínica dental la conveniencia o no quitársela" ····························································································································································································· Subo al portafirmas digital el documento remitido por Estrella: "AUTORIZACIÓN EXPRESA + COMPROMISO FORMAL"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='TRINIDAD'and apellido2='ESTEBAN'),'2024-08-14','Ana: guardo en su expediente digital la carta de PNC, solicitando ALTA DE TERCEROS. ················································································· Envío a María, Secc. ecca: "Adjunto el ALTA DE TERCEROS relativo a MIGUEL TRINIDDAD ESTEBAN para que lo remitáis al banco. Esperemos que sirva con la firma digital."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2024-08-16','Ana: Envío correo a Estrella Durán, TS CSS: "Adjunto: - La AUTORIZACIÓN EXPRESA - El COMPROMISO FORMAL De ingreso en UHDAC relativos a FELISA BRUNO SAAVEDRA, firmados digitalmente por el suplente de la Representante Legal."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GLORIA'and edp.apellido1='VERA'and apellido2='LLORENTE'),'2024-08-16','Ana: correo del día 14 de Estrella Durán, TS CSS (estrella.duranc@salud-juntaex.es): "Acabamos de terminar una subcomisión regional el la que hemos hablado entre otros casos de Gloria Vera Llorente. Hemos quedado con Soraya Masa, que, si ya tenéis aceptado el cargo, se podría pedir revisión PIA y también del perfil del Cadex..." ················································································ Mi respuesta: "Este cargo ha sido aceptado recientemente (mes de julio). Se ha solicitado ya al Juzgado el Testimonio de la Aceptación del cargo y, aunque estamos pendiente de que nos lo envíen, hemos comenzado ya a elaborar el inventario que nos exigen (nos dan 60 días para conformarlo). De hecho el compañero ya ha comenzado a solicitar de oficio todos los documentos pertinentes (al CADEX, al INSS, a vuestro centro…). Normalmente no podemos empezar a intervenir hasta que enviamos al Juzgado el INVENTARIO. Además, como sabes, el Juzgado nos suele manda la sentencia/auto “pelada y mondada” y de entrada no tenemos más información. Eso sí, he visto en el expediente un informe de marzo que remitiste tú, firmado por la Psicóloga y la Psiquiatra. Indicabais que se emitía a petición de la CTAEx y me resulta raro que se os haya pedido meses antes de aceptarse el cargo, pues hasta ese momento, en teoría, no debemos pedir documentación alguna al no ostentar la CTAEx el cargo. De todos modos, no habrá problema en solicitar la revisión PIA, para lo que nos tendréis que facilitar el Informe de Salud (Anexo II) y el Índice de Barthel para adjuntarlo a la solicitud. El perfil del CADEX lo piden las compañeras de la sección correspondiente cuando reciben de dependencia la solicitud de plaza residencial." ····························································································································································································· Según el Informe de la UHDAC, firmado por la Psicóloga y la Psiquiatra, permanece ingresada en dicha unidad desde el 20/07/2023, procedente de la UHB de Mérida, tras subcomisión regional en que se acordó ingreso preferente. ··· Mantiene buena relación con el padre, quién llama con frecuencia para interesarse por ella. "La comunicación con el sistema parental es únicamente a través del padre." En los pases a domicilio se da buena conducta y disfrute, sólo en una ocasión protagonizó una ingesta medicamentosa. ···· "Muy activa en actividades de ocio y ocupacionales." "Altamente funcional y autónoma para las AVD y el cuidado personal", "sin problemas de comunicación" ,"Toma correcta de medicación con supervisión". "Con planes de futuro de acercamiento a su casa y ocupación de plaza en centro residencial". ···································································································································· *Según AUTO, se trata de una CURATELA "CON FUNCIONES REPRESENTATIVAS para realizar los actos de carácter patrimonial y económico, de naturaleza contractual y administrativa, así como para los actos de carácter personal y en particular, cuidado personal, aseo e higiene, vestido, alimento, descanso; especialmente, en aquellos que sean necesarios para asegurar el control del tratamiento médico prescrito por los facultativos para sus enfermedades, así como los necesarios para proceder al ingreso hospitalario o internamiento en centro adecuado a sus circunstancias si fuera oportuno, cuando su estado o su salud así lo requieran y en la gestión de su patrimonio." ················· Según Certificado y Dictamen Técnico del CADEX tiene reconocido un 75% de discapacidad. Presenta: Trastorno Cognitivo, Discapacidad Intelectual LEVE, Deficiciencia del Sistema Nervioso y Muscular y Hemiparesia Izquierda entres otros diagnósticos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='CANTERO'and apellido2='JIMENEZ'),'2024-08-07','Ana: Llamada de Mª Pilar Cantero, hermana de Antonio (649 619 458): comunica que han designado a la CTAEx CURADORA REPRESENTATIVA de Aº. El juicio tuvo lugar el día 26 de junio y el AUTO tiene fecha de 03/07/2024. *Aún no es firme. ········ Antonio vive en Valdefuentes y ella en Cáceres. ········ Ella se propuso como Curadora, pero el Juez, por entender que puede haber conflicto de intereses no la ha nombrado. ························ Dice que ella le da de su dinero mensualmente 400€ y su padre le da 50€/día, pues sino le amenaza y ya está mayor. ·························· Me informa que su hermano tiene 59 años, presenta Patología de Salud Mental + Consumo de Alcohol, pero no lo reconoce. *Está en tratamiento psiquiátrico. ··········· Tiene reconocida Discapacidad desde los 8-9 años, pero sus padres siempre se lo ocultaron a Antonio. ·············· Tiene varias propiedades procedentes de herencia, ella tiene miedo de que dilapide todo en poco tiempo y luego no tenga para vivir.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='CANTERO'and apellido2='JIMENEZ'),'2024-08-12','Ana: Hoy mismo se ha solicitado la FIRMEZA DEL AUTO de Curatela de Antonio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-08-16','Ana: Tras llamada de José Manuel, envío correo a Toni y Nieves, Futuex, y a los A. Jurídicos: "Tan sólo comunicaros que me ha llamado José Manuel Romero Mediavilla diciendo que le han llamado tanto a él como a su hermano José Luis, para informarles que la cita con el Médico Forense prevista para el día 19 de agosto (lunes) la posponen la día siguiente, martes 20 a la misma hora. Estaba previsto que le acompañara Nieves. Nieves, espero que puedas cuadrar en agenda acompañarle el martes."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JONATAN'and edp.apellido1='GARCIA'and apellido2='TERRON'),'2024-08-19','Ana: Jaime me confirma que pidió el TESTIMONIO DE LA ACEPTACIÓN DEL CARGO el día 7/08/2024. **Se trata de CURATELA ASISTENCIAL, no representativa. "...respecto los ambitos económicos-jurídicos-administrativo y contractuales... así como respecto de la aministración de sus ingresos"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2024-08-19','Ana: Envío correo a Alberto, Jefe S. Ecca: "Te reenvío correo de Laura, TS de La Once, en relación al viaje de Navidad al que lleva yendo Ventura los últimos años. Como puedes ver en el documento adjunto: “El precio de este turno vacacional asciende a TRESCIENTOS OCHENTA y NUEVE EUROS (389 €) por persona en habitación doble, pues si bien el coste total de cada plaza vacacional es muy superior, se encuentra subvencionado por la ONCE aproximadamente en más de dos tercios.” Por mi parte, un año más, ok al mismo. Si me confirmas cumplimento y subo los documentos pertinentes a la firma correspondiente." ······················································································· Respuesta de Alberto, jefe s. ecca: "ANA: VACACIONES 2024: OK AL PAGO DE 389 €....CUANDO HAYA QUE ABONAR SE LO PASAS A MARIA. MARIA: ABONAMOS CUANDO/COMO NOS INDIQUE ANA. ANA: CATERING...TENGO ANOTADO UN PRECIO DE 185 €/MES, PERO LA REALIDAD ES DE 230 €/MES DESDE INICIO (EN MES DE 05/2024): SIN PROBLEMA ECO...SÓLO X SI QUIERES VERLO. MARIA: XFA, TRANSFERENCIA PUNTUAL X 3.500 € DESDE UNICAJA A CAIXABANK "TRANSFERENCIA INTERNA DESDE UNICAJA" PARA ATENDER LOS GASTOS DOMICILIADOS EN CAIXABANK (YA QUE EN ESTA CCC NO HAY INGRESOS)" ········································································································· Subo al portafirmas digital: SOLICITUD DE VACACIONES DE NAVIDAD, CONSENTIMIENTO PARA EL TRATAMIENTO DE DATOS PERSONALES y AUTORIZACIÓN DE DERECHOS DE IMAGEN. ·················································· Envío a Laura, TS ONCE (LASS@once.es) los documentos anteriores ya firmados, junto con la Resolución de las Suplencias de la consejería. ····· *Este año el hotel está en Alicante, del 22 de diciembre de 2024 y el 2 de enero de 2025. ······································································································································································································· En otro correo de Alberto, informa: "ANA/ALBERTO: GASTO PROSEGURO NO SE HABÍA AUTORIZADO. MARIA (URGENTE): EN CCC CAIXABANK HAY 2 CARGOS "PROSEGUR"...SALVO QUE ANA LO HAYA AUTORIZADO, DEVOLVEMOS INMEDIATAMENTE + INFORMAMOS DE QUE DEN DE BAJA ESTA DOMICILIACIÓN Y NO LA VUELVAN A ACEPTAR" ···· Es de prosegur alarmas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2024-08-19','Ana: Correo de Paula, TO CRR-Plas: "...Por nuestra parte pasaremos a facilitarle la cantidad solicitada por él y os informaremos, en su caso, si necesitara de alguna otra cantidad más allá de los extras anuales acordados."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2024-08-19','Ana: Correo de Estrella Durán, TS CSS Plas. (estrella.duranc@salud-juntaex.es): "En reunión de equipo se ha puesto de manifiesto que Julia quiere ir al pueblo a ver a su madre, pero la comunicación con bus es complicada, para que vaya y vuelva en el día. Habíamos pensado que a lo mejor, la puede acompañar Clara de Futuex, no sé si dispone de coche para ello...., porque taxi entiendo que no dispone de ese dinero para tal fin..." ····················· Llamo a Estrella, le explico que los vehículos que utilizan las Educadoras de Futuex son personales, no va a llevar a Julia. ········· Abonar un taxi, dada su situación económica aún no es conveniente. ···· Le pregunto si la familia le ha ido a visitar, pero dice que sólo el padre. ···· Hablará con la madre al respecto para promover una visita al centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2024-08-19','Ana: Tras concretar con Estrella Durán, TS CSS, envío correo a la secc. ecca: "Cuando te sea posible, hay que enviar AUTORIZACIÓN DE CENTRO PARA RETIRADA DE EFECTIVO para GASTOS DE BOLSILLO, relativo a FELISA BRUNO SAAVEDRA, que actualmente está ingresada en el Centro Sociosanitario de Plasencia. Se ha acordado un máximo mensual de 50 €." ······························································································································································································· Llamada de Estrella Durán, TS y Catia, Médica Somática del CSS-Plas: Catia expresa que considera necesario que le quiten la ortodoncia a Felisa. Se ha arrancado el alambre. Todo su afán es hacerse daño para que la lleven a urgencias del hospital. Se intenta arrancar también las otras piezas de la ortodoncia y considera que supone un riesgo tanto para ella misma como para el resto de pacientes de la unidad. ··················· Acordamos que consultarán a la clínica dental, pues no sabemos el tiempo que le quedaría de tratamiento. ··········································· Correo de Estrella Durán: "hablé con la clínica de Plasencia, me dice que esa valoración debe hacerla la Ortodoncista de Don Benito que es la que la ha pautado. Llamo a Don Benito y me dicen que estos tratamientos suelen durar 2 años, y ella lleva escasos meses. Así que ya nos decís que os parece que hagamos, ya sabes la opinión de la Médica Somática de este centro..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2024-08-19','Ana: Correo de Toni-Futuex: "Con fecha 09 de agosto de 2024, se realiza visita a Guadalupe para confirmar y acompañar en su caso, a la administración de inyectable de Juan Chamorro en centro de salud de Guadalupe ya que, en Trujillo lugar habitual de administración y seguimiento, están de vacaciones. Como Juan acudió con fecha 23 de julio a consulta de enfermería y psiquiatría a Trujillo tal como tenía programada, decidieron al valorarlo que debían administrarle medicación de rescate en ese mismo momento. Así mismo se recomienda seguir con la administración mensual de Abilify, Por tanto, entre el 8 o 9 de agosto, le correspondía su inyectable pautado mensual y debía ser en Guadalupe por motivo de vacaciones en salud mental de Trujillo. Pero Juan no tenía dicha cita y su planificación era que, el 23 de agosto sería su siguiente inyectable. Se acude al centro de salud para que nos informaran si ya el día anterior jueves 8 de agosto se ha pasado por allí, nos confirman que no, ni tampoco ese dia, viernes 9, de ahí que solicitamos a Fátima la enfermera que nos genere e imprima una cita con fecha actual (que suele requerir las citas en papel, como sabeis) y acudimos al domicilio para comunicarle que le corresponde el mensual independiente de lo que se le administrara el 23 de julio. Y así se hizo, acudimos con la cita al domicilio de Juan chamorro, y para grata sorpresa nuestra, nos atendió con buena interacción, mostrándole la cita, además de explicarle la situación de confusión de fechas que tenía por lo del 23, Incluso se le entrega copia de las citas siguientes en Trujillo que será el 12 de septiembre: trabajador social, enfermería y psiquiatría. Se le acompaña al centro de salud y se administra su inyectable que ya había recogido de la farmacia, acude tranquilo, sin violencia verbal, tan solo presentaba algunas quejas en relación a que le parece mucha medicación en tan poco tiempo, pero con buena interacción en todo momento. Acuerda con la enfermera de centro de salud pasarse unos días antes de la siguiente cita de Trujillo, 12 septiembre, para solicitar ambulancia como acostumbra a hacer."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MORENO'and apellido2='ACERA'),'2024-08-19','Ana: Envío correo a Maite Cañadas, Directora Res. San Fco. Plas. (maria.canadasv@salud-juntaex.es): "...cuando os sea posible, hacednos llegar INFORME SOCIAL en los términos que indica Miguel en el hilo (dos correos por debajo), subrayo en amarillo, para poder remitirlo al Juzgado para la revisión de las medidas de Joaquina."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VENTURA'and edp.apellido1='GOMEZ'and apellido2='GARCIA'),'2024-08-20','Ana: Laura, TS ONCE, confirma que al viaje de PRIMAVERA SENIOR, finalmente Ventura no fue, pues aunque se presentó la documentación hubo tantas solicitudes que quedó fuera en la selección. ····· De hecho no se ha abonado. ············ Confía en que le seleccionen para el de navidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2024-08-20','Ana: Respondo a Estrella Durán, TS CSS: "Teniendo en cuenta que sólo lleva unos meses y los riesgos para ella misma y para terceros que expuso ayer la Médica Somática mediante conversación telefónica, de acuerdo, podéis proceder a pedir cita en la clínica dental para que se le retiren la ortodoncia."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2024-08-20','Ana: Llamo a Ana Setien, Responsable y Enfermera de la Res. Riolobos (677 11 68 46). *Me facilitará todos los informes de alta del hospital de los distintos ingresos que ha tenido José Manuel. Ha estado ingresado bastantes meses (primero en UHB y depués en otros servicios) y se han olvidado de renovar la demanda de empleo. ···· Antes incluso podía ir el solo pero ahora está muy dependiente, incluso tiene que darle de comer y hay días que tiene que usar silla de ruedas. Tuvo pueta una sonda veesical que se arrancó. ··· Estuvo también una temporada muy agresivo, incluso empujó a otras personas mayores del centro, pero la Pisquiatra - ESM, le cambió la medicación y parece que en ese sentido está más tranquilo. ··········· En cuanto a los gastos, sólo tiene los de centro, farmacia y acompañamientos. Las trabajadoras del centro le llevan ropa de sus hijos para que no tuviera que comprarla. ······························································································································································································· Envío correo a Toni y Clara, Ed, Futuex: "En relación a JOSÉ MANUEL MORENO CARLOS, entre los ingresos hospitalarios y demás dificultades que han tenido con él, en la residencia se han olvidado de renovar la demanda de empleo, con lo cual lleva meses sin percibir su SUBSIDIO POR DESEMPLEO. Además él cada vez es más dependiente y necesita más apoyos. Solicitamos, por favor; 1- que a la mayor brevedad, acudáis a visitarle y con los informes médicos de alta de los ingresos hospitalarios que tienen en el centro, acudáis, si puede ser con él, al SEPE y al SEXPE, para renovar la demanda y para presentar la documentación e intentar que se subsane la suspensión del subsidio y no le penalicen por no haber asistido a renovar por causa justificada (ingresos hospitalarios y convalecencia). No tenemos resolución, pero como os digo ha dejado de cobrarla. Si no fuera posible, desistiremos de este subsidio y tramitaré la PNC. *En principio el subsidio era más beneficioso para él porque tendría derecho después a la pensión de jubilación (contributiva), pero quizá tras este parón, si no se subsana, igual ya no tendrá derecho a la misma. Quedo a la espera de la respuesta que os den. 2- Estéis pendientes para las futuras renovaciones de la demanda de empleo, para apoyarle en la gestión, pues desde la residencia me dicen que están desbordadas y no pueden estar pendiente de esta gestión. 3- Intensifiquéis el seguimiento y los apoyos que pueda necesitar y nos mantengáis informadas de su evolución." ································································· Respuesta de Toni: "de acuerdo, esta misma semana el viernes seguramente se hara un seguimiento en Riolobos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2024-08-20','Ana: Llamada de Julia, madre (644 876 893), dice que en estos momento no se encuentra bien para ir a ver a Julia al CSS, le duelen mucho las piernas, otro día ha estado con lumbago y ayer tuvo "colitis". ··· Pero dice que cuando se encuentre mejor irá a verla. ···· Habla con ella con mucha frecuencia, pero le ha dicho que todos los días no porque no hay tanto que contar. ··· Le indico que el simple hecho de escucharla le viene bien porque siente su cariño. ········································ *El municipio de CC en el que vive con su otra hija es ELJAS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTHER'and edp.apellido1='GARCIA'and apellido2='MARTIN'),'2024-08-20','Ana: Llamo a Felisa Custodio, TS CAMF - Alcuéscar (927 121 951): No tenemos en el expediente el Cdo. de Discapacidad de Esther. En el CADEX NO les constan valoraciones en su base de dato. Entiendo que se le valoró en otra CC.AA. Puesto que en el Informe Social indica un 96%, al igual que en el Médico Forense. ··················· *Le valoraron en Castilla León. Me remitirá por correo el Cdo. escaneado para que pueda solicitar al CADEX el traslado del expte. ······························································································································································································ Tras hablar con Maribel, TS CADEX CC (21994), envío correo a cadex.caceres@salud-juntaex.es: "En relación a Dª. ESTHER GARCÍA MARTÍN, cuyo cargo de CURATELA REPRESENTATIVA ostenta la CTAEx, adjuntamos el Certificado de Discapacidad y el Dictamen Técnico Facultativo, facilitado por el CAMF de Alcuéscar, centro en que reside, para que puedan solicitar traslado de expediente a la Gerencia Territorial de Servicios Sociales de Salamanca. Adjuntamos así mismo: - Testimonio de sentencia de las medidas judiciales de apoyo - Certificado de empadronamiento"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='TRINIDAD'and apellido2='ESTEBAN'),'2024-08-20','Ana: envío a Jaime, Aux. Área Social - CTAEx: "adjunto la siguiente documentación para remitir por REGISTRO (TRAMITA) al Servicio de Prestaciones Sociales y Ayudas de la Secretaría General de Servicios Sociales, Inclusión, Infancia y Familia (Nº de buzón: A11030105): - Oficio - Alta de Terceros debidamente cumplimentado y certificado por la entidad bancaria - Escrito remitido por el citado Servicio Pongo en copia a Teresa, para que esté al corriente dado que el expediente es de su zona."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GLORIA'and edp.apellido1='VERA'and apellido2='LLORENTE'),'2024-08-20','Ana: Llamada de Estrella Durán, TS CSS (24146): *Al parecer Gloria debe meses de la plaza del centro de Plena Inclusión en que estuvo previamente, la familia no quiso abonarlo, según me dice ella. Por lo que tendrá deudas. ·························· Por otra parte, ella lleva ya tanto tiempo en la UHDAC, que ha decidido que a partir del mes que viene tiene que comenzar a abonar la plaza (la pondrán como "extópica". ······ *Pido que desde el CSS envíen un correo comunicándolo a ctutelar@. ··· *Le recuerdo a Estrella que aún estamos en fase de inventario y todavía no tenemos acceso a las cuentas. ············································································· Envío correo a Alberto, Jefe Secc. para inoformarle al respecto. ··················································· *Con respecto a la posible deuda, consulto a Belén, TS - Secc. Acceso a RR. Discapacidad, dice que lo hable mejor el jueves con Maribel, su compañera.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTHER'and edp.apellido1='GARCIA'and apellido2='MARTIN'),'2024-08-21','Ana: Correo de Alberto, Jefe S. Ecca: "TOD@S: SE HA ELABORADO UN INFORME QUE SERÁ REMITIDO A UNICAJA...PREVIAMENTE LOURDES LO REMITIRÁ "OFICIOSAMENTE" A JUANA (UNICAJA) PARA QUE LE ECHE UN VISTAZO PREVIO...A TRAVÉS DEL CUAL SOLICITAMOS LA CONDONACIÓN TOTAL/PARCIAL DE LOS PRÉSTAMOS O CUALQUIER OTRA SOLUCIÓN QUE UNICAJA PUDIERA IDEAR PARA ALIVIAR LA SITUACIÓN DE LA TUTELADA."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ESTHER'and edp.apellido1='GARCIA'and apellido2='MARTIN'),'2024-08-21','Ana: Correo de Alberto, Jefe S. Ecca: "','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='LANCHO'and apellido2='SANGUINO'),'2024-08-21','Ana: Correo de Alberto, Jefe S. Ecca: "ESTRELLA: ABONAMOS LAS FACTURAS PENDIENTE Y, EN PRINCIPIO, DOMICILIAMOS LAS MISMAS EN RELACIÓN CON EL DOMICILIO QUE FIGURA AL INICIO DE ESTOS CORREOS APARECE UN ENLACE...SI NO ACCEDES IMAGINO QUE TENDRÁS QUE HABLAR CON AYUNTAMIENTO Incluyo copia (cursiva) del correo de Miguel...ha hablado con el Ayuntamiento de Malpartida y le confirman que debemos abonar facturas. ..." ······························································································································································································· Reenvío el correo a Estrella, TS del SSASB de Malpartida de Cáceres (ssb@malpartidadecaceres.es).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2024-08-21','Ana: Conversación con la Dra. Carmen Perez, Psiquiatra HVP - Plas. Me pide le solicite el informe por escrito a la dirección mariacarmen.perezp@salud-juntaex.es. ················ Envío correo: "Tal y como hemos acordado mediante conversación telefónica, te envío este correo para solicitar el Informe del ingreso y alta en 2024 en la UHB relativo a JOSÉ MANUEL MORENO CARLOS, cuyo cargo de CURADOR ostenta la Comisión Tutelar de Adultos, a los efectos de ejercer adecuadamente el cargo asignado. Adjunto: - Testimonio de Auto de nombramiento - Testimonio de firmeza del mismo" ··························································································································································································· *Guardo en el expte. digital el INFORME DE ALTA de UHB recibido. ·· Estuvo ingresado desde noviembre 2023 - marzo 2024.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSA'and edp.apellido1='MONTALBAN'and apellido2='SERRANO'),'2024-08-21','miguel, queda aplazada la firma de las dos herencias de los hijos de la tutelada a que vuelva de vacaciones la abogada y concretada la información a la notaria de los datos bancarios que le faltaban. La notaria por su parte me enviará el borrador en breve. Hablo con la sobrina, Josefa Perez Montalban 661-268500, y me confirma que el testamento ya fue firmado por su tía, habíendo asistido el notario al centro a finales de julio con esa finalidad, por lo que cuando Loli le entregue el borrador a ella, ésta se lo explicará a la tutelada para dé el visto bueno previo a la firma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='AVILA'and apellido2='FEMIA'),'2024-08-20','Ana: Correo de Alberto Arias Bueso, TO EVD - Brozas (alberto.arias@salud-juntaex.es) a la Secc. Acceso a centros de Salud Mental (saludmental.accesoacentros@salud-juntaex.es): "remito aceptación PIA para inclusión en lista de espera de CRR. El solicitante está tutelado por la comisión tutelar de adultos. Incluyo en el correo a la Trabajadora Social de la comisión para que esté al corriente y se dirijan al Equipo de Salud Mental para derivación."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='AVILA'and apellido2='FEMIA'),'2024-08-21','Ana: Respuesta de la Secc. Acceso a centros de Salud Mental (saludmental.accesoacentros@salud-juntaex.es): "Recibido el PIA de José Luis Ávila Femia, lo guardamos a la espera de que llegue su derivación desde su Equipo de Salud Mental. Una vez llegue, lo valorará la Comisión encargada, y pasaría a la Lista de Espera para acceder a vacante de CRR." ······························································································································································································· Envío correo a Toni y Nieves, Ed. Futuex: "quería preguntaros si ha habido algún avance con respecto a la aceptación de ingreso en CRR. Tal y como se acordó en un inicio con los distintos profesionales de Salud Mental y con Soraya Masa, desde el Gabinete Técnico de la CTAEx solicitamos la REVISIÓN PIA, para que le concedieran plaza. Me comunican desde Dependencia que ya está hecho el trámite correspondiente y enviado a la sección de acceso a recursos de salud mental. Pero falta la derivación desde el ESM, qué él mismo no aceptó. Contactaré con la compañera del Equipo de Salud Mental, para que también lo aborden ellos e intenten que acepte la derivación en las próximas citas. No obstante, por favor, si sigue reacio, seguid abordando con él la cuestión, haciéndole saber que el ingreso no sería inmediato pues hay mucha lista de espera, que sería una opción a un futuro a medio plazo. Ya me vais diciendo." ································································································································································································ Llamo a Pilar Martín, TS ESM - CC: está ocupada, me devolverá la llamada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='VAZQUEZ'and apellido2='GILEZ'),'2024-08-21','miguel, me llama la inmobiliaria Miguel Angel 666679026, que me comenta que la familia del tutelado hace unos 10 años vendió de palabra una vivienda y quieren ahora escriturar la herencia de esos bisabuelos y la venta en la notaria de Agustin Sanabria (Ramón oficial). Quedo en que lleve la documentación a Ramón y él me llame para ver qué trámites vamos a tener que hacer.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PILAR'and edp.apellido1='JIMENEZ'and apellido2='AGUILAR'),'2024-08-21','Ana: envío a Toni - Futuex, la hoja de derivación pendiente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2024-08-21','Ana: Llamada de Jairo, dice que lleva un verano tranquilo, sin hacer nada en espeical. Se encuentra bien. ···· Quiere ir a la UNED, para preparar el acceso a la Universidad para mayores de 25 años, pero pide ayuda para preparar las documentación a presentar y realizar las gestiones de la matrícula. ················· También solicitaré apoyo para la búsqueda de piso de alquiler. ····························································································································································································· Envío correo a Toni-Futux: "Te reenvío correo remitido en junio, para que cuando podáis, retoméis la gestiones a este respecto (búsqueda de vivienda de alquiler). Por otra parte, solicitaros también que a primeros del mes de septiembre, cuando os sea posible, le acompañéis a la UNED y le apoyéis tanto en preparación de la documentación pertinente para aportar, así como en las gestiones de MATRÍCULA paralas clases de preparación a las pruebas de acceso a la Universidad para mayores de 25 años. Según me ha verbalizado en conversación telefónica, necesita apoyo en estos trámites pues él sólo se aturulla. Pongo en copia a Clara, Educadora, y a Cristina, Trabajadora Social del C. Sociosanitario para su conocimiento."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GLORIA'and edp.apellido1='VERA'and apellido2='LLORENTE'),'2024-08-21','Ana: Reenvío a Jaime y María, CTAEx, el INFORME SOCIAL para el Inventario remitido por Estrella Durán, TS CSS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2024-08-21','Ana: Correo de Cristina Hdez., TS del CSS -Plas (cristina.hernandezca@salud-juntaex.es): "veo que Enrique esta valorado con GI de dependencia y podríamos solicitar CRR, mañana comentare al equipo por si comenzamos los tramites."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='MORENO'and apellido2='ACERA'),'2024-08-21','Ana: Envío a Miguel, A. Jurídico, el INFORME MÉDICO que me remite Maite Cañadas, Directora de la Res. San Francisco para la revisión de las medidas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA MARIA'and edp.apellido1='PLESA'and apellido2='GUERRA'),'2024-08-22','Ana: Correo de Estrella Gómez, TS SSASB - Malpartida de CC (ssb@malpartidadecaceres.es): "decirte que ha venido la abuela de Ana María Plesa Guerra, para pedir el traslado más cerca de su casa. Yo opto por que se pueda traer a Ana de vez en cuando a pasar unas horas con los hermanos y abuela, ya que entiendo que el proceso de adaptación de Ana estará siendo duro para ella, como para proponer otro cambio. Este tema lo hablamos en alguna ocasión, pero desconozco si se ha descartado por algo, o si se puede retomar. Ya me cuentas" ·············································································· Respondo: "Sí, esto ya lo hablamos en su día y estamos de acuerdo que es preferible organizar estas visitas yendo Ana acompañada e incluso que la abuela, si su estado de salud se lo permite, pueda ir a visitarla también a ella al centro. Como este expediente lo lleva desde hace ya tiempo mi compañera Teresa, la pongo en copia, pues se incorpora ya a mediados de la semana que viene, para que pueda hablarlo con el centro y contigo para organizar visitas y valorar la primera experiencia. Si todo va bien entiendo que podría seguir haciéndose así."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ROMERO'and apellido2='PEREZ'),'2024-08-05','Ana: Correo de Jesús (susiyesli@gmail.com) al ctutelar@: "...Ha cambiado de propietario el edificio y se ha de depositar la mensualidad o abono de la vivienda a este número de cuenta y banco.." ······································ Jesús reenvía la carta y primera factura de los nuevos propietarios: "Gares Gosoy S.L." de Madrid. ······························ *María, Secc. Ecca., reenvía correo con documentos a los A. Jurídicos para su conomicimiento y por si hubiera que hacer algo más.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ROMERO'and apellido2='PEREZ'),'2024-08-22','Ana: Con respecto a la consulta de Jesús a Mamen, Ed. Futuex, le envío correo: "Confirmarte que mi compañera María está sobre el tema de cambio de domiciliación bancaria debido al cambio de propietario del inmueble en que vive Jesús. Ella llamó al antiguo propietario Miguel Galera Buesas, quién le confirmó que con respecto el abono del mes de agosto, ya domiciliado, él se encargaba de hacer transferencia a la nueva empresa, con lo que quedaba pendiente cambiar la domiciliación para el mes de septiembre. Puesto que aún faltaba casi un mes, lo dejó agendado para hacerlo a finales de agosto. Me acaba de confirmar, dada la preocupación de Jesús, que hoy mismo lo va a gestionar, para que en septiembre ya reciba el alquiler la nueva empresa propietaria: “Gares Godoy S.L.”','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA PRISCILA'and edp.apellido1='SAQUERO'and apellido2='SANCHEZ'),'2024-08-13','miguel, email de Angel: Buenos días, En relación con este asunto, la vivienda en cuestión sigue inscrita, tanto en el Registro de la Propiedad, como en el catastro, a nombre de la madre y los herederos de ésta. La única heredera es la curatelada. No está hecha la herencia. El Ayuntamiento nos comunica que el estado en el que se encuentra es muy defectuoso, pudiendo iniciar un expediente de ruina, nos dan 3 meses para que actuemos. He hablado con el Alcalde y me comenta que la vivienda se encuentra en muy mal estado, por fuera, porque por dentro no han podido acceder. Que hace unos 10 años tuvo oportunidad de entrar en la vivienda y ya entonces había grietas en las paredes/techos, con lo que ahora debe estar aún peor. Que los tejados, una parte son de uralita, otras de tejas, que los techos son de palos de madera, que probablemente estén descolgados. Las fotos que pueden verse en la fachada, en el Google maps son del 21, ya puede observarse que están en mal estado, con humedades. Que en el municipio han reparado viviendas en mismas circunstancias y que siendo más pequeñas que esta, se gastaron más de 50.000 euros. Por otro lado, el expediente de ruina es aún más costoso. Por este motivo y si os parece bien, antes de proceder a tomar un camino u otro, vamos a autorizar al Ayuntamiento para que puedan entrar en la vivienda y nos envíen un informe técnico, tanto del interior, como del exterior y, una vez tengamos esa información, estaremos en disposición de, bien reparar/ruina o renunciar a la herencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2024-08-09','miguel, email de Tere a la parte eco, jur y social (Maite): Hola He recibido llamada del propietario del piso de Pedro para decirme que le continua alquilando el piso porque está recibiendo continuas quejas de los vecinos. Pedro ha roto en varias ocasiones la puerta del piso y ahora ya ha decidido no ponerle mas cerraduras con lo cual el piso esta siempre abierto y se llena de amigos de Pedro los cuales consumen tanto dentro del piso como por las zonas comunes. Comenta que en una ocasione Pedro andaba por el bloque con un cuchillo en la mano, en otra ocasión dejo una sartén al fuego y casi sale ardiendo. Son múltiples las llamada que hacen los vecinos a la policía local por el comportamiento incívico de Pedro. En el último informe de la rendición anual la trabajadora social deja constancia de que la vivienda se encuentra en malas condiciones de habitabilidad y salubridad, tiene almacenados medicamentos y suciedad. Sospecho que está descompensado y creo que lo más conveniente es pedir un ingreso involuntario pues ahora no se encuentra en condiciones para vivir solo en un piso. Toni: necesitamos informe del psiquiatra para poder pedir el ingreso involuntario lo antes posible pues el propietario quiere que lo saquemos de allí rápido pues teme que le pongan una denuncia. ME VOY DE VACACIONES HASTA EL DIA 26 INCLUSIVE, GESTIONARLO CON MAITE','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2024-08-13','miguel, contestacion de Alberto a Tere:TERE: SOSPECHAS QUE ESTÁ DESCOMPENSADO???... MAITE: NECESITO SABER CON URGENCIA (LA SITUACIÓN ECO DE ESTA PERSONA, EN EL MOMENTO EN EL QUE ASUME GASTOS DE ALQUILER NO ES LA MEJOR): • CUANDO DEJAMOS DE ABONAR ALQUILER. • LOS GASTOS RELACIONADOS QUE NOS VAN A RECLAMAR (SI ES QUE LO HACEN), EN RELACIÓN CON EL ARREGLO DEL PISO DE ALQUILER • O INDICARLE AL PROPIETARIO QUE DENUNCIE A TUTELADO, ANTES DE ABONARLE NADA (ÁREA JURÍDICA), SI LLEGA EL CASO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2024-08-22','Ana: Guardo en el expediente los distintos INFORMES MÉDICOS de ingreso en el SERV. MEDICINA INTERNA y de asistencia al Serv. de Urgencias y al PAC a lo largo de 2024, remitidos por Ana Montaña Alamos, Res. Riolobos (alamoseras@gmail.com). ························ Pendiente de valoración por Neurología. ··· Deterioro importante y generalizado. ·································································································································································································· Llamo al SEPE de Plasencia (927 74 89 65): no obtengo respuesta. ··························· Envío un correo (dp10.ratel@sepe.es): "En relación al subsidio por desempleo para mayores de 52 años que venía percibiendo D. JOSÉ MANUEL MORENO CARLOS, con DNI 07005095P, cuyo cargo de curador ostenta la Comisión Tutelar de Adultos de Extremadura, ha dejado de percibirla desde febrero de este año, entendemos que por no haber renovado la demanda de empleo. Informarles que esta persona presenta limitaciones y reside en una residencia de mayores, desde donde iban a apoyarle en estas renovaciones de la demanda, pero de esta cuestión se han olvidado desde que ingresara en el hospital en noviembre de 2023 con varios ingresos hospitalarios y atenciones en urgencias posteriores hasta el mes pasado con un estado de salud cada vez más delicado y complicado. La cuestión que queríamos plantear es si, por casusa justificada, podría eximírsele del deber de renovar la demanda y volver a percibir el subsidio e incluso de forma retroactiva. Podríamos adjuntar todos los informes médicos pertinentes para su justificación. Si no fuera posible esta opción, por favor, infórmennos sobre si existen otras alternativas. Quedo a la espera de su respuesta para poder realizar las gestiones oportunas." ······························································································································································································ Llamo a Ana, TS de Riolobos (927 45 30 04 // Hoy en Olivera: 927 45 10 65: "Desajuste emocional tremendo", la mayoria de residentes pasan de los 80 años y él acaba de cumplir 60. En los momentos de lucidez se siente muy desubicado. ········ Puesto que está pendiente de revisión en el Serv. de Neurología, planteamos que una vez tengamos el informe de dicha consulta podemos solicitar revisión PIA para cambio de recurso residencial a centro especializado o a Ud. de Psicogeriatría. ······························································································································································································ Envío a Jaime, Aux. Adtvo. CTAEx: "Adjunto para remitir por REGISTRO (TRAMITA) al CADEX de Cáceres, la siguiente documentación relativa a JOSÉ MANUEL MORENO CARLOS: - Solicitud de revisión del grado de discapacidad por empeoramiento - Informes Médicos - DNI representante legal - Decreto Nombramiento como Directora Gerente del SEPAD - Resolución de Delegación de Funciones como Presidenta de la Comisión Tutelar de Adultos - Resolución de régimen de suplencia de los órganos directivos de la Consejería"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2024-08-22','Ana: Llamada de Mamen, Ed. Futuex (663 85 17 59): ha acompañado a Carlos a la consulta de Psiquiatría. Éste se ha mostrado más receptivo que en otras ocasiones. ··· Esperemos que vuelva a aceptar el seguimiento. ···· Si volviera a rechazar el apoyo del programa sería conveniente que nos lo comunicaran por escrito. ······················· *Le ha manifestado a la Psiquiatra que rechaza el tratamiento farmacológico. *Lo va a hacer constar en el informe y me lo enviará por correo electrónico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GLORIA'and edp.apellido1='VERA'and apellido2='LLORENTE'),'2024-08-22','Ana: Hablo con Maribel, Secc. Acceso a RR. Discapacidad. *Gloria sigue apareciendo en ALTA en INCLUDES - Almendralejo, por tanto, si esta plaza no está abonando sigue generando deuda. *Aún no tenemos acceso a sus cuentas. ···························· Hablaré con Soraya Masa, pues a partir de septiembre van a empezar a cobrarle la plaza en el CSS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2024-08-23','Ana: Envío correo a Toni-Futuex: "Ahora quién acaba de llamarme es JUAN JOSÉ GONZÁLEZ CARRERO, me cuenta que una persona sin hogar a la que acogió unos días en su casa le agredió hace unos días, que tuvo que ir al médico para que hiciera parte de lesiones y que Nieves le acompañó a la policía a poner la denuncia. Mientras hablaba conmigo fue a la farmacia, pues necesitaba más productos para curarse las heridas, me ha pasado con la farmacéutica y hemos acordado que nos enviará la factura para su abono mediante transferencia. *Esto más que nada para que estéis al corriente. Por favor, cuando podáis, hacednos llegar el parte de lesiones y la denuncia, ponedme en copia, pero enviadlo a la atención de los Asesores Jurídicos al ctutelar@salud-juntaex.es"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2024-08-23','Ana: Envío correo a Alberto, Jefe S. Ecca. y a Miguel, A. Jurídico: "Os reenvío correo de Toni – Futuex, con las facturas pendientes de abono de la casa en la que vivía de alquiler. Leed el hilo por favor. Alberto, cuando se pueda…. Habrá que abonarlo todo. El problema es que la dueña tiene “prisa” por que se abone y Vanesa no tiene ahora ni ingresos… Estoy a la espera de respuesta de PNC, ya solicité que se reactivara la misma aportando la documentación que solicitaban. Miguel, como puedes leer Vanesa ya ha devuelto las llaves a la casera. Espero que nos pasen el acuerdo firmado, en el que si no me equivoco iban a hacer constar que la dueña “perdona” los recibos pendientes de alquiler, sólo exige que se abonen las facturas de suministros para poder ellos darlos de nuevo de alta." ·········································· Respueta de Alberto: "TODOS: IMPOSIBLE REALIZAR NINGÚN TIPO DE ABONO...SALDO HOY 23/08/2024: 0 € HA REALIZADO REINTEGROS SIN CONTROL X LA TOTALIDAD DE SUS INGRESOS..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2024-08-23','Ana: Subo al portafirmar digital, para que lo firme la D.Gerente ya el lunes, el CI para la retirada de los brackets sin terminar el tratamiento, que me remite Estrella, TS CSS. *Tiene que llevarlo el día 24 del próximo mes, cuando la han citado para tal fin.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='AVILA'and apellido2='FEMIA'),'2024-08-22','Ana: Llamo a Pilar Martín, TS ESM - CC (54612): Hablará con el Psiquiatra para tener en cuenta en la próxima cita la derivación al CRR. Le expliqué que de entrada él es reacio y la educadora de Futuex está abordando esta cuestión en las visitas para que lo acepte. ····· Pido le expliquen también que el hecho de que él acepte la derivación no supone el ingreso inmediato en el recurso pues hay mucha lista de espera.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='AYUSO'and apellido2='TENA'),'2024-08-16','Ana: Llamada de Fátima, TS CSS (en sustitución de Javier): Antonia es dependiente total, ni siquiera habla, por lo que entiende que la propia Antonia no ha pedido el cambio de recurso residencial. Cree que ha sido una decisión del propio centro. Hablará con la Directora del centro la semana que viene, pues hoy no está.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='AYUSO'and apellido2='TENA'),'2024-08-19','Ana: Llamada de Fátima, TS CSS (en suplencia de Javier). Ha hablado con la Directora. Al parecer la decisión de dejar camas libres de las unidades de larga estancia y psicogeriatría, viene de la Gerencia, no la han tomado en el centro. ······························ *Lo hablaré con Maite para que lo hable con Soraya. ·························','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2024-08-26','Ana: Correo de Jesús Manuel (jesusmanuelramosbargom@gmail.com) al ctutelar@: "querría mandar este correo a la atención de los asesores jurídicos por si pudieran informarme sobre qué significa que me "liquidan la condena" en el año 2026. Os adjunto el informe y en la primera página se señala donde lo pone." ············································································· *Lo reenvío a los A. Jurídicos y pido que le den respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2024-08-23','Ana: Jaime, Aux. Adtvo. Secc. Soc. CTAEx, me envía el JUSTIFICANTE DE REGISTRO de la SOLICITUD DE REVISIÓN DEL GRADO DE DISCAPACIDAD.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2024-07-15','Ana: Respondo a la consulta de Alberto; Jefe S. Ecca. con copia a Miguel,A. Jurídico: "Tenía este correo pendiente. La vivienda de FELISA sita en la C/Nuestra Señora de la O, nº 71 - Navas del Madroño. La del número 30, según consta en el correo de la empresa del serv. Municipal de depuración es la de la herencia de su padre."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2024-08-23','Ana: Correo de Lourdes, S. Ecca., a Alberto, Miguel y a mí: "Tras comprobar con Miguel, el tema de la vivienda con la referencia catastral que nos aportan, resulta que corresponde 100% a su hermana Josefa Felipe Teomiro. Lo comunico a edarnavas." ····························································································································································································· Respuesta de Albeto, Jefe S. Ecca.: "LOURDES/MIGUEL: • MIGUEL: o ENTIENDO QUE, A NIVEL ECO NO HAY NADA QUE ABONAR...ES ASÍ??? o PERO HABRÍA QUE NOTIFICAR ALGO AL "servicio municipal de depuración de aguas residuales de la localidad de Navas del Madroño", O SIMPLEMENTE NOS OLVIDAMOS DE ESTA CUESTIÓN Y QUE ELLOS VAYAN CONTRA LA HERMANA DE FELISA (TITULAR DE LA VIVIENDA). YA ES CURIOSIDAD...DE LA HERENCIA DE LA QUE HABLAMOS Y A TRAVÉS DE LA CUAL ESTA VIVIENDA LE CORRESPONDIÓ A LA HERMANA DE FELISA...A NUESTRA TUTELADA, NO LE TOCÓ NADA???" ······························································································································································································· Respuesta de Miguel: "no tengo conocimiento de la herencia que se tramitara en su día. Según veo en el expte hay alguna información suelta pero no, escritura de adjudicación de herencia, caso de que se firmara…o documentación de testamentaria (certificado de últimas voluntades, testamento), y bienes que compusieran la masa hereditaria (notas simples, certificados bancarios…). Pongo en copia a Angel por si supiera algo más. En cuanto a los recibos impagados referidos a la vivienda que hemos visto Lourdes y yo en catastro (lo dejo en la carpeta herencia) aparece a nombre exclusivamente de la hermana (desconocemos si el origen del 100% de propiedad es porque lo comprara la hermana o proviniese de una herencia). Por tanto hasta que no se demuestre lo contrario nuestra tutelada no debe abonar nada si no acreditan que sea propietaria o usufructuaria de dicho bien. Entiendo que desde la parte económica podríais contestar al email que enviaron en su día EdarNavas >info@edarnavas.es> de 27-5-24, que aparece al final de estos emails y adjuntarle el certificado de catastro indicando que no nos consta titularidad alguna de nuestra tutelada y hasta que no acrediten documentalmente que nuestra tutelada es titular no podemos proceder al abono de cantidad alguna. Por otra parte y para posteriores ocasiones deben remitirnos factura o documento justificativo de deuda, que no lo han enviado…"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2024-08-26','Ana: Reenvío a la secc. ecca.: "Os reenvío presupuesto del móvil que quiere regalar Mª Luisa Montaña Aliseda a su hija. Ya lo habíamos hablado María y yo. Puede permitírselo." ···· Pido que avisen a Toni y a Nieves, Ed. cuando esté abonado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINA AMELIA'and edp.apellido1='TORRADO'and apellido2='LEON'),'2024-08-26','Ana: Envío a Laura Vegas, TS de la Casa Residencial Guadiana (LVEGAS@caseresidencial.es / 924 262 100) el Consentimiento Informado para la administración de la VACUNA frente al NEUMOCOCO debidamente firmada y sellada. ······················· Guardo el CI en el expdte. digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='BERGANTIÑO'and apellido2='GONZALEZ'),'2024-08-23','Ana: Correo de Sheila, CRR (crr@grupociudadjardin.com): "Buenas tardes, Desde el centro hemos organizado excursión a la playa desde el 9-13 de septiembre. El coste total de la excursión es de 520€ con transporte y todo incluido. Solicitamos que el pago de 520€ de la persona usuaria JUAN JOSÉ BERGANTIÑO GONZALEZ se haga mediante transferencia a la agencia Nevatur, si es posible. A continuación os facilitamos sus datos: AGENCIA NEVATUR - LA CAIXA-ES9421007685112200079951" ····································· Se autoriza el gasto/viaje.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AGUSTIN'and edp.apellido1='SERRANO'and apellido2='TRANCON'),'2024-08-26','Ana: Reenvío a Alberto, Jefe S. Ecca., y a Miguel, A. Jurídico, correo remitido desde la Asociación Vera (asociacionvera@msn.com) con NOTIFICACIÓN DE LA AGENCIA TRIBUTARIA. ··················· Se concede un APLAZAMIENTO/FRACCIONAMIENTO del abono de una DEUDA por importe de 172,94 €. ······· Yo no sé a qué obedece esta deuda ni quién ha solicitado el fraccionamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MORA'and apellido2='GARCIA MORA'),'2024-08-26','miguel, Estrella me envía las 2 diligencias de embargo del Oar y del Jzdo nº3 de Don Benito para que me informe del origen de las mismas. Llamo, pregunto y envío email a Alberto, Estrella y Tere: Buenos días, he llamado para averiguar el origen de los embargos del OAR y del jzdo nº3 de Don Benito, en ambos desconocían que hubiésemos sido nombrados curatela asistencial. Me comentan: 1)OAR de Don Benito: El embargo cargado de 98,76€ procede de multa por llevar el perro suelto. En catastro aparecen 3 bienes de los que el curatelado es titular 33% cada uno: la Rústica no tributa (no llega al mínimo según me dicen, y además no tiene construcción). Los IBI de las 2 urbanas en las que José Luis es propietario en 33%, se han pagado en ventanilla, no están domiciliados y están emitidos sólo a nombre de nuestro curatelado. Por tanto se están abonando por alguno de los dos hermanos en ventanilla. Me van a enviar desde el OAR modelo de petición de domiciliación bancaria así como de petición para que en adelante se emitan los recibos a nombre de cada hermano en su parte proporcional, por si desde la parte económica decidís más adelanta solicitar esa domiciliación y pago individualizado de los recibos. Según hablo con Estrella, no se van a domiciliar y que siga pagándolo en ventanilla el hermano que lo haya hecho anteriormente. 2)Embargo del JZDO DE 1º Instancia e instrucción nº3 de Don Benito. El embargo procede de un procedimiento monitorio de 2019(la Ctaex fue nombrada en 2023)…Ejecución de títulos judiciales procedimiento monitorio 582/19. Me comenta que el cargo de los 296,29€que se hizo en mayo eran sobre el principal, y que ahora en julio deberían haber cargado unos 72,99€ por intereses, que la tasación de costas debería ser 0€, en definitiva que no sabe decirme si queda algún cargo por llegar por lo que le doy nuestro email y tlfnos de Tere y Mío para cualquier comunicación, ya que las cartas le vienen devueltas…Ya le he dicho que está residiendo en Residencia las Cruces de Don Benito y cualquier comunicación debe hacer con la Ctaex. Le indico los datos del procedimiento por el que la Ctaex fue nombrada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='MENDO'and apellido2='PALACIOS'),'2024-08-26','Ana: Llamada Abraham Mendo Gía (927 772 155 / 639 88 78 97), hijo de Pilar García Moreno, también a cargo de la CTAEx, es SOBRINO de Juan. ··· Me pide que comuniquemos al CSS que él y su madre son familiares de Juan. Llaman todos los meses al CSS para preguntar por él. Les gustaría que les informasen si se pone enfermo o necesita algo. ···························· Envío correo a Javier, TS CSS (javier.rdguezper@salud-juntaex.es): "Me pongo en contacto contigo tras haber recibido llamada de Abraham Mendo García, SOBRINO de Juan (927 772 155 / 639 88 78 97). Me pide, por favor, que os comunique que tanto él como su madre (cuñada de Juan) son familiares directos de Juan, dice que llama todos los meses para preguntar por él y le gustaría que cuando a Juan le pase algo, por ejemplo, enfermedad, se lo comuniquen como familiares también. Por nuestra parte, a no ser que en el centro tengáis un motivo que lo justifique y que nosotros desconozcamos, no hay inconveniente en que así sea, pues siempre que sean favorables para la persona se deben fomentar las relaciones familiares."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2024-08-26','Ana: Envío correo a Alberto, Jefe Secc. Ecca. y Miguel, A. Jurídico: "acabo de recibir llamada de Ana, sobrina de la dueña del piso de alquiler (656 485 213). Puesto que Vanesa no tiene nada de dinero para abonar lo que debe de suministros, proponen abonar ellas la deuda de agua para poder volver a darla de alta, pues se la cortaron. La luz no les corre tanta prisa, pero el agua sí, pues dice que dejó la casa sucísima y por lo menos quieren ir a limpiarla y sin agua no pueden hacerlo. Por mi parte ok a la propuesta. Alberto ya nos dices si es factible. Pongo en copia también a Miguel, por si tiene que añadir algo. Puesto que Alberto no se incorpora hasta la semana que viene (no sé qué día) y como Maite y yo no estaremos, pongo en copia a Mamen, Educadora del programa de apoyo de Futuex y a Toni, su coordinadora, para que podáis confírmales si se acepta la propuesta y puedan informar a Ana, sobrina de la propietaria."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2024-08-26','Ana: correo de Cristina Hdez., TS CSS (cristina.hernandezca@salud-juntaex.es): "Anteriormente se solicito revisión de Grado Dependencia, la compañera nos ha comunicado que si realiza dicha revisión puede perjudicar a su grado I, con lo que solicitamos que nos mandéis dicho documento relleno" ······ Se trata del DESISTIMIENTO DE SOLICITUD de la revisión de grado. ······ Anteriormente desde el CSS nos pidieron que se solicitara la revisión. ······························································································································ Cumplimento y subo al portafirmar el documento de DESISTIMIENTO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2024-08-26','Ana: Envío a Maricruz, Hermanos de la Cruz Blanca (trabajosocialcf-caceres@cruzblanca.org): "Adjunto los siguientes documentos firmados digitalmente por la Representante Legal: - Protección de datos y consentimiento de representante legal de Alejandro Montero Vázquez"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PILAR'and edp.apellido1='JIMENEZ'and apellido2='AGUILAR'),'2024-08-26','Ana: Llamada de Ana Benavente, TS ESM (74955): Pilar no ha acudido hoy a la cita de Psiquiatra, la ha llamado, que se le ha olvidado, se la reprogramarán. ·························· Por otra parte le ha dicho que ya no está agusto en la casa de Ahigal y que quieren buscar una vivienda en Plasencia. Ana les ha dicho que en Plasencia apenas hay viviendas de alquiler y además está muy caro el alquiler.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2024-08-26','Ana: Llamada de Ana Benavente, TS ESM - Plas (74955): Ha recibido llamada de Guadalupe, la semana pasada llamó también. De nuevo dice que se quiere ir de esa residencia, a Jaraíz, localidad en que vive su hija, no puede ir porque no hay plazas de su perfil. ·········· *Ahora dice que quiere irse a vivir de alquiler con una pareja que conoce a Plasencia. ······ Con los apoyos que necesita esto es impensable, presenta bastante depenencia. ···· Además la nota un tanto alterada. ·········································································· *Hablará con su Psiquiatra de nuevo al respecto por si fuera preciso reajustar la medicación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2024-08-26','Ana: Correo de Carmen Santos, hermana de Enrique: "Fui a visitar a mi hermano hace unos días ya que estuve en Plasencia. Le encontré regular. Tenéis alguna noticia de su situación? Mis otros dos hermanos mayores hablan ya de ir moviendo la venta de la casa familiar ya que sólo son gastos e inconvenientes, te lo comento porque con Quique existe el problema que la propiedad donde se queda en sus salidas no está a su nombre y veremos cómo hacemos para la venta porque esa vivienda va incluida con todo." ················· Lo reenvío a Alberto, Jefe S. Ecca. y a los A. Jurícos. ············································································· Respondo a Carmen: "La única novedad de la que puedo informarte es que él, actualmente y si no camba de parecer, acepta la derivación al CRR (Centro Residencial de Rehabilitación) cuestión que antes rechazaba de plano, por lo que se están haciendo los trámites pertinentes. En cuanto a la venta, entiendo que cuando lo tengáis claro, tendréis que poneros en contacto con mis compañeros Asesores Jurídicos, por la parte que le toca a Enrique. Los teléfonos de contactos de ellos son ..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2024-08-26','Ana: Envío correo a Estrella Durán, TS CSS- Plas: "Adjunto el Consentimiento Informado para la retirada de los Brackets de FELISA BRUNO SAAVEDRA, firmado digitalmente por la presidenta de la CTAEx"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO'and edp.apellido1='MARIN'and apellido2='DE CACERES'),'2024-08-27','Ana: Envío a Jaime, Aux. Adtvo. CTAEx (jaime.munoz@salud-juntaex.es): "...- adjunto documento de DESISTIMIENTO de SOLICITUD de REVISIÓN DEL GRADO DE DEPENDENCIA para remitir por REGISTRO (TRAMITA) a la UNIDAD DE GESTIÓN DE ACCESO Y VALORACIÓN DE DEPENDENCIA, Buzón de Revisión de GRADO: A11032816"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='BRAVO'and apellido2='PATILLA'),'2024-08-27','Ana: Envío correo a Cristina, Ed. Asoc. Vera (educadorasocial@asociacionvera.com): "En relación con Antonia Bravo Patilla, y a instancias del Juzgado, os solicitamos INFORME SOCIAL en que se haga constar “Cualquier consideración que estimen conveniente sobre ella en razón al procedimiento judicial de revisión de medidas de apoyo”. Quedamos a la espera de que nos le enviéis para remitirlo al Juzgado junto con el resto de documentos que nos solicitan. Por cierto, si los envías en septiembre, pon, por favor, en copia a mis compañeros Asesores Jurídicos..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ROMERO'and apellido2='PEREZ'),'2024-08-27','Ana: En relación al correo de PEDRO PASTOR VILLEGAS (ppasvill@gmail.com), amigo de Jesús, solicitando un ordenador nuevo y adjuntando presupuestos, envío correo a Alberto, jefe de secc. ecca.: "Ya sé que este correo te lo ha enviado Lourdes. Sólo te escribo para darte el ok por mi parte en caso de ser viable. Entiendo que es necesario para él, ha hecho buen uso del anterior y creo que también lo hará de éste. Y al igual que Pedro, amigo y principal apoyo de Jesús, creo que comprar el que él indica, aunque sea un poco más caro (635 €) y en este establecimiento será mejor para él ante cualquier problema que pudiera surgir con el mismo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CESAREO'and edp.apellido1='PANIAGUA'and apellido2='CALLE'),'2024-08-23','Ana: Respuesta de Toni-Futuex, a mi correo: "en torno a este tema, finalamente se le ha entregado, el 21 de Agosto, pero sigue siendo practicamente imposible verlo, ya que el cura con quien hay que contactar no colabora. Se le consiguió ver en hace unos meses, pero posteriormente no se ha vuelto a realizar ningún seguimiento, debido a la poca colaboración por parte de quien custodia su residencia actual en Barrado, ya que, ante los intentos de contactar para una nueva visita, se han visto denegados por no haber respuesta por parte de quien se está haciéndose cargo de Cesáreo. Además, durante el primer contacto, no ha habido intención de colaborar con lo que el programa desde un principio. En las últimas llamadas telefónicas para realizar una quedada y avisarle de una notificación de revisión mandada. se ha contactado con el cura que lleva su residencia sin éxito alguno, ya que negaba las visitas, excusándose en falta de tiempo y dificultad para acordar una cita. Se ha vuelto a intentar y esta vez se ha avisado directamente de que se iba a ir el 21/08/2024 a primera hora a dejarle la notificación, aunque no estuviese presente. Así pues, la educadora del programa se ha dirigido a Barrado hacia su domicilio. En un primer momento, se le ha avisado de que la educadora ya estaba en el domicilio sin recibir respuesta, ante la insistencia de la profesional. Se ha hecho tiempo por si hubiese posibilidad de ver al cura y al tutelado que se encuentra ahí. Finalmente, ha salido del domicilio con el tutelado, se le ha entregado la notificación y rápidamente ha despachado a la educadora, sin dar pie para hablar con el tutelado, quien preguntó si hablaría con él, pero debían irse a realizar unas gestiones de la Iglesia. No tenemos desglosados los intententos realizados desde enero hasta el momento porque han sido llamadas telefónicas, elaboramos un informe con esta información pues?"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CESAREO'and edp.apellido1='PANIAGUA'and apellido2='CALLE'),'2024-08-27','Ana: Respondo a Toni-Futuex, a su correo del día 23: "Gracias por la información. Me alegro de que al menos se le haya podido entregar la documentación, pero sí, por favor, elaborad informe como tal donde quede bien recogida esta información, detallando lo mejor posible los intentos, la falta de colaboración, la imposibilidad de visitar al tutelado, hacer seguimiento y prestar apoyos."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='MONTAÑA'and apellido2='ALISEDA'),'2024-08-27','Ana: Correo de María, S. Ecca. a Electrocash y a Nieves y Toni de Futuex: "se adjunta el justificante de transferencia del pago del móvil de M. Luisa Montaña Aliseda. Necesito me envíen la factura."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GREGORIA'and edp.apellido1='MORENO'and apellido2='BERMUDEZ'),'2024-08-28','Ana: correo de Nadia, Ed. Futuex (delegadapoyo.coria@futuex.es): "Goya me comenta que semanalmente retira 38 euros y actualmente le han reducido el pago de la residencia y ella me pide que si se le pudiese subir la paga semanal" ································································································································· Lo reenvío a Alberto, Jefe S. Ecca. y al ctutelar@, aclarando: "Os reenvío correo de Nadia, Educadora de Futuex, con petición de GREGORIA MORENO BERMUDEZ, por favor, leed el hilo. Gregoria solicita se le aumente la asignación semanal de gastos de bolsillo. Alberto, si es viable, por mi parte ok a esta petición. Por favor, dar respuesta a la Nadia, Educadora de Futuex: delegadapoyo.coria@futuex.es, pues cuando lo vea Alberto yo estaré de vacaciones."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-08-28','Ana: Envío correo de José Manuel a Miguel, A. Jurídicos CTAEx, aclaro: "Te reenvío correo de José Manuel Romero Mediavilla, como puedes ver, adjunta imagen de CÉDULA DE CITACIÓN para reconocimiento por el Médico Forense. Diligencias previas – Procedimiento abreviado por DELITO DE LESIONES. Le citan el día 9 a las 10:00 h en el INSTITUTO DE MEDICINA LEGAL DE CÁCERES. No sé si tendrás que llamar, pedir abogado de oficio o hacer alguna otra gestión."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2024-08-28','Ana: Correo de Estrella Durán, TS del CSS: "Está llamando a Felisa Bruno, un hermano llamado Ángel porque quiere hablar con ella. No está la Psicóloga (Maripaz), con lo cual yo le he dicho que hasta que no venga ésta, no puede ser. Maripaz cuando vuelva de vacaciones, va a decir que os pregunte a vosotras, así ya me decís si es conveniente o no que hable con este hermano...." ··································· Mi respuesta: "Desde que la CTAEx ostenta el cargo de Felisa, la primera vez que ha habido contacto con su hermano ha sido estado ella en el Proyecto Mi Casa en Don Benito, donde se inició e intentó un contacto progresivo, periódico y supervisado por los profesionales del recurso. He hablado con Sergio, Coordinador del piso, y me informa que la relación tanto con la madre como con el hermano, resulta totalmente perjudicial para Felisa, le generan expectativas que no cumplen, la llaman o van a verla y no vuelven a dar señales de vida hasta pasado meses, se mueven por el interés por las pertenencias materiales de Felisa y lo que puedan obtener de ella, le inducen a pensar que se le trata mal en los recursos… y la desestabilizan mucho. Cuando pueda me enviará un informe al respecto. Por tanto, en base a la experiencia negativa previa, desde la SECCIÓN SOCIAL DEL GABINETE TÉCNICO DE LA CTAEx, no se recomienda las visitas ni llamadas del hermano ni de la madre."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2024-08-28','Ana: Subo al portafirmas digital el documento de ACEPTACIÓN DE DERIVACIÓN A CRR, que me remite Cristina Hdez., TS del CSS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2024-08-29','Ana: Envío a Miguel, A. Jurídico, con copia a Ángel y a Alberto, Jefe S. Ecca: "Te reenvío correo correo de Helga, hermana de JUAN JOSÉ GONZÁLEZ CARRERO. Me ha llamado también. Sus números de contacto son (personal: 652 30 39 11 / Trabajo Interno: 50124). Al parecer estuvo en contacto en relación a todos los trámites de la herencia de su padre fallecido (ella renunció a favor de su hermano Juanjo) y lo relativo a la vivienda, cambios de titularidad, etc., con Ángel, le pongo en copia. Dice que ella siguió todos los pasos que se le fueron indicando desde aquí y que del resto ya se le dijo que se encargaba la CTAEx. Pero está muy enfadada porque hay gestiones que en teoría se harían desde aquí y no se han hecho. De hecho reenvía un correo que envió en 2022 con unos documentos y manifiesta que, además de no tener respuesta, no se ha hecho nada. Pongo también en copia a Alberto, por la parte que le pueda tocar."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2024-08-29','Ana: Correo de Ana Sánchez, Res. (anatdelat@hotmail.com) a la S. Ecca. y a mí: "La usuaria Isabel Muñoz Melchor me comenta que si es posible que se le añada 40€ para pagar el taxi para ir al dentista que tiene el día 16 de septiembre. Como ya os comentamos la otra vez, esta taxista no hace facturas. Es la taxista que la lleva siempre desde que estaba en Jaraicejo. También quiere ir a Plasencia al cementerio y a ver a los familiares un día de la semana del 9 de septiembre, que serían 150€ lo que le pide la taxista porque llevarla, traerla y quedarse con ella mientras realiza sus quehaceres." ·············· Respondo, si es viable, por parte de la S. Soc. OK a ambas propuestas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='MATILLAS'and apellido2='JIMENEZ'),'2024-08-29','Ana: Correo de Pilar, Directora del Hogar San Vicente de Paúl (direccion.hgsvplasencia@gmail.com): "les informamos que, como cada año, realizaremos la actividad "Vacaciones en Rota", los días 14 al 24 de Septiembre a la que acudirá Mª del Carmen Matillas Jiménez. El coste de la actividad asciende a 700,00 €, cantidad que deben abonar en la Cuenta del Hogar San Vicente donde, normalmente, realizan el ingreso mensual de la estancia en nuestro centro de Mª del Carmen." ·································· Reenvío a la S. Ecca. dando ok por parte de la S. Social.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO TOMAS'and edp.apellido1='MURILLO'and apellido2='MATIAS'),'2024-08-29','TERESA Ya que se ha recabado información desde el Equipo de Apoyo Social Comunitario y realizado seguimiento presencial esta semana. Se habló con el casero y aunque estaba efectivamente en la misma actitud de que Pedro Tomás se tiene que marchar... mas o menos transigia a que podria esperar hasta que se encontrara algo por según sus palabras, tampoco queria que se quedase en la calle.. y nos dijo que lo primero y fundamental era arreglar la cerradura de la puerta que está rota (la ha roto Pedro o sus amigos.. ) y eso fue lo que se hizo el lunes, se puso un bombín nuevo pero no le han cobrado nada por ponerselo. Como antecedentes, el pasdo lunes 26 de agosto, el casero actual de Pedro Tomás se puso en contacto con la educadora de referencia para informarnos de que, debido a las quejas recibidas por parte del vecindario y a la ausencia de una cerradura en la puerta, lo que permite el acceso no controlado de personas al domicilio, se ve en la obligación de solicitar que Pedro abandone la vivienda. En esta llamadad del lunes fue en la que indicó que, si se repara la cerradura, concederá un poco más de tiempo antes de proceder con el desalojo, aunque Pedro deberá marcharse. Ese mismo día nos comunicamos con el centro de salud de Don Benito con el fin de establecer contacto con la psiquiatra de Pedro, explicarle la situación actual y solicitar la elaboración de un informe de valoración, como nos pediste, que seria necesario para un posible internamiento involuntario.Aunque no logramos hablar directamente con la psiquiatra, (a la que ya se le habia escrito hace algunas semanas para ver si podrian adelantarle la cita) el personal de administración se comprometió a trasladarle la información. Asimismo, nos proporcionaron una hoja de solicitud para solicitar ese informe, con el propósito de agilizar el proceso. Adjuntamos dicha hoja, ya que es necesario que sea firmada por los tutores legales de Pedro. Por esta razón, el martes 27 de agosto se realizó un seguimiento presencial en Monterrubio para informar a Pedro de lo sucedido. Se le presentaron las dos alternativas disponibles: buscar otro alquiler o gestionar su ingreso en una comunidad terapéutica. Aunque inicialmente no descartó ninguna de las opciones, manifestó su deseo de no abandonar el pueblo. En consecuencia, nos pusimos en contacto con una inmobiliaria, la cual nos informó de la disponibilidad de un piso con un alquiler mensual de aproximadamente 200 euros, aunque debían consultar con el propietario para confirmarlo y programar una visita. Además, contactamos a un cerrajero, quien instaló un bombín en la puerta para que esta pueda mantenerse cerrada en caso de que Pedro se ausente, permitiendo su apertura únicamente con llave. Cabe destacar que el cerrajero no cobró por el servicio realizado. Esa opción de piso de 200 euros seria muy interesante, pero tenemos serias dudas de que cuando sepan que es él el inquilino, se lo quieran alquilar, no obstante proxima semana iriamos a la inmobiliaria con el para ver el piso. Respecto al seguro de decesos, la compañía Seguro Norte Hispana realizó una entrevista telefónica para evaluación. Tras la realización de la entrevista, se nos ha informado que no será posible contratar el seguro de decesos con ellos. Por lo tanto, procederemos a explorar otras opciones de seguros disponibles. A ver si podemos con alguna asesoria pedir presupuesto, porque ahora mismo no tiene seguro contratado.. aunque se pasara pagando años a la compañia anterior.. han decidido que no le aseguran. Además, el teléfono móvil de Pedro está presentando problemas, por lo que hemos solicitado un presupuesto para la adquisición de un nuevo dispositivo. Por ello, nos hemos dirigido a ELECTRODOMÉSTICOS MONTERRUBIO, S.L. Después de revisar las opciones disponibles, hemos encontrado un dispositivo que se ajusta a sus necesidades: - Redmi Note 12 (4GB-128GB): 185€ El número de cuenta para realizar la transferencia es EN UNICAJA: ES42.2103.7308.9605.5000.0062 En el caso que lo valoreis .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ROSA'and edp.apellido1='IGLESIAS'and apellido2='CALZAS'),'2024-08-29','Ana: Tras hablarlo y decirlo con Maite, Jefa Secc, cumplimento el ANEXO OPCIÓN optando por la PFHC, para evitar posible futuros problemas con el INSS, al considerar éste incompatibles la P. ORFANDAD con la PNC, aunque para la Junta no lo sea. ·················································································· *Envío a Jaime, Aux. Adtvo. CTAEx: "En relación con Dª. MARÍA ROSA IGLESIAS CALZAS, adjunto la siguiente documentación para remitir por REGISTRO a los Servicios Territoriales de Cáceres, Serv. De Prestaciones y Ayudas DIR03 A11030102: - Oficio - Anexo opción"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2024-08-29','Ana: Envío correo a Cristina Hdez., TS del CSS -Plas (cristina.hernandezca@salud-juntaex.es): "Adjunto ACEPTACIÓN DE DERIVACIÓN A CRR firmada digitalmente por la Representante Legal."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CACHO'and apellido2='GARCIA'),'2024-08-28','Ana: Correo de Toni-Futuex: "El informe pendiente solicitado, te adjunto el nuevo número, el que se compró en agosto, según comenta se lo robaron.. y le pidió dinero a su madre y tiene otro, por el momento, este es el número por si lo necesitas: ‎+34 642 64 78 93" ······································· Envío INFORME a los A. Jurídicos para que lo remitan al Juzgado.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2024-08-29','Ana: Correo de Toni-Futuex: "El informe pendiente solicitado, te adjunto el nuevo número, el que se compró en agosto, según comenta se lo robaron.. y le pidió dinero a su madre y tiene otro, por el momento, este es el número por si lo necesitas: ‎+34 642 64 78 93" ······································· Envío INFORME a los A. Jurídicos para que lo remitan al Juzgado. ···································· En la valoraión del INFORME DE FUTUEX maniestan: "La intervención con Francisco es compleja y está profundamente mediatizada dada su situación de calle y su adicción a las drogas, pero aun así se ha conseguido construir una relativa adherencia al programa y a la profesional responsable, por lo que esto facilita la intervención con él. Aunque siempre es a demanda del mismo, en raras ocasiones accede, si no es él quien lo demanda, o se trata de encuentros fortuitos. Debido a esta inestabilidad del tutelado, lo más importante ahora mismo es seguir fortaleciendo el vínculo con él con el fin de que siempre pueda contar, al menos, con la presencia de la educadora/monitora cuando él considere necesario y acuda a ella. Por otro lado, también es importante trabajar con él en la búsqueda de alternativas habitacionales y poder cambiar su situación de calle, que es el origen de la mayoría de sus problemas. El recurso que mejor podría resultar para Francisco sería una comunidad terapéutica, donde contaría con los profesionales adecuados y los recursos específicos para tratar sus adicciones; sin embargo, ya se ha intentado en otras ocasiones y no ha resultado efectivo, pero se seguirá trabajando en esta línea."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2024-08-29','Ana: Llamada de José Luis, Director de la oficina RATEL (Red de Atención Telefónica) del SEPE de Plasencia (927 224 162 - nº directo: 927 748 943)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2024-08-30','Ana: Envío a Alberto nuevo correo que ha llegado al ctutelar@: "En relación al correo que reenvié ayer a Miguel, con copia a ti y a Ángel, hoy te reenvío otro que ha enviado esta mañana Helga, hermana de Juan José Glez. Carreero relativos a seguros, recibos y cuentas bancarias al descubierto. Pongo a los Asesores Jurídicos en copia, ya que todo deriva de la herencia."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='TEJADA'and apellido2='FERNANDEZ'),'2024-08-30','Ana: Envío a Maricruz, Hermanos de la Cruz Blanca (trabajosocialcf-caceres@cruzblanca.org) los siguientes documentos firmados digitalmente por la D.Gerente: Protección de datos y consentimiento de representante legal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='MOLANO'and apellido2='IGLESIAS'),'2024-08-30','Ana: Envío a Maricruz, Hermanos de la Cruz Blanca (trabajosocialcf-caceres@cruzblanca.org) los documentos de Protección de datos y consentimiento de representante legal firmados digitalmente por la D.Gerente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2024-08-30','TERESA Los propietarios de la vivienda quieren hablar con vosotros. Por favor, pueden llamarlo. 665668320 (Rosario Suarez) o 655576513 (Enrique) llamame primero a mi si quieres.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2024-08-30','Ana: Envío correo a Jaime, Aux. Adtvo. CTAEx: "Adjunto la siguiente documentación relativa a JUAN JOSÉ MASEDA DEL SOL para remitir por registro a la GERENCIA TERRITORIAL DE CÁCERES DEL SEPAD. Sección de Dependencia I. Pza. Hernán Cortés, 1. C.P. 10001 CÁCERES Código de registro SIREX: A11030403: - Aceptación PIA de SERVICIO DE ATENCIÓN RESIDENCIAL DE DISCAPACIDAD debidamente firmada y sellada por la representante legal."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2024-08-29','Ana: correo de Toni-Futuex: "Adjunto, el acuerdo firmado para la rescisión de contrato y una nota de seguimiento con los intentos (muchos de ellos infructusos) porque como sabes es frecuente que de evasivas de cara a recibir el apoyo. Se esta pendiente recibir de la sobrina de la casera el numero de cuenta, para que cuando se pueda , se le pueda pagar lo que quedó pendiente de las facturass que iba a asumir ella. De las cuestiones mas complicadas con ella, por resumir, por una parte su deseo manifiesto de dejar de tomar anticonceptivas, por su deseo de ser madre.. y que no hay donde empadronarla y por lo tanto no podra acceder a ninguna ayuda o servicio desde servicio social de base. La ts, comentó que no la puede empadronar en la dirección de las casas (donde esta la madre y el hermano) porque eso es ilegal... Esperanza (ts) explica que esa vivienda es ilegal y no puede emitir un certificado de empadronamiento. Propone que Vanessa acuda a una cita con ella y se lo explica. Esto del empadronamiento es un problema. Hoy iba ir a ir Vanesa supestamente a hablar con la ts , en cuanto tengamos mas información la pasamos.. ······························································································································································································ Mi respuesta: "A ver que tal en la cita de ayer con la Trabajadora Social. Lo cierto es que lo relativo a Vanesa está resultando muy difícil. Espero que se consiga la adherencia al programa. En cuanto a su deseo de ser madre… no sé qué vamos a poder hacer al respecto… parece mentira que dada la gravedad de su situación sea ahora cuando se lo plantea… sería importante que volviera a pedir cita a planificación familiar, tanto con la TS como con la Médica, aunque entiendo que ella rechazará esta idea. No obstante, pongo en copia a Mamen, educadora para que esté al corriente y pueda abordar esta cuestión con ella."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOLEDAD'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2024-08-30','miguel, monica garcia de la asesoria de Coria me envía las liquidaciones de impuesto de sucesiones de los hermanos Esteban Iglesias. Envío email a Rafael despacho de abogados Pajuelo de Badajoz, a Carlos Arjona, a Susana Clemento de Unicaja sclemented@unicaja.es>, a la fundación promi de Córdoba (tutora de la hermana Maxima) asesoriajuridica@promi.es, y a mis compañeros parte social (Ana y Tere), Angel, y Alberto informando que envío a Unicaja petición que hagan el ingreso de la cuenta de la herencia de la abuela Dolores, para lo cual adjunto los certificados de titularidad, testamentaria de Tomás, liquidación de impuesto de sucesiones, herencia y ratificación. ************************************************ También envío a Alberto las dos facturas emitidas por la asesoría de Coria por el trámite de la liquidación del impuesto de sucesiones, para su abono ************************************************ Me llama Carlos Arjona juridico@liberalyarjona.com, 679290698, y quedamos que para la liquidación de impuesto de sucesiones de Tomás él haga un escrito adjuntando algún documento del registro civil que acredite que el padre de Tomás Esteban Iglesias no ha fallecido, debido a que pedimos la ampliación de presentación del impuesto de sucesiones, con el fin de evitar que en un futuro puedan pasar complementaria del impuesto de sucesiones a los hermanos Esteban Iglesias.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='LANCHO'and apellido2='SANGUINO'),'2024-08-30','Ana: Correo de Estrella, S. Ecca. a Miguel, con copia a mí: "Hola, acabo de pagar las facturas pendiente de iberdrola. Oscar es su día solicitó la baja de las tres viviendas que tiene. Creo que no lo tenía q haber pagado." ······································· Respuesta de Miguel: "Lo ignoraba…es este el documento enviado en su día por Oscar? Imagino que identifica los 3 domicilios cuyas facturas ha reclamado Iberdrola, es así? Estrella, puedes adjuntarme los justificantes que has abonado? Vamos a enviar al email de debajo notificacion@clientescurenergia.es> con copia a la Trabajadora social de ssb@malpartidadecaceres.es esta solicitud de baja junto con los justificantes de ingreso… Recordad que no se abone nada más en adelante..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='MASEDA'and apellido2='DEL SOL'),'2024-08-27','Ana: Llamada de Gloria, Técnica de Valoración de Dependencia (64736). Ya han solucionado los problemas que tenía con este expediente (tenían ciclos de gestión abiertos en SIDEX desde que rechazó la plaza residencial en la anteior ocasión que se le concedió). En los próximos días me enviarán la ACEPTACIÓN PIA de SAR-DISCAPACIDAD.','2');
