insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2024-08-30','TERESA LA CASEREA DE ILDEFONSO NO QUIERE QUE CONTINUE VIVIENDO EN SU PISO VAMOS A BUSCAR ALQUILER EN BADAJOZ QUE ES DONDE DICE QEU QUIERE IRSE ESTA GENERANDO MULTAS POR INCIVISMO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='RIVERA'and apellido2='RAMOS'),'2024-08-30','TERESA RECIBO LLAMA DE MEDICINA INTERNA PARA COMUNICARME QUE ESTA JOSE ALLI INGRESADO PORQUE LA FAMILIA HA LLAMADO AL 112 PERO QUE NO TIENE CRITERIO CLINICO PARA ESTAR ALLI LE COMENTO QUE HABLE CON EL PSQUIATRA PARA QUE LO VALORE ME LLAMA ANA LA TRABAJADORA SOCIAL DEL HOSPITAL Y ME DICE QUE TRAS VALORACION DEL PSIQUIATRA LO PROPONE PARA DERIVACION A ULE. ESTA PENDIENTE DE VALORACION SE LO HE COMENTADO A SORAYA PARA QUE HABLE CON EL SOCIOSANITARIO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO DAVID'and edp.apellido1='REBANALES'and apellido2='NIETO'),'2024-08-30','TERESA RECIBO LLAMADA DE GUADALUPE TRABAJADORA SOCIAL DEL SASB DE MERIDA ME INDICA QUE TIENE EN EL DESPACHO A ALFONSO Y A SU MADRE PORQUE LLEVAN DOS SEMANA SIN PODER SACAR DINERO LE AUTORIZO RETIRAR 50€ HASTA QUE PUEDAN HABLAR CON AMALIA','2');
