insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2024-08-28','miguel, envío el acuerdo de desembolso y reparto firmado a Ana de la Caixa: ANA MARIA ACEDO RATO >amacedo@caixabank.com> ANA MARIA ACEDO RATO Subdirectora / Oficina 7616 / Cabezarrubia ********************************************************** Y aviso por email a Alberto y a Estrella de que en próximos días será el desembolso. amacedo@caixabank.com Tel. Móvil: +34 628 985320 C/ Londres 28, 10005 Cáceres','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2024-08-30','Ana: Correo de Mónica Hernández, TS Sierra de Gata (mhernandez@sierradegata.es): "Lo primero comentarte que Mª Ángeles se encuentra bien. De momento está adaptada y tranquila. Todos los días sale a visitar a su padre. Lo que te quería preguntar, que me he acordado esta semana, es que como ella es pensionista de PNC, que dirección tiene ella puesta para todo tema de comunicaciones?? Porque yo he buscado en el expediente que hay aquí pero claro, como lleva ya varios años fuera no hay nada de eso. En todo lo que se le ha pedido siempre aparece la C/ Barrio Nuevo que es donde vive su padre. Para el tema de las declaraciones anuales quien las hace? Donde llegan?Sólo es para estar informada, por si hubiese que hacer alguna comunicación de cambio de domicilio o algo. Ya me cuentas. En cuanto a tema sanitario si que le cambiamos ya de área de salud y la dirección en el centro de salud para que nos llegue todo a los pisos tutelados. El día 25 de septiembre tiene consulta en Coria con el ESM. Vamos a ver si hay alguien que pueda acompañarla y buscaremos transporte. Ya iré contando por el tema del dinero." ················································································ Respondo: "Qué bueno que Mª Ángeles se esté adaptando bien y pueda disfrutar de la compañía de su padre a diario, el cuál estará también encantado de tenerla por allí. En cuanto a la PNC, no te preocupes, la declaración anual la presentamos desde aquí todos lo años. Es verdad que aún o he comunicado el cambio de domicilio, solemos esperar un tiempo prudencial de adaptación cada vez que cambian de recurso y localidad y a la malas lo comunicamos con la declaración anual (en PNC ya lo contemplan). El domicilio a efectos de comunicaciones es el de la CTAEx (SEPAD). Perfecto por el cambio de centro de salud y de domicilio al respecto. Tomo nota de la cita en salud mental. Si te parece voy a pedir a FUTEUX que la acompañen si es posible a la consulta, no obstante, habrá que buscar transporte, podéis enviar presupuesto de taxi a la atención de las sección económica a la siguiente dirección: ctutelar@salud-juntaex.es " ······························································································································································································· Envío correo a Toni-Futuex: "En relación a MARÍA ÁNGELES SANTOS URBANO, quién ya fue derivada en su día al programa para otras cuestiones, comunicar que está residiendo ya en su pueblo, en los PISOS TUTELADOS de Valverde del Fresno, sito en la C/ Libertad S/N (Residencia de Mayores) de dicha localidad. La persona de contacto es Mónica. Teléfono: 927 51 06 37, por favor, haced seguimiento periódico e intentad prestar los apoyos que precise. El día 25 de septiembre tiene consulta en Coria con el ESM. Organizad el acompañamiento a la misma. Desonozco la hora, pero la informaicón la tiene Mónica, la pongo en copia."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='FELIPE'and apellido2='TEOMIRO'),'2024-08-30','Ana: Envío correo a Toni y Nieves, Futuex: "He recibido llamada de Felisa, entre otras muchas cuestiones, como su desesperación para que se vaya su hijo ya de casa pues no aguanta más la convivencia, me dice que del dinero que tiene asignado Aitor para aportar productos de alimentación e higiene a la vivienda (100 €/semana ) sólo se destina la mitad (50€) y que él se queda el resto. No quiere darle de entrada credibilidad al 100%, pues como sabéis, Felilsi no controla bien la cuestión monetaria. Además él tiene su asignación aparte de 40 € para gastos de bolsillo, pero conociendo a Aitor, tampoco me extrañaría que se quedara con más dinero de la cuenta… Cuando podáis, por favor, aclararme este punto. Y si fuera como dice Felisi, instarle a que destine los 100 € correspondientes a alimentación e higiene, pues si no es así, se hará transferencia a Felisi de esta cantidad para que con vuestro apoyo ella sí haga buen uso del dinero. Ya me vais diciendo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AITOR'and edp.apellido1='MORENO'and apellido2='FELIPE'),'2024-08-30','Ana: Envío correo a Toni y Nieves, Futuex: "He recibido llamada de Felisa, entre otras muchas cuestiones, como su desesperación para que se vaya su hijo ya de casa pues no aguanta más la convivencia, me dice que del dinero que tiene asignado Aitor para aportar productos de alimentación e higiene a la vivienda (100 €/semana ) sólo se destina la mitad (50€) y que él se queda el resto. No quiere darle de entrada credibilidad al 100%, pues como sabéis, Felilsi no controla bien la cuestión monetaria. Además él tiene su asignación aparte de 40 € para gastos de bolsillo, pero conociendo a Aitor, tampoco me extrañaría que se quedara con más dinero de la cuenta… Cuando podáis, por favor, aclararme este punto. Y si fuera como dice Felisi, instarle a que destine los 100 € correspondientes a alimentación e higiene, pues si no es así, se hará transferencia a Felisi de esta cantidad para que con vuestro apoyo ella sí haga buen uso del dinero. Ya me vais diciendo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2024-08-30','Ana: Correo de Estrella, S. Ecca: "Buenos días, se adjunta autorización de modificación de reintegro de Carlos, ahora es 60 €/semanal. Gracias por su colaboración." ······················· Reenvío a Toni y Mamen, Futuex. Pido que se lo comuniquen a Carlos cuando puedan.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CACHO'and apellido2='GARRIDO'),'2024-08-30','Ana: Correo de ESM (equiposaludmental.caceres@salud-juntaex.es) con INFORME DE PSIQUIATRÍA de última cita (28/08/2024) en que refiere que NO ACUDE A LA CITA, le llama por teléfono y expresa que no ha acudido "por VOLUNTAD PROPIA". El lunes anterior acudió a URGENCIAS para solicitar valoración, pero después se fue de "alta por FUGA". ············································································ Reenvío a los A. Jurídicos para que lo remitan también al JUZGADO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CARLOS'and edp.apellido1='GONZALEZ'and apellido2='LEO'),'2024-08-29','Ana: Correo de ESM (equiposaludmental.caceres@salud-juntaex.es) con INFORME DE PSIQUIATRÍA de última cita (22/08/24): Carlos sigue sin tomar la medicación, verbaliza a la Psiquiatra, Dra. Cristina Donoso, que no la necesita. *La Dra. le recomienda de nuevo tomar el tratamiento y tomar la medicación. Realiza "psicoeducación". ·············· Hace constar que la educadora que le acompaña, Mamen-Futuex, expresa que en algunos momentos se ha mostrado amenazante y le informa de algunas alteraciones conductuales como la de cortar los cables de la TV de la comunidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='MORENO'and apellido2='CARLOS'),'2024-08-30','Ana: Envío correo a Toni y Clara, Futuex: "Tras haber hablado con el Director de la Oficina RATEL del SEPE de Plasencia, os remito los informes médicos que he recabado para que acudáis al SEXPE de Plasencia para solicitar que a JOSE MANUEL MORENO CARLOS se le “RECUPERE LA DEMANDA DE EMPLEO A FECHA DE 12/01/24”. Hay que solicitar también que después le suspendan la demanda por IT para que le hagan las renovaciones automáticas. Estos trámites serán los previos para intentar restaurar el SUBSIDIO para mayores de 52 años. *Podéis preguntar por Generoso, Director del SEXPE."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='RIVERA'and apellido2='RAMOS'),'2024-09-02','-Amalia ; ingresado en HME , no está en fase aguda , es residual , van a proponer ingreso directamente en Larga Estancia . Está en una cama de medicina interna pero sin criterio.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='ARNEDO'and apellido2='LOPEZ'),'2024-09-02','Buenas tardes, informaron que el paciente Francisco José Arnedo López, del centro sociosanitario "Adolfo Díaz Ambrona", ha fallecido sobre la 13:30 del 21 de agosto de 2024. Se ha informado a la familia y será trasladado la provincia de Granada. También se ha informado al seguro de decesos. Un saludo','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='PEREZ'),'2024-09-02','-Amalia ; derivo el caso a zona Tere.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIA'and edp.apellido1='PEREZ'and apellido2='PEREZ'),'2024-09-02','TERESA RECIBO LLAMADO DEL TS DE LA MORERA PREGUNTANDO POR LA PALZA DE CO LE COMENTO A AMALIA YA QUE ERA UN CASO SUYO le he preguntado a Charo , está la primera en lista para Zafra , así que no creo que tarde mucho en entrar . El problema de la higiene es ese , igual le ocurría cuando iba al CO de Ap3 . Es una familia donde la madre y todos los hermanos tienen discapacidad. No colaboran en nada , el programa Familia dejó de atenderlos porque no aceptaban la ayuda . El juzgado autorizó el internamiento involuntario en plaza residencial pero se oponen por completo y amenazan con todo . Aunque llegase a entrar , saldría el mismo día del centro , involuntariamente aunque tengamos la orden judicial no podemos retenerla . Sí estaría dispuesta a ir a C.O. por eso lo solicité. Percibe PFHC y P. Orfandad , se le entrega un reintegro mensual que saca el hno. mayor que es el que no tiene discapacidad y los engaña a todos . Si aceptara una hora de SAD para bañarse , pero no va a querer . Y luego la ropa no se lava . Ella es muy buena , tiene bastante discapacidad , muy bruta también . En la pandemia le pegó una patada y mordió a un policía local que la paró cuando iba con el hno. al banco . No me veas ! iba un amigo mío de compañero y lo dejaron pasar ... Se han ido de Badajoz , vivían en las 800 , en una casa que no reunía condiciones de habitabilidad por conflictos con un vecino. La Morera es el pueblo del padre ( fallecido ) y allí tenían esta casa donde se han ido a vivir . Está adaptada en el pueblo , pero dentro de sus limitaciones claro . Te paso el caso para seguimiento en tu zona , en la intranet tengo bastante anotado . El que manda en la casa es el hno. mayor , tengo su tf en la intranet . Se niega a un ingreso en RAL pq sabe que le quitamos la pensión y él es el que maneja y se gasta todo el dinero. Si tienes cualquier duda me dices.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALFONSO DAVID'and edp.apellido1='REBANALES'and apellido2='NIETO'),'2024-09-03','Se le dará 93€ a la semana , en lugar de los 100 iniciales para que pueda cubrir los 24€ del alquiler de la VPP Lo va a retirar en el Santander de la zona Sur de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='AGUDO'and apellido2='CUMPLIDO'),'2024-09-03','Psicologo CRR Merida : Te escribimos para informarte de la evolución de Javier Agudo, su estado actual y para poder contrastar contigo sobre una última información que Javier nos ha dado. Respecto al proceso de planificación terapéutica de alta que habíamos abierto con Javier, ante su motivación e insistencia de querer marcharse del recurso y por tanto, en ese caso, hacerlo de la mejor manera posible, actualmente se ha pausado, volviendo a tener una mínima motivación de mantenerse en el recurso y seguir trabajando en su proceso de rehabilitación. Aun así, sigue manteniendo la motivación de trabajar para marcharse del recurso en un medio plazo, con actitud resistente a la hora de tolerar los tiempos necesarios para conseguir terminar su proceso de rehabilitación y, por tanto, se mantiene la posibilidad de volver a iniciar el proceso terapéutico de alta (aunque ésta no sea terapéutica sino por voluntad de Javier) en caso de que vuelva a tener una motivación de marcharse del recurso inminente. Actualmente, además, presenta un nivel de activación elevado con mucha ansiedad, teniendo un alto nivel de sufrimiento. Pese a ello, se mantiene abordable y se sigue trabajando con él para que, en estas situaciones, mejore su capacidad de autorregulación, así como el manejo funcional de sus dificultades psicológicas. Información a contrastar: Javier nos ha comunicado preocupación acerca de una casa de su propiedad, en Puerto de Santa Cruz, la cual no tiene adecuadamente cerrada desde su último ingreso en el CRR de Mérida. Al no tener información previa al respecto, le preguntamos sobre cuando adquirió dicha propiedad y sobre las escrituras. Nos devolvió que la propiedad de la vivienda la adquirió junto con su padre y que no sabe nada de las escrituras desde un proceso de mantenimiento que se hizo de la casa, cuando estaba en el CRR de Plasencia, a través de la comisión tutelar de Cáceres. Respecto a su principal preocupación, comunica que la última vez que estuvo en la casa fue antes de ingresar en el CRR de Mérida, cerrando la puerta principal sólo con una cuerda. Dado que hay muchas lagunas en su narrativa y teniendo en cuenta las dificultades psicológicas que tiene Javier, necesitamos contratar esta información, para que, en caso de que sea cierta, poder apoyarle en una gestión adecuada y autónoma de su propiedad. ------------------------------------------------ Se confirma que es propietario al 50% de esa propiedad , se le da la información al centro.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2024-09-04','TERESA EMAIL DE FUTUEX Comentar que se ha producido el ingreso en centro de día de la localidad, de Pablo Galán en el día de ayer. En primer lugar, desde el equipo de apoyo social comunitario, en visita efectuada ayer, se ha gestionado y reunido toda la información necesaria para que Pablo pueda comenzar a realizar sus comidas en el Centro de Mayores Adolfo Suárez, ubicado en Zalamea de la Serena. Se ha mostrado muy satisfecho y colaborador con esta nueva disposición, lo que facilita su integración en el servicio ofrecido por el centro. En cuanto a la ayuda a domicilio, Pablo continuará recibiendo este servicio, aunque se ha determinado una reducción en las horas de asistencia. Debido a este cambio, los días martes y jueves no podrá asistir al desayuno en el centro ya que coincide en el horario. Para asegurar que no le falte el desayuno en estos días, se ha dispuesto que continúe recibiendo los alimentos mínimos necesarios en su hogar. El Centro de Mayores se encargará de proporcionarle todas las comidas diarias, que incluyen desayuno, almuerzo, merienda y cena. Además, se cuenta con el servicio de enfermería en la residencia, por lo que el próximo 9 de septiembre, Pablo recibirá allí la inyección correspondiente a su tratamiento médico. Es importante destacar que, a solicitud de Pablo, la medicación continuará siendo adquirida en la farmacia de referencia. Por último, se ha acordado que la asignación quincenal destinada a Pablo se utilizará para la compra de tabaco, algunos alimentos para el desayuno, la adquisición de bombonas de gas, la recarga de su teléfono móvil, y la compra de productos de limpieza e higiene personal, así como para cubrir algunas necesidades adicionales de ropa. Debido a que al parecer esta en plaza privada, porque no daba grado de dependencia, le cobran unos 500 euros, asique sin duda no podra disponer de la misma cantidad de dinero quincenal que esta ahora, por si considerais ajustarle el presupuesto, y en función de lo que se decida se lo comunicamos. DOY ORDEN DE ANULAR CENTRO DE DIA ES INVIABLE PABLO SOLO COBRA PNC','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='LEAL'and apellido2='PARRA'),'2024-09-03','Ana M.ª (633.613.809).Madre','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANASTASIO'and edp.apellido1='VAQUERIZO'and apellido2='PIZARRO'),'2024-09-05','TERESA SITUACIÓN ECONÓMICA CORRECTA. SALDO 05/09/2024: 8.200 € APROX. PRESUPUESTO OBRA: 8.700 € DADO QUE EL PRESUPUESTO ES MUY ELEVADO PARA SU PATRIMONIO ACTUAL, SE VA A ACTUAR DE LA SIGUIENTE MANERA: • MIGUEL VA A AVERIGUAR SI LA VIVIENDA ESTÁ A SU NOMBRE O DEBERÍA DE ESTARLO. • MIGUEL: GESTIONARÁ LA AUTORIZACIÓN PARA LA VENTA (VECINA O INMOBILIARIA) • SI TODO ESTÁ A SU NOMBRE. 2 OPCIONES:  VENDER SIN ARREGLAR.  ARREGLAR Y VENDER.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-09-06','TERESA RECIBO LLAMADA DE LA POLICIA NACIONAL DE CACERES 927301693 INDICANDO QUE TIENEN DETENIDO A JOSE MANUEL. SOLICITAN QUE SE PERSONE ALGUIEN EN LA COMISARIA. LE EXPLICO QUE ES UNA TUTELA ADMINISTRATIVA QUE NO TENEMOS PERSONAL PARA DESPLAZARSE HASTA CACERES LE PREGUNTO QUE HA HECHO Y ME DICE QUE NO ME LO PUEDEN DECIR SE QUEDAN MI TELEFONO POR SI TIENEN QUE VOLVER A CONTACTAR CONMIGO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANASTASIO'and edp.apellido1='VAQUERIZO'and apellido2='PIZARRO'),'2024-09-06','miguel, envío a Tere, Alberto y Angel lo que he averiguado tras recibir el presupuesto de arreglo de la vivienda de Tere y algunos documentos de Tere ayer(escritura donación del abuelo a la tía Elena, copia simple del testamento del tío Luciano a favor del tutelado, fotocopia de la partida de nacimiento del tutelado...): "Hola, de la documentación que me dio ayer Tere: una escritura de donación del abuelo a la tía (finca registral 918), y un testamento del tío del tutelado Luciano, a favor de nuestro tutelado (cuyos bienes desconocemos y no sabemos si hizo o no herencia y que no viene ahora al caso, y demás documentos sin relevancia aqui) Como os comenté ayer, estamos intentando localizar la vivienda de la que dice el Ayto que es dueño nuestro tutelado para arreglarla, venderla…para lo cual necesitamos algún documento que diga que nuestro tutelado es dueño y por tanto responsable de arreglar su vivienda. Tras varias indagaciones con notaria de Barcarrota, la de jerez (depositaria de escrituras notariales antiguas de Barcarrota), y el registro de la propiedad de Jerez de los Caballeros, me confirman que efectivamente esta casa fue de nuestro tutelado, adquirida el 14-6-1994 ante el notario de Barcarrota Pablo Antonio Mateos Lara, y cuya escritura me están localizando en la notaria. Pero me confirman enla notaria de Barcarrota que no es esta nuestra casa, y por tanto la vivienda que da problemas es otra la de la c/Francisco Rubio 16, es decir que nuestro tutelado ha tenido 2 o 3 casas en la misma calle. Por tanto, seguimos sin tener ningún documento oficial que diga que esta vivienda es de nuestro tutelado (la notaria me dice que a lo mejor está inmatriculada, es decir que nunca se inscribiera en el registro de la propiedad) Por tanto, lo único que tenemos es el certificado catastral que os adjunto a nombre del abuelo. Si no logramos algún documento de esta vivienda habría que traer desde el abuelo hasta él la titularidad de la vivienda para lo que necesitaría certificados de defunción y certificado de últimas voluntades del abuelo, abuela, sus dos tíos Elena y Luciano, sus testamentos o declaración de herederos, el certificado de defunción, certificado de últimas voluntades, testamento o declaración de herederos de su madre Angela, y los bienes inmuebles y cuentas bancarias que dejaran los mencionados familiares. Una vez obtenida esta documentación necesitaríamos un abogado y procurador y solicitar aprobación de la herencia, y preparar la documentación para una venta (pediríamos una tasación) de la vivienda recién inscrita en el registro de la propiedad. Por tanto, si no obtenemos esa documentación no podría ni venderla ni nada de nada. Para lo cual necesito fechas y lugares de fallecimiento de estas personas, sus dni, sus cuentas bancarias, los bienes inmuebles (los buscaría yo por catastro y registro de la propiedad). Por tanto en mi opinión como no se puede vender algo que no está a su nombre oficialmente o la vecina se lo reclame vía judicial y ahí se demuestre la titularidad o no de nuestro tutelado o que renuncie a la herencia. Ya me dices Tere si podemos conseguir esa documentación o algún otro documento de la vivienda correcta ya que las escrituras que me diste como digo es de otra vivienda (me lo confirma Mar de la Notaria de Barcarrota)"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-09-06','miguel, llamo a la polícia que me indica que ya ha puesto a disposición judicial al tutelado en el jzdo de instrucción nº2 Cáceres. Envío email a Tere, Ana, Inés y Angel: Buenos días, he hablado con la policía nacional y me han remitido al juzgado de instrucción nº2 donde ahora tendrá la vista. Le han asignado abogado de oficio, D. José Alvaro Santibañez Baez. No es necesario que comparezcamos. Me ha tomado nota del teléfono, email de la ctutelar y de Lexnet para comunicarme el número de procedimiento DPA que está dando de alta. El motivo no me lo ha dicho pero ha venido a decirme que por lo mismo que el procedimiento que adjuntas Inés del lunes… No os preocupéis le acompaña Nieves, y ya están informados los dos de que el lunes vuelvan para que le vea el forense a las 10h. Por tanto el procedimiento de hoy nos comunicará el juzgado el motivo del mismo pero no creo le de tiempo de la vista que ahora va a ver… Cuando sepa algo más os informo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PABLO'and edp.apellido1='GALAN'and apellido2='GILGADO'),'2024-09-09','TERESA ENVIO REVISION PIA PARA REACTIVAR EXPEDIENTE Y NEGOCIAR CENTRO DE DIA Y PODER PAGAR PLAZA PUBLICA PABLOC COMIENZA HOY A ASISTIR A CENTRO DE DIA DE LA LOCALIDAD','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='VICENTE'and apellido2='VICENTE'),'2024-09-09','TERESA Se persona el cliente tutelado Jose Vicente Vicente con DNI 8892616B en la oficina solicitando la transferencia de sus saldos a la cuenta corriente del banco Santander ES0500495346772817007303. Está a su nombre y dice que le habéis dado el visto bueno por teléfono. Si esto es así, por favor, háganos llegar el documento que valide la operación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUANA DE LOS REMEDIOS'and edp.apellido1='PALOMO'and apellido2='GONZALEZ'),'2024-09-10','-Amalia , pido al centro que lleven el DNI a escanear al banco.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANASTASIO'and edp.apellido1='VAQUERIZO'and apellido2='PIZARRO'),'2024-09-09','TERESA ENVIO CORREO A EVA VECINA QUE RECLAMA EL ARREGLO DE LA VIVIENDA Lamento comunicarle que no vamos a poder arreglar la vivienda. Nos consta que ha vendido una vivienda en la misma calle pero ni Ayto, Oar, Notaria de Barcarrota, Catastro, ni registro de la propiedad consta a nombre del tutelado ningún bien inmueble, y que sin un documento oficial que acredite que él es titular no podemos entrar en arreglar la vivienda ya que no nos lo autoriza el juzgado al ser un importe tan elevado. Entendemos que debes denunciarlo ante el juzgado, ya que necesitamos que haya un documento oficial (aunque sea una sentencia judicial) que diga que ese bien es de él para que podamos proceder al arreglo. La pista se pierde en el abuelo, que es el único que aparece en Ayto y Catastro. Siento darle esta noticia pero como ya le digo no podemos arreglar una vivienda que no está a su nombre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='IGLESIAS'and apellido2='MENDOZA'),'2024-09-10','Amalia: Hablo por tf con Teresa , sobrina de la fallecida ( 626303272 ) quiere información para hacer la herencia . En el juzgado le han dicho que el expediente está archivado. Le confirmo que la R.Final de cuentas está enviada . Volverá al juzgado , son 5 hermanos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENCARNACION'and edp.apellido1='PITEL'and apellido2='MARQUEZ'),'2024-09-10','-Amalia Nombrada C.R. para todas las esferas Hablo con Inma , TS Pueblonuevo, vive sola , tiene hnos en el pueblo con los que no se relaciona , padece esquizofrenia . El verano pasado tuvo un internamiento involuntario en UHB promovido desde A.P. No acude al ESM de Montijo , dejó la medicación que le pautaron en la UHB. Hace años el enfermero le inyectaba la medicación pero lo trasladaron y nadie ha vuelto a tratarla . Ella no tiene conciencia de enfermedad y no hay adherencia a tto. Tiene delirios en relación a la materniadad ( hay una habitación preparada para un naciemiento ...) La TS del ESM ( Lali) e Inma están coordinadas con el caso . La casa era de los pades , los hnos se la han cedido , sucia , acumulación de enseres.. Compras compulsivas en Venta catálogo , compra con una revista y paga ingresando en un Nº cuenta . No vamos a poder evitar eso pq dinero hay que enviarle . Pensión alta .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2024-09-11','miguel, email a ctutelar de FRANCISCO JAVIER RODRIGUEZ PEREDA >javier.rdguezper@salud-juntaex.es> Hola, buenas tardes: Aporto la dirección que me facilitó su hermana María José por si es de vuestro interés y lo queréis actualizar. -Dña. María Josefa Murillo Horrillo, mayor de edad, vecina de Azkoitia-Gipuzkoa con domicilio en c/ Joanes Etxeberri, num 2, 1ºC. CP 20720 D.N.I. 08902080-E. Mª José móvil 675882305','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REGINA'and edp.apellido1='REINA'and apellido2='LARA'),'2024-09-10','TERESA correo de la casa hospital de santiago Regina está ya en el centro. Su familia de acogida nos irá pasando las facturas de objetos personales que le han ido comprando este verano para su estancia aqui y en el instituto. Os las pasaremos en cuanto las tengamos. Nos mandarán también un presupuesto para las gafas que necesita. Os lo haremos llegar para su aprobación o no. Está pendiente de una beca para material escolar, la ha solicitado su familia de acogida. Nos pide que nos informéis cuando le sea concedida para que se lo comuniquemos también. Mañana tiene la presentación del curso en el instituto. En esta nos indicarán materiales que necesita, horarios,...etc Os iremos informando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN PABLO'and edp.apellido1='ESTEBAN'and apellido2='CORRAL'),'2024-09-11','miguel, email de Estrella a Alberto, Tere y a mi: Buenos Días, he comprobado la cuenta que acaba en 6701(cargan agua.luz.basura y IBI) y ya solo hay 300 y pico de euros. Como va el tema de la herencia?. urge resolverla. Los seguros con Caser están a nombre del padre, no me facilitan nada.uno de ellos cumple el 16 de octubre de 2024, lo devuelvo? Que hago con los suministros? Ya me decis -------------------------------- Mi contestación:Hola, como os comenté la última vez, había hablado con la tía y me dijo que el primo estaba muy ocupado, que era el que tenía papeles, el que sabía del tema, pero que sus horarios eran por las tardes y que imposible me llamara por la mañana, aunque le daría el recado. Elvira, la Ts también quedó en junio en buscar de forma inmediata y enviarme todo lo que tuviera. Han pasado cerca de 3 meses y nadie ha enviado nada, y por tanto seguimos en el punto inicial…sin papeles no puedo hacer nada. He llamado a Elvira pero no está y en el ayto de Castilblanco (en Puebla de Alcocer es donde está el tutelado) me dicen que sólo va los lunes, miércoles y viernes. Voy a volver a llamar a final de la mañana por que ha salido, y si no lo logro la llamaría el viernes…Insistiré, más no puedo hacer.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN PABLO'and edp.apellido1='ESTEBAN'and apellido2='CORRAL'),'2024-09-12','miguel, envío email a Alberto, Estrella y Tere: Buenos días, ayer logré hablar con Elvira la Ts, que aunque dice no tener más documentación que la que remitió en su día, va a intentar hablar con el primo para que deje la documentación necesaria para hacer la herencia en la notaria. La llamaré en unos días a ver qué averigua.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2024-09-12','TERESA EMAIL DE OLGA TS Teresa, pide el informe y que te digan. yo lo veo por la calle como muy adormilado en ocasiones, se acuesta en los bancos de la plaza y son las 12 de la mañana y sigue allí tumbado, y muchas veces dormido (la última vez los municipales lo levantaron, por eso te digo que siempre hay algo con él) él está relacionándose ahora con un muchacho que no es tampoco muy inestable. Ha ido en diferentes ocasiones a molestar al centro residencia, para pedir información por comida a domicilio, pero no guarda turno, llama por la ventana para que se le atienda,... Bueno, lo que ya sabemos hace años de este hombre. Esta semana son las fiesta en la plaza del pueblo, vamos en su misma puerta, miedo me da como reaccione, por que no sabe por donde va a salir. Ya me dices que te dice la psiquiatra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2024-09-10','TERESA EMAIL DE OLGA TS Buenos días Teresa, ¿cómo va la búsqueda de vivienda para Ildelfonso? Te comento un poco la situación: Ildelfonso tiene un perro en su domicilio, lleva dos días llevándolo a casa de una señora, se lo amarra a la ventana de madrugada (en torno a las 2 de la mañana). El perro se pone a ladrar al verse atado. Además en esta vivienda hay perros que se ponen a ladrar al escuchar a el que está en la calle. Esto está acarreando incomodidad para el resto de vecinos, mal estar,,... La policía local ya le ha apercibido verbalmente, pero lo ha vuelto a hacer, por lo que van a denunciarlo. La señora de la vivienda (con la que antes mantenía relación de amistad, pero rompieron la relación hace un tiempo) también ha indicado que va a denunciarlo. Por otro lado, como te quedamos, he pedido a la policía local las denuncias que han puesto a Ildelfonso, me han entregado un pequeño informe, me indican verbalmente que es muy habitual tener alguna queja de él por parte de vecinos, o él pasa por su despacho con alguna historia, o quiere denunciar a alguien.... Bueno, ya me cuentas qué tal va lo de la búsqueda de vivienda en Badajoz. Seguimos en contacto. Un saludo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2024-09-13','TERESA Lo de los pisos es prácticamente misión imposible.. Tiene un perro de unas grandes dimensiones, no se ha visto nada que admita mascotas, o que no solicite contrato de trabajo, pisos en torno a 500/550.. y medianamente en buenas condiciones, que el seguramente va a destrozar. Donde vive ahora es digamos es como muy modesto y el no tiene como estercolera. Asique de lo mirado, hasta ahora la verdad no vemos nada. Nos hablaron a través de otra tutelada, de un apartamento en el cerro de reyes por 250 eu (no se si conoces badajoz) pero es un barrio algo conflictivo, no es el peor, pero no sabemos si seria buena idea que recalará en un barrio así..y luego que según nos dice es un apartamento hecho de una forma no legal, ya que la persona no podria empadronarse alli, y no sabemos si admitiria contrato y estas cosas reguladas. Es decir, en cualquier circunstancia, no barajaiamos esta opcion de hecho al plantearlo esta tutelada como te digo, lo desestimamos directamente y no llegamos ni a pasar la propuesta a la comisión, pero en este caso.. no se, como medida desesperada, localizar el numero del arrendador y facilitarselo a Ati y que se entiendan entre ellos?? no se si es la mejor idea tampoco..','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO JAVIER'and edp.apellido1='FRAILE'and apellido2='SALAMANCA'),'2024-09-20','TERESA Bono social válido hasta: 26 de julio de 2026','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOLORES'and edp.apellido1='MACARRO'and apellido2='CAMACHO'),'2024-09-13','TERESA TERE: OK, ACTUALIZADA FICHA CON NUEVA SITUACIÓN INDICADA X TERE. Coste plaza residencial: 660,26€/mes Coste podología: 10€/mes Coste de farmacia: lo cargan directamente en la cuenta Dinero de bolsillo: no maneja MARIA: DAMOS DE BAJA LOS CONSUMOS: AGUA Y LUZ • TUTELADA NO VA A VOLVER A VIVIENDA. TERE/MARÍA: COBRO INDEBIDO X VINCULADA...CÁLCULO APROX. 10 MESES X 361 €/MES: 3.610 € • TERE ESTÁ EN CONTACTO CON ELLO. • UNA VEZ QUE TERE TENGA LA RESOLUCIÓN DECIDIMOS COMO ABONAR (FRACCIONADO O NO).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='MUÑOZ'and apellido2='MELCHOR'),'2024-09-16','Ana: Correo del 2/09 de Ana Sánchez, Res. (anatdelat@hotmail.com) a la S. Ecca. y a mí: "Le escribo desde la Residencia de Mayores de Torrecillas de la Tiesa. Habría alguna posibilidad de cambiar de banco a la usuaria ISABEL MUÑOZ MELCHOR? En el pueblo ya no tenemos Unicaja, solamente disponemos de Caja Almendralejo. Podría ser?" ·········································· *Me comunican desde la secc. ecca. que ya están haciendo las gestiones para el cambio. Intentarán que esté abierta para octubre.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2024-09-16','Ana: Correo de Ángel, del día 2/09, en respuesta a mi correo: "En relación con el correo que reenvía Ana, de Helga, la hermana de Juan José, os reenvío el correo que os remití, en octubre del 23, en el que os indicaba que se procediera al cambio de titular de los suministros, info de cuentas, comunidad de propietarios, recibos y seguros. En cuanto a la venta, contacté con Viprés y Helga, para intentar hacer una visita a la casa, a los efectos la valoraran, sin éxito, por parte de ambas. Les vuelvo a insistir."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUIS'and edp.apellido1='JARAIZ'and apellido2='LEON'),'2024-09-04','Se envía al CSS-Plas. CONSENTIMIENTO INFORMADO PARA LA ADMINISTRACIÓN DE CONTRASTE ENDOVENOSO debidamente firmado y sellado por la Representante Legal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTIN'and edp.apellido1='MIRANDA'and apellido2='HERNANDEZ'),'2024-09-16','Ana: El día 4/09/24, Amalia, TS, remitió al CRR (crr@grupociudadjardin.com) solicitud urgente de INFORME DE PSIQUIATRÍA (Dra. Mª Isabel Rubio) para la revisión del grado de "incapacidad". ········ Consulto a Amalia a qué se refieren exactamente. ····· Me reenvía el correo original, no lo especifican.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN JOSE'and edp.apellido1='GONZALEZ'and apellido2='CARRERO'),'2024-09-16','Ana: Tiene seguro de hogar hasta abril de 2025, Estrella, S. Ecca, lo cambiará a uno más económico llegada la fecha. ······ El Seguro de Decesos de Santa Lucía está a nombre de la madre, lo abona ella, tenemos copia de la póliza (están la madre, la hermana y él). ······················ *Correo de Helga, hermana, el día 4/09: "Vengo de una oficina de Iberdrola, he realizado el cambio de titular y les he facilitado la cuenta de Juan José. A partir de hoy realizarán el cargo de los recibos. Tiene contratada muy poca potencia. Los recibos son de 3,5 € mensuales aproximadamente." *Se refiere a la vivienda herencia del padre, ella renunció a dicha herencia. ······················· *Ya ha cambiado la domiciliación de todo (comunidad de vecinos, suministros, IBI).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2024-09-16','Ana: Llamada de Isabel Cano (649 642 635) con Mónica, Ed. PP.SS.: ha acudido al Jdo. a la comparecencia (Procedimiento por abuso sexual - taxista). Por segunda vez lo han suspendido. La primera vez fue por no asistir nadie de la CTAEx y en esta ocasión por no contar con Abogado ni Procurador. ················ *Hablo con Ángel, Asesor Jurídico CTAEx, estaba ya haciendo la solicitud al COLEGIO DE ABOGADOS. ··········· A petición de Ángel, envío correo a Carolina, Directora, Paula, TO - CRR y Mónica, Ed. PPSS, solicitanto Certificado de Ingreso/Residencia en el recurso residencial. ·········································· Escribo a Ángel, A. Jurídico: "Te reenvío correo con CERTIFICADO DE PRESTACIÓN DE SERVICIO DE PISO SUPERVISADO relativo a Isabel Cano, especifica fecha de ingreso y permanencia en la actualidad." ············ Guardo Cdo. en el expediente digital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2024-09-16','Ana: Correo del 2/09 de la farmacia San Pedro Ledesma (mariacarmensan@redfarma.org) al ctutelar@: "EL PACIENTE JEUS MANUEL RAMOS BARGÓN SOLICITA UN TRATAMIENTO NO FINANCIADO POR LA SEGURIDAD SOCIAL. EL MOTIVO DE ESTE CORREO ES SABER SI SE LO SUMINISTRO , Y LUEGO PASO LA FACTURA MENSUALMENTE. A LA ESPERA DE RESPUSTA , AGRADECERÍA UN TELÉFONO Y UNA PERSONA DE CONTACTO." ······················································ Respuesta de la S. Ecca: "Buenos días, si el tratamiento ha sido prescrito por su medico de atencion primaria y no está financiado por la seguridad social, se le facilita y lo recargan en la factura mensual Si por el contrario, este tratamiento lo está solicitando sin prescripción médica, nosotros no lo abonamos, debe hacerlo Jesus Manuel con sus gastos de bolsillo. La persona de contacto es su trabajadora social Ana Matamoros, su teléfono es 924 930245 y correo electrónico amatamorosg@salud-juntaex.es., estando de vacaciones esta primera quincena de septiembre"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ROMERO'and apellido2='PEREZ'),'2024-09-16','Ana: Correo de Alberto, Jefe S. Ecca. del día 3/09: "LOURDES: OK A LA COMPRA DEL ORDENADOR (DE LOS 2 INCLUIDOS EN PRESUPUESTO), QUE CONSIDEREN OPORTUNO."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE LUIS'and edp.apellido1='MURILLO'and apellido2='HORRILLO'),'2024-09-16','Ana: Se acepta PRESUPUESTO de TRATAMIENTO DENTAL (220 €) facilitado por Javier Rodríguez, TS del CSS-Plas. (javier.rdguezper@salud-juntaex.es). ··································································································································································································· Correo del día 9/09 de Javier, TS CSS - Plas. (javier.rdguezper@salud-juntaex.es) en respuesta a la consulta realizada por Miguel, A. Jurídico CTAEx: "le adjunto dni del tutelado y la información sobre los hermanos que disponemos: Dña. María Josefa Murillo Horrillo, mayor de edad, vecina de Azkoitia-Gipuzkoa con domicilio en Barrio Alcibar, Casa Toki Eder, S/N – 4º Izda. y con número de D.N.I. 08902080-E. Mª José móvil 675882305 D. Andrés Murillo Horrillo, mayor de edad, vecino de Ordizia-Gipuzkoa, con domicilio en Zuberoa Kalea, 3 – 3º B, y con número de D.N.I. 15244794-A. Andrés (634450994) Dña. Inés María Murillo Horrillo, mayor de edad, vecina de Donostia-San Sebastián, con domicilio en Katalina Eleizegi, 34 – 2ºA B, y con número de D.N.I. 44126638-B. Ainés (tlfno 659-251339)"','2');
