insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOROTEO'and edp.apellido1='DIAZ'and apellido2='CERRO'),'2024-09-16','Ana: Llamada de Doroteo Díaz Cerro (609 928 621), sólo para saludar. Aún tiene pendiente hacer los trámites de herencia de su tío fallecido. ···· Dice que irá a Cáceres para pedir el presupuesto, pues ya solicitó la documentación necesaria a Gefiscal.','2');
