insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MONTAÑA'and edp.apellido1='GONZALEZ'and apellido2='ROLO'),'2024-09-16','Ana: Envío correo a Mamen y Toni, Futuex: "...¿Podrías por favor tratar de averiguar si tiene deudas con la comunidad de vecinos y en caso contrario informarnos sobre cómo se están afrontando estos pagos, es un gasto que no está domiciliado?"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GLORIA'and edp.apellido1='VERA'and apellido2='LLORENTE'),'2024-09-16','Ana: Conversación con Soraya Masa, Jefa Ud. PP.AA.: Según Dictamen Técnico del CADEX, presenta DISCAPACIDAD INTELECTUAL LEVE. Puesto que no ha funcionado nunga en los centros de discapacidad, plantea que solicitemos plaza en Salud Mental. ····································· Consulto a Raquel, Secc. Acceso a RR de Salud Mental si alguna vez ha sido derivada a CRR. ··· Lo único que les consta es que estuvo ingresada en CRR de Ba desde Julio de 2007 hasta marzo de 2009 en que causó BAJA. No saben motivo. ····································· *Plantearemos a Estrella Durán, TS del CSS, que plantee en el equipo del centro posible derivación a los RR de la Red de Salud Mental.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE BLAS'and edp.apellido1='CAÑAS'and apellido2='LOZANO'),'2024-09-16','Ana: Llamada de Teodora, madre de José Blas (927 248 986), quiere si su hijo entrará pronto en un centro. Dice que ella ya es mayor (86 años) y no puede controlarlo. ··································································································································· Consulto a Charo, Aux. Adtvo. de la Secc. Discapacidad: José Blas está muy abajo en la lista pues sólo tiene grado I de dependencia. ······ *Los centros en los que está más cerca son: Fuente de Cantos (el 6º) y Nuñomoral (7º).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELISA'and edp.apellido1='BRUNO'and apellido2='SAAVEDRA'),'2024-09-16','Ana: Correo del día 02/09 de Estrella Durán, TS CSS Plas: "Me preguntan desde Admisión si Felisa Bruno Saavedra tiene el Auto de ingreso involuntario, para que nos lo enviéis." ······································· Mi respuesta: "Te copio aquí la respuesta que me da mi compañero Miguel, A. Jurídico: “no sabemos cómo volvió a ingresar en la UHDAC. Si la Ctaex no lo ha solicitado, entiendo que fue por derivación, y es al equipo médico que corresponda a quién deberían pedirlo. Nosotros unas vez que la persona ya está ingresada no podemos solicitar un internamiento porque ya se ha producido. Si les vale el que hace años se dictó, sería lo único que podríamos enviarles. No obstante, según nos explicó José Manuel (el fiscal), cuando se producen ingresos de urgencia, se pide sea ratificado el mismo por el juzgado por parte de quién lo realiza.“ "','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='LANCHO'and apellido2='SANGUINO'),'2024-09-17','Ana: Envío a Jaime, Aux. Adtvo. CTAEx: "Cuando puedas, por favor, envía mediante registro (TRAMITA), la siguiente documentación relativa a D. ANDRÉS LANCHO SANGUINO, cuyo cargo de Curatela Representativa ostenta la CTAEx, a la Dirección Provincial del INSS – Avda. de Cáceres, 14. CP: 10001 – Cáceres: - Comunicación de MODIFICACIÓN DE DATOS BANCARIOS – Pensión de Jubilación - ALTA DE TERCEROS" ································································································································································································· Respondo a la consulta de Alberto, Jefe S. Ecca.: "- Andrés reside en la Localidad de Santa Marta de Magasca (en la residencia de mayores), no en Malpartida de Cáceres. En esta otra localidad es en la que tiene sus inmuebles (viviendas y local) - En relación a su hermano, Dionisio: o no tenemos constancia de que vayan a nombrar a la CTAEx para cargo alguno. o Reside en la Residencia de Mayores de Malpartida de Cáceres. - El cambio de nº de cuenta para el ingreso de la pensión, está en proceso. Ya le he enviado a Jaime la documentación necesaria para le dé registro en cuanto pueda. - En cuanto a los suministros de las viviendas, Óscar en su día solicitó la baja de las tres propiedades, pero se ve que no le hicieron caso y no llegó a materializarse la baja, de ahí, deduzco, vienen los recibos impagado, que son lo que ha abonado Estrella. *Andrés NO va a regresar a su domicilio pues presenta deterioro cognitivo. - En mi opinión, a Andrés se le puede quitar de las cuentas en las que consta sólo como autorizado. - En cuanto a la cuenta bancaria de la que son titulares ambos hermanos, entiendo que cuando tengamos los movimientos bancarios de los últimos 5 años se podrá tomar una decisión, no antes. Si en esos años sólo hubiera ingresos de Andrés, todo lo que se haya ingresado desde entonces se le podrá transferir a la nueva cuenta, al igual, por supuesto, que la mitad del depósito que se ha rescatado. - En cuanto a la domiciliación bancaria de su plaza residencial, entiendo que una vez se haga el traspaso del dinero que le corresponda a su cuenta, también hay que cambiar la domiciliación del cobro a su cuenta (sólo él titular). - Por último, no sé si Dionisio estaría dispuesto a tener todo en Unicaja, puedo preguntar a la trabajadora social de su localidad... si me dan respuesta os digo."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='RIVERA'and apellido2='RAMOS'),'2024-09-17','-Amalia: mañana ingresará en U.L.Estancia del CSS de Mérida . Doy orden de anular la transferencia a la familia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE BLAS'and edp.apellido1='CAÑAS'and apellido2='LOZANO'),'2024-09-17','Ana: correo de Ángel, A. Jurídico: "Se ha puesto en contacto con nosotros, Juan Manuel, el hermano de José Blas, para trasladarnos su interés en que se tramite la herencia del padre y se venda la casa donde vive José Blas con su madre (Teodora). En el Informe Social que acompañamos al inventario, la TS del SSB, de Cáceres, pone de manifiesto la mala relación que existe entre José Blas y su madre y cito: “…son muy conflictivas, llegando a amenazas verbales muy fuertes y amenazas con objetos punzantes, con miedo por parte de Teodora, que José Blas, la agreda en cualquier momento, y ella por sus limitaciones, no puede defenderse. Tras las entrevistas mantenidas por el Forense, con los miembros de la familia, éste determina que “las conductas agresivas de José Blas hacia su madre hace insostenible la convivencia de ambos en el mismo domicilio” En el mismo informe del forense se indica que “las medidas de supervisión y ayuda que precisa José Blas podrían ser provistas por un recurso de tipo residencial”. El Auto que dictó las medidas de apoyo se hace eco de esta situación, pero no se determinó su ingreso en centro, ni se dictó medida alguna. Me ha enviado, entre otra documentación, un contrato de arras con el compromiso de venta de esa casa, por 90.000 euros. En esta casa, José Blas, tiene un 15% de propiedad. Teniendo en cuenta la mala situación de convivencia en la vivienda y el interés, tanto de la madre (que tiene el 50% de propiedad), como del hermano (que tiene el 35%), para vender y que existen compradores, por el área jurídica no vemos inconveniente que iniciemos los procedimientos de autorización, tanto para aceptar la herencia, como para vender. Si estáis de acuerdo, decidme y empezamos. En el inventario, de fecha, 31/3/23, el saldo de José Blas en cuenta, era de 33.473,53 €. Entiendo que ahora será mayor. Por este motivo, hay que buscar Abogado y Procurador, de pago. Alberto: Envíame saldo en cuenta actual. Ana: Una vez conseguida la autorización de venta, supondría que habría que buscarle, bien un alquiler, bien, centro residencial a José Blas, puesto que saldría de esa vivienda y ya no sería conveniente que volviera a convivir con su madre." ······················································································ Mi respuesta: "En abril de 2023, poco después de aceptarse el cargo, José Blas renunció a la plaza residencial que le concedieron en Plena Inclusión Mérida, así mismo su hermano y su madre se negaban a su ingreso en este centro. Puesto que como tú bien has dicho no teníamos autorización de internamiento involuntario, no pudimos hacer nada al respecto, a pesar de lo que se hacía constar en los Informes Social y Forense. Pasados unos meses se arrepentían de la decisión y realizamos de nuevo las gestiones para solicitar plaza residencial otra vez. Ayer precisamente me llamó la madre preguntando por el centro, pues ella ya es muy mayor para atenderle. Pregunté a las compañeras de la sección de acceso a recursos de discapacidad y me dijeron que lo tiene difícil actualmente, pues sólo tiene reconocido grado I de dependencia, por tanto no tiene prioridad en la concesión de plaza (los de mayor grado se le ponen por delante). *En el centro en el que está más cerca está en la 6ª posición en la lista de espera, lo cual también puede variar según las solicitudes que vayan entrando. Por otra parte, aunque tiene bastante autonomía, José Blas necesita un mínimo de supervisión y apoyo, por lo que no debería vivir sólo, así que no contemplo la opción de alquilarle una vivienda. ¿Qué opción contempla el hermano para que vivan tanto su madre como José Blas? Yo no veo inconveniente en que se venda dicha vivienda, pero no antes de que se le conceda plaza residencial."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CASTILLO'and edp.apellido1='SOLIS'and apellido2='MELENDEZ'),'2024-09-17','-Amalia , su marido me indica que hoy pasa a UME , ha estado 2,5 meses en UHB. LLamo al centro para cuadrar pto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2024-09-17','Ana: Correo de Felisa Custodio, TS CAMF (trabajadora_social_alcuescar@imserso.es) a los A. Jurídicos, con copia a mí: "estoy hablando con la hermana de la residente. Refiere que necesita la renuncia formal de Carmen Gómez a la herencia de su madre, a efectos de que su hijo pueda renunciar también a la misma (sobrino de Carmen). Ruego por favor la firma ante la notaría, llevamos pendientes de este trámite desde el 22 de mayo. Si lo estiman oportuno, ruego contacten con la hermana de la residente, Rocío, ya que es el familiar que insiste en tener hecho este trámite, la misma me autoriza a darles su teléfono: 626877276. Está muy preocupada porque ya han pasado más de seis meses desde el fallecimiento."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='DEBON'and apellido2='CHENIQUE'),'2024-09-17','Ana: Correo de Felisa Custodio, TS CAMF (trabajadora_social_alcuescar@imserso.es): "el pasado mes de agosto desde el Departamento de Terapia ocupacional se ofrecieron en las salidas que hacen al mercadillo, a comprarle a la residente unos tops que demandaba. Se les dio 15 euros el día antes para poder realizar la compra y lo guardaron en su despacho. Cuando fueron a coger el dinero ya no estaba, desconocemos que ha podido pasar. La terapeuta Marta optó por ponerlo ella de su bolsillo además de hacer un comunicado sobre la “pérdida del dinero”. Si os parece bien os propongo que el dinero puesto por Marta le sea devuelto por la residente. Adjunto el ticket, en concreto son 13,90 euros." ············································································· Mi respuesta: "Acabo de hablar este tema con mis compañeras del área social y entendemos que a Marta, como profesional en el desempeño de su trabajo, no debería suponerle ningún coste, habiendo actuado de buena fe prestándole ese dinero. Por tanto, siendo una situación excepcional, se acepta vuestra propuesta de que Isabel Debón Chenique le devuelva el dinero que le prestó. Ya nos diréis si averiguáis que ocurrió con el dinero que se había apartado para la compra de los tops. Pongo en copia a Lourdes, compañera de la sección económica."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LEON'and edp.apellido1='LEAL'and apellido2='PEREZ OLAGUE'),'2024-09-17','Ana: Correo de Sara, enfermera de la Residencia Santa Ana (malpartida@nexusintegral.com): "BUENOS DIAS, NOS PONEMOS EN CONTACTO CON USTED PARA COMUNICALRE LA NEGATIVA A LOS TRATAMIENTOS PAUTADOS Y A LA ASISTENCIA A LA CONSULTA MEDICA DE NEUMOLOGIA POR PARTE DE D. LEON LEAL PEREZ OLAGUE, ANTE LA IMPOSIBILIDAD DE CONVENCERLE TANTO MEDICO COMO EQUIPO TECNICO Y DIRECCION DEL CENTRO NOS PONEMOS EN CONTACTO PARA VER SI A TRAVES DE USTEDES SE PUEDE HACER ALGO. ADJUNTO DOCUMENTO FIRMADO POR EL USUARIO." ···················· Reenvío coreo a los A. Jurídicos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SERGIO'and edp.apellido1='SOLANILLA'and apellido2='LUJAN'),'2024-09-18','Ana: envío correo a la Casa de la Misericordia (casadelamisericordia.alcuescar@gmail.com): "Adjunto el Consentimiento Informado par la Administración de la vacuna frente al Neumococo firmada digitalmente por la Representante Legal."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUSTAVO ALFREDO'and edp.apellido1='CASTAÑO'and apellido2='SOTO'),'2024-09-16','Ana: Correo del día 13/09, de Estrella, S. Ecca., a Toni-Futuex: "se adjunta póliza de seguro de hogar formalizado con la correduría de seguros GEX BROK."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2024-09-18','Ana: Correo del día 9/09 de Alberto, Jefe de Secc.: "LOURDES/ANA: OK AL COMPROMISO DE ABONO DE LUZ Y AGUA CUANDO SEA POSIBLE. • AGUA: QUE NOS REMITAN PRIMERO EL IMPORTE DE LA DEUDA. • LUZ: EL IMPORTE DE LA DEUDA ES DE 193,22 €"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN ANGEL'and edp.apellido1='CHAVARRIAS'and apellido2='VIZUETE'),'2024-09-18','miguel, me llama Ana la abogada y trasmito a la parte eco, social y a Angel la conversación: Buenos días, me ha llamado la abogada del procedimiento penal que se ha tramitado del tutelado. Por un fallo judicial no se nos comunicó que asistiésemos por lo que para evitar repetir la vista, se ha llegado a un acuerdo de la abogada con el Ministerio Fiscal para el cumplimiento de una condena de internamiento de 4 meses (la continuaría cumpliendo en el CSS Mérida, porque caso de que no la cumpla se le obligaría a cumplirla en la cárcel). En principio no me ha aclarado que haya multa o indemnización por responsabilidad civil, así que estaremos a la espera de lo que nos remitan desde el juzgado. Me comenta que este acuerdo aunque haya sido firmado por abogado-procurador-ministerio fiscal, debe ser ratificado por la Ctaex, por lo que tendrá que ser firmado por nuestra Gerente Estrella. Por último, la juez le ha indicado que tendremos que personarnos (va a preguntar si tiene que ser Estrella o podemos ser nosotros) a ratificar en persona el acta de conformidad por lo que le he pedido lo consulte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='REGINA'and edp.apellido1='REINA'and apellido2='LARA'),'2024-09-18','TERESA ENVIO BAJA CO HOSPITAL SANTIAGO YA QUE HA COMENZADO GRADO BASICO DE JARDINERIA EN EL INSTITUTO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2024-09-18','Ana: Llamada de Mª Antonia - Residencia de Hervás (927 47 34 10): Eugenia quiere solicitar traslado a otra residencia y no sabe si ella puede tomar esa decisión. Le explico su curatela es principalmente de tipo económico y para algunas cuestiones jurídicas, como interponer demanda o renunciar a derechos. Le leo literalmente el fallo del Testimonio de la Sentencia. ······· Por tanto ella puede acudir a la TS de la localidad y firmar/presentar la solicitud de la revisión PIA para cambio de RR residencial.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELICIANO'and edp.apellido1='LOPEZ'and apellido2='CORBACHO'),'2024-09-18','Ana: Envío correo a Inmaculada Gil, TS del HDBV (maria.gilto@salud-juntaex.es): "Adjunto el Consentimiento Informado para la realización de TOMOGRAFÍA AXIAL COMPUTARIZADA relativa a FELICIANO LÓPEZ CORBACHO. Pongo en copia a Teresa, compañera de referencia de vuestra zona."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EMILIA'and edp.apellido1='GUTIERREZ'and apellido2='SERRADILLA'),'2024-09-18','Ana: Correo del día 10/09 de Jaime, Aux. Adtvo: "Desde el Servicio de Orientación Jurídica del Colegio de Abogados de Cáceres nos han solicitado documentación para la Asistencia Jurídica Gratuita de EMILIA GUTIERREZ SERRADILLA. Ya he enviado todos los documentos, excepto Declaración de Renta o Certificado Negativo, ya que nos lo tiene que mandar hacienda. En su lugar mando la solicitud del certificado de IRPF. Cuando nos lo mande hacienda se lo reenvío. Ésta es toda la documentación que les he mandado: - Oficio Documentación Asistencia Jurídica. - Documento que nos solicita la documentación (la carta que nos mandó el Servicio de Orientación Jurídica del Colegio de Abogados de Cáceres). - Certificado Empadronamiento. - Certificado de Pensiones. - Certificado de Bienes. - Fotocopia del DNI. - Certificado Bancario. - Solicitud certificado IRPF."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='SILVA'and apellido2='BONIFACIO'),'2024-09-18','Ana: correo del día 11/09 de Susana, Adtvo. CADEX - BA (susana.hernandeze@salud-juntaex.es / 924 00 95 29): "Andrés Silva Bonifacio es usuario de Cadex Badajoz que tiene un reconocimiento de grado de discapacidad provisional hasta abril de 2024. Le remitimos cita a Mayte de la comisión Tutelar de adultos pero no vinieron a la cita. Lo hemos citado de nuevo pero al no localizarlo he hablado con Amalia y me dice que está ingresado en Plasencia Por favor cuando leas el correo ponte en contacto conmigo a ver que hacemos, si lo traen o se hace traslado de expediente a Cáceres" ····························· Llamo a Susana: Andrés tiene caducado el Certificado de Discapacidad provisional desde abril. Le enviaron citación para el día 25 de abril con antelación a Maite, al no acudir enviaron nueva citación, pero no ha acudido. Yo lo desconocía. ···································· Acordamos trasladarán el expediente al CADEX Cáceres para que puedan citarle nuevamente allí.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2024-09-18','Ana: Paso la consulta de Jesús Manuel al ctutelar@ a los A. Jurídicos: "me pueden informar sobre la pensión de los niños pues están trabajando y me gustaría saber si tengo que seguir pasando la pensión que les pasó gracias"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SALVADORA'and edp.apellido1='CHAVES'and apellido2='MENDOZA'),'2024-09-18','Ana: Envío a los A. Jurídicos los informes médicos recibidos por TRAMITA pra la revisión de las medidas de apoyo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-09-18','Ana: llamada de José Manuel (627 788 797):','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANDRES'and edp.apellido1='LANCHO'and apellido2='SANGUINO'),'2024-09-19','Ana, correo de Alberto, Jefe S. Ecca, tras reunión entre él, Lourdes y yo: "LOURDES/ANA: • REALIZAMOS TRANSFERENCIA PUNTUAL X 39.259,39 (50% DE 78.518´78, QUE ES EL SALDO A 18/0972024 DE CCC COMPARTIDA 2544), EL OTRO 50 % SE QUEDA EN UNICAJA 2544 A DISPOSICIÓN DE SU HERMANO DIONISIO • MANTENEMOS TUTELADO EN CCC UNICAJA COMPARTIDA 2544, PERO NO INTERVENIMOS EN ESTA CUENTA  REVISAMOS SITUACIÓN CADA 6 MESES Y VOLEMOS A PLANTEAR QUITAR A TUTELADO DE TITULAR. LOURDES: PAGO PLAZA RM SANTA MARTA MAGASCA: • DOMICILIAMOS EL PAGO EN CCC UNICAJA NUEVA 0321, EN EL MOMENTO EN QUE LA PENSIÓN TUTELADO TAMBIEN SE HA COBRADO X ESTA CCC. LOURDES: • REDEXIS: TRAS CANCELACIÓN UNICAJA COMPARTIDA 0418: SE DOMICILIA EN UNICAJA COMPARTIDA 2544 (EN ESTA CCC, LA PRETENSIÓN ES QUE SE QUEDE SÓLO DIONISIO.  SI REDEXIS PERTENECE A PROPIEDAD DISTINTA A C/PIÑUELAS (ÚNICA 100 % TUTELADO), SE MANTIENE EN UNICAJA 2544 HASTA QUE DIONISIO DECIDA. • IMPUESTOS: DOMICILIAR TODOS LOS IMPUESTOS DE C/ PIÑUELAS (100 % TUTELADO), EN NUEVA CCC UNICAJA SOLO TUTELADO 0321 • OTROS CONCEPTOS A DOMICILIAR EN CCC UNICAJA SOLO TUTELADO 0321 (ACTUALMENTE ESTÁN DOMICILIADOS EN UNICAJA COMPARTIDA 2544)  RESIDENCIA STA MARTA MAGASCA: PLAZA DE TUTELADO  COMUNIDAD PROPIETARIOS BARJOLA S/N: C/PIÑUELAS 8 (MALPARTIDA CC): DEUDOR TUTELADO  IBI C/ PIÑUELAS 2: DEUDOR TUTELADO + COMPROBAR QUE PUEDAN EXISTIR OTROS CONCEPTOS (AGUA, BASURA...)  HOGAR CASER: POL.10000000/10011252 MULTIRRIESGO CL PINUELAS: A NOMBRE TUTELADO LOURDES: DEJAMOS PENDIENTE DE QUE OBTENGAS TODA LA INFORMACIÓN PARA DECIDIR SOBRE ABANCA Y CAJA ALMENDRALEJO (VER LINEA CORREOS)"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LEON'and edp.apellido1='LEAL'and apellido2='PEREZ OLAGUE'),'2024-09-19','Ana: Respondo al correo de Sara, Enfermera de la Residencia Santa Ana (malpartida@nexusintegral.com): "Tras haberlo consultado con mis compañeros, Asesores Jurídico, me indican lo siguiente: “…necesitamos: 1. Informe del Neumólogo en el que indique el motivo por el que ha prescrito esa consulta. 2. Consentimiento informado, para que conste nuestra autorización. Todo para ponerlo en conocimiento de Fiscalía de Cáceres (Carmen Barquilla, jeje) y del Juzgado.” Por favor, cuando os sea posible hacédnoslo llegar. Pongo en copia a Ángel y Miguel, Asesores Jurídicos, por favor, ponedlos en copia cuando enviéis los documentos." ······················· envío nuevo correo con indicación de Miguel: "“…entiendo que no se le puede obligar. Lo más que se puede hacer es que se acompañe a ese deseo de León, un informe médico indicando las consecuencias de esa decisión para comunicarlo al juzgado…”"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA SALVADORA'and edp.apellido1='CHAVES'and apellido2='MENDOZA'),'2024-09-19','Ana: Respondo al correo de Miguel, A. Jurídico: "Lo que se ve mal es la primera página, que es el oficio, realmente. Lo que me preocupa son los informes que nos hacen llegar y el contenido de los mismos. En cuanto a los datos que indicas, creo que ya os los había enviado yo. Esta es la información de la que disponemos: - Su domicilio actual es RESIDENCIA DE MAYORES DE VILLA DEL REY, AVENIDA PÁRROCO PEGUERO S/N, 10960, VILLA DEL REY CÁCERES, TELÉFONO DEL CENTRO 633 17 65 82. - FAMILIARES: • Fernanda (prima que vive aquí en Villa del Rey) 619 51 33 39 • Emi (prima que vive en Madrid) 666276445"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2024-09-19','Ana: Envío correo a Alberto, Jefe S. Ecca: "Retomamos la cuestión económica de ÁNGEL FÉLIX MAILLO SANTIBAÑEZ, ayer llamaba de nuevo diciendo que necesita que se le suba la asignación. Ya se han hecho todas las prueba posible, pero viendo que no ha funcionado ninguna de ellas, que no acaba de materializar nada de alquiler cada vez que lo plantea y que tampoco quiere ir a recurso residencial, ya le dije que se le va a autorizar para que retire periódicamente, como hasta ahora, toda su pensión, excepto las pagas extras, y con la condición de que no pida más retiradas extraordinarias a lo largo del año. Ayer dijo que le parecía bien. Por favor, cuando puedas me dices la cuantía y a partir de qué día se hará efectivo este cambio."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL MARIA'and edp.apellido1='CANO'and apellido2='BLAZQUEZ'),'2024-03-21','Ana: Correo de Paula, TO: "hemos planificado salida a Trujillo, en hostal, del 22 al 25 de Marzo. Está mostrando un importante compromiso con su proceso de recuperación: cuidado de su salud física y emocional, participación en recursos comunitarios CRPS, participación en espacios transversales de la residencia, entre otros"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2024-03-21','Ana: Correo de Paula, TO CRR: "hemos planificado salida al pueblo con su padre con 4 noches, del 27 de marzo al 1 de Abril. Preparamos con ella cómo sostener los autocuidados y poder participar junto a su padre en actividades domiciliarias y comunitarias (interesada en ver procesiones y realizar una celebración por el aniversario del fallecimiento de su madre)."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='VALERO'and apellido2='AGUEDO'),'2024-09-19','En relación a Natalia Valero Aguedo y al recurso residencial definitivo para ella, hemos iniciado una toma de contactos con AEXPAIMBA para ver si la joven tenía el perfil adecuado para entrar y residir en sus hogares tutelados, ya que además está realizando sus estudios allí. Tras reunirnos con ellos y analizar el perfil de Natalia, nos confirman que sí, que es el perfil adecuado para sus hogares tutelados y que estarían encantados de poder contar con ella. Además, en estos momentos tienen plazas. Yo entiendo tas las conversaciones que hemos tenido sobre la búsqueda de un recurso en el que estamos, que respete el arraigo de la menor a la zona de Olivenza-Badajoz, que sirva como referente de futuro para que la joven pueda desarrollarse con semejantes y sobre todo, que no la lleve cerca del hogar familiar, de donde tuvo que salir y ser tutelada por la Administración, que ésta es la mejor opción que en estos momentos podemos ofrecerle a Natalia. Por ello creo que debemos aprovechar esta oportunidad. En este sentido os solicito Amalia que podáis dar vuestro consentimiento para que iniciemos los trámites adecuados (solicitud, petición de informe social al SSB...) y sobre todo, que podáis agilizarlo, ya que depende del SEPAD su autorización y a ellos dirigiremos la solicitud.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='NATALIA'and edp.apellido1='VALERO'and apellido2='AGUEDO'),'2024-09-19','-Emal del Dtor del CAM Olivenza. En relación a Natalia Valero Aguedo y al recurso residencial definitivo para ella, hemos iniciado una toma de contactos con AEXPAIMBA para ver si la joven tenía el perfil adecuado para entrar y residir en sus hogares tutelados, ya que además está realizando sus estudios allí. Tras reunirnos con ellos y analizar el perfil de Natalia, nos confirman que sí, que es el perfil adecuado para sus hogares tutelados y que estarían encantados de poder contar con ella. Además, en estos momentos tienen plazas. Yo entiendo tas las conversaciones que hemos tenido sobre la búsqueda de un recurso en el que estamos, que respete el arraigo de la menor a la zona de Olivenza-Badajoz, que sirva como referente de futuro para que la joven pueda desarrollarse con semejantes y sobre todo, que no la lleve cerca del hogar familiar, de donde tuvo que salir y ser tutelada por la Administración, que ésta es la mejor opción que en estos momentos podemos ofrecerle a Natalia. Por ello creo que debemos aprovechar esta oportunidad. En este sentido os solicito Amalia que podáis dar vuestro consentimiento para que iniciemos los trámites adecuados (solicitud, petición de informe social al SSB...) y sobre todo, que podáis agilizarlo, ya que depende del SEPAD su autorización y a ellos dirigiremos la solicitud . -Tras este email inicio tramites para la solicitud de plaza , sin ser por emergencia social . Quedo pte. de recibir I.sociales del Centro y SSASB , el martes subo a que me firme la solicitud de centro .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FAUS'and apellido2='LEMUS'),'2024-09-19','miguel, envío email a la Abogada ROSA MARIA MUÑOZ BERNALDEZ >2913@icaba.com> Teléfono 924662763: Buenos días Rosa, en relación al procedimiento arriba indicado finalmente nunca nos llamaron ni remitieron nada los del jzdo de 1º instancia e instrucción nº1 de Zafra y tampoco nos citaron para la vista que comentabas en tu último email. Me llamó ayer el juzgado de lo Penal nº1 de Badajoz ayer, que me comentan que es el competente para resolver este procedimiento, y me han remitido este documento que te adjunto en relación al procedimiento que estaban tramitando en el jzdo de Zafra de 1º instancia e instrucción nº1 de Zafra, del que nunca nos remitieron nada (desconocemos al completo dicho procedimiento) y me citan a mí para asistir a las sesiones del juicio oral para llegar a una conformidad, lo cual es un error evidente porque yo no soy tutor de nadie, soy un mero funcionario del Gabinete Técnico de la Ctaex, (la Comisión Tutelar de Adultos representada por Doña Estrella Angeles Lavado Martinez, actual Gerente del SEPAD de la Consejería de Salud y Servicios Sociales). Quien es tutor es la Comisión Tutelar de Adultos del SEPAD. Recuerda que te remití las resoluciones judiciales de nombramiento y aceptación del cargo de tutor por la Comisión Tutelar de Adultos, con lo que el juzgado debería estar informado de que quién ostenta dicho cargo es la Comisión Tutelar de Adultos y no un funcionario del Gabinete Técnico. En su día me comentaste que no quiso llegar a una conformidad y ahora me dicen que sí quieren llegar?. Desconozco si es una sola vista, varias, etc. Necesito me aclares la situación y me aportes toda la documentación para su estudio por la Comisión Tutelar de Adultos antes de tomar la decisión si apoyar o no dicha conformidad por el tutelado en el referido procedimiento por nuestra representante de la Comisión Tutelar de Adultos. Así mismo al ser tú la representante procesal del tutelado, entiendo que debe ser a través tuya el poner en conocimiento del juzgado que el tutor es la Comisión Tutelar de Adultos y su representante Doña Estrella Angeles Lavado Martinez, actual gerente del SEPAD o lo envío yo directamente por Lexnet? Nunca se nos ha dado un caso similar, por si lo quieres hablar con el juzgado, ya que normalmente asistimos por videoconferencia y nos ratificamos en la voluntad del tutelado y nos adherimos a lo que diga nuestra abogada, y caso que no lo haya a lo que diga el Ministerio Fiscal. Recuerda que somos equipo técnico, no actuamos como letrados. En cuanto a mi asistencia conforme citación adjuntada que me han enviado hoy por email desde el juzgado, yo podría asistir a una vista no a varias sesiones de juicio oral, y a ser posible por videoconferencia, ya que aquí tenemos más de 800 personas con las que trabajamos y no puedo estar faltando continuamente. Y tampoco podemos hacer asistir presencialmente a la representante de la Comisión Tutelar de Adultos, Doña Estrella Angeles Lavado Martinez, porque es un puesto político y no para de viajar, reuniones, etc. Entiendo que hay que contestar a este escrito adjuntando el nombramiento y aceptación de cargo de tutor de la Comisión Tutelar de Adultos. Cuando puedas ponte en contacto conmigo para remitirme lo que haya del procedimiento y explicarme a qué acuerdo quiere llegar el tutelado. ********************************************** Reenvio email a Amalia, Alberto y Angel: Buenos días, me llamaron ayer desde el juzgado de lo penal nº1 de Badajoz para comunicarme que quieren que asista yo como tutor a las sesiones de juicio oral de Rafael Faus Lemus. Adjunto email que he mandado a la abogada que le representa. Voy a preparar un escrito de contestación aclarando que es la Comisión la tutora no yo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2024-09-19','Ana: envío correo a Estrella Durán, TS CSS-Plas (estrella.duranc@salud-juntaex.es): "En relación a JULIA MORÓN HERNÁNDEZ, adjunto la Aceptación de derivación a recurso de salud mental, debidamente firmada y sellada por la Representante Legal."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARTA'and edp.apellido1='RIVERA'and apellido2='NUÑEZ'),'2024-09-19','miguel, llamo a la abogada que la asistió cuando denunció el 13/9/24 Ana Isabel Gallego Lozano que me confirma que sólo fue en el momento de la denuncia y no se dictó orden de alejamiento ni de protección. Me confirman telefónicamente el procedimiento y me indican abogado y procurador. Envío email a Tere, Angel e Inés con lo averiguado: Buenas tardes, voy a preparar un oficio para remitir testimonio de incapacitación y nombramiento de tutor por la Ctaex al juzgado nº1 de Castuera, DPA 57/2023. Me comentan que el actual procurador es Diego Pablo Lopez Garrido y abogado Pedro Galan Tamurejo, que está de baja, motivo por el cual mandaremos directamente al juzgado nuestra representación. El nig del procedimiento es 0603641220230000102.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='MOLANO'and apellido2='IGLESIAS'),'2024-09-19','Ana: Subo al portafirmas digital el PAI remitido por Raquel Arias Almendro Psicóloga - Casa Familiar Virgen de la Montaña (psicologiacf-caceres@cruzblanca.org).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PILAR'and edp.apellido1='JIMENEZ'and apellido2='AGUILAR'),'2024-09-19','Ana: Conversación con Piedad Cabezas, TS SSB de Ahigal, Guijo de Granadilla, Santibáñez el Bajo y Santa Cruz de Paniagua (670 293 045 // ssbp@trasierratierrasdegranadilla.es): Pilar está estaba preocupada porque tenía que pagar un recibo de luz y Jesús está ingresado en el hospital. ·················································· Llamo a Pedro, Hijo del propietario (646 227 862) con quien hemos contractado en otras ocasiones en referncia al contrato y otras cuestiones. *Al parecer no tienen deudas de aquí para atrás, pero la mensualidad y suministros del mes de septiembre aún no los han abonado. ········· Le explico que desde aquí se hace una transferencia mensual a Jesús, su pareja, de la parte que le correspone abonar a ella, y él se encarga de pagar a us padres. *Acordamos que van a esperar unos días (al menos hasta final de mes/principios del siguiente) para ver si dan el alta a Jesús, pues entendemos que él pondrá al día los pagos, como hasta ahora. Si no fuera así, volveremos a hablar al respecto para buscar una solución. ························· Llamo a Ana Benavente, TS ESM-Pla., quién también ha escrito por el mismo asunto, pero no obtengo respuesta. ··············· Le envío un correo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIA'and edp.apellido1='PACHECO'and apellido2='VICENTE'),'2024-09-19','Ana: Correo de Ana Benavente (anamaria.benavente@salud-juntaex.es): "Ha venido acompañada por alguien que contrata la residencia de mayores , pero que no tenía información de la paciente. Desconozco ahora mismo si FUTUEX la podría acompañara a las citas y tener un seguimiento. Era para preguntarte si sabías algo al respecto." ··············································· Mi respuesta: "desconocía que haya ido acompañada por Aux. de pago, quiero pensar que desde Futuex no han podido acompañarla, porque ella leva años derivada al Programa. La monitora-educadora actual es Clara. Preguntaré al respecto y pediré, que a ser posible, a partir de ahora le acompañe ella."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='AZUCENA'and edp.apellido1='BEJAR'and apellido2='HERNANDEZ'),'2024-09-19','Ana: Se trata de una Curatela Reprsentativa. Azucena presenta Grado III de Dependencia. Tiene reconocido Prestación de SAR con plaza RAE, en el Centro de Discapacidad','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALBERTO'and edp.apellido1='MOLANO'and apellido2='IGLESIAS'),'2024-09-20','Ana: Envío correo a Raquel, Psicóloga - Casa Familiar Virgen de la Montaña(psicologiacf-caceres@cruzblanca.org): "Adjunto el PAI relativo a Alberto Molano Iglesias de este 2024 firmado digitalmente por la Representante Legal."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-09-16','Ana: Correo de Inés, Adtvo. Secc. Jurídica, del día 6/09: "adjunto os reenvío citación de Jose M. Romero Mediavilla, reconocimiento de Medico Forense en calidad de investigado. A día de hoy se ha recibido una llamada en la Ctaex por la policía, comunicando que está detenido. Esta subido al expediente y anotado en hoja excell de citaciones." ···························· Respuesta de Miguel, A. Jurídico, al correo de Inés: "he hablado con la policía nacional y me han remitido al juzgado de instrucción nº2 donde ahora tendrá la vista. Le han asignado abogado de oficio, D. José Alvaro Santibañez Baez. No es necesario que comparezcamos. Me ha tomado nota del teléfono, email de la ctutelar y de Lexnet para comunicarme el número de procedimiento DPA que está dando de alta. El motivo no me lo ha dicho pero ha venido a decirme que por lo mismo que el procedimiento que adjuntas Inés del lunes… No os preocupéis le acompaña Nieves, y ya están informados los dos de que el lunes vuelvan para que le vea el forense a las 10h. Por tanto el procedimiento de hoy nos comunicará el juzgado el motivo del mismo" ······························································································································································································ Correo del día 7/09 de Mercedes Romano García - FARMACIA (farmaciamromano@hotmail.com) al ctutelar@: "Adjunto la prescripcion de Jose Manuel Romero mediavilla de loperamida, le hemos dado esta misma mañana una caja de fortasec."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-09-20','Ana: Envío correo a la Secc. Jurídica: "1) Os adjunto los informes médicos que solicité tanto a la Médica de Atención Primaria como al Equipo de Salud Mental y me remitieron en su día, para la revisión de las medidas y dos posteriores a éstos del Servicio de Psiquiatría. 2) Los datos de José Manuel que requieren son: a. DNI: 28941714D b. Lugar y fecha de nacimiento: Cáceres - 18/10/1967 c. Domicilio: C/ Ecuador, nº 36 – 4º Dcha. – Cáceres d. Teléfono: 627 788 797 3) Hermanos con los que tiene contacto: a. José Luis Romero Mediavilla. i. DNI: 07005929Z ii. Lugar y fecha: Cáceres - 15/01/1963 iii. Domicilio: C/ Los Serranillos, bloque. 6, portal 2, 2º H – CP: 10004 - Cáceres iv. Tlf. 687 581 061 b. Mª de los Ángeles Romero Mediavilla. A ella le visita puntualmente, pues según nos cuenta José Manuel presenta un estado de salud delicado y recientemente ha enviudado. No disponemos de datos de contacto ni más información. c. Julia Romero Mediavilla. Con ella sólo tiene contacto muy esporádico, principalmente si se ven por casualidad. No disponemos de datos de contacto ni más información. d. Eulogio Romero Mediavilla. Con éste sólo tiene trato cuando se lo encuentra por la calle. No disponemos de datos de contacto ni más información. De los cuatro hermanos, el único que contacta con el Gabinete Técnico de la CTAEx y muestra interés y preocupación y le brinda su apoyo en el día a día, es José Luis. El resto nunca ha contactado con este equipo." ································································································································································································ Correo de Toni-Futuex: "José Manuel acudió hace unas semanas al podólogo, el especialista le realizó una limpieza y una revisión de su pisada y el calzado que utilizaba normalmente, y le recomendó un cambio para mejorar su salud a la hora de caminar y que también repercutirá en otros dolores de los que él se queja como las rodillas. Se adjunta de nuevo el informe del podólogo y también el presupuesto de unas zapatillas que en cuanto a relación calidad-precio son las que más se ajustan a lo recomendado." ······················· Mi respuesta: "Ok al presupuesto de las zapatillas. Pongo en copia a mi compañera María, quien me confirma que realizará sendos abonos el lunes que viene." ·························································································································································································································································· Envío nuevo correo a Toni y Nieves- Futuex: "En relación a JOSÉ MANUEL ROMERO MEDIVILA, tan sólo comunicaros la existencia del servicio de podología gratuito que ofrece el IMAS ahora asociado al Servicio de Ayuda a Domicilio. Puesto que José Manuel es usuario del mismo y hace poco necesitó atención con el Podólogo plantearos que si vuelve a necesitarlo en un futuro próximo, por favor, se haga a través de este servicio. Eso sí, tendréis que enviarnos la solicitud para que se firme desde aquí."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELICIANO'and edp.apellido1='LOPEZ'and apellido2='CORBACHO'),'2024-09-20','Ana: Envío correo a Inmaculada Gil, TS del HDBV (maria.gilto@salud-juntaex.es): "Adjunto consentimiento informado para realización de Ecobroncoscopia Flexible debidamente firmado y sellado referente al paciente Feliciano López Corbacho. Pongo en copia a Teresa."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MIGUEL'and edp.apellido1='CORDERO'and apellido2='MASA'),'2024-08-05','Ana: Envío correo a Toni-Futuex: "Te envío, para cuando regreses, hoja de derivación de nuevo usuario al programa: JOSÉ MIGUEL CORDERO MASA. En principio espero haber explicado bien la situación en la propia hoja, no obstante, ante cualquier cuestión, ya sabes, no dudes en contactar." ···························································································································································································· Envío correo a Soraya Masa, Jefa de Ud. PP.AA.: "Recientemente, el pasado jueves día 1 de agosto, se ha aceptado el cargo de CURATELA REPRESENTATIVA de JOSÉ MIGUEL CORDERO MASA, como sabes de larga trayectoria como paciente de Salud Mental y como usuario en tres de los CRR. Actualmente estamos en fase de inventario, no obstante, en el AUTO DE NOMBRAMIENTO, como puedes leer en el documento adjunto: “…SE AUTORIZA EL INTERNAMIENTO de D. José Miguel Cordero Masa en CENTRO O PISO TUTELADO, adecuado, ya sea uno u otro, para su patología, el cual deberá ser designado por la Unidad de programas Asistenciales del SEPAD.” Presenta Grado II de Dependencia y un grado de discapacidad del 81%, con diagnóstico según dictamen técnico del CADEX de: alteraciones de conducta, trastorno de la afectividad, deficiencia expresiva y sordera. Cuando quieras/puedas lo vemos, pues tenemos que solicitarle recurso, dada la claudicación familiar en el cuidado y atención a José Miguel."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MIGUEL'and edp.apellido1='CORDERO'and apellido2='MASA'),'2024-08-01','Ana: Correo de Isabel Pino, TS Miajadas (ipino@miajadas.org // Tf: 927 34 70 00 Ext: 3216): "EN RELACIÓN A LA PETICIÓN DE INFORME SOCIAL DE JOSÉ MIGUEL CORDERO MASA, HE CITADO A LA FAMILIA PARA ENTREVISTA. ACUDIÓ SOLO LA MADRE, QUE SE MOSTRÓ REACIA EN LA ENTREVISTA, PUES DICE QUE A QUÉ VIENE ESTO, PUES LA TRABAJADORA SOCIAL DE SALUD MENTAL YA LO SABE, Y ES ELLA QUIEN LLEVA EL CASO. INTENTÉ EXPLICARLE LO QUE SIGNIFICA QUE SU HIJO ESTÉ TUTELADO POR LA CTAEX POR LO QUE PIDEN EL INFORME SOCIAL, A LO QUE ME RESPONDE QUE ESO NO ES ASÍ, PORQUE SU HIJO ESTÁ EN CASA Y ELLOS LO QUE NECESITAN ES UN CENTRO PARA SU HIJO, YA QUE LA FAMILIA ESTÁ DESBORDADA. ANTE ESTO DESISTÍ DE CONTINUAR CON LA ENTREVISTA Y CONTACTAR CONTIGO. AL OBJETO QUE HABELIS CON LA FAMILIA Y LES EXPLIQUÉIS LO QUE SIGNIFICA QUE SU HIJO ESTÉ TUTELADO POR CTAEX. Y MÁS ADELANTE, POR MI PARTE, RETOMAR EL CONTACTO CON LA FAMILIA PARA PODER REALIZAR DICHO INFORME SOCIAL."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOBAL'and edp.apellido1='CASQUERO'and apellido2='GARCIA'),'2024-09-20','-Amalia , solucionado el tema eco con el centro , le van a devolver todos esos meses que habían pasado . Hay que hacerle un pto. nuevo como persona que reside fuera del centro , está de alquiler con Gori. He pedido su tf para cuadrarlo con él .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2024-09-20','Ana: envío correo a Toni-Futuex: "He recibido llamada de José Luis, hermano de José Manuel Romero Mediavilla, pregunta por la factura de agua que hay que abonarle. Dice que se la entregó a Nieves, pero aquí aún no ha llegado. Por favor, cuando podáis remitidla al ctutelar@salud-juntaex.es, a la atención de la sección económica."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MIGUEL'and edp.apellido1='CORDERO'and apellido2='MASA'),'2024-09-20','Ana: Envío correo a Toni-Futuex: "En relación a JOSÉ MIGUEL CORDERO MASA, residente en Miajadas, por favor, en cuanto podáis, informarme acerca de las primeras visitas de seguimiento y sobre la situación sociofamiliar a día de hoy. No sé a qué educadora habrás asignado, pero al ser Miajas imagino que a Mamen, la pongo en copia." ··································································································································································································· En ausencia por baja de Isabel Pino, TS SSASB Miajadas, llamo a Chelo, TS SSASB (927 90 12 15): No obtengo respuesta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='GOMEZ'and apellido2='MUÑOZ'),'2024-09-20','Ana: Llamada de Felisa Custodio, TS CAMS (927 12 19 51): Tanto Carmen como su hermana han vuelto a pregutnarle por las gestiones de la renuncia de la herencia. No ha obtenido respuesta al correo que envió el martes 17 a los jurídicos. ··················· Envío un correo a Ángel y a Miguel al respecto y pido que le den respuesta en cuanto puedan.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='MARIN'and apellido2='LAUREANO'),'2024-06-22','EXITUS - EN EL HOSPITAL SAN PEDRO DE ALCÁNTARA - CC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2024-09-20','Ana: Llamo Rafa, Control de pensiones INSS - CC (927 62 00 51) para preguntar por el estado del expediente de orfandad tras haberles enviado en julio la documentación. ············· Intentará ponerse con ello hoy o el lunes a mucho tardar y me informará.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2024-09-20','Ana: Llamo a Rafa, Control de Pensiones INSS-CC (927 62 00 51) en relación al expediente de la pensión de orfandad que dieron de baja. ··········· Tras varias consultas y gesiones, me confirma que se va a rehabilitar la pensión. **Tal y como me solicita, le digo el IBAN nuevo, pues les constaba el antiguo (anterior a las fusiones de los bancos) y le daba error.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ALEJANDRO'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2024-09-20','Ana: Llamo a Rafa, Control de pensiones INSS - CC (927 62 00 51) para preguntar por el estado del expediente de la pensión de orfandad. ······· *Finalmente la van a reactivar. Me pide y le facilito el nuevo número de IBAN, pues el que tenían era el antiguo y le daba error.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='GARCIA'and apellido2='MORENO'),'2024-09-20','Ana. Envío correo a Toni-Futuex: ", ayer recibí llamada de Abraham, su hijo. Me pregunta por una solicitud de Podólogo del IMAS – Ayto del Cáceres, servicio asociado al Servicio de Ayuda a domicilio. El plazo termina en unos meses y no quieren perder este derecho. Dice que Mamen, Educadora, lo ha enviado, pero he filtrado y no hemos recibido nada al respecto. También me preguntó por un presupuesto de un frigorífico, pues se ha averiado el suyo. Por favor, cuando podáis hacednos llegar ambas cosas. Pongo en copia a Mamen."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2024-09-20','Ana: correo de Toni - Futuex (areasocial3@futuex.es): "Juan Chamorro está aceptando el seguimiento del equipo, y en las ultimas intervenciones ha aceptado el seguimiento lo que es una buena noticia, el otro dia tenia cita en salud mental en Trujilo y no acudió según el, porque no fue la ambulancia... estamos a la espera que se le reprogramme, pero sin embargo si que se pone los inyectables en Guadalupe y está mucho mas receptivo y relajado, es por ello que hacemos llegar estos presupuestos, porque consideramos que si puede necesitarlas. PRESUPUESTO GAFAS PRESBICIA Durante los ultimos seguimientos presencial en Guadalupe, Juan se mostró muy colaborador y solicitó unas gafas para mejorar su visión al utilizar el teléfono móvil. En consecuencia, se le acompaño a la farmacia para obtener un presupuesto. -Gafas presbicia: 18.85€ Número de cuenta: ES 6721037111750030023270 Es importante destacar la relevancia de que Juan perciba nuestros seguimientos como útiles, a fin de establecer una vinculación adecuada. Por ello, proponemos realizar el pago de las gafas y recogerlas juntos en la próxima intervención." ····················· Respondo con copia María, Ed. : "Qué buena noticia! A ver si es verdad que va a la próxima cita cuando se la reprogramen y no haya sido una excusa, tomo nota de todo. Paso los presupuestos a Alberto, Jefe de la Sección Económica. Por mi parte, si es viable ok a ambos." ·································································································································································································· Correo-respuesta de Alberto: "ALE: OK A COMPRA GAFAS...AVISA A ANA CUANDO ESTE HECHO EL PAGO PARA QUE PASEN A RECOGERLAS"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL FELIX'and edp.apellido1='MAILLO'and apellido2='SANTIBAÑEZ'),'2024-09-20','Ana: Respuesta de Alberto a mi correo de ayer: "...LO QUE INDICAS EN TU CORREO YA SE HA HECHO HACE TIEMPO)...TE INDICO: • INGRESOS: PENSIÓN INVAL: 776,85 €/MES • ACTUALMENTE HAY UN REINTEGRO PERMANENTE X 185 €/SEMANA (802 €/MES), DESDE 01/08/2024...LO ACORDAMOS X C.ELECTRONICO DE 08/07/2024.  QUE ES BASTANTE SUPERIOR A LA TOTALIDAD DE SU PENSIÓN.  ESTO SUPONE QUE SÓLO AHORRAMOS UNA (NO LAS DOS) PAGA EXTRA (SI NO HAY EXTRAS!!!)....PERO SI QUE HAY EXTRAS (Y ESTA PARTE TAMPOCO LA ENTIENDO). • EXTRAS: TAMPOCO SE EL MOTIVO PERO...INCLUSO DESPUÉS 01/08/2024, SE LE HAN ABONADO LOS SIGUIENTES EXTRAS: o 07/08 ROPA X 100 € o 29/08 ROPA Y VIAJE X 100 € ANA: ENTIENDO QUE ESTO LO DEBEMOS CONTROLA A PARTIR DE AHORA: • EN MI OPINIÓN, CON ESTE REINTEGRO NO DEBERIAMOS DARLE NI UN SOLO EXTRA...X NINGÚN CONCEPTO." ·········································································· Nuevo correo de Alberto, Jefe, a, a todas las compañeras de la sección ecca: "AREA ECO: (ANA/ALBERTO): NO HAY MÁS EXTRAS PARA ESTE TUTELADO...YA ESTÁ SACANDO UN IMPORTE SUPERIOR A CADA UNA DE SUS PAGAS MENSUALES. REITERO: NO HAY MAS EXTRAS...SI SE TRATA DE ALGUNA CUESTIÓN A CONSIDERAR, SE TRATA PREVIAMENTE CON ANA Y LUEGO CONMIGO. " ······································································································································································································ Llamo a Ángel Félix para comunicárselo, pero el móviel está apagado y fuera de cobertura.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LEON'and edp.apellido1='LEAL'and apellido2='PEREZ OLAGUE'),'2024-09-20','Ana: Correo de Sara, enfermera de la Residencia Santa Ana (malpartida@nexusintegral.com) a Ángel, A. Jurídico, con copia a mí: "Le adjunto informe médico de neumología al alta junto con las citas de las pruebas mencionadas, su medico de cabecera me comenta que no esta capacitado para realizar informe con las posibles consecuencias a su salud por su decisión de no ir a la cita y no seguir tratamiento, ya que le corresponde a su médico especialista en neumología, si precisan algo más pónganse en contacto con nosotros"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2024-09-20','Ana: Envío, de nuevo,a Toni, Futuex, la DERIVACIÓN AL PROGRAMA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MATEO'and edp.apellido1='RUANO'and apellido2='MORENO'),'2024-09-23','Ana: Envío correo a Rosana, Directora de la Residencia Balcón de Extremadura (balconextremadura@grupociudadjardin.com) con copia a Margarita, TS de la Mancomunidad (tsocial4@mancomunidadsierrademontanchez.es): "hemos recibido Informe Social de Margarita, Trabajadora Social, la pongo en copia, junto con Nota de Enfermería e informe de Psiquiatría. Indica la necesidad de que solicitemos Revisión del Grado de Dependencia para que pueda ocupar plaza de asistido, dado el empeoramiento del estado de salud y su mayor dependencia para las ABVD. No hay inconveniente en hacerlo, pero como sabéis, necesitamos el Informe de Salud, Anexo II que adjunto, para poder adjuntarlo a la solicitud. Por favor, cuando os sea posible, solicitarle cita al médico para que haga el informe. Por otra parte, en la nota de enfermería, indica que estaban pendiente de resultados de urocultivo por posible infección de orina, ¿disponéis ya de los mismos? Ya nos decís cuando podáis." ································································································································································································· Según los informes Mateo se encuentra estabable en cuanto a la Esquizofrenia residual que presenta. Participa en las actividades del centro y tiene buena relación con los compañeros y profesionales. En los últimos meses presenta mayor dependencia para las ABVD, habiendo además sufrido varias caídas y empeorado su estado de salud.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MIGUEL'and edp.apellido1='CORDERO'and apellido2='MASA'),'2024-09-23','Ana: Respuesta de Toni a mi correo del viernes 20: "...no tenemos el seguimiento de este caso aún, si se incorpora cuando puedas me pasas los datos xfa." ········································ *Le reenvío el correo remitdo el 5/08 con la hoja de derivación. ···· Le informo que dada la baja de Isabel Pino, TS, pueden contactar con Chelo, TS SSASB (927 90 12 15). ································································································································································································ En ausencia por baja de Isabel Pino, TS SSASB Miajadas, llamo a Chelo, TS SSASB (927 90 12 15): No obtengo respuesta. ······· *Le envío un correo (cblanco@miajadas.org) pidiendo que se ponga en contacto conmigo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SONIA'and edp.apellido1='VALCARCEL'and apellido2='VIDAL'),'2024-09-23','-Amalia , comunican desde el CRR que está ingresada voluntariamente en la UHB Bjoz.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PILAR'and edp.apellido1='JIMENEZ'and apellido2='AGUILAR'),'2024-09-20','Ana: Correo de Pedro, hijo del propietario de la vivienda (ryoga.hibiki.330@gmail.com): "En relación a lo que hablamos ayer: El día de pago es el 25 de cada mes. O sea que todavía hay una semana de plazo. En caso de que no se pague está vez en plazo mis padres están dispuestos a esperar a que den de alta a Jesús sin problemas y luego ajustarían cuentas de alquileres y consumos. Ahora creo que la situación no es preocupante, pero es una situación que hay que tratarla, pues el problema de pilar es que cree que la vamos a echar si no paga el 26 a pesar de que mi madre la aseguró que estaba dispuesta a esperar el alta de Jesús. Por ellos la instamos a qué fuera a la asistenta social para poder poner en conocimiento de la administración su caso. Si tiene alguna otra duda por favor póngase en contacto con migo a través de este medio u contacto telefónico."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PILAR'and edp.apellido1='JIMENEZ'and apellido2='AGUILAR'),'2024-09-23','Ana: Llamo a Ana Benavente, TS ESM-Pla (74955): no obtengo respuesta. ······································································· Le reenvío correo del hijo del propietario a ella y a Piedad, TS SSASB (ssbp@trasierratierrasdegranadilla.es) y añado: "Como sabéis el jueves hablé con Pedro, el hijo del propietario de la vivienda y al día siguiente, tras hablar con sus padres me envío este correo que os reenvío. Pilar, por favor, si Pilar acude a tu despacho, transmítele el mensaje, para que esté más tranquila. Por otra parte, Ana, si puedes averiguar algo sobre la duración del ingreso de Jesús, su pareja, sería estupendo para poder estudiar opciones en caso de que se vaya a prolongar, que ojalá que no sea así." ····················································· *Respuesta de Piedad, TS SSASB: "Pilar hoy no ha venido por aquí, si la veo tranquila que se lo trasmito y la tranquilizo"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='SANCHEZ'and apellido2='GARCIA'),'2024-09-23','Ana: Según Informe Social del CSS para la rendición anual: ingresada de forma ininterrumpida en el CSS desde 1995. Familia de etnia gitana, se dedica a la venta ambulante. En los últimos años la frecuencia de las llamadas han disminuido, pero sigue realizando salidas con la familia en periodos vacacionales (navidad y verano). ············ Ingresada en URHA. Participa en actividades de rehabilitación y ocupacionales.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FAUS'and apellido2='LEMUS'),'2024-09-23','miguel, llamo al centro penitenciario de Badajoz 924289100 y hablo con la Beatriz Ts, y me confirma que por ahora tiene condena hasta el 22-3-32. Está adaptado y no ha solicitado nada, por lo que con lo que está recibiendo en la cuenta peculio debe estar satisfecho.. Para posteriores ocasiones por la ley de protección de datos me pide lo solicitemos por escrito para que el departamento jurídico nos conteste. Comunico la conversación a Amalia','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANGELES'and edp.apellido1='SANTOS'and apellido2='URBANO'),'2024-09-23','Ana: Subo al portafirmas digital la Comunicación de variación de domicilio a PNC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FAUS'and apellido2='LEMUS'),'2024-09-23','miguel, envío email a Rosa la abogada ROSA MARIA MUÑOZ BERNALDEZ >2913@icaba.com>: Buenos días Rosa, he intentado en reiteradas ocasiones localizarte en el tlfno 924662763, necesito te pongas en contacto conmigo para aclarar este asunto. Necesitaría que además de remitirme las condiciones de la propuesta de la conformidad, te confirmen de qué penas le quedan pendientes. Por ahora sé que le queda hasta el 2032 de condena penitenciaria. Quedo a la espera de tu contestación. Mientras remitiré al juzgado escrito indicando que se han equivocado en la citación y que quien ejerce el cargo de tutor es la Comisión Tutelar de Adultos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='ALEGRE'and apellido2='GOMEZ'),'2024-09-23','Ana: según Informe Social para la rendición anual: ingresado de forma definitiva en el CSS desde 1996. Es el 2º de 4 hermanos. Una de ellos también presenta enfermedad mental. ·········· Recibe visitas esporádicas de los familiares. ···· Participa en las actividades rehabilitadoras y ocupacionales del centro. ····· Desde el centro se le cubren todas las necesidades y se le apoya en la gestión del dinero de bolsillo y en la compra de ropa u otros.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELICIANO'and edp.apellido1='LOPEZ'and apellido2='CORBACHO'),'2024-09-23','Ana: Envío correo a Inmaculada Gil, TS del HDBV (maria.gilto@salud-juntaex.es): "Adjunto el consentimiento informado para procedimientos con anestesia referente al paciente Feliciano López Corbacho debidamente firmado y sellado por la representante legal."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='COSTI ALEXANDRU'and edp.apellido1='RIZEA'and apellido2=''),'2024-09-23','Ana: Según Informe Social recibido para la rendicón anual, guardada en la carpeta de Rendiciones: Alex convive con otros cuatro compañeros con los que se siente a gusto. Se encuentra bien adaptado e integrado en la residencia. Buenas relaciones con el resto de residentes y con los profesionales. Realiza diferentes actividades que favorecen la inclusión en la comunidad así como su bienestar físico, emocional y social. ···· Sigue teniendo grandes necesidades de apoyo para las ABVD. ······· Mantiene las citas de seguimiento en Psiquiatría y están pendientes aún de los resultdos de la analítica que le indicó el Neuropsiquiatra. ····· Actualmete se encuentra más estable, colaborador, relajado, contento y con el sueño más estable.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO ANGEL'and edp.apellido1='IGLESIAS'and apellido2='RODRIGUEZ'),'2024-09-23','Ana: Según informe de la Residencia de Ntra. Sra. de la Asunción de Galisteo para la rendición anual: Prestenta Síndrome de Down, APNEA e infecciones respiratorias y *Deterioro cognitivo entre otras patologías. ··· Dependiente para todas las ABVD. ···· Deambulación independiente pero con supervisión por riesgo de caídas. *Alteraciones de conducta ocasionales. ················· mantiene correcto comportamiento en el entorno residencial, buen trato con profesionales y residentes. ···· No suele recibir visitas frecuentes, siendo el contacto familiar muy escaso desde que falleció su hermana (sólo 2 visitas en el último año).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA GUADALUPE'and edp.apellido1='GIL'and apellido2='CABELLO'),'2024-09-23','Ana: correo de Cristina, TS CSS - Plas: "desde el programa PADDI me comunican que Guadalupe Gil no cumple con los criterios, necesitara ir al dentista. Necesito saber si va a disponer de recursos económicos, aunque mandare los presupuestos una vez que tenga nueva cita" ····························· Respondo que la situación económica es delicada, no obstante que envíen los presupuestos para que mis compañeras de las S. Ecca. puedan darle respuesta sobre cuantía concreta. ········ Aprovecho para preguntarle cómo sigue a nivel psicopatológico y si sigue rechando la derivación a CRR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FAUS'and apellido2='LEMUS'),'2024-09-23','miguel, respuesta de la abogada Rosa Buenos días: He hablado con el Juzgado esta mañana, indicándole cuanto me expones en tu email sobre que no eras tú la persona que tiene la tutela de Rafael, y que no te tenían que haber citado a ti. Me dice la funcionaria, que ha sido la Juez, la que ha solicitado que se te citara a ti. Creo que debes ser tú directamente el que presentes el escrito en el Juzgado, indicando que tú no eres el tutor de este hombre. Respecto a la comparecencia para conformidad, señalada el día 18 de octubre en el Penal Nº 1 de Badajoz, les he indicado, que este hombre no quería conformarse, que se intentó por activa y por pasiva y dijo que no quería conformidad, así que no entiendo por qué nos citan otra vez para conformidad, sí este hombre no quiere conformarse, que señalen directamente el juicio. Me dice que lo comentará con la Juez, y que llame a partir del miércoles. De momento es todo lo que te puedo indicar. Mi móvil es 647835693, por sí necesitas localizarme, y quieres que comentemos por teléfono, y en el despacho también me puedes encontrar 924662763','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='ROMERO'and apellido2='PEREZ'),'2024-09-23','Ana: Respondo al correo de Jesús en que, con apoyo de Mamehn, Ed, plantea múltiples cusetiones y algunas peticiones: "...Vamos por partes: - Gracias por el informe médico, lo guardo en tu expediente, recordarte, eso sí, que sería bueno que, en próximas ocasiones, contaras con el apoyo de Mamen, Educadora. Y recordarte así mismo que los Consentimos Informados sí deben ser firmas por la Representante legal. - Para el bono del bus, yo creo que no es necesario que se firme desde aquí y que puedes firmarlo tú sin problemas. Es una cuantía pequeña pero supone una gran ayuda en tu día a día. Coméntalo si quieres cuando vayas al IMAS, pero yo entiendo que no es necesario. - La carta del bono social térmico la paso al jefe de la sección económica de la Comisión tutelar. - En cuanto a la ayuda para suministros mínimos vitales, perfecto, se la paso también al mencionado jefe para su conocimiento y para que lo tenga en cuenta en los cálculos que tenga que hacer. - Le comunico también a dicho Jefe, la necesidad de que hagas la Declaración de la Renta para la renovación del Bono Social (Iberdrola) - Al igual que tu solicitud de aumento de la asignación. Tras la compra del portátil no sé cómo estará tu cuenta, pero él estudiará tu situación económica y ya se te confirmará si es viable o no. - Quedamos a la espera también del presupuesto de teléfono. Pongo en copia a Mamen, Educadora, para que esté al corriente de mi respuesta..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA JESUS'and edp.apellido1='CRUZ'and apellido2='ESPERILLA'),'2024-09-23','miguel, email de Maria Jesús María Jesús >mariajesusmile@gmail.com> Buenas Miguel, Cada vez están pasando más cosas con el tema del padre con lo del quebrantamiento y, aunque lo estoy apuntando todo, cada vez urge más y no sé cuanto va a tardar entonces en que me asignen el abogado. Os han llamado a vosotros? Es que lo que me preocupa es que cuando me asignen uno para la demanda no de tiempo suficiente a prepararlo o que luego para lo que esté pasando no me pueda asesorar ante estás cosas que están pasando.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ENRIQUE'and edp.apellido1='SANTOS'and apellido2='GARCIA PUENTE'),'2024-09-24','Ana: Envío correo a Cristina Hdez., TS del CSS -Plas (cristina.hernandezca@salud-juntaex.es): "Comunicaros que se presentó en registro solicitud de CRR Plasencia de Enrique Santos"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='SANCHEZ'and apellido2='BENITEZ'),'2007-02-07','Las tres hermanas se encuentran en el CAMP "Mª Jesús López Herrero" de Plasencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='SANCHEZ'and apellido2='BENITEZ'),'2012-05-25','La pasada semana recibimos escrito del CAMP de Plasencia informando de la imposibilidad de realizar la exploración correspondiente al Programa de Detección Precoz del Cáncer de Mama a Dª Francisca Sánchez Benitez. Acompaña al escrito documento de renuncia, de la D.G. de Salud Pública, a la participación de nuestra Tutelada en el mencionado pograma para ser firmado por la CTAEx, cosa que de ninguna manera se va a firmar. Puestos en contacto con la D.G. de Salud Pública se ve la posibilidad de realizar dicha exploración con la usuaria acostada, si su mobilidad permite dejar libre la zona a explorar. En contacto con Maite, la T.S. del CAMP, quedamos en que volverá a pedir cita para la prueba y, caso de algún problema, se pondrá nuevamente en contacto con nosotros, ofreciéndonos a acudir a la cita en caso necesario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='SANCHEZ'and apellido2='BENITEZ'),'2012-05-31','Conversación con Maite, T. Social CAMP Plasencia.(927-017281). Manuel (Director:927-017273). Centralita (927-017270/71) Dentro del^Programa de Prevención del Cáncer de Mama no se puede realizar la mamografía a Dª Francisca. ALTERNATIVA: a través de revisión ginecológica solicitada por su médico se podría realizar ECO o cualquier otra prueba (TAC, Resonancia, etc.) que el Gine considerara oportuna. La Médica del CAMP pedirá cita a Ginecología. Nos avisarán del día y si se ve necesario acudiremos a la cita.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='SANCHEZ'and apellido2='BENITEZ'),'2019-02-13','Iciar: llama Maite, t.s. del camp de Palsencia ext. 21661, Francisca está ingresada, con pronóstico grave. Maite pregunta por las actuaciones de la Comisión cuando se produce un fallecimiento. Llamará a las primas de los padres para recabar más información. Tiene seguro de decesos con nicho incluido hasta 400€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='SANCHEZ'and apellido2='BENITEZ'),'2019-03-01','Ana: Llama Maite, TS del CAMP de Plasencia (21661). Comunica el fallecimiento de Dña. Francisca Sánchez Benítez ayer sobre las 07:00 a.m. El cuerpo ha sido trasladado esta misma mañana a Feria, localidad en que su padres tenían un nicho famliar en que será enterrada. ///// Maite pregunta si hay que hacer algo en relación a la herencia, que se tenga en cuenta desde aquí, pues las dos hermanas son las herederas de la parte proporcional de la cuantía de la cuenta bancaria que comparten las tres. De momento no hay que hacer nada.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='SANCHEZ'and apellido2='BENITEZ'),'2019-02-28','FALLECIMIENTO ANTE LA IMPOSIBILIDAD DE CERRAR ESTE EXPTE., POR SER COMPARTIDO, SE ESCRIBE EL PRESENTE PARA DEJAR CLARO EL FALLECIMIENTO DE francisca EL 28/02/2019.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='SANCHEZ'and apellido2='BENITEZ'),'2019-04-02','Ana: Recibo llamada de Maite, CAMP de Plasencia (21661). En la cuenta que comparten las dos hermanas han vuelto a ingresar la dos pensiones de Francisca, fallecida el día 28 de febrero. Esta comunicación la suele hacer el seguro, no sabemos qué habrá pasado. /////// Llamo a Prestaciones de Orfandad - CC, me comunican que lo que ha cobrado es el finiquito (la parte proporcional de la paga extra de este año: 189,01 €, lo correspondiente a diciembre, enero y febrero)//////// Llamo a Prestaciones Familiares - CC: Me comunican que la prestación es de carácter trimestral, tiene derecho a percibirla hasta el 31 de marzo. Comprueba los datos y corrobora que consta de baja desde el día 1 de abril). /////// Llamo a Maite, CAMP Plas., y se lo comunico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='SANCHEZ'and apellido2='BENITEZ'),'2019-09-25','Ana: Adelanto a Maite(927017281 Corto: 21661 // camp.plasencia@salud-juntaex.es)escaneado por mail el CI para Estirpación de la Paratiroides de Joaquina. // Se lo paso a Juan Pedro, Admtvo. para que envíe el original tal y como me han solicitado.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='SANCHEZ'and apellido2='BENITEZ'),'2019-10-23','(Pedro)Conversación con la Médico del CAM Plasencia, Esther (927-017307) +++No considera adecuado someter a Dª Joaquina a la colonoscopia diagnóstica y terapéutica, no aconsejando la misma en el inofrme que al respecto le pido y envía por correo-e.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='SANCHEZ'and apellido2='BENITEZ'),'2019-10-25','(Pedro)Conversación con la Dra. Elena Abadía, especialista de Digestivo del H. Virgen del Puerto.(927-458000). +++No les consta petición alguna de la prueba diagnóstica y terapéutaica para Dª Joaquina. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Vuelvo a hablar con maite, T. Social del CAM. +++La prueba se solcita desde el programa de detección precoz de cáncer colorrectal en población de riesgo medio, por lo que parte del Csalud sin pasar pore el Hospital.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='SANCHEZ'and apellido2='BENITEZ'),'2019-11-27','Ana: Recibimos correo del CAMP-Plas.: "Para conocimiento de esa Comisión, informamos que en la tarde del día de ayer, 25 de noviembre-19 se lleva al Servicio de Urgencias Hospitalario a la tutelada de esa Comisión Dña. Joaquina Sánchez Benitez quedando ingresada. Dada la absoluta dependencia de la tutelada y su capacidad económica, entiendo necesario y viable su acompañamiento hospitalario por lo que procederemos, si no nos indican algo en contra, a contratar por medio de una empresa el acompañamiento hospitalario de la citada residente." /// *Se lo paso a Alberto, Jefe Secc. Ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='SANCHEZ'and apellido2='BENITEZ'),'2019-12-17','TERESA: RECIBO LLAMADA TELEFONICA DE ANGEL PARA QUE AUTORICEMOS ACOMPAÑAMIENTO LAS 24 HORAS (317€/DIAS YA QUE SE ENCUENTRA MUY ALTERADA Y SE QUITA LA VIA SIENDO NECESESARIA UNA SUPERVISION CONTINUA. LO AUTORIZO YA QUE ECONOMICAMENTE LO PODEMOS A SUBIR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='SANCHEZ'and apellido2='BENITEZ'),'2020-01-08','Ana: Recibo llamada de Ángel, Director del CAMP Mª Jesús López Herrero - Plas. (21653). Joaquina sigue ingresada, está muy grave. **Ahora han ingresado también a su hermana Ángela. Han conseguido que las pongan a las 2 en la misma habitación, de modo que el acompañamiento vale para ambas. **Nos enviarán al ctutelar@ facturas pendientes del acompañamiento hospitalario 24 h (13€/h durante el día y 15€/h por la noche) para que se abone desde aquí. *De momento tienen bastante dinero en la cuenta. **Hablado con Alberto, Jefe Secc. Ecca.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='SANCHEZ'and apellido2='BENITEZ'),'2020-02-04','Ana: Recibo llamada de Ángel, direcort del CAMP, comunca que Joaquina ha vuelto al centro con oxígeno y sondas para comer (le dieron el alta el 22/01/2020). En cuanto a su hermana Ángela, continúa ingresada, le han hecho un escaner y han detectado una masa. Posiblemente le darán en alta hoy o mañana. /////// *Por otra parte me comunica que se ha enviado otras facturas del acompañamiento hospitalario al ctutelar@ el día 27/01/2020, la localizaré y se la pasaré a Alberto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='SANCHEZ'and apellido2='BENITEZ'),'2021-01-14','TERESA ENVIO SOLICITUD CAMBIO N DE CUENTA PF','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='SANCHEZ'and apellido2='BENITEZ'),'2021-03-30','EXITUS COMUNICA LS TS DEL CAMP DE PLASENCIA el fallecimiento de Joaquina el 30/03/2021.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUINA'and edp.apellido1='SANCHEZ'and apellido2='BENITEZ'),'2023-06-28','-Amalia : Hablo con Ana Marta , TS , Joaquina y Fca han fallecido . Son las 3 hnas que estaban en las camitas . Quiere solictar para Angela una silla de ruedas electrica. No entra por SES por su discapacidad. Va a enviar ptos. y justificación de la necesidad de comprarla . Quizás necesitemos A. judicial pq superará los 3000€ o dos pagos ??','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCA'and edp.apellido1='SANCHEZ'and apellido2='BENITEZ'),'2007-02-07','Las tres hermanas se encuentran en el CAMP "Mª Jesús López Herrero" de Plasencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCA'and edp.apellido1='SANCHEZ'and apellido2='BENITEZ'),'2012-05-25','La pasada semana recibimos escrito del CAMP de Plasencia informando de la imposibilidad de realizar la exploración correspondiente al Programa de Detección Precoz del Cáncer de Mama a Dª Francisca Sánchez Benitez. Acompaña al escrito documento de renuncia, de la D.G. de Salud Pública, a la participación de nuestra Tutelada en el mencionado pograma para ser firmado por la CTAEx, cosa que de ninguna manera se va a firmar. Puestos en contacto con la D.G. de Salud Pública se ve la posibilidad de realizar dicha exploración con la usuaria acostada, si su mobilidad permite dejar libre la zona a explorar. En contacto con Maite, la T.S. del CAMP, quedamos en que volverá a pedir cita para la prueba y, caso de algún problema, se pondrá nuevamente en contacto con nosotros, ofreciéndonos a acudir a la cita en caso necesario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCA'and edp.apellido1='SANCHEZ'and apellido2='BENITEZ'),'2012-05-31','Conversación con Maite, T. Social CAMP Plasencia.(927-017281). Manuel (Director:927-017273). Centralita (927-017270/71) Dentro del^Programa de Prevención del Cáncer de Mama no se puede realizar la mamografía a Dª Francisca. ALTERNATIVA: a través de revisión ginecológica solicitada por su médico se podría realizar ECO o cualquier otra prueba (TAC, Resonancia, etc.) que el Gine considerara oportuna. La Médica del CAMP pedirá cita a Ginecología. Nos avisarán del día y si se ve necesario acudiremos a la cita.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCA'and edp.apellido1='SANCHEZ'and apellido2='BENITEZ'),'2019-02-13','Iciar: llama Maite, t.s. del camp de Palsencia ext. 21661, Francisca está ingresada, con pronóstico grave. Maite pregunta por las actuaciones de la Comisión cuando se produce un fallecimiento. Llamará a las primas de los padres para recabar más información. Tiene seguro de decesos con nicho incluido hasta 400€.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCA'and edp.apellido1='SANCHEZ'and apellido2='BENITEZ'),'2019-03-01','Ana: Llama Maite, TS del CAMP de Plasencia (21661). Comunica el fallecimiento de Dña. Francisca Sánchez Benítez ayer sobre las 07:00 a.m. El cuerpo ha sido trasladado esta misma mañana a Feria, localidad en que su padres tenían un nicho famliar en que será enterrada. ///// Maite pregunta si hay que hacer algo en relación a la herencia, que se tenga en cuenta desde aquí, pues las dos hermanas son las herederas de la parte proporcional de la cuantía de la cuenta bancaria que comparten las tres. De momento no hay que hacer nada.','2');
